var sahislarData = [{"isim": "Abbâs", "slug": "abbas", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Abdülmuttalibin en küçük oğludur. Resûlulla-\nhın amcasıdır. Üç yaş büyükdür. Bedr gazâsında düşman askeri arasında idi. Müs-\nlimânların eline esîr düşdü. Kendisi için ve kardeşlerinin oğulları Ukayl ve Nevfel \nbin Hâris için para verip kurtuldular. O sene îmân etdi. En son hicret eden budur. \nMekkenin fethinde ve Huneyn gazâsında Resûlullahın yanında bulundu. 32 [m. \n652] senesinde seksensekiz yaşında vefât etdi. Bakî’de medfûndur. Uzun boylu, \nbeyâz ve güzel idi. Abbâsî halîfeleri hazret-i Abbâsın soyundandır. Abbâsî devleti-\nnin bayrağının rengi siyâh idi. Me’mûn yeşile çevirdi. (Eshâb-ı Kirâm) kitâbında \ngeniş bilgi vardır.", "gectigiMaddeler": ["1/31", "1/84", "1/95", "1/97", "2/17", "2/23", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abduh", "slug": "abduh", "unvan": "", "kategori": "diger", "biyografi": "Muhammed Abduh, islâm âlimlerinin büyüklüğünü, üstünlüklerini \nanlıyamıyan bir din adamıdır. Kâhire mason locası reîsi olan Cemâleddîn-i Efgânînin \n(din adamı perdesi altında islâmı içerden yıkmak) propagandalarına aldanmışdır. \n1265 [m. 1849] de Mısrda tevellüd, 1323 [m. 1905] de vefât etdi. (Fâideli Bilgiler) kitâ-\nbında Abduh hakkında geniş bilgi verilmişdir. 195.ci sırada Cemâleddîn ismine bakı-\nnız!", "gectigiMaddeler": ["2/17", "2/71", "3/19", "3/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdül'azîm-i Münzirî", "slug": "abdulazim-i-munziri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâfız \nAbdül’azîm-i Münzirî Kayrivânî, Mısrlıdır. Şâfi’î mezhebindendir. 581 [m. 1185] \nde tevellüd, 656 [m. 1258] de vefât etdi. (Ettergîb vetterhîb) hadîs kitâbı çok kıy-\nmetlidir. Türkçe tercemesi, yedi cild hâlinde, İstanbulda (Hikmet Kitâbevi) tara-\nfından m.1993 de neşr edilmişdir.", "gectigiMaddeler": ["1/79", "2/5", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdül'azîz Hân", "slug": "abdulaziz-han", "unvan": "", "kategori": "diger", "biyografi": "Osmânlı pâdişâhlarının otuzikincisi ve islâm halîfe-\nlerinin doksanyedincisidir. Sultân ikinci Mahmûdun ikinci oğludur. 1245 [m. 1830] \nde tevellüd edip, 25 Hazîran 1277 [m. 1861] de halîfe oldu. 1288 [m. 1871] de tram-\nvay işletdi. 1292 [m. 1875] de galata tünelini yapdırdı. 1293 [m. 1876] de Dolma-\nbağçe serâyından alınıp, Topkapı serâyına habs edildi. Birkaç gün sonra Midhat \npâşa ve serasker [savunma bakanı] Hüseyn Avnî pâşa ve arkadaşları tarafından, \nFer’ıyye serâyında Kur’ân-ı kerîm okurken bilek damarları kesdirilerekşehîd edil-\ndiği, sultân Vahîdeddînin baş kâtibi Alî Fuad beğin hâtıralarında yazılıdır. Fer’ıyye \nserâyı, Beşiktaş ile Ortaköy arasında, Galata-serây lisesinin orta kısmı olan yalıdır. \nSultân Mahmûd türbesindedir. Sultân Murâd, bu ölümü işitince, korkudan aklı \nbozuldu. (Eshâb-ı\n Kirâm) kitâbında Abdül’azîz ismine bakınız! Vâlidesi Pertevni-\nyal Vâlide Sultân olup, İstanbulda Akserâyda bir mescid ve bir mekteb yapdırmış-\ndır. Kabri mescidin yanındadır.", "gectigiMaddeler": ["1/28"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdül'azîz-i Dehlevî", "slug": "abdulaziz-i-dehlevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şâh Abdül’azîz \nGulâm Halîm-i Fârûkî Dehlevî, 1159 [m. 1745] da Delhîde tevellüd, 1239 [m. 1824] \nsenesinde orada vefât etdi. Hind âlimlerinin büyüklerindendir. Meşhûrşâh Veliyyul-\nlah Ahmed Sâhib Dehlevînin oğludur. Derin hadîs âlimidir. Çok kitâb yazdı. Eserle-\nrinin en kıymetlisi (Tuhfe-i isnâ aşeriyye)dir. Fârisî olup, bin sahîfeye yakındır. 1266 \n[m. 1849] senesinde Delhîde basılmışdır. İstanbul Üniversite ve Süleymâniyye ve Bur -\nsa kütübhânelerinde vardır. Yeniden tab’ edilerek, m.1988 de, Hakîkat Kitâbevi ta -\n– 1059 –\nrafından neşr edilmişdir. Şî’î adındaki kimselerin yanlış yazılarına vesîkalarla cevâb \nvermekdedir. 1227 [m. 1811] senesinde, Hindistânda hâfız Muhammed bin Muhyid-\ndîn Eslemî tarafından arabîye terceme edildi. Bu arabîyi Irâk âlimlerinden Ebülfevz \nMuhammed Emîn bin Alî Süveydî ve ayrıca seyyid Mahmûd Şükri Âlûsî 1301 [m. \n1883] de arabî olarak kısaltmışlardır. (Muhtasar-ı Tuhfe) adındaki ikincisi, 1315 [m. \n1896] de Bombayda ve 1373 [m. 1953] de Kâhirede ve 1396 [m. 1976] da, ofset yolu \nile İstanbulda basıldı. Bekara sûresinin yüzseksendördüncü âyetine kadar ve yirmi-\ndokuzuncu ve otuzuncu cüz’lerin fârisî tefsîri olan (Tefsîr-i Azîzî) si de çok kıymet-\nlidir. 1386 [m. 1966] da Kâbilşehrinde basılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdül'azîz-i Dehlevî", "slug": "abdulaziz-i-dehlevi-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şâh Abdül’azîz \nGulâm Halîm-i Fârûkî Dehlevî, 1159 [m. 1745] da Delhîde tevellüd, 1239 [m. 1824] \nsenesinde orada vefât etdi. Hind âlimlerinin büyüklerindendir. Meşhûrşâh Veliyyul-\nlah Ahmed Sâhib Dehlevînin oğludur. Derin hadîs âlimidir. Çok kitâb yazdı. Eserle-\nrinin en kıymetlisi (Tuhfe-i isnâ aşeriyye)dir. Fârisî olup, bin sahîfeye yakındır. 1266 \n[m. 1849] senesinde Delhîde basılmışdır. İstanbul Üniversite ve Süleymâniyye ve Bur -\nsa kütübhânelerinde vardır. Yeniden tab’ edilerek, m.1988 de, Hakîkat Kitâbevi ta -\n– 1059 –\nrafından neşr edilmişdir. Şî’î adındaki kimselerin yanlış yazılarına vesîkalarla cevâb \nvermekdedir. 1227 [m. 1811] senesinde, Hindistânda hâfız Muhammed bin Muhyid-\ndîn Eslemî tarafından arabîye terceme edildi. Bu arabîyi Irâk âlimlerinden Ebülfevz \nMuhammed Emîn bin Alî Süveydî ve ayrıca seyyid Mahmûd Şükri Âlûsî 1301 [m. \n1883] de arabî olarak kısaltmışlardır. (Muhtasar-ı Tuhfe) adındaki ikincisi, 1315 [m. \n1896] de Bombayda ve 1373 [m. 1953] de Kâhirede ve 1396 [m. 1976] da, ofset yolu \nile İstanbulda basıldı. Bekara sûresinin yüzseksendördüncü âyetine kadar ve yirmi-\ndokuzuncu ve otuzuncu cüz’lerin fârisî tefsîri olan (Tefsîr-i Azîzî) si de çok kıymet-\nlidir. 1386 [m. 1966] da Kâbilşehrinde basılmışdır.", "gectigiMaddeler": ["2/17", "2/71", "3/27", "3/55", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdül'azîz bin Sü'ûd", "slug": "abdulaziz-bin-suud", "unvan": "", "kategori": "diger", "biyografi": "Sü’ûd oğullarından iki Abdül’azîz vardır. \nBirincisi Abdül’azîz bin Muhammed bin Sü’ûd olup, 1134 [m. 1721] de tevellüd, \n1217 [m. 1802] de Der’ıyye câmi’inde birşî’î tarafından hançerle öldürüldü. 1178 [m. \n1765] de vehhâbîlerin ikinci reîsi oldu. 1217 [m. 1802] de Tâifde Ehl-i sünnet âlimle-\nrini ve kadın, çocuk, binlerce müslimânı katl etdi. Açlıkdan ölenler de çokdu. \nİkincisi, Abdül’azîz bin Abdürrahmân bin Faysal olup, 1297 [m. 1880] de Rıyâd-\nda tevellüd, 1372 [m. 1953] de vefât etdi. Sü’ûdî hükûmetinin ondokuzuncu reîsi-\ndir. Birinci cihân harbinde İngilizlerle birlikde Osmânlılara karşı harb etdi. O \nzemân Necdde bundan başka, ibn-ür-Reşîd kabîlesi de vardı. İbn-ür-Reşîd, \nOsmânlılara sâdık kalıp, Türklerle birlikde İngilizlere ve Sü’ûd oğullarına karşı \nharb etdi. Sulh oldukdan sonra, Abdül’azîz, İbn-ür-Reşîdi öldürtdü. 13 Ramezân \n1338, 1 Hazîran 1920 târîhli İstanbul gazetelerindeşu haber okundu: \n(Arabistânın başlıca iki hâkiminden biri olan Necd emîri İbn-ür-Reşîdin öldü-\nrüldüğünü on Mayıs târîhli The Times gazetesi yazmışdır. Harb esnâsında İbn-ür-\nReşîd Türkiye ile işbirliği yapmışdı. İbn-üs Sü’ûd ise, İngilizlerle birlikde İbn-ür-\nReşîde ve Türklere karşı harb etmişdi.) 1337 [m. 1919] ilk ayları\nnda Kuwaitden \nRiyâda gelerek vehhâbîlerin başına geçdi. 1342 [m. 1924] de İngilizler Tâifi ve \nMekkeyi, şerîf Hüseyn efendiden alarak, buna verdiler. 1351 [m. 1932] de Sü’ûdî \nhükûmeti kurmasını sağladılar. 9 Eylül 1926 da İstanbulda çıkan Son Sâat gazetesişu haberi vermişdi:  \nMEDÎNE BOMBARDIMANI \nAbdül’azîz tarafından Medîne-i münevverenin bombardıman edilmesi, Hindis-\ntân halkı arasında galeyân yapdığını yazmışdık. Hindistânda çıkan (The Times of \nIndia) diyor ki: Son zemânlarda Medîneye hücûm ve Kabr-i Nebevîyi bombardı-\nman haberlerinin Hind müslimânlarında husûle getirdiği te’sîri hiçbir hâdise vücû-\nde getirmemişdir. Hindistânın her tarafında bulunan müslimânlar, bu hâdise dola-\nyısı ile o makâm- ı mukaddese ne derece hurmetkâr olduklarını göstermişlerdir. \nHindistânda ve Îrândaki bu mühim teessürât, hiçşübhesiz İbni Sü’ûd üzerinde \nte’sîr yapacak ve onu bütün İslâm memleketlerinin nefretini kazanmamak için, \nböyle hareketlerde bulunmakdan men’ edecekdir. Hind müslimânları, İbn-üs-\nSü’ûde bu fikrlerini açıkça bildirmişlerdir.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülbehâ Abbâs", "slug": "abdulbeha-abbas", "unvan": "", "kategori": "diger", "biyografi": "Behâullahın büyük oğludur. Bu da zındık idi. Sultân \nHamîd hân, hal’ oluncaya kadar Akkada habs edildi. Hayfaya yerleşdi. Mısr, Avrupa \nve Amerikaya giderek Behâîliği yaydı. 1339 [m. 1921] da öldü. Hayfaya gömüldü. \nBâbın kemikleri de Îrândan buraya getirildi. Yerine, oğlu Şevkî geçdi.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdül Ehad", "slug": "abdul-ehad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Rabbânînin babası-\ndır. [927] de tevellüd etdi. Genç iken, Hindistânın büyük Evliyâsından olan Ab -\ndülkuddüs “kuddise sirruh” hazretlerinin sohbetinde bulundu. İlm öğrenmesini emr \netdi. Tahsîlden dönünce, hocası [944] de ölmüşdü. Oğlu olan Rükneddîn-i Çeştî \n“kuddise sirruh” hazretlerinin sohbetinde yetişdi. Kâdirî ve Çeştî yolunda kemâle \nerdi. Seksen yaşında iken 1007 [m. 1598] senesinde vefât etdi. Serhendşehri dı -\nşındaşimâl tarafında medfûndur. Yedi oğlu vardı. Dördüncüsü, İmâm-ı Rabbânî \n– 1060 –\nhazretleri idi.", "gectigiMaddeler": ["1/41", "3/47", "3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülfettâh-ı Bağdâdî Akrî", "slug": "abdulfettah-i-bagdadi-akri-rahmetullahi-teala-al", "unvan": "", "kategori": "alim", "biyografi": "Hâlid-i Bağdâdînin talebelerindendir. Senelerce İstanbul halkını irşâd etdi. Binikiyüzseksenbir 1281 [m. 1865] Muharrem ayının dokuzuncu Cum’a günü vefât etdi. Üsküdârda Eski vâlide câmi’inden Karaca-Ahmed mezârlığına çıkan yol ile (Selîmiye-Bağlarbaşı) caddesinin kesişdiği köşedeki, Şeyh-ul-islâm Ârif Hikmet beğin kabristânındadır. Ârif Hikmet beğ yüzbeşincişeyh-ul-islâm olup, 1275 [m. 1858] de vefât etmişdir. Dedesi vezîr İsmâ’îl Râif pâşa ile, babası kadı-asker İsmet efendi de bu kabristândadır. Medînede, büyük kütübhâne yapdırmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülganî Nablüsî", "slug": "abdulgani-nablusi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası İsmâ’îl \nNablüsîdir. 1050 [m. 1640] de Şâmda tevellüd, 1143 [m. 1731] de vefât etdi. Şâmda-\ndır. Fıkh, tefsîr ve hadîs ilmlerinde ve tesavvufda çok derin âlim idi. Alâüddîn \nAttârın “kuddise sirruh” rûhâniyyetinden de feyz aldı. İstanbulda, Mısrda ve \nHicâzda da ders verdi. Yüzden fazla değerli kitâb yazdı. (Hadîka) kitâbı, Birgivînin \n(Tarîkat-i Muhammediyye)sininşerhıdir. (Keşf-ün-nûr an eshâb-il-kubûr) kitâbın-\nda, Tâcüddîn-i Hindînin, râbıtayı isbât eden (Tâciyye) risâlesine yapdığışerhde, \nEvliyânın öldükden sonra da kerâmet sâhibi olduklarını ve rûhlarından istigâse ve \nistifâde edileceğini çok güzel anlatmakdadır. Birinci kitâb, Süleymâniyye kütübhâ-\nnesinde (Es’ad efendi)  kısmında [3601] sayı ile mevcûddur. (Hulâsat-üt-tahkik) \nkitâbı, mezheblerin birleşdirilemiyeceğini isbât etmekdedir. (Keşf-ün-nûr) ve \n(Hülâsat-üt-tahkîk) kitâbları, Hakîkat Kitâbevi tarafından yeniden tab’ edilmişdir. \nŞâm matba’asında ilk basılan, bunun (Evrâd) kitâbıdır.", "gectigiMaddeler": ["1/70", "2/5", "2/16", "2/17", "2/21", "2/43", "2/52", "3/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhak-ı Dehlevî", "slug": "abdulhak-i-dehlevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Seyfed-\ndîndir. Hindistânın büyük âlimlerindendir. 958 [m. 1551] de tevellüd, 1052 [m. \n1642] de vefât etdi. Muhammed Bâkî-billahın talebelerindendir. Hicâzda hadîs \nâlimi oldu. Delhîdedir. Çok kitâb yazdı. (Medâric-ün-nübüvve) ve (Merec-ül-bah-\nreyn) ve (Eşi’at-ül-leme’ât) ismindeki (Mişkât) şerhı kitâbları fârisî olup, Hindis-\ntânda basılmışdır.", "gectigiMaddeler": ["1/74", "1/79", "1/84", "1/85", "2/10", "2/17", "2/18", "2/52", "2/73"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhak-ı Sücâdil Serhendî", "slug": "abdulhak-i-sucadil-serhendi-rahmetullahi-teala-a", "unvan": "", "kategori": "alim", "biyografi": "Muhammed Ma’sûm-i Fârûkînin yetişdirdiği büyüklerdendir. Urvetül-vüskâ Muhammed Ma’sûmu gasl etdi. Fârisî (Şerh-ı Vikâye) ve (Mesâil-işerh-ı Vikâye) fıkh kitâbları meşhûr olup, her ikisi de Hindistânda basılmışdır.", "gectigiMaddeler": ["1/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhakîm Efendi", "slug": "abdulhakim-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Zâhir ve bâtın ilm-\nlerinde kâmil ve dört mezhebin de fıkh bilgilerinde mâhir, veliy-yi kâmil idi. Rûh \nbilgilerinin mütehassısı idi. Binikiyüzseksenbir 1281 [m. 1865] senesinde Van vilâye-\ntinin Başkaleşehrinde tevellüd, 1362 [m. 1943] de, Eyyûbde Murtedâ efendi tekkesi \ncâmi’i imâmı iken, tevkîf edilip, Ankarada vefât etdi. Bağlumda medfûndur. Babası \nseyyid Mustafâ, seyyid Tâhâ-i Hakkârînin “kuddise sirruh” oğlu olan, seyyid Ubey-\ndüllahın talebesi idi. Seyyid Mustafâ çok kâmil idi. Gördüğü kimsenin, hangi nemâzı \nkılmadığını, yüzünden anlardı. Bunun babası, seyyid Muhyiddîndir. Onun babası, \nseyyid Muhammed, bunun babası da, seyyid Abdürrahmândır. İmâm-ı Alî Rızâ bin \nMûsâ Kâzım soyundan olup, Seyyid oldukları, Irâkdakişer’î mahkeme defterlerinde \nyazılı olduğu gibi, seyyid Abdülkâdir-i Geylânînin torunu olan seyyid Abdürrezza-\nkın mübârek el yazısı ile de tasdîk edilmiş olduğu, Van mebûsu İbrâhîm Arvâsın \n1371 [m. 1952] de basdırdığı (Seyâhatnâme-i Kâsım-ı Bağdâdî) kitâbında yazılıdır.", "gectigiMaddeler": ["1/17", "1/25", "1/27", "1/36", "1/54", "1/68", "1/71", "1/74", "1/77", "1/83", "1/95", "1/97", "1/98", "2/4", "2/5", "2/17", "2/21", "2/29", "2/35", "2/40", "2/43", "2/45", "2/46", "2/50", "2/52", "2/53", "2/54", "2/59", "3/3", "3/21", "3/34", "3/37", "3/53", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhakîm-i Siyalkûtî", "slug": "abdulhakim-i-siyalkuti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Rab-\nbânî hazretlerinin sınıf arkadaşı idi. Hocaları mevlânâ Kemâleddîn-i Kişmîrî idi. Ba -\n– 1061 –\nbası Şemseddîn Muhammeddir. 1067 [m. 1656] senesinde, Siyâlkütşehrinde vefât \netdi. Hanefî fıkh ve kelâm âlimidir. (Beydâvî)ye hâşiyesi, Sa’deddîn-i Teftâzânînin \n(Şerh-ı akâ’id)ine hâşiyesi ve Ahmed Hayâlînin Teftâzânîşerhıne yapdığı hâşiyenin \nde (Siyalkûtî hâşiyesi) ve Teftâzânînin (Mevâkıfşerhı)ne ve (Mutavvel) adındaki \nBeyân ve Me’ânî kitâbına hâşiyesi ve (Ed-Dürret-üssemîne fî-isbât-il-vâcib-i teâlâ) \nkitâbı meşhûrdur. 864. cü isme bakınız!", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhâlık-ı Goncdüvânî", "slug": "abdulhalik-i-goncduvani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Vilâyet \nyolunun rehberlerindendir. İslâm âlimlerinin büyüklerindendir. Buhârâda Gonc-\ndüvân köyünde tevellüd ve 575 [m. 1180] de orada vefât etdi. Yirmiiki yaşında iken \nBuhârâda Yûsüf-i Hemedânî hazretlerinin sohbetinde kemâle geldi. İmâm-ı Mâlik \nsoyundandır. Babası Abdülcemîl, Malatyalı idi. Hızır aleyhisselâmdan ders aldı. \nTesavvufda meşhûr olan (Onbir temel kelime) Abdülhâlık Goncdüvânînin sözle-\nrindendir. (Vasıyyetnâme) kitâbında diyor ki, (Sana vasıyyet eylerim ey oğul ki, \nher hâlinde ilm ve edeb ve takvâ üzere ol! İslâm âlimlerinin kitâblarını oku! Fıkh \nve hadîs öğren! Câhil tarîkatcılardan sakın! Şöhret yapma! Şöhretde âfet vardır. \nÇok simâ’ eyleme! Çok simâ’, kalbde nifak yapar, kalbi öldürür. Simâ’ ı inkâr da \netme ki, büyüklerin çoğu simâ’ yapmışlardır. Arslandan kaçar gibi, câhillerden \nkaç! Bid’at sâhibi, sapıklar ile ve dünyâya düşkün olanlar ile arkadaşlık etme! \nHalâldan yi! Çok gülme! Kahkaha ile gülmek, gönlü öldürür. Herkese, şefkat ve \nmerhamet et! Kimseyi hakîr görme! Kimse ile münâkaşa, mücâdele etme! Kimse-\nden birşey isteme! Tesavvuf büyüklerine dil uzatma! Onları inkâr eden felâkete \ndüşer. Mayan fıkh ve evin mescid olsun!) Pencere camı bunun zemânında keşf \nedildi.", "gectigiMaddeler": ["3/51", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhamîd Hân I", "slug": "abdulhamid-han-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlı pâdişâhla-\nrının yirmiyedincisi ve islâm halîfelerinin doksanikincisidir. Sultân üçüncü Ahme-\ndin oğlu, sultân dördüncü Mustafâ ile, sultân ikinci Mahmûdun babalarıdır. 1137 \n[m. 1725] de tevellüd etdi. 1187 [m. 1773] de halîfe oldu. 1203 [m. 1789] de vefât \netdi. Sirkecide, dördüncü vakf hânı karşısında, köşedeki türbededir. Oğlu dördün-\ncü Mustafâ hân da bu türbededir. Türbede, Yeni câmi’ tarafındaki dıvardaki dola-\nba yerleşdirilmiş taşda Resûlullahın mubârek ayaklarının izleri mevcûddur. Türbe \nyanındaki ince san’atlı olan sebili, cumhûriyyet devrinde Gülhâne parkı kapısı kar-\nşısına nakl edilmişdir. Yerine üçüncü Selîm hân geçdi. Vâlidesi Râbi’a sultânın \nrûhu için, [1192] de, Beğlerbeğinde, deniz kenârında, bir minâreli câmi’ yapdırdı. \nİkinci minâresini sultân Mahmûd yapdırdı. Emîrgân câmi’ini de birinci Abdülha-\nmîd hân yapdırmışdır. Eski ismi Emîrgün idi. Çünki, dördüncü Murâd hân Revân \n[Erivan] kal’asını feth edince, kal’a kumandanı Mirgün oğlu, afv diledi. Kabûl edi-\nlip, şî’îlik propagandası yapmamakşartı ile, pâşalık rütbesi ve ayrıca Emîrgânda \nbir serây kendine verildi. Mirgün oğlu burada kaldı. Fekat, sultân Murâd vefât \nedince, yerine geçen kardeşi, sultân İbrâhîm hân zemânında, kızılbaşlık propagan-\ndasına başlayıp, müslimânları aldatdığı görülünce, başı kesildi. Halk arasında \nkesikbaş denilen mezârda, işte bu hurûfî babası yatmakdadır. Hurûfîler ve mülhîd-\nler, bundan dolayı sultân İbrâhîme düşman oldular. Bu mubârek Türk sultânına \ndeli İbrâhîm dediler. Gençler de, bu yalana ve uydurma hikâyelere inanıyor. Bu \ntemiz sultâna ve afîfe zevcesi Turhân sultâna bilmiyerek dil uzatıyorlar. Sultân \nİbrâhîm, amcası Mustafâ hânın Ayasofyadaki türbesindedir. Emîrgân korusuşimdi belediyenin olup halk için umûmî bağçedir. 850 dönüm olup Mısr Hidîvi \nİsmâ’îl pâşanın bağçesi idi. Köşkü, tepededir. İsmâ’îl pâşa, İbrâhîm pâşanın oğlu \nolup, 1246 [m. 1830] da tevellüd ve 1313 [m. 1895] de vefât etdi. 1279 [m. 1863] da \nhidîv oldu. 1296 [m. 1879] da azl edildi. Yerine oğlu Tevfîk pâşa geçdi. Bu, yirmialtı \nyaşında idi. İngilizler bunun zemânında Mısrın idâresine karışdı. 1309 [m. 1892] da \nvefât etdi. Yerine oğlu Abbâs Hilmi pâşa geçdi. Onsekiz yaşında idi. Çubukludaki \nköşk ve koru bunun idi. Bunun yerine, 1332 [m. 1914] de İsmâ’îl pâşanın oğlu \n– 1062 –\nHüseyn Kâmil pâşa geçip, ittihâdcılara karşı oldu. 1335 [m. 1917] de Mısrda vefât \netdi. Yerine kardeşi Ahmed Füâd geçip, 1340 [m. 1922] da, türklerden ayrılarak, \ndevlet reîsi demek olan melik adını aldı. 1354 [m. 1936] de vefât etdi. Yerine oğlu \nFârûk melik oldu ise de, 1371 [m. 1952] de, askerî ihtilâl olarak yurd dışına çıkarıl-\ndı.", "gectigiMaddeler": ["1/84"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhamîd Hân II", "slug": "abdulhamid-han-ii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlı pâdişâhla-\nrının otuzdördüncüsü ve islâm halîfelerinin doksandokuzuncusudur. Sultân Abdül-\nmecîd hânın ikinci oğludur. 21 Eylül 1258 [m. 1842] de tevellüd, 10 Şubat 1336 [m. \n1918] da Beğlerbeği serâyında vefât etdi. Çenberlitaşda, dedesi sultân ikinci Mah-\nmûdun türbesindedir. Sultân Abdül’azîz hânışehîd eden Midhat pâşa ve arkadaş-\nları 30 Mayıs 1293 [m. 1876] günü serây hazînesini ve sultân Azîz hânınşahsî ser-\nvetini de yağma etdikden sonra, sultân Abdülmecîdin Şevk-efzâ vâlide sultândan \nolan birinci oğlu beşinci Murâdı o gün halîfe yapdılar. Otuzaltı yaşında idi. Beş gün \nsonra, 4 Hazîran 1293 [m. 1876] de sultân Abdül’azîz Fer’ ıyye serâyındaşehîd edi-\nlince, sultân Murâdınşü’ûru bozuldu. Üç ay ve bir gün süren saltanatından sonra, \n31 Ağustos günü tahtdan indirildi. Çırağan serâyına götürüldü. Yirmisekiz sene \ndahâ burada yaşadı. 29 Ağustos 1322 [m. 1904] de vefât edince, Eminönünde Tur-\nhân vâlide sultân türbesine defn edildi. 11 Şa’bân 1293 ve 31 Ağustos 1876 da ikinci \nAbdülhamîd hânı halîfe yapdılar ve devlet işlerine karışmaması, yalnız millet mec-\nlisinin çıkaracağı kanûnlara göre hareket etmesi için söz aldılar. (Tanzîmât-i hay-\nriyye)ye sâdık kalacağını bildiren (Kanûn-ı esâsî) yi i’lân etdirdiler. Abdülmecîd \nhânın ikinci oğlu olan sultân Abdülhamîd onbir yaşında iken annesi Tîr-i Müjgân \nikinci kadın efendi vefât etmişdi. Dördüncü kadın efendi Perestu sultân tarafından \nbüyütüldü. Pâdişâh olunca, bunu Valîde sultân i’lân etdi. Büyük kardeşi ile berâber \ntahsîl gördü. Arabca, farsca, fransızca ve dînî ilmlerde çok iyi yetişdirildi. (Türkiye \ntârîhi)nde diyor ki, ( İkinci Abdülhamîd hân, ittihâdcıların propaganda etdikleri \ngibi câhil değil, onların hemen hepsinden dahâ bilgili idi.) Merkezi Selânikde bulu-\nnan üçüncü ordunun genç subayları, İstanbula gelerek, 1327 [m. 1909] de halîfeyi \ntahtından indirip, Selâniğe götürdü. Mâbeyn başkâtibi Es’ad beğ (Hâtırât-ı Abdül-\nhamîd hân) kitâbında, ikinci Abdülhamîd hânın memlekete hizmetlerini uzun yaz-\nmakdadır.", "gectigiMaddeler": ["1/95", "2/1", "2/30", "2/43", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülhayy", "slug": "abdulhayy", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindistânda Safâşehrinden-\ndir. İmâm-ı Rabbânî hazretlerinin sohbetinde yıllarca bulundu. Çok feyzlere \nkavuşdu. Muhammed Ma’sûm hazretlerinin emrleri ile, (Mektûbât)ın ikinci cildini \ntopladı. Tesavvufu âşıklara bildirmek için, Pütneşehrine gönderildi. Orada bulu-\nnanları irşâd eyledi. Velîler, halîfeler yetişdirdi. Kutb olduğu müjdelendi. Abdül-\nhayy Luknevî için 82. ci isme bakınız!", "gectigiMaddeler": ["3/29", "3/50"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülkâdir-i Geylânî", "slug": "abdulkadir-i-geylani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhyiddîn \nEbû Muhammed bin Ebû Sâlih Mûsâ Cengî dost, Îrânın Geylânşehrinde, 471 [m. \n1078] de tevellüd, 561 [m. 1166] de Bağdâdda vefât etdi. Babası hazret-i Hasenin \noğlu Hasen-i müsennânın oğlu Abdüllahın soyundandır. Hazret-i Hüseynin kızı \nFâtımanın Abdüllahın vâlidesi olduğu (Kısas-ı Enbiyâ) da yazılıdır. Bunun için \nAbdülkâdir-i Geylânî, hem seyyid, hem deşerîfdir. Anası Fâtıma binti Ebû \nAbdüllah seyyidedir. Fıkh ve hadîs ilmlerinde müctehid idi. Önceden Şâfi’î mez-\nhebinde idi. Hanbelî mezhebi unutulmak üzere olduğundan, Hanbelî mezhebine \ngeçdi. Böylece, bu mezheb yayıldı. Önceleri ders verirdi. Çok meşhûr oldu. Sonra \ntesavvufa daldı. Cüneyd-i Bağdâdî yolundaki Ebû Sa’îd Alî Mahzûmîden feyz \naldı. \nİnsanı Allahü teâlânın sevgisine kavuşduran yol ikidir: Birisi (Nübüvvet yolu) \nolup, aslın aslına kavuşdurur. Eshâb-ı kirâmın hepsi, bu yoldan vâsıl oldular. Son -\nra gelenlerden pekaz zevât da, bu yoldan ermişdir. Bu yolda sebebe, vâsıtaya lü -\n– 1063 –\nzûm yokdur. Bir kâmil ve mükemmilin sohbetinde kemâle geldikden sonra, feyzi \nasldan alıp ilerlerler. İkinci yol, (Vilâyet yolu)dur. Kutblar, Evtâd, Nücebâ, Büdelâ \nve bütün Evliyâ bu yoldan vâsıl olmuşdur. Bu yola, (Sülûk yolu)  da denir. Bu \nyolda, vâsıta, aracı lâzımdır. Her iki yolun reîsi ve rehberi Resûlullahdır. Vilâyet \nyolunun imâmı, feyz kaynağı, hazret-i Alîdir. Bu yolda, Resûlullah onu vekîl \netmişdir. Hazret-i Fâtıma ve Hasen ile Hüseyn onunla ortakdırlar. Bu yolda giden-\nlerin hepsine feyz ve hidâyet, hazret-i Alînin aracılığı ile gelir. Ondan sonra haz-\nret-i Hasen ve Hüseyn bu vazîfeyi teslîm aldı. Bunlardan sonra, sıra ile, oniki imâ-\nmın evlâdına verildi. Sonları olan Muhammed Mehdîden sonra, başkasına veril-\nmedi. Bütün Evliyâya feyz ve hidâyet bunlardan gelmeğe devâm etdi. Abdülkâdir-i \nGeylânî kemâle gelince, bu mansıb, ona verildi. Bundan sonra da, kimseye veril-\nmediği keşf ve müşâhede ile anlaşılmakdadır. Vefâtından sonra da, kıyâmete \nkadar, herkese, feyz, rüşd ve hidâyet, onun rûhâniyyetinden gelmekdedir. Her \nasrda gelen müceddidler, onun vekîlleridir. İmâm-ı Rabbânî (Nübüvvet yolu) ile \nvâsıl olduğundan, vâsıtaya ihtiyâcları yokdur. Ebû Bekr-i Sıddîk, nübüvvet yolun-\nda Resûlullahın vekîlidir.", "gectigiMaddeler": ["1/27", "1/31", "1/41", "1/50", "1/74", "1/85", "2/17", "2/23", "2/72", "2/73", "3/28", "3/36", "3/37", "3/42", "3/51", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülkerîm", "slug": "abdulkerim", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmdandır. Mu’âviye \n“radıyallahü anh” ın İstanbulu feth etmek için, gönderdiği askerler arasında iken \nhastalanarak, Akyazı ile Pazarköy arasında vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülkerîm-i Râfi'î", "slug": "abdulkerim-i-rafii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Muham-\nmeddir. 623 [m. 1226] de Kazvinde vefât etdi. Şâfi’î âlimlerindendir. (Muharrer) \nadındaki fıkh kitâbı meşhûrdur. Bunu birçok âlimlerşerh etmişdir. İmâm-ı Nev-\nevînin (Minhâc) adındaki muhtasarı çok kıymetlidir. (Minhâc)ı daşerh etmişler-\ndir. Bunların en kıymetlisi İbni Hacer-i Mekkînin (Tuhfe-tül-muhtâc) adındakişerhıdir. Dört cilddir.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülkuddüs", "slug": "abdulkuddus", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Abdüllahdır. \nMuhammed bin Muhammed Ârif Çeştînin ve Derviş Muhammed Sühreverdînin \nhalîfesi, imâm-ı Rabbânînin babası Abdül-Ehad hazretlerinin üstâdı idi. Çok kitâbı \nvardır. Bunlardan (Envârül-uyûn) meşhûrdur. Buyururdu ki, (Hataralar, vesveseler \niki dürlüdür: Birincisi, ibtilâ ve imtihân için gelir. Bunlara günâh, cezâ olmaz. Yük-\nselmeğe sebeb olurlar. İkincisi, sonsuz felâkete sebeb olur.) Oğlu ve halîfesi Rük-\nneddîne yazdığı mektûbda buyuruyor ki, (Vaktin kıymetini bil! Gece gündüz ilm \nöğrenmeğe çalış! Her zemân abdestli bulun! Beş vakt nemâzı, sünnetleri ile ve \nta’dîl-i erkân ile, huzûr ve huşû’ ile ve dînin sâhibinin bildirdiği gibi kılmağa çalış! \nBunları yapınca, dünyâda ve âhıretde, sayısız ni’metlere kavuşursun. İlm öğrenmek, \nibâdet yapmak içindir. Kıyâmet günü, işden sorulacak, çok ilm öğrendin mi diye \nsorulmıyacakdır. İş ve ibâdet de, ihlâs elde etmek içindir. İ\nhlâs da, hakîkî ma’bûd ve \nkaydsız, şartsız var olan sevgiliyi sevmek içindir.) 944 [m. 1538] de, Hindistânda, \nKenkühşehrinde vefât etdi. Hâcı Abdülvehhâb-ı Buhârî bir tefsîr yazmışdı. Abdül-\nkuddüs hazretlerine gönderdi. Bir yerini açınca, Ehl-i beytin temizliğini bildirirken, \n(Fâtıma son nefesinden emîn idi. Onun sonu, elbette hayrlı idi) yazılmış gördü. \nBunun kenârına, (Bu yazı, Ehl-i sünnet mezhebine uygun değildir) yazıp geri gön-\nderdi. Abdülkuddüsün yazısının doğru olduğu anlaşıldı. Hâl tercemesi, 1036 da te’lîf \nve 1336 da tab’ edilen fârisî (Siyer-ül-aktâb) kitâbında yazılıdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah", "slug": "abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Resûlullahın Hadîce-tül-kübrâ-\ndan olan son çocuğudur. Nübüvvetden sonra tevellüd edip, memede iken vefât \netdi. Tayyib ve Tâhir de denilir. Abdüllah vefât edince, Âs bin Vâil (Muhammed \nebter oldu) ya’nî soyu kesildi dedi. (İnnâ a’taynâ) sûresi gelerek, Âs kâfirine Alla-\nhü teâlâ cevâb verdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah Ağa", "slug": "abdullah-aga", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Üçüncü Murâd hânın bos-\ntancı başıdır. 1000 [m. 1591] de Kısıklı câmi’ini yapdırdı. Beğlerbeğindeıstavroz \n– 1064 –\ncâmi’i ve Langada da bir câmi’i vardır. Kabri Kısıklı câmi’inin yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Abbâs", "slug": "abdullah-bin-abbas", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Resûlullahın en \nküçük amcası olan Abbâsın oğludur. Hicretden üç yıl önce Mekkede tevellüd, 68 \n[m. 687] de, Tâifde vefât etdi. Uzun boylu, beyâz, güzel idi.", "gectigiMaddeler": ["1/35", "1/39", "1/61", "1/63", "1/95", "1/96", "1/97", "1/98", "2/5", "2/17", "2/23", "2/24", "2/25", "2/31", "2/41", "2/44", "3/2", "3/3", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Abdülmuttalib", "slug": "abdullah-bin-abdulmuttalib-rahmetullahi-teala-a", "unvan": "", "kategori": "alim", "biyografi": "Muhammed aleyhisselâmın mubârek babasıdır. Babasının onuncu oğludur. Onsekiz veyâ yirmibeş yaşında iken, hazret-i Âmine ile evlendi. Birkaç ay sonra, Medîneye giderken yolda, Resûlullah efendimiz dünyâya gelmeden yedi ay önce vefât etdi. Hazret-i Hamza, Abdüllahdan, hazret-i Abbâs da, Hamzadan dahâ küçük idi.", "gectigiMaddeler": ["1/84", "1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Cahş", "slug": "abdullah-bin-cahs", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın halası Ümey-\nme ile Cahşın oğludur. Zevcât-ı tâhirâtdan Zeyneb binti Cahşın kardeşidir. Habe-\nşe iki kerre hicret etdi. Birkaç kerre ordu kumandanı yapıldı. Bedr gazâsı esîrleri \niçin, Resûlullah hazret-i Ebû Bekre ve Ömere ve buna danışmışdı. Uhuddaşehîd \nolup, dayısı olan hazret-i Hamza ile bir mezâra defn edildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Ebî Evfâ", "slug": "abdullah-bin-ebi-evfa", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmdan, \nKûfeşehrinde, en son vefât eden budur. 86 [m. 705] senesinde vefât etdi.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Faysal", "slug": "abdullah-bin-faysal", "unvan": "", "kategori": "diger", "biyografi": "Terkînin torunudur. 1306 [m. 1888] da \nVehhâbî emîri idi. Babası Faysal zemânında, 1271 [m. 1854] senesinde, Ummâna \nkarşı harb ederek, vergiye bağlamışdı. Medîneşimâlindeki (Hâil)de bulunan \nMuhammed ibnür-Reşîde mağlûb ve esîr oldu.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Hanzala", "slug": "abdullah-bin-hanzala", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Ensâr- ı kirâmın \nbüyüklerindendir. Uhud gazâsından bir yıl sonra dünyâya geldi. [63] yaşında \nAbdüllah bin Zübeyr vak’asında Medînedeşehîd oldu. Babası Hanzala, Uhud \ngazâsına çıkılacağı gece evlenmişdi. Ertesi günşehîd olup, melekler yıkamışdı. \nBunun için (Gasîl-ül-melâike) ismi ileşereflenmişdi.", "gectigiMaddeler": ["3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Kevâ", "slug": "abdullah-bin-keva", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâbi’îndendir. \nDeve vak’asında Alî “radıyallahü anh”ın yanında idi.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Mahmûd", "slug": "abdullah-bin-mahmud", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mecdeddîn-i \nMûsulî denir. Hanefî mezhebi fıkh âlimlerindendir. [599] da tevellüd, 683 [m. 1285] \nde vefât etdi. (Muhtâr) ve bununşerhı olan (İhtiyâr) kitâbları meşhûrdur.", "gectigiMaddeler": ["2/16", "2/40"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Mes'ûd", "slug": "abdullah-bin-mesud", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "İslâma gelenlerin altın-\ncısıdır. Genç iken îmân etdi. Kur’ân- ı kerîmi ve çok hadîs-işerîf ezberledi. İki \nkerre Habeşe ve Medîneye hicret etdi. Bütün gazâlarda ve Yermük muhârebesin-\nde bulundu. Cennetle müjdelendi. 32 [m. 651] senesinde vefât etdi. Bakî’dedir.", "gectigiMaddeler": ["1/41", "1/73", "2/16", "2/17", "2/42", "2/44", "3/3", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Mubârek", "slug": "abdullah-bin-mubarek", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tebe’i \ntâbi’înin büyüklerindendir. Hanefî, hadîs ve fıkh âlimidir. [118] de tevellüd, 181 \n[m. 797] de vefât etdi.", "gectigiMaddeler": ["1/43", "1/63", "2/17", "2/40"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Muhammed Bitûşî", "slug": "abdullah-bin-muhammed-bitusi-rahmetullahi-teala", "unvan": "", "kategori": "alim", "biyografi": "Bağdâdşimâlinde Zûrşehrinde tevellüd ve 1211 [m. 1796] senesinde Basrada vefât etdi. (Hadîkatüs-serâir) kitâbı meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Ömer", "slug": "abdullah-bin-omer", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmın bü -\nyüklerindendir. Hicretden ondört sene önce tevellüd ve 73 [m. 692] senesinde Mek-\nkede vefât etdi. Babası ile birlikde îmân etdi. Çocuk olduğundan en önce Hendek \ngazâsında bulundu. Çok müttekî idi. Hilâfet için, bir tarafa karışmamağa ictihâd \netmişdir. (Kısas-ı Enbiyâ)da, Hayber gazâsını anlatırken diyor ki, (Eshâb- ı kirâm \narasında, en çok hadîs bilen, Abdüllah bin Ömer idi. \nİşitdiklerini yazardı. Ondan \n– 1065 –\nsonra, en çok hadîs bilen, Ebû Hüreyre idi).", "gectigiMaddeler": ["1/62", "1/71", "1/75", "2/17", "2/18", "2/40", "2/44", "2/47", "2/52", "3/2", "3/34", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Sâlih", "slug": "abdullah-bin-salih", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "900. cü sırada, \nTâhâ-yı Hakkârî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Selâm", "slug": "abdullah-bin-selam", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ensâr- ı kirâmın büyükle-\nrindendir. Yehûdî âlimlerinden idi. Fahr-i âlemi “sallallahü aleyhi ve sellem” işi-\ntince, yanına gitdi. Bunu, nübüvvet nûru ile tanıyıp, (Sen Medîne âlimi İbni Selâm \nmısın?) buyurdu ve İhlâs-ışerîf okudu. Abdüllah, hemen (Tevrâtın haber verdiği \nâhır zemân Peygamberi budur) diyerek, îmân etdi. Osmân “radıyallahü anh” \nvak’asında âsîlere çok nasîhat etmişdi. [43] senesinde vefât etdi.", "gectigiMaddeler": ["1/90"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Sü'ûd", "slug": "abdullah-bin-suud", "unvan": "", "kategori": "diger", "biyografi": "Sultân ikinci Mahmûd hân zemânında, [1231] \nde vehhâbî emîri oldu. Ehl-i sünnete çok zulm yapdı. 1233 [m. 1818] de yakalana-\nrak Mısra ve sonra İstanbula getirilip i’dâm edildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Tâhir", "slug": "abdullah-bin-tahir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Me’mûn halîfe \nzemânında Horâsân vâlîsi idi. Onyedi sene adâlet ile idâre edip, 230 [m. 844] da \nNişâpûrda vefât etdi.", "gectigiMaddeler": ["1/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Zeyd", "slug": "abdullah-bin-zeyd", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Tâbi’înin büyüklerin-\ndendir. Ensârdan Zeyd bin Erkamın “radıyallahü anh” oğludur. Babası Zeyd bin \nErkam, küçük olduğundan Uhud gazâsına götürülmemiş, diğer gazâların hepsinde \nhâzır bulunmuşdu. 61 [m. 680] senesinde Kûfede vefât etmişdi.", "gectigiMaddeler": ["1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Zübeyr", "slug": "abdullah-bin-zubeyr", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Aşere-i mübeşşereden olan Zübeyr bin Avvâmın oğludur. Ebû Bekr-i Sıddîkın kızı Esmânın oğludur. Medînede Muhâcirlerden ilk önce dünyâya gelen çocuk budur. Çok cesûr idi. Çok ibâdet ederdi. Tunus muhârebesinin kazanılmasına sebeb olmuşdu. Deve harbinde babası ile birlikde, Âişe “radıyallahü anhüm” yanında idi. Yezîde bî’at etmedi. Hazret-i Hüseynşehîd olunca, Mekkede halîfe oldu. Yezîdin vefâtından sonra da, dokuz sene halîfelik yapdı. Abdülmelikin gönderdiği Haccâc bin Yûsüf tarafından 73 [m. 692] de yetmişüç yaşındaşehîd edildi.", "gectigiMaddeler": ["1/59", "3/4", "3/68"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah bin Zübeyr", "slug": "abdullah-bin-zubeyr-2", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Abdül-Muttalibin \noğlu Zübeyr, babası hayâtda iken vefât etdi. Oğlu Abdüllah îmâna gelip, Huneyn \ngazâsında Resûlullahın yanından hiç ayrılmadı. Hazret-i Ebû Bekr zemânında \nFilistinde (Ecnâdeyn) muhârebesinde çok kahramânlık gösterip, şehîd oldu. \nCesedini on rum ölüsü arasında buldular. Hepsini bunun öldürdüğü anlaşıldı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah Bosnevî", "slug": "abdullah-bosnevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah Abdî bin \nMuhammed, Bayrâmiyye meşâyıhinden olup, 1054 [m. 1645] de Konyada vefât \netdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah Hâ Şimî", "slug": "abdullah-ha-simi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ürdün Emîri idi. \nŞerîf Hüseynin oğludur. 1299 [m. 1882] da tevellüd, 1370 [m. 1951] de mesciddeşehîd edildi. Yerine oğlu Talâl geçdi ise de, [m. 1953] de yerini oğlu Hüseyne terk \netdi. Emîr Hüseyn 1354 [m. 1936] de tevellüd etdi. Ürdün devletini çok iyi idâre \netmişdir. Komünist komandolarla mücâdele edip zafer kazanmışdı. m. 1999 da \nvefât etmişdir.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Dârimî", "slug": "abdullah-i-darimi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İkiyüzdokuzuncu \n[209. cu] sırada, Dârimî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Dehlevî", "slug": "abdullah-i-dehlevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyiddir. Babasışâh Abdüllatîf, rü’yâda hazret-i Alînin emri ile adını Alî koymuşdur. Kendisi Gu -\nlâm-ı Alî yapdı. Tesavvuf mütehassıslarının büyüklerindendir. Müslimânların göz-\nbebeğidir. 1158 [m. 1744] de Hindistânın Pencâbşehrinde tevellüd, 1180 [m. 1765] \nde, Mazher-i Cân- ı Cânân ile teşerrüf eyledi. Çok kerâmetleri görüldü. En büyük \nkerâmeti, gelen sâdık kimselerin kalblerine bir teveccüh ederek feyz ve bereketle \n– 1066 –\ndoldururdu. Binlerce âşıkı, bir bakışda cezbelere ve vâridât-i ilâhiyyeye kavuşdu-\nrurdu. 1240 [m. 1824] da Delhîde vefât eyledi. Şâhcihân câmi’i yakınındaki kendi \nDergâhında, çok san’atle yapılmış mermer dıvâr içinde üstâdının yanında ve onun \ngarb tarafında medfûndur. Çeşidli memleketlere göndermiş olduğu mektûblarından \nyüzyirmibeş adedi talebelerinden Rauf Ahmed müceddidî tarafından toplanarak \n(Mekâtib-işerîfe) ismi verilmiş ve önce 1334 [m. 1915] senesinde Madrasda ve sonra \nbinüçyüzyetmişbir 1371 [m. 1951] senesinde Lâhorda ve 1396 [m. 1976] senesinde, \nİstanbulda, basılmışdır. Şâh Rauf Ahmed, bir sene içinde işitdiklerini de bir kitâb \nhâlinde toplamış, buna (Dürr-ül-me’ârif) ismini vermişdir. 1394 [m. 1974] senesinde \nİstanbulda yeniden tab’ edilmişdir. Rauf Ahmed, İmâm-ı Rabbânînin küçük oğlu \nMuhammed Yahyâ soyundan olup, 1253 [m. 1837] de hacca giderken, Yemende, \ndenizdeşehîd oldu. Behûpalşehrinde irşâd ile meşhûr idi.", "gectigiMaddeler": ["2/17", "2/21", "2/52", "2/71", "2/72", "2/73", "3/3", "3/37", "3/51", "3/53", "3/55", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Ensârî", "slug": "abdullah-i-ensari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası, Muham-\nmed bin Alîdir. 396 [m. 1005] da Hirâtda tevellüd, 481 [m. 1088] de orada vefât \netdi. Şeyh-ul-islâm idi. Hanbelî idi. (Te’arrüf) kitâbınaşerhı ve (Menâzil-üs-sâyi-\nrîn) kitâbı meşhûrdur.", "gectigiMaddeler": ["1/41", "1/78", "2/61", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Kurtubî", "slug": "abdullah-i-kurtubi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "551. ci sırada \nKurtubî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Nesefî", "slug": "abdullah-i-nesefi", "unvan": "", "kategori": "diger", "biyografi": "717. ci sırada Nesefî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Rûmî", "slug": "abdullah-i-rumi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yeni-şehrli Abdüllah \nefendi, 1130 [m. 1717] daşeyh-ul-islâm oldu. Buğaziçinde Kanlıcada 1156 [m. \n1743] senesinde vefât etdi. Kanlıcada, İskender pâşa câmi’i yanındadır. (Behce-tül-\nfetâvâ) fetvâ kitâbının sâhibidir.", "gectigiMaddeler": ["1/79", "1/97", "1/98", "2/21", "2/30", "2/39", "3/19", "3/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllah-i Tercümân", "slug": "abdullah-i-tercuman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Akdenizde Bale-\nar adalarının büyüğü olan Mayorka adasında bir hıristiyanın tek çocuğudur. Asl ismi \nAnselmo Turmeda olup bir İspanyol papası idi. Nebuniyeşehrinde, en meşhûr papas \nolan Nikola Mertilin yanında yetişdi. İncîli ezberledi. Bu papasın yol göstermesi ile \nTunusa geldi. Müslimân oldu. Arabcayı ve islâm ilmlerini iyi öğrendi. Hıristiyanlığın \niç yüzünü, nasıl bozulduğunu gösteren (Tuhfe-tül-erîb) adında bir kitâb yazdı. Kitâbı \n823 [m. 1420] de temâmladı. 1290 [m. 1873] da Londrada ve (Elmünkız) kitâbı ile bir-\nlikde 1402 [m. 1981] de Hakîkat Kitâbevi tarafından, İstanbulda basdırılmışdır. Hâcı \nZihnî efendi türkçeye çevirdi. Oğlu Abdül-Halîm, bu kitâbı arabca kısaltmışdır. Yaz-\nması Berlin kütübhânesindedir. Türkçesi, Osmânlılar zemânında İstanbulda basıldığı \ngibi, lâtin harfleri ile, 1385 [m. 1965] de tekrâr basdırılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdüllatîf-i Harpûtî", "slug": "abdullatif-i-harputi", "unvan": "", "kategori": "diger", "biyografi": "1330 [m. 1912] senesinde İstanbul Dâr-ül-\nfünûnunda (İlm-i kelâm)  mu’allimi [profesörü] idi. (Tenkîh-ul kelâm)  adındaki \nkitâbında, islâm dînini ilm, akl ve fen ile çok güzel müdâfe’a etmekdedir.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülmecîd Hân", "slug": "abdulmecid-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlı pâdişâhları-\nnın otuzbirincisi ve islâm halîfelerinin doksanaltıncısıdır. Sultân ikinci Mahmûdun \noğludur. Sekiz oğlundan dördü pâdişâh oldu. 1237 [m. 1821] de doğdu. 1255 [m. \n1839] de pâdişâh oldu. 24 Hazîran 1277 [m. 1861] de vefât etdi. Sultân Selîm câmi’i \nbağçesindedir. Dolmabağçe serâyını ve galata köprüsünü yapdırdı. (Eshâb-ı kirâm) \nkitâbında geniş bilgi vardır.", "gectigiMaddeler": ["2/30", "2/48", "2/52", "3/12"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülmesîh", "slug": "abdulmesih", "unvan": "", "kategori": "diger", "biyografi": "Resûlullah “sallallahü aleyhi ve sellem” efendimize süâl \nsormak için Necrandan gelen hıristiyanların reîsi idi.", "gectigiMaddeler": ["1/92", "1/93"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülmuttalib", "slug": "abdulmuttalib", "unvan": "", "kategori": "diger", "biyografi": "İsmi Şeybedir. Resûlullah “sallallahü aleyhi ve sel-\nlem” efendimizin dedesidir. Kureyş kabîlesinin reîsi idi. Hâşimin oğludur. Amcası \nMuttalib, Mekkelilere bunu, kölesi olarak tanıtdığı için, Abdülmuttalib ismi ile \n– 1067 –\nşöhret bulmuşdur. Hazret-i İsmâ’îlden kalmış olan zemzem kuyusu, Cürhüm \nhükûmeti zemânında gayb olmuşdu. Bu kuyuyu bularak temizletdi. Oniki oğlu ve \naltı kızı vardı. En büyükleri Ebû Tâlib, en küçükleri Abbâs idi. Abdüllah, Resûlul-\nlahın tevellüdünden yedi ay önce vefât etdiği için, Resûlullah “sallallahü aleyhi ve \nsellem” dedesinin yanında büyüdü. Sekiz yaşında iken dedesi de vefât etdi. İsmâ’îl \naleyhisselâmın dînine göre ibâdet ederdi.", "gectigiMaddeler": ["1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdülvehhâb-i Şa'rânî", "slug": "abdulvehhab-i-sarani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Aliy-yül-\nHavâsın talebesidir. 973 [m. 1565] de vefât etdi. Dört mezhebin fıkh bilgilerini \nanlatan (Mîzân-ül-kübrâ) kitâbı iki cilddir. [1275] de Mısrda basılmışdır. (Letâif-\nül-minen) kitâbının birinci cildi 56. cı sahîfesinden i’tibâren kimyâ ilmini ve Câbir \nbin Hayyânı uzun anlatmakdadır. Buna (Minen-ül kübrâ) da denir. 1357 de basıl-\nmışdır. Kenârında Tâcüddîn-i İskenderînin (Letâif-ül minen) ve (Miftâh-ul-felâh) \nkitâbları vardır. (Envâr-ül-kudsiyye)si, (Tabakât-ül-kübrâ)sının kenârında basıl-\nmışdır. Hadîs ve Şâfi’î fıkh âlimidir. Çok kitâbı vardır.", "gectigiMaddeler": ["1/39", "1/97", "2/17", "3/1", "3/12", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdü-Menâf", "slug": "abdu-menaf", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın ikinci dedesi olan Hâşim, Abdü- Şems, \nMuttalib ve Nevfelin babaları ve Kusayyin oğludur. İsmi Mugîredir. Menâf, \nKureyş ve Huzeyl kabîlelerinin bir putu idi. Abd-üd-dâr ve Abd-ül-Uzzâ adındaki \nkardeşleri arasında enşereflisi ve Kâ’be bekçisi oldu. Kâ’benin anahtarı Abd-üd-\ndâr oğullarında idi.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahîm", "slug": "abdurrahim", "unvan": "", "kategori": "diger", "biyografi": "Tütün içmenin günâh olmadığını bildirmişdir.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahîm Semerkandî", "slug": "abdurrahim-semerkandi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû \nBekr-i İmâdînin oğlu olup, Mergınânî, Fergânî ve Semerkandî lakabları ile meş-\nhûrdur. Hanefî fıkh âlimidir. (Hidâye) kitâbının sâhibi olan Burhân-üd-dîn Alînin \ntorunudur. Altıyüzellibir 651 [m. 1253] de hayâtda idi. (Füsûl-i imâdî) fıkh kitâbı \nmeşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahmân", "slug": "abdurrahman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Zebid müftîsi idi. Sey-\nyiddir. (Vehhâbîleri Reddiyye) si çok kıymetlidir.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahmân bin Avf", "slug": "abdurrahman-bin-avf", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Abd-i Avf bin Hars bin \nZühre bin Kusay torunudur. Eshâb-ı kirâmın büyüklerinden ve aşere-i mübeşşere-\ndendir. Önce îmân eden sekiz kişiden biridir. Uzun boylu, beyâz idi. Bütün gazâ-\nlarda bulundu. Uhudda iki kâfir öldürdü. Hazret-i Ömerin halîfe olmak için seçdi-\nği altı kişiden biridir. Uhud gazâsında yirmi yerinden yaralandı. Topal oldu ve \noniki dişi düşdü. Çok zengin idi. Çok sadaka verirdi. [31] senesinde, yetmişbeş \nyaşında vefât etdi. Beyâz, iri, güzel idi.", "gectigiMaddeler": ["1/54", "2/23", "2/41", "2/47", "2/73", "3/3", "3/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahmân bin Ebû Bekr", "slug": "abdurrahman-bin-ebu-bekr", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Babası, \ndedesi ve oğlu hep Eshâbdandırlar. Bedr ve Uhudda düşman ordusunda idi. \nHudeybiyede müslimân oldu. Yemâme cenginde çok kahramânlık etdi. Yedi kâfiri \nöldürdü. Deve günü, kız kardeşi Âişenin “radıyallahü anhümâ” yanında idi. 53 [m. \n673] senesinde vefât etdi. Mekkededir.", "gectigiMaddeler": ["2/23", "3/68"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahmân bin Muhammed", "slug": "abdurrahman-bin-muhammed-rahmetullahi-teala-aley", "unvan": "", "kategori": "alim", "biyografi": "Gelibolulu Süleymân efendinin torunudur. Şeyhîzâde denir. Dâmâd adı ile meşhûrdur. Rumeli kâdî-askeri idi. Şeyh-ul-islâmın dâmâdı idi. 1078 [m. 1668] de vefât etdi. (Mecma’ul-enhür) adındaki (Mültekâşerhı) meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahmân Cevzî", "slug": "abdurrahman-cevzi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Alîdir. \nHanbelî fıkh âlimidir. [508] de tevellüd, 597 [m. 1201] de Bağdâdda vefât etdi. \nEbül-ferec ibni Cevzî adı ile meşhûrdur. Tefsîr, hadîs ve Hanbelî fıkh ve târîh bil-\ngilerinde derin âlim idi. Yüzden fazla kitâb yazdı. (El-mugnî) tefsîri meşhûrdur.", "gectigiMaddeler": ["1/63", "1/78", "2/16", "2/17", "2/21", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrahmânimâdî", "slug": "abdurrahmanimadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Mu -\n– 1068 –\nhammed Imâd-üd-dîndir. Şâm müftîsi idi. 978 [m. 1571] de tevellüd, 1051 [m. 1641] \nde vefât etdi. Hanefî fıkh âlimlerindendir. (El-hediyye fil-ibârât-il-fıkhiyye) kitâbı \nmeşhûrdur.", "gectigiMaddeler": ["2/21", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Abdürrezzak Kâşî", "slug": "abdurrezzak-kasi", "unvan": "", "kategori": "diger", "biyografi": "Tesavvuf ve fıkh âlimidir. Tefsîr, Füsûsşerhı \nve kıymetli eserleri vardır. 730 da vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âbidîn Pâşa", "slug": "abidin-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "[1259] da tevellüd, 1324 [m. \n1906] de vefât etdi. Fâtih câmi’işerîfi bağçesindedir. Ankara vâlîsi iken (Mesn-\nevî)yişerh etmişdir.", "gectigiMaddeler": ["2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Adam Smith", "slug": "adam-smith", "unvan": "", "kategori": "diger", "biyografi": "İngiliz iktisâdcısıdır. 1135 [m. 1723] de İskoçyada tevel-\nlüd, 1214 [m. 1799] de vefât etdi. Yirmibir yaşında iken Glaskow üniversitesine \nmantık profesörü oldu. [m. 1759] da yazdığı (Ahlâk duyguları teorisi) kitâbı ile \ndevrinin filozofları arasına girdi. [m. 1776] da neşr etdiği (Milletlerin tabî’atleri ve \nzenginlikleri) kitâbında, ticâretde serbest rekâbeti ve iktisâdda liberalizmi savun-\ndu. (Servetin kaynağı çalışmakdır. Paranın değeri, arz ve taleb üzerine kurulmuş-\ndur. Bunlar hükûmetler tarafından zorlanamaz) dedi.", "gectigiMaddeler": ["3/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Addâs", "slug": "addas", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Mekkede Utbe ve Şeybe kâfirlerinin kölesi, \nNusaybinli nasrânî idi. Resûlullahı bir görüşde îmân etdi.", "gectigiMaddeler": ["1/85"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âdem", "slug": "adem", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Yeryüzünde yaratılan ilk insandır ve ilk Peygam-\nberdir. Bütün insanların babasıdır. Çeşidli memleketlerden getirilen toprakları \nmelekler su ile çamur yapıp, insanşekline koydu. Mekke ile Tâif arasında kırk \nsene yatıp (Salsâl) oldu. Pişmiş gibi kurudu. Önce Muhammed aleyhisselâmın \nnûru alnına kondu. Sonra Muharremin onuncu Cum’a günü rûh verildi. Herşeyin \nismi ve fâidesi bildirildi. Boyu ve yaşı kesin olarak bildirilmedi. Bir rivâyetde boyu \nbeşyüz zrâ’ [ikiyüzelli metre] idi. Cennetden çıkınca altmış zrâ’ oldu. Allahü teâlâ-\nnın emri ile, bütün melekler, Âdeme doğru secde etdi. Meleklerin hocası olan \nİblîs, emri dinlemedi. Secde etmedi. Kırk yaşında iken (Firdevs) adındaki Cennete \ngötürüldü. Cennetde yâhud dahâ önce, Mekke dışında uyurken sol kaburga kemi-\nğinden, hazret-i Havvâ yaratıldı. Allahü teâlâ, bunları nikâh etdi. Cennetde, bin \nsene kadar yaşayıp, yasak edilen ağaçdan unutarak, önce Havvâ, sonra kendisi, \nbuğday yidikleri için çıkarıldılar. Âdem “aleyhisselâm”, Hindistânda, Seylân \n(Serendip) adasına, Havvâ ise, Ciddeye indirildi. İkiyüz sene ağlayıp yalvardıkdan \nsonra, tevbe ve düâları kabûl olup, hacca gelmesi emr olundu. Arafât ovasında, \nHavvâ ile buluşdu. Kâ’beyi yapdı. Her sene hac yapdı. Arafât meydânında veyâ \nbaşka meydânda, kıyâmete kadar gelecek çocukları, belinden zerreler hâlinde \nçıkdı. (Ben sizin Rabbiniz değil miyim?) soruldu. Hepsi (Evet) dedi. Sonra, hepsi \nzerreler hâline gelip, beline girdiler. Yâhud, belinden yalnız kendi çocukları çıkdı. \nHer çocuğun belinden, bunun çocukları çıkdı. Böylece, herkes, kendi babasından \nzâhir oldu. Sonra Şâma geldiler. Burada yirmi def’a ikiz evlâdı, bir def’a da yalnız \nŞis “aleyhisselâm” oldu. Neslinden kırkbin kişiyi gördü. Binbeşyüz yaşında iken \nevlâdına Peygamber oldu. Evlâdı çeşidli dil ile konuşdu. Cebrâîl “aleyhisselâm” \noniki kerre gelmişdir. Oruc, her gün bir vakt nemâz, gusl abdesti emr edildi. Kitâb \ngelip, fizik, kimyâ, tıb, eczâcılık, matematik bilgileri öğretildi. Süryânî, İbrânî ve \nArabî diller ile kerpiç üstünde çok kitâb yazıldı. Hiç sakalı yok idi. İlk sakalı çıkan \nŞis aleyhisselâmdır. Çok güzel idi. Siyâh saçlı, buğday renkli idi. Havvâ da böyle \nidi. Bir rivâyete göre, ikibin yaşına gelince, onbir gün hasta olup, Cum’a günü vefât \netdi. Havvâ, kırk sene sonra Ciddede vefât etdi. Kabrleri, Kudüsde veyâ Minâda \nmescid-i Hîfde veyâ Arafâtdadır. Hayâtlarını bildiren rivâyetler de çok farklıdır-\nlar.", "gectigiMaddeler": ["1/1", "1/11", "1/31", "1/39", "1/41", "1/46", "1/61", "1/63", "1/71", "1/77", "1/84", "1/85", "1/90", "1/95", "1/97", "2/16", "2/17", "2/20", "2/21", "2/22", "2/23", "2/25", "2/26", "2/30", "2/34", "2/39", "2/47", "2/50", "2/56", "3/4", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Adnân", "slug": "adnan", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın yirmibirinci babasıdır. Alnında Resûlullahın nû -\n– 1069 –\nru parlıyordu. Hicâzda bulunan arab kabîleleri hep bunun soyundandır. Resûlul-\nlahın bundan önceki dedelerinin adı kesin olarak belli değildir. Abdüllah ibni \nAbbâs buyurdu ki, (Adnân ile İsmâ’îl “aleyhisselâm” arasında otuz baba vardır. \nFekat, kimler oldukları belli değildir).", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Âsım", "slug": "ahmed-asim", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ayntablıdır. Seyyiddir. 1235 \n[m. 1820] de İstanbulda vefât etdi. Üsküdârda Nûh kuyusundadır. Fîrûzâbâdînin \narabî (Kâmûs) ve fârisî (Burhân-ı kâtı’) lügat kitâblarını türkceye terceme, (Emâlî \nkasîdesi)ni türkceşerh etmişdir. Üçü de basılmışdır.", "gectigiMaddeler": ["2/48", "2/67", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Baba", "slug": "ahmed-baba", "unvan": "", "kategori": "diger", "biyografi": "Hurûfî babalarındandır. Samatyada hurûfîşeyhi olan \nHalîl babanın çömezi idi. Merdiven köyündeki tekkeyi kurmuşdur.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed-i Bedevî", "slug": "ahmed-i-bedevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Alî efendidir. \nŞerîflerdendir. 596 [m. 1199] da Fasda tevellüd, 675 [m. 1276] de Mısrda Tantada \nvefât etdi. Yüzüne peçe örterdi. (Câmi’u kerâmât-il-evliyâ) da diyor ki, (Ahmed \nBedevî, hem seyyiddir, hemşerîfdir. Mısrdaki Evliyâ arasında, imâm- ı Şâfi’îden \nsonra en üstünü Ahmed-i Bedevîdir. Ondan sonra seyyidet Nefîsedir. Sonra Şere-\nfeddîn-i Kürdî, sonra Abdüllah Menûfî Şâzilîdir.) (Mir’ât-ı Medîne) de diyor ki, \n(Kutb-i rabbânî seyyid Ahmed Bedevî hazretlerinin vefâtından altmışbeş sene \nsonra, Tantadaki türbesinin bulunduğu câmi’işerîfde her sene, Rebî’ulevvel ayının \nbirinci Cum’a gecesi mevlid okumak âdet olmuşdur. Bu mevlide her memleketden \nbinlerce âlim, Velî toplanır. Bir hafta sürer. İmâm-ı Bedevî, şeyh Berînin, bu da \nAlî bin Nu’aym Bağdâdînin, bu da seyyid Ahmed Rıfâ’înin halîfesidir.) Allahü \nteâlâ, Evliyâsının kimine az, kimine çok kerâmet vermişdir. Ahmed Bedevî hazret-\nlerine, vefâtından sonra da çok kerâmet vermişdir.", "gectigiMaddeler": ["1/82", "3/28", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed-i Bezzâr", "slug": "ahmed-i-bezzar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Amrdır. Hadîs \nâlimlerindendir. 292 [m. 905] de Remle kasabasında vefât etdi. (Müsned) kitâbı \nmeşhûrdur.", "gectigiMaddeler": ["1/84", "2/6"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed bin Abdüllah", "slug": "ahmed-bin-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Nu’aym \nIsfehânî adı ile meşhûrdur. Şâfi’îdir. Hadîs âlimidir. 336 [m. 948] da tevellüd, 430 \n[m. 1039] da vefât etdi. Kıymetli kitâbları vardır. (Hilye-tül-Evliyâ)sı Beyrutda, \n(Mekteb-üt-ticârî) tarafından ve Berlinde basılmışdır.", "gectigiMaddeler": ["1/35", "1/61", "3/3", "3/23", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed bin Atâullah", "slug": "ahmed-bin-ataullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüzdok-\nsanaltıncı [896] sırada Tâcüddîn-i İskenderî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed bin Hanbel", "slug": "ahmed-bin-hanbel", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanbelî mezhebinin \nreîsidir. Dedesi Hanbeldir. 164 senesinde Bağdâdda tevellüd, 241 [m. 855] de orada \nvefât etdi. Üçyüzbinden fazla hadîs ezberlemişdi. İmâm-ı Şâfi’înin talebesidir. Hâl \ntercemesini, Beyhekî ve İbni Cevzî ve başka âlimler yazmışlardır. (El-Müsned) \nhadîs kitâbında otuzbin hadîs-işerîf vardır. Mu’tezile fırkası ile çok mücâdele ve \nonları rezîl etdiği için, Me’mûn tarafından habs edildi. 50, 211, 415, 424, 458, 476, \n567, 581, 582, 609, 629, 643, 686, 788, 842, 881, 992, 993, 1008, 1108, 1175, 1184. \nAhmed bin Muhammed Nâtıfî Taberî başka olup, 446 da vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Câmî", "slug": "ahmed-cami", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül-Hasen Ahmed bin Alî \nNâmıkî Câmî, büyük âlim ve büyük velîdir. Eshâb- ı kirâmdan Cerîr bin Abdüllah \nsoyundandır. Cerîr “radıyallahü anh”, Resûlullah “sallallahü aleyhi ve sellem” \nvefât edeceği sene îmân etmişdi. Çok güzel, boylu idi. Ahmed Câmînin otuzdokuz \noğlu vardı. Ölünce, ondördü kaldı. Hepsi de derin âlim ve âmil ve kâmil idi. Çok \nkitâb yazmışlardı. [441] de tevellüd ve 536 [m. 1142] da vefât etdi. Altıyüzbin kim-\nsenin îmâna gelmesine sebeb oldu. (Miftâh-un-necât) ve (Üns-üt-tâibîn) kitâbları \nbasılmışdır. (Miftâh-un-necât) kitâbı, Hakîkat Kitâbevi tarafından yeniden basıl-\nmışdır.", "gectigiMaddeler": ["1/31", "2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Dahlân", "slug": "ahmed-dahlan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Seyyid Zey -\n– 1070 –\nnî Dahlân, Mekkenin müftîsi ve reîs-ül-ulemâsı ve Şâfi’îşeyh-ul-hutebâsı idi. 1231 \n[m. 1816] de Mekkede tevellüd, 1304 [m. 1886] de Medînede vefât etdi. Birçok eser-\nleri olup (Hulâsat-ül-kelâm fî beyân-i umerâ-i beled-il-harâm), (Firredd-i alel-veh-\nhâbiyye-ti-etbâ-ı mezheb-i İbni Teymiyye) ve (Ed-Dürer-üs-seniyye firredd-i alel-\nvehhâbiyye) kitâblarında vehhâbîlerin, yanlış yolda olduklarını âyet-i kerîme ve \nhadîs-işerîflerle göstermekdedir. (Hulâsat-ül-kelâm)ın ikinci cüz’ü ve (Ed-Dürer-\nüs-seniyye) ve (El-Fütûhât-ül-İslâmiyye) kitâbının bir parçası olan (Fitne) ismlerin-\ndeki eserleri Hakîkat Kitâbevi tarafından ofset yolu ile basdırılmışlardır. Hindli \nMuhammed Beşîr bin Bedreddîn, (Sıyânet-ül insân)  kitâbında, Ahmed Dahlâna \nreddiyye yazdı ise de, mevlânâ Abdülhay bin Abdülhalîm Lüknevî, Beşîri rezîl \netmişdir. Abdülhay Lüknevî binüçyüzdört, Beşîr binüçyüzyirmiüç 1323 [m. 1905] \nsenelerinde vefât etdi.", "gectigiMaddeler": ["2/17", "2/38"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Hamevî", "slug": "ahmed-hamevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Muhammed \nMekkîdir. Seyyiddir. Hanefî fıkh âlimidir. Mısrda müderris [profesör] idi. 1098 [m. \n1686] de vefât etdi. Çok sayıda kitâb yazmışdır. (Uyûn-ül-besâir) ismindeki \n(Eşbâh) şerhi ve (Nefehât-ül-kurb vel-ittisâl bi-isbâtittesarrufi li-evliyâ ba’del-inti-\nkal) kitâbları çok kıymetlidir.", "gectigiMaddeler": ["1/69", "1/70", "1/97", "2/16", "2/17", "2/41", "2/43", "2/53", "3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Hân I", "slug": "ahmed-han-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin yetmiş-\ndokuzuncusu ve Osmânlı pâdişâhlarının ondördüncüsüdür. Binoniki 1012 [m. \n1603] de halîfe oldu. 1026 [m. 1617] da, yirmisekiz yaşında vefât etdi. Nemçe ile \nya’nî Avusturya ile ve Îrânla ve Celâlî eşkıyâsı ile harb edip gâlib geldi. Akllı ve iyi \nidâreli idi. Devlet idâresindeki başarılarında zevcesi Mâhpeyker sultânın çok yar-\ndımı olmuşdur. At meydânında, sultân Ahmed Câmi’ini, mekteb ve imâretini yap-\ndırmışdır. Câmi’in altı minâresi, dördünde üçer olmak üzere, onaltışerefesi vardır. \nİki kerre Edirneye, bir kerre de Bursaya seyâhat etdi. Câmi’ yanındaki türbededir. \nBeytullahın ve Hucre-i se’âdetin perdeleri Mısrda dokunurdu. Ahmed hân, İstan-\nbulda dokutup saygı ile göndermişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Hân IIı", "slug": "ahmed-han-iii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin seksen-\nsekizinci ve Osmânlı pâdişâhlarının yirmiüçüncüsüdür. [1084] de tevellüd, 1149 [m. \n1736] da vefât etdi. Turhân sultân türbesindedir. 1115 [m. 1703] de cülûs edip, 1143 \n[m. 1730] de hal’ edildi. İsveç kralı onikinci Şarl, ruslara mağlûb olarak, Ahmed \nhâna sığınmışdır. Bunun üzerine başlıyan Osmânlı-Rus harbinde ruslar bozguna \nuğramış, büyük Petro, zor kurtulmuşdur. \nÜçüncü Ahmed hânın ve ikinci Mustafâ hânın vâlideleri (Gülnûş Emetullah) \nsultân, 1109 [m. 1696] da (Galata yeni câmi’)  demekle meşhûr (Vâlide câmi’i) ni \nyapdırdı. Üsküdârda (Yeni vâlide câmi’i), vâlide sultân için, 1120 [m. 1707] sene-\nsinde, Ahmed hân tarafından yapdırılmışdır. Bu vâlide sultân 1127 [m. 1714] de, \nEdirnede vefât etdi. Üsküdâra getirilip, câmi’i önüne defn edildi. Ahmed hânın \nkızı Zeyneb sultân Gülhâne parkı\n karşısındaki mescidi yapdırdı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmedibni Kemâl", "slug": "ahmedibni-kemal", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemseddîn Ahmed \nefendi, Süleymân efendinin oğludur. Dedesi, Kemâl pâşadır. Kânûnî sultân Süley-\nmân hân zemânında, 932 [m. 1526] den 940 [m. 1534] senesine kadar Osmânlıların \ndokuzuncuşeyh-ul-islâmı idi. Cinnîlere de fetvâ verirdi. Bunun için (Müfti-yüs-\nsekaleyn) adı ile meşhûr oldu. Edirnelidir. İstanbulda Edirnekapı mezârlığında-\ndır. Buğaz köprüsünün çevre yolu yapılırken, etrâfındaki kabrler nakl edilmiş, \nkendi kabri, on metre kadar geri alınmışdır. Tefsîr, hadîs ve fıkhda derin âlim idi. \nÇok kitâb yazdı. Fetvâları ve arabîden fârisîye lügat kitâbı ve (El-münîre)si ve \n(Hadîs-i erba’în) şerhi çok kıymetlidir. 940 [m. 1534] da vefât etdi. 234, 286, 365, \n444, 476, 698, 728, 908, 1014, 1164. \n– 1071 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Kâdıyânî", "slug": "ahmed-kadiyani", "unvan": "", "kategori": "diger", "biyografi": "Hindistânda Pençabda, 1296 [m. 1879] da, ingiliz-\nlerin yardımı ile, (Kâdıyâniyye) veyâ (Ahmediyye) adında yeni bir din kurdu. Pey-\ngamber olduğunu söyledi. İstanbulda ofset baskısı yapılan (El-mütenebbî) kitâbın-\nda uzun bilgi vardır. 1326 [m. 1908] de öldü.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Na'îm Efendi", "slug": "ahmed-naim-efendi", "unvan": "", "kategori": "diger", "biyografi": "Mustafâ Zihnî pâşanın oğludur. Babanzâde \nadı ile meşhûrdur. 1290 [m. 1872] da tevellüd, 14 Ağustos 1352 [m. 1934] de kalb \nsektesinden vefât etdi. Edirnekapıdadır. Galataserây Lisesinde ve mülkiyye mek-\ntebinde okudu. Orta boylu, sakallı idi. Galataserâyda ders verdi. Felsefe üzerinde \nfransızcadan tercemeler yapdı. 1346 [m. 1928] da (Buhârî hulâsası)nı terceme ve \niki cildini neşr etdi. Dâr-ül-fünûnda yirmiiki sene profesörlük yapdı. 1351 [m. \n1933] de dârülfünûn lâğv edilince, kıymeti bilinmiyerek açıkda bırakıldı. Tâm ve \nhâlis müslimân idi. Arabî ve fransızca iyi bilirdi. Felsefe âlimi idi. Tevfik Fikretle \nAbdüllah Cevdetin islâm düşmanlıklarını hiç beğenmezdi. Kuru mütercim değil, \nmütefekkirdi. Tevfik Fikret için (Ma’nevî en büyük destekden mahrûm, bedbaht, \nölmeğe mahkûm bir kimsedir) derdi. Garb felesoflarından iki üç kimseden başka \nhiçbir felesofun ulûhiyyeti inkâr etmediğini söylerdi. Fikretin niçin dalâlete düş-\ndüğüneşaşardı. Onu felsefede olgunlaşmamış sayardı. Na’îm beğin eserleri: \n(Ahlâk-\nı islâmiyye esâsları), (Buhârî tercemesi), (Da’vâ-yı kavmiyyet), (Felsefe \ndersleri), Nevevînin (Hadîs-i erba’în) i tercemesi, (İlm-ün-nefs) [psikoloji], (Man-\ntık), (Temrînât) ve sâiredir.", "gectigiMaddeler": ["2/6"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Rıfâ'î", "slug": "ahmed-rifai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül Abbâs Ahmed bin \nEbül Hüseyn Alî, seyyiddir. Evliyânın büyüklerindendir. Basra civârında [512] de \ntevellüd, 578 [m. 1183] de Basrada vefât etdi. Şâfi’î idi. Türbesi ve mescidi, ikinci \nAbdülhamîd hân tarafından ta’mîr edilmişdir.", "gectigiMaddeler": ["3/28"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed Sa'îd-i Fârûkî", "slug": "ahmed-said-i-faruki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed Sa’îd \nibni Ebî Sa’îd bin Safî bin Azîz bin Muhammed Îsâ bin muhtesib-ül-ümmeşeyh \nSeyfeddîn-i Fârûkî Serhendî “rahmetullahi aleyhim”, hicretin [1217] senesinde \nHindistânda Rampurşehrinde tevellüd ve 1277 [m. 1861] de Medîne-i münevvere-\nde vefât etdi. Bakî’ kabristânında, Osmân “radıyallahü anh” türbesi yanındadır. \nAhmed Sa’îd hazretlerinin üç oğlu vardı. Birinci Muhammed Mazher, biniki-\nyüzkırksekiz [1248] de tevellüd ve 1301 [m. 1884] de Medîne-i münevverede vefât \netdi. Babasının yanındadır. 1277 senesinde yazdığı (Makâmât-ı sa’îdiyye)  kitâbı \nfârisî olup, babası Ahmed Sa’îdin ve mürşidlerinin “kuddise sirruhüm” hâllerini \nve yüksek makâmlarını bildirmekdedir. Kitâb 1281 de Delhîde basdırılmışdır. \nİmâm-ı Rabbânîyi bildiren risâlesi (Hak Sözün Vesîkaları) kitâbında basılmışdır. \nMekkede seyyid Fehîm Efendi ile sohbet eylemişdir. \nİkinci oğlu mevlânâ Ebüsse’âdet Muhammed Ömer, binikiyüzkırkdört [1244] \nde tevellüd ve binikiyüzdoksansekiz 1298 [m. 1881] de Rampurda vefât etdi. Oğlu \nEbülhayrın mürşidi idi. Ebülhayr, binüçyüzkırkbir [1341] de Delhîde vefât etdi. \nKabri, Abdüllah-i Dehlevî dergâhında, dedesi Ebû Sa’îdin yanındadır. Mermerden \ntabutşeklindeki dört kabr, mermerden pek san’atli dört dıvâr içinde ve Dergâhın \nortasındadırlar. Ebülhayrın oğlu Ebül-Hasen Zeyd-i Fârûkî, 1324 [m. 1906] sene-\nsinde, Delhîde Abdüllah-i Dehlevî dergâhında tevellüd etdi. Bu dergâhda vefât \netdi. 1391 [m. 1971] Şa’bân ayında Delhîyi ziyâretimde, sohbeti ile iki def’aşeref-\nlendim. 1376 [m. 1957] da basdırmış olduğu fârisî (Menâhic-üs-seyr) kitâbını bu \nfakîre hediyye etdi. Câmi’ul-ezherde okuduğunu, Mısrdaşeyh-ül-islâm Mustafâ \nSabrî efendi ile çok sohbet etdiğini de söyledi. 1394 [m. 1974] de, Kandihârda bas-\ndırdığı, fârisî (Makâmât-i ahyâr)  kitâbında dedelerini uzun anlatmakdadır. Zeyd \nefendi, kitâbında diyor ki, babam, Peygamberimizi rü’yâda görmüş. Çok üzüntülü \nimiş, sebebini sormuş. (Türkler benim halîfemi bugün makâmından ayırdılar. \nBunun cezâsını çok acı çekeceklerdir) buyurmuş. \n– 1072 –\nÜçüncü oğlu Mevlânâ Abdürreşîd, binikiyüzotuzyedi [1237] de Lucknowda \ntevellüd ve binikiyüzseksenyedi 1287 [m. 1870] de Mekke-i mükerremede vefât \netdi. Bu da, oğlu Şâh Muhammed Ma’sûm-i Ömerînin mürşidi idi. Muhammed \nMa’sûm [1263] de Abdüllah-i Dehlevî hazretlerinin tekkesinde tevellüd etdi. 1274 \n[m. 1858] de İngilizler Delhîde büyük fitne çıkardı. Sultân ikinci Behâdırşâhı, iki \nzevcesi ve iki oğlu ile Kalkuteye götürüp habs etdiler. Hindistânın her tarafında \nmüslimânlarşehîd edildi. Müslimânlar, Medîne-i münevvereye hicret etdi. [1290] \nda Hindistâna döndü. Otuzüç sene sonra akrabâ ve talebesinden altmış kişi ile \n[1323] de Medîneye döndü. Burada İmâm-ı Rabbânî hazretlerinin (Mebde’ ve \nme’âd) kitâbını arabîye terceme etdi ve çok kitâb yazdı. Bunlardan (Ahsen-ül-\nkelâm fî-isbât-i mevlid-i vel-kıyâm) kitâbı, Hindistânın Urdu dilinde olup, vehhâ-\nbîleri red ve rezîl etmekdedir. Hindistânda basılmış ve arabîye terceme edilmiş-\ndir. (Es-sebe’ul-esrâr fî medâric-il-ahyâr)  kitâbı, tesavvufu çok açık anlatmakda-\ndır. Urdu dilindedir. Oğlu Muhammed Abdülkâdir Medenî tarafından [1329] da \narabîye terceme edilmiş, 1331 [m. 1913] de İstanbulda basılmışdır. İkinci oğ\nluşeyh Ebülfeyz Muhammed Abdürrahmânın kitâbın başına yazdığı takrîz çok isti-\nfâdelidir. Mütercim, önsözünde buyuruyor ki, ( Şâh Veliyyullah muhaddis \nAhmed-i Dehlevî (Mukaddeme-tüs-seniyye fî isbât-i mezheb-is-sünniyye) kitâ-\nbında, İmâm-ı Rabbânîyi uzun övmekde ve mü’minler onu sever, münâfıklar, \nşakîler ise kötüler demekdedir). Şâh Muhammed Ma’sûm, 1341 [m. 1923] de \nMekke-i mükerremede vefât etdi. \nAhmed Sa’îd-i Serhendî, babası ile birlikde Abdüllah- ı Dehlevî hazretlerinin \nsohbetinde bulunup, on yaşına varmadan tarîkat-i Nakşibendiyyeye intisâb etdi. \nOnbeş yaşına kadar bu sohbetde kemâle geldi. Abdüllah-i Dehlevî hazretleri evlen-\nmemiş idi. Bunu oğulluğa kabûl buyurdu. Hilâfet-i mutlaka ileşereflendirdi. Çok \nVelî yetişdirdi. Çok kitâb yazdı. (El-hakk-ul-mübîn fî-redd-i alelvehhâbîn) kitâbı \nvehhâbîlere cevâb vermekdedir. (Mektûbât-i Ahmediyye) si çok kıymetlidir. (Tah-\nkîk-ul-hakkılmübîn) kitâbı 1386 senesinde Karaşide basılmış olup, (Mesâil-i \nerba’în)e cevâb vermekdedir.", "gectigiMaddeler": ["2/17", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed-i Yekdest", "slug": "ahmed-i-yekdest", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dokuzyüzaltmışseki-\nzinci [968] sırada, Yekdest ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed-i Zerrûk", "slug": "ahmed-i-zerruk", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şihâb-üd-dîn Ahmed \nbin Ahmed Fâsî, 846 [m. 1442] da Trablus-garbda tevellüd, 899 [m. 1493] da orada \nvefât etdi. Mâlikî fıkh âlimi ve tesavvuf büyüklerindendir. Çok sayıda kıymetli eser-\nleri vardır. (Şerh-ı hizb-il-bahr) ve (Kavâ-id-üttarîka fil-cem’-i beyneşşerî’at-i vel-\nhakîka) ve (Kavâid-üt-tesavvuf) kitâbları meşhûrdur. Sonuncusu büyük olup, Mısr-\nda basılmışdır.", "gectigiMaddeler": ["1/27", "2/17", "2/42"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ahmed-i Zeynî", "slug": "ahmed-i-zeyni", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seksenikinci [82] sayıda \nAhmed Dahlân ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âişe", "slug": "aise", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın zevce-i mutahherasıdır. Ebû \nBekr-i Sıddîkın kızıdır. Çok akllı, zekî, âlime, edîbe ve afîfe ve sâliha idi. Hâfızası \npek kuvvetli olduğu için, Eshâb- ı kirâm, birçokşeyleri ondan sorup öğrenirdi. \nÂyet-i kerîme ile medh edildi. İctihâdı hazret-i Alîye uymadığı için, Deve \nvak’asında hazret-i Alî ile harb eden Eshâb- ı kirâm ile birlikde idi. Hazret-i Alîşehîd edilince pek üzüldü. Şî’îler kendisine çok iftirâ ediyor. Hazret-i Alîyi sev-\nmezdi diyorlar. Hâlbuki (Alîyi sevmek îmândandır) hadîs-işerîfini, hazret-i Âişe \nhaber verdi. Böylece, onu sevdiğini ve herkesin de sevmesi lâzım geldiğini bildirdi. \nHicretden sekiz sene önce tevellüd, üç sene evvel nikâh ve ikinci yıl Şevvâl ayında \nzifâf, 57 [m. 676] senesinde Medînede vefâtı vâkı’ oldu. 60, 349, 380, 381, 382, 398, \n457, 473, 503, 574, 601, 643, 646, 695, 730, 740, 784, 952, 1022, 1066, 1068, 1077, 1169, \n1197, 1198. \n– 1073 –                                  Se’âdet-i Ebediyye 3-F:68", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âişe Hanım", "slug": "aise-hanim", "unvan": "", "kategori": "diger", "biyografi": "Hüseyn Hilmi Işıkın vâlidesidir. 1374 [m. 1954] de vefât \netdi. Ankarada Bağlûmdadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Akkermânî", "slug": "akkermani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Mustafâ 1174 \n[m. 1760] de Mekke-i mükerremede kâdî iken vefât etdi. Akkermân, Karadeniz \nsâhilinde Dinyester nehri yakınındadır. Çok kitâb yazdı.", "gectigiMaddeler": ["2/48", "2/49"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Akreme (yâhud İkrime)", "slug": "akreme-yahud-ikrime", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın en büyük düş-\nmanı olan Ebû Cehlin oğludur. Önceden, babası gibi düşman idi. Mekke feth edil-\ndiği gün öldürülmesi emr olunan sekiz erkek ile dört kadından biri idi. Gemiye \nbinip Yemene kaçdı. Yolda fırtına çıkıp gemi batıyordu. (Kurtulursak, Resûlulla-\nhın ayaklarına kapanacağım) diye niyyet etdi. Kurtuldular. Yemende müslimân \noldu. Zevcesi ve amcasının kızı olan Ümm-ül-Hakîm bint-il Hâris dahâ önce müs-\nlimân olmuşdu. Medînede onun için emân aldı. Yemene gidip, (İnsanların en halî-\nmi ve kerîmi olan zât tarafından sana emân getirdim) dedi. Müslimân oldukdan \nsonra, Eshâb- ı kirâmın kahramânlarından oldu. Ummanda, Yemende cihâd edip, \n13 [m. 634] senesinde, Yermük muhârebesindeşehîd oldu.", "gectigiMaddeler": ["1/96"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Akşemseddîn", "slug": "aksemseddin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Hamza, \nŞihâbüddîn-i Sühreverdî neslindendir. Şâmda tevellüd etmişdir. Hâcı Bayram- ı \nvelînin halîfesi olup, Göynükde yerleşdi. İstanbulun fethinde bulunup, hazret-i \nHâlidin kabrini keşf etdi. 864 [m. 1460] de Göynükde, ya’nî Torbalıda vefât etdi. \n(Risâlet-ün-nûriyye) ve (Maddet-ül-hayât) kitâbları vardır. İstanbulda, Hırka-işerîf câmi’i civârında mescidi ve sübyan mektebi ve mahallesi vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alâüddevle", "slug": "alauddevle", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Rükneddîn Ahmed, Sem-\nnân pâdişâhının oğludur. Tesavvufa intisâb etdi. Kübreviyye tarîkatinde kemâle \ngeldi. 659 [m. 1260] da Semnânda tevellüd, 736 [m. 1335] senesinde vefât etdi. Sofî \nÂbâdşehrindedir. 112, 768, 936, 1016, 1076. [ (Mesmû’ât)da sahîfe 110.]", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alâ'üddîn-i Attâr", "slug": "alauddin-i-attar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMuhammed Buhârî, Muhammed Behâ-üddîn-i Buhârî hazretlerinin dâmâdı ve \ntalebesi idi. Zemânının kutb-i irşâdı idi. Buhâranın Cağanyân nâhiyesinde sekizyü-\nziki 802 [m. 1400] de vefât etdi. (Evliyânın kabrlerini ziyâret etmenin te’sîri çokdur. \nRûhlarına teveccüh etmek dahâ fâidelidir) buyururdu. Abdülganî Nablüsînin, \nbunun mubârek rûhundan çok feyz aldığı (İrgâmül-merîd) de yazılıdır. Büyük âlim \nSeyyid Şerîf-i Cürcânî diyor ki, (Alâüddîn-i Attâr hazretlerinin sohbetine kavuşun-\nca, Rabbimi tanıyabildim).", "gectigiMaddeler": ["2/17", "2/19", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alâ' Üddîn-i Bağdâdî", "slug": "ala-uddin-i-bagdadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin \nMuhammed, Şâfi’î fıkh ve tefsîr âlimidir. [678] de Bağdâdda tevellüd, 741 [m. \n1340] senesinde Halebde vefât etdi. (Hâzin) tefsîrini yazmışdır.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alâ 'üddîn-i Haskefî", "slug": "ala-uddin-i-haskefi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nAlî, [1021] de Haskefde tevellüd, 1088 [m. 1677] de vefât etdi. Şâm müftîsi idi. \n(Dürr-ül-muhtâr) kitâbına İbni Âbidîn, Burhâneddîn İbrâhîm bin Mustafâ Halebî \nve Ahmed Tahtâvî hâşiyeler yapmışlardır.", "gectigiMaddeler": ["1/78", "1/79", "1/98", "2/16", "2/40", "2/52", "3/19", "3/21", "3/59", "3/63", "3/64"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alb Arslan", "slug": "alb-arslan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Dâvüd 425 \n[m. 1033] de tevellüd etdi. Selçûkî sultânlarının ikincisidir. 455 [m. 1063] de amcası \nTuğrul beğ vefât edince, tahta çıkdı. İstanbul imperatoru Diyojenin ordusunu \nMalazgirdde [463] hicrî, [1071] mîlâdî yılında mağlûb etdi. Reyşehrindeki Selçûkî \ndevleti, 429 [m. 1037] dan 590 [m. 1193] senesine kadar devâm etdi. Konyadaki Sel-\nçûkîler 477 [m. 1083] den 699 [m. 1299] a kadar devâm etdi.", "gectigiMaddeler": ["2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Aleksandrus", "slug": "aleksandrus", "unvan": "", "kategori": "diger", "biyografi": "Mîlâdın [325]. ci senesinde büyük Kostantinin İznik-\nde topladığı üçyüzonsekiz papasın başkanı idi. İskenderiyye patrîki idi. [Bu ism, \n(Fâideli Bilgiler) kitâbındadır.]", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âlemgîr", "slug": "alemgir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Evrenkzîb, Şâhcihâ-\n– 1074 –\nnın üçüncü oğlu olup, 1028 [m. 1619] de tevellüd ve 1118 [m. 1707] de vefât etdi. \nBirinci oğlu Dârâ Şekve çok âlim ve kâdirî idi. (Hasenât-ül-ebrâr) kitâbında islâmiy-\nyeti Hindû dîni ile birleşdirdiği için, 1069 [m. 1658] da Evrenkzîb tarafından i’dâm \nedildi. Fârisî (Sefînet-ül-Evliyâ) kitâbı (Pişâver)de basılmışdır. Âlemgîr, 1068 [m. \n1657] de babasını habs edip, tahta çıkdı. Çok müttekî ve âlimleri severdi. Berehmen-\nlerle veşî’îlerle mücâdele etdi. Muhammed Ma’sûm-i Fârûkî ve oğlu Muhammed \nSeyf-üd-dîn hazretlerinden feyz aldı. Elli sene adâletle hükm sürdü. Şeyh Nizâm \nMuînüddîn-i Nakşibendî başkanlığındaki bir hey’ete, Hanefî mezhebi üzerine (Fetâ-\nvâ-i hindiyye) adındaki çok kıymetli fetvâ kitâbını hâzırlatdı. Binüçyüzon 1310 [m. \n1891] da Mısrda basılmış, 1393 [m. 1972] de üçüncü baskısı yapılmışdır. Dakenşehrle-\nrini de ele geçirdi. Ölünce, yerine oğlu birinci Şâh-ı âlem Behâdır tahta çıkdı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî", "slug": "ali", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın amcası olan Ebû Tâlibin oğlu idi. \nİslâm halîfelerinin ve Cennetle müjdelenen on kişinin dördüncüsüdür. Resûlulla-\nhın dâmâdıdır. Ehl-i beytin birincisidir. Hicretden yirmiüç yıl önce Mekkede tevel-\nlüd etdi. On yaşında iken îmân etdi. Bütün gazâlarda kahramânlıklar gösterdi. \nYalnız Uhudda onaltı yerinden yaralandı. Otuzbeş [35] senesinin Zilhicce ayında \nhalîfe oldu. 40 [m. 660] da, Ramezân-ışerîf ayı onyedinci Cum’a günü sabâh nemâ-\nzına giderken Abdürrahmân ibni Mülcem isminde bir hâricî tarafından kılıncla \nalnına vurularakşehîd edildi. Kûfede ya’nî Necef denilen yerde medfûndur. Buğ-\nday benizli, uzun gerdanlı, güler yüzlü, iri ve siyâh gözlü, geniş göğüslü, iri yapılı \nidi. Sakalı sık idi. Muhârebe zemânlarında uzatırdı ve omuzlarına kadar yayılırdı. \nSon zemânlarda saçı ve sakalı pamuk gibi beyâz olmuşdu. Evliyânın büyüğü, Vilâ-\nyet yolunun reîsidir. Her tarîkatde herkese Vilâyetin feyzleri ve ma’rifetleri haz-\nret-i Alîden gelmekdedir.", "gectigiMaddeler": ["1/1", "1/11", "1/31", "1/39", "1/43", "1/46", "1/71", "1/74", "1/78", "1/81", "1/85", "1/91", "1/95", "1/96", "1/97", "1/98", "2/4", "2/5", "2/16", "2/17", "2/21", "2/22", "2/23", "2/24", "2/25", "2/34", "2/39", "2/41", "2/43", "2/45", "2/46", "2/47", "2/49", "2/51", "2/53", "2/61", "2/71", "2/73", "3/2", "3/15", "3/16", "3/23", "3/27", "3/28", "3/36", "3/55", "3/56", "3/59", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî bin Ahmed Hîtî", "slug": "ali-bin-ahmed-hiti", "unvan": "", "kategori": "diger", "biyografi": "(Seyf-ül-bâtir li-rikâbişşî’at-i verrâfıda-til-\nkevâfir) kitâbı çok kıymetlidir. Bu kitâbı 1025 [m. 1616] da İstanbulda yazmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî bin Emrullah", "slug": "ali-bin-emrullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "916 [m. 1509] da \ntevellüd, 979 [m. 1571] da Edirnede vefât etdi. (Ahlâk-ı Alâî) kitâbını yazdı. Tefsîr, \nkelâm ve fıkhşerhleri de vardır.", "gectigiMaddeler": ["2/67"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî bin Hüseyn", "slug": "ali-bin-huseyn", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hüseyn vâ’ ız-ı Kâşifînin \noğludur. Fahrüddîn ve Safî ismleri ile meşhûrdur. 867 [m. 1462] de tevellüd ve 939 \n[m. 1533] senesinde Hirâtda vefât etdi. Fârisî eserleri arasında (Reşehât) kitâbı çok \nkıymetlidir. Şeyh Ahmed Allân-ı Mekkî ve sonra Muhammed Murâd-ı Kazânî tara-\nfından arabîye terceme edilmişdir. Üçüncü Murâd hân zemânında, 993 [m. 1584] \nsenesinde, Muhammed Şerîf-i Abbâsî tarafından türkceye terceme edilmişdir. \nTürkcesi çeşidli târîhlerde basılmışdır. Binikiyüzdoksanbirde İstanbulda taşbas-\nması harekeli olup, sonunda mevlânâ Hâlid-i Bağdâdînin arabî (İrâde-i cüz’iyye) \nkitâbı ve kenârında, mevlânâ-i mezkûrün (Râbıta) risâlesinin arabîsi ve ayrıca \ntürkcesi ve yine onun (Âdâb-ı tarîkat) risâlesinin türkcesi ve fârisî (Silsile-i aliy-\nye)si ve ayrıca İsmâ’îl Hakkı Bursevînin (Huccet-ül bâliga) risâlesi ve (Hatm-i \nhâcegân) ve Niyâzî Mısrînin (Süâl-cevâb) risâlesi veşeyh Sâdık efendinin (Abdes-\ntin âdâbı) ve (İnsân-ı kâmil) ve Edirne müftîsi Feyzi efendinin (Ayn-ül hakîka)  \nadındaki çok kıymetli kitâbları ve hazret-i Alînin “radıyallahü anh” kırk sözü ve \ntercemeleri vardır. Sözün kısası, Reşehât tercemesinin bu baskısı bir hazînedir. \nEline geçip okuyan, dünyânın en tâli’li insanıdır. Abdülhakîm efendi, (Reşehât \nokumak, insanın ihlâsını artdırır) buyururdu. \n– 1075 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî bin İsmâ'îl", "slug": "ali-bin-ismail", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alâüddîn Konevî olup, \n[668] de tevellüd ve 729 [m. 1329] da vefât etdi. Şâfi’î fıkh âlimidir. Mısrda ders \nverdi. Şâmda kâdîlık yapdı. (El a’lâm fî-hayât-il-Enbiyâ aleyhimüssalâtü vesselâm) \nve (Hâvî) ile (Te’arrüf) şerhleri ve (Minhâc) muhtasarı meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî bin Ma'bed", "slug": "ali-bin-mabed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Muhammedin \ntalebesidir. Onun (Câmi’ul-kebîr) ve (Câmi’üs-sagîr) kitâblarını rivâyet etmişdir. \nMervden Mısra geldi. 218 [m. 833] Ramezânında vefât etdi.", "gectigiMaddeler": ["2/40"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî bin Yûsüf", "slug": "ali-bin-yusuf", "unvan": "", "kategori": "diger", "biyografi": "Nûreddîn 741 [m. 1340] senesinde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Cürcânî", "slug": "ali-curcani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Abdül’azîzdir. 392 \n[m. 1001] senesinde Cürcânda vefât etdi. Şâfi’î fıkh ve tefsîr âlimidir. Reyşehrinde \nkâdî idi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Echürî", "slug": "ali-echuri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İkiyüzdoksanbirinci [291] \nsırada, Echürî Alî ismine bakınız!", "gectigiMaddeler": ["2/1", "2/43", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Efendi", "slug": "ali-efendirahmetullahi-teala-aleyh", "unvan": "Çatalcalı", "kategori": "alim", "biyografi": "Osmânlı Şeyh-ülislâmlarının kırküçüncüsüdür. 1041 de Çatalcada doğdu. Dördüncü Muhammed hân zemânında, 1084 [m. 1673] de Şeyh-ül-islâm oldu. Onüç sene sonra azl edildi. 1103 [m. 1692] de vefât etdi. (Alî efendi fetvâsı) meşhûrdur.", "gectigiMaddeler": ["1/58", "3/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Haydar Be Ğ", "slug": "ali-haydar-be-g", "unvan": "", "kategori": "diger", "biyografi": "Ahiskalı hoca Emîn efendi zâde, temyîz mahke-\nmesi a’zâlığında ve başkanlığında, fetvâhâne-i âlî emînliğinde ve adliye nezâretinde \nbulunmuşdur. Dâr-ül-fünûn hukûk fakültesinde ve medresetül-kudâtda ve mülkiye \n[siyâsal bilgiler] okulunda müderrislik ya’nî profesörlük yapdı. (Mecelle) kitâbına \nyapdığı (Dürer-ül-hükkâm) adındakişerhi çok kıymetlidir. Buşerhin 1323 [m. \n1905] de basılan (Kitâb-ül-kefâle) sonunda bildirildiği gibi, (Erâzî kanûnuşerhı) ve \n(Evkâfda muvâda’a) ve (Risâle-i mefkûd) ve (İntikâl kanûnu)naşerhı vardır. 1355 \n[m. 1937] de vefât etdi. 1321 [m. 1903] de vefât ederek Üsküdârda Nesûhî kabristâ-\nnına defn edilmiş olan büyük Alî Haydar beğ başkadır. O da, hukuk fakültesinde \nusûl-i fıkh ve mecelle profesörlüğü yapmışdı.", "gectigiMaddeler": ["2/40", "3/4", "3/5", "3/11", "3/13"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Hullî", "slug": "ali-hulli", "unvan": "", "kategori": "diger", "biyografi": "Babası Hasendir. [601] de vefât etdi.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Kuşcu", "slug": "ali-kuscu", "unvan": "rahmetullahi aleyh", "kategori": "alim", "biyografi": "Alâüddîn bin Muhammed, Semer-\nkandda Ulug beğin doğancı başısı idi. İstanbula geldi. Ayasofya medresesine \nmüderris oldu. Akâid ve astronomi kitâbları vardır. 879 [m. 1474] de vefât etdi. \nEyyûbdedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âlim bin Alâ", "slug": "alim-bin-ala", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanefî fıkh âlimidir. 688 \n[m. 1289] de vefât etdi. Büyük tatâr hânı için hâzırladığı (Tatârhâniyye) adındaki \nfetvâ kitâbı çok kıymetli olup, (Zâd-ül-müsâfir) adı ile meşhûrdur.", "gectigiMaddeler": ["1/78"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Râmitenî", "slug": "ali-ramiteni", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm âlimlerinin büyükle-\nrindendir. (Hâce azîzân) ve (Pîr-i nessâc) ismleri ile meşhûrdur. Mahmûd-i İncîr-\nfagnevînin talebesidir. Dokumacılık yapardı. Şeyh Alâüddevle-i Semnânî ile mek-\ntûblaşırdı. Celâlüddîn-i Rûmî ile sohbet etdiği (İrgâm-ül-merîd) de yazılıdır. Buhâ-\nrânın Râmiten köyünde tevellüd ve yediyüzyirmibir 721 [m. 1320] de yüzotuz \nyaşında Hârezmşehrinde vefât etdi. Eshâb- ı hâcât ziyâret edip teberrük etmekde-\ndir.", "gectigiMaddeler": ["2/17", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Rızâ", "slug": "ali-riza", "unvan": "", "kategori": "diger", "biyografi": "Yediyüzyetmişikinci [772] sırada Rızâ ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî Ûşî", "slug": "ali-usi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Osmândır. [569] da (Sirâciy-\nye) fetvâ kitâbını ve ayrıca Ehl-i sünnet i’tikâdını bildiren (Emâlî kasîdesi)ni yazdı. \nFergânelidir. 575 [m. 1180] de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alî-Ül-A'lâ", "slug": "ali-ul-ala", "unvan": "", "kategori": "diger", "biyografi": "Hurûfî babalarındandır. Fadlullah- ı Hurûfînin mürîdle-\nrinden idi. Tîmûr hândan kaçıp, Kırşehre geldi. Bektâşîşekline girdi. Bektâşîlik \ntarîkâtini, islâm düşmanlığı hâline çevirdi. (Câvidân) kitâbını Anadoluya, el altın-\ndan yaydı. Binlerle müslimânın dinden, îmândan çıkmasına sebeb oldu. 500. \n– 1076 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Al‹yy-Ül-Kârî", "slug": "alyy-ul-kari", "unvan": "", "kategori": "diger", "biyografi": " Hirâtl› d›r. Babas› Muhammeddir. Yaz› c› l›kla geçi-\nnirdi. Çok kitâb terceme veşerh etdi. (Ehâdîs-ül-mevdû’ât) ad›ndaki kitâb›nda, \nsahîh hadîslere mevdû’ demekdedir. ‹mâm-› a’zam›n (F›kh-› ekber)inişerh eder-\nken, Resûlullah›n “sallallahü aleyhi ve sellem” mubârek ana ve babas› n›n kadr ve \nk›ymetlerini küçültücü yaz› lar›ndan ve tesavvuf büyüklerininşânlar› na yak›şm› -\nyacak iftirâlar›ndan dolay› islâm âlimlerinin gözlerinden düşmüşdür. 1014 [m. \n1606] de Mekke-i mükerremede vefât etdi. F›kh-› ekberin (El-Kavl-ül-fasl) \nad›ndakişerhinde, böyle sayg› s›z yaz› yokdur. (El-Müstened-ül-mu’temed) \nkitâb›nda ve (Mektûbât-› Ahmediyye) nin altm› şüçüncü mektûbunda, Aliyy-ül-\nkârîye cevâb verilmişdir. (Fâideli Bilgiler) kitâb› na bak› n›z! (Mektûbât-i Ahme-\ndiyye) kitâb›, 1372 [m. 1953] senesinde, Karaşide basd› r›lm›şd›r. \n(Turub-ül-emâsil bi-terâcim-il-efâdıl) kitâbının sonunda diyor ki, (Alî Hirevî, \nHiratda doğdu. Mekkede yerleşdi. İbni Hacer-i Hiytemîden de okudu. Çok eser \nbırakdı ise de, din büyüklerine i’tirâzları çirkin oldu. İmâm-ı Şâfi’înin ve imâm- ı \nMâlikin ictihâdlarına dil uzatdı. Büyük âlim Muhammed Miskin, ona lâyık olan \nreddiyyeyi yazdı.) (Sedâd-üd-dîn fî-isbâtin-necât-i lil-vâlideyn) de diyor ki, (Aliyy-\nül-kârî, Fıkh-ı ekberişerh ederken, Resûlullahın vâlideynine dil uzatmış, bu yet-\nmiyormuş gibi, ayrıca bir risâle de yazmışdır. Şifâ kitâbınışerh ederken, küfrlerini \nbildiren risâle yazmış olduğunu, öğünerek bildirmişdir. Mekke-i mükerreme müf-\ntîsi iken, 1033 de vefât eden İmâm-ı Abdülkâdir Taberî, o risâleyi red için bir risâle \nyazmışdır.) (Turub-ül-emâsil) 1393 [m. 1973] de Karaşide basılmışdır.", "gectigiMaddeler": ["1/97", "2/5", "2/16", "2/71"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Alkama", "slug": "alkama", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Kaysdır. İbrâhîm-i Nehâî-\nnin dayısı idi. Abdüllah ibni Mes’ûddan ve Alî ve Âişe “radıyallahü anhüm”den \nders almışdır. 62 [m. 681] senesinde vefât etdi.", "gectigiMaddeler": ["1/73", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âlûsî", "slug": "alusi", "unvan": "", "kategori": "diger", "biyografi": "Şihâbüddîn seyyid Mahmûd bin Abdüllah Âlûsî-i kebîr Bağdâdî, Bağdâdda müftî idi. Şâfi’î âlimlerindendir. 1217 [m. 1803] de Bağdâdda tevellüd, 1270 [m. 1853] de orada vefât etdi. İstanbula da geldi. Şî’îlere cevâb olarak, (El-ecvibe-tül-Irâkıyye anil es’iletil-Îrâniyye) kitâbı ve (Nehc-üs-selâme) ve (Elecvibe-tül-Irâkıyye anil-es’ile-til-Lâhûriyye), (Nefehât-ül-kudsiyye fî-mebâhîs-ilimâmiyye) kitâblarını yazmışdır. Birincisi 1317 [m. 1899] de İstanbulda sanâyı’ mektebinde, üçüncüsü 1301 [m. 1883] de Bağdâdda basılmışdır. (Rûh-ul-me’ânî) adındaki tefsîri, dokuz cilddir. Gençler arasındaşöhret bulan bu tefsîr, din âlimleri arasında bir kıymet kazanamamışdır. İçindeki haberlerden ba’zısının doğru olmadığı, (Dürerüs-seniyye)de yazılıdır. İbni Teymiyyenin fikrlerini benimsemişdir.", "gectigiMaddeler": ["1/84", "3/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âlûsî", "slug": "alusi-2", "unvan": "", "kategori": "diger", "biyografi": "Nu’mân bin Mahmûd bin Abdüllah Âlûsî, Bağdâdda [1252] de \ntevellüd, 1317 [m. 1899] de vefât etdi. Mevtâ işitmez derdi. (Cilâ-ül-ayneyn) kitâ-\nbında İbni Teymiyyeyi övmekde, İbni Hacer-i Mekkî hazretlerine dil uzatmakda-\ndır. Yûsüf Nebhânî (Şevâhid-ül-hak) kitâbında, bunun haksız olduğunu isbât \netmekdedir. (Gâliyye-tül-mevâ’ız) kitâbında dört mezheb imâmlarını çok övüyor \nve İmâm-ı a’zamı müjdeliyen hadîs-işerîfleri yazıyor ve Hanefî fıkh kitâblarından \nbilgiler bildiriyor ise de, yüzondokuzuncu [119] sahîfesinde, Evliyânın kabrini \nziyâret için (Cilâ-ül-ayneyn) kitâbını tavsiye etmekdedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âlûsî", "slug": "alusi-3", "unvan": "", "kategori": "diger", "biyografi": "Nu’mân bin Mahmûd bin Abdüllah Âlûsî, Bağdâdda [1252] de \ntevellüd, 1317 [m. 1899] de vefât etdi. Mevtâ işitmez derdi. (Cilâ-ül-ayneyn) kitâ-\nbında İbni Teymiyyeyi övmekde, İbni Hacer-i Mekkî hazretlerine dil uzatmakda-\ndır. Yûsüf Nebhânî (Şevâhid-ül-hak) kitâbında, bunun haksız olduğunu isbât \netmekdedir. (Gâliyye-tül-mevâ’ız) kitâbında dört mezheb imâmlarını çok övüyor \nve İmâm-ı a’zamı müjdeliyen hadîs-işerîfleri yazıyor ve Hanefî fıkh kitâblarından \nbilgiler bildiriyor ise de, yüzondokuzuncu [119] sahîfesinde, Evliyânın kabrini \nziyâret için (Cilâ-ül-ayneyn) kitâbını tavsiye etmekdedir.", "gectigiMaddeler": ["1/31", "1/84", "2/17", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âmidî", "slug": "amidi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyf-üddîn Alî bin Muhammed, \nşâfi’î fıkh ve kelâm âlimidir. 551 de Âmid, ya’nî Diyâr- ı Bekrde tevellüd, 631 [m. \n– 1077 –\n1234] de Şâmda vefât etdi.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âmine", "slug": "amine", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Resûlullahın “sallallahü aleyhi ve \nsellem” muhterem annesidir. Veheb bin Abd-i Menâf bin Zühre bin Kilâb kızıdır. \nOndört yaşında iken Abdüllah ile evlendi. Abdüllahın alnındaki nûr, Âminenin \nalnına geçip parladı. İki ay sonra Abdüllah vefât etdi. Yirmi yaşında iken, Medîne \nile Mekke arasında, (Ebvâ) denilen yerde vefât etdi. [Kusayy adına bakınız!].", "gectigiMaddeler": ["1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Amribni Âs", "slug": "amribni-as", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Âs bin Vâil-i Sehmînin oğludur. Es -\nhâb-ı kirâmın meşhûrlarındandır. Hicretin sekizinci [8] senesinde, Mekkenin fet-\nhinden altı ay önce, Hâlid bin Velîd ile birlikde Medîneye gelerek müslimân \nolmuşlardır. Fethden önce îmâna gelenlerinşereflerine ve yüksek derecelerine \nkavuşmuşlardır. Resûlullahın “sallallahü aleyhi ve sellem” Ummânda vâlîsi idi. \nHiç azl olunmadı. Ebû Bekr-i Sıddîk tarafından Şâmın fethine gönderildi. Mısra \nvâlî yapıldı. Doksan yaşında iken 43 [m. 663] senesinde Mısrda vefât etdi. Çok zekî \nidi. Meşhûr dâhîlerden idi. (Amr ibni Âs, Kureyşin sâlihlerindendir) hadîs-işerîfi \n(Medâric-ün-nübüvve)de yazılıdır.", "gectigiMaddeler": ["2/17", "2/44", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Amribni Luhay", "slug": "amribni-luhay", "unvan": "", "kategori": "diger", "biyografi": "Hicâzda Huzâ’a hükûmetinin reîsi idi. Şâmdaki \nputa tapınma dînini Mekkeye getirdi. Hicretden bin sene önce öldü.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "A'râbî Pâşa", "slug": "arabi-pasa", "unvan": "", "kategori": "diger", "biyografi": "Mısrda millî cebhe reîsi idi. İngilizlerin zulmüne karşı \nmücâdele etdi. 1329 [m.1911]de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Arfece", "slug": "arfece", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Arfece bin Es’ad Temîmî, Eshâb- ı kirâm-\ndandır. Altın burun takmasına izn verilmişdir.", "gectigiMaddeler": ["1/54"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ârif-i Rîvegerî", "slug": "arif-i-rivegeri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Buhârânın Rîvgir \nköyündendir. İslâm âlimlerinin büyüklerindendir. Çok yaşadı. 616 [m. 1219] da \nRîvgirde vefât etdi.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Aristo", "slug": "aristo", "unvan": "", "kategori": "diger", "biyografi": "Yunan felesoflarındandır. Mîlâddan [384] sene önce doğdu. \nBabası tabîb idi. Eflâtunun talebesi idi. İskenderin hocası oldu. Sonra, Atinada \nLisyonda mekteb yapdı. Onun için mekteblere lise denildi. Altmışiki yaşında Agri-\nboz adasında öldü. Rûh kadîmdir, derdi. Tecribeden ziyâde, aklına dayandığından, \nyanılmışdı. Orta çağda unutuldu. Eserleri, sonradan arabcadan lâtinceye çevrildi.", "gectigiMaddeler": ["1/24", "2/30", "2/67"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Arnd", "slug": "arnd", "unvan": "", "kategori": "diger", "biyografi": "Yirminci asrın büyük kimyâgerlerindendir. Sultân ikinci Abdül-\nhamîd hân zemânında İstanbul Dâr-ül-fünûnunda, uzun yıllar kimyâ profesörü idi. \n[m. 1934] de İstanbul üniversitesine tekrâr getirildi. Fritz Arnd iyi türkçe konuşur-\ndu. [m. 1969] sonunda Hamburgda öldü. Kıymetli din kitâbları yazarlığı ile tanın-\nmış Hüseyn Hilmi Işık, [m. 1936] senesinde, Arndın yanında çalışarak organik bir \ncism keşf etdi. Bu buluş, İstanbul fen fakültesi dergisi, 1937 senesi, ikinci cildin \nikinci sayısında ve Berlinde çıkan [m. 1937] yıl ve [2519] sayılı almanca (Zentrall \nBlatt) kimyâ kitâbında (Işık Hilmi) adı ile yazılıdır.", "gectigiMaddeler": ["1/24", "3/54"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ar Şimed", "slug": "ar-simed", "unvan": "", "kategori": "diger", "biyografi": "Eski yunan fizik ve matematikcisidir. Mîlâddan [278] sene \nönce, Sicilya adasında doğdu. [212] sene önce öldürüldü. İskenderiyyede Öklidin \ntalebesi idi. Kaldıraclar üzerinde çok uğraşdı. (Bana bir destek noktası veriniz! \nDünyâyı yerinden oynatayım) demişdir. Kitâbları Me’mûn zemânında arabcaya \nçevrildi.", "gectigiMaddeler": ["2/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Aryüs", "slug": "aryus", "unvan": "", "kategori": "diger", "biyografi": "Mîlâdın [270] senesinde doğdu. [336] da öldürüldü. Büyük Kos-\ntantinin mîlâdın üçyüzyirmibeşinde [325] İznikde topladığı üçyüzonsekiz [318] \npapasa karşı, yeni yapılan (İncîl)in yanlış olduğunu, Barnabas İncîlinin doğru \nolduğunu, orada Allah birdir denildiğini söyledi. Mısra kaçdı.", "gectigiMaddeler": ["1/25", "2/4", "3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âtıf Be Ğ", "slug": "atif-be-g", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kuyucaklı zâde Âtıf beğ, mül -\n– 1078 –\nkiyye mektebi [siyâsal bilgiler okulu] mecelle [hukûk] mu’allimi idi. 1316 [m. 1898] \nda, Bağdâdın Süleymâniyye kazâsında vefât etdi.", "gectigiMaddeler": ["1/78", "2/29", "3/11", "3/20"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Attilâ", "slug": "attila", "unvan": "", "kategori": "diger", "biyografi": "(Kâmûs-ül a’lâm) da diyor ki, (Orta çağlarda, Avrupayı basan \nvahşî Hunların reîsi idi. Mîlâdın [432] senesinde idâreyi ele aldı. Çok zâlim ve kan \ndökücü bir kumandan idi. [451] de Galyaya, ya’nî Fransaya girdi. [453] de içki içer-\nken öldü. Allahın gadabı denirdi).", "gectigiMaddeler": ["2/15", "2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Aynî", "slug": "ayni", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "(Buhârî) şârihidir. Bedreddîn Mah-\nmûd bin Ahmeddir. (Hidâyeşerhı) ve (Akd-ül-cümân) adındaki ondokuz cild târî-\nhi ve (Keşf-ül-lisân) adındaki İbni Hişâmşerhı meşhûrdur. 760 [m. 1359] da Ayn-\ntâbda tevellüd, 855 [m. 1451] de Kâhirede kâdî iken vefât etdi.", "gectigiMaddeler": ["2/53", "3/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Aynülkudât Hemedânî", "slug": "aynulkudat-hemedani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyyeden-\ndir. İmâm-ı Gazâlî ile sohbet etmişdir. 533 [m. 1138] de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Âzer", "slug": "azer", "unvan": "", "kategori": "diger", "biyografi": "İbrâhîm aleyhisselâmın amcası ve üvey babası idi. Kâfir idi. İbrâhîm aleyhisselâmın kendi babası Târuh idi.", "gectigiMaddeler": ["1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâbâ Âbriz", "slug": "baba-abriz", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "(Reşehât) kitâbında diyor ki, \n(Ubeydüllah-i Ahrâr hazretlerinin dedelerinden Ömer Dağistânî, Hasen-i Bulgârî-\nnin, bu da Muhammed Râzînin, bu da Hasen-i Sekânın, bu da Ebünnecîb-i Sühre-\nverdînin talebesidir. Bâbâ Âbriz, şeyh Ömerin talebesi olup, çok kerâmetleri \ngörülmüşdür.)", "gectigiMaddeler": ["2/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâbertî", "slug": "baberti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzkırkyedinci [647] sırada, \nMuhammed bin Mahmûd Bâbertî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâbürşâh", "slug": "babursah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Emîr Tîmûr Gürgân hânın \noğlu olan Esterâbâd fâtihi Mîrânşâhın torunu sultân Ebû Sa’îdin torunudur. Sul-\ntân Ebû Sa’îd, Ubeydüllah Ahrârın düâsını almışdı. Bâbür, 888 [m. 1482] de tevel-\nlüd, 933 [m. 1526] de Hindistânı alıp büyük bir islâm devleti kurdu. Bu devlet 1274 \n[m. 1858] senesinde ingilizlerin işgâline kadar, 342 sene sürdü. 937 [m. 1530] de \nvefât etdi. Kâbildedir. Âlim, âdil ve edîb idi. Hayâtını kendi yazdı. (Tüzük Bâbürî) \ndediği bu kitâbı, Ekberşâh zemanında Çagatay dilinden fârisîye, sonra ingilizceye \nterceme ve neşr edildi. Bâbürün kurduğu (Tîmûr oğulları) veyâ (Gürgâniyye) dev-\nletinin onyedi hükümdârı vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bacon", "slug": "bacon", "unvan": "", "kategori": "diger", "biyografi": "İngilterenin büyük fizikcisi idi. Fransisken tarîkatinde papas idi. 610 [m. 1214] da tevellüd, 691 [m. 1292] de vefât etdi.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâkânî", "slug": "bakani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nûreddîn Mahmûd Bâkânî Kâdirî, \nHanefî fıkh âlimidir. Dokuzyüzseksenyedi 987 [m. 1579] de vefât etmiş olan allâmeşeyh-ul-islâm Muhammed Behnesînin talebesidir. (Mecrel-enhür) adındaki (Mül-\ntekâ) şerhı çok kıymetlidir. Buşerhıni dokuzyüzdoksanbeş 995 [m. 1577] de \ntemâmlamışdır. (Risâletü-fişşürût-is-salât-il-cum’a) ve (Şerh-ün-nikâye-muhtasar-\nil-vikâye) kitâbları da vardır. 1003 [m. 1594] senesinde vefât etdi.", "gectigiMaddeler": ["1/73"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâkî Efendi", "slug": "baki-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mahmûd Abdülbâkî efen-\ndi, hemşâ’ir, hem âlim idi. 933 [m. 1526] de tevellüd, 1008 [m. 1600] de vefât etdi. \nEdirnekapıdadır. Nişâncı pâşayı cedîd yanında (Bâkî efendi mescidi) ni yapdırdı. \nKâdîasker iken vefât eyledi. Önce sarâc çırağı idi. Sonra ilm adamı oldu. Müder-\nrislik yapdı. Hazret-i Hâlid bin Zeydin bildirdiği hadîs-işerîfleri toplamışdır.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Barnabas", "slug": "barnabas", "unvan": "", "kategori": "diger", "biyografi": "Pâkistânda çıkan (Müslimmerks) mecmû’ası 1393 [m. \n1973] târîhli nüshasında diyor ki: (Joseph Barnabas, Kıbrısda doğdu. Yehûdî idi. Îsâ \naleyhisselâma îmân etdi. Eshâbından oldu. Fekat oniki Havârîsinden olup olmadığı \nbelli değildir. Îsâ aleyhisselâma inandığı ve çok sevdiği için, Havârîler, ona (Barna-\nbas) ismini verdiler. Fransızlar (Saint Barnabe) diyorlar. 11 Hazîranda yortusunu \nyapıyorlar. Yunan felsefesine saplanmış olan Bolüs, buna yanaşdı. Yıkıcı fikrleri-\n– 1079 –\nni aşılamak için, kendisi ile senelerce arkadaşlık yapdı. Avlıyamıyacağını anlayın-\nca, düşmanlığını açığa vurdu. İkisinin tarafdârları çoğalarak Îsevîler ikiye ayrıldı. \nPolcüler Avrupa krallarını elde edip kuvvetlendiler. Barnabacıların ise sayıları \nartdı. Bunlardan Antakya piskoposu Lucian, teslîse inanmadığı için 312 de öldü-\nrüldü. Bunun talebesi, Libyalı Ariusa, İskenderiyye piskoposu Peter tarafından \nkilisede vazîfe verildi. Sonra aforoz edildi. Çünki, bu da, Barnabas gibi, Îsâ insan-\ndır. Ona tapılmaz diyordu. Büyük Kostantinin zevcesi Polcü, kızkardeşi Kostanti-\nnia ise Ariuscu olmuşdu. İskenderiyyenin yeni piskoposu Aleksander ile Ariusun \ndüşmanlığı, Kostantinin milletini ikiye bölüyordu. İznik toplantısında Ariusun afo-\nroz edilmesine ve Barnabas İncîlinin yok edilmesine ve bu İ\nncîli okuyanların öldü-\nrülmelerine karâr verildi. Ariuscular yok edilmeğe başlandı. Kostantin pişmân \nolup, Ariusu İstanbula da’vet etdi ise de, gelirken öldürüldü. F.P. Sozzini 1562 de \nbir kitâb yazarak teslîsi red etdi. 1578 de Transilvanyada Kalusenberge gitdi. Bura-\nnın hükümdârı Ariuscu idi. Buranın piskoposu Francis David de [1510-1579] teslî-\nse karşı idi. \nBarnabasın yazdığı İncîl, mîlâdın 325. ci senesine kadar İskenderiyye kiliselerin-\nde okunuyordu. 383 senesinde Papa bu İncîlden bir nüsha elde ederek husûsî \nkütübhânesine koydu. Papa beşinci Sixtus, (1585-1590) arasındaki papalık zemâ-\nnında, arkadaşı F.O. Marinoya bunu ibrâniceden italyancaya terceme etdirdi. \nPrusya kralının müşâviri J.F. Gramer, bunu bulup 1713 de, Osmânlılarla yapdığı \nmühârebeleri ile meşhûr olan, kitâb meraklısı prens Eugene hediyye etdi. Prens \n1149 [m. 1736] da öldükden iki sene sonra, kütübhânesi Viyana (Hofbibliyothek) \nkütübhânesine katıldı. Bu el yazma İncîl, Viyana imperatorluk kütübhânesinde, \nhâlâ durmakdadır. Aynı senelerde, Madridde bir italyanca nüsha dahâ bulundu ise \nde, kilise baskısı ile yok edildi. Viyanadaki İncîl, 1325 [m. 1907] de Oxfordda, Ragg \nve hanımı tarafından ingilizceye terceme edildi. Bu tercemenin birçok nüshaları \nda, ingilizler tarafından yok edildi. Bu nüshadan foto-ofset yolu ile, 1973 de Pâkis-\ntânda ikibin nüsha basılmışdır. İkiyüzelli sahîfedir. S.Alî Yûsüf, P.O.Box 2120, \nKarachi -18- den istiyenlere gönderilmekdedir.)", "gectigiMaddeler": ["1/24", "1/25", "2/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Batlemyüs", "slug": "batlemyus", "unvan": "", "kategori": "diger", "biyografi": "Buna Batlemyus ve Ptolemee de denir. Mısrda Sa’îdde \ntevellüd ve mîlâdın [167] senesinde İskenderiyyede vefât etdi. Astronomi, târîh ve \ncoğrafya ile uğraşdı. (Dünyâ duruyor, gökler dönüyor) derdi. Astronomi üzerinde \neski yunanca yazdığı Mecistî kitâbı meşhûrdur. (Mecistî), ekber [büyük] demekdir. \nArabîye terceme edilmişdir. Arabîden de lâtinceye çevrilmişdir.", "gectigiMaddeler": ["2/30", "2/67"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Battâl Gâzî", "slug": "battal-gazi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Battâl gâzî, islâm \nmücâhidlerindendir. Rumlarla çok cihâd etdi. Mesleme kumandasındaki ordu ile, \ndoksanaltı 96 [m. 715] senesinde İstanbula geldi. Yüzyirmibir [121] senesindeşehîd oldu. Eskişehrin Seyyid gâzî kazâsındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâyezîd-ı", "slug": "bayezid-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yıldırım sultân Bâyezîd, Osmânlı \npâdişâhlarının dördüncüsüdür. Murâd- ı Hüdâvendigârın oğlu ve Çelebî sultân Mu -\nhammedin babasıdır. 761 [m. 1360] de tevellüd etdi. 791 [m. 1388] de, babasışehîd \nolunca, tahta çıkdı. Rumelide ve Anadoluda çokşehrler aldı. Macaristana kadar feth \netdi. İstanbulu almak için Anadolu hisârını yapdı ise de, 791 [m. 1388] de İstanbul \nimperatörü, senede onbin altın cizye vermeği veşehrde bir müslimân mahalle ve \ncâmi’ yapmağı istedi. Fekat üç sene sonra, bunları yıkdı. Yıldırım, şehri on sene \nmuhâsara etdi. Alman, Macar, Fransız orduları yardıma gelirken, 799 [m. 1396] da \nYıldırım hücûm ederek Niğboluda hepsini perişân etdi. 805 [m. 1402] de, Ankarada \nTîmûr ile harb ederken, oğlu Süleymân efendinin emrindeki asker Tîmûr tarafına \ngeçince, mağlûb ve esîr oldu. Tîmûr çok i’zâz ve ikrâm etdi ise de, kederinden sekiz \nay sonra nefes darlığından vefât etdi. Bursaya defn edildi. Tîmûr, Yıldırımın ölü -\nmünü işitince, (Yazık oldu. Büyük bir mücâhid gayb etdik) dedi. Çok cesûr ve âdil \n– 1080 –\nidi. İslâm düşmanları, bu kahramân mücâhidi lekelemek için, içki içerdi diye iftirâ \netdi ise de, bunu bildiren hiç bir vesîka yokdur. 797 [m. 1394] de Bursada yapdırdığı \n(Câmi’-i kebîr), islâmiyyete olan bağlılığının büyük bir vesîkasıdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bâyezîd-i Bistâmî", "slug": "bayezid-i-bistami", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Evliyânın büyükle-\nrindendir. Üveysî idi. [136] veyâ [188] senesinde Îrânda, Hazer denizi kenârında, \nBistâmda tevellüd, 231 [m. 846] veyâ 261 [m. 875] senesinde burada vefât etdi. Adı \nTayfur, babası Îsâ idi. İmâm-ı Ca’fer-i Sâdıkın vefâtından kırk sene sonra tevellüd \nederek, imâm- ı Alî Rızânın sohbetinden ve bunun bereketi ile imâm- ı Ca’ferin \nrûhâniyyetinden istifâde etmişdir. (Şerh-ı mevâkıf) altıyüzonyedinci [617] sahîfe-\nsinde diyor ki, (Ebû Yezîd, imâm- ı Ca’fer-i Sâdık zemânında yokdu. Fekat, imâ-\nmın rûhundan istifâde etdi. Bundan feyz alması ile meşhûr oldu.) Bu husûsda \nEbûl-esfâr Alî Muhammed Belhînin (Târîh-u evliyâ) kitâbında geniş ma’lûmât \nvardır. Otuz sene Şâm civârında dolaşmış, yüzonüç Velî ile sohbet etmişdir. 50, 94, \n503, 564, 684, 957, 958, 969, 1051, 1093, 1094, 1162, 1178. \n— Bedr Gazâsı: Hicretin ikinci senesinde Ramezân ayında Cum’a günü oldu. \nMüslimânlar 313, Kureyşliler bin kişi idi. Yüzü süvârî idi. 14 Sahâbîşehîd oldu. \nEbû Cehl ile yetmiş kâfir katl edildi. 506.cı sahîfeye bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bedrüddîn-i Lü'lü", "slug": "bedruddin-i-lulu", "unvan": "", "kategori": "diger", "biyografi": "Mûsul atabeklerinden Nûreddîn-i Arslanşâhın kölelerinden idi. 607 [m. 1210] senesinde, şâh ölünce oğlu adına idâreyi ele \naldı. Elli sene hükm sürdü. Hülâgüye itâ’at etdi. 657 [m. 1259] de öldü.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bedrüddîn Samâvnevî", "slug": "bedruddin-samavnevi", "unvan": "", "kategori": "diger", "biyografi": "Samavne kâdîsi oğlu Mahmûd Bedred-\ndîn, Mısrda okuyup, sultân Ferruh bin Berkuka hoca olmuş, şeyh Hüseyn Ahlâtî-\nden tesavvuf öğrenmişdir. Tebrîzde Tîmûrun sohbetlerinde bulundu. Edirnede \nMûsâ çelebînin kâdî-askeri oldu. Mehmed çelebî, Mûsâ çelebîyi öldürünce, bunu \nafv edip, İznikde vazîfe verdi. Buradan İsfendiyar beğe kaçdı. Sonra ilhâda sapıp, \nmürîdleri halkın îmânlarını bozmağa başladılar. Üzerlerine Bâyezîd pâşa gönde-\nrilip dağıtıldılar. Kendisi Bosnaya kaçdı. Mürîdler topladı. Yine sapık yol tutdu-\nlar. Üzerlerine yine asker gönderildi. Tevbe eden mürîdleri tarafından yakalanıp \nteslîm edildi. Mevlânâ Hayder Hirevînin başkanlığındaki ilm heyeti tarafından \nmuhâkeme olunarak, verdikleri fetvâ ile, sekizyüzonsekiz 818 [m. 1415] veyâ 823 \n[m. 1420] de Serezde i’dâm edildi.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Beethoven", "slug": "beethoven", "unvan": "", "kategori": "diger", "biyografi": "Almandır. Mûsîkîcidir. Dokuz symphonisi meşhûrdur. \n1184 [m. 1770] de tevellüd, 1243 [m. 1827] de vefât etdi.", "gectigiMaddeler": ["1/25", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Begavî", "slug": "begavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hüseyn bin Mes’ûd, Muhyissünne \ndenir. Horâsânda (Bâg) şehrinde tevellüd ve 516 [m. 1122] da vefât etdi. Şâfi’î fıkh \nâlimidir. (Me’âlim-üt-tenzîl) adındaki tefsîri ile, (Mesâbih) hadîs, (Tehzîb) fıkh \nkitâbı meşhûrdur.", "gectigiMaddeler": ["1/97", "2/4", "2/23", "2/44", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Behâeddîn Muhammed bin Muhammed Buhârî", "slug": "behaeddin-muhammed-bin-muhammed-buhari-rahme-tu", "unvan": "", "kategori": "diger", "biyografi": "Şâh-ı Nakşibend denir. Evliyânın büyüklerindendir. Müslimânların gözbebeğidir. Seyyiddir. Buhârâda (Kasr-ı ârifân) şehrinde 718 [m. 1318] de tevellüd ve 791 [m. 1389] de orada vefât etdi. İki def’a hacca gitdi. Çok evliyâ yetişdirdi. (Evrâd), (Tuhfe) ve (Hediyye) kitâbları çok kıymetlidir. Hâl tercemesi ve kerâmetleri, fârisî (Enîs-üt-tâlibîn) de uzun yazılıdır. Bu kitâb, Fâtihde, Hakîkat Kitâbevi tarafından m.1993 de, ofset ile basdırılmışdır. İzzî Süleymân efendi türkçeye terceme ve tab’ edilmiş ve 1168 [m. 1754] de vefât etmişdir. Murâd-i Münzâvî kabristânındadır. (Mekâtîb-işerîfe)nin seksenyedinci mektûbunda da, uzun yazılıdır. Muhammed Huccetullah Nakşibend-i sânî, Muhammed Ma’sûm hazretlerinin oğlu olup, 1115 [m. 1703] de vefât etdi. Serhenddedir.", "gectigiMaddeler": ["1/41", "1/46", "2/17", "2/52", "2/61", "3/27", "3/28", "3/37", "3/44", "3/51", "3/52", "3/53", "3/55", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Behâî", "slug": "behai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlışeyh-ul-islâmlarının otuzi-\n– 1081 –\nkincisidir. 1064 [m. 1654] de vefât etdi. Tütün câiz derdi ve içerdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Behâullah", "slug": "behaullah", "unvan": "", "kategori": "diger", "biyografi": "Mirzâ Hüseyn Alî Nûrî denir. 1232 [m. 1817] de Îrânda \nNûr kasabasında doğdu. 1309 [m. 1892] da Akkâda öldü. Bunun için Filistin Behâî-\nlerin mukaddes yeridir. Elbâb Alî Muhammed adında bir acemin talebesi idi. \nHocasının düşüncelerini, yüzden fazla mektûb ve kitâbları ile dünyâya yaydı. Bu \nfikrlere (Behâîlik) dedi. Îrânda, habs edilip, Bağdâda kaçdı. Bağdâddan İstanbula, \nburadan da Akkâya sürüldü. Burada yirmidört sene habsde kaldı. (Hüvallah) \nadındaki kitâbı 1326 [m. 1908] senesinde Petersburgda basılmışdır.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bel'am bin Bâûrâ", "slug": "belam-bin-baura", "unvan": "", "kategori": "diger", "biyografi": "Mûsâ “aleyhisselâm” zemânında idi. İsm-i a’za-\nmı biliyor, her düâsı kabûl oluyordu. Bulunduğu Belkaşehrinin vâlîsi Belâk, Mûsâ \naleyhisselâmın askerininşehre girmemesi için, düâ etmesini istedi. Ölüm ile tehdîd \netdi. Cân korkusu ile ve halkın verdiği rüşvete aldanarak, Mûsâ aleyhisselâma \nkarşı düâ etdi. Mûsâ aleyhisselâmın askeri tarafından öldürüldü. (A’râf) sûresinde \nsoluyan köpeğe benzetildi.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Belkıs", "slug": "belkis", "unvan": "", "kategori": "diger", "biyografi": "Yemende Sebe’ şehrinde hükûmet süren Himyerîlerden bir \nkadın sultândır. Süleymân “aleyhisselâm” bunu Filistine çağırdı. Geldi ve îmân \netdi. Mûsâ aleyhisselâmın vefâtından beşyüzotuzbeş sene sonra, Dâvüd “aleyhis-\nselâm” vefât edince, oniki yaşındaki oğlu Süleymân “aleyhisselâm” babasının yeri-\nne geçdi. Sultân ve sonra Peygamber oldu. Dört sene sonra, Mescid-i aksâyı yap-\nmağa başladı. Yedi senede temâmlandı. Sonra hükûmet serâyına başladı. Bu da \nonüç senede yapıldı. Bundan bir sene sonra, Belkıs gelip, görüşdüler. Süleymân \n“aleyhisselâm” kırk sene hükûmet eyledikden sonra, vefât etdi. Belkısın Süleymân \n“aleyhisselâm” ile mektûblaşması ve Kudüse gelmesi, Kur’ân- ı kerîmde Neml \nsûresinde uzun beyân olunmakdadır.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Berâ' bin Âzib", "slug": "bera-bin-azib", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb-ı kirâmdandır. Ensârdandır. \nBedr gazâsında çocuk idi. Diğer gazâlarda bulundu. Hazret-i Alî ile birlikde Cemel, \nSıffîn ve Hâricî savaşlarında bulundu. 72 [m. 691] de Kûfede vefât etdi.", "gectigiMaddeler": ["1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bergson", "slug": "bergson", "unvan": "", "kategori": "diger", "biyografi": "Fransız fikr adamıdır. 1275 [m. 1859] de tevellüd, 1360 [m. \n1941] da vefât etdi. (Madde ve hâfıza), (Din ve ahlâkın iki kaynağı), (Şu’ûrun ver-\ngileri) kitâbları meşhûrdur.", "gectigiMaddeler": ["1/11", "2/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Beşîr Ağa", "slug": "besir-aga", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "1129 [m. 1717] da Dâr-üs-\nseâde ağası, ya’nî İstanbul vâlîsi olmuş, otuz sene bu vazîfede bulunmuşdur. 1159 \n[m. 1746] da, doksanaltı yaşında vefât etmişdir. Bâb-ı âlîde bir câmi’ ve burada ve \nEyyûbde Baba-Haydarda mekteb, kütübhâne ve çeşme yapdırmışdır. Ahmed \nYekdestin talebesidir. Kabri Eyyûb sultân türbesinin kapısı yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Beydâvî", "slug": "beydavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdî Abdüllah bin Ömer, Şîrâz \ncivârında Beydâşehrinde tevellüd, 685 [m. 1286] senesinde Tebrîzde vefât etdi. \nŞîrâzda kâdî idi. Tefsîr ilminin büyük üstâdıdır. (Envârüttenzîl) tefsîr kitâbı çok \nkıymetlidir. Şâfi’î mezhebinde fıkh âlimidir. İlminden, takvâsından bir parçası \n(Mevdû’ât-ül-ulûm)da yazılıdır. Okuyup anlıyan, onun tefsîrine dil uzatamaz. Fıkh \nve ahlâk ilminde de kitâbları vardır. (Tavâli’ul-envâr) ismindeki kelâm kitâbında, \neski yunan felesoflarının birçok yazılarını bildirip, bunlara cevâblar vermişdir. Bu \nkitâbı gören câhiller, ( İmâm-ı Beydâvî, kitâblarına yunan felsefecilerinin yazıları-\nnı, fikrlerini karışdırmışdır) demişlerdir. Hâlbuki, onların fikrlerini benimseme-\nmiş, onları cevâblandırmış, red etmişdir. Tefsîrinde, onların fikrleri hiç mevcûd \ndeğildir.", "gectigiMaddeler": ["1/97", "1/98", "2/5", "2/18", "2/21", "2/30", "2/44", "3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Beyhekî", "slug": "beyheki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nişâpûrun Beyhek kasabasında \n384 [m. 994] de tevellüd ve 458 [m. 1066] de orada vefât etdi. Ebû Bekr Ahmed bin \nHüseyn, hadîs ve Şâfi’î fıkh âlimi idi. Kitâblarının adedi binden fazladır. Bunlar \narasında (Delâil), (Sünen) ve \n(Şu’abül-îmân) kitâbları çok kıymetlidir. 164, 278, \n279, 313, 419, 424, 465, 476, 511, 643, 723, 740, 993, 1013, 1014, 1070. \n– 1082 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bezm-i Âlem Sultân", "slug": "bezm-i-alem-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Abdülmecîd \nhânın vâlidesidir. Câmi’, çeşme ve mekteb gibi çok hayrâtı vardır. Topkapıda \n(Gurebâ hastahânesi)ni ve Dolma-bağçe serâyı yanındaki vâlide câmi’ini yapdırdı. \n1269 [m. 1852] de vefât etdi. Sultân Mahmûd türbesindedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bilâl-i Habeşî", "slug": "bilal-i-habesi", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Babası Ribâhdır. Resûlullahın \nmüezzini idi. Umeyye bin Halefin kölesi idi. Müslimân olduğu için karnına taş bağ-\nlayıp kızgın kum üzerinde iple, ayağından çekerlerdi. Ebû Bekr-i Sıddîk satın alıp \nazâd etdi. Her gazâda bulundu. [20] senesinde Şâmda vefât etdi. Sesi çok güzeldi. \nEzân okurken, herkes ağlardı.", "gectigiMaddeler": ["1/61", "1/95", "2/23", "2/44", "2/72"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Birgivî", "slug": "birgivi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Zeyn-üd-dîn-i Muhammed efendi. \nBabası Alîdir. 928 [m. 1521] de Balıkesirde tevellüd, 981 [m. 1573] de (Birgi)de \ntâ’ûndan vefât etdi. (Vasıyyetnâme), (Tarîkat-ül-Muhammediyye), (Avâmil) ve \n(İzhâr) kitâbları ve (Etfâl-ül-müslimîn) risâlesi ve kadınların hayz hâllerini bildi-\nren (Zuh-rul-müteehhilîn) risâlesi çok kıymetlidir. İbni Âbidîn (Zuhr)uşerh ede-\nrek (Menhel-ülvâridîn) ismini vermişdir. (Tarîkat)i Abdülganî ve Hâdimîşerh, \nSüleymân Fâdıl efendi, ihtisâr etmişlerdir. Bu muhtasara (Miftâh-ul-felâh) ismini \nvermiş, bu üçünü ve (Menhel)i Hakîkat Kitâbevi ofset ile basdırmışdır.", "gectigiMaddeler": ["2/17", "2/44", "2/53", "3/37", "3/59", "3/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bişr-i Hâfî", "slug": "bisr-i-hafi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Evliyânın büyüklerindendir. \n150 [m. 767] de Mervde tevellüd, 227 [m. 841] de Bağdâdda vefât etdi.", "gectigiMaddeler": ["2/34", "2/40", "2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bohr", "slug": "bohr", "unvan": "", "kategori": "diger", "biyografi": "Danimarkalı fizikcidir. [m. 1885] de doğdu. 1340 [m. 1922] da \natomların devâmlı değil, kesik kesik enerji verdiklerini tesbit ederek, enerjinin ve \natomun yapısının sonşeklini gösterdi. Nobel mükâfâtı aldı.", "gectigiMaddeler": ["2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Bolüs", "slug": "bolus", "unvan": "", "kategori": "diger", "biyografi": "Yediyüzellidördüncü [754] sırada Paulus ismine bakınız!", "gectigiMaddeler": ["1/24"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Boyle", "slug": "boyle", "unvan": "", "kategori": "diger", "biyografi": "Robert Boyle İngiliz fizikçisi ve kimyâgeridir. 1034 [m. 1624] \nde tevellüd, 1102 [m. 1691] de vefât etdi. Fransız fizikcisi olan Mariot ile aynı ze -\nmânda gazların basıncı kanûnunu buldu.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Brockelmann", "slug": "brockelmann", "unvan": "", "kategori": "diger", "biyografi": "Alman müsteşrikidir. Arabî din kitâblarının kılavu-\nzunu almanca olarak yazmışdır. 1362 [m. 1943] de Hollandada Leidenşehrinde \nbasılmışdır.", "gectigiMaddeler": ["1/7"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Buhârî", "slug": "buhari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin İsmâ’îl 194 [m. \n810] de Buhârâda tevellüd, 256 [m. 870] da Semerkandda vefât etdi. Kur’ân- ı \nkerîmden sonra dünyânın en kıymetli kitâbı olan (Câmi-i sahîh) hadîs kitâbı, \n(Buharî-işerîf) adı ile meşhûrdur. İçinde [7275] sahîh hadîs vardır. Bunları altı-\nyüzbin hadîs-işerîf arasından seçmişdir. Bu kitâbını onaltı senede vücûde getir-\nmişdir. Çokşerhleri ve baskıları yapılmışdır. 1312 [m. 1894] senesinde sultân \nAbdülhamîd hân tarafından Mısrda yapdırılan iki cild baskısı, pek nefîs cildlen-\nmiş, altın tugra ve nukûş ile tezyîn edilmişdir. 1315 senesinde, İstanbulda (Mat-\nbaa-i âmire) baskısı da latîf olup, 1413 [m. 1992] de ziyâ üsûlü ile teksîr edilmişdir. \nBaşka çok kitâbları da vardır. Zeyn-üd-dîn Ahmed Zübeydînin 889 da hâzırladığı, \niki cild, Buhârî muhtasarı, (Tecrîd-i sarîh) ismi ile, 1347 de Mısrda basılmış, 1390 \n[m. 1970] da Beyrutda ofset baskısı yapılmışdır.", "gectigiMaddeler": ["2/6", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Buhtunnasar", "slug": "buhtunnasar", "unvan": "", "kategori": "diger", "biyografi": "Nabuchodonosor, Âsûrî devletinin en meşhûr \nhükümdârıdır. Mîlâddan [603] sene önce, Filistini alıp Kudüsü yıkdı. Tevrât nüs-\nhalarını imhâ etdi. Yehûdî âlimlerini ve Danyal aleyhisselâmı Bâbilde esîr etdi. \nEsîrlik yetmiş sene sürmüşdür. Sûriye ve Mısrı da çöllere kadar aldı. Mîlâddan \n[562] sene önce vefât etdi. Ateşe tapardı.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Burhâneddîn-i Buhârî", "slug": "burhaneddin-i-buhari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Beşyüzyet-\n– 1083 –\nmişdördüncü [574] sırada, Mahmûd-i Buhârî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Burhâneddîn-i Mergınânî", "slug": "burhaneddin-i-merginani-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Burhâneddîn Alî bin Ebî Bekr, Fergâne kasabalarından Mergınânda tevellüd ve 593 [m. 1197] de Cengiz askeri tarafındanşehîd edildi. Çok kitâb yazdı. Bunlardan (Hidâye) ve (Tecnîs) meşhûrdur. Cengizin Buhâraşehrini tahrîb ve ehâlisini katl etmesi 616 hicrî senesinde olduğu ve Burhâneddîn Mahmûd Buhârînin bu esnâdaşehîd olduğu (Kısas-ı enbiyâ) ve (Kâmûs-ul-a’lâm)da yazılıdır. (Hidâye)si Milton tarafından ingilizcesi ile birlikde 1206 [m. 1791] de basıldı. (Hidâye) şerhleri çokdur. Talebesi, Hüseyn bin Alî Hüsâmeddîn Sagnâkî, yapdığışerhe (Nihâye) ismini vermiş, 710 [m. 1309] da vefât etmişdir. Ekmeleddîn-i Bâbertînin (İnâye) adındakişerhıne Sa’dî Çelebînin hâşiyesi meşhûrdur.", "gectigiMaddeler": ["1/98", "2/16", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Burhân-Ü Ş-Şerî'a", "slug": "burhan-u-s-seria", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mahmûd bin Sadr-\nüş-şerî’a-tül-evvel Ahmed bin Ubeydüllah Mahbûbî, 673 [m. 1274] de Moğol \naskerlerinin işkencelerinde yüzlerce âlimler ile birlikdeşehîd oldu. (Vikâye) kitâbı \nmeşhûrdur. (Vikâye) kitâbını, kızının oğlu olan Sadr-üş-şerî’a-i sânî Ubeydüllah \nbin Mes’ûd için yazmışdır. (Hidâye) kitâbından önemli gördüğü yerleri alarak yaz-\nmışdır. Bu da, (Vikâye)yi kendisi hemşerh etmiş, hem de ihtisâr etmişdir. Şerhı \n(Sadr-üş-şerî’aşerhı) adı ile meşhûrdur. (Muhtasar)ına da, (Muhtasar-ı Vikâye) \nveyâ (Nikâye) adını vermişdir. (Nikâye)nin çeşidli arabîşerhleri vardır. Bâkânîninşerhı ve Kuhistânînin (Câmi’ur-rümûz) adındakişerhı en meşhûrlarındandır. \n(Nikâye)nin fârisîşerhlerinden, Celâleddîn Mahmûd bin Ebû Bekrin (Terceme-\ntül-muhtasar) adındakişerhı 1317 [m. 1898] de İstanbulda basılmışdır. \nMahmûd bin Ubeydüllah, Burhâneddîn-i Mergınânînin torunlarındandır. \nDâmâdı, Mes’ûd bin Tâc-üş-şerî’a Ömerdir. (Vikâye)ninşerhleri arasında İznik \nmedresesinde müderris Alâüddîn Alî bin Ömerin (İnâye) adındakişerhı meşhûr-\ndur. (Vikâye)nin Sadr-üş-şerî’aşerhıne yapılan hâşiyeler arasında Ehî Çelebînin \n(Zahîre-tül-ukba)sı ve Şeyhülislâm Mevlânâ İsâmeddîn İsferâyînin hâşiyesi çok \nkıymetlidir. İsâmeddîn İbrâhîm bin Muhammed 944 [m. 1536] de Semerkandda \nvefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Busayrî", "slug": "busayri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Muhammed bin Sa’îd \nŞeref-üd-dîn, büyük islâmşâ’iridir. Hadîs ilminde ve hattâtlıkda mâhir idi. Ebül \nAbbâs-ı Mürsînin talebesidir. 609 [m. 1213] da Mısrda Busayrşehrinde tevellüd ve \n695 [m. 1295] de Mısrda vefât etdi. (Bürde) ve (Hemziyye) kasîdeleri olup, çeşidli \ndillerde doksandan fazlaşerhleri vardır.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Câbir bin Abdüllah", "slug": "cabir-bin-abdullah", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmdandır. \nİstanbulu muhâsara ederken, 74 [m. 693] senesindeşehîd olduğu ve Koca Mustafâ \npâşada bulunduğu sanılmakda ise de, kitâblar Medîne-i münevverede vefât etdiği-\nni yazmakdadır.", "gectigiMaddeler": ["1/63", "1/79", "1/96", "2/23", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Câbir bin Sümre", "slug": "cabir-bin-sumre", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmdan olup, Sa’d \nibni Ebî Vakkâs hazretlerinin hemşîresi Hâlidenin oğludur. Kûfede yerleşdi. 66 \n[m. 685] senesinde vefât etdi.", "gectigiMaddeler": ["1/96"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ca'fer-i Sâdık", "slug": "cafer-i-sadik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah da denir. \nHazret-i Alînin torununun torunudur. Muhammed Bâkırın oğlu ve Mûsâ Kâzımın \nbabasıdır. Oniki imâmın altıncısıdır. [83] de Medînede tevellüd, 148 [m. 765] de \norada vefât etdi. İmâm-ı a’zam ve kimyâger Câbir, bunun talebesi idiler. Büyük \noğlu İsmâ’îl, babasından önce vefât etdi. Yedinci imâm İsmâ’îldir ve ondan sonra \nçocuklarıdır diyen sapıklara (İsmâ’îlî) denir. Şî’îler, kendilerine (Ca’ferî) diyor. \nHâlbuki, bu büyük imâm, Ehl-i sünnet idi. Ehl-i sünnet âlimlerinin ve Evliyânın \nüstâdı idi. Büyük islâm âlimlerinin gözbebeğidir. Din bilgisi üzerinde hiç kitâb \nyazmadı. Şî’îlerin dört esâs kitâbı olan Küleynînin (Kâfî)si, İbni Bâbeveyh Ebû \nCa’fer Muhammed bin Ahmed Alî Kummînin (Menlâ yahdur) u, Ebû Ca’fer Mu -\n– 1084 –\nhammed bin Hasen Tûsînin (Tehzîb) ve (İstibsâr) kitâblarında, imâm- ı Ca’fer \nSâdıkdan emrler, haberler yazılı ise de, bunları bildirenlerin sağlam ve sahîh olma-\ndıklarını kendileri de bildirmekdedir. İmâmiyyenin otuzikinci fırkasına (Ca’feriy-\nye) denilir. Bunlar, Hasen-i Askerî öldükden sonra, kardeşi Ca’fer bin Alî imâm \noldu. Hasen-i Askerînin evlâdı yokdu derler. Bu Ca’ferîlerin, imâm-ı Ca’fer Sâdık-\nla bir ilgileri yokdur. Şî’îlerin bugün ellerinde bulunan hadîs ve fıkh kitâblarını \nEbû Ca’fer Muhammed bin Ya’kûb Küleynî ile Ebû Ca’fer Muhammed bin Hasen \nKummî yazdıkları için, kendilerine Ca’ferî diyorlar.", "gectigiMaddeler": ["1/31", "1/89", "2/5", "2/16", "2/21", "2/30", "2/45", "3/42", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ca'fer Tayyâr", "slug": "cafer-tayyar", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ebû Tâlibin oğludur. Hazret-i \nAlîden on yaş büyük, hazret-i Ukaylden on yaş küçük idi. Habeşe hicret edip, \nHayber günü avdet buyurmuşdu. Hicretin sekizinci [8] senesinde, üçbin askerle, \nŞâm civârında (Mü’te)de rumlarla harb ederken, çok hücûm etdi ve kırkbir yaşın-\ndaşehîd oldu. O gün yetmişden fazla yara almışdı. Resûlullaha çok benziyen yedi \nkişiden biri bu idi.", "gectigiMaddeler": ["1/84", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Calvin", "slug": "calvin", "unvan": "", "kategori": "diger", "biyografi": "Kalven, protestanlığı kuran papaslardandır. 914 [m. 1509] de \ntevellüd, 971 [m. 1564] de ölmüşdür.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Câmî", "slug": "cami", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "615.ci sırada Molla Câmî ismine bakı-\nnız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Câmî Ahmed", "slug": "cami-ahmed", "unvan": "", "kategori": "diger", "biyografi": "Seksenbirinci [81] sırada Ahmed Câmîye bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Celâleddîn-i Devânî", "slug": "celaleddin-i-devani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \nEs’ad, büyük âlimdir. 833 [m. 1426] de tevellüd, 908 [m. 1502] de vefât etdi. Şîrazda \nyaşadı. Çok kitâb yazdı. (Akâid-i Adudiyye)  şerhı meşhûrdur. (Levâmi’ul işrak) \nismindeki (Ahlâk-ı celâlî) kitâbı ingilizceye terceme edilmişdir.", "gectigiMaddeler": ["3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Celâleddîn-i Egrî", "slug": "celaleddin-i-egri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindistânda kâdî \nidi. Derin âlim idi.", "gectigiMaddeler": ["3/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Celâleddîn-i Hindî", "slug": "celaleddin-i-hindi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMahmûd Celâleddîn-i kebîr pânî-pütî, Çeştiyye meşâyıhindendir. Hazret-i Osmân \nsoyundandır. Şems-üddîn-i pânî-pütînin halîfesidir. O da, hâce mahdûm Alî Sâbi-\nrin, bu da Ferîdeddîn Gencşekerin halîfesidir. Yediyüzaltmışbeş 765 [m. 1363] de \nvefât etdi. Pânî-pütşehrinde büyük türbesi vardır. (Fevâid-ül-füâd) ve (Zâd-ül-\nebrâr) kitâbları çok kıymetlidir. Senâüllah-i pânî-pütî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Celâleddîn Muhammed Rûmî", "slug": "celaleddin-muhammed-rumi-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Evliyânın büyüklerindendir. (Mekâtîb-işerîfe)nin yüzyedinci mektûbunda diyor ki, (Mevlânâ Celâlüddîn Rûmî, Ehl-i sünnet Evliyâsının büyüklerindendir.) Kâdirî tarîkatinde idi. 604 [m. 1207] de Belhşehrinde tevellüd, 672 [m. 1273] de Konyada vefât etdi. Babası sultân-ül-Ulemâ Muhammed Behâeddîn-i Veled büyük âlim ve Velî idi. Dahâ çocuk iken babasının kalbindeki feyzlere kavuşdu. (Nefehât)da diyor ki, (Beş yaşında iken kirâmen kâtibîn meleklerini, Evliyânın rûhlarını ve sokakda dolaşan cinnîleri görürdü.) Pederi, oğlu ile Hicâza, sonra Şâma ve Konyaya geldi. Babası ölünce, oğlu ders verirdi. Önce Pederinin halîfesi olan Seyyid Bürhâneddîn Tirmüzîden dokuz sene feyz aldı. Seyyid Bürhâneddîn Kayseride medfûndur. Bundan sonra, Şemseddîn-i Tebrîzî gelip irşâd eyledi. Ney ve dümbe", "gectigiMaddeler": ["1/27", "1/41", "1/97", "2/49", "2/52", "2/53", "3/27", "3/28", "3/55", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cemâleddîn-i Efgânî", "slug": "cemaleddin-i-efgani", "unvan": "", "kategori": "diger", "biyografi": "Mason idi. Mısrlı Edîb İshak, (Ed-dürer) \nkitâbında, bunun Kâhire mason locası reîsi olduğunu yazmakdadır. 1380 [m. 1960] \nde Fransada basılan, fransızca (Les franco-maçons) kitâbının yüzyirmiyedinci sahî-\nfesinde, (Mısrda kurulan mason localarının başına Cemâleddîn Efgânî ve ondan \nsonra Muhammed Abdüh getirildi. Bunlar, müslimânlar arasında masonluğun yayıl-\nmasına çok yardım etdiler) diyor. Bu sahîfesinde, birşarklının mason locası başkan-\nlık elbisesi ile büyük bir resmi de vardır. Erzurum üniversitesi profesörlerinden \nM.Kaya Bilgegil (Ziyâ pâşa) adındaki kitâbında, Ziyâ pâşanın ve Cemâleddîn-i \nEfgânînin mason olduklarını yazmakdadır. Bütün masonlar gibi, çeşidli kılıklara \ngirerek, islâmiyyeti içerden yıkmağa çalışmışdır. 1254 [m. 1838] de Efganistânda \ntevellüd ve 1314 [m. 1897] de İstanbulda vefât etdi. Din bilgisi azdı. Zındıkların \nkitâblarını okuyarak dinden çıkmışdır. Bir aralık ruslar tarafından satın alınarak, \nana vatanı olan Efganistâna karşı câsûsluk yapdı. Dînine ve vatanına hiyânet etmek-\nden çekinmedi. İngiliz masonları ile de işbirliği yaparak zengin oldu ise de, Osmânlışeyh-ul-islâmı Hasen Fehmî efendi, onun câhilliğini ve zındıklığını ortaya koydu. \n(Fâideli Bilgiler) kitâbında hâl tercemesi uzun yazılıdır. 1944 senesinde, kemikleri, \nİstanbuldan, Kâbile nakl edildi. Abdüh ismine bakınız!", "gectigiMaddeler": ["2/17", "3/19"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cemşîd", "slug": "cemsid", "unvan": "", "kategori": "diger", "biyografi": "Cem de denir. Îrânda ilk hükûmet kuran Pişdânî oğullarının \ndördüncü hükmdârı olup, sekizyüz sene saltanat sürmüş, beşyüz sene Îrânda kimse \nhasta olmamış. Bunun için, milleti kendine tapdırmışdır. Martın yirminci günü \ntahta çıkdığı için, bugüne Nevruz diyerek yılbaşı ve dînî bayram yapmışdır. Bu \nkâfir bayramı, Îrânda bugün de kutlanmakdadır. Câhiller, Îrânda ve başka islâm \nmemleketlerinde, islâmiyyetden önce yaşamış olan kâfirlerin âdetlerini, tapınma-\nlarını, bugün meydâna çıkararak, ecdâd yâdigârı diyor, millete bunları yapdırıp, \ndinden çıkarıyorlar. İngilizler de, bu islâm düşmanlığını körüklüyorlar. Cemşîd bin \nyaşında iken, Şeddâdın birâderzâdesi olan Dahhâk ile muhârebede yakalanmış, \ndestere gibi olan balık kemiği ile ikiye biçilmişdir.", "gectigiMaddeler": ["1/30", "2/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cengiz Hân [dechingis-chan]", "slug": "cengiz-han-dechingis-chan", "unvan": "", "kategori": "diger", "biyografi": "CENG İZ HÂN [Dechingis-chan]: Cengiz veyâ Timoçin denir. Türk \ndeğildir. Moğol olduğu bütün dillerdeki târîhlerde yazılıdır. Kitâbsız kâfir olduğu, \n(Kısas-ı Enbiyâ)nın sekizyüzonbirinci sahîfesinde yazılıdır. 551 [m. 1155] da tevel-\nlüd, 624 [m. 1227] de vefât etdi. (Kâmûs-ül-a’lâm)da diyor ki, Cengiz, dünyânın en \nbüyük cihângirlerinden ve en meşhûr zâlim ve kan dökücülerindendir. Moğoldur. \nİslâmiyyete çok zararı dokunmuş olan bu adam, bir kabîle reîsi iken, 599 [m. 1202] \nda (Kara-kurum)da moğol ve tatâr hânlarının başı, ya’nî hakânı oldu. Câhil ve \nvahşî moğollardan ve tatârlardan büyük bir ordu, dahâ doğrusu yağmacılar gürûhu \ntoplayıp, doğu Türkistânı, Çini aldı. 616 [m. 1219] da, sultân Kutb-üd-dîn Muham-\nmed Hârizmşâhın memleketine saldırdı. Horâsân, Kandihar, Mültan gibi mede-\nniyyet merkezlerini yakdı, yıkdı. Milyonlarca müslimânı öldürdü. Çoğunu \ncâmi’lerde kılıncdan geçirdi. 290.cı sahîfeye bakınız!", "gectigiMaddeler": ["1/50", "1/95", "2/35", "3/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cevdet Pâşa", "slug": "cevdet-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed Cevdet pâşa 1238 \n[m. 1823] de Lofcada tevellüd, 1312 [m. 1894] de vefât etdi. Fâtih câmi’işerîfi bağ-\nçesinde mermer kabri vardır. Bütün milletlerin çok kıymet verdiği (Mecelle) adın-\ndaki kitâbı hâzırlamakla, islâmiyyete büyük hizmet etmişdir. (Kısas-ı Enbiyâ) ve \n(Ma’lûmât-i nâfi’a) kitâbları meşhûrdur.", "gectigiMaddeler": ["2/24", "2/25", "2/27"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cezûlî", "slug": "cezuli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzellibirinci [651] sırada Mu -\nhammed bin Süleymân Cezûlî ismine bakınız! \n– 1086 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cihângîrşâh", "slug": "cihangirsah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüzonikinci [812] \nsırada Selîmşâh ismine bakınız! \n201— C İRCİS: İbnül’amîd, rûm târîhcilerindendir. 601 [m. 1205] de tevellüd, \n671 [m. 1273] de Şâmda vefât etdi. Bu ism, (Fâideli Bilgiler) kitâbında geçmekde-\ndir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cüneyd-i Bağdâdî", "slug": "cuneyd-i-bagdadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid-üt tâife ismi \nile meşhûrdur. Babası Muhammed Zeccâcdır. Hanefîdir. 207 [m. 821] de Nehâ-\nvendde tevellüd, 298 [m. 910] de Bağdâdda vefât etdi. Dayısı ve mürşidi Sırrî Sekâ-\ntînin yanındadır. Sırrî Sekâtînin mürşidi Ma’rûf-i Kerhîdir. Ma’rûf-i Kerhî, imâm- ı \nAlî Rızâdan ve Dâvüd-i Tâîden feyz almışdır. \nTarîkatlerin çeşidli ismler alması, başka başka olduklarını göstermez. Aynı \nVelînin talebeleri, birbirlerini tanımak ve üstâdları ile öğünmek için, bulundukları \nyola, üstâdlarının ismini vermişlerdir. Tarîkatler başlıca ikidir: (Zikr-i hafî), ya’nî \nsessiz zikr yapan ve (Zikr-i cehrî), ya’nî yüksek sesle zikr yapan tarîkatler. Birincisi \nhazret-i Ebû Bekrden gelmiş olup, üstâdlarının adına göre, (Tayfûriyye), (Yes-\neviyye), (Medâriyye), hakîkî olan (Bektâşiyye), (Ahrâriyye), (Ahmediyye-i \nmüceddidiyye) ve (Hâlidiyye) gibi ismler almışlardır. \nZikr-i cehrî hazret-i Alîden oniki imâm vâsıtası ile gelmişdir. Bunlardan sekizin-\ncisi olan imâm- ı Alî Rızâdan Ma’rûf-i Kerhî almış ve Cüneyd-i Bağdâdînin çeşidli \nhalîfelerinin silsilelerinde bulunan meşhûr Velîlerin ismi verilerek, kollara ayrıl-\nmışdır. Böylece Ebû Bekr-i Şiblî yolundan (Kâdirî) ile (Şâzilî), (Sa’dî) ve (Rıfâ’î), \nEbû Alî Rodbârî yolundan Ahmed Gazâlî ve Dıyâ-üd-dîn Ebû-Necîb-i Sühreverdî \nvâsıtaları ile (Kübrevî), Mimşâd-i Dîneverî yolundan yine Ebû Necîb-i Sühreverdî \nmeydâna gelmişdir. İmâm-ı Alîden Hasen-i Basrî vâsıtası ile (Edhemî) ve bundan \n(Çeştî) hâsıl olmuşdur. (Bedeviyye), Rıfâ’iyyeden hâsıl olmuşdur. \nEbû Necîb-i Sühreverdî, Şihâbüddîn Ömer-i Sühreverdînin mürşidi ve amcası idi. \n[563] de Bağdâdda vefât etdi. Şihâbüddînden (Sühreverdî) hâsıl olmuş, Ebû Necîb-\nden bir kol da Rükn-üd-dîn Muhammed Sencâsîye gelmiş, bundan Şems-i Tebrîzî ile \nRükneddîn İbrâhîm-i Zâhid feyz almışlardır. Birincisinden (Mevlevî) meydâna gel-\nmiş, ikincisi ikiye ayrılmışdır. Birincisinden Safiyyeddîn Erdebîlî yolu ile (Bayrâmî) \nve bundan da (Celvetî)ler hâsıl olmuş, ikincisinden Muhammed bin Nûr Halvetî \nyolu ile (Halvetî) ve (Zeyniyye) meydâna gelmişdir. Halvetîlerden seyyid Yahyâ \nŞirvânî hâsıl olup, 868 [m. 1464] senesinde vefât etmişdir. Bunun bir talebesinden \n(Gülşenî) meydâna geldi. Şirvânînin diğer talebesi pîr Muhammed Erzincânî 876 [m. \n1472] da vefât etmişdir. Bundan ayrılan bir koldan (Niyâzî Mısrî), (Ümmî Sinân) ve \n(Cerrâhî) tarîkatleri hâsıl oldu. Cerrâhî pîri olan Nûreddîn Cerrâhî, Kara-gümrükde \nKedhudâ câmi’i yanındaki tekkede onsekiz sene vazîfe yapıp, 1133 [m. 1720] sene-\nsinde orada vefât etdi. Pîr Muhammedin diğer halîfesi Çelebî halîfe Muhammed \nCemâleddîn efendinin bir talebesinden (Şa’bâniyye) hâsıl oldu. İkinci talebesi Sün-\nbül Sinân Yûsüf efendidir. 852.ci sırada bu isme bakınız! Topkapıda otobüs durak \nyerinin ismi olan Pazar tekkesininşeyhi Ümmî Sinân efendi 958 [m. 1551] senesinde \nvefât etmiş ve Eyyûbde talebesi Nasûh dedenin Düğmecilerdeki tekkesine defn edil-\nmişdir. Bunun yerine, talebesi Kazzâz Muhammed Harîrî efendişeyh olmuş, bu \nmakâmda doksan sene kalarak, 1050 [m. 1639] de vefât etmişdir. Bu tekke ile kürk-\ncübaşı Ahmed beğ câmi’i arasındaki türbesindedir. Tekke yerindeşimdi benzin \nistasyonu vardır. Eyyûbdeki Ümmî Sinân tekkesinin sonşeyhi Yahyâ Gâlib, dedele-\nrinin yolundan ayrıldı. Halk partisine girerek, Kırşehir vâlîsi ve sonra meb’ûs oldu. \nİslâmın son halîfesi Vahîdeddîn hâna Ankaradan gönderdiği iğrenç tehdîd mektûb-\nları ile halîfeyi İstanbulu terke mecbûr etdiğini, Cumhûriyyet gazetesinde neşr etdiği \nhâtırâtında yazmakdadır. İngiliz askerleri, halîfeyi yatağından kaldırarak, harb \ngemisi ile, Malta adasına götürdü. Vahîdeddîn hân 1344 [m. 1926]de vefât etdi. \nYahyâ Gâlib 1359 [m. 1940] da öldü. Eyyûbde, Bahâriyyededir. \n– 1087 –\nHâcı Bayram- ı Velînin talebesi Ömer Sekînînin talebesi Hızır Dede, Üftâde \nefendiye rûhsat verdi. Bunun talebesi de, Hüdâyî Azîz Mahmûd efendidir. \n(Uşâkî) yolunun reîsi Hasen Hüsâmeddîn efendidir. Buhârâda seyyid Ahmed-i \nSemerkandîden feyz aldı. Uşakda yerleşdiği için Uşâkî denildi. 1003 [m. 1594] de \nKonyada vefât etdi. (Ticânî) yolu, Afrikanın batısında yayılmışdır. Ticânî ismine \nbakınız!", "gectigiMaddeler": ["1/27", "1/41", "1/78", "2/47", "3/17", "3/51", "3/59", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Cüveyriyye", "slug": "cuveyriyye", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Benî Mustalak kabîlesi reîsi olan \nHârisin kızı idi. Hicretin beşinci senesinde yapılan (Müreysi’) gazvesinde esîr alın-\nmışdı. Amcasının oğlu olan zevci muhârebede katl edildi. Yirmi yaşında, çok \nhasnâ idi. Cüveyriyye satılığa çıkarıldıkda, bir rivâyetde babası satın almak için \nMedîneye bir sürü deve getirdi. İki a’lâ deveye kıyamayıpşehr dışında sakladı. \nResûl “aleyhisselâm”, filân yerde sakladığın iki deveyi de getir dedi. Hâris, şaşırıp, \niki oğlu ve dahâ nice kimse ile îmân etdi. Resûl “aleyhisselâm” develeri alıp, kızını \ngeri verdi. Kız da îmâna geldi. Resûlullah “sallallahü aleyhi ve sellem”, Cüveyriy-\nyeyi babasından isteyip nikâh buyurdu. Hicretin ellialtı 56 [m. 675] senesinde vefât \netdi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dahhâk", "slug": "dahhak", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dahhâk bin Kays, Tâbi’îndendir. \nCemel harbine karışmadı. Sıffînde hazret-i Alî ile birlikde idi. Hazret-i Mu’âviye-\nnin huzûrunda pek acı konuşduğu hâlde, hazret-i Mu’âviye, riâyeti ve hurmeti \nbırakmayıp, buna yine ihsân ederdi. 37 [m. 657] senesinde, yetmiş yaşlarında vefât \netdi. Semerkandın fethinde bir gözü sakatlandı. Tefsîr sâhibi Dahhâk-i Belhî 102 \nde vefât etdi.", "gectigiMaddeler": ["1/97", "2/30", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dalton", "slug": "dalton", "unvan": "", "kategori": "diger", "biyografi": "İngiliz fizikcisi ve kimyâgeridir. 1179 [m. 1766] da tevellüd, 1260 [m. 1844] da vefât etdi.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Danyal", "slug": "danyal", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Hazret-i Dâvüd evlâdından bir Peygamber-\ndir. Mîlâddan [606] sene önce Bâbile götürülüp, Buhtunnasar serâyında büyüdü.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dârâ", "slug": "dara", "unvan": "", "kategori": "diger", "biyografi": "Eski Îrânın Kiyâniyânşâhlarının dokuzuncusu ve sonuncusudur. Mîlâddan önce [342] den [330] senesine kadar hükm sürdü. Erbilde İskendere mağlûb olup kaçarken öldü. Sonra İşkâniyân, dahâ sonra Sâsâniyân devletleri kurulmuşdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dâre Kutnî", "slug": "dare-kutni", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Ömer, hadîs âlimidir. \n306 [m. 918] senesinde Bağdâdda Dâre kutnda tevellüd, 385 [m. 995] de vefât etdi. \n(Sünen) kitâbı meşhûrdur.", "gectigiMaddeler": ["2/6", "2/18", "3/64"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dârimî", "slug": "darimi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah bin Abdürrahmân hâfız \nEbû Muhammed, 181 [m. 798] de Semerkandda tevellüd, 255 [m. 869] de vefât et -\ndi. Hadîs âlimidir. (Müsned) adındaki kitâbı çok kıymetlidir.", "gectigiMaddeler": ["1/31", "2/6", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Darwin", "slug": "darwin", "unvan": "", "kategori": "diger", "biyografi": "İngiliz tabî’iyyecisidir. 1224 [m. 1809] de doğdu. 1299 [m. 1882] da öldü.", "gectigiMaddeler": ["1/39", "2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Davenport", "slug": "davenport", "unvan": "", "kategori": "diger", "biyografi": "John Davenport. Ondokuzuncu asrın sonunda yaşamış \nolan lord Davenport, İngiliz müşteşriklerindendir. (Hazret-i Muhammed ve \nKur’ân-ı kerîm) adındaki ingilizce kitâbı, önce Londrada, sonra birkaç kerre de \nHindistânda basılmışdır. 1346 [m. 1928] da Ömer Rızâ tarafından türkcesi neşr \nedilmişdir. [m. 1966] sonunda türkcesi latin harfleri ile basılmışdır. Misyonerlerin \n[m. 1925] de çıkardıkları (The Islamic World Today) ya’nî (Bugünkü islâm âlemi) \nadındaki kitâbın yirminci faslında Davenport ve kitâbı hakkında geniş bilgi var-\ndır.", "gectigiMaddeler": ["2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dâvüd", "slug": "davud", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Hem Nebî, hem sultân idi. Mîlâddan [1086] \nsene önce Kudüsde tevellüd, [1016] sene önce orada vefât etdi. Kumandanlarından \n– 1088 –\nUrya, muhârebede öldürülünce bunun zevcesini alıp, bundan Süleymân “aleyhis-\nselâm” tevellüd etdi. Çok güzel ve te’sîrli sesi vardı. Kendisine ibrânî dilinde \n(Zebûr) kitâbı geldi.", "gectigiMaddeler": ["1/95", "2/18", "2/20", "2/30", "2/47", "2/48", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dâvüd bin Süleymân", "slug": "davud-bin-suleyman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâlid-i Bağdâ-\ndînin talebelerindendir. 1222 [m. 1807] de Bağdâdda tevellüd, 1299 [m. 1881] da \norada vefât etdi. Onsekiz sene Mekkede kaldı. (Minhat-ül-vehbiyye fî reddil-Veh-\nhâbiyye) kitâbı [1305] de Bombayda ve [1389] da İstanbulda basıldı. Arabîdir. \nTürkcesi (Kıyâmet ve Âhıret) kitâbının (Müslimâna nasîhat) kısmındadır.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dâvüd-i Tâî", "slug": "davud-i-tai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Süleymân Dâvüd bin \nNasîr, Hanefî fıkh âlimi ve çok zâhid idi. Horâsânlıdır. İmâm-ı a’zamın talebesi ve \nHabîb-i Acemînin halîfesi idi. 165 [m. 781] de vefât etdi.", "gectigiMaddeler": ["1/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dâvüd-i Zâhirî", "slug": "davud-i-zahiri", "unvan": "", "kategori": "diger", "biyografi": "Dörtyüzkırkbeşinci [445] sırada İbni Hazm ismine \nbakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Debbûsî", "slug": "debbusi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Zeyd Ubeydüllah bin Ömer, \nBuhârânın meşhûr yedi kâdîsından biridir. Debbûs, Semerkandda bir kasabadır. \nHanefî fıkh âlimlerindendir. 432 [m. 1039] de Buhârâda vefât etdi. (Te’sîs) fıkh \nkitâbı Mısrda basılmışdır. (Esrâr fil-üsûl-i vel-fürû’) kitâbı, (Hazâne) fetvâ kitâbı \nve imâm-ı Muhammedin (Câmi’ul-kebîr)ineşerhı vardır. 308", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Demîrî", "slug": "demiri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kemâleddîn Muhammed bin Îsâ, \nMısr Şâfi’î âlimlerindendir. [742] de tevellüd, 808 [m. 1405] de vefât etdi. (Hayât-\nül-hayvân) kitâbı Beyrutda (Mektebe-tül-ticârî)de satılmakdadır. İki cilddir. \nKenârında Zekeriyyâ Kazvînînin (Acâib-ül-mahlûkât) kitâbı vardır.", "gectigiMaddeler": ["2/5", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dervî Ş Muhammed", "slug": "dervi-s-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Evliyânın büyük-\nlerindendir. Rûh ilmlerinin mütehassısı idi. Dayısı Muhammed Zâhid hazretlerin-\nden feyz aldı. Dayısının vefâtından sonra, bu da Semerkandda dalâlet ve bid’atleri \nyok etdi. Önce onbeş sene zühd ve riyâzetle, zikr ve fikrle çalışdı. Sonra Hızır aley-\nhisselâmın tavsiyesi ile hâce Muhammed Zâhid hazretlerinin sohbetine kavuşup \nkemâle erdi. Çok Velî yetişdirdi. Hicretin dokuzyüzyetmiş 970 [m. 1562] senesinde \nMâverâünnehrde Büster nâhiyesinin Dasferâr köyünde vefât etdi. Silsile-i aliyye-\nnin yirminci ferd-i kâmilidir.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Deylemî", "slug": "deylemi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şehrdâr bin Ebû Şücâ’ Şîreveyh \n[483] de Hemedânda tevellüd, 558 [m. 1163] senesinde vefât etdi. Ebû Nasr Dey-\nlemî, hadîs âlimidir. (Müsned-ül-firdevs) kitâbı meşhûrdur.", "gectigiMaddeler": ["1/41", "2/5", "2/17", "2/18", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dıhye-i Kelbî", "slug": "dihye-i-kelbi", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Geç îmâna geldi. Zengin tüccâr idi. \nMüslimân olmadan önce de Resûlullahı sever, uzakdan geldikce hediyye getirirdi. \nMüslimân olunca, Resûlullah çok sevindi. İyi rumca bilirdi. Rum devletine sefîr \nolarak gönderildi. Yermük ve Şâm savaşlarında bulundu. 50 [m. 670] senesinde \nvefât etdi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dioskorüs", "slug": "dioskorus", "unvan": "", "kategori": "diger", "biyografi": "İskenderiyye patrîki idi. [m. 451] senesinde Kadıköyünde \ntoplanan beşinci meclisde, fikrleri red edildi. Fikrlerine (Monofisiyye) veyâ \n(Ya’kûbiyye) denir.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Dırâr", "slug": "dirar", "unvan": "", "kategori": "diger", "biyografi": "Mısrda, Fâtımîler zemânında bulunan bir yehûdî dönmesidir. \nHalîfe Hâkimi aldatdı. İslâmiyyeti yıkmağa uğraşdı. Bunun ve talebesi Hamzanın \nyolunda olanlara (Derezî) veyâ (Dürzî) denir.", "gectigiMaddeler": ["2/21", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Draper", "slug": "draper", "unvan": "", "kategori": "diger", "biyografi": "William Draper, hıristiyan dînine düşmânlığı ile meşhûr ingi-\nlizdir. 1226 [m. 1811] da tevellüd ve 1299 [m. 1881] da vefât etdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Abdüllah", "slug": "ebu-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Mûsâ \nbin Nu’mân Merâkişî Tilimsânî, tesavvuf büyüklerindendir. Mâlikîdir. 683 [m. 1284] \nde vefât etdi. (Misbâh-uz-zulâm) kitâbı çok kıymetlidir. 458. \n– 1089 –                                  Se’âdet-i Ebediyye 3-F:69", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Alî Dekkak", "slug": "ebu-ali-dekkak", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Adı, Hasen bin \nMuhammeddir. Ebül-Kâsım Kuşeyrînin kayın pederi ve üstâdı idi. 405 [m. 1014] \nsenesinde Nîşâpûrda vefât etdi.", "gectigiMaddeler": ["1/71"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Alî Fârmedî", "slug": "ebu-ali-farmedi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Adı Fadl bin Muham-\nmeddir. Ebül-Kâsım Kuşeyrînin talebesi ve Ebül-Kâsım Gürgânî ile Ebül-Hasen \nHarkânînin halîfesidir. Ebül Kâsım da, Ebû Osmân- ı Magribînin, bu da Cüneyd-i \nBağdâdînin halîfesidir. Rûh ilmlerinin mütehassısı idi. Ebû Sa’îd-i Ebül-Hayr haz-\nretlerinden de feyz aldı. Zâhir ilmlerinde derin âlim idi. İmâm-ı Gazâlînin ve \nYûsüf-i Hemedânînin mürşididir. Dörtyüzotuzdörtde [434] tevellüd ve dörtyüzyet-\nmişyedide 477 [m. 1085] Meşhedde, ya’nî Tusda vefât etdi.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Bekr bin Alî Haddâd-i Yemenî", "slug": "ebu-bekr-bin-ali-haddad-i-yemeni-rahmetullahi-t", "unvan": "", "kategori": "alim", "biyografi": "Hanefîdir. 800 [m. 1397] senesinde vefât etdi. (Kudûrî Muhtasarı)nışerh etdi. Buşerhı üç cild olup, (Sirâc-ül-vehhâc) adını vermişdir. Bunu ihtisâr ederek (Cevheretün-neyyire) demişdir. İbrâhîm İbnül-Lakânînin ilm-i kelâmda yazdığı (Cevhere-tüt-tevhîd) başkadır. İbrâhîm Lakânî Mâlikî kelâm âlimi ve büyük Velî olup, 1041 [m. 1632] senesinde vefât etmişdir. Abdülganî ganîmî Meydânînin (Ellübâb) ismindeki Kudûrîşerhı meşhûrdur. İbni Âbidînin talebesi olup, 1274 [m. 1857] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Bekr-i Bâkıllânî", "slug": "ebu-bekr-i-bakillani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdî Muham-\nmed bin Tayyib, Basrada tevellüd, 403 [m. 1013] de Bağdâdda vefât etdi. Kelâm \nâlimi idi. Eş’arî mezhebinde idi. İlmi ve zekâsı çok idi. İstanbula elçi gönderildi. \nÇok kıymetli eserleri vardı.", "gectigiMaddeler": ["2/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Bekr-i Belhî", "slug": "ebu-bekr-i-belhi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hamîdeddîn-i Belhî, \nBelh kâdîsı idi. Babası, Ömer bin Mahmûddur. 559 [m. 1165] senesinde vefât etdi. \nFârisî (Makâmât) kitâbı meşhûrdur.", "gectigiMaddeler": ["2/35", "3/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Bekr-i Sıddîk", "slug": "ebu-bekr-i-siddik", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Adı Abdüllah bin Ebû Kuhâ-\nfe bin Âmir bin Amr bin Kâ’b bin Sa’d bin Teym bin Mürredir. İlk îmâna gelen \nhür adamdır. Büyük tüccâr idi. Bütün malını, evini, barkını Resûlullah uğruna ver -\ndi. Gençlikde de arkadaş idiler. Müslimânların birinci halîfesidir. Resûlullah “sal-\nlallahü aleyhi ve sellem” âhırete teşrîf edince, Mekkeden ve Medîneden ve Tâif-\nden başka, bütün Arabistân mürted oldu. Halîfe, önce Medîneye yakın dört kabî -\nle üzerine yürüyüp, bunları itâ’ate getirdi. Sonra, onbir kabîleye bölükler gönder-\ndi. Bunlardan İkrime emrindeki asker, Yemâmede, Müseylemenin kırkbin aske -\nrine karşı gelemedi. Halîfe, Hâlid bin Velîdi imdâda gönderdi. Hâlid, Talîha ve \nSücâh ve Mâlik bin Nüveyreyi perîşan edip Medîneye dönmüşdü. Yemâmede de bü -\nyük zafer kazandı. Yirmibin mürted öldürdü. İki bine yakın müslimânşehîd oldu. \nAmr ibni Âs da, Huzâ’a kabîlesini îmâna getirdi. Alâ bin Hadremî, Bahreynde çe -\ntin muhârebeler yapıp mürtedleri dağıtdı. Huzeyfe ve Arfece ve İkrime, Ummân \nve Bahreynde birleşip, mürtedleri bozdular. Onbin mürted öldürdüler. Halîfe, Hâ -\nlid bin Velîdi Irâk tarafına gönderdi. Hîreden yüzbin altın cizye aldı. Hürmüz ku -\nmandasındaki Îrân ordusunu bozdu. Basrada otuzbin kişilik orduyu perîşan etdi. \nİmdâda gelen büyük ordudan yetmiş bin kâfir öldürüldü. Sonra, çeşidli muhârebe-\nlerle, büyükşehrler aldı. Halîfe, Medînede ordu toplayıp, Ebû Ubeyde kumanda-\nsında Şâm tarafına, Amr ibni Âsı da Filistine gönderdi. Sonra Yezîd bin Ebû Süf-\nyânı Şâma yardımcı gönderdi. Sonra asker toplayıp, hazret-i Mu’âviye kumanda-\nsında, kardeşi Yezîde yardıma gönderdi. Hâlid bin Velîdi de, Irâkdan Şâma gön-\nderdi. Hâlid, askerin bir kısmını Müsennâya bırakıp, birçok muhârebe ve zafer-\nlerle Sûriyeye geldi. İslâm askerleri birleşerek (Ecnâdeyn)de büyük rum ordusu-\nnu yendiler. Sonra, (Yermük)de kırkaltı bin islâm askeri, Herakliüsün ikiyüzkırk \nbin askeri ile uzun ve çok çetin savaşlar yapıp gâlib geldi. Yüzbinden ziyâde rum \naskeri öldürüldü. Üçbin müslimânşehîd oldu. Bu muhârebede islâm kadınları da \nharb etdi. Başkumandan Hâlid bin Velîdin ve tümen komutanı İkrimeninşaşıla-\n– 1090 –\ncak kahramanlıkları görüldü. Bütün bu zaferler, halîfenin cesâreti, dehâsı ve gü -\nzel idâresi ve bereketi ile oldu. Yermük savaşı yapılırken, halîfe Medînede vefât \netdi. \nHazret-i Ebû Bekr, Aşere-i mübeşşerenin birincisidir. Peygamberlerden sonra, \nbütün insanların en üstünüdür. Bütün gazâlarda bulundu. Âyet-i kerîmeler ile \nmedh olundu. Kur’ân- ı kerîmi kitâb hâlinde ilk toplıyan budur. 13 [m. 634] senesi-\nnin Cemâzil-âhır yirmisekizinci salı gecesi, altmışüç yaşında vefât etdi. Resûlulla-\nhın yanındadır. Beyâz idi. Yüzü ve göğdesi za’îf, yanakları üstünde sakalları az, \ngözleri çukurca, alnı yumruca idi.", "gectigiMaddeler": ["1/25", "1/31", "1/41", "1/43", "1/46", "1/63", "1/70", "1/78", "1/84", "1/85", "1/95", "2/16", "2/17", "2/19", "2/22", "2/23", "2/24", "2/25", "2/40", "2/41", "2/47", "2/61", "3/4", "3/19", "3/28", "3/31", "3/36", "3/37", "3/46", "3/50", "3/53", "3/60", "3/66", "3/68"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Bekr-i Şiblî", "slug": "ebu-bekr-i-sibli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Evliyânın büyüklerin-\ndendir. Adı Ca’fer bin Yûnüsdür. 247 [m. 861] de Samrâda tevellüd, 334 [m. 945] \nde Bağdâdda vefât etdi. Mâlikî idi. Cüneyd-i Bağdâdînin talebelerindendir.", "gectigiMaddeler": ["1/27", "1/31", "1/46"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Berze", "slug": "ebu-berze", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Adı Fadl bin Muhammed Eslemîdir. \nEshâb-ı kirâmdandır. Gazâlarda bulundu. Hazret-i Alî ile birlikde hâricîlerle harb \netdi. Horasanda, çok yaşlı iken vefât etdi.", "gectigiMaddeler": ["2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Ca'fer", "slug": "ebu-cafer", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Haddâd denir. Cüneyd-i Bağ-\ndâdînin hocalarından idi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Ca'fer-i Mensûr", "slug": "ebu-cafer-i-mensur", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası, Muham-\nmed bin Alî bin Abdüllah bin Abbâsdır. Abbâsî hükümdârlarının ikincisi, islâm \nhalîfelerinin yirmibirincisidir. [95] senesinde tevellüd, 158 [m. 775] senesinde Mek-\nkede vefât etdi. [136] da, kardeşi Abdüllah ölünce, halîfe oldu. [137] de, devletin \nkurucusu olan Ebâ Müslimi öldürdü. [145] de Bağdâdşehrini yapdı.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Cehl", "slug": "ebu-cehl", "unvan": "", "kategori": "diger", "biyografi": "Adı Amr bin Hişâm bin Mugîre bin Abdüllah bin Amr bin \nMahzûmdur. Ebû Hakem ve İbni Hanzala da denir. İslâmiyyetin en azılı düşmanı \nidi. Bedr gazâsında yetmiş yaşında iken öldürüldü.", "gectigiMaddeler": ["1/95", "2/23", "2/24"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Dâvüd", "slug": "ebu-davud", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüzotuzdördüncü [834] \nsırada, Sicstânî ismine bakınız!", "gectigiMaddeler": ["1/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebüdderdâ", "slug": "ebudderda", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb-ı kirâmdandır. Hazrec kabîle-\nsindendir. Bedrden sonraki gazâlarda bulundu. 33 [m. 653] senesinde Şâmda vefât \netdi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Dücâne", "slug": "ebu-ducane", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Hazrec kabîlesindendir. Bedr ve \nUhud gazâlarında ve Yemâme cenginde çok kahramanlık yapdı. 11 senesinde, \nHâlid bin Velîdin idâresinde, Müseylemetül-kezzâb ile yapılan Yemâme cengindeşehîd oldu. Bu cengde müslimânlardan iki bin, mürtedlerden yirmi binden ziyâde \ntelef oldu.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Eyyûb-i Ensârî", "slug": "ebu-eyyub-i-ensari", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Hâlid bin Zeyddir. \nEshâb-ı kirâmın büyüklerindendir. Resûlullah Medîneye hicret edince, bunun \nevinde yedi ay müsâfir oldu. Bütün gazâlarda bulundu. Yüzelli hadîs-işerîf bil-\ndirmişdir. 50 [m. 670] de, Süfyân bin Avf emrinde İstanbula gelen ve içlerinde \nYezîdin de bulunduğu asker arasında otuzüç Sahâbî vardı. Bunlardan hazret-i \nHâlid dizanteriden vefât etdi. Fâtih sultân Muhammedin hocalarından Akşem-\nseddîn efendi kabrini keşf etdi. Üzerine güzel türbe ile bir câmi’ yapıldı. Rame-\nzânlarda câmi’lere mahya kurulması emr olununca, 1136 [m. 1723] da uzun iki \n– 1091 –\nminâre yapıldı. (Mir’at-ülharemeyn) sekizyüzikinci sahîfede diyor ki, (Çifte mi -\nnâreli câmi’lere mahya kurulması, sultân üçüncü Ahmed hân devrinde oniki sene \nkadar sadr- ı a’zamlık yapmış olan dâmâd İbrâhîm pâşanın 1132 [m. 1719] sene-\nsinde ihdas eylediği bid’atdir.) Eyyûb sultân câmi’i, üçüncü Selîm hân tarafından \n1215 [m. 1800] de yeniden yapıldı. İlk Cum’a nemâzında sultân da bulundu. \nCâmi’in son ta’mîrini 1380 [m. 1960] de başvekîlşehîd Adnan Menderes yapdır-\nmışdır. Türbenin son ta’mîrini ikinci Mahmûd hân yapdırmışdır. Sanduka üzerin-\ndeki yazılar, sultânın el yazısıdır. Türbede asılı levhadaki iki beyti üçüncü Selîm \nhân söylemiş, Yesârîzâde yazmışdır. Nakş-i kadem-i Peygamberî, Birinci Mah-\nmûd hânın emri ile 1144 [m. 1731] de serâydan türbeye getirildi. Türbe civârın-\ndaki kabrler, (Hadîkat-ül-cevâmi’) de uzun yazılıdır.", "gectigiMaddeler": ["1/82"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Eyyûb-i Sahtıyânî", "slug": "ebu-eyyub-i-sahtiyani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr-il \nBasrî, Tâbi’înin büyüklerinden ve fıkh âlimlerindendir. Çok kerâmetleri görüldü. \nBasrada deri satardı. Yüzotuzbir 131 [m. 748] senesinde tâ’ûndan, altmışbeş yaşın-\nda vefât etdi.", "gectigiMaddeler": ["1/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Eyyûb-i Süleymân", "slug": "ebu-eyyub-i-suleyman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Medîne-i \nmünevverede bulunan yedi büyük âlimlerden biridir. 104 [m. 722] de vefât etdi.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Hanîfe", "slug": "ebu-hanife", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı a’zam Nu’mân bin \nSâbit, İslâm âlimlerinin en büyüklerindendir. 80 [m. 699] senesinde Kûfede tevel-\nlüd, 150 [m. 767] de Bağdâddaşehîd edildi. İkinci Abbâsî halîfesi Ebû Ca’fer Men-\nsûr zâlim idi. İmâmı, hergün on sopa artdırarak, zındanda döğdürdü. Sopa adedi \nyüz olduğu gün, İmâm yıkıldı. Yatarken ağzına zehr akıtdılar, şehîd oldu. Fıkh bil-\ngilerini, Ehl-i sünnet i’tikâdını topladı. Yüzlerce talebesine öğretip, kitâblara geçi-\nrilmesine sebeb oldu. Müslimânlar tarafından kâğıd i’mâli bunun zemânında baş-\nladı. 2, 22, 23, 49, 50, 59, 95, 106, 114, 115, 120, 125, 126, 133, 134, 136, 137, 144, 149, \n155, 176, 178, 179, 194, 215, 223, 228, 229, 231, 234, 244, 258, 260, 268, 270, 271, 273, \n294, 303, 304, 307, 318, 322, 324, 339, 349, 352, 388, 393, 408, 435, (437),", "gectigiMaddeler": ["2/16", "2/17", "2/21", "2/22", "2/24", "2/34", "2/38", "2/40", "2/41", "2/42", "2/43", "2/49", "2/53", "2/72", "3/4", "3/12", "3/13", "3/15", "3/17", "3/19", "3/20", "3/21", "3/22", "3/24", "3/26", "3/54", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Hasen-i Sübkî", "slug": "ebu-hasen-i-subki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Abdülkâfî \nhâfız Takıyyüddîn Sübkî, 683 [m. 1284] de Mısrda Sübk kasabasında tevellüd, 756 \n[m. 1355] da Kâhirede vefât etdi. Tâc-üddîn-i İskenderînin talebesidir. Mısrda ve \nŞâmda Şâfi’î âlimlerinin reîsi idi. Şâmda kâdıl-kudât ya’nî temyîz reîsi iken imâm- ı \nNevevînin evini ziyâret etdiği zemân, Nevevînin mubârek ayakları basmışdır diye-\nrek halılara yüzünü, sakalını sürmüşdü. Yüzelliden fazla kitâb yazdı. İbni Teymiy-\nyeye çok nasîhat etdi. Ona reddiyye olan kitâblarından (Şifâ-üs-sikâm), Beyrutda \n(Dâr-ül-âfâk-ı Cedîde) kitâbevi tarafından ve ofset yolu ile İstanbulda yeniden \nbasılmışdır. Oğlu Abdülvehhâb Tâc-üddîn-i Sübkî, Şâfi’î âlimlerinden olup, 771 [m. \n1370] de Şâmda vefât etmişdir.", "gectigiMaddeler": ["1/54", "1/84", "1/89", "2/17", "2/21", "2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Hâtim-i Temîmî", "slug": "ebu-hatim-i-temimi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dörtyüzkırkaltıncı \n[446] sırada İbni Hibbân ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Hüreyre", "slug": "ebu-hureyre", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Adı Abdürrahmândır. Hayberde \nmüslimân oldu. Hazret-i Ömer zemânında Bahreyn vâlîsi, hazret-i Osmân zemânında \nMekke kâdîsi ve hazret-i Mu’âviye zemânında Medîne vâlîsi oldu. 57 [m. 676] sene-\nsinde, yetmişsekiz yaşında Medînede vefât etdi. Abdüllah bin Ömerden sonra, en çok \nhadîs bilen budur.", "gectigiMaddeler": ["1/43", "1/77", "1/79", "1/84", "1/96", "2/5", "2/17", "2/44", "2/52", "3/3", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Huzeyfe bin Utbe", "slug": "ebu-huzeyfe-bin-utbe", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Babası Utbe bin Re -\nbî’a bin Abd-i Şems, Bedr gazâsında Kureyş ordusunun kumandanlarından idi. Ut -\n– 1092 –\nbe, kardeşi Şeybe ve oğlu Velîd ile birlikde katl edilmişdi. Ebû Huzeyfe ise ilk \nîmâna gelenlerdendir. Gazâların çoğunda bulundu. Bedr gazâsında, babası Utbeye \nve kardeşi Velîde karşı harb etdi. Yemâme harbinde ellidört yaşındaşehîd oldu. \nUzun boylu, beyâz, çok güzeldi. Utbe ismine bakınız!", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebûishak Gülâbâdî", "slug": "ebuishak-gulabadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr \nMuhammed bin İbrâhîm Buhârî Gülâbâdî, Sôfiyye-i aliyyedendir. 380 [m. 990] sene-\nsinde vefât etdi. (Te’arrüf) kitâbı çok kıymetlidir. İsmâ’îl bin Muhammed tarafından \nyapılan fârisîşerhi 1330 [m. 1912] de Lüknovda basılmışdır. Şârih 434 [m. 1042] de \nvefât etmişdir. 1388 [m. 1969] de Câmi’ul-ezherde basılmışdır.", "gectigiMaddeler": ["3/41", "3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebûishakşîrâzî", "slug": "ebuishaksirazi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbrâhîm bin Alî, Şâfi’î \nfıkh âlimlerindendir. 476 [m. 1082] da Bağdâdda vefât etdi. Ebû İshak İbrâhîm İsfe-\nrâînî 418 [m. 1026] de Nişâpûrda vefât etdi. (El-Mühezzeb) kitâbı meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Katâde", "slug": "ebu-katade", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ensâr-ı kirâmdan olup, süvârilerden \nidi. 45 [m. 665] de yetmiş yaşında, Medînede veyâ Kûfede vefât etdi.", "gectigiMaddeler": ["3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Kebşe", "slug": "ebu-kebse", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ensâr-i kirâmdan idi.", "gectigiMaddeler": ["2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül Abbâs-ı Mürsî", "slug": "ebul-abbas-i-mursi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Ömer-\nil-ensârî, Mâlikî olup, zemânının kutbu idi. Ebül-Hasen-i Şâzilînin halîfesi ve Tâc-\nüddîn-i İskenderî ile İmâm-ı Busayrînin ve Abdüllah-i İsfehânînin mürşidleridir. \n686 [m. 1287] da İskenderiyyede vefât etdi.", "gectigiMaddeler": ["1/97", "2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Bekâ", "slug": "ebul-beka", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şeyh-ül-islâm idi. Tütün \ngünâh değildir derdi. Ebülbekâ Muhammed bin Ahmed bin Diyâüddîn Sâgânî \nbaşkadır. Yediyüzseksendokuzda tevellüd, sekizyüzellidört 854 [m. 1450] senesin-\nde vefât etmişdir. (Kâfî) şerhı olan (Şâfî) ve Nesefînin (Vâfî)sineşerhı ve (Diyâül-\nma’neviyye alâ mukaddime-til-gazneviyye) ve (Mecma’ul-bahreyn)  şerhı ve \n(Menâkıb-ül-İmâm-il-a’zam) kitâbları meşhûrdur.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebülberekât Nesefî", "slug": "ebulberekat-nesefi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yediyüzonye-\ndinci [717] sırada, Nesefî Abdüllah ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebülhâris bin Alkama", "slug": "ebulharis-bin-alkama", "unvan": "", "kategori": "diger", "biyografi": "Necrandan Resûlullaha gelen altmış \nhıristiyanın en âlimi idi.", "gectigiMaddeler": ["1/92"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hasen-i Alî", "slug": "ebul-hasen-i-ali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Alî bin \nMüzeyyen idi. Sôfiyye-i aliyyedendir. 323 [m. 934] de Mekkede vefât etdi.", "gectigiMaddeler": ["1/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hasen-i E Ş'arî", "slug": "ebul-hasen-i-e-sari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Adı Alî bin \nİsmâ’îldir. Ehl-i sünnetin i’tikâddaki iki imâmından biridir. 260 veyâ 266 [m. 879] \nda Basrada tevellüd, 324 veyâ 330 [m. 941] da Bağdâdda vefât etdi. (Kitâb-\nül’ulûm)u [1953] de ingilizceye terceme edilmişdir.", "gectigiMaddeler": ["1/7", "1/31", "2/4", "2/21", "2/49"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hasen-i Harkânî", "slug": "ebul-hasen-i-harkani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliy-\nyenin büyüklerindendir. Hâl tercemesi (Reşehât)da ve (Tezkiret-ül Evliyâ) da ve \n(Nefehât)da yazılıdır. Adı, Alî bin Ca’ferdir. Bâyezîd-i Bistâmînin rûhâniyyetin-\nden terbiye gördü. (Esrâr-ı sülûk) kitâbını Salâhâddîn-i Uşâkî türkceye çevirmiş-\ndir. (Beşâret-nâme) kitâbı çok kıymetlidir. 425 [m. 1034] de Harkanda vefât etdi.", "gectigiMaddeler": ["1/98", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hasen-i Şâzilî", "slug": "ebul-hasen-i-sazili", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nûr-üddîn Alî \nbin Abdüllahşerîfdir. Mâlikîdir. 592 [m. 1196] de Tûnusda Şâzile kasabasında \ntevellüd etdi. Silsilesi, Sırrî Sekâtîden gelmekdedir. Bir yoldan da, seyyid Ahmed \nRıfâ’îye bağlanmakdadır. İskenderiyyede Şâzilî tarîkatini te’sîs etdi. (Her istedi-\nğim zemân, Resûlullahı baş gözümle görmezsem, kendimi Onun ümmeti saymam) \nbuyururdu. (Hizb-ülbahr) düâ kitâbı meşhûrdur. Mekke yolunda 654 [m. 1256] de \nvefât etdi. Ebül Hasen Alî bin Nâsirüddîn Şâzilî Mâlikî başkadır.", "gectigiMaddeler": ["1/97", "2/21", "2/52", "2/54", "3/28"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hüseyn bin Sem'ûn", "slug": "ebul-huseyn-bin-semun", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \n– 1093 –\nbin Ahmeddir. (Nâtık-ı bil-hikme) adı ile meşhûrdur. Birgün Bağdâdda, minberde \nva’z veriyordu. Minberin önünde oturanlardan biri uyudu. İbni Sem’ûn hemen \nsusdu. Uyandığı zemân (Resûlullahı rü’yâda gördün değil mi?) dedi. Evet gördüm \ndedi. (Seni uyandırıp da, tatlı rü’yânı yarıda bırakmamak için susdum) buyurdu. \nZâhid olmağı, dünyâya gönül bağlamamağı söylüyorsun, kendin yeni, şık giyini-\nyorsun ve çeşidli yemekler yiyorsun dediklerinde, Allahü teâlâyı, islâmiyyetin emr \netdiği gibi bilen kimseye, dünyâ malı zarar vermez buyurdu. (Allahü teâlânın adı \nbulunmıyan söz, kıymetsizdir. Allahü teâlâyı hâtırlamadan susmak, boşuna vakt \ngeçirmekdir. İbret almadan bakmak fâidesizdir) buyururdu. 387 [m. 997] senesin-\nde vefât etdi. Evinin bağçesine defn edildi. Otuz dokuz sene sonra kabristâna nakl \netmek îcâb etdi. Kefeni hiç solmamış, yepyeni görüldü.", "gectigiMaddeler": ["1/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hüseyn Müslim", "slug": "ebul-huseyn-muslim", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzdoksan-\nyedinci [697] sırada Müslim ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Hüseyn-i Nûrî", "slug": "ebul-huseyn-i-nuri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin \nMuhammed, Cüneyd-i Bağdâdînin arkadaşı idi. 295 [m. 907] de ölünce, Cüneyd, \n(İlmin yarısı gitdi) buyurdu.", "gectigiMaddeler": ["2/34"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Leheb", "slug": "ebu-leheb", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın amcası idi. Düşmanı idi. Bedr gazâsından yedi \ngün sonra çiçek hastalığından Mekkede öldü. Kokdu. Karısı Ümm-ı Cemîl, Ebû Süf-\nyân bin Harbin hemşîresi idi.", "gectigiMaddeler": ["1/95", "1/97", "2/23", "2/24", "2/50"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebül-Kâsım-ı Semerkandî", "slug": "ebul-kasim-i-semerkandi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muham-\nmed bin Yûsüf, Hanefî fıkh âlimlerindendir. 556 [m. 1161] senesinde vefât etdi. \n(Câmi’ul-fetâvâ) kitâbı meşhûrdur. Buna (Câmi’ul kebîr)  de denir. (Mültekıt) ve \nbaşka kitâbları da vardır.", "gectigiMaddeler": ["1/74"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebülleys-i Semerkandî", "slug": "ebulleys-i-semerkandi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nasr bin \nMuhammed, hanefî fıkh ve tefsîr âlimidir. (Bostân-ül’Ârifîn), (Tenbîh-ül-gâfilîn), \n(Mukaddime) kitâbları meşhûrdur. (Ebülleys tefsîri)nin türkçe Mûsâ İznikî terce-\nmesi m. 1983 de basılmışdır. 373 [m. 983] de vefat etdi.", "gectigiMaddeler": ["1/25", "1/73", "2/36", "2/40", "2/44", "3/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebülvefâ", "slug": "ebulvefa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebülvefâ bin Ma’rûf Hamevî, \nhalvetî meşâyihindendir. 1016 [m. 1607] da Hamâda vefât etdi. Tâc-ül-ârifîn \nMuhammed Ebül-Vefâ 501 h. [m. 1107] de Irâkda vefât etdi. Şeyh Müslih-uddîn \nMustafâ Vefâ bin Ahmed, 896 [m. 1490] da İstanbulda vefât etdi. Abdüllatîf-i \nKudsînin, bu da Zeyn-üddîn-i Hâfînin halîfesidir. Hocası Bursada Zeynîlerde, \nkendisi Vefâdadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Mensûr-ı Mâtürîdî", "slug": "ebu-mensur-i-maturidi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \nbin Mahmûd, Ehl-i sünnetin iki i’tikâd imâmından birincisidir. Hocası Ebû Nasr- ı \nİyâd, Ebû Bekr-i Cürcânînin talebesi, o da Ebû Süleymân-i Cürcânînin talebesi idi. \nBu da imâm- ı Muhammed Şeybânînin talebesi idi. 333 [m. 944] de Semerkandda \nvefât etdi. Kabrini bir yehûdî ruslardan satın alarak eğlence yeri yapdı. İstanbuldan \ngelen İhlâsşirketi, bu çirkin hâli görünce, 1416 h.k. [1996 m.]de, [yehûdîden 30000] \ndolara satın alarak kıymetlendirdi. İmâm-ı a’zam Ebû Hanîfeden gelen kelâm bilgi-\nlerini kitâblara geçirdi. Îzâh ve isbât etdi.", "gectigiMaddeler": ["1/7", "2/16", "2/21", "2/49"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Mûsâ Dîneverî", "slug": "ebu-musa-dineveri", "unvan": "", "kategori": "diger", "biyografi": "Bâyezîd-i Bistâmînin talebesinden idi. Adı \nAhmed bin Dâvüddür. Çok kitâb yazdı. 281 [m. 894] senesinde vefât etdi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Mûsel-E Ş'arî", "slug": "ebu-musel-e-sari", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Abdüllah bin Kays, Eshâb- ı \nkirâmdandır. Hicret-i seniyyeden evvel, Yemenden iki kardeşi ve arkadaşları ile \nHabeşistâna gitdi. Orada Ca’fer-i Tayyar “radıyallahü anh” ile konuşarak müsli-\nmân oldu. Hayberin fethinde Medîne-i münevvereye geldi. Resûlullahın “sallalla-\nhü aleyhi ve sellem” Zebîd, Aden ve Yemende vâlîsi idi. Ömer “radıyallahü anh” \nzemânında da Basra ve Kûfe vâlîliklerinde bulundu. Çok memleketler feth etdi. \nSıffîn muhârebesinden sonra, sulh için hazret-i Alînin “radıyallahü anh” vekîli idi. \nHazret-i Mu’âviyenin vekîli olan Amr ibni Âsın “radıyallahü anhümâ” dehâsı kar-\n– 1094 –\nşısında mağlûb olmuşdu. Kırkiki 42 [m. 662] senesinde Kûfede veyâ Mekke-i mü -\nkerremede vefât etdi. Yazılarda islâm târîhini ilk kullanan budur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Nasr-ı Akta", "slug": "ebu-nasr-i-akta", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Muham-\nmed, fıkh âlimidir. 474 [m. 1082] senesinde İsfehânda, Ram Hürmüzşehrinde vefât \netdi.", "gectigiMaddeler": ["1/57"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Nu'aym", "slug": "ebu-nuaym", "unvan": "", "kategori": "diger", "biyografi": "Yetmişsekizinci [78] sırada, Ahmed ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Sa'îd-i Fârûkî", "slug": "ebu-said-i-faruki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "[1196] da Rampur-\nda tevellüd ve binikiyüzelli 1250 [m. 1834] senesinde fıtr bayramında, hacdan \ndönerken (Tonk) şehrinde vefât etdi. Delhîye getirilip, mürşidi Abdüllah-i Dehl-\nevînin yanına defn edildi. Fârisî (Hidâyet-üt-tâlibîn) kitâbı çok kıymetlidir. Urdu \ntercemesi ile birlikde 1385 [m. 1965] de Karaşinin Nâzımâbâd kasabasında basıl-\nmışdır. Bunun babası Safiyyülkadr, [1165] de tevellüd ve 1236 [m. 1820] senesinde \n(Lucknow)da vefât etdi. Ebû Sa’îd hazretlerinin üç oğlu vardı. Birincisi Ahmed \nSa’îddir. [Bu isme bakınız!] İkincisi Abdülganî Müceddidî, [1235] de tevellüd ve \nbinikiyüzdoksanaltı 1296 [m. 1879] da Medîne-i münevverede vefât eyledi. \n(Hüvelganî) adındaki Abdüllah-i Dehlevî hazretlerinin makâmâtını fârisî olarak \nyazmışdır. Bu eseri [1296] da Hindistânda basılmışdır. Üçüncü oğlu, Abdülmugnî, \n1291 [m. 1874] de Medîne-i münevverede vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Sa'îd-i Harezmî", "slug": "ebu-said-i-harezmi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMensûr, üçüncü selçûkî sultânı Melikşâhın vezîrlerindendir. 494 [m. 1101] senesin-\nde vefât etmişdir. Mirzâ Ebû Sa’îd bin Muhammed başka olup, Mîrânşâhın torunu \nidi. Ubeydüllah- ı Ahrâr hazretlerinin sohbetinde bulundu. Düâsını alıp, Semer-\nkand sultânı oldu. 873 [m. 1468] senesinde Uzun Hasenle harb ederkenşehîd oldu. \nYerine geçen oğlu mirzâ Ahmed de, Ubeydüllah hazretlerinden feyz almış ve 899 \n[m. 1494] senesinde vefât etmişdir.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Sa'îd-i Harrâz", "slug": "ebu-said-i-harraz", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Îsâ, \nSôfiyye-i aliyyedendir. 277 [m. 890] de Bağdâdda vefât etdi.", "gectigiMaddeler": ["1/41", "2/5", "3/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Sa'îd-i Hudrî", "slug": "ebu-said-i-hudri", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "İsmi Sa’ddır. Kendisi ve baba-\nsı Mâlik bin Sinân Sahâbedendir. Babası Uhud gazâsındaşehîd olmuşdu. Uhudda \nonüç yaşında idi. Diğer gazâlarda bulundu. 64 [m. 683] senesinde vefât etdi. İstan-\nbulda Ka’riyye câmi’i yanında denilmekdedir.", "gectigiMaddeler": ["1/96", "1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Sa'îd Kükbûrî", "slug": "ebu-said-kukburi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Erbil meliki idi. \nİsmi El-Muzaffer ibnü Zeynüddîn-i Alî bin Büktekindir. Salâhüddîn-i Eyyûbînin \neniştesidir. Mevlid gecelerinde yapdığı büyük ziyâfetleri meşhûrdur. 630 [m. 1232] \nda haçlı ordularına karşı Akkâ kal’ası cihâdındaşehîd olmuşdur.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Seleme", "slug": "ebu-seleme", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın halası Berre ile AbdülEsed bin Hilâl Mahzûmînin oğludur. İsmi Abdüllahdır. Resûlullahın ve hazret-i Hamzanın Süveybeden süt kardeşidir. Habeşistâna ve Medîneye zevcesi ile ilk hicret eden budur. Bedr ve Uhud gazâlarında akrabâları olan Mahzûm oğullarına karşı kahramanca cihâd etdi. Uhudda aldığı yaradan kan akarken, Resûlullah mubârek elleri ile gözlerini kapayıp hayr düâ etdi. Böyleceşehîd oldu.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Seleme", "slug": "ebu-seleme-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Aşere-i mübeşşereden \nAbdürrahmân bin Avfın oğludur. Tâbi’înin büyüklerindendir. Yirmiiki [22] sene-\nsinde tevellüd, 94 [m. 713] senesinde vefât etdi.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebüssü'ûd Efendi", "slug": "ebussuud-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Musta-\nfâ, onüçüncüşeyh-ul-islâmdır. Cinnîlere de fetvâ verirdi. Eyyûbde yazılı medrese-\ndeki odası, şimdi de duruyor. 896 [m. 1490] da tevellüd, 982 [m. 1574] de vefât etdi. \nEyyûb câmi’i karşısındadır. 952 [m. 1544] deşeyh-ul-islâm oldu. Tefsîri ve fetvâları \nçok kıymetlidir. 156, 233, 244, 248, 249, 271, 297, 305, 464, 604, 698, 714, 734, 897, \n1125, 1171. \n– 1095 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Süfyân bin Harb", "slug": "ebu-sufyan-bin-harb", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Dedesi Ümeyye bin \nAbd-i Şems bin Abd-i Menâfdır. Hazret-i Mu’âviyenin babasıdır. İslâmın büyük düş-\nmanı idi. Kureyş ordusunun baş kumandanı olup, çok müslimânşehîd etdi. Resûlul-\nlahın kayın pederi idi. Mekke feth olunacağı zemân islâm ordusuna gelip müslimân \noldu. Tâif gazâsında bir gözü, Yermük harbinde ikinci gözüşehîd oldu. 31 [m. 651] \nsenesinde seksensekiz yaşında vefât etdi.", "gectigiMaddeler": ["1/95", "3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Süfyân bin Hâris", "slug": "ebu-sufyan-bin-haris", "unvan": "rad ıyallahü anh", "kategori": "diger", "biyografi": "Resûlullahın amcası \noğlu ve süt kardeşidir. Önce çok severken, Nebî olduğunu bildirince çok düşman \noldu. Mekke fethine gidilirken yolda îmâna geldi. Yapdıklarına utandığından \nResûlullahın yanında başını eğer, mubârek yüzüne bakamazdı. Huneyn gazâsında \nResûlullahın yanından hiç ayrılmadı. Düşmana kılınç sallarken, Resûlullahın \nmubârek ayağını öper, afv dilerdi. (Ebû Süfyân Cennet yiğitlerindendir) hadîs-işerîfi ileşereflendi. 20 [m. 641] senesinde Medînede vefât etdi. Resûlullaha çok \nbenziyen yedi kişiden biri bu idi.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Süleymân-ı Dârânî", "slug": "ebu-suleyman-i-darani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrah-\nmân bin Ahmed, âlim ve müttekî idi. 205 [m. 820] senesinde Şâmda vefât etdi.", "gectigiMaddeler": ["2/47", "2/52", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Tâlib", "slug": "ebu-talib", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın amcası ve hazret-i Alînin babası idi. Resû-\nlullah sekiz yaşında iken dedesi vefât edince, Ebû Tâlibin yanında kaldı. İslâma \ndüşmanlık etmedi. Hicretden üç sene önce, seksen yaşını aşmış olarak vefât etdi. \nDiriltilerek îmân etdiği, İbni Hacer-i Mekkînin (Ni’met-ül-kübrâ) mevlid kitâbın-\nda ve (Mir’ât-i Mekke) 1096 sahîfesinde yazılıdır. Dört oğlu ve Ümm-i hânî ve \nbaşka bir kızı vardır.", "gectigiMaddeler": ["1/85", "1/97", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Tâlib-i Mekkî", "slug": "ebu-talib-i-mekki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Alî \nmâlikî, Sôfiyye-i aliyyenin meşhûrlarındandır. 386 [m. 996] senesinde Bağdâdda \nvefât etdi. (Kût-ül-kulûb) kitâbı meşhûrdur.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebüttufeyl Âmir bin Vâsile", "slug": "ebuttufeyl-amir-bin-vasile", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Uhud günü \ntevellüd, 100 [m. 718] senesinde Mekkede vefât etdi. Eshâb- ı kirâmdan en son \nvefât eden budur.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Ubeyde bin Cerrâh", "slug": "ebu-ubeyde-bin-cerrah", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Âmir bin Abdüllah \nbin Cerrâh bin Kâ’b bin Dabbe bin Hars bin Fehr, bütün gazâlarda bulundu. Çok \nkahramân idi. Bedrde pederini katl etdi. Uhudda Resûlullahın yanağına batan iki \ndemir halkayı dişleri ile çekip çıkardı. Rumlar ile olan muhârebede, senelerce \nnefer olarak savaşırken, halîfe Ömer “radıyallahü anh” tarafından Şâm ordularına \nbaş kumandan yapıldı. Adâleti ile rum halkını hayretde bırakdı. Şâmlıların seve \nseve îmân etmelerine sebeb oldu. Onsekiz [18] senesinde, ellisekiz yaşında, Kudüs \nile Remle arasında tâ’ûndan vefât etdi.", "gectigiMaddeler": ["1/93", "2/23", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Ümâme", "slug": "ebu-umame", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Sadî bin Aclân-i Bâhilî, sahâbîdir. \nYüzelli hadîs-işerîf haber vermişdir. Mısrda yerleşdi. Humsda, 81 [m. 700] sene-\nsinde vefât etdi. Şâmda en son vefât eden budur.", "gectigiMaddeler": ["1/58", "1/90"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Ya'kûb-i Basrî", "slug": "ebu-yakub-i-basri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "EBÛ YA’KÛB- İ BASRÎ “rahmetullahi teâlâ aleyh”: Sôfiyyedendir.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Ya'lâ", "slug": "ebu-yala", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Alî, hadîs âlimidir. \n(Müsned) kitâbı meşhûrdur. [210] da tevellüd, 307 [m. 920] senesinde Mûsulda \nvefât etdi.", "gectigiMaddeler": ["1/98", "2/6"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Yûsüf", "slug": "ebu-yusuf", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ya’kûb bin İbrâhîm Ensârî, Ebû \nHanîfenin talebesinin en büyüğüdür. Hanefî mezhebinde ilk kitâb yazan budur. 113 \n[m. 731] senesinde Kûfede tevellüd, 182 [m. 798] de Bağdâdda vefât etdi. (Kitâb-\nül-harâc)ı fransızcaya terceme edilmişdir. 72, 120, 132, 133, 137, 139, 155, 167, 202, \n– 1096 –", "gectigiMaddeler": ["1/67", "1/68", "1/73", "1/76", "1/78", "1/81", "2/5", "2/16", "2/34", "2/37", "2/38", "2/40", "2/41", "2/42", "2/43", "2/45", "3/4", "3/5", "3/6", "3/12", "3/13", "3/19", "3/20", "3/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ebû Zer-i Gıfârî", "slug": "ebu-zer-i-gifari", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Müncidde Zer kelimesinde \nGaffârî yazıyor. İlk müslimân olanlardandır. Hendekden sonra Medîneye geldi. 32 \n[m. 652] senesinde Medîneye yakın Rebzede vefât etdi. Hadîs-işerîf ile medh edil-\nmişdir.", "gectigiMaddeler": ["1/90", "2/17", "2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Echürî Alî", "slug": "echuri-ali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mısrdaki Mâlikî âlimlerinin \nbüyüklerindendir. [967] de tevellüd, 1066 [m. 1656] da vefât etdi. Tütün içmenin \nmubâh olduğuna fetvâ verdi.", "gectigiMaddeler": ["2/1", "2/43", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Edison", "slug": "edison", "unvan": "", "kategori": "diger", "biyografi": "Thomas, Amerikalı fizikcidir. 1263 [m. 1847] de tevellüd, 1350 \n[m. 1931] de vefât etdi. Phonograph, megaphon, elektrik ampulüne sonşeklini ver-\nmişdir.", "gectigiMaddeler": ["2/15", "2/49"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Eflâtun", "slug": "eflatun", "unvan": "", "kategori": "diger", "biyografi": "Platon, eski yunan felsefecisidir. Sokratın talebesi, Aristo-\nnun hocasıdır. Avrupalılar, mîlâddan [429] sene önce tevellüd etmiş diyorlar ise \nde, Îsâ “aleyhisselâm” zemânında yaşadığı (Burhân-ı kâtı)da yazılıdır. Mısra da \ngitdi. Sekseniki yaşında vefât etdi. Çok kitâb yazdı. Tenâsüha inanırdı. (Trinite) \ndenilen (Teslîs) inancını ilk olarak ortaya çıkaran budur. Îsâ “aleyhisselâm” göke \nçıkarıldıkdan sonra, dört İncîli yazanlar, bu inancı karışdırarak, beşeriyyeti büyük \nfelâkete sürüklediler.", "gectigiMaddeler": ["1/25", "2/67", "3/51"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ehîçelebî", "slug": "ehicelebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dokuzyüzyetmişdokuzuncu \n[979] sırada Yûsüf bin Cüneyd ismine bakınız!", "gectigiMaddeler": ["1/41", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Einstein", "slug": "einstein", "unvan": "", "kategori": "diger", "biyografi": "Aynştayn, Alman fizikçisi bir yehûdîdir. 1296 [m. 1879] da \ntevellüd, 1375 [m. 1955] de vefât etdi.", "gectigiMaddeler": ["2/30", "2/32", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ekberşâh", "slug": "ekbersah", "unvan": "", "kategori": "diger", "biyografi": "Celâleddîn Muhammed, Hindistânda Bâbürşâhın torunu \nve Hümâyûnşâhın oğludur. 949 [m. 1542] da tevellüd, 1014 [m. 1605] de vefât etdi. \n[963] de hükûmet reîsi oldu. Mecûsî, Berehmen ve Hıristiyanlara hürriyyet tanır. \nMüslimânlara zulm, işkence ederdi. Egrede büyük türbesi vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ekmelüddîn", "slug": "ekmeluddin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzkırkyedinci [647] \nsırada Muhammed bin Mahmûd ismine bakınız!", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Elbâb Alî", "slug": "elbab-ali", "unvan": "", "kategori": "diger", "biyografi": "Alî Muhammed, Îrânda 1236 [m. 1821] da tevellüd etdi. \nTesavvuf ile felsefeyi karışdıranlardan (Ahmed Zeyneddîn İhsâî)nin talebesi idi. \nÎrân ve Hindistânda dolaşdı. Birkaç def’a hacca gitdi. [1260] da Şîrâzda yeni bir din \nkurdu. Şîrâzda bir büyük câmi’, Kâ’be ve kıble yapdı. Yalnız iki rek’at sabâh \nnemâzı ile senede bir ay oruc farzdır dedi. (Bâbî) denilen bu dîne girmiyenleri \nöldürmek halâldir dedi. Öldürüldükden sonra, Kurre-tül-ayn adında bir acem kızı, \nbu dîni yaymağa çalışdı. Mini etek ve çıplak gezmek modasını çıkardı. Yakalanıp \ndiri olarak yakıldı. Bâb fikrlerini, yirmiüç kitâbda bildirdi. Buna Behâîlik denildi. \n1266 [m. 1850] da Îrân hükûmeti tarafından, Tebrîzde kurşuna dizildi.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Elmalılı Hamdi", "slug": "elmalili-hamdi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Hamdi bin \nNu’mân, Antalyanın Elmalı kazâsında [1294] de tevellüd, 1361 [m. 1942] de, İstan-\nbulda vefât etdi. Erenköydedir. Sultân ikinci Abdülhamîd hân zemânında yetişen \ndin adamıdır. Zemânının âlimi idi. Tefsîri meşhûrdur.", "gectigiMaddeler": ["1/60", "1/61", "1/64", "2/17", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Emîr Gilâl", "slug": "emir-gilal", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyiddir. Muhammed Buhâ-\nrînin üstâdıdır. Buhârânın Sûhârî kasabasında tevellüd, 772 [m. 1370] de orada \nvefât etdi. Hâce Bâbâ Semmâsînin talebesi idi. Gençliğinde güreş yapardı. Sonra, \nçömlekcilik yapdığı için Gilâl ismi ile meşhûr olmuşdur.", "gectigiMaddeler": ["1/41", "3/51", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Emîr Sultân", "slug": "emir-sultan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Adı Muhammed Şemsüd-\ndîndir. Buhârâda tevellüd etdi ve oradaki Evliyâdan feyz aldı. Kerâmetleri görül-\ndü. Bursada molla Fenârîden okudu. Yıldırım Bâyezîde dâmâd oldu. 833 [m. 1430] \n– 1097 –\nde vefât etdi. İsmi ile anılan câmi’ yanındaki türbesindedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Enes bin Mâlik bin Nadr", "slug": "enes-bin-malik-bin-nadr", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ebû Hamza Ensârî \nHuzrecîdir. Dokuz yaşında Resûlullaha hizmete başlayıp, vefâtlarına kadar ayrıl-\nmadı. Yüz yaşlarında, [91] de vefât etdi. İmâm-ı Mâlikin babası Enes başkadır.", "gectigiMaddeler": ["1/95", "1/96", "2/16", "2/40", "2/44", "2/45", "3/2", "3/59", "3/68"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Engels", "slug": "engels", "unvan": "", "kategori": "diger", "biyografi": "Fredirik Engels bir Alman fabrikatörünün oğludur. 1235 [m. \n1820] de tevellüd, 1313 [m. 1895] de vefât etdi. Karl Marx ile birlikde komünist \nbeyânnâmesini neşr etdi.", "gectigiMaddeler": ["2/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Enver Pâşa", "slug": "enver-pasa", "unvan": "", "kategori": "diger", "biyografi": "(İslâm Ahlâkı) 474.cü sahîfeye bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Enver Ören", "slug": "enver-oren", "unvan": "", "kategori": "diger", "biyografi": "Hüseyn Hilmi Işıkın en çok sevdiği talebesi ve dâmâdı-\ndır. 1939 da Denizlide tevellüd etdi. İhlâs Holdingin ve Türkiye gazetesinin sâhibi \nidi. 1434 [m. 2013] de vefât etdi. Kaşgârî dergâhı yakınında, çok sevdiği hocası \nHüseyn Hilmi Işık “rahmetullahi aleyh” yanında medfûndur. Ehl-i sünnet bilgile-\nrinin basılmasına ve yayılmasına çok hizmet etmişdir. 628", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Esîrüddîn-i Ebherî", "slug": "esiruddin-i-ebheri", "unvan": "", "kategori": "diger", "biyografi": "Müfaddal bin Ömer, matematik, astronomi, \nfizik ve mantık âlimi idi. Mûsulda ve Anadoluda bulundu. (Hidâye) fizik kitâbını \nyazmış, Hüseyn Kâdî mîr bunuşerh etmişdir. (Îsâgûcî) mantık kitâbı da meşhûr-\ndur. Îsâgûcî yunancada başlangıç demekdir. 663 [m. 1265] de vefât etdi. Esîreddîn \nMuhammed Ebû Hayyân Endülüsî 745 [m. 1344] de Mısrda vefât etdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Esmâ", "slug": "esma", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Hazret-i Ebû Bekrin büyük kızı, aşere-i \nmübeşşereden Zübeyr bin Avvâmın zevcesi idi. 73 [m. 692] senesinde, yüz yaşında \nvefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Eşrefzâde-i Rûmî", "slug": "esrefzade-i-rumi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah bin Eşref \nbin Muhammed Mısrî, babasının ismi ileşöhret bulmuşdur. Kâdirî meşâyıhinden-\ndir. Çok kitâb yazdı. (Müzekkin-nüfûs) kitâbı meşhûrdur. Sekizyüzseksendokuz \n889 [m. 1484] senesinde İznikde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Evzâî", "slug": "evzai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrahmân bin Amr Evzâî, 88 [m. \n707] de Ba’lebekde tevellüd, 157 [m. 774] de vefât etdi. Şâmın en büyük fıkh âlimi \nidi. Beyrutun cenûbunda, kendi adını taşıyan câmi’ kıblesindedir.", "gectigiMaddeler": ["1/64", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Eyyûb", "slug": "eyyub", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Benî-Îsrâîl Peygamberlerindendir. Yedi kişi îmân \netdi. Çok malı ve on oğlu vardı. Çocukları öldü. Malı, mülkü gitdi. Hasta oldu. Hepşükr etdi. Yaralarının kurtlandığını büyük âlim Feridüddîn-i Attâr yazmakdadır. \nYeniden sıhhat verildi. Çok malı ve çocukları oldu. Yüzkırk sene yaşadı.", "gectigiMaddeler": ["1/85", "2/20", "3/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Eyyûb Sabri Pâşa", "slug": "eyyub-sabri-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İkinci Abdülhamîd \nhânın amirallerinden idi. 1308 [m. 1890] de vefât etdi. Türkçe (Mir’ât-ül-Hare-\nmeyn) târîh kitâbı beş cilddir. Türkçe (Târîh-i Vehhâbiyân) kitâbı 1296 [m. 1879] \nda İstanbulda basdırılmışdır.", "gectigiMaddeler": ["1/95", "2/17", "2/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Eyyûb-i Sahtiyânî", "slug": "eyyub-i-sahtiyani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İkiyüzkırkıncı [240] \nsırada, Ebû Eyyûb ismine bakınız!", "gectigiMaddeler": ["1/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fadl", "slug": "fadl", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın amcası olan hazret-i Abbâsın \nbüyük oğludur. Annesi, Meymûne vâlidemizin hemşîresi olan Lübâbe idi. \nHuneynde çok kahramânlık gösterdi. Resûlullah yıkanırken su döküyordu. Çok \ngüzel idi. Yermük gazâsındaşehîd oldu.", "gectigiMaddeler": ["3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fadl bin Ruzbehân", "slug": "fadl-bin-ruzbehan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İsfehânlıdır. Ehl-i \nsünnet âlimlerindendir. Şî’îlerden İbnül-Mutahhiri red eden (İbtâl-ül-menhec-il-\nbâtıl) kitâbı çok kıymetlidir. 852 [m. 1448] senesinde yazmışdır. Abdül-Hâlık-ı \nGoncdüvânînin vasıyyetlerinişerh eden (Şerh-ul-vasâyâ) kitâbı da meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fadlullah-ı Hurûfî", "slug": "fadlullah-i-hurufi", "unvan": "", "kategori": "diger", "biyografi": "Fadlullah bin Abdürrahmân Tebrîzî, hurûfî-\nlik denilen sapık inançların kurucusudur. Bir acem yehûdîsidir. 741 [m. 1340] de Îrâ-\n– 1098 –\nnın kuzeyinde Esterâbâdşehrinde tevellüd, 796 [m. 1393] da Tîmûr hânın oğlu Mî -\nrânşâh tarafından, babasının emri ile öldürüldü. Karâmıtî fırkasının döküntülerin-\nden idi. (Câvidân) adında fârisî büyük bir kitâb yazdı. Burada Kur’ân- ı kerîmdeki \nharflere ma’nâlar vererek, kendisinin tanrı olduğunu bildirdi. Bütün dinleri inkâr ve \nislâmiyyet ile alay etdi. Talebesinden Şemseddîn adındaki hurûfînin halîfesi Bâyezî-\ndin talebesinden olan Ferişteh oğlu denilen Abdülmecîd İzzeddîn (Aşknâme) adı \nile, bu kitâbı genişletdi. Kitâblarında dinsizlik, ahlâksızlık olduğundan ve herşeye \nhalâl dediklerinden gizli tutarlar. (Sır) derler. Tîmûr hân, Fadlullahı öldürtdü. Tek-\nkelerini dağıtdı. Esterâbâdşehrini yakdı, yıkdı. İslâmiyyeti bu sapıklardan temizledi. \nYavuz sultân Selîm hân, şî’îliğin yayılmasını önlediği gibi, Tîmûr hân da bu din veırz düşmanlarının yayılmasını önleyerek, islâmiyyete çok büyük hizmet etmişdir. \nHurûfîlik sonradan bektâşî tekkelerine yayıldı. Bektâşî adını müslimânlardan ala-\nrak, kendilerine mâl etdiler.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fahrüddîn-i Râzî", "slug": "fahruddin-i-razi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nÖmer, büyük islâm âlimidir. Tefsîr, kelâm, fıkh, fizik, matematik ve tıb üzerinde \nçok kitâb yazmışdır. Tefsîr ve Şâfi’î fıkh âlimidir. Allâme veşeyh-ul-islâm ismleri \nverilmişdir. 544 [m. 1149] de Reyşehrinde tevellüd, 606 [m. 1209] da Hiratda vefât \netdi.", "gectigiMaddeler": ["1/93", "1/97", "2/5", "2/17", "2/19", "2/21", "2/30", "2/44", "2/50", "2/67", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fahr-Ul- İslâm", "slug": "fahr-ul-islam", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Muhammed \nPezdevî, Hanefî fıkh âlimlerindendir. 400 senesinde tevellüd, 482 [m. 1089] de \nSemerkandda vefât etdi. Çok kitâb yazdı.", "gectigiMaddeler": ["2/16", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fârâbî", "slug": "farabi", "unvan": "", "kategori": "diger", "biyografi": "Muhammed bin Turhân, felsefeci ve mûsikî üstâdı idi. 259 [m. \n873] da Seyhûn nehrine yakın Fârâb kasabasında tevellüd, 339 [m. 950] da Şâmda \nvefât etdi. Çok kitâb yazdı.", "gectigiMaddeler": ["2/67", "3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fâtih Muhammed Hân", "slug": "fatih-muhammed-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlı pâdi-\nşâhlarının yedincisidir. Halîfe değildi. İkinci Murâd hânın oğlu, ikinci Bâyezîd hânın \nbabasıdır. 833 [m. 1429] de Edirnede tevellüd, 886 [m. 1481] da Gebzede vefât etdi. \nTürbesi Fâtih câmi’i yanındadır. 855 [m. 1451] de pâdişâh oldu. Bosna Herseği ve \nbirçok yerleri aldı. 857 [m. 1453] Mayıs ayının yirmidokuzuncu Salı günü İstanbulu \nBizans rumlarından alarak, orta çağa son verdi. Ayasofya kilisesini câmi’ yapdı. \nKıyâmete kadar câmi’ kalmasını yazılı vasıyyet ve vakf eyledi. Fekat, 1354 [m. 1935] \nRamezân ayında müze yapıldı. 1411 [m.1990] Ramezân ayında, bir kısmı, 3 Zilhicce \n1441 [24 Temmuz 2020] Cum’a günü temâmı, Ayasofya-i Kebîr Câmi’i Şerîfi olarak \nibâdete açıldı. Ayasofya [Sainte Sophie] câmi’i, İstanbulda, Topkapı serâyı yanında-\ndır. Mîlâdın 325 senesinde, büyük Kostantin tarafından ahşap olarak yapıldığı, \nAryüs mezhebinde olup, 408 de vefât eden Arkadyus zemânında yandığı, bunun \noğlu Teodosyusun yeniden yapdırdığı, Jüstinyanus zemânındaki ihtilâlde yine yan-\ndığı, bunun tarafındanşimdiki binânın yapdırıldığı (Kâmûs-ül-a’lâm)da yazılıdır. \nJustinyanus, 565 de ölmüşdür. Bunun zemânında, zelzelede kubbesi yıkılmış, şimdi-\nki kubbe 548 de yapılmışdır. Şarkdan garba 81, şimâlden cenûba 73, yüksekliği 57 \nmetredir. Makedonyalı Vasil [Balis I.] ve Roman ve Andronik zemânlarında tâmir \nedilmişdir. Fâtih, bir tuğla minâre yapdırmışdır. Serây kapısı köşesindeki minâreyi \nikinci Bâyezîd, diğer iki minâreyi ikinci Selîm hân yapdırmışdır. Şadırvanı birinci \nMahmûd hân, büyük top kandili üçüncü Ahmed hân yapdırmışdır. Bağçesinde, ikin-\nci Selîmin, üçüncü Murâdın, üçüncü Muhammedin, birinci Mustafânın ve üçüncü \nMurâdşahzâdelerinin olarak beş türbe vardır. Kumkapıdaki küçük Ayasofyayı da \nJüstinyanus yapdırmışdır. Sultân Mahmûd türbesi yanındaki kırmızı mermerden \n(Çemberli taş)ı büyük Kostantin Romadan getirmişdir. Üzerinde Apolonun hey-\nkeli vardı. Sonra Jülyanus ve Teodosyüs heykellerini koydurdular. Komnus zemâ-\nnında yıldırım heykelleri yıkdı, yerlerine haç kondu. Bu da yandı. Demir çember-\nlerle bağladılar. Fâtih câmi’i, Yedikule câmi’i, Kireç iskelesi câmi’i, Şehremini \ncâmi’i ve Rumeli-hisârı, Fâtih sultân Muhammedin türklere bırakdığı yâdigârlarının \nen kıymetlilerindendir. Rumeli-hisârı câmi’ini hâcı Kemâleddîn efendi yapdırmış-\n– 1099 –\ndır. Kabri de oradadır. 1159 [m. 1746] da yandığı için birinci Mahmûd hân yeniden \nyapdırdı. Ayvanserâyda Tahta-minâre ve Akserâyda Horhor çeşmelerine bitişik \nHindiler tekkesi mescidlerini de Fâtih yapdırdı. Havan topunu ilk yapdıran Fâtihdir.  \nFâtih sultân Muhammedin vezîrlerinden Murâd pâşa, 870 [m. 1465] de Akserây-\nda Murâd pâşa câmi’ini yapdırdı. 879 [m. 1474] de Ak-koyunlu uzun Hasen ile \nharb ederken Diyâr- ı Bekrdeşehîd oldu. Şadırvanını yapdıran Kara Dâvüd pâşa \nikinci Osmân hânışehîd eden zorbalarla işbirliği yapdığından, i’dâm olunup \nMurâd pâşa câmi’i yanına defn edilmişdir. Sadr-ı a’zam Mesîh Alî pâşa veşeyh-ul-\nislâm pîrî zâde Osmân Sâhib efendi de oradadır. Fâtih sultân Muhammed, Kâsım \npâşada Dîvânhâne mescidini de yapdırmışdır. Sultân Süleymân, bu câmi’in etrâfı-\nna bir serây ve bir dîvânhâne yapdı. Osmânlılarda ilk tersâneyi 922 [m. 1516] de \nYavuz sultân Selîm hân yapmışdır. Okmeydânı câmi’ini de Fâtih yapdırmışdır. \nİstanbulu kuşatınca, yetmiş gemiyi Balta limanından kızaklarla karadan Kâsım \npâşaya indirdi. Bir sene sonra Bâyezîd kulesinin olduğu yerde, ilk türk serâyını \nyapdırdı. Bu büyük serâya (Eski serây)  denir.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fâtıma", "slug": "fatima", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın dördüncü kızı, hazret-i Alînin \nzevcesi ve hazret-i Ömerin kayın vâlidesidir. Nikâh yapılırken onbeş yaşında idi. \nMehri dörtyüz miskal gümüş olduğu (Mevâhib-i ledünniyye) de Sevîk gazvesinde \nyazılıdır. 57,14 miskal altın demekdir. Bugün için 38 altın liradır. Alî “radıyallahü \nanh” yirmibeş yaşında idi. Ehl-i beytdendir. Beyâz, çok güzel idi. Hicretden onüç \nsene önce, Mekkede tevellüd, onbirinci [11] senede yirmidört yaşında vefât etdi. \nHasen, Hüseyn ve Muhsîn adında üç oğlu ile Ümm-i Gülsüm ve Zeyneb adında iki \nkızı oldu. Resûlullahın soyu, Fâtımadan türedi. Zeyneb, Abdüllah bin Ca’fer Tay-\nyâr ile nikâhlanıp, Alî ve Ümm-i Gülsüm ve zürriyyetleri oldu. Bunlara (Şerîf-i \nCa’ferî) denir.", "gectigiMaddeler": ["1/31", "1/84", "2/25", "2/34", "2/53", "2/61", "3/36", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fâtıma binti Esed", "slug": "fatima-binti-esed", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Ebû Tâlibin zevcesi, Alî, \nUkayl ve Ca’fer Tayyâr hazretlerinin annesidir. Mekkede müslimân oldu. Medîne-\nye hicret etdi. Resûlullaha annelik etdi. Çok iyi bakdı. Medînede vefât etdi. Resû-\nlullah nemâzını kıldırdı. Elleri ile kabre koydu.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fâtıma Sultân", "slug": "fatima-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Yâvuz sultân Selîm \nhânın kerîmesidir. Topkapıda, zevci kara Ahmed pâşanın câmi’ine yakın (Fâtıma \nsultân mescidi)ni yapdırmışdır. Kara Ahmed pâşanın yapdırdığı (Topkapı câmi’i), \n(Pazartekke mescidi)nin yanındadır. Ahmed pâşa dokuzyüzaltmışiki 962 [m. 1554] \nsenesindeşehîd edilince, inşâsı yarım kalmışdı. Dokuzyüzyetmişikide [972], karde-\nşi Rüstem pâşa temâmlamağa başladı. Yedi senede temâm oldu. Ahmed pâşa \ncâmi’i yanındaki türbededir. Zevcesi Fâtıma sultân, bu türbenin yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fâtıma Sultân", "slug": "fatima-sultan-2", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Yâvuz sultân Selîm \nhânın kerîmesidir. Topkapıda, zevci kara Ahmed pâşanın câmi’ine yakın (Fâtıma \nsultân mescidi)ni yapdırmışdır. Kara Ahmed pâşanın yapdırdığı (Topkapı câmi’i), \n(Pazartekke mescidi)nin yanındadır. Ahmed pâşa dokuzyüzaltmışiki 962 [m. 1554] \nsenesindeşehîd edilince, inşâsı yarım kalmışdı. Dokuzyüzyetmişikide [972], karde-\nşi Rüstem pâşa temâmlamağa başladı. Yedi senede temâm oldu. Ahmed pâşa \ncâmi’i yanındaki türbededir. Zevcesi Fâtıma sultân, bu türbenin yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Faysal", "slug": "faysal", "unvan": "", "kategori": "diger", "biyografi": "Sü’ûdî devlet reîslerindendir. İkinci Abdül’azîzin oğludur. \nKardeşi Sü’ûd müsrif hareketleri ile memleketi felâkete götürdüğünden, 1384 [m. \n1964] de tahtdan indirildi. Yerine, ellisekiz yaşındaki Faysal geçdi. m.1975 de, serâ-\nyında yeğeni tarafından öldürüldü. Yerine kardeşi Hâlid geçdi. Hâlid de, 1402 [m. \n1982] de öldü. Yerine kardeşi Fahd geçdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fehîm-i Arvâsî", "slug": "fehim-i-arvasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüzyirmialtıncı \n[826] numarada, seyyid Fehîm kelimesine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fenârîşemsüddîn", "slug": "fenarisemsuddin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nHamza, Osmânlışeyh-ul-islâmlarının birincisidir. 751 de tevellüd, 834 [m. 1431] de \nvefât etmişdir. Bursada, Keşiş dağı eteğindeki mescidi yanındadır. Din ve fen bil-\ngilerinde, zemânının en meşhûru idi. Çok talebe yetişdirdi. Kütübhânesinde on -\n– 1100 –\nbinden fazla kitâb vardı. Tesavvufda yüksek dereceye kavuşmuşdu. İki oğlu da, \nkendisi gibi âlim idi. Soyundan Alî bin Yûsüf, Akserâyda vatan caddesindeki kili-\nseyi câmi’ yapmışdır. İmâmı, Îsâ efendi, câmi’e çok vakf yapdığından, (Fenârî Îsâ) \nmescidi denilmişdir. Bursada kâdî iken 903 de vefât etmişdir. Ahfâdından Muhyid-\ndîn bin Muhammed Fenârî, onüçüncüşeyh-ul-islâm olup, Beykoza bağlı (Dere-\nseki)de ve Rumeli-hisârında birer mescid yapdırmış, dokuzyüzellidört [954] de \nvefât etmişdir. Eyyûb sultândadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Feridüddîn-i Attâr", "slug": "feriduddin-i-attar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nİbrâhîm, Sôfiyye-i aliyyedendir. (Mantık-ut-tayr) kitâbında, tesavvufu kuşlar \nağzından anlatmakdadır. Fârisî (Tezkiret-ül-Evliyâ)sından bir kısmı (Hakîkat \nKitâbevi) tarafından (Akâid-i Nizâmiyye) içinde tab’ edilmişdir. [513] de Nîşâpûr-\nda tevellüd, 627 [m. 1230] de Cengiz askeri tarafından, oradaşehîd edildi. Babası \nattâr idi. Ya’nî, ilâc, esans satardı. Ferîdeddîn-i Genc-işeker başkadır. Sekizyüzalt-\nmışdokuzuncu [869] sırada Şeker Genç ismine bakınız!", "gectigiMaddeler": ["1/78"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ferişteh Oğlu", "slug": "feristeh-oglu", "unvan": "", "kategori": "diger", "biyografi": "Hurûfî babalarındandır. Hurûfîliğin kurucusu olan \nFadlullah-ı Hurûfînin müridlerindendir. Adı Abdülmecid İzzeddîndir. 874 [m. \n1469] de öldü. Hurûfî dedelerinin dinden çıkmalarına sebeb olan (Aşknâme) kitâ-\nbını yazmışdır.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ferrûh Sîrşâh", "slug": "ferruh-sirsah", "unvan": "", "kategori": "diger", "biyografi": "Hind sultânlarının dokuzuncusu Ferrûh Sîr Şâh \n1122 [m. 1710] de vefât etdi. Muhammed Ma’sûmun oğlu Muhammed Sıddîkın \nmürîdi idi. [(Umdetül-makâmât) sahîfe 395.]", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Feth-i Mûsulî", "slug": "feth-i-musuli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Alî efendidir. \nBişr-i Hâfînin arkadaşı idi. 220 [m. 835] senesinde Bağdâdda vefât etdi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Feyzullah Efendi", "slug": "feyzullah-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Erzurumludur. Şem-\nseddîn-i Tebrîzî soyundandır. Osmânlışeyh-ul-islâmlarının kırkaltıncısıdır. Edirne-\nde 1115 [m. 1703] senesindeşehîd edildi. Medrese, kütübhâne, mektebler yapdırdı. \nFeyzullah Erzincânî, Mevlânâ Hâlid-i Bağdâdînin (İ’tikâdnâme) kitâbını türk-\nçeye terceme etmiş, (Herkese Lâzım Olan Îmân)  kitâbının birinci risâlesi olarak \nbasılmışdır. 1323 [m. 1905] de vefât etmişdir.", "gectigiMaddeler": ["2/35"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fihr", "slug": "fihr", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın onbirinci babasıdır. Mâlikin oğlu, Gâlibin babasıdır. \nFihr, avuc dolusu taş demekdir. İsmi Kureyşdir. Bunun soyundan olanlara (Kurey-\nşî) denir. Kureyş, köpek balığı demekdir ve cem’ olmak ve toplanmak demekdir. \nHac için Mekkede toplandıkları için Kureyş denildi.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fir'avn", "slug": "firavn", "unvan": "", "kategori": "diger", "biyografi": "Eski Mısr hükümdârlarına verilen ismdir. Yirmialtı Fir’avn \nsülâlesi vardır. Her sülâlede çeşidli Fir’avnlar asrlarca hükümdârlık etdi. Çoğu, \ninsanları kendilerine tapındırdı. Mûsâ “aleyhisselâm” zemânındaki Fir’avn, Muhar-\nrem ayının onuncu günü, askeri ile birlikde bahr-i ahmerin Süveyş kısmında boğul-\ndu. Îmânı kabûl olmadı.", "gectigiMaddeler": ["1/46", "1/85", "2/17", "2/21", "2/26", "2/44", "2/47", "3/18"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fîrûzâbâdî", "slug": "firuzabadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Ya’kûb, \n(Kâmûs) lügâtini yazmışdır. Îrânda Şîrâzın cenûbunda, Fîrûz-âbâdda, 729 [m. 1329] da \ntevellüd, 816 [m. 1414] da Yemende Zebîdde kâdî iken vefât etdi. Tefsîr, hadîs, fıkh ve \nlügât âlimi idi. Yıldırım ve Tîmûr ile görüşüp ihsânlarına kavuşdu.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fîrûzşâh", "slug": "firuzsah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Delhîde hükm süren Tuğluk \nsülâlesindendir. [752] de tahta çıkdı. Çok âdil idi. Bendler, barajlar, kal’a ve mek-\ntebler yapdı. Çeştiyye meşâyıhından Kutb- ı zemân Celâl-i Buhârînin halîfesi idi. \nMürşidinin emri ile Serhendşehrini yapdı. 790 [m. 1388] da, seksen yaşında vefât \netdi. Yapdırdığı su yolu, Serhend kısmını sulamakdadır. İkiyüzkırk kilometre \nuzunluğundadır. Geçdiği yerleri sulamakdadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Fudayl bin Iyâd", "slug": "fudayl-bin-iyad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Evliyânın büyüklerin-\ndendir. [107] de tevellüd, 187 [m. 803] senesinde Mekkede vefât etdi. Sırrî-yi Se -\n– 1101 –\nkâtînin mürşidlerindendir. (Hicâb-ül-aktâr) kitâbı Pârisdedir.", "gectigiMaddeler": ["1/41", "2/21", "2/47", "3/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Galile", "slug": "galile", "unvan": "", "kategori": "diger", "biyografi": "İtalyan astronomlarındandır. 981 [m. 1574] de Pizede tevellüd, \n1051 [m. 1642] de vefât etdi. Yirmiiki yaşında, Üniversite matematik profesörü \noldu. Dünyâ dönüyor dediği için, yetmiş yaşında habs edildi. Habshânede gözleri \nkör oldu.", "gectigiMaddeler": ["2/49"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ganîm-i Bağdâdî", "slug": "ganim-i-bagdadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Muhammed-\ndir. Hanefî âlimlerindendir. Çok kitâb yazdı. Tütün içmenin harâm olmadığına \nfetvâ verdi. 1030 [m. 1621] da vefât etdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Gazâlî Muhammed", "slug": "gazali-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMuhammed Gazâlî, islâm âlimlerinin en büyüklerindendir. 450 [m. 1058] senesin-\nde, Îrânın Tus ya’nî Meşhedşehrinin Gazâl kariyyesinde tevellüd, 505 [m. 1111] de \norada vefât etdi. Müctehid idi. İctihâdı, Şâfi’î mezhebine uygun oldu. O kadar çok \nkitâb yazdı ki, ömrüne bölününce, bir güne onsekiz sahîfe düşmekdedir. [484] de \nBağdâdda Nizâmiyye üniversitesine profesör oldu. Hacca gidip gelince, Şâmda \nprofesörlük yapdı. Sonra Nişâpûrda profesörlüğü zorla kabûl etdi. Kitâbları çok \nkıymetlidir. Garb dillerine çevrilmekdedir. (Eyyühel-veled) kitâbı arabîdir. Fârisî \ntercemesi, Bursada, Orhân câmi’i kütübhânesinde mevcûddür. Bu kitâbı, 1364 [m. \n1945] de kurulmuş olan milletler arası ilm yayma (Unesco) teşkilâtı tarafından \n1370 [m. 1951] de fransızcaya, ingilizceye ve ispanyolcaya terceme edilerek, hepsi \nbasılmışdır. [m. 1959] da, dört alman ordinaryüs profesörünün, Gazâlînin kitâbla-\nrını okuyarak, islâm dînine âşık olduklarını ve imâmın kitâblarını almancaya çevir-\nmekde olduklarını gazetelerde okuduk. \nİmâm-ı Gazâlîye islâm felesofu diyenler oluyor. Bu büyük imâm, felesof değil-\ndir. Bir islâm âlimi, bir müctehid idi. Onun kitâblarında mevdu’ hadîs var sanan \nkimse, yâ onu tanımıyan, din imâmı ve müctehid ne demek olduğunu bilmiyen \ncâhillerdendir. Yâhud Ehl-i sünnete düşman olan vehhâbîlerin tuzağına düşmüş \nbir zevallıdır. İslâm âlimlerinin hiçbiri felesof değildir. Felesof, islâm âlimi olamaz. \nNasıl ki, cam parçası pırlanta olamaz. İslâm felesofu diye birşey yokdur. İslâmiy-\nyetde felsefe yokdur. Binüçyüzseksenüç 1383 [m. 1963] senesinde Pâkistânda bası-\nlan (Me’ârif-üs-sünen) adındaki yedi cild kitâbın birinci cildinde de ( İslâm âlimle-\nrine göre rûh cismdir. Eski yunan felsefecileri rûh cism değildir dedi. İmâm-ı Gazâ-\nlî de böyle dedi. Onun felsefeye bağlılığı birçok yerde kendine hâkim olmuşdur) \ndiyor. Mücessimeden olan İbni Teymiyyenin rûh hakkındaki sözlerini, islâm âlim-\nlerinin sözü diye yazarak koca Gazâlîyi küçümsemek gafletine düşmekdedir. Arabî \nbeş cild (İhyâ-ül-ulûm) kitâbı 1387 [m. 1968] senesinde Beyrutda ve fârisî bir cild \n(Kimyâ-i se’âdet) kitâbı Muhammed Şâh Rızâ Pehlevî zemânında 1374 [m. 1955] \nde Tahranda ve 1398 [m. 1977] de İstanbulda basılmışdır. Bu Ehl-i sünnet kitâbının \nve benzerlerinin Tahranda basılması ve Îrânda Ehl-i sünnet medrese ve tekkeleri-\nnin açılması sebebi ile taşkınşî’îler, Humeynî ismindeki bir âhundun teşvîkı ileşâha karşı isyân ederek, Îrânda Şî’î Cumhûriyyeti kurdular. (Dürret-ül-fâhire) \nkitâbının arabîden türkçeye tercemesi, (Kıyâmet ve Âhıret hâlleri) ismi ile basıl-\nmışdır. Îsâ aleyhisselâmın, Allahü teâlânın kulu ve Peygamberi olduğunu vesîka-\nlarla isbât eden (Er-reddül-cemîl li-ülûhiyyet-i Îsâ bi-sarîh-il İncîl) kitâbı, fransızca \ntercemesi ile birlikde, 1359 [m. 1939] senesinde Robert Chidiac tarafından Parisde \nbasdırılmış, 1407 [m. 1986] da İstanbulda Hakîkat Kitâbevi tarafından, ikisi de \nofset ile basdırılmışdır. 18, 26, 34, 42, 82, 105, 108, 116, 120, 132, 279, 412, 415, 418, \n419, 420, 430, 455, 470, 490, 491, 497, 600, 605, 677, 698, 700, 719, 758, 761, 766, 909, \n962, 964, 1008, 1010, 1047, 1053, 1058, 1079, 1090, 1103, 1116, 1118, 1173, 1184. \n— Gazevât-ı Peygamberî: (İslâm Ahlâkı) sahîfe 195 e bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Göte (goethe)", "slug": "gote-goethe", "unvan": "", "kategori": "diger", "biyografi": "GÖTE (Goethe): Ünlü almanşâ’iridir. 1162 [m. 1749] de tevellüd, 1248 \n[m. 1832] de vefât etdi. Hikâye ve tiyatro kitâbları yazdı. Faust tiyatrosu çok \n– 1102 –\nmeşhûr oldu. Kur’ân- ı kerîmin büyüklüğünü söylerdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Gülşenî", "slug": "gulseni", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbrâhîm bin Muhammed Gülşenî, \ntanınan velîlerdendir. [830] da Azerbaycanda tevellüd, 940 [m. 1534] senesinde \nMısrda vefât etdi. Seyyid Yahyâ-yı Şirvânî halîfelerinden Ömer Rûşenîden feyz \naldı. Şâh İsmâ’îlin işkenceleri zemânında Mısra gitdi. (Ma’nevî) adındaki kırkbin \nbeytlik mesnevîsinin bir kısmını halîfelerinden Muhammed Fenâî efendi türkceye \nterceme etmişdir. Bu terceme ve sonunda Gülşenî hazretleri ile Gülşenî meşâyı-\nhinden Hasen Sezâî efendinin mektûbâtı ve hâl tercemelerini eklemişdir. 1289 [m. \n1871] da İstanbulda basılmışdır. Sezâî efendi, Edirnede Muhammed Sırrî efendi-\nden ve sonra Fenâî efendiden feyz alıp, 1151 [m. 1737] de vefât etmişdir. Torunları \nasrlarca Edirnede irşâdda bulundular.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Habîb-i Acemî", "slug": "habib-i-acemi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dâvüd-i Tâînin mürşidi \nve Hasen-i Basrînin halîfesidir. 120 [m. 739] senesinde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâcegî Muhammedimkenegî", "slug": "hacegi-muhammedimkenegi-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Hicretin dokuzyüzonsekiz [918] senesinde Buhârânın İmkene kasabasında tevellüd, binsekiz 1008 [m. 1600] de orada vefât etdi. Rûh ilmlerinin mütehassısı idi. Babası, Derviş Muhammed hazretlerinden feyz aldı. Çok Velî yetişdirdi.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâce-Zâde", "slug": "hace-zade", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muslih-uddîn Mustafâ bin \nYûsüf, Bursalıdır. Fâtih sultân Muhammed hânın hocası ve İstanbul kâdîsı oldu. \nFâtihin emri ile, Gazâlînin (Tehâfüt-ül-felâsife)si ile, İbnür-Rüşdün buna olan red-\ndiyyesini incelemiş, Gazâlînin haklı olduğunu bildiren kıymetli bir kitâb yazmışdır. \n893 [m. 1487] de vefât etdi. Bursada, Emîr Sultân kabristânındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâcı Bayram-ı Velî", "slug": "haci-bayram-i-veli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliyye-\ndendir. Ankarada Zülfadl [Sol-Fasol] köyünde tevellüd ve orada 833 [m. 1429] \nsenesinde vefât etdi. Kayseride Somuncu baba denilen Hamîdüddîn Hâmid-i \nAkserâyîden feyz aldı. Edirnede eski câmi’de va’z etdi. Ankaradadır.", "gectigiMaddeler": ["3/28", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâcı Bektâş-ı Velî", "slug": "haci-bektas-i-veli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Adı seyyid Muham-\nmed bin İbrâhîm Atadır. Hicrî [680] senesinde Horâsânın Nîşâpûrşehrinde tevel-\nlüd etdi. 738 [m. 1338] de vefât etdiği (Kısas-ı Enbiyâ)da yazılıdır. Anadoluda Kır-\nşehrdedir. Şeyh Lokmân- ı Horâsânînin halîfesi idi. Bu da, şeyh Ahmed-i Yesevî-\nnin, bu da, Yûsüf-i Hemedânînin halîfesi idi. Hâcı Bektâş-ı Velî hazretleri, sultân \nOrhân ile sohbet etdi. Yeni-çeri askeri kurulurken düâ etdi. Bundan feyz alanlara \nBektâşî denildi. Bu temiz, iyi bektâşîler, zemânla azaldı. Hurûfî denilen zındıklar, \nbu mubârek ismi kendilerine mal edindi.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hadîce Sultân", "slug": "hadice-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Dördüncü Muhammed \nhânın kerîmesidir. Binyüzellibirde [1151] Defterdâr ile Ayvânserây arasında (Sul-\ntân câmi’i) ni yapdırdı. Buna (Yâ-Vedûd câmi’i)  de denir. Çünki, öncedenşeyh \nAbdül-Vedûd yapdırmışdı. Kendisi, Buhârâdan, İstanbulu almak için gelenlerden-\ndir. 860 [m. 1456] senesinde vefât edip, orada defn olundu. Sonra, halîfelerinden \nTokmak dede, vakfını ta’yîn etdi. Bu da orada medfûndur. Bunun için oradaki kab-\nristâna (Tokmaktepe) denir. Hadîce sultân, buradaki sâhil serâyları yerine çeşme, \nsebil ve mekteb ve mektebin altında Muhammed Ensârînin “radıyallahü anh” tür-\nbesini yapdırırken, bu mescidi yeniden yapdırmışdır. Rumeli-kavağı câmi’ini de \nHadîce Turhân sultân yapdırmışdır. 1156 [m. 1743] da vefât etdi. Turhân sultân tür-\nbesindedir. Zevci Hasen pâşa, Üsküdârda (Nesûhî tekkesi mescidi) ni yapdırmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hadîce-Tül-Kübrâ", "slug": "hadice-tul-kubra", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Huveylid bin Esed bin \nAbdil-Uzza bin Kusayy kızıdır. Resûlullahın ilk zevcesidir. Çok zengin ve âlim ve \nâkıl idi. Bütün malını Resûlullaha bağışladı. Yirmibeş sene çok iyi hizmet etdi. \nHicretden üç yıl önce, altmışbeş yaşında Mekkede vefât etdi. İlk îmâna gelen hür \nkadındır. Resûlullahın bütün kızlarının ve iki oğlunun annesidir. 379, 380, 388, 574, \n– 1103 –", "gectigiMaddeler": ["2/39", "3/50"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâdimî", "slug": "hadimi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Mustafâ, Konya-\nnın Hâdim kasabasında tevellüd, 1176 [m. 1762] da, orada vefât etdi.", "gectigiMaddeler": ["1/71", "2/43", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hafîdzâde Sâdık", "slug": "hafidzade-sadik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzyetmişüçün-\ncü [673] sırada Muhammed Sâdık ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâfız-Işîrâzî", "slug": "hafiz-isirazi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemseddîn Muhammed \nbin Kemâleddîn, [720] de Şîrâzda tevellüd, 791 [m. 1389] de orada vefât etdi. \nBüyük islâmşâ’iridir. Nakşibendî idi. Tîmûr hân ile görüşdü. Dîvânı fârisîden garb \ndillerine terceme edildi.", "gectigiMaddeler": ["3/51"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâfız Es'ad", "slug": "hafiz-esad", "unvan": "", "kategori": "diger", "biyografi": "Kanlı bir ihtilâl ile Sûriye devlet reîsi oldu. Şî’îlerin en \nkötüsü olan Nusayrî fırkasındandır. Çok zâlim idi. Yalnız Hamâşehrinde binlerce \nEhl-i sünnet müslimânı öldürdü. 1421 [m.2000] de öldü.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hafsa", "slug": "hafsa", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Hazret-i Ömerin kerîmesi idi. Zevci ile Habe-\nşistâna ve Medîneye hicret etmişdi. İlk zevci Huneys bin Huzâfe Bedrde bulundu. \nSonra vefât etdi. Hicretden iki buçuk sene sonra Resûlullaha zevce olmaklaşeref-\nlendi. Kırkbeş 45 [m. 665] senesinde altmış yaşında iken vefât etdi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hahn", "slug": "hahn", "unvan": "", "kategori": "diger", "biyografi": "Atom çekirdek enerjisini ve bombasını bulanlardandır. Alman kimyâgeridir. 1296 [m. 1879] da Frankfurtda tevellüd etdi. Nobel mükâfâtı aldı.", "gectigiMaddeler": ["2/33"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâkim-Bi-Emrillah", "slug": "hakim-bi-emrillah", "unvan": "", "kategori": "diger", "biyografi": "Altıncı Fâtımî hükümdârıdır. Babası Azîzdir. \n375 [m. 985] de tevellüd etdi. Onbir yaşında tahta çıkdı. 411 [m. 1020] senesinde \nöldürüldü. Dırâra aldanarak, dînini sapıtdı. Tanrılık da’vâsına kalkışdı.", "gectigiMaddeler": ["2/21", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâkim Nîşâpûrî", "slug": "hakim-nisapuri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nAbdüllah hadîs âlimlerindendir. [321] de tevellüd ve 405 [m. 1014] senesinde Nîşâ-\npûrda vefât etdi. (Buhârî)de ve (Müslim)de bulunmıyan sahîh hadîsleri toplıyarak \nmeydâna getirdiği (Müstedrek) kitâbı çok kıymetlidir. Beyrutda (Mekteb-üt-ticâ-\nrî)de satılmakdadır.", "gectigiMaddeler": ["1/58", "1/60", "2/17", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâkim-i Şehîd", "slug": "hakim-i-sehid", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Muham-\nmed bin Ahmed, fıkh âlimidir. 334 [m. 946] senesindeşehîd edildi. (Gurer), (Kâfî) \nve (Müntekâ) kitâbları meşhûrdur.", "gectigiMaddeler": ["1/73"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hakîm-i Tirmizî", "slug": "hakim-i-tirmizi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah Muham-\nmed bin Alî, hadîs imâmlarındandır. 320 [m. 932] senesindeşehîd edildi. Çok kitâb \nyazdı. (Nevâdir-ül-üsûl) kitâbı çok kıymetlidir.", "gectigiMaddeler": ["2/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Halebîibrâhîm", "slug": "halebiibrahim", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbrâhîm bin Muham-\nmed, fıkh âlimidir. [866] da Halebde tevellüd ve 956 [m. 1549] da vefât etdi. İstan-\nbulda Fâtih câmi’inin imâmı idi. Edirnekapı kabristânından, Buğaz köprüsü yolu \nyapılırken, yanındaki Sakızağacı kabristânına nakl edilmişdir. (Mültekâ) kitâbı \nfransızcaya terceme edilmişdir. (Halebî) kitâbı meşhûrdur. Ayasofya ders-i-âmla-\nrından ve nakşî meşâyıhından Alî Yektâ efendi, buna hâşiye yapmışdır. Siyer \nsâhibleri Nûreddîn Alî Halebî Hanefî 1044 [m. 1633] de ve Burhâneddîn Alî Hale-\nbîş\nâfi’î 1014 [m. 1604] de vefât etmişlerdir.", "gectigiMaddeler": ["1/73", "1/74", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Halebî Muhammed", "slug": "halebi-muhammed", "unvan": "", "kategori": "diger", "biyografi": "439.cu sırada, İbni Emîr ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâlid bin Velîd", "slug": "halid-bin-velid", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Velîd bin Mugîre bin Abdüllah \nbin Amr bin Mahzûm oğludur. Ebû Cehl bin Hişâm ile ve Velîd bin Abd-i Şems \nile kardeş çocuklarıdır. Velîd bin Velîdin kardeşidir. Kardeşi Velîd, Bedrde esîr \nolup fidye ile kurtulunca, Mekkeye gitdikden sonra îmâna gelmiş, Medîneye hicret \netmişdi. Hâlid, Mekkenin fethinden evvel kardeşi Velîdin tavsıyesi ile, Amr ibni \nÂs ile berâber Medîneye gelip îmân etdiler. Uhudda ve Hudeybiyyede düşman \nordusunda idi. Mekkenin fethinde Resûlullahın yanında idi. Mûte gazâsında üçbin \n– 1104 –\nkişi ile yüzbin rûma gâlib geldi ve (Seyf-ullah) ismi ileşereflendi. Yemâme cengin-\nde ve Îrân, Rûm gazâlarında hep zafer kazandı. Hicretin yirmibirinde [21] Humsda \nvefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâlid Karsıalan", "slug": "halid-karsialan", "unvan": "", "kategori": "diger", "biyografi": "Hâlid pâşa, Kars fâtihidir. Meclis kürsîsinde \nkonuşma yaparken, vurularakşehîd edildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâlid-i Bağdâdî", "slug": "halid-i-bagdadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliyyenin \nbüyüklerindendir. İslâm bilgilerinin mütehassıslarındandır. Hayâtı, (Mecd-i tâlid) ve \n(Şems-üş-şümûs)da ve hesâb, hendese ve heyet ilmlerinde ve (Rub- ı-dâire) üzerinde \nmâhir olduğu (El-Hadâik-ul-verdiyye)de yazılıdır. Yüzlerce büyük âlim yetişdirdi. \nBağdâdınşimâlinde Zûrşehrinde 1192 de tevellüd ve Şâmda 1242 [m. 1826] de vefât \netdi. Cenâze nemâzını allâme İbni Âbidîn kıldırdı. Ehl-i sünnet düşmanları, bu \nbüyük âlime kürd asllı diyor. Bu sözleri, temâmen yanlış ve iftirâdır. Üçüncü halîfe \nOsmân “radıyallahü anh” soyundan olduğu vesîkalarla sâbitdir. 1224 [m. 1809] de \nBağdâddan hareket ederek, bir senede Dehlîye geldi. Abdüllah- ı Dehlevîden dokuz \nay feyz aldı, 1226 da Bağdâda avdet etdi. (İkdül-cevherî) kitâbında irâde-i cüz’iyyeyi \nuzun yazmakdadır. (İ’tikâdnâme) kitâbı, fârisî olarak, hadîs-i Cibrîlinşerhidir. Arabî \ntercemesi, (El-îmân vel-islâm) ismi ile 1981 de İstanbulda basılmışdır. Türkçe terce-\nmesi ve arabî (Câliyet-ül-ekdâr) düâ kitâbı Hakîkat Kitâbevi tarafından basdırılmış-\ndır. Fârisî dîvânı çok kıymetlidir.", "gectigiMaddeler": ["1/60", "2/17", "2/23", "2/35", "2/43", "2/49", "3/28", "3/37", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Halîl (şeyh)", "slug": "halil-seyh", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mâlikî fıkh âlimlerindendir. \nBabası İshakdır. 767 de vefât etdi. (Muhtasar)ı meşhûrdur.", "gectigiMaddeler": ["2/17", "2/43", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Halîl bin Osmân", "slug": "halil-bin-osman", "unvan": "", "kategori": "diger", "biyografi": "Kârî’lerdendir. 811 [m. 1408] de vefât etdi.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Halîmî", "slug": "halimi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hüseyn bin Hasen bin Muhammed \nbin Halîm Cürcânî, Şâfi’î fıkh ve hadîs âlimidir. 338 de tevellüd ve 403 [m. 1012] \nde vefât etdi. (Minhâc-üd-dîn) kitâbı meşhûrdur.", "gectigiMaddeler": ["1/68", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hallâc-ı Mensûr", "slug": "hallac-i-mensur", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliyyeden-\ndir. Tarîkat serhoşluğunda gördüklerini, islâmiyyete uymıyan kelimelerle söyledi-\nğinden 306 [m. 919] da Bağdâddaşehîd edildi. Alî Râmitenî hazretleri buyurdu ki, \n(Hüseyn Mensûr zemânında, hâce Abdülhâlık-ı Goncdüvânînin oğullarından biri \nbulunsaydı, Mensûr i’dâm edilmezdi.) Hâcenin ma’nevî oğullarından biri bulun-\nsaydı, Hüseyn Mensûru terbiye ederek, o makâmdan geçirirdi.", "gectigiMaddeler": ["1/41", "2/21", "2/71", "3/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Halvânî", "slug": "halvani", "unvan": "", "kategori": "diger", "biyografi": "Dörtyüzonbeşinci [415] sırada, Hulvânî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâmân", "slug": "haman", "unvan": "", "kategori": "diger", "biyografi": "Fir’avnın vezîri idi. Îmâna gelmesine mâni’ oldu. Âsiyeninşehîd edilmesine sebeb oldu. Mûsâ aleyhisselâmın da öldürülmesini istedi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamdan Kurmut", "slug": "hamdan-kurmut", "unvan": "", "kategori": "diger", "biyografi": "Karmat da denir. Gözleri kırmızı demekdir. \nİsmâ’îlî mezhebinde iken, mürîdleri çoğalınca (Kurmutî) tarîkatını kurdu. Kûfeşehrinde tüccâr idi. (Dâr-ül-hicre) adında bir tekke yapdı. 277 [m. 890] senesinde \nöldü. (Karamıta) devletini kurdu. Müslimânlara çok zulm yapdılar.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamdi Akseki", "slug": "hamdi-akseki", "unvan": "", "kategori": "diger", "biyografi": "Diyânet işleri reîsi idi. Mezhebsiz Reşîd Rızânın \n(Muhâverât) kitâbını türkçeye terceme ederek (Mezheblerin telfîkı) ismini ver-\nmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamevî Ahmed ve Hamevî Sa'deddîn", "slug": "hamevi-ahmed-ve-hamevi-sadeddin", "unvan": "", "kategori": "diger", "biyografi": "HAMEVÎ AHMED ve HAMEVÎ SA’DEDDÎN: [83] numarada, \nAhmed-i Hamevî ve [784] de Sa’düddîn Hamevî ismlerine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamîdullah", "slug": "hamidullah", "unvan": "", "kategori": "diger", "biyografi": "1326 [m. 1908] senesinde Hindistânın güneyinde Hay-\ndarâbâtda tevellüd etdi. [m. 1971] de İstanbulda kendisi ile konuşuldu. İslâm âlim-\nlerine, Selef-i sâlihîne güvenmediğini, Haydarâbâtdaki hocasının sözlerine uymı-\nyan bilgilere inanmadığını söyledi. Orada Osmâniye üniversitesinde okudu. Dev-\nletler hukûku üzerinde doktora yapdı. [m. 1947] de Hindistân hükûmeti kendisini \nvatandaşlıkdan çıkardı. Pârisde CNRS ilmî araşdırma a’zâsı idi. İsmâ’îlî mezhe -\n– 1105 –                                  Se’âdet-i Ebediyye 3-F:70\nbinde, koyu Ehl-i sünnet düşmanı olarak yetişdi. Açıkca ve sinsice, islâmiyyeti \nbozmağa, Ehl-i sünnet âlimlerini lekelemeğe çalışdı. (İslâma Giriş) ve (İslâm Pey-\ngamberi) kitâblarında, bozuk düşüncelerini açığa vurmakdadır. Sebe’ sûresinin \nyirmisekizinci [28] âyetinin meâl-işerîfi, (Seni bütün insanlara Peygamber gönder-\ndim)dir. O ise, kitâbına, yalnız müslimânların Peygamberi olduğunu anlatan ism \ntakmışdır. Kâfirlerin çoğunun inançları böyledir. (Fâideli Bilgiler)  kitâbımızın \nsonundaki 63.cü maddede, bozuk yazılarına cevâblar verilerek, azgın bir islâm düş-\nmanı olduğu, isbât edilmişdir. 1424 [m. 2003] de öldü.", "gectigiMaddeler": ["1/78", "2/4", "2/17", "2/34", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hammâd", "slug": "hammad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû İsmâ’îl bin Ebî Süleymân \nMüslim, İmâm-ı a’zamın hocasıdır. İbrâhîm-i Neha’înin ve Enes bin Mâlikin tale-\nbeleridir. 120 [m. 738] senesinde vefât etdi.", "gectigiMaddeler": ["1/73", "2/16", "3/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamza", "slug": "hamza", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın amcasıdır. Hicretden yedi yıl \nönce îmâna geldi. Bedr gazâsında çok kahramânlık gösterdi. Uhud gazâsında Vahşî \ntarafındanşehîd edildi. Uhud gazâsındaşehîd olanların ismleri (Mir’ât-i Medîne)de \nyazılıdır. (Vahşîye niçin bed düâ etmiyorsunuz) dediklerinde, (Mi’râc gecesi, Hamza \nile Vahşîyi kolkola Cennete giderken gördüm) buyuruldu. Uhud gazâsı, hicretin \nüçüncü senesi Şevvâl ayında oldu. Kâfir ordusu üçbin [3000] kişi olup, yediyüzü zırh-\nlı ve ikiyüzü atlı idi. Onbeş de kadın olup def çalar, şarkı söylerlerdi. Düşmandan \notuza yakın kişi öldürüldü. İslâm askeri yediyüz [700] olup, yüzü zırhlı idi. İki at \nvardı. Eshâb-ı kirâmdan yetmiş kişişehîd oldu. Altısı Muhâcirlerden, kalanı Ensâr-\ndan idi. Uhud gazâsından dört ay sonra, Necd halkına da’vet için, yetmiş genc gön-\nderildi. (Bi’ri Me’ûne) denilen yerde, hücûm edip, hepsinişehîd etdiler. Yalnız, iki \nsahâbî kurtuldu.", "gectigiMaddeler": ["3/59", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamza bin Ahmed", "slug": "hamza-bin-ahmed", "unvan": "", "kategori": "diger", "biyografi": "Derezîlerin bozuk inanışlarını yayan, Mısrlı bir \nsapıkdır. Fâtımî hükmdârı olan Hâkim-bi-emrillah da, bunun yalanlarına aldana-\nrak, yoldan çıkdı.", "gectigiMaddeler": ["2/21", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hamza Efendi", "slug": "hamza-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "(Bey’ veşirâ risâlesi) çok \nistifâdelidir. Bu kitâbı İsmâ’îl bin Osmânşerh etmiş, 1306 [m. 1890] da İstanbulda \nbasılmışdır.", "gectigiMaddeler": ["2/44", "3/4", "3/6", "3/16", "3/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hân I Hânân", "slug": "han-i-hanan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mirzâ Azîz Abdürrahîm, \nEkberşâhın ve Selîmşâhın devlet adamlarındandır. Şâ’ir idi. Gücerat vâlîsi iken \n1036 [m. 1627] da vefât etdi. Delhîdeki büyük türbesi harâbe hâlindedir. İmâm-ı \nRabbânî hazretlerini çok severdi. Hân- ı a’zam ise, 1033 de vefât etmişdir.", "gectigiMaddeler": ["1/31", "1/43", "2/57", "2/59", "2/62"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hârice Tebni-Zeyd", "slug": "harice-tebni-zeyd", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâbi’înden ve \nfukahâ-i seb’a [yedi büyük âlim]dan idi. Doksandokuz 99 [m. 717] senesinde Medî-\nnede vefât etdi. Babası Zeyd bin Sâbit, Sahâbenin büyüklerinden idi.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Harîrî", "slug": "hariri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Alî, Halvetî idi. Tütün \niçmenin harâm olmadığı\nnı bildirdi. 1048 [m. 1639] de vefât etdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâris", "slug": "haris", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Arabistânda Benî-Mustalak kabîlesinin reîsi \nidi. Hicretin beş veyâ altıncı yılında, islâmiyyeti kabûl etmediğinden harb edilerek \nesîr alındı. Mu’cize görünce müslimân oldu. Kızı Cüveyriyyeyi Resûlullaha nikâh \neyledi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hârûn", "slug": "harun", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Beni- İsrâîl Peygamberlerindendir. Mûsâ aley-\nhisselâmın büyük kardeşi idi. Mûsâ aleyhisselâmdan üç sene önce, yüzyirmiüç \nyaşında, yolda vefât etdi.", "gectigiMaddeler": ["2/20"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hârûnürreşîd", "slug": "harunurresid", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Mehdînin \noğlu, Ebû Ca’fer-i Mensûrun torunu idi. Beşinci Abbâsî halîfesi idi. [148] de tevel-\nlüd, 193 [m. 809] de Tus ya’nî Meşhedşehrinde vefât etdi. [170] de büyük kardeşi \nMûsâ Hâdînin yerine halîfe oldu. Orduları ile Üsküdâra kadar geldi. Fransa kra -\n– 1106 –\nlı birinci Şarl, ya’nî büyük Şarlmanla mektûblaşırdı. Ona bir dıvâr sâati hediyye \ngöndermişdi. Avrupalılar, sâatin kendi kendine işlediğini görünce, içindeşeytân \nvar diyecek kadar câhil idiler. Çalar sâat 516 [m. 1022] de yapıldı. Muhammed bin \nAlî ibni Sââtî, sâat i’mâlinde mâhir idi. Rakkaslı sâati, ilk olarak papa ikinci Sil-\nvestr Endülüs müslimânlarında görerek Avrupaya getirdi. 1003 [m. 1594] de öldü.", "gectigiMaddeler": ["1/59", "1/78", "2/17", "2/45", "3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen Advî", "slug": "hasen-advi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hasen bin Advî Hamzâvî \nMısrî, Mâlikî âlimlerindendir. 1220 [m. 1806] de Advede tevellüd, 1303 [m. 1885] \nde vefât etdi. Câmi’ul-ezherde yetişdi ve müderris oldu. Çok kitâb yazdı. (İrşâd-ül-\nmürîd fî-hulâsa-ti ilmi tevhîd) ve (En-nefehât-üş-şâziliyye fîşerh-ı Burde-til-\nBusayriyye) kitâbları çok kıymetlidir.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen bin Alî", "slug": "hasen-bin-ali", "unvan": "radıyallahü anhümâ", "kategori": "sahabi", "biyografi": "Resûlullahın kızı hazret-i Fâtı-\nmanın oğludur. Beyâz ve güzel yüzlü olup, yüzü Resûlullahın yüzüne çok benziyen \nyedi kişiden biri bu idi. Resûlullaha bundan dahâ çok benziyen kimse yokdu. Oniki \nimâmın ikincisi, islâm halîfelerinin beşincisidir. Hicretin üçüncü [3] senesi, Medîne-\nde tevellüd, [49] da Medînede vefât etdi. Babası hazret-i Alîşehîd olunca, kırk [40] \nsenesinde Kûfede halîfe seçildi. Kûfe, Basra, Irâk, Horâsân, Mekke, Medîne, Hicâz \nve Yemen ehâlisine, pederi gibi halîfe oldu. Diğer memleketler, hazret-i Mu’âviye-\nnin elinde idi. Yedi ay sonra, Bağdâd yanında Anbar denilen yerde, ikisinin ordusu \nharbe hâzır iken, müslimân kanı dökülmemesi için, hilâfeti hazret-i Mu’âviyeye \nbırakdı. Hazret-i Mu’âviye kendisine dörtyüzbin akça gümüş para hediyye gönderdi. \nSonra hazret-i Hasen Medîneye geldi. Ölünciye kadar orada yaşadı. Hazret-i \nMu’âviye, kendisinden sonra hazret-i Hasenin halîfe olmasına karâr verdi. Bu haber \nher tarafa yayıldı. Fekat, hazret-i Hasen, kadın yüzünden, zevcesi tarafından zehr-\nlendi. Soyundan olanlara (Şerîf) denir.", "gectigiMaddeler": ["1/31", "1/95", "2/5", "2/23", "2/24", "2/40", "2/41", "2/51", "2/61", "2/72", "3/16", "3/36", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen bin Alî Askerî", "slug": "hasen-bin-ali-askeri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Oniki imâmın \nonbirincisi, Alî Nakînin oğludur. [232] de Medînede tevellüd, 261 [m. 875] senesin-\nde Bağdâdda vefât etdi.", "gectigiMaddeler": ["1/31", "2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen bin Sabbâh", "slug": "hasen-bin-sabbah", "unvan": "", "kategori": "diger", "biyografi": "Yemen âmirlerinden Yûsüf-i Humeyrî neslin-\ndendir. Nizâm-ül-mülk ve Ömer Hayyâm ile birlikde, imâm- ı Muvaffak-ı Nîşâpû-\nrînin talebesi idiler. Alb Arslanın hâcibi oldu. [472] de Nizâm-ül-mülkle arası açı-\nlarak Mısra kaçdı. Şî’î olduğu için, Fâtımî hükümdârı Müstansırdan iltifât gördü. \nOrada İsmâ’îl bin Ca’fer Sâdık torunlarından birisi ile tanışıp, İsmâ’îliyye yolunu \ntutdu. Tevellüd yeri olan Reyşehrine geldi. Câhilleri aldatdı. Yol kesiciliğe, eşkı-\nyâlığa, meşhûr adamlara pusu kurup öldürmeğe başladı. [473] de Selçûkîlereısyân \nedip birkaç kal’a aldı. İsmâ’îliyye devletini kurdu. Afrikadaki ( İsmâ’îliyye) devle-\ntinden ayırmak için, buna ( Şarkî), doğu devleti denir. [654] senesine kadar sekiz \nhükümdâr geldi. Hasen, kırkbeş sene hükm sürüp, 518 [m. 1124] de vefât etdi. \nİsmâ’îlî fırkasını yaymak için çok zulm yapdılar. Ortalığı kana boyadılar. Ehl-i sün-\nnet âlimlerinişehîd etdiler. [498] de Hind, Türkistân ve Horâsân hâcılarının, Rey \nyakınında, yollarını kesip öldürdüler.", "gectigiMaddeler": ["2/21", "2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen bin Ziyâd", "slug": "hasen-bin-ziyad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanefî fıkh âlimlerin-\ndendir. 204 [m. 819] senesinde vefât etdi. İmâm-ı a’zam Ebû Hanîfenin talebesinin \nmeşhûrlarındandır. İbni Ziyâdşâfi’î Yemenî başkadır.", "gectigiMaddeler": ["1/50", "1/73", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen Hulûsî", "slug": "hasen-hulusi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Karadeniz sâhilindeki \nÇarşamba kasabası müftîsi idi. Türkçe (Mecma’ul-âdâb) kitâbı meşhûrdur.", "gectigiMaddeler": ["1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen-i Basrî", "slug": "hasen-i-basri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâbi’înin en büyüğüdür. \nBabası, Eshâb- ı kirâmdan Zeyd bin Sâbitin kölesi olan Ca’fer idi. Annesi de, \nÜmm-i Seleme “radıyallahü anhâ” vâlidemizin câriyesi idi. Hadîs ve fıkhda çok de -\nrin idi. [21] de tevellüd, yüzon 110 [m. 728] da vefât etdi. Basradadır. Alî “radıyal-\n– 1107 –\nlahü anh” ile sohbet etdiği (Fetâvâ-yı hadîsiyye)de uzun yazılıdır.", "gectigiMaddeler": ["1/43", "2/47", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hasen-i Berkî", "slug": "hasen-i-berki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindistânda Ahmed-i Ber-\nkînin talebesidir. İmâm-ı Rabbânînin bereket-i sohbeti ileşereflenmişdir. Öleceği \nzemân buyurdu ki, bana bağlı olanların afv olunacakları müjdesini aldım. Dahâ fazla \nistedim. Sana inananlar mağfûrdur denildi. Dahâ ziyâdesini istedim. Seni işitip de \nsevenler, kıyâmete kadar mağfûrdurlar buyuruldu. [Ya’nî kalbi yumuşıyarak tevbe \neder ve Cennete girmeğe sebeb olan sâlih amelleri yapması nasîb olur.]", "gectigiMaddeler": ["2/1"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hassâf", "slug": "hassaf", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr Ahmed bin Ömer, fıkh âli-\nmidir. (Edeb-ül-kâdî) kitâbı meşhûrdur. 261 [m. 874] de Bağdâdda vefât etdi.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâ Şim", "slug": "ha-sim", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın üçüncü babasıdır. İsmi Amrdır. Mekkede Tirid \nçorbasını ilk yapdığı için Hâşim denildi. Kureyşlilerin Şâmda ticâret yapmaları için \nKayserden izn aldı. Nevfelin, Muttalibin ve Benî-Ümeyyenin ceddi olan Abd-i \nŞemsin birâderidir. Abd-i Şems ile ikiz olarak tevellüd etmişlerdir. Abd-i Şemsin \noğlu Ümeyye, Kureyş kabîlesinin büyüklerinden idi. Resûlullahın ve amcalarının \noğullarına (Hâşimî) veyâ (Benî-Hâşim) denir.", "gectigiMaddeler": ["1/78", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâşim-i Keşmî", "slug": "hasim-i-kesmi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "660. cı sırada, Muhammed \nHâşime bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hatîb-i Bağdâdî", "slug": "hatib-i-bagdadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâfız Ahmed bin Alî, \nhadîs âlimlerindendir. Çok sayıda, kıymetli kitâb yazdı. Şâfi’î idi. 392 [m. 1002] de \nBağdâdda tevellüd, 463 [m. 1071] de orada vefât etdi. İmâm-ı a’zama ve imâm- ı \nAhmede dil uzatdı ise de, mağlûb edildi.", "gectigiMaddeler": ["1/98", "2/17", "2/18"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâtim-i Esâm", "slug": "hatim-i-esam", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İsmi Ebû Abdürrahmân \nbin Alvân olup, Sôfiyye-i aliyyedendir. Şakîk-i Belhînin eshâbındandır. Belhşeh-\nrinde tevellüd ve ikiyüzotuzyedi 237 [m. 852] de vefât etmişdir.", "gectigiMaddeler": ["3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hâtim-i Tâî", "slug": "hatim-i-tai", "unvan": "", "kategori": "diger", "biyografi": "Cömertliği ile meşhûr birşâ’irdir. Dîvânı ilk olarak 1289 \n[m. 1872] da Londrada, sonra 1315 [m. 1897] de almanca tercemesi ile basıldı. \nBi’setden önce ölmüşdür.", "gectigiMaddeler": ["2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hattât Hâfız Osmân", "slug": "hattat-hafiz-osman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hattâtşeyh \nHamdullahın talebesi olup, hocasını geçmişdir. Ayasofyada bulunan mushafından \nfoto-kopiler yapılarak çoğaltılmışdır. 1110 [m. 1699] da vefât etmişdir. Koca Mus-\ntafâ pâşa câmi’i bağçesindedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Havârîler", "slug": "havariler", "unvan": "", "kategori": "diger", "biyografi": "Îsâ aleyhisselâmın Eshâbı, ya’nî kendisini görüp de îmân \nedenler azdı. Kendisinden sonra Îsevîliği dünyâya yaymak için, Eshâbı arasından \nseçdiği oniki mü’mine (Havârî) denir. Fransızlar (Douze Apotres), Almanlar \n(Apostel), Müncid ise, (Resûller) diyor. Bunlar; 1- (Petrus) veyâ (Pierre) olup, asl \nismi Kâmûsda (Şem’ûn), Lexiconda (Simon), Müncidde ise (Sim’ân) olarak yazı-\nlıdır. Çok kimseleri îmâna getirdi. Antakyada büyük bir ma’bed yapdı. Kırkıncı \nsenede Romaya gitdi. Birkaç kerre Kudüse geldi. Altmışbeşde, Neron tarafından \nhaça gerilerek i’dâm edildi. Îsâ aleyhisselâm sanarak (Yehûdâ)yı da böyle çarmıha \ngermişlerdi. Papaların birincisi sayılmakdadır. Mezârı üzerine (Saint pierre) kilise-\nsi yapılmışdır. Hazîranın yirmidokuzunda yortusu yapılır. 2- (Andreas), Petrusun \nkardeşidir. (André) de denir. Xşeklindeki çarmıha gerilerek öldürüldü. İkinci teş-\nrînin [kasım] otuzunda yortusu yapılır. 3- (Yuhannâ) olup, (Yahyâ) demekdir. \nBuna (Johannes), (Jean) ve (Jani) de denir. Ortodokslar (Juvan), İngilizler \n(John), ermeniler de (Ohannes) derler. Yüz senesinde Efesde ölmüşdür. Onikinci \nayın yirmiyedisinde yortusu yapılır. 4- (Büyük Ya’kûb) dur. İngilizler (James), \nFransızlar (Jacque) diyor. Yuhannânın kardeşidir. Temmuzun yirmibeşinde yortu-\nsu yapılmakdadır. 5- (Filip), Anadoluda öldü. Mayısın birinci günü yortusu yapıl-\nmakdadır. 6- (Toma), yâhud (Thomas), Îrân ve Hind taraflarına gidip, oralardaşehîd edilmiş, Urfaya getirilmişdir. Son ayın yirmibirinde yortusu yapılır. Barna-\nbas İncîlinde bunun ismi yazılı değildir. 7- (Bartelemi) veyâ (Bartolome), 71 se -\n– 1108 –\nnesinde Erzurumdaşehîd edildi. Ağustosun yirmidördünde yortusunu yaparlar. 8- \n(Matthias) veyâ (Mathias) olup, mürted olan ve Îsâ aleyhisselâmın bulunduğu yeri \nyehûdîlere haber veren ve onunşekline çevrilerek çarmıha gerilen (Yudas İshar-\nyot) [Yehûdâ]nın yerine, havârîler tarafından havârî seçilmişdir. Habeşe ve Îrâna \ngitmiş, 61 de Îrândaşehîd edilmişdir. Şubâtın yirmidördünde yortusu yapılır. Îsâ \naleyhisselâmdan sekiz sene sonra, ondan işitdiklerini yazmış olan (Mettâ) [Matt-\nhaus=Mattieu] başka olup, havârîlerden değildir ve yortusu eylülün yirmibirinde-\ndir. 9- (Küçük Ya’kûb) veyâ (Jacque), altmışiki senesindeşehîd edildi. Mayısın ilk \ngünü yortusu yapılır. 10- (Simon) veyâ (Şem’ûn), hazret-i Meryemin hemşîresinin \noğlu olduğu ve yüzyedi senesindeşehîd edildiği (Kâmûs)da yazılıdır. (Müncid)de \nbuna (Sim’ân) denilmekdedir. Yirmisekiz ekimde yortusu yapılmakdadır. 11- \n(Yehûdâ) veyâ (Yudas), küçük Ya’kûbun kardeşidir. Yirmisekiz ekimde yortusu \nyapılmakdadır. 12- (Taddeus) [Thaddaus] un havârî olduğu Markusun İncîlinde \nyazılıdır. Lukanın İncîlinde, bunun yerine, (Judas Yakobi) yazılıdır. Mettânın İncî-\nlinde ise (Lebbaus) denildiğini Knaurs Lexikon bildiriyor. \nÎsâ aleyhisselâmdan gördüklerini ve işitdiklerini doğru olarak yazmış olan (Bar-\nnabas), kendisinin oniki Havârîden biri olduğunu bildiriyor. Hâlbuki hıristiyan \nkitâblarında bunun yerinde Thomas yazılıdır. Îsâ aleyhisselâmdan işitdik dedikleri-\nni yazmış olan (Marko) ve (Luka)nın Havârî olmadıkları ve (Yuhannâ)nın Havârî \nolduğu bellidir.", "gectigiMaddeler": ["1/24", "1/97", "2/17", "2/29", "2/67"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Havvâ", "slug": "havva", "unvan": "", "kategori": "diger", "biyografi": "Âdem aleyhisselâmın zevcesidir. Cenâb- ı Hak, Âdem aleyhis-\nselâmı toprakdan halk buyurdukdan sonra, sol kaburga kemiğinden hazret-i Hav-\nvâyı yaratdı. İkisini Cennete koydu. İblîs, Havvâyı aldatıp, yasak edilen meyveden \nyediler. Cennetden çıkarıldılar. İbni İshak, kırkbir erkek, kırk kızı oldu diyor. \nKitâbların çoğunda ise, yirmi def’a ikiz evlâdı, bir def’a da yalnız Şis “aleyhisse-\nlâm” olmuşdur denilmekdedir. Âdem aleyhisselâmdan sonra Ciddede vefât etdi.", "gectigiMaddeler": ["1/84", "1/97", "2/34", "2/39"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hayâlî", "slug": "hayali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Mûsâ, büyük âlimler-\ndendir. İzniklidir. Mısra gitdi. 870 [m. 1465] senesinde Bursada vefât etdi. (Şerh-i \nakâid hâşiyesi) çok kıymetlidir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hayâtî Halîl Efendi", "slug": "hayati-halil-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Elbüstânlı sey-\nyid Halîl bin Hayâtî, 1267 [m. 1851] de vefât etdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hayreddîn-i Remlî", "slug": "hayreddin-i-remli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Ahmeddir. \nHanefî mezhebinde büyük fıkh âlimidir. 993 [m. 1585] de Remlede tevellüd, 1081 \n[m. 1670] de orada vefât etdi. Fetvâları, İstanbulda Süleymâniyye kütübhânesi, \nYeni Câmi’ kısmında vardır. 1300 senesinde Mısrda Bulakda, gâyet nefîs basılmış, \n1974 de Beyrutda ofset baskısı yapılmışdır. (Levâih-ul-envâr) ismindeki (Minah-\nul-Gaffâr) hâşiyesi ve (Eşbâh) hâşiyesi çok kıymetlidir. (Dürr-ül-muhtâr) sâhibi \nAlâ-üddîn-i Haskefînin hocasıdır.", "gectigiMaddeler": ["1/98", "2/1", "2/38", "2/40", "3/12", "3/21", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Heisenberg", "slug": "heisenberg", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Atomun yapısı ile uğraşdı. \nMüslimân oldu. 1376 [m. 1956] da İstanbulda konferans verdi. 563. \n— Hempher: (İngiliz Câsûsunun İ’tirâfları) kitâbındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Herakliüs", "slug": "heraklius", "unvan": "", "kategori": "diger", "biyografi": "Rum imperatörü idi. Resûlullah ile mektûblaşırdı. Karşı-\nlıklı elçi ve hediyye gönderirlerdi. Îmâna gelmedi. 20 [m. 641] senesinde, otuzbir \nyıl hükm sürdükden sonra altmışaltı yaşında öldü.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Herder (von)", "slug": "herder-von", "unvan": "", "kategori": "diger", "biyografi": "HERDER (Von): Alman dinler târîhi profesörü idi. 1157 [m. 1744] de \ntevellüd, 1218 [m. 1803] de vefât etdi. Dünyâ çapında bir teolog idi. İnsanlık târî-\nhinin felsefesi üzerinde uğraşdı. Hıristiyanlığa karşı yapılan düşmanlığın, körü \nkörüne islâmiyyete de yapılmasının yanlış olacağı fikrini ortaya koydu.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Herem bin Hayyân", "slug": "herem-bin-hayyan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Veysel Karânîyi \ngördü. Ondan çok nasîhat aldı. 677. \n– 1109 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Herod (büyük)", "slug": "herod-buyuk", "unvan": "", "kategori": "diger", "biyografi": "HEROD (Büyük): Romalıların emrinde Filistin vâlisi idi. Yehûdî idi. Îsâ \naleyhisselâmı çocuk iken, öldürmek için emr verdi. Hazret-i Meryem bunu işitince, \noğlunu Mısra götürdü.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hind", "slug": "hind", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Mekke kâfirlerinden Utbe bin Rebî’a bin \nAbd-i Şems bin Abd-i Menâf kızı, Ebû Süfyânın zevcesi idi. Uhud gazâsında düş-\nmân askerlerine cesâret veriyordu. Hazret-i Hamzanınşehîd edilmesine sebeb \noldu. Mekke fethinde müslimân oldu. Kadınlar adına Resûlullah ile sözleşme \nyapdı. Hayrlı düâya mazhar oldu. 11 senesinde yapılan Yermük gazâsında, islâm \nordusunda bulunup, askeri harbe teşvîk etdi. Onüç [13] senesinde vefât etdi. Haz-\nret-i Mu’âviyenin annesidir.", "gectigiMaddeler": ["3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hitler", "slug": "hitler", "unvan": "", "kategori": "diger", "biyografi": "1307 [m. 1889] da tevellüd etdi. 1353 [m. 1934] de alman devlet \nbaşkanı oldu. Çok sayıda yehûdî öldürdü. 1358 [m. 1939] Eylül ayında ikinci dünyâ \nharbini açdı. İspanyadan başka bütün Avrupayı, Balkanları, Libyayı aldı. Mosko-\nvaya kadar yayıldı. Sonra mağlûb oldu. 1364 [m. 1945] de intihâr etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hızır", "slug": "hizir", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "İbrâhîm aleyhisselâmdan sonra yaşamış bir Nebî \nveyâ Velîdir. Zülkarneyn askerinin reîsi idi. Mûsâ aleyhisselâm ile yolculuk etdi. \nÜmmet-i Muhammedden değildir. Fekat rûhu, ba’zı Velîlere feyz vermişdir. \nÖldükden sonra, rûhu insanşeklinde görünüp garîblere yardım etmekdedir.", "gectigiMaddeler": ["2/20", "2/47", "2/54"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hûd", "slug": "hud", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Yemende bulunan Âd kavmine Peygamber idi. \nİnanmadılar. Rüzgâr ile helâk oldular. Hûd “aleyhisselâm”, îmân edenlerle Mek-\nkeye gelmişdi. Orada vefât etdi. İbni Âbidîn, ön sözünde diyor ki, (Şâmda Ümeyye \ncâmi’inin kıble dıvarının yeri, Hûd aleyhisselâmın makâmı idi. (Kurtubî \ntefsîri)nde, Câmi’-i Ümeyyeyi Velîd bin Abdülmelik yapdırmadan önce, burası \nzeytinlik idi. Vaktîle Hûd aleyhisselâmın bostanı idi yazılıdı\nr. Bu câmi’in dört dıva-\nrını ilk önce Hûd “aleyhisselâm”, bostan dıvarı olarak yapmışdır.)", "gectigiMaddeler": ["1/54", "2/20"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hugo De Vries", "slug": "hugo-de-vries", "unvan": "", "kategori": "diger", "biyografi": "Hollandalı nebâtâtcıdır. Mutasyon teorisini kurdu. \n1264 [m. 1848] de tevellüd, 1353 [m. 1934] de vefât etdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hülâgü Hân", "slug": "hulagu-han", "unvan": "", "kategori": "diger", "biyografi": "Cengizin torunudur. Onun gibi kâfir idi. Îrânda ilhânî \ndevletini kurdu. 656 [m. 1258] da Bağdâdı yakdı, yıkdı. Sekizyüzbin müslimân \nöldürdü. Buna karşılık, Hasen Sabbâhın kurmuş olduğu İsmâ’îliyye devletinin son \nreîsleri olan Rükneddîni öldürdü. Horâsân ve Azerbaycândaki İsmâ’îliyye eşkıyâ-\nlarını kılıncdan geçirdi. Yüzlerce kal’a ve sığnaklarını yıkdı. Müslimânları büyük \nbir felâketden kurtardı. Yalnız Süriyedeki kal’a ve tekkeleri kaldı. 663 [m. 1265] \nsenesinde Îrânda Merâgada öldü.", "gectigiMaddeler": ["1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hulvânîşems-Ül-Eimme", "slug": "hulvanisems-ul-eimme", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüz-\nyetmişbeşinci [875] sırada, Şems-ül-eimme-i Hulvanî ismine bakınız! Halvânî de \ndenir. Halvânî, tatlıcı demekdir.", "gectigiMaddeler": ["1/64", "1/65", "1/73", "1/78", "2/16", "3/12"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hümâyûnşâh", "slug": "humayunsah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindistândaki büyük \nislâm devletinin ikinci sultânıdır. 913 [m. 1508] de Kâbilde tevellüd edip, [937] de \ntahta çıkdı. [947] de hükûmetden ayrılıp, Îrâna ilticâ etdi. [962] de Efganlılarla \nharb edip, Delhîde tekrâr hükümdâr oldu. 963 [m. 1556] de vefât etdi. Delhîde tür-\nbesi, müze hâlindedir. Âlim ve âdil olup, islâmiyyete çok hizmet etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüsâmeddîn Ahmed", "slug": "husameddin-ahmed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdî Nizâmüd-\ndîn Bedahşînin oğludur. Hindistânda Hâce Bâkî-billahın eshâbındandır. İmâm-ı \nRabbânî hazretlerinin büyüklüğünü de herkesden iyi bilirdi. İmâm-ı Rabbânî \nvefât edince, Muhammed Hâşim-i Keşmîye yazdığı başsağlığında, (Allahü teâlâ, \no sûrî ve ma’nevî kemâllerin, fazîletlerin, toplandığı yer olan zâtı, dostların kalb-\nlerinin ve gözlerininışığı eylesin! O Evliyâların sığınağı\nnın ayrılık acısı hangi keli-\nme ile anlatılabilir ki, yalnız onu tanıyanlara değil, bütün müslimânlara yazık \noldu. Îmânı olan herkes, ciğerleri yakan bu olaydan ağlamalı, sızlamalıdır) demiş-\ndir. Her tanıdığını, imâm- ı Rabbânînin hizmetine, sohbetine, derslerine sarılma -\nğa teşvîk ederdi. Binkırküç 1043 [m. 1634] de vefât etdi. Kabri, Delhîde hâce Bâ -\n– 1110 –\nkî-billah türbesinin yanındadır.", "gectigiMaddeler": ["2/1", "3/44", "3/51", "3/53", "3/68"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüsâmeddîn Ömer", "slug": "husameddin-omer", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ömer bin \nAbdül’azîz, Hanefî fıkh âlimidir. [483] de tevellüd, 536 [m. 1142] da Semerkanddaşehîd oldu. Sadr-üş-şehîd de denir. Muhammed Şeybânînin kitâblarınışerh etdi. \n(Fetâvâ-i kübrâ)sı ve (Umdetül-müftî)si çok kıymetlidir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüsâmeddîn-i Râzî", "slug": "husameddin-i-razi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanefî fıkh âlimi-\ndir. Adı, Alî bin Ahmeddir. 598 [m. 1203] senesinde Şâmda vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüseyn", "slug": "huseyn", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın torunu, hazret-i Alînin ikinci \noğludur. Oniki imâmın üçüncüsü, Ehl-i beytin beşincisidir. Bunun soyundan olanla-\nra (Seyyid) denir. Hicretin altıncı [6] senesinde tevellüd, 61 [m. 680] senesinin \nMuharrem ayının onuncu günü Kerbelâdaşehîd oldu. Mubârek başı, Mısrda, Karâfe \nkabristânındadır. Resûlullahın torunu ve çok sevdiği olduğu için, Ehl-i sünnetin göz-\nbebeğidir. Şî’îler, kendisini, hazret-i Alînin oğlu olduğu için, aşırı seviyoruz diyerek, \nMuharremin onuncu günü mâtem tutuyorlar.", "gectigiMaddeler": ["1/31", "1/85", "1/95", "2/5", "2/24", "2/30", "2/51", "2/53", "2/61", "2/72", "3/16", "3/36"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüseyn bin Alî", "slug": "huseyn-bin-ali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şerîf Hüseyn, Mekke \nemîri idi. [1268] de tevellüd, 1349 [m. 1931] da vefât etdi. Birinci cihân harbinde, \ningilizler Arabistân çöllerinde yaşıyan câhilleri silâhlandırıp, Mekkeye saldırtdı. \nŞerîf Hüseyni, seni koruyacağız diye aldatıp, Kıbrısda bir otele habs etdi. Hicâz \n[m. 1924] de vehhâbîlerin eline geçince, Kıbrısdan çıkardı. Otel parasını da kendi-\nsinden aldılar.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüseyn Hilmi Işık", "slug": "huseyn-hilmi-isik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nâm- ı müsteârı (Sıd-\ndîk Gümüş)dür. Babası Sa’îd, dedesi Lofcanın Tepova köyünden İbrâhîm Pehlivân-\ndır. İkisi de Eyyûb Sultânda medfûndur. Balkan harbindeşehîd olduğu tepeye ismi \nverilen Bursalı Kâmil efendi ile hemşîresi Âişe hanımın anneleri Fâtıma hanım İbrâ-\nhîm Pehlivânın birâderinin kızıdır. Çeşidli din ve fen kitâblarının yazarıdır. Türkçe, \narabî, fârisî, fransızca, almanca ve ingilizce kitâbları neşr etmişdir. Kitâbları bütün \nmemleketlerde okunmakdadır. Teğmenlikden albaylığa kadar türk ordusunda zehr-\nli gazlar mütehassıslığı ve kimyâ öğretmenliği yapmış, çok subay yetişdirmişdir. \nİstanbul üniversitesinde çalışarak, (Phenyl-ciyan-nitrometan) cisminin sentezini \nyapmış ve formülünü bulmuşdur. Bunu bildiren raporunu Fen fakültesi 1937 de, \n(Fritz Arnd, Lotte Loewe, Hilmi Işık) ismleri ile Devlet matbaasında, ingilizce ola-\nrak, 2.ci cild numarası ile basdırmışdır. Ayrıca fen fakültesinin 1937 senesi ikinci \nkânûn târîhli (Fen fakültesi mecmu’asında) 139.cu sahîfesinde neşr edilmişdir. Bu \nbaşarılarından dolayı çok tebrîkler almışdır. Din bilgilerinde derin âlim ve tesavvuf \nma’rifetlerinde kâmil ve mükemmil olan, kerâmetler, hârikalar sâhibi seyyid Abdül-\nhakîm efendinin yetişdirdiği salâhiyyetli bir din adamıdır. 1929 dan 1362 [m. 1943] \nsenesine kadar o büyük zâtdan ders almış, arabî ve fârisî tercemeler yaparak gençli-\nğe hizmet için çalışmışdır. (Hakîkat Kitâbevi)nde, 1415 hicrî ve 1995 mîlâdî senesin-\nde, kendi hâzırladığı 60 arabî ve 25 fârisî ve 14 türkçe ve bunlardan terceme etdir-\ndiği, fransızca, ingilizce, almanca, rusca ve arnavudca ve diğer dillerdeki kitâbların \nmikdârı yüzden fazladı\nr. Vehhâbî, râfızî ve teblîg- ı cemâ’at denilen Ehl-i sünnet \ndüşmanlarını rezîl etmişdir. Hakîkat Kitâbevinin basdırdığı kitâblar, (İnternet) \nvâsıtası ile bütün dünyâya dağılmakdadır. (Çok kitâb okudum. Ehl-i sünnet âlimle-\nrinin yükseklikleri yanında, pek câhil, bir hiç olduğumu anladım. Onları tanıyabil-\nmek, yollarında bulunmak, büyük ni’metdir. Resûlullahın yolu, onların gösterdikle-\nri yoldur. Resûlullahın güzel ahlâkı, onların ahlâkıdır. Dünyâda ve âhıretde se’âde-\nte kavuşmak isteyen, o büyüklerin yoluna, sımsıkı sarılsın!) derdi. 1911 de, Eyyûb \nSultânda, (Vezîr tekkesi)nde tevellüd etdi. İlk tahsîlini Eyyûb sultân Reşâdiye \nnümûne mektebinde, lise tahsîlini Halıcıoğlu askerî lisesinde yapdı. 1960 da tekâ’üd \noldu. 2000 ve sonraki senelerde Boğaziçinde Sarıyerdeki yalısında, kitâblarına ilâ-\nveler yaparak ve tevbe ve istigfâr ile vaktlerini kıymetlendirdi. Talebelerinden \nbaşka hiç kimse ile görüşmezdi. Hüseyn Hilmi Işıkın “rahmetullahi aleyh” babası \n– 1111 –\nSa’îd efendi 1929 senesinde Eyyûb Sultânda vefât etmiş, Eyyûb Sultân kabristânın-\nda medfûndur. Annesi Âişe hanım, Mamakda vefât etmiş, Bağlumda medfûndur. \nBüyük birâderi Mustafâ efendi, astsubay mektebini bitirip, bu mektebde öğretmen \niken, Şifâ yokuşundaki babasının evinde hastalanarak vefât etmiş, Eyyûbde defn \nedilmişdir. Diğer birâderi İbrâhîm efendi, deniz astsubay mektebini bitirip, Alman-\nyada ihtisâs yapdıkdan sonra, Karaköyde polis me’mûru iken, bir kazâ kurşunuylaşehîd olmuş ve karakol civârındaki kabristâna defn edilmişdir. Küçük birâderi, \nMehmed Sedâd efendi, Türkiye gazetesinde yazar iken, 1997 de vefât etmiş, Kaşgârî \ndergâhı yanında medfûndur. Hemşîreleri Zehrâ, Fâika ve Nazîme hanımlar evlen-\nmemiş, Zehrâ ve Nazîme hanımlar İstanbulda vefât etmişler, Fâika hanım, Fâtihde-\nki evinde oturmakda iken, 1424 [m.2003]de vefât etmişdir. Mehmed Sedâd beğin \nhanımı Fâtıma hanım, Fâtihdeki evinde oturmakdadır. Hüseyn Hilmi Işıkın amcası \nHalîl efendi, Ca’fer ve Mustafâ efendiler vefât etmişlerdir. İki teyzesi, Cemîle ve \nFevziye hanımlardır. Fevziye hanımın oğlu Şemi’ beğ ve kızı Suhandan hanımdır. \nŞemi’ beğin üç kızı ile Suhandan hanım Fâtihde oturmakdadırlar. [Hüseyn Hilmi \nIşık “rahmetullahi aleyh” 26 Ekim 2001 [9 Şa’bân 1422]de vefât etmiş olup, Kaşgârî \ndergâhı yanında medfûndur. Kıymetli insan Abdülhakîm Işık, 25 Mart 2001 [30 Zil-\nhicce 1421]de vefât etmiş olup, kabri babasının yanındadır.]", "gectigiMaddeler": ["1/41", "1/89", "3/54"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüseyn-i Buhârî", "slug": "huseyn-i-buhari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Yahyâdır. 400 \n[m. 1010] senesinde vefât etdi.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Hüseyn Vâ'iz-ı Kâ Şifî", "slug": "huseyn-vaiz-i-ka-sifi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hüseyn bin Alî \nHirâtda vâ’ ız idi. 910 [m. 1505] da orada vefât etdi. Çok kitâb yazdı. Fârisî (Mevâ-\nhib-i aliyye) tefsîri meşhûrdur. [1246] da İsmâ’îl Ferrûh Kırîmî, türkceye çevirmiş, \n(Mevâkib) ismini vermişdir. Muhammed Bitlîsî [vefâtı 982] başka bir tercemesini \nyapmışdır. (Ahlâk-ı Muhsinî) kitâbı ingilizceye terceme edilmişdir.", "gectigiMaddeler": ["1/35", "1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Husrî", "slug": "husri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Alî bin İbrâhîm Husrî \nBasrada tevellüd etdi. Hanbelî idi. Bağdâdda büyük Velî Ebû Bekr Muhammed \nŞiblînin talebesinden idi. 371 [m. 981] de vefât etdi.", "gectigiMaddeler": ["1/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Huzeyfe-i Mer'aşî", "slug": "huzeyfe-i-merasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbrâhîm Edhemin \ntalebesindendir. 207 [m. 822] de vefât etdi. Mer’aş Şâmdadır. (Sohbet az da olsa, \nte’sîr eder) hadîsini okur. Dünyâ ehlinin sohbetinden kaçınırdı.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Huzeyfe-Tübni Yemân", "slug": "huzeyfe-tubni-yeman", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Babası Yemân ile \nberâber Medîneye gelip müslimân oldu. Uhud gazâsında bulundu. Münâfıkları \nyalnız bu bilirdi. Îrân fütûhâtında bulundu. Nusaybin vâlîsi oldu. Hazret-i Osmâ-\nnınşehâdetinden kırk gün sonra vefât etdi.", "gectigiMaddeler": ["2/5", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Abdilberr", "slug": "ibni-abdilberr", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâfız Cemâleddîn Ebû \nÖmer Yûsüf bin Abdüllah, Mâlikî fıkh ve hadîs âlimidir. 368 [m. 978] de Kurtuba-\nda tevellüd, 463 [m. 1071] de Şâtıbede vefât etdi. (El-isti’âb fî-ma’rife-til-eshâb)  \nkitâbı iki cild olup, Hindistânda basılmışdır. Berlinde el yazısı ile mevcûddür. 1328 \nde Mısrda basılan (El-isâbe fî-temyîz-is-sahâbe)  kitâbının kenârında da vardır. \nBeyrutda ofsetle yeniden basılmışdır.", "gectigiMaddeler": ["3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Âbidîn", "slug": "ibni-abidin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Muhammed Emîn bin \nÖmer bin Abdül’azîz fıkh âlimlerindendir. 1198 [m. 1784] de Şâmda tevellüd, 1252 \n[m. 1836] de orada vefât etdi. Mevlânâ Hâlid-i Bağdâdînin sohbeti ileşereflenerek \nkemâle geldi. O vilâyet güneşinin Şâmda cenâze nemâzını bu kıldırdı. Çok kitâb \nyazdı. (Dürr-ül-muhtâr) a yapdığı hâşiyesi beş cild olup, (Redd-ül-muhtâr)  adı ile, \nbirkaç def’a basılmışdır. Hanefîde en sağlam fıkh kitâbıdır. (Se’âdet-i ebediyye)  \nkitâbının her üç kısmındaki yüzotuz madde tutan fıkh bilgilerinin çoğu bu hâşiye-\nnin [1272] hicrî senesinde Mısrda, Bulak matba’asında basılan beş cildinden ter-\nceme edilmişdir. Fetvâları da basılmışdır. 9, 19, 20, 21, 34, 35, 52, 53, 72, 96, 97, \n113, 120, 125, 130, 132, 134, 142, 143, 144, 148, 151, 154, 157, 158, 159, 163, 167, \n– 1112 –", "gectigiMaddeler": ["1/60", "1/61", "1/63", "1/64", "1/65", "1/67", "1/68", "1/69", "1/70", "1/71", "1/73", "1/74", "1/75", "1/76", "1/78", "1/79", "1/80", "1/81", "1/82", "1/83", "1/84", "1/85", "1/90", "1/95", "1/97", "1/98", "2/4", "2/5", "2/15", "2/16", "2/17", "2/18", "2/21", "2/31", "2/34", "2/36", "2/37", "2/38", "2/39", "2/40", "2/41", "2/42", "2/43", "2/47", "2/52", "2/59", "2/67", "3/2", "3/3", "3/4", "3/6", "3/12", "3/14", "3/19", "3/20", "3/21", "3/23", "3/24", "3/26", "3/59", "3/63", "3/64"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Adî", "slug": "ibni-adi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Ahmed Abdüllah ibnül’adî, \nhadîs imâmlarındandır. [242] de Cürcânda tevellüd, 323 [m. 935] de Esterâbâdda \nvefât etdi. Hadîs-işerîf toplamak için, Irâk, Mısr, Şâm ve Hicâzı dolaşdı.", "gectigiMaddeler": ["1/31", "2/17", "2/18"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Asâkir", "slug": "ibni-asakir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Hasen fıkh ve hadîs \nâlimidir. 499 [m. 1105] da Şâmda tevellüd, 571 [m. 1176] de orada vefât etdi. Sek-\nsen cild (Şâm târîhi) yazmışdır.", "gectigiMaddeler": ["2/23", "2/67", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Battâl", "slug": "ibni-battal", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Halef, Kurtubada \nMâlikî âlimlerindendir. 449 [m. 1057] senesinde Valensiyada vefât etdi. (Buhârî)yişerh etmişdir.", "gectigiMaddeler": ["2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Cerîr", "slug": "ibni-cerir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüzdoksanbeşinci [895] \nsırada Taberî ismine bakınız!", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Cevzî", "slug": "ibni-cevzi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altmışaltıncı [66] sırada Ab -\ndürrahmân Cevzî kelimesine bakınız!", "gectigiMaddeler": ["1/63", "1/78", "2/16", "2/17", "2/21", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Cezerî", "slug": "ibni-cezeri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemseddîn Muhammed bin \nMuhammed bin Alî, Şâfi’î âlimlerindendir. 751 [m. 1350] de Şâmda tevellüd, 833 \n[m. 1429] de Şîrâzda vefât etdi. Yıldırımdan ve Tîmûr hândan çok iltifât gördü. \n(Hısn-ül-hasîn) düâ kitâbı, arabî ve fârisîşerhleri ile birlikde basılmışdır. Bunu \nokuyan hastanın iyi olacağı, (Hadarât-ül-kuds) 191. ci sahîfesinde yazılıdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Cüreyc", "slug": "ibni-cureyc", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdülmelik bin Abdül’azîz \nKureyşî ve Emevî, [80] senesinde tevellüd, 149 [m. 766] senesinde, Mekkede vefât \netdi. İslâmda, ilk kitâb yazan budur. (Tefsîr) ve (Sünen) kitâbı vardır.", "gectigiMaddeler": ["2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Ebiddünyâ", "slug": "ibni-ebiddunya", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr Abdüllah \nbin Muhammed, târîhcidir. Üçyüze yakın kitâb yazdı. 208 [m. 823] de tevellüd, 281 \n[m. 894] de Bağdâdda vefât etdi. Kureyşlidir. Şâfi’î idi.", "gectigiMaddeler": ["2/5", "2/44", "3/23", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Ebîşeybe", "slug": "ibni-ebiseybe", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr Abdüllah bin \nMuhammed, hâfız idi. Yüzbin hadîs-işerîfi râvîleri ile birlikde, ezber bilene \n(Hâfız) denir. 234 [m. 850] senesinde vefât etdi. (Müsned) kitâbı meşhûrdur.", "gectigiMaddeler": ["1/63", "1/98", "2/17", "2/18"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Emîr Hâc Halebî", "slug": "ibni-emir-hac-halebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nEmîr hâc Muhammed bin Muhammed Halebî, Hanefî âlimlerindendir. İbni \nHümâmın talebesidir. Kâdî idi. 879 [m. 1474] da vefât etdi. İbni Hümâmın (Tahrîr) \nadındaki fıkh kitâbını ve (Münyetül-musallî) fıkh kitâbını ve (Muhtâr) fıkh kitâbı-\nnışerh etmişdir. Birincisine (Takrîr), ikincisine (Hilye-tül-mücellî) adını vermiş-\ndir.", "gectigiMaddeler": ["1/54", "3/57"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Esîr", "slug": "ibni-esir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül-Hasen İzzeddîn Alî bin \nEbilkerem Cezrî 555 [m. 1160] de Cezîre-i İbni Ömerde tevellüd, 630 [m. 1232] da \nMûsulda vefât etdi. Hadîs âlimi ve târîhci idi. (Kâmil) adındaki târîhi 1282 [m. \n1866] de Felemenkde Leidenşehrinde ve Beyrutda basıldı. (Üsüd-ül-gâbe) kitâbı, \nbeş cild olup, yedibinbeşyüz Sahâbînin hâl tercemesini bildirmekdedir.", "gectigiMaddeler": ["2/48", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hacer-i Askalânî", "slug": "ibni-hacer-i-askalani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şihâbüddîn \nAhmed bin Alî, hadîs imâmı ve Şâfi’î fıkh âlimidir. 773 [m. 1371] de Mısrda tevel-\nlüd, 852 [m. 1448] de orada vefât etdi. Yüzelliden çok kitâbı vardır. (El-isâbe fî-\ntemyîzissahâbe) kitâbı İbni Esîrin (Üsüd-ül-gâbe) kitâbından dahâ mükemmeldir. \nDört cilddir. [1280] de Hindistânda ve [1328] de Mısrda ve Beyrutda basılmışdır. \n– 1113 –\n(Buluğ-ul-merâm) kitâbının ve bunun (Sübül-ü-selâm) adındaki arabîşerhınin \n1379 [m. 1960] senesinde Beyrutda ofsetle dördüncü baskısı yapılmışdır. Beyrutda \n(Mekteb-üt-ticârî)de satılmakdadır.", "gectigiMaddeler": ["2/16", "2/17", "2/22", "2/44", "2/71"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hacer-i Mekkî", "slug": "ibni-hacer-i-mekki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şihâbüddîn Ahmed \nbin Muhammed Hiytemî, Mekke-i mükerremenin büyük âlimi ve Şâfi’î fükahâsın-\ndan idi. 899 [m. 1494] da tevellüd, 974 [m. 1566] de Mekkede vefât etdi. Fetvâları ve \n(Savâ’ık) kitâbı ve (Minhâc) şerhı olan (Tuhfe)si ve (Zevâcir)i ve (Kalâid-ül-ukbân) \nkitâbı çok kıymetlidir. (Savâ’ık-ul muhrıka)sı, Mısrda ikinci def’a olarak, 1385 [m. \n1965] de basılmışdır. (Hayrât-ül-Hisân) kitâbı 1304 de Mısrda ve Urdu tercemesi \nPâkistânda ve Hakîkat Kitâbevi tarafından İstanbulda, (El-i’lâm bi-kavâti’il-islâm) ı, \n(Zevâcir)inin ve (Sebîl-ün-necât)ın sonlarında basdırılmışdır.", "gectigiMaddeler": ["1/25", "1/31", "1/59", "1/68", "1/69", "1/74", "1/78", "1/97", "2/5", "2/16", "2/17", "2/18", "2/21", "2/52", "2/53", "3/2", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Haldun", "slug": "ibni-haldun", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrahmân bin Muham-\nmed büyük islâm târîhcisidir. 732 [m. 1332] de Tûnusda tevellüd, 808 [m. 1406] de \nvefât etdi. Târîhi yedi büyük cilddir. Türkçeye ve Avrupa lisânlarına terceme edil-\nmişdir.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hanefiyye", "slug": "ibni-hanefiyye", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Hane-\nfiyye, hazret-i Alînin oğludur. Annesi Havle binti Ca’fer bin Kays-il-Hanefiyye \nolduğu için, İbni Hanefiyye denilir. Hicretin yirmibirinde [21] tevellüd, 71 [m. 690] \nsenesinde de, Medînede vefât etdi. Verâ’ ve takvâsı çokdu. Çok cesûr idi.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hazm", "slug": "ibni-hazm", "unvan": "", "kategori": "diger", "biyografi": "Ebû Muhammed Alî bin Ahmed, Endülüs felsefeci ve \nâlimlerindendir. Vezîr [bakan] idi. 384 [m. 994] de Kurtubada tevellüd, 456 [m. \n1064] da vefât etdi. Çok kitâb yazdı. Selef-i sâlihîni beğenmeyip, doğru yoldan çık-\ndığı, (Keşf-üz-zünûn)da, (Milel-nihal) kelimesinde yazılıdır. (Zâhiriyye) mezhe-\nbinde olduğu, Dâvüd-i Bağdâdînin (Eşeddül-cihâd) kitâbı sonunda yazılıdır. Bu \nmezhebin kurucusu Dâvüd bin Alî İsfehânî olup, 202 [m. 817] de Kûfede tevellüd, \n270 [m. 883] de Bağdâdda vefât etmişdir. Şâfi’î idi. Fekat taklîde ve kıyâsa karşı \nidi. Mezhebi tutunamamış\n, kalmamışdır.", "gectigiMaddeler": ["1/74", "2/17", "2/29", "2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hibbân", "slug": "ibni-hibban", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Hâtim Muhammed bin \nAhmed Temîmî, hadîs imâmı ve Şâfi’îdir. Semerkand kâdîsı idi. Sicstânda Bust kasa-\nbasında tevellüd ve 354 [m. 966] de Semerkandda vefât etdi.", "gectigiMaddeler": ["1/97", "1/98", "2/17", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hişâm", "slug": "ibni-hisam", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Muhammed Abdülmelik \nbin Hişâm-i Humeyrî, Basrada tevellüd, 218 [m. 833] senesinde Mısrda, Füstatşeh-\nrinde vefât etdi. Resûlullahın hayâtını anlatan (İbni İshak sîreti) ninşerhı olan \n(Sîret-i İbni Hişâm) kitâbı çok kıymetlidir. (Sîret-i İbni Hişâm) târîhini çok kimse-\nlerşerh etmişdir. Buşerhler arasında Süheylînin (Ravd-ül-enf)i ve (Aynîşerhı) \nmeşhûrdur.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Hümâm", "slug": "ibni-humam", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kemâleddîn Muhammed bin \nAbdülvâhid Sîvâsî, Hanefî fıkh âlimlerindendir. 790 [m. 1388] da tevellüd, 861 [m. \n1456] de vefât etdi. (Hidâye) şerhı olan (Feth-ul kadîr)  kitâbı ve (Tahrîr) kitâbı \nçok kıymetlidir. [988] de vefât eden onaltıncışeyh-ul-islâm Kâdî zâde Şemsüddîn \nAhmed efendi (Feth-ul-Kadîr)e hâşiye yapmışdır. Sekiz cild olup Mısrda basılmış-\ndır. 1006 [m. 1597] da vefât eden, halvetî meşâyıhinden Ahmed Şemsüddîn bin \nMuhammed Sîvâsî başka olup, (İrşâd-ül-avâm) ve (Mevlid-ün Nebî) kitâbları meş-\nhûrdur.", "gectigiMaddeler": ["1/50", "1/54", "1/73", "1/74", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni İshak", "slug": "ibni-ishak", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin İshak, ilk is -\nlâm târîhcisidir. 151 [m. 768] senesinde Bağdâdda vefât etdi. (Sîret-i Resûl) kitâ-\nbını İbni Hişâmşerh ederek (Tezhîb-i siyer-i İbni İshak) demiş, alman Westen -\nfeld basdırmışdır. (Sîret-i Resûl) târîhini çok kimselerşerh etmişdir. Bunlar ara-\nsında (Aynî) ve (Süheylî) meşhûrdur. Süheylîşerhine (Ravd-ül-enf) denir. Ab -\ndürrahmân bin Abdüllah-i Süheylî 508 de Endülüsde tevellüd ve beşyüzseksen-\n– 1114 –\nbir 581 [m. 1186] senesinde Merrâküşde vefât etmişdir. Başka kitâbları da vardır. \nHadîs âlimi İbni İshak başkadır.", "gectigiMaddeler": ["1/79", "1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni İshak-ı Kindî", "slug": "ibni-ishak-i-kindi", "unvan": "", "kategori": "diger", "biyografi": "Ebû Yûsüf Ya’kûb bin İshak-ı Kindî, meşhûr fel-\nsefecidir. Tıb ve matematikde yüzlerce kitâb yazdı. 260 [m. 873] de vefât etdi. \nBabası, Mehdî ve Hârûn-ür-Reşîd zemânlarında Kûfe emîri idi. Büyük dedesi \nEş’as bin Kays Sahâbedendir.", "gectigiMaddeler": ["1/89", "2/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Kayyım-i Cevziyye", "slug": "ibni-kayyim-i-cevziyye", "unvan": "", "kategori": "diger", "biyografi": "Ebû Abdüllah Muhammed bin Ebû \nBekr Zer’î, Şâmda ibni Teymiyyenin yetişdirdiği, Hanbelî âlimlerindendir. 691 [m. \n1292] de tevellüd, 751 [m. 1350] de vefât etdi. Hocasının bozuk fikrlerine kapılmış-\ndır. Çok sayıda kıymetli kitâbları da vardır. Tesavvuf büyüklerinin keşflerini, aklı \nile çözmeğe kalkmış, (Hed-yün-Nebevî) ismi ile meşhûr olan (Zâd-ül-me’âd) kitâ-\nbında Ehl-i sünnetden ayrılmışdır. Kâfirlere Cehennemde azâb sonsuz değildir, \nderdi.", "gectigiMaddeler": ["1/84", "2/17", "2/21", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Kesîr", "slug": "ibni-kesir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İsmâ’îl bin Ömer, Şâfi’î hadîs \nâlimidir. 774 [m. 1372] de Şâmda vefât etdi. On cild tefsîrini hadîs-işerîflerle açık-\nlamış ve kendi görüşlerini de karışdırmış olduğu (Keşf-üz-zunûn)da yazılıdır.", "gectigiMaddeler": ["3/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Mâce", "slug": "ibni-mace", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah Muhammed bin \nYezîd, hadîs âlimlerindendir. (Sünen) kitâbı çok kıymetlidir. 209 [m. 824] da Kaz-\nvinde tevellüd, 273 [m. 886] de vefât etdi.", "gectigiMaddeler": ["2/6", "2/17", "2/44", "3/1", "3/2", "3/58", "3/64"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Melek (veyâ Melik)", "slug": "ibni-melek-veya-melik-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Adı Abdüllatîfdir. Hanefî fıkh âlimlerindendir. İzmirin (Tire) kasabasında ders verirdi. 801 [m. 1399] de vefât etdi. (Üsûl-i fıkh) kitâbı olan (Menâr) şerhı meşhûrdur.", "gectigiMaddeler": ["1/74", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Mende", "slug": "ibni-mende", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah Muhammed \nbin İshak bin Muhammed bin Yahyâ bin Mende, hadîs âlimidir. Üçyüzonda tevel-\nlüd ve üçyüzdoksanbeş 395 [m. 1005] senesinde vefât etdi. (Esmâ-üs-sahâbe) ve \n(Târîh-i isbehân) kitâbları meşhûrdur.", "gectigiMaddeler": ["3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Merzûk", "slug": "ibni-merzuk", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Ahmed bin \nMerzûk Şemseddîn Ebû Abdüllah Tilmsânî, Mâlikî fıkh âlimidir. 711 [m. 1311] de \nTilmsânda tevellüd ve 781 [m. 1379] de vefât etdi. İBNİ MERZÛK, Muhammed \nbin Ahmed bin Muhammed, birincinin torunu olup, 842 de Kâhirede vefât etdi. \nÇok kitâb yazdı. İBNİ MERZÛK, Osmân bin Merzûk, tesavvuf büyüklerinden ve \nHanbelî idi. 564 de Mısrda vefât etdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Muvaffık", "slug": "ibni-muvaffik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Muvaffık Bağdâ-\ndî, Zünnûn-i Mısrînin arkadaşı idi. Yetmişdört hac yapdı. 265 [m. 879] senesinde \nvefât etdi.", "gectigiMaddeler": ["3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Nasr", "slug": "ibni-nasr", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nasr bin İbrâhîm bin Nasr \nMukaddesî Şâmda hadîs ve Şâfi’î reîs-ül-ulemâsı idi. 490 [m. 1097] senesinde vefât \netdi. (Hucce) kitâbı meşhûrdur. Çok âlim, müttekî idi.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Nüceym-i Ömer", "slug": "ibni-nuceym-i-omer", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ömer bin İbrâ-\nhîm ibni Nüceym-i Mısrî, Hanefî fıkh âlimidir. 1005 [m. 1597] senesinde Mısrda \nvefât etdi. Büyük kardeşi ve hocası olan Zeynel’âbidîn ibni Nüceym-i Mısrî yanın-\ndadır. İmâm-ı Nesefînin (Kenz) fıkh kitâbınışerh ederek, (Nehr-ül-fâık) adını ver-\nmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Nüceym Zeynül'âbidîn", "slug": "ibni-nuceym-zeynulabidin-rahmetullahi-teala-ale", "unvan": "", "kategori": "alim", "biyografi": "Zeynel’âbidîn bin İbrâhîm ibni Nüceym-i Mısrî, [926] da tevellüd ve 970 [m. 1562] de Mısrda vefât etdi. Hanefî fıkh âlimidir. (Eşbâh), (Zeyniyye), (Kebâir) kitâbları ve üsûl-i fıkhdan (Menâr) şerhı meşhûrdur. (Kenz) kitâbınışerh ederek (Bahr-ür-râık) adını vermişdir. Yedi cild olup, bir cild tekmilesi ile ve İbni Âbidînin bunlara Hâşiyesi ile birlikde 1311 de Mısrda ve 1393 [m. 1973] de Beyrutda basılmışdır. 219, 282, 284, 310, 316, 318, 319, 341, 365, 587, 619, 629, 738, 822, 845, 872, 998, 1001, 1053. – 1115 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Nusayr", "slug": "ibni-nusayr", "unvan": "", "kategori": "diger", "biyografi": "Onbirinci imâm olan Hasen bin Alî Askerînin adamla-\nrından olduğunu söylemişdir. Buna inananlar, kendilerine (Nusayrî) dediler. Îrân-\nda, Irâkda ve Sûriyede çokdurlar. Şî’îlerin bir fırkası olduğu (Milel ve Nihal) de \nyazılıdır. Allah, hazret-i Alîye ve çocuklarına hulûl etmişdir. Onlarınşeklinde \ngörünmüşdür. Bâtın esrârını ancak onlar bilir dedi. 259 [m. 873] da öldü.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Râvendî", "slug": "ibni-ravendi", "unvan": "", "kategori": "diger", "biyografi": "Ahmed bin Yahyâ, İsfehanlı bir yehûdî dönmesinin \noğludur. Bağdâdda Mu’tezilî fırkasında iken, taşkınlık yaparak mülhid olmuşdur. \nYa’nî mezhebsizdir. Çok hadîs uydurmuşdur. Yehûdîlerden para alarak müsli-\nmânları aldatıcı kitâblar yazardı. 293 [m. 906] senesinde öldü.", "gectigiMaddeler": ["2/45"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Sînâ", "slug": "ibni-sina", "unvan": "", "kategori": "diger", "biyografi": "Ebû Alî Hüseyn bin Abdüllah, felesof ve tabîb idi. 370 [m. \n980] de Buhârâ civârında tevellüd, 428 [m. 1037] de Hemedânda vefât etdi. Arabî \nve fârisî, çok kitâb yazdı. Vezîr iken, işlediği haksız işlerine hastalandığında tevbe \netdi ise de, eski Yunan felesoflarının küfre sebeb olan fikrlerinden sıyrılamadığı, \n(Mu’âd) ve (Müstezâd) kitâblarından anlaşıldığı, imâm- ı Rabbânînin 245. ci ve \n266. cı mektûblarında ve imâm- ı Gazâlînin (El münkız) kitâbında bildirilmekde-\ndir.", "gectigiMaddeler": ["1/39", "2/21", "2/53", "2/67", "3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Sîrîn", "slug": "ibni-sirin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr Muhammed bin Sîrîn \nTâbi’îndendir. Basralıdır. [33] de tevellüd, 110 [m. 729] senesinde vefât etdi. Hadîs \nâlimi ve rü’yâ ta’bîrcisi idi.", "gectigiMaddeler": ["2/39"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbnissâ'atî", "slug": "ibnissaati", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Alî Ba’lebekî, \nhanefî fıkh âlimidir. 694 [m. 1294] senesinde vefât etdi. (Mecma’ul-bahreyn ve \nMültekânehreyn) ve bununşerhi meşhûrdur. İbni Sâatî Muhammed bin Alî başka \nolup, sâat i’mâlinde mâhir idi. Sultân Nûreddîn Zengînin emri ile, Şâmda câmi’i \nkebîr kapısındaki sâatları yapmış, 628 [m. 1230] da vefât etmişdir.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbnisserrâc", "slug": "ibnisserrac", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr Muhammed bin \nSırrı nahv âlimi idi. 316 [m. 928] senesinde vefât etdi. Bir de Muhammed bin Sa’îd \nvardır ki, Endülüsde tevellüd, 549 [m. 1155] senesinde Mısrda vefât etdi. Mâlikî \nidi. Nahv âlimi idi.", "gectigiMaddeler": ["2/18", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Teymiyye", "slug": "ibni-teymiyye", "unvan": "", "kategori": "diger", "biyografi": "Ahmed bin Abdülhalîm Harrânî, Şâmda hanbelî fıkh \nve hadîs âlimi idi. 661 [m. 1263] de Harrânda tevellüd, 728 [m. 1328] de Şâmda \nkal’ada habsde iken, hastalanarak vefât etdi. Çok kitâb yazdı. Şî’îleri ve eski Yûnân \nfelesoflarını red etdi. Ehl-i sünnete uymıyan yazılarından dolayı Mısrda iki def’a \nhabs edildi. (El-ubûdiyyet) kitâbında, Allahü teâlânın ismini zikr etmenin bid’at ve \ndalâlet olduğunu bildirmekde ve tesavvuf âlimlerine çirkin iftirâlar yapmakdadır. \nBu kitâbını, Pâkistânda Sadrüddîn sâhib isminde bir vehhâbî, urdu diline terceme \netmiş ve 1401 [m. 1981] de, (Hakîkat-i ubûdiyyet) ismi ile neşr edilmişdir. Merdanşehrinin kâdısı, allâme Habîb-ül-Hak Permûlî, buna bir reddiyye yazarak, (Zikrul-\nlah) ismi ile neşr eylemişdir. Bu reddiyyeye Pâkistân âlimleri, takrîzler, tasdîkler \nyazmışlardır. İbni Teymiyyeden önce vefât etmiş olan, Tâcüddîn Ahmed ibni Atâ-\nullah İskenderânînin (Miftâh-ul-felâh fî-zikrillah) kitâbı da, bu iftirâları, kuvvetli \ndelîllerle, vesîkalarla red etmekdedir. Allâme İbni Hacer-i Mekkî hazretleri (Fetâ-\nvâ-yı hadîsiyye) kitâbında, buna, (Allahü teâlânın, sapıtmasına ilmini sebeb etdiği \nkimsedir) buyurdu. Câmi’ul-ezherdeki hanefî âlimlerinden Muhammed Bahîtin \n(Tathîr-ül-füâd min-denisil i’tikâd) kitâbı ve (Et-Tevessülü bin Nebî ve bis-Sâlihîn) \nve (Şevâhid-ül-hak) ve (Cevâhir-ül-bihâr) kitâbları, İbni Teymiyyenin dalâlete düş-\ndüğünü vesîkalarla isbât etmekdedirler. İlk iki kitâb, 1396 [m. 1976] senesinde, \nİstanbulda, ofset yolu ile basdırılmışdır. İkinci kitâb (Berâet-ül-Eş’ariyyîn) adı ile \nŞâmda basılmışdır. (Cevâhir)in bu kısmı, (En-ni’met-ül-kübrâ) mevlid kitâbına ek \nolarak, İstanbulda basdırılmışdır. (Essırât-ul-müstekîm) kitâbında, Abdüllah ibni \nAbbâs gibi büyük sahâbîleri tekfîr etdiği (Keşfüzzünûn)da yazılı\ndır. \nHindistândaki büyük âlimlerden Muhammed Abdül’azîz Ferhârevî, (Nebrâs) \n– 1116 –\nismindeki, şerh-i Akâidşerhınin hâşiyesi, yüzonaltıncı sahîfesinde diyor ki: İbni \nHacer Askâlânî, (Ed-dürer-ül-kâmine) de diyor ki, (İbni Teymiyye, kabrin-Nebîyi \n“sallallahü aleyhi ve sellem” ziyâret için sefere çıkmak harâmdır dedi. Alî “radı-\nyallahü anh” îmân etdiği zemân çocuk olduğu için müslimânlığı sahîh olmadı \ndedi. Osmân ibni Affân “radıyallahü anh”, malı çok severdi dedi. (Sünen) kitâb-\nlarındaki hadîslerden za’îf olanları bile red etdi. Âlimler, bunun hakkında ihtilâf \netdiler.) Onu övenlerden, imâm- ı Zehebî bile, (O da insandır. Günâhları, hatâları \nelbet olacakdır) dedi. Allâme Ahmed ibni Hacer-i Mekkî (El-cevher-ül-mun-\nzam)da diyor ki, ( İbni Teymiyye öyle bir kimsedir ki, bozuk sözlerine ve çürük \nvesîkalarına, büyük âlimler cevâb vermişler ve düşüncelerinin çirkinliğini ortaya \nkoymuşlardır. [ Şâm, Mısr ve Kudüsde kâdîlık yapmış olanşâfi’î fıkh ve hadîs \nâlimlerinden Muhammed] İzz-ibni Cemâ’a, onun için, Allahü teâlânın dalâlete \nsürüklediği, azdırdığı ve zillet gömleği giydirdiği kimsedir. İslâm âlimlerine ve bil-\nhâssa Hulefâ-i râşidîne karşı ahmakca i’tirâzlarda bulunmuşdur demişdir. Aklı \nnoksan olan kimsede irfân bulunur mu?). İmâm-ı Ebül-Hasen Sübkî diyor ki, \n(İbni Teymiyye, ilmi aklından çok olan bir kimsedir. Ona Şeyh-ul-islâm diyenin \nkâfir olacağını söyliyenler vardır.) Celâlüddîn-i Devânî (Akâid-i Adudiyyeşerhı)nde diyor ki, ( İbni Teymiyyenin ba’zı kitâblarında, Arş kadîmdir dediğini \ngördüm.) Celâlîye yapılan hâşiyede, (İbni Teymiyyenin sapık sözleri haddi aşınca, \nKâhirede Kal’a-i Cebelde, Kadilkudât Zeynüddîn-i Mâlikî başkanlığında, derin \nâlimler toplandı. İbni Teymiyye bunlara cevâb veremedi. Yediyüzbeş senesi idi. \nHabsine karâr verildi. Şâmda ve başka yerlerde, (İbni Teymiyyeye uyanın malı ve \ncanı halâldir) denildiği (Mirâtül-cenân) da yazılıdır. Yediyüzyedide tevbe edip, \nserbest bırakıldı. Sözünde durmadı. Tekrâr habs edildi. Yine tevbe etdi. Şâmda \nyerleşdi.) Nebrâsın hâşiyesinden terceme temâm oldu. İbni Teymiyyenin (Kazâ \nnemâzı kılmak lâzım değildir. Her hayrlı iş kazâ nemâzı olur) sözü, dalâletinin \nbüyükşâhididir. \nBüyük âlim Cemâlüddîn Muhammed Muzcâcî, (Hidâyet-ül-hâlık) kitâbında, \nMuhyiddîn-i Arabî hazretlerini medh ve müdâfe’a ve İbni Teymiyyeyi red ve ibtâl \netmekdedir. Bu kitâb, İstanbulda Süleymâniyye umûmî kütübhânesinde, Vehbî \nefendi kısmında altıyüzkırkaltı [646] numarada mevcûddur. \nİbni Teymiyye, Ehl-i sünnet âlimlerinin büyüklüğünü anlamamış, tesavvufu \ninkâr etmiş, Ehl-i sünnetden ayrılmışdır. Kitâbları, kendilerine (Selefiyye)ci diyen \nmezhebsizlere kaynak olmakdadır. Mezhebsizler, onu övmekde, islâm müceddid-\nlerinin pîri demekdedirler. İbni Teymiyyeninşakî ve dalâletde olduğu (Seyf-ül-\nCebbâr) ve fârisî (Ta’lîm-üs-sübyân)da da yazılıdır. Abdürrâzık pâşa diyor ki, \n(Vehhâbîlik, bir bakımdan ibni Teymiyyeye bağlı olduğu gibi, son asrın islâm \nmüceddidi bilinen Muhammed Abdühdeki dinde reform fikrleri de, bir bakımdan, \nibni Teymiyyeye bağlıdır.) Abdürrâzık pâşa, 1366 [m. 1946] da öldü. Hocası Abdü-\nhün ve yardımcısı Reşîd Rızânın Câmi’ul-ezherde yaydıkları yıkıcı fikrleri yerleş-\ndirmek için uğraşmaları başarısız kaldı. Sudândaki mâlikî âlimlerinden Tâhir \nMuhammed Süleymân, (Zahîretül-fıkhil-kübrâ) kitâbında diyor ki, ( İbni Teymiy-\nyenin sözlerinin kıymeti yokdur. O, dalâletdedir ve müslimânları dalâlete sürükle-\nmekdedir. Müslimânların icmâ’ ından ayrılmış, bid’at yolunu tutmuşdur. İslâm \nâlimleri, onun dalâletde [sapık] olduğunu, sözbirliği ile bildirdi. Kutbüd-Berdîrî, \n(Şerh-i Muhtasar) da, bunu uzun yazmakdadır). (Zahîre)nin ikinci baskısı, 1409 \n[m.1989]da yapılmışdır. Dâl ve mudil olduğu, (Sâvî tefsîri) 107.ci sahîfesinde de \nyazılıdır. Dahâ çok bilgi almak için ikinci kısmda, onyedinci maddeyi ve (Fâideli \nBilgiler) kitâbını okuyunuz! \nYukarıda adı geçen, bid’at sâhibi Ahmed ibni Teymiyye ile Ehl-i sünnet olan Fah-\nrüddîn Muhammed bin Ebilkâsım ibni Teymiyyeyi birbiri ile karışdırmamalıdır. Bu, \n542 [m. 1146] de Harrânda tevellüd ve 621 [m. 1223] de vefât etmişdir. Hanbelî fıkh \n– 1117 –\nkitâbı ve tefsîri vardır.", "gectigiMaddeler": ["1/31", "1/53", "1/71", "1/74", "1/78", "1/84", "2/4", "2/5", "2/16", "2/17", "2/20", "2/21", "2/22", "2/28", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbni Verdî", "slug": "ibni-verdi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Zeyneddîn Ömer ibni Verdî \nHalebî, edîb ve Şâfi’î fıkh âlimidir. 688 [m. 1289] de tevellüd, 749 [m. 1348] da H -\nlebde vefât etdi. (Lâmiyye) kasîdesi meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbnürrüşd", "slug": "ibnurrusd", "unvan": "", "kategori": "diger", "biyografi": "Kâdî Muhammed bin Ahmed ibnürrüşd, âlim değil, En -\ndülüsde yetişen bir felesof idi. 514 [m. 1120] de Kurtubada tevellüd, 595 [m. 1198] \nde Merrâküşde vefât etmişdir. Çok kitâb yazdı. Kitâbları latinceye terceme edil-\nmişdir. Fransız (Ernest Renan), bunun hayâtını, fikrlerini yazmış, bu kitâbı üçüncü \nolarak 1272 [m. 1856] de Pârisde basılmışdır. Din bilgilerini, kendi görüşüne göre \nanlatmış, imâm-ı Gazâlîye karşı, felsefecileri müdâfe’ada bulunmuşdur. Ehl-i sün-\nnet âlimi olan Muhammed İbnürrüşd, bunun dedesi idi.", "gectigiMaddeler": ["2/17", "2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbn-Üs-Sakkâ", "slug": "ibn-us-sakka", "unvan": "", "kategori": "diger", "biyografi": "982. ci sırada Yûsüf Hemedânî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm", "slug": "ibrahim", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Resûlullahın oğullarının üçüncüsü ve \nbütün çocuklarının sonuncusudur. Herakliüsun Mısr vâlîsi olan Mukavkasin \nhediyye gönderdiği Mâriyenin oğludur. Hicretin sekizinci [8] senesi tevellüd edip, \nbirbuçuk yaşında iken, vefât etdi. Hasta iken, Resûlullah kucağına alıp mubârek \ngözlerinden yaş akardı. Vefâtı için güneş tutuldu dediler. Resûlullah “sallallahü \naleyhi ve sellem” bunu işitince, (Ay ve güneş Allahü teâlânın varlığını ve birliğini \ngösteren iki mahlûkudur. Kimsenin ölmesi, kalması ile tutulmazlar. Onları görün-\nce Allahı hâtırlayınız!) buyurdu. İbrâhîm vefât edince, (Yâ İ\nbrâhîm! Ölümüne çok \nüzüldük. Gözlerimiz ağlıyor, kalbimiz sızlıyor. Fekat, Rabbimizi gücendirecek bir-\nşey söylemeyiz) buyurdu. Mâriye hâtun müslimân olup, hicretin onaltısında Medî-\nnede vefât etdi. Cenâze nemâzını Ömer “radıyallahü anh” kıldırdı.", "gectigiMaddeler": ["1/13", "1/84", "1/85", "1/90", "1/94", "1/95", "1/97", "2/5", "2/20", "2/21", "2/47", "2/53", "2/67", "2/72", "3/2", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm", "slug": "ibrahim-2", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın oğullarının üçüncüsü ve \nbütün çocuklarının sonuncusudur. Herakliüsun Mısr vâlîsi olan Mukavkasin \nhediyye gönderdiği Mâriyenin oğludur. Hicretin sekizinci [8] senesi tevellüd edip, \nbirbuçuk yaşında iken, vefât etdi. Hasta iken, Resûlullah kucağına alıp mubârek \ngözlerinden yaş akardı. Vefâtı için güneş tutuldu dediler. Resûlullah “sallallahü \naleyhi ve sellem” bunu işitince, (Ay ve güneş Allahü teâlânın varlığını ve birliğini \ngösteren iki mahlûkudur. Kimsenin ölmesi, kalması ile tutulmazlar. Onları görün-\nce Allahı hâtırlayınız!) buyurdu. İbrâhîm vefât edince, (Yâ İ\nbrâhîm! Ölümüne çok \nüzüldük. Gözlerimiz ağlıyor, kalbimiz sızlıyor. Fekat, Rabbimizi gücendirecek bir-\nşey söylemeyiz) buyurdu. Mâriye hâtun müslimân olup, hicretin onaltısında Medî-\nnede vefât etdi. Cenâze nemâzını Ömer “radıyallahü anh” kıldırdı.", "gectigiMaddeler": ["1/81", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Ağa", "slug": "ibrahim-aga", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Üçüncü Murâd hânın \nbâbüsse’âde ağasıdır. Haydarpâşa ile Koşuyolu arasında bir mescidi vardır. 988 [m. \n1580] senesinde yapılmışdır. Sürre alayları hacca giderken, burada veda’laşırlar-\ndı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm bin Abdüllah", "slug": "ibrahim-bin-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Ha -\nsenin soyundandır. Halîfe olmak istedi. Mensûr askeri ile yapdığı savaşda 145 [m. \n763] senesindeşehîd edildi.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm bin Edhem", "slug": "ibrahim-bin-edhem", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Belh pâdişâhının \nveyâ kızının oğludur. Babası Edhemdir. Ömerül-Fârûk neslindendir. Şâmda Çeş-\ntiyye Evliyâsının büyüklerindendir. [96] da tevellüd, 162 [m. 779] senesinde vefât \netdi. 73, 644, 677, 687, 787, 788, 789, 909, 1112. \n– 1118 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Binşeybân", "slug": "ibrahim-binseyban", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kazvinlidir. Sô -\nfiyye-i aliyyedendir. İbrâhîm-i Havvâsın arkadaşı idi. 337 [m. 949] de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Hakkı", "slug": "ibrahim-hakki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliyyedendir. \nErzurumda, Hasen kal’a kasabasında tevellüd, 1195 [m. 1781] senesinde Si’ridde, \nTilloda vefât etdi. Kâdirî idi. Fakîrullah İsmâ’îl Tilevînin halîfesidir. (Ma’rifetnâ-\nme) kitâbı ve 1263 [m. 1846] de divânı basılmışdır.", "gectigiMaddeler": ["1/60", "2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Hân", "slug": "ibrahim-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sultân İbrâhîm, İslâm halî-\nfelerinin seksenüçüncüsü ve Osmânlı pâdişâhlarının onsekizincisidir. Birinci \nAhmed hân ile Mâh- ı peyker kösem Sultânın oğludur. Binyirmidörtde tevellüd \netdi. Binkırkdokuz 1049 [m. 1640] da halîfe oldu. 1058 [m. 1648] deşehîd edildi. \nGirid adasının fâtihidir. Dînine çok bağlı olduğu için, kâfirler, bunu çok kötüledi-\nler. Yalan hikâyeler uydurdular. Gençleri aldatdılar. Onyedinci sırada, Abdülha-\nmîd hân (I) ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm-i Havvâs", "slug": "ibrahim-i-havvas", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Cüneyd-i Bağdâdî-\nnin eshâbından idi. 291 [m. 903] de Reyşehrinde câmi’de vefât etdi. Babası \nİsmâ’îldir. Havvâs, hurma yaprağından, zenbil dokuyucu demekdir.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm-i Müteferrika", "slug": "ibrahim-i-muteferrika", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Macar iken \nislâm dînini tercîh etmiş, müslimân olmuşdur. [1139] da ruhsat alıp, metal harfler \ndökerek ilk islâm matba’asını kurmuşdur. En önce (Vankuli) lügatini basdı. İlm ve \nfen adamı idi. Latinceden tercemeleri ve fennî kitâbları vardır. 1158 [m. 1744] \nsenesinde vefat etdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm-i Neha'î", "slug": "ibrahim-i-nehai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Fıkh âlimlerindendir. \nHammâdın hocası idi. Hammâd da, imâm-ı a’zam Ebû Hanîfenin hocası idi. 96 [m. \n715] senesinde Kûfede vefât etdi.", "gectigiMaddeler": ["1/63", "1/73", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Pâşa (dâmâd)", "slug": "ibrahim-pasa-damad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nevşehrlidir. \nÜçüncü Ahmed hânın dâmâdı ve sadr-ı a’zamı idi. 1143 [m. 1730] de, patrona Halîlısyânındaşehîd edildi. Şâhzâde başında yapdırmış olduğu mescid yanındadır. Çen-\ngelköyünde, kuleli lisesi önündeki câmi’i İbrâhîm pâşanın dâmâdı, kaptan-ı deryâ \nKaymak Mustafâ pâşa 1137 [m. 1724] de yapdırdı. 1143 [m. 1730] de patrona Halîlısyânındaşehîd edildi. Divân yolunda Parmakkapı Kara Mustafâ pâşa medresesi \nkabristânındadır. Üsküdârda (Kaptan pâşa câmi’i)ni de 1140 [m. 1727] da bu yap-\ndırmışdır.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Pâşa (dâmâd)", "slug": "ibrahim-pasa-damad-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nevşehrlidir. \nÜçüncü Ahmed hânın dâmâdı ve sadr-ı a’zamı idi. 1143 [m. 1730] de, patrona Halîlısyânındaşehîd edildi. Şâhzâde başında yapdırmış olduğu mescid yanındadır. Çen-\ngelköyünde, kuleli lisesi önündeki câmi’i İbrâhîm pâşanın dâmâdı, kaptan-ı deryâ \nKaymak Mustafâ pâşa 1137 [m. 1724] de yapdırdı. 1143 [m. 1730] de patrona Halîlısyânındaşehîd edildi. Divân yolunda Parmakkapı Kara Mustafâ pâşa medresesi \nkabristânındadır. Üsküdârda (Kaptan pâşa câmi’i)ni de 1140 [m. 1727] da bu yap-\ndırmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İbrâhîm Pâşa (kavalalı)", "slug": "ibrahim-pasa-kavalali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mehmed Alî pâşa-\nnın büyük oğlu idi. 1204 [m. 1789] de Kavalada tevellüd, 1265 [m. 1848] de Mısrda \nvefât etdi. Cidde vâlîsi oldu. Sultân Mahmûd hânın emri ile vehhâbîlerle harb etdi. \n1233 [m. 1818] sonunda, başşehrleri Der’iyyeyi aldı. Vehhâbîler, sonra Riyâdı hükû-\nmet merkezi yapdılar. Sonra Mora isyânını basdırdı. 1247 [m. 1831] de de sultân ikinci \nMahmûdaısyân ederek Sûriyeyi aldı. Kütahyaya kadar geldi. 1248 [m. 1832] de Sûriye \nve Adana, Mısra verildi. 1264 [m. 1847] de tekrârısyân etdi ve ilerledi ise de, İngiltere \nişe karışıp Sûriyeyi Osmânlılara bırakdı. 1262 [m. 1845] de, babası Mısrın idâresini \nbuna bırakdı. 1265 [m. 1848] de halîfeden, müstekıl vâlî demek olan (Hidîv) unvânını \naldı ise de, o senede babasından birkaç ay evvel vefât etdi. Yerine Tosun pâşanın oğlu \nbirinci Abbâs hidîv oldu. Bu da 1271 [m. 1854] de vefât edince, yerine İbrâhîm pâşanın \noğlu Sa’îd pâşa geçdi. Sa’îd pâşa 1238 [m. 1822] de tevellüd etdi. Süveyş kanalını ve \nPort Sa’îdşehrini yapdırdı. 1280 [m. 1863] de vefât etdi. Yerine kardeşi İsmâ’îl pâşa \nhidîv oldu. Onyedinci [17] sırada Abdülhamîd hân (I) adına bakınız! 1062. \n– 1119 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İdrîs", "slug": "idris", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Şis aleyhisselâmın torunlarındandır. Allahü \nteâlâ, buna otuz sahîfe [forma] gönderdi. Eski Yunânlıların Hermens dedikleri \nkimse ve dahâ sonraki felesofları, fizik, kimyâ ve tıb bilgilerini, İdrîs aleyhisselâ-\nmın kitâbından çaldılar. Kalem ile kitâblar yazan ve iğne ile dikiş diken budur. Da -\nhâ önce, deriden elbise giyilirdi. Diri olarak göke kaldırıldı.", "gectigiMaddeler": ["1/39", "1/85", "2/20", "2/26", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İlyâs", "slug": "ilyas", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın onyedinci babasıdır. Kâ’beye sel basınca ye’se düş-\ndüğü için İlyâs denildi. Kâ’beye kurban kesmek bundan kalmışdır. Hac yaparken \nbelinde Resûlullahın tekbîr, telbiye sesini işitirdi.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İmâdibni Kesîr", "slug": "imadibni-kesir", "unvan": "", "kategori": "diger", "biyografi": "Ebül-fidâ İsmâ’îl bin Ömer 774 [m. 1372] de vefât \netdi. Şâfi’îdir. Dörtyüzelliikinci sırada, İbni Kesîr ismine bakınız!", "gectigiMaddeler": ["3/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İmâdüddîn-i Zengî", "slug": "imaduddin-i-zengi", "unvan": "", "kategori": "diger", "biyografi": "Atabek sultânlarından üçünün ismidir. Birin-\ncisi, Mûsulda ve Halebde hükûmet süren Atabek devletinin kurucusudur. Selçuk \nhükümdârı sultân Mahmûd bin Muhammed bin Melikşâhın Mûsulda vâlîsi iken \n521 [m. 1127] de Halebi aldı. 524 [m. 1130] de Haçlılarla harb edip gâlib geldi. \nOndokuz yıl hükûmet sürüp 540 [m. 1146] senesinde vefât etdi. Mülkü ikiye ayrıl-\ndı. Oğlu Nûreddîn Mahmûd Zengî Haleb sultânı oldu. Diğer oğlu, Kütbüddîn \nMevdûd, Mûsul sultânı oldu. İkinci İmâdüddîn bin Kutbüddîn Mevdûd Zengînin \nbabası, beşyüzaltmışbeş [565] de ölünce, kardeşi Seyfüddîn bin Kutbüddîn, sonra \ndiğer kardeşi İzzeddîn Mes’ûd, Mûsul sultânı, İmâdüddîn de Sincâr sultânı oldular. \nHaleb sultânı İsmâ’îl Sâlih bin Nûreddîn beşyüzyetmişyedi [577] de vefât edince, \nİmâdüddîn Haleb sultânı oldu. Beşyüzdoksaniki [592] de vefât edince, yerine oğlu \nKutbüddîn Muhammed geçdi. İzzeddîn Mes’ûd beşyüzseksendokuz [589] da vefât \nedince, oğlu Nûreddîn Arslan Şâh, Mûsul sultânı oldu. Bedreddîn Lülü, bunun \nkölesi idi. Bu da altıyüzyedi 607 [m. 1210] de vefât edince, yerine oğlu Kahir İzzed-\ndîn Mes’ûd geçdi. Bu da altıyüzonyedi 617 [m. 1220] senesinde vefât etdi. Yerine \noğlu ikinci Arslan Şâh geçdi. Bu on yaşında olduğundan, Lülü idâreyi eline aldı. \nAz zemânda Arslan Şâh ölünce, oğlu üçüncü İmâdüddîn, Nusaybin ve Hakkârîde \nsultân oldu. İmâdüddînin zevcesi, Erbil hâkimi Muzafferüddîn Ebû Sa’îd Kükbû-\nrînin kızı idi. Kükbûrî, mevlid cem’ ıyyetleri yapmakla meşhûrdur. Bunun zevcesi \nRabî’a hâtun, Salâhuddîn-i Eyyûbînin hemşîresi idi. İmâdüddîn ile birleşerek Bed-\nreddîni mağlûb etdiler. İmâdüddînin mülkü genişledi. Bedreddîn Lülüşeyh \nHasen-i Yezîdî üzerine gönderildi. Yezîdîler dağıldı.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İmâm-ı Rabbânî", "slug": "imam-i-rabbani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Abdülehad, \nderin âlim, büyük Velî idi. Müctehid idi. İslâm âlimlerinin gözbebeğidir. Tesavvuf \nbilgilerinin mütehassısı idi. Âlimlerin önderi, Velîlerin baş tâcı idi. (Mektûbât) ki -\ntâbı, üç cild olup, beşyüzotuzaltı mektûbunun toplanmasından meydâna gelmişdir. \nKelâm, fıkh bilgilerini ve Resûlullahın güzel ahlâkını açıklıyan bir deryâdır. Bu \nderyâdan inci mercan çıkarmak, ancak usta dalgıclara nasîb olur. Fârisî aslı Hin-\ndistânda ve Efganistânda basılmış ise de, 1392 [m. 1972] senesinde Pâkistânda \nbasılmış olanı pek nefîsdir. Bu fârisî baskının, foto-kopisi 1397 [m. 1976] senesin-\nde, İstanbulda Hakîkat Kitâbevi tarafından gâyet nefîs olarak basdırılmışdır. \nBirinci cildi türkçeye terceme edilerek (Mektûbât Tercemesi) adı ile basdırıldı. \nFârisî el yazması, İstanbul Bâyezîd kütübhânesinde [1790] sayıda ve Süleymâniyye-\nnin çeşidli kısmlarında vardır. 971 [m. 1563] de Hindistânda, Serhendşehrinde \ntevellüd etdi. Ömrünün sonuna doğru, mezhebsizlerin iftirâları üzerine, 1027 sene-\nsinde Selîmşâh tarafından Gwaliyarşehrinde habs edildi. [1029] da çıkarıldı. Bin \nrupye ihsân olunup, iki sene dahâ askerde kaldı. Kış aylarında nefes darlığı olurdu. \n[1624] Kanûn-ı evvel [aralık] ayının onuncu ve binotuzdört 1034 Safer ayı yirmido-\nkuzuncu salı günü, Serhendde vefât etdi. Evinin yanına defn edildi. Efganistân pâdi-\nşâhı Şâh-i zemân, imâm için büyük ve çok san’atli bir türbe yapdırdı. İki oğlu \nMuhammed Sâdık ve Muhammed Sa’îd de bu türbededirler. Şâh-i zemân, on metre \n– 1120 –\nuzakdaki türbede zevcesi ile birlikdedir. \n(Mektûbât) kitâbını Muhammed Murâd-ı Kazânî fârisî dilinden arabîye terceme \netmişdir. Bundan seçilen yüzdoksandört ve fârisî (Mektûbât)dan seçilen yüzelliüç \nmektûb (Müntehabât) adı ile iki kitâb hâlinde basdırılmışdır. İmâm-ı Rabbânî haz-\nretlerinin hâl tercemesi, Muhammed Hâşim-i Keşmî tarafından fârisî olarak yazıl-\nmış, buna (Berekât) veyâ (Makâmât-i Ahmediyye) ve (Zübde-tül-makâmât) denil-\nmişdir. Muhammed Ma’sûm-i Fârûkînin torununun oğlu olan Gulâm Muhammed \nMa’sûmun torununun torunu hâce Muhammed Fadlullah, (Umde-tül-makâmât) \nadındaki fârisî kitâbında, dedelerinin hayâtlarını uzun bildirmekdedir. 1397 de \nKâbilde ve 1416 [m.1996] da İstanbulda basılmışdır. 99.cu sahîfesinde diyor ki, \n(İmâm-ı Rabbânînin ondördüncü dedesi Şihâbüddîn Alî Ferrûh Şâh, Gaznevî sul-\ntânlarının Kâbil vâlîsi idi. Gaznevî hükûmeti yıkılınca, Kâbilde hükûmet reîsi oldu. \nBirkaç sene sonra, hükûmeti terk ederek, tesavvufda çalışarak büyük velî oldu. \nKâbil civârında medfûndur. Mahdûm- ı cihâniyân seyyid Celâlüddîn-i Buhârî Buhâ-\nrâdan Hindistâna gelirken, dâmâdı ve halîfesi olan imâm- ı Refî’üddîni berâber \ngetirdi. İmâm-ı Refî’üddîn, imâm- ı Rabbânînin altıncı ceddidir. Delhî sultânı Firûz \nŞâh›n emri ile, ormanl›k olan Serhendişehr hâline koydu. Şehr hâricindeki türbe-\ndedir. ‹mâm-› Rabbânînin valîdesi de burada medfûndur). Hakîkat Kitâbevinin \n‹stanbulda neşr etdiği (Documents of the Right Word) kitâb›nda, ingilizce olarak \nyaz› l› d›r. Muhammed Fadlullah, [1238] de Kandihârda vefât etdi. Bedrüddîn-i Ser-\nhendînin fârisî (Hadarât-ül-kuds) kitâb›nda da, hâl tercemesi uzun yaz› l› d›r. Bu \nkitâb 1391 [m. 1971] de Pâkistânda çok güzel bas›lm› şd›r. ‹stanbul Bâyezîd kütüb-\nhânesinde [1788] say› da el yaz› s› ile vard›r. Hâce zâde Ahmed Hilmi efendinin \n‹stanbulda [1318] de bas› lan türkçe (Hadîka-tül-evliyâ) kitâb› da, ‹mâm-› Rabbânî-\nnin ve üstâdlar› n›n hayâtlar› n› ve kerâmetlerini uzun bildirmekdedir. \nŞâh-ı Dehlevî Gulâm Alî Abdüllah “kuddise sirruh”, talebesinin büyüklerinden \nmevlânâ Hâlid-i Bağdâdîye “kuddise sirruh” gönderdikleri bir mektûbda, Mevlâ-\nnânın derece ve fazîletlerini uzun uzun anlatdıkdan sonra, İmâm-ı Rabbânî “kud-\ndise sirruh” hakkındaşöyle buyuruyor: (Âlimler ve ârifler söylemişler ve yazmış-\nlardır ki, imâm- ı Rabbânîyi sevenler, mü’min ve müttekî olanlardır. Sevmiyenler \nde, münâfık veşakîlerdir. İslâm memleketleri hazret-i Müceddidin feyz ve nûrları \nile doldu. Bütün müslimânlara, hazret-i Müceddidin “rahmetullahi aleyh” ni’met-\nlerineşükr ve hamd etmesi vâcib oldu.) Başka bir mektûbunda, ( İnsanda buluna-\nbilecek her kemâli, her üstünlüğü, Allahü teâlâ, İmâm-ı Rabbânî hazretlerine ver-\nmişdir. Vermediği yalnız Peygamberlik makâmı kalmışdır) demiş ve aşağıdaki \nrubâ’îyi yazmışdır: \nHer letâfet ki, nihân bûd pes-i perde-i gayb, \nheme der sûret-i hûb-i tûıyân sâhte end, \nHerçi ber safha-i endîşe keşed kilk-i hıyâl, \nşekl-i matbû’i tû zîbâ-ter ezân sâhte end. \n1394 [m. 1974] senesinde, Pâkistânın Şeyhûfûreşehrinde, Urdu dili ile basılmış \nolan (Meslek-i Müceddid) kitâbında ve (El-Hadâik-ul-verdiyye) kitâbında da, \nimâm-ı Rabbânî hazretlerinin hâl tercemesi yazılıdır. Bu iki kitâbdaki hâl terceme-\nleri bir arada olarak, 1396 [m. 1976] senesinde, İstanbulda ofset yolu ile basdırıl-\nmışdır. (Hak Sözün Vesîkaları)nda da çok güzel yazılıdır. \nMuhammed bin yâr Muhammed Burhânpûrînin (Atıyyet-ül-vehhâb El-fâsılatü \nbeynel-hakkı vessavâb firreddi alelmu’terıdı aleşşeyhi Ahmed-el-Fârûkî)  kitâbın-\nda kerâmetleri yazılıdır. Bu kitâb, arabî mektûbâtın üçüncü cildi hâşiyesinde basıl-\nmışdır. Muhammed beg 1110 [m. 1698] da vefât etdi. \nİmâm-ı Rabbânînin fârisî (Redd-i revâfıd) kitâbı ve türkçe tercemesi ve (İsbât-\nün-nübüvvet) ve (Mebde ve me’âd) kitâbı İstanbulda neşr edilmişdir. (Âdâb-ül-\n– 1121 –                                  Se’âdet-i Ebediyye 3-F:71\nmürîdîn), (Ta’lîkât-ül-avârif), (Tehlîliyye), ( Şerh-ı rubâ’ ıyyât-i Abd-il-Bâkî), \n(Me’ârif-i ledünniyye), (Mükâşefât-i gaybiyye) ve başka eserleri de vardır. (Çehl \nhadîs-i mubârek) risâlesi, (Mükâşefât) kitâbının sonunda basılmışdır.", "gectigiMaddeler": ["1/1", "1/17", "1/25", "1/27", "1/31", "1/35", "1/37", "1/39", "1/50", "1/52", "1/53", "1/54", "1/64", "1/71", "1/74", "1/79", "1/90", "1/94", "2/1", "2/2", "2/4", "2/5", "2/16", "2/17", "2/23", "2/39", "2/44", "2/52", "2/53", "2/67", "2/71", "2/72", "2/73", "3/1", "3/2", "3/19", "3/28", "3/30", "3/33", "3/35", "3/36", "3/37", "3/43", "3/44", "3/49", "3/50", "3/51", "3/52", "3/53", "3/54", "3/55", "3/56", "3/57"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İmâm-Ül-Haremeyn", "slug": "imam-ul-haremeyn", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İki dânedir. Biri, \nhanefî âlimlerinden Ebû Muzaffer Yûsüf Cürcânîdir. İkincisi, Abdülmelik bin \nAbdüllah Nîşâpûrî olup, Şâfi’î hadîs ve fıkh âlimidir. [419] da Nîşâpûrda tevellüd ve \n478 [m. 1085] de orada vefât etdi. Uzun zemân Bağdâdda, Mekkede ve Medînede \nbulundu. Vezîr Nizâmül-mülk bunun için Nîşâpûrda medrese yapdı.", "gectigiMaddeler": ["2/17", "2/43", "2/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Îsâ", "slug": "isa", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "İnsan idi. Peygamber idi. Allahü teâlâ, Onu babasız \nyaratdı. Annesi hazret-i Meryem, Hunnenin kızı idi. Hunne, Imrânın hem üvey \nkızı, hem zevcesi idi. Kudüsün Beyt-i Lahm kasabasında tevellüd etdi. Annesi \nyirmi yaşında idi. Rum Kayserinin Şâmda vâlîsi olan Herdüs, babasız doğduğu \niçin, ikisini öldürmek istedi. Meryemin amcası oğlu Yûsüf Neccar, bunları Mısra \ngötürdü. Oniki sene sonra, Herdüsün öldüğünü haber alınca, Şâmın Nâsıra kasa-\nbasında cebel-i Halîl köyüne getirdi. Otuz yaşında Peygamber oldu. Otuzüç yaşın-\nda, diri olarak göke kaldırıldığı, bütün islâm kitâblarında yazılıdır. Kendisine az \nkimse inandı. Kıyâmet yaklaşınca Şâmda, Ümeyye câmi’i minâresine inecek, evle-\nnecek, çocukları olacak, hazret-i Mehdî ile buluşacak, kırk sene yaşayıp, Medînede \nvefât edip, Hucre-i se’âdete defn edilecekdir. Allahü teâlâ, buna (İncîl) kitâbını \ngönderdi. İncîlde Allahü teâlânın bir olduğu, Îsâ aleyhisselâmın, Allahın kulu ve \nPeygamberi olduğu, âhır zemânda, Ahmed isminde bir Peygamber geleceği yazılı \nidi. Bolüs [Pavlos] isminde bir yehûdî, Îsevî görünüp, Havârîler arasına karışdı. Îsâ \naleyhisselâmdan sonra, ilk işi, hakîkî İncîli yok etmek oldu. Havârîlerden olan \nBarnabas, Îsâ aleyhisselâmdan gördüklerini ve işitdiklerini doğru olarak yazdı ise \nde, Bolüs bunun yayılmasına mâni’ oldu. Dahâ sonra, bozuk İncîl kitâbları her \nyere yayıldı. Kitâbın sonundaki ism cedvelinde Barnabas ismine bakınız! Şimdi \nelde bulunan İncîller birbirlerine benzemiyor. Katolikler, ortodokslar ve protes-\ntanlar, hep başka başka İncîller okuyorlar. Birbirlerini beğenmiyorlar. Îsâ aleyhis-\nselâm kendisine inananlar arasından oniki kişiyi seçdi. Bunlara (Havârî) denir. \nYehûdîlerin çoğu inanmadı. Kendisine ve annesine çok kötüşeyler söylediler. Îsâ \naleyhisselâm göke çıkarıldıkdan kırk sene sonra, Romalılar Kudüse hücûm etdi. \nYehûdîlerin çoğunu öldürdü, bir kısmını da esîr etdiler. Şehri yağma etdiler. \nKitâblarını yakdılar. Yehûdîler, sonra hakîr, zelîl oldular.", "gectigiMaddeler": ["1/3", "1/7", "1/18", "1/19", "1/24", "1/25", "1/26", "1/31", "1/46", "1/70", "1/81", "1/83", "1/85", "1/87", "1/92", "1/93", "1/94", "1/95", "1/97", "2/4", "2/20", "2/21", "2/22", "2/30", "2/34", "2/47", "2/53", "2/67", "2/72", "3/1", "3/2", "3/3", "3/36"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İshak", "slug": "ishak", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "İbrâhîm aleyhisselâmın ikinci oğludur. İshak, \n(gülüyor) demekdir. Annesi Sârânın gençlikde çocuğu olmamışdı. İhtiyârlıkda, \nçocuğu olacağı, Allah tarafından müjdelenince, şaşırıp güldüğü için oğluna bu ism \nverilmişdi. Bunun da, İys ve Ya’kûb adında iki oğlu oldu.", "gectigiMaddeler": ["1/97", "2/20", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İshak bin Râheveyh", "slug": "ishak-bin-raheveyh", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanefî âlimle-\nrindendir. [161] de tevellüd, 233 [m. 848] senesinde vefât etdi.", "gectigiMaddeler": ["1/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İshak Efendi", "slug": "ishak-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Harputludur. 1309 [m. \n1891] de vefât etdi. Hıristiyanlara cevâb olarak, (Dıyâ-ül-kulûb) ve (Şems-ül-hakî-\nka) kitâblarını yazmışdır. Birincisi türkce olup, (Cevâb veremedi) ismi ile, ingiliz-\nceye terceme edilmiş, her iki dilde, Hakîkat Kitâbevi tarafından basdırılmışdır.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İshak Efendi", "slug": "ishak-efendi-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Harputludur. 1309 [m. \n1891] de vefât etdi. Hıristiyanlara cevâb olarak, (Dıyâ-ül-kulûb) ve (Şems-ül-hakî-\nka) kitâblarını yazmışdır. Birincisi türkce olup, (Cevâb veremedi) ismi ile, ingiliz-\nceye terceme edilmiş, her iki dilde, Hakîkat Kitâbevi tarafından basdırılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İskender", "slug": "iskender", "unvan": "", "kategori": "diger", "biyografi": "Üç İskender vardır: 1- Makedonya kralı Filipin oğludur. \nMîlâddan [356] sene önce tevellüd, [323] sene önce otuzüç yaşında vefât etdi. Onüç \nyaşında Aristonun terbiyesine bırakıldı. Yirmi yaşında hükümdâr oldu. Yunanistâ-\nnı, Îrân ve Anadoluyu aldı. Ayaş yanında Dârâyı esîr aldı. Sûriye ve Mısrı aldı. \nİskenderiyeşehrini yapdı. Erbilde Dârâyı ikinci def’a bozguna uğratdı. Dârâ \nkaçarken öldü. Horâsân, Hirât ve Belhi de aldı. Bu zaferleri, ahlâkını bozdu. \nZulme başladı. İşret ve sefâhetle öldü. 2- İkinci İskender, çok eski Yemen hüküm-\ndârı olup, birinci İskenderden ikibin sene önce idi. Çine kadar gitmişdi. Adı Mün-\nzir idi. 3- Üçüncü İskender, Kur’ân-ı kerîmde Zülkarneyn adı ile bildirilen, mubâ-\nrek bir zâtdır. Peygamber veyâ Evliyâdandır. Doğuya ve batıya gitdiği için Zülkar-\nneyn denildi. Yâfes soyundan idi. Hızır “aleyhisselâm” bunun kumandanlarından \nidi ve teyzesinin oğlu idi. Birinci ve ikinci İskenderlerden önce idi. Hazret-i İbrâ-\nhîm ile görüşdü. Düâsını aldı. Avrupa ve Asya kıt’alarının bir kısmına mâlik oldu. \nAsyanınşarkşimâlindeki, ya’nî kuzey doğusundaki mü’min türklerin ricâsı üzerine \nYe’cûc ve Me’cûc kavminden korunmak için büyük dıvar yapdı. Bu sed, iki dağ \narasında, altı kilometre uzunluğunda, yirmibeş metre genişlik ve yüz metre yüksek-\nlikde idi. Taş ve demirden yapıldı. Bugün, bilinen Çin seddi başkadır. Ye’cûc ve \nMe’cûc sed arkasında kaldı. Sedden dışarı kalanlar, türklerdir. Târîhler, hattâ ba’zı \ntefsîrler, bu üç İskenderi birbiri ile karışdırmakdadır.", "gectigiMaddeler": ["1/31", "2/20", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl", "slug": "ismail", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "İbrâhîm aleyhisselâmın büyük oğludur. Anne-\nsi, Fir’avnın hediyye etmiş olduğu Hâcer adındaki câriyedir. Hâceri oğlu ile \nKudüsden Mekkeye götürdü. Kendi geri döndü. Annesi su ararken, yatan çocuğu \ntepindi. Ayaklarının vurduğu, yâhud Cebrâîl aleyhisselâmın vurduğu yerden Zem-\nzem suyu çıkdı. Konuşmağa başlayınca, bunu kesmesi için İbrâhîm aleyhisselâma \nemr verildi. Bıçak buğazını kesmedi. Üzülüp taşa vurdu. Taşı kesdi. Sonra gökden \ngönderilen koçu kurban etdi. Büyüdükde babası ile birlikde Kâ’benin yerini \nbulup, temelinden yapdılar. Sonra, Mekkeye Yemenden Cürhüm kabîlesi gelip \nyerleşdi. Bunlardan kız aldı. Bunlara Peygamber oldu. Bunun dîni, islâmiyyete \nkadar doğru olarak, devâm etdi. Muhammed aleyhisselâmın bütün dedeleri, \nbunun soyundan ve bunun dîninden idi. İsmâ’îl aleyhisselâmın ve vâlidesi hazret-i \nHâcerin, Kâ’be-i muazzamaşimâl dıvarı önündeki Hatîm denilen yerde medfûn \noldukları, (Dürr-ül-muhtâr)da yazılıdır.", "gectigiMaddeler": ["1/68", "1/97", "2/20", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Ağa", "slug": "ismail-aga", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Üçüncü Ahmed hân zemâ-\nnında, ellialtıncı Şeyh-ul-islâm idi. Alâiyyelidir. Binyüzotuzaltıda [1136], Fâtih \nÇarşambasında (İsmâ’îl ağa câmi’i) ni yapdırmışdır. Binyüzotuzyedide 1137 [m. \n1724] de vefât etmişdir. Câmi’in yanındadır. İsmâ’îl ağa mescidi, iki kat olup, eni, \nboyu ve yüksekliği Kâ’benin eni, boyu ve yüksekliği kadardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl bin Abdülganî", "slug": "ismail-bin-abdulgani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nablüslüdür. \nÖnce Şâfi’î idi. Sonra Hanefî oldu. 1062 [m. 1652] de vefât etdi. Hanefîde oniki cild \n(Dürerşerhi) ve Şâfi’îde, İbni Hacerin (Tuhfe)sine hâşiyesi vardır.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Hakkı", "slug": "ismail-hakki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliyyeden, Cel-\nvetî meşâyıhındandır. 1063 [m. 1652] de Aydosda tevellüd edip, Üsküdarda Atpa-\nzarında Osmân efendiden hilâfet aldı. 1137 [m. 1725] de Bursada vefât etdi. Çok \nkitâb yazdı. (Kenz-i mahfî) si meşhûrdur. Tütün içmeğe önceleri harâm diyordu. \n– 1123 –\nSonra, mubâh dedi. (Rûh-ul-beyân) tefsîri on cild olup, Beyrutda ve İstanbulda 1389 \nda basdırılmışdır. Üsküdârdaki Ahmediyye câmi’inde Cum’a vâ’ ızı idi. Bu câmi’i \n[1134] de tersâne emîni Ahmed ağa yapdırmışdır.", "gectigiMaddeler": ["2/15", "2/22", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îlisfehânî", "slug": "ismailisfehani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İsmâ’îl bin Muham-\nmed Kavvâmüssünne, hadîs âlimidir. [459] da tevellüd, 535 [m. 1141] senesinde \nvefât etdi. Çok kitâb yazdı.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Mer'aşî", "slug": "ismail-merasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Fıkh âlimlerindendir. \nTütün içmek harâm değildir derdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Nablüsî", "slug": "ismail-nablusi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dörtyüzdoksandoku-\nzuncu [499] sırada İsmâ’îl bin Abdülganî ismine bakınız!", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Pâşa", "slug": "ismail-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Bağdâdlıdır. Jandarma \ngenel kumandanlığı ikincişu’be müdîrliğinden emekli iken 1339 [m. 1921] da vefât \netdi. (Keşf-üz-zünûn) kitâbına iki zeyl [ek] yapmış, ayrıca iki cild \n(Esmâ-ül-müel-\nlifîn) kitâbını yazmışdır. Hepsi arabîdir. 1941-1955 de İstanbulda basılmışdırlar. \nBunlar için otuz seneden fazla çalışmışdır.", "gectigiMaddeler": ["1/7"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Rûmî", "slug": "ismail-rumi", "unvan": "", "kategori": "diger", "biyografi": "576. cı sırada Mahmûd Hân-II ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İsmâ'îl Sivâsî", "slug": "ismail-sivasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şeyh Şemseddîn-i Sivâsî-\nnin kardeşinin torunudur. 1048 [m. 1639] senesinde vefât etdi.", "gectigiMaddeler": ["1/90"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İşbîlî", "slug": "isbili", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdülhak, Endülüsde Mâlikî âlimle-\nrindendir. [510] da tevellüd, 582 [m. 1187] senesinde vefât etdi.", "gectigiMaddeler": ["3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "İtkanî", "slug": "itkani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Lutfullah bin Emîr Ömer, Hanefî \nfıkh âlimlerindendir. [685] de tevellüd, 758 [m. 1356] de Mısrda Kâhirede vefât \netdi. (Gâyet-ül-beyân) adındaki (Hidâye) şerhı meşhûrdur.", "gectigiMaddeler": ["1/54"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Itrî", "slug": "itri", "unvan": "", "kategori": "diger", "biyografi": "Mustafâ Itrî efendi, sultân üçüncü Muhammed hân zemânında \nbulunan mûsikî meraklısı idi. Tekbîri segâh makâmına besteledi. 1039 [m. 1630] \nsenesinde vefât etdi. Edirnekapıda Eyyûb sultâna inen yolun sağındadır.", "gectigiMaddeler": ["2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâ'b", "slug": "kab", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Resûlullahın sekizinci babasıdır. Lüvey’in oğlu ve Gâlibin torunudur. İlk olarak Cum’a günleri Kureyşlileri toplayıp hutbe okuyan budur. Kendi soyundan Peygamber geleceğini söyler, ona yetişeceklerin îmân etmelerini emr ederdi. Söylediğişi’r ve sözleri meşhûrdur.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâ'b", "slug": "kab-2", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmdandır.", "gectigiMaddeler": ["2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ka'b-Ül-Ahbâr", "slug": "kab-ul-ahbar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâbi’îndendir. Yemen \nyehûdîsi iken îmâna geldi. Tevrât âlimi idi. 32 [m. 652] senesinde Humusda vefât \netdi.", "gectigiMaddeler": ["2/48"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî Adud", "slug": "kadi-adud", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrahmân bin Ahmed \nAdud-üd-dîn-i Îcî [700] senesinde Şîrâzda Îc kasabasında tevellüd, Fâris vilâyetin-\nde kâdî [hâkim] oldu. 756 [m. 1354] da vefât etdi. (Mevâkıf) kitâbını seyyid Şerîf-i \nCürcânîşerh etdi. Hasen Çelebî, Kara Kemâl ve Celâleddîn-i Devânî ve Abdül-\nhakîm-i Siyalkûtî birer hâşiye yapdı. Kendi (Mevâkıf)ını kendisi kısaltarak, \n(Cevâhir) adını vermişdir. Şemseddîn-i Fenârî, (Cevâhir)işerh etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî Bedrüddîn Muhammed", "slug": "kadi-bedruddin-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdî \nBedrüddîn Muhammed bin Abdüllah-i Şeblî, Trablusda ve Şâmda Hanefî kâdîsı \nidi. Yediyüzaltmışdokuz 769 [m. 1367] da vefât etdi. (Akâm-ül-mercân) ve başka \nkitâbları vardır.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî Hân", "slug": "kadi-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hasen bin Mensûr Fergânî, 592 \n[m. 1196] de vefât etdi. Şerhleri ve (Hâniyye) isminde bir fetvâ kitâbı meşhûrdur. \nHanefî fıkh âlimidir. Fetâvâsı çok kıymetli olup, (Fetâvâyı Hâniyye) ve (Mecmû’a-\nyı Hâniyye) de denir. 1310 hicrî senesinde Mısrda basılan (Fetâvâ-yı Hindiyye)nin \nkenârında basılmışdır. 1393 [m. 1973] de ofset tarîkı ile yeniden basılmışdır. 133, \n247, 282, 444, 768, 1009, 1028, 1032. \n– 1124 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî Iyâd", "slug": "kadi-iyad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Mûsâdır. Mâlikîdir. \nHadîs âlimidir. [476] da tevellüd, 544 [m. 1150] de Merrâküşde vefât etdi. Çok \nkitâb yazdı. (Meşârik-ul-envâr) adındaki hadîs kitâbı ile (Şifâ) kitâbı pek kıymet-\nlidir. Çeşidlişerhleri yapılmışdır.", "gectigiMaddeler": ["1/71", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî-Zâde", "slug": "kadi-zade", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed Emîn bin Abdüllah, [1133] de tevellüd, 1197 [m. 1783] senesinde vefât etdi. (Birgivî vasıyyetnâmesi)nişerh etdi. (Âmentüşerhı) olan (Ferâid) kitâbını yazdı. İkisi de çok kıymetlidir.", "gectigiMaddeler": ["1/46", "1/54", "1/58", "1/98", "2/15", "2/17", "2/40", "2/53", "2/54", "3/28", "3/58", "3/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî-Zâde", "slug": "kadi-zade-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemseddîn Ahmed bin Mahmûd efendi, Osmânlışeyh-ul-islâmlarının onaltıncısıdır. Dokuzyüzonsekizde tevellüd, dokuzyüzseksensekiz 988 [m. 1580] senesinde vefât etdi. Kabri küçük Karamandadır. Çivi-zâdeden ve Ebüssü’ûd efendiden okudu. (Hidâye) ş erhı olan (Feth-ul-kadîr)e tekmilesi, (Miftâh) ve (Tecrîd) şerhlerine hâşiyeleri çok kıymetlidir. (Feth-ul-kadîr), (Vekâlet) bahsine kadar olup, sonra (Tekmile) başlamakdadır. İkisi birlikde sekiz cild hâlinde 1318 de Mısrda basılmış ve 1388 [m. 1968] de Beyrutda foto-kopisi yapılmışdır. Kenârına da, (İnâye) kitâbı ve Sa’dî Çelebînin buna yapdığı hâşiye basılmışdır.", "gectigiMaddeler": ["3/19"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâdî-Zâde", "slug": "kadi-zade-3", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Ârif efendi, 1173 \n[m. 1759] senesinde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Karabaş Efendi", "slug": "karabas-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Karabaş Tecvîd kitâ-\nbının sâhibi olarak üç kişi vardır. Bunlardan birincisi, Kastamonilişeyh Şa’bân-ı \nVelî silsilesinden Alî efendidir. Bindoksanyedi 1097 [m. 1685] senesinde vefât \netmişdir. İkincisi, Ahmed efendi, Eyyûbde Şâh sultân türbesinin Eyyûb tarafında, \nDefterdâr caddesi üzerindeki türbesindedir. Başvekîl Adnan Menderes, Câmi’leri \nve türbeleri ta’mîr ederken, bunu da yenilemişdir. Üçüncüsü, Abdürrahmân Kara-\nbaş efendidir. Karagümrükde Karabaş mescidini yapdırdı. Dokuzyüzkırk 940 [m. \n1534] senesinde vefât etdi. Mihrâbı önündeki türbesindedir. Bu mescid yanında, \nÖküz Mehmed pâşa câmi’i vardı. Câmi’ yapılırken, taş taşıyan arabanın öküzü \nsakatlanınca, pâşa yerine girip arabayı çekdiği için, bu ismleşeref duymuşdur. \nBirinci Ahmed hânın Sadr-ı a’zamı idi. 1029 [m. 1620] da Halebde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Karâfî", "slug": "karafi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şihâb-üddîn Ahmed bin İdrîs \nKarâfî, Mâlikî fıkh âlimidir. [626] da tevellüd ve 684 [m. 1285] de Mısrda vefât etdi. \nÇok kitâb yazdı.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Karamânî Kemâleddîn", "slug": "karamani-kemaleddin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İsmâ’îl \nKemâleddîn, Hanefî âlimlerindendir. 920 [m. 1514] de vefât etdi. (Şerh-i mevâkıf)a \nve (Vikâye)ye hâşiyesi ve (Beydâvî tefsîri)ne ve (Keşşâf)aşerhleri meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Karlayl [carlyle]", "slug": "karlayl-carlyle", "unvan": "", "kategori": "diger", "biyografi": "KARLAYL [Carlyle]: İngiliz yazarlarındandır. Thomas Karlayl 1210 [m. \n1795] da tevellüd, 1298 [m. 1881] de vefât etdi. Fransız ihtilâlini, büyük Friedrich \ntârîhini yazdı. (Kahramânlar ve kahramânlara saygı) kitâbında, Muhammed aley-\nhisselâmın üstünlüğünü, başarılarını uzun yazmakda ve çok övmekdedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Karlayl [carlyle]", "slug": "karlayl-carlyle-2", "unvan": "", "kategori": "diger", "biyografi": "KARLAYL [Carlyle]: İngiliz yazarlarındandır. Thomas Karlayl 1210 [m. \n1795] da tevellüd, 1298 [m. 1881] de vefât etdi. Fransız ihtilâlini, büyük Friedrich \ntârîhini yazdı. (Kahramânlar ve kahramânlara saygı) kitâbında, Muhammed aley-\nhisselâmın üstünlüğünü, başarılarını uzun yazmakda ve çok övmekdedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Karl Marx", "slug": "karl-marx", "unvan": "", "kategori": "diger", "biyografi": "Sosyalizm rejimini ortaya çıkartan bir Alman yehûdîsi-\ndir. 1233 [m. 1818] de tevellüd etdi. 1300 [m. 1883] de öldü. Sosyalizm, bir iktisâdî \nmetod diyerek kuruldu. Tatbîkâtde tiranlığa, diktatörlüğe döndü. Komünistliğe \nyol açdı. Sosyalizm, işçinin, çiftçinin doymasını sağlamadı. Şarlatanların, nutk \nçekenlerin, akademik aydınların yüksek mevkı’, bol ma’âş almalarına yaradı. \nBunlar da dizgini ellerinden kaçırmamak için, dîne, islâmiyyete, âileye, cem’ ıyyet-\nlerin cânlı kaynaklarına saldırdılar. İnsan haklarını yok etmek için çalışdılar. İlk \n– 1125 –\nsosyalist devlet olan Rusyada, kendi milletini ve bütün dünyâyı aldatmak ve kor-\nkutmak için, ağır sanâyı’, aya gitmek gibi ilerlemeler gösterilmekdedir. Fekat, ikti-\nsâdın asl gâyesi olan (sosyal refâh) elde edilememişdir. Sovyet rejimi, fezâya insan \nyollıyabilmek için, halkın günlük çorbasını azaltdı. Millete leş yidirdi. Doymıyan \nhalk, Gagarin ve Sputnikden önce, ne yiyeceğini, ne cezâya çarpdırılacağını düşün-\ndü. Ferdin her hakkını elinden alarak, herşeyi devlet kapitalizminin eline vermeği \nistiyen Marx usûlü, Rusyada da, liberalizmden alınan çârelerle değişdirildi. Sovyet \nidârecileri, Marksist iktisâdî gidişe (geri dön) emrini vermek zorunda kaldılar. Bir-\nçok fabrikalar, liberal nizâmda olduğu gibi, kâr esâsına göre çalışmağa başladı. [m. \n1917] den beri Moskova meydânlarında Marksın, Engelsin ve Leninin dev gibi \nheykellerinde putlaşan komünizm, silinmekde, yerini ilâhî hak dînin gösterdiği \nticâret ahkâmına yakın olan liberalizme bırakmakdadır. Hak gelmekde, bâtıl \nuzaklaşmakdadır.", "gectigiMaddeler": ["2/26", "3/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kârûn", "slug": "karun", "unvan": "", "kategori": "diger", "biyografi": "Mûsâ aleyhisselâmın ümmetinden ve akrabâsından idi. Ondan \nkimyâ öğrenerek, çok mal mülk sâhibi oldu. (Tevrât)ı pek iyi okurdu. Fakîr iken \niyi huylu idi. Zengin olunca kibrli oldu. Emr olunan zekâtı vermedi. Mûsâ benimle \nzinâ etdi demesi için bir kadına iki kese altın verdi. Kadın, herkesin arasında, \nAllahdan korkarak doğruyu söyledi. Kârûn, bütün malı ile yere batdı.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâsım", "slug": "kasim", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın üç oğlundan birincisidir. Bunun \niçin, Resûlullaha (Ebül-Kâsım) denildi. Nübüvvetden önce Mekkede dünyâya \ngeldi. Annesi, Hadîcet-ül-kübrâdır. Onyedi aylık iken vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâsım bin Muhammed", "slug": "kasim-bin-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr-i \nSıddîkın torunudur. (Reşehât)da diyor ki, (Îrândaki Sâsânî devletinin yirmidokuz \nhükümdârından sonuncusu, üçüncü Yezdecerdin orduları Kadsiye ve Nehâvendde \nmağlûb olunca, halîfe Ömer “radıyallahü teâlâ anh” esîrler arasında bulunanşâhın \nüç kızını, Hüseyn bin Alîye, Muhammed bin Ebû Bekre ve oğlu Abdüllaha verdi. \nBu üç câriyeden, Zeynel’âbidîn, Kâsım ve Sâlim tevellüd etdi.) Buradan, Kâsımın \n19. cu senede tevellüd etdiği anlaşılmakdadır. Tâbi’înin büyüklerinden, Medîne-i \nmünevveredeki yedi âlimdendir. Selmân- ı Fârisînin teveccühleri ile kemâle geldi. \n106 [m. 725] senesinde Mekke ile Medîne arasında Kudeyd denilen yerde vefât \netdi. İmâm-ı Ca’fer-i Sâdık hazretleri, bunun sohbetinden feyz aldı.", "gectigiMaddeler": ["1/31", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâsım Pâşa", "slug": "kasim-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kânûnî sultân Süleymân \nhânın serâyında terbiye olup, dokuzyüzyirmidokuz 929 [m. 1523]da Mısr vâlîsi \nolmuşdur. (Güzelce Kâsım Pâşa) câmi’ini yapdırmış, bunun için Halicin bu tarafı-\nna Kâsımpâşa adı verilmişdir. Üçüncü Ahmed hân zemânında ta’mîr edildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kastalânî", "slug": "kastalani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Ahmed bin Muham-\nmed Şihâbüddîn, Şâfi’î âlimlerindendir. 851 [m. 1448] de tevellüd, 923 [m. 1517] \nde Mısrda vefât etdi. Çok kitâb yazdı. (Mevâhib-i ledünniyye) si türkçeye terceme \nedilmiş [1313] ve 1392 [m. 1972] senelerinde İstanbulda basılmışdır.", "gectigiMaddeler": ["1/95", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâşânî", "slug": "kasani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr bin Mes’ûd Alâüddîn-i \nŞâşî, Türkistânda Kâşânda tevellüd, 587 [m. 1191] senesinde Halebde vefât etdi. \nHocası Alâüddîn Muhammed bin Ahmed Semerkandînin, (Tuhfe-tül-fükahâ) fıkh \nkitâbınışerh ederek (Bedâyı-us-sanâyı’ fî-tertîb-iş-şerâyı’) adını vermişdir. Bu kitâ-\nbı 1328 [m. 1910] senesinde Mısrda basılmışdır. Üç cilddir. Semerkandîye dâmâd \nolmuşdur.", "gectigiMaddeler": ["3/19"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kâtibçelebî", "slug": "katibcelebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mustafâ bin Abdüllah, bü -\nyük târîhcidir. Hâcı halîfe ismi ile meşhûrdur. 1017 [m. 1608] de İstanbulda tevel-\nlüd, 1067 [m. 1656] de vefât etdi. Kabri, Vefâdan Unkapanındaki Mahmûdiyye Köp-\nrüsüne inen büyük caddenin sağ kenârındadır. Târîh kitâbları ve (Keşf-üz-zü -\nnûn)u çok kıymetlidir. (Keşf-üz-zünûn)da onbine yakın islâm kitâbını ve yazarla-\n– 1126 –\nrını tanıtmakdadır. Mısrda, İstanbulda ve Almanyada basıldı. Lâtinceye de terce-\nme ve tab’ edildi. Arabîsi Beyrutda (Mekteb-üt-ticârî)de satılmakdadır.", "gectigiMaddeler": ["1/7"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kefevî", "slug": "kefevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hüseyn bin Rüstem, Mekkede \nHanefî kâdîsı idi. 1010 [m. 1601] da vefât etdi.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kehvâkî", "slug": "kehvaki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Kehvâkî fıkh âlim-\nlerinden idi. Tütün günâh değil buyurdu.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kelebî", "slug": "kelebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebün-Nasr Muhammed bin Sâib, \nTâbi’îndendir. 146 [m. 764] da Kûfede vefât etdi. Abdüllah bin Sebe’ ile çok soh-\nbet etdiğinden, tefsîri sağlam sayılmaz. Oğlu Hişâm ibnül-Kelbîşî’î idi.", "gectigiMaddeler": ["1/97", "2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kemâleddîn Muhammed", "slug": "kemaleddin-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Taşköprü \nzâde Muhammed bin Ahmed Usâm-üd-dîn, [959] da tevellüd, 1032 [m. 1623] de \nİstanbulda vefât etdi. (Mevdû’ât-ül-ulûm) tercemesi meşhûrdur.", "gectigiMaddeler": ["1/7"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kerderî", "slug": "kerderi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbn-ül-Bezzâz Muhammed bin \nMuhammed Kerderî, hanefî fıkh âlimidir. (Müncid) lügat kitâbında Bizzâz denil-\nmekdedir. Bursada molla Fenârî ile çok sohbet etdi. 827 [m. 1424] de vefât etdi. \n(Bezzâziyye) fetvâsı (Fetâvâ-yı Hindiyye) ile bir arada 1310 da ve 1393 [m. 1973] \nde Mısrda basılmışdır. (Menâkı\nb-i imâm-ı Ebî Hanîfe)si meşhûrdur.", "gectigiMaddeler": ["1/78", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kerhî", "slug": "kerhi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ubeydüllah bin Hüseyn Ebül-\nHasen, Hanefî fıkh âlimlerindendir. [260] da tevellüd, 340 [m. 952] senesinde Bağ-\ndâdda vefât etdi. (Câmi’us-sagîr), (Câmi’ul-kebîr) ve (Muhtasar) kitâbları çok kıy-\nmetlidir. (Muhtasar)ı Kudûrîşerh etmişdir.", "gectigiMaddeler": ["1/43", "2/16", "2/40"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kilâb", "slug": "kilab", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İsmi Hakîmdir. Resûlullahın altıncı \nbabasıdır. Mürrenin oğludur.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kilâ'î", "slug": "kilai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Süleymân bin Mûsâ, Mâlikî hadîs âli-\nmidir. 567 [m. 1172] de Gırnatada tevellüd, 634 [m. 1237] de cihâd ederkenşehîd \noldu. İmâm ve kâdî idi. Çok kitâb yazdı. (Misbâh-uz-zulâm fil-müstegîsîn bi-hay-\nril-enâm) kitâbını okuyan, İbni Teymiyyenin bozuk ve sapık düşüncelere aldana-\nrak doğru yoldan ayrıldığını iyi anlar.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kılınc Alî Pâşa", "slug": "kilinc-ali-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Üçüncü Murâd hân ve \nbabası zemânlarında kaptan- ı deryâ idi. Dokuzyüzseksensekiz 988 [m. 1580] de \nTophânede kendi adına câmi’ yapdı. 995 de vefât etdi. Câmi’i yanındadır. Birinci \nMahmûd hân bu câmi’ yanında 1145 [m. 1732] de güzel bir çeşme yapdı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kirmânî", "slug": "kirmani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Rükn-üd-dîn Ebû Bekr Muham-\nmed bin Abdürreşîd, Hanefî fıkh âlimidir. İshak-ı Kirmânî soyundan olup, Abdür-\nrahmân-ı Kirmânînin talebesidir. Beşyüzaltmışbeş 565 [m. 1169] senesinde vefât \netdi. (Cevâhir-ül-fetâvâ)sı meşhûrdur.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kisâî", "slug": "kisai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Hamza, kurrâ-i seb’a ya’nî \nyedi meşhûr hâfızdan biridir. Hârûn Reşîd ile Reyşehrinde iken 189 [m. 805] sene-\nsinde vefât etdi. Nahv ve lügat âlimi idi.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Klaudius", "slug": "klaudius", "unvan": "", "kategori": "diger", "biyografi": "İkinci Klaudius Roma imperatörlerindendir. Mîlâdın [215] \nsenesinde tevellüd, [m. 271] de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kopernik", "slug": "kopernik", "unvan": "", "kategori": "diger", "biyografi": "Polonyalı astronomi âlimidir. 877 [m. 1473] de Prusyada \ntevellüd, 949 [m. 1543] da vefât etdi. Fraynburgşehrinde papas idi. Dünyânın ve \ndiğer seyyârelerin güneş etrafında döndüğünü islâm kitâblarından okuyarak, isbât \netdiğinden, buna Kopernik Usûlü dediler. Beğenilmez diyerek, bunu çok zemân \naçıklıyamamışdır. Ömrünün sonlarında yazdı.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kostantin", "slug": "kostantin", "unvan": "", "kategori": "diger", "biyografi": "Avrupalılar buna Constantine derler. İstanbuldaki Roma \nimperatörlerinin birincisidir. Mîlâdın [274]. cü senesinde Sırbistânda Niş şehrin-\n– 1127 –\nde tevellüd etdi. m.306 da imperatör oldu. m.337 de vefât etdi. Yerine üç oğlun-\ndan ikincisi olan Kostans bizans imperatörü oldu ve m.361 de öldü. Ayasofya \ncami’ini 360 da bunun yapdırdığı söylenilmekde ise de bu, babasının yapdığını \ntevsi’ etmişdir. Büyük Kostantin Galyayı, ya’nî Fransayı, İngiltereyi, İtalyayı, Afri-\nkanınşimâlini, Yunânistânı aldı. Bayrağına haç resmi koydu. m.325 de İznikde \nüçyüzonsekiz papas toplayıp, yeni İncîl yazdırdı. Îsâ aleyhisselâmın dînine sonra-\ndan karışdırılmış olan, Eflâtunun ortaya çıkarmış olduğu teslîs [Trinite] inancını \nbu yeni İncîle de koydurdu. Bu dinde teslîs bulunmadığını, Allahın bir olduğunu \nsöyliyen Aryüsü aforoz etdirdi. Doğru olan Barnabas İncîlini yasak etdi. Noel \ngecesini bayram i’lân etdi. m.330 da Bizans kasabası\nnı büyültüp, Kostantîniyye \nismini verdi. Sonradan İstanbul, İstambol, İslâmbol, Derseâdet ismleri de verilmiş-\ndir. İstanbulşehrini (Sûr) denilen büyük bir dıvar ile çevirdi. Sonra gelen kayserler \ntarafından ta’mîr edilmişdir. Kara tarafında yedi, deniz tarafında dokuz kapusu \nvardır. Yedi Kule zındanları, sur ile birlikde yapılmışdır. Asrlar boyunca, binlerce \nhıristiyana, zulm, işkence yapılmış olan bu zındanlar, Fâtih tarafından kapatıldı. \nHiçbir pâdişâh zemânında kullanılmadı. Osmânlı sultânlarının onaltıncısı olan \nikinci Osmân bin birinci Ahmed hân, onsekiz yaşında iken, 1031 [m. 1622] senesin-\nde bu zındandaşehîd edilmişdir. Şehîd eden sadr- ı a’zam Bosnalı Dâvüd pâşa da, \nbir sene sonra bu zındanda katl edilip, Akserâydaki Murâd pâşa câmi’ine defn \nedilmişdir.", "gectigiMaddeler": ["1/24", "1/25", "1/30", "2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kudûrî", "slug": "kuduri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül-Hüseyn Ahmed bin Muham-\nmed Bağdâdî, hanefî fıkh âlimlerindendir. 362 [m. 973] de tevellüd, 428 [m. 1037] \nde Bağdâdda vefât etdi. (Muhtasar) kitâbı meşhûrdur. Şerhleri ve türkçesi vardır.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kudsî", "slug": "kudsi", "unvan": "", "kategori": "diger", "biyografi": "Altıyüzonyedinci [617] sırada Molla Kudsî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kuhistânî", "slug": "kuhistani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemseddîn Muhammed bin \nHüsâmeddîn, Hanefî fıkh âlimi ve Buhârâ müftîsi idi. 962 [m. 1555] de Buhârâda \nvefât etdi. (Câmi’ur-rumûz) adındaki (Nikâye) şerhi ve (Câmi’ul-mebânî) adında-\nki fârisî (Fıkh-ı Gîdânî) şerhı meşhûrdur.", "gectigiMaddeler": ["2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kureyş", "slug": "kureys", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kureyş, Resûlullahın onbirinci \nbabası olan Fihrin ismidir. Nûh aleyhisselâmdan sonra Arabistân yarım adasında \nyerleşenlere (Arab-ı bâide) denir. Âd, Semûd ve Amâlika bunlardandır. Hûd aley-\nhisselâm Âd kavmine, Sâlih aleyhisselâm Semûd kavmine gelmişlerdir. Hepsi \n(Sâm) soyundandır. Bunlardan sonra, gelip Yemene yerleşen (Kahtân) evlâdları-\nna (Arab-ı âribe) denir. Bunlar Yemende (Himyer) devletini kurdu. Bu devlet \nçökünce, önce Habeşliler, sonra Îrânlılar Yemene vâlî ta’yîn etdiler. Etrâfa dağılan \nHimyerîlerden Medînede (Evs) ve (Hazrec) kabîleleri meydâna geldi. Şâm tarafı-\nna gelenler, (Gassân) devletini kurup hıristiyan oldular. Irâka gelenler (Hîre) dev-\nletini kurdu. İsmâ’îl aleyhisselâmın oniki evlâdının (Arab-ı âribe) ile karışmasın-\ndan (Arab-ı müsta’ribe) meydâna geldi. Arablar, islâmiyyetden sonra yabancılarla \nkarışdı. Lisânları değişerek (arab-ı müsta’cime) meydâna geldi. \nArab-ı müsta’ribeden (Benî Adnân) ve bunlar arasında da (Mudar) ve (Rebîa) \nkabîleleri meşhûr oldu. (Benî Mudar)dan (Kinâne), (Kureyş), (Hevâzîn), (Sakîf), \n(Temîm) ve (Müzeyne) kabîleleri meydâna geldi. Bunlardan (Kureyş) Mekkede \nyerleşmekle ayrıcaşeref kazandı. Kabîle reîsleri, mühim işlerde anlaşmak için, \nMekkede (Dâr-ün-nedve) denilen yerde toplanıp meşveret ederlerdi. \nKureyş kabîlesi de, (Hâşimî), (Emevî), (Nevfel), (Abdüddâr), (Esed), (Teym), \n(Mahzûm), (Adîy), (Cumah) ve (Sehm) adında on kola ayrılmışdı. Zemzem dağıt-\nmak ve Kâ’beyi ta’mîr ve tezyîn, Hâşimîlere, Kâ’be kapısını açmak, Abdüddâr \noğullarına, Ukâh denilen Kureyş sancağını taşımak Emevîlere, hac zemânı ziyâfet \nvermek Nevfel oğullarına, Dârünnedve reîsliği Benî Esede, mahkeme hâkimliği \n– 1128 –\nTeym oğullarına, asker toplamak Benî-Mahzûma, başka kabîlelerle görüşmek, an -\nlaşmak Adîy kabîlesine, (Ezlâm) denilen kur’a ve fal işleri Cumah kabîlesine, put-\nlara adak yapmak da Benî-Sehme mahsûs vazîfeler idi. Kureyşden Abbâs, Teym-\nden Ebû Bekr, Adîyden Ömer-ül-Fârûk, Mahzûmdan Hâlid bin Velîd, Umeyye-\nden Ebû Süfyân bu vazîfeleri yapıyorlardı. Teym, Mürrenin oğlu olup, hazret-i Ebû \nBekrin ceddidir. Adî, Kâ’b bin Lüvey oğlu olup, hazret-i Ömerin ceddidir. (Mah-\nzûm) kabîlesi, Mürrenin oğlu (Yakaza)dan meydâna gelmişdir.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kurtubî", "slug": "kurtubi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah Muhammed bin \nAhmed, Endülüs âlimlerinin büyüklerindendir. Ensâr- ı kirâm sülâlesindendir. 671 \n[m. 1272] de vefât etdi. Mâlikî mezhebi âlimlerindendir. (Câmi’ul-ahkâm) adındaki \ntefsîri ve birçok kıymetli eserleri vardır. Abdülvehhâb-ı Şa’rânî, bunun (Tezkire) kitâ-\nbını ihtisar etmiş, (Muhtasar) ismini vermişdir. 1302 [m. 1884] de Mısrda ve (Hakîkat \nKitâbevi) tarafından 1421 [m. 2000] de İstanbulda basılmışdır. Ebül-Abbâs Ahmed \nKurtubî, (Müslim) şârihi olup, 656 [m. 1258] da vefât etmişdir.", "gectigiMaddeler": ["1/39", "1/97", "2/53", "3/1"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kus bin Sa'îde", "slug": "kus-bin-saide", "unvan": "", "kategori": "diger", "biyografi": "İslâmiyyetden evvel Arabistânda bulunan hatîbler-\ndendir. Allahın bir olduğuna inanır. Herkesi İsmâ’îl aleyhisselâmın dînine çağırır-\ndı. Konuşurken kılınca veyâ bastona dayanırdı.", "gectigiMaddeler": ["1/91"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kusayy", "slug": "kusayy", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kilâbın oğludur. İsmi Mücem-\nmi’dir. Çünki, dağılmış olan Kureyşlileri toplayıp Mekkede bir kuvvet meydâna \ngetirdi ve bunun reîsi oldu. Kâ’benin hizmeti, İsmâ’îl oğullarından Cürhüm kabî-\nlesine ve sonra Huzâ’a kabîlesine geçmişdi. Kusayy, buşerefli vazîfeyi Huzâ’adan \naldı. (Dâr-ün-nedve) denilen danışma evini kurdu. Kusayyin Zühre ismindeki kar-\ndeşi soyundan Âmine hazretleri oldu.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kuşeyrî", "slug": "kuseyri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül-Kâsım Abdülkerîm bin \nHevâzın, 376 [m. 986] da tevellüd, 465 [m. 1072] de Nîşâpûrda vefât etdi. Şâfi’î âli-\nmidir. (Risâle-i Kuşeyrîyye)si 1379 [m. 1959] da Mısrda basılmışdır.", "gectigiMaddeler": ["3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kutb-ı Zemân", "slug": "kutb-i-zeman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Bendegî mahdûm-i cihâni-\nyân seyyid Celâl-i Buhârî, 707 de tevellüd, 785 [m. 1383] de Küceratın Ahmedâbâdşehrinde vefât etdi. Hindistânda Çeştiyye ve Sühreverdiyye Evliyâsının büyüklerin-\ndendir. Şeyh Nasîreddîn-i Mahmûd Dehlevînin halîfesidir. Bu da, Nizâmüddîn Evli-\nyânın halîfesidir. (Hazâne-i Celâlî)  kitâbı meşhûrdur. İmâm- ı Rabbânî \n(Mektûbât)ının ellidördüncü mektûbunda kitâbları tavsiye olunmakdadır. İmâm-ı \nRabbânînin altıncı ceddi imâm- ı Refî’uddînin ve Delhî sultânı Fîrûzşâh Tuglukun \nmürşidleridir. Hâl tercemesi, fârisî (Ahbâr-ül-ahyâr)da uzun yazılıdır. Fîrûzşâh \nismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Kutbüddîn-i İznîkî", "slug": "kutbuddin-i-izniki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMuhammed Rûmî, Hanefî fıkh âlimi ve tesavvuf büyüklerindendir. Tîmûr hân \nkendisine çok saygı göstermişdir. Sekizyüzyirmibir 821 [m. 1418] senesinde İznik-\nde vefât etdi. Türkçe (Râhat-ül-kulûb) kitâbı Ayasofya, (Mukaddime-tüs-salât) ı \nNûr-ı Osmâniyye kütübhânesindedir. Tefsîri ve başka eserleri de vardır. Oğlu \nMuhammed İznîkî de derin âlim idi. Çok kitâb yazdı. Sekizyüzseksenbeş 885 [m. \n1480]de Edirnede vefât etdi. Meşhûr (Mürşid-ül-müteehhilîn) kitâbını ve (Mızrak-\nlı ilmihâl) de denilen (Miftâh-ül-Cennet) kitâbını oğlu yazmışdır.", "gectigiMaddeler": ["2/36"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lakânî", "slug": "lakani", "unvan": "", "kategori": "diger", "biyografi": "227. ci sırada Ebû Bekr bin Alî ismine bakınız! Muhammed \nNâsır Lakânî mâlikî 958 [m. 1551] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lamarck", "slug": "lamarck", "unvan": "", "kategori": "diger", "biyografi": "Fransız doktorudur. 1157 [m. 1744] de tevellüd, 1244 [m. 1829] de vefât etdi. Cânlıların basîtden mükemmele doğru değişdiğini ilk yazan budur.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lâmi'î", "slug": "lamii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Bursada tevellüd ve 938 de orada \nvefât etdi. (Şevâhid-ün-nübüvve) ön sözüne bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lawe", "slug": "lawe", "unvan": "", "kategori": "diger", "biyografi": "Alman fizikçisidir. 1269 [m. 1852] da tevellüd etdi. Işığın dalga – 1129 – boylarının ayrılmasını [tayf] buldu. [m. 1914] de Nobel mükâfatı aldı.", "gectigiMaddeler": ["2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lavoisier", "slug": "lavoisier", "unvan": "", "kategori": "diger", "biyografi": "Fransız kimyâgeridir. 1156 [m. 1743] da tevellüd etdi. \n1209 [m. 1794] da cumhûriyyetci ihtilâlciler tarafından giyotinle başı kesildi. \nKimyâ reaksiyonlarında, maddenin yok olmadığını ve yaratılmadığını, insanların \nbirşeyi yok edemiyeceklerini ve yaratıcı olmadıklarını deney ile açıklamışdır.", "gectigiMaddeler": ["2/30", "2/67", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lemoine ve Gerard", "slug": "lemoine-ve-gerard", "unvan": "", "kategori": "diger", "biyografi": "LEMOİNE ve GERARD: İki Fransız doktorudur. Birlikde (Formulaire \nmedicales) doktorluk kitâbını yazdılar.", "gectigiMaddeler": ["2/46"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lenin", "slug": "lenin", "unvan": "", "kategori": "diger", "biyografi": "Vladimir Lenin, Rusyadaki biricik siyâsî parti olan komünist \npartisinin kurucusudur. Karl Marx’ ın ortaya koyduğu sosyalist fikrlerin ilk tatbik-\ncisidir. 1286 [m. 1870] da tevellüd, 1342 [m. 1924] de vefât etdi. Rus tatârıdır. [m. \n1900] den beri Rusyada sınıf kavgalarını hâzırladı. [m. 1917] de Alman orduları \nRusyaya girince, Stalin ile birlikde bolşevik ihtilâlini çıkardı. Komünist idâresini \nkurdu. Ölünciye kadar kan dökdü. Lenine göre komünizmin başarılı olması için, \nkullanacağı birinci vâsıta (yalan) söylemek, aldatmakdır. Ne kadar büyük yalan \nsöylerseniz, o kadar muvaffak olmuş sayılırsınız demişdir. Çok yalancı ve o kadar \nda çok zâlim ve kan kusdurucu idi. Yedi senelik iktidârı içinde, otuzikimilyon insa-\nnın cânına kıydı. 2 Aralık 1917 de, Stalinle birlikde, Rusyadaki müslimânlara (Çar-\nlar ve zâlimler tarafından dinleri tahkîr edilen müslimânlar! Dîninizin ve kültür \nmüesseselerinizin serbest olduğunu bildiriyoruz) dedi. Anayasaya da din ve vicdân \nhürriyyetini koydu. Hâlbuki, kitâblarında, (Din ile mücâdele edeceğiz. Dinleri yok \netmek materyalizmin, marksizmin alfabesidir) diyordu. Ateistler birliğini kurdu. \nLeninizm denilen, din düşmanlığı, önce yalan ve yaldızlı sözlerle aldatmak, sonra \nzulm ve işkence ile yok etmek prensibine dayanmakdadır.", "gectigiMaddeler": ["2/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lokman Hakîm", "slug": "lokman-hakim", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Peygamber veyâ Velî-\ndir. Dâvüd “aleyhisselâm” zemânında idi. Arabistânın Ummân tarafında idi. Ahlâ-\nkî sözleri meşhûrdur.", "gectigiMaddeler": ["1/43", "2/20", "2/53", "3/3", "3/21", "3/62"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lother Meyer", "slug": "lother-meyer", "unvan": "", "kategori": "diger", "biyografi": "Alman kimyâgeridir. 1245 [m. 1830] de tevellüd, \n1312 [m. 1895]de vefât etdi. Elementlerin periyodik sistemini bulanlardandır.", "gectigiMaddeler": ["2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lui [louis]", "slug": "lui-louis", "unvan": "", "kategori": "diger", "biyografi": "LU İ [LOU İS]: Fransa kralı yedinci Lui, altıncışişman Luinin oğludur. \n514 [m. 1120] de doğdu. 576 [m. 1180] da öldü. Vitrişehrini alınca, kiliseyi ateşe \nverdi. İçindeki binüçyüz kişiyi yakdı. Pişmân olup, buna karşılık, kendi askerlerini \nöldürdü.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Luka", "slug": "luka", "unvan": "", "kategori": "diger", "biyografi": "Antakyalı bir papasdır. Îsâ aleyhisselâmı görmedi. Göke çıkarıl-\ndıkdan sonra, yehûdî dönmesi olan Bolüs tarafından Îsevî dînine alınmışdır. Bolü-\nsün zehrli fikrleri ile aşılanarak, şimdi elde bulunan dört ( İncîl)den, en yanlışını \nyazmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lût", "slug": "lut", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Peygamberdir. İbrâhîm aleyhisselâmın kardeşinin \noğludur. Lût gölü yanında Sedumşehri halkına Peygamber oldu. Onları çirkin işle-\nrinden men’ etdi. Karısı da dinlemedi. Kendisişehrden çıkdı. Şehr yerin dibine \ngeçdi. Seksen yaşında Hicâzda vefât etdi. Yehûdîlerin ve hıristiyanların (Mukad-\ndes kitâb) dedikleri ve her memlekete yaymağa çalışdıkları kitâbın (Ahd-i atîk)  \nkısmındaki (Genesis) veyâ (Tekvîn)in ondokuzuncu bâbının otuzuncu ve sonraki \nâyetlerinde diyor ki, (Lutşehrden çıkıp iki kızı ile berâber dağda sâkin oldu. \nBüyük kızı küçüğe dedi ki, pederimiz ihtiyâr oldu. Yer yüzünde erkek dahî kalma-\ndı. Gel, pederimizeşerâb içirip, onun ile yatarak, pederimizden zürriyyet peydâ \nedelim. O gece pederineşerâb içirerek pederi ile yatdı. O dahî onu tanımadı. Erte-\nsi gece pederlerine yineşerâb içirdiler ve küçük kız onun ile yatdı. Lûtun iki kızı ba -\nbalarından hâmile oldular. Büyük kız oğluna (Muâb), küçük kız da oğluna (Amî) \nismini koydu. Muvâbî ve Amûnî denilen kimselerin cedleri bu iki çocukdur.) Ki -\ntâb-ı mukaddesin bu yazısı, açık bir fuhş hikâyesidir. Bu yazı, bugün, dünyânın \n– 1130 –\nher yerinde pornografi [müstehcen] neşriyyât sınıfına girer ve neşr edilmesi yasak-\nlanır. Kitâbı mukaddesde buna benzer dahâ birçok gayr-i ahlâkî bahsler vardır. \nİslâm âlimleri bunları bulup açıklıyarak, bugünki Tevrât ve İncîl denilen kitâbların \nAllah kelâmı olmadıklarını, sonradan insanlar tarafından değişdirmeler ve ilâveler \nyapılarak ortaya çıkarıldıklarını, bu sûretle de isbât etmişlerdir. Bu kıymetli islâm \nkitâblarından birkaçının ismleri, birinci kısm, 93. cü madde sonunda yazılıdır. Bun-\nlardan (Tuhfe-tül-erîb) arâbî ve (Mîzân-ül-mevâzîn) fârisî olup, İstanbulda, Hakî-\nkat Kitâbevi tarafından basdırılmışdır.", "gectigiMaddeler": ["1/54", "2/20", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Luther Martin", "slug": "luther-martin", "unvan": "", "kategori": "diger", "biyografi": "Alman papasıdır. Protestanlığı kurdu. 888 [m. \n1483] de tevellüd, 953 [m. 1546] de öldü. İtalyadaki papa onuncu Leon ile arası \naçıldı. Tel’în edildi. 931 [m. 1524] de Nürnbergde protestanlığı i’lân etdi. Çok kitâ-\nbı vardır. İslâmiyyete karşı çirkin hücûmları vardır. Katoliklerle protestanlar bir-\nbirlerine düşmandırlar.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Lutfullah Efendi", "slug": "lutfullah-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Lutfullah bin \nAbdüllah, Kastamonilidir. Latîfî ismi ile meşhûrdur. 990 [m. 1582] da vefât etdi. \n(Tezkire-tüş-şu’ara) kitâbı basılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahdûm-i Cihâniyân", "slug": "mahdum-i-cihaniyan", "unvan": "", "kategori": "diger", "biyografi": "(Kutb-i zemân) ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd bin Muhammed Buhârî", "slug": "mahmud-bin-muhammed-buhari-rahmetullahi-teala-ale", "unvan": "", "kategori": "alim", "biyografi": "Ebülmehâmid Mahmûd bin Muhammed bin Dâvüd Buhârî, fıkh âlimlerindendir. 671 [m. 1272] de Buhârâda vefât etdi. (Hakâyık-i manzûme) kitâbı meşhûrdur. Bu kitâb, (Manzûme-i Nesefî) şerhı olup iki cilddir. Fıkh kitâbıdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd bin Sadr-Ü Ş-Şerî'a", "slug": "mahmud-bin-sadr-u-s-seria-rahmetullahi-teala-al", "unvan": "", "kategori": "alim", "biyografi": "Yüzseksenikinci [182] sırada Burhân-üş-şerî’a ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Buhârî", "slug": "mahmud-buhari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Burhâneddîn Mah-\nmûd bin Tâc-üd-dîn Ahmed bin Abdül’azîz Buhârî, Hanefî âlimlerindendir. 551 \n[m. 1156] de tevellüd, 616 [m. 1219] daşehîd oldu. (Tecrîd), (Muhît-i Burhânî), \n(Zahîre), (Fetâvâ-i Burhânî) ve (Vâkı’ât) kitâbları meşhûrdur.", "gectigiMaddeler": ["2/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Gaznevî", "slug": "mahmud-gaznevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Sübektekin, \nBuhârâdaki Sâmânî devletinin Horâsândaki vâlîsinin kölesi iken, vâlî ölünce, yerine \nvâlî oldu. Sultân Mahmûd 357 [m. 967] de tevellüd etdi. Horâsân vâlîsi oldu. Babası \nölünce, 387 [m. 997] de hükûmet kurdu. Türkistânı, Irâkın bir kısmını, Lâhoru, Del-\nhîyi aldı. Çok kiliseleri câmi’ yapdı. Hindûların hazînelerini Haremeyn-işerîfeyne \n[Mekkeye ve Medîneye] hediyye etdi. Berehmenlerin, kadınların, kocalarının cenâ-\nzesi ile birlikde, diri diri yakılması, ölülerin nehre atılması gibi, insanlığa yakışmayan \nâdetlerini yasak etdi. Âlimleri, edîbleri severdi. Çok kitâb yazdırdı. Firdevsînin (Şâh-\nnâme)si bunlardan biridir. Ehl-i sünnet âlimleri yetişdirdi. 421 [m. 1030] de Gaznede \nvefât etdi. Devleti 543 [m. 1148] senesine kadar devâm etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Hân II", "slug": "mahmud-han-ii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin dok-\nsanbeşincisi ve Osmânlı pâdişâhlarının otuzuncusudur. Birinci Abdülhamîd hânın \noğlu, sultân Abdülmecîd hânın babasıdır. 1199 [m. 1785] de tevellüd, 1255 [m. 1839] \nde vefât etdi. 1223 [m. 1808] de halîfe oldu. Yeniçerileri kaldırdı. Vehhâbîleri Hicâz-\ndan çıkardı. Harbiyye ve tıbbiyye-i mülkiyye mekteblerini vücûde getirdi. 1241 [m. \n1826] de Tophânede Nusratiyye câmi’ini yapdırdı. 1244 [m. 1828] de Bâyezîdde \nEski serây bağçesine yangın kulesi yapdırdı. 1253 [m. 1837] de Unkapanı ile Azap-\nkapı arasında (Mahmûdiyye) köprüsünü yapdırdı. 1247 [m. 1831] de İstanbulda ilk \ngazete çıkarıldı. Dünyâda ilk gazete 1051 [m. 1641] de çıkarıldı. 1253 [m. 1837] de \nmâliye nezâretini kurdu. 1254 [m. 1838] de karantina vücûde getirdi. Bağçekapıda \n(Hidâyet câmi’i), Üsküdârda Şemsi pâşa câmi’i yanında, 1232 [m. 1816] de (Adliye) \ncâmi’ini, yağlı boyalı ahşâb Beğlerbeyi ve Çırağan serâylarını yapdırdı. 1235 [m. 1819] \nde hazret-i Hâlidin türbesini ta’mîr etdi. Sandûkası pûşîdesi üzerindeki kendi el ya -\nzılarıdır. 1241 [m. 1825] de hurûfî tekkelerini kapatdı. 1235 [m. 1819] de Beyoğlun -\n– 1131 –\nda Galata-serây lise binâsını yapdırdı. Burası 1250 [m. 1834] de Tıbbiyye mektebi \nyapıldı ise de, 1266 [m. 1850] da yandı. 1243 [m. 1827] de (Tıbbiyye-işâhâne) yap-\ndırdı. Arnavutköy sâhilinde (Tevfîkiyye) câmi’ini yapdırdı. Çeşidli yerlerde çeşme-\nler yapdırıldı. Tophânede Kâdirî câmi’ ve tekkesini Tosyalı İsmâ’îl Rûmî yapdı ve \n1053 [m. 1644] de vefât etdi. İkinci Mahmûd hân 1239 [m. 1823] da yeniden yapdı. \nTürbesi Çenberlitaşdadır.", "gectigiMaddeler": ["2/17", "2/22", "2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Hüdâyî", "slug": "mahmud-hudayi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Azîz Mahmûd Hüdâ-\nyî efendi, Celvetiyye meşâyıhindendir. Koçhisârlıdır. Bursada, hâcı Bayram-ı Velî-\nnin halîfelerinden, Muhammed Üftâde hazretlerinden feyz aldı. 1007 de Üsküdâr-\nda câmi’ ve tekke yapdı. Dördüncü Murâd hân tahta çıkınca Eyyûbde kılıncını \nHüdâyî efendi takdı. 1038 [m. 1628] de vefât etdi. Tekkesi yanındaki türbesinde-\ndir. Üftâde efendi 989 [m. 1581] da Bursada vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûdincirfagnevî", "slug": "mahmudincirfagnevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm âlimle-\nrinin büyüklerinden bir ferd-i kâmildir. Buhârânın Fagne köyünde tevellüd edip, \nAkbenî nâhiyesinde yerleşdi. Mi’mârlık ile geçinirdi. Yediyüzonbeş 715 [m. 1315] \nde vefât etdiği (Sebe’ul-esrâr) ve (Tâc-ül-asfiyâ)da yazılıdır.", "gectigiMaddeler": ["2/52", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Kirmânî", "slug": "mahmud-kirmani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâc-ül-Kurrâ Mah-\nmûd bin Hamza Kirmânî 500 [m. 1106] senesinde vefât etdi.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd-i Kürd-i Şeyhânî", "slug": "mahmud-i-kurd-i-seyhani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "(Câmi’u \nkerâmât-i Evliyâ) da diyor ki, (Mahmûd-i Kürdî, Medîneye yerleşdi. Abdülganî \nNablusî diyor ki, (1205 [m. 1790] senesinde Medînede Mahmûd-i Kürdîyi gördüm. \nBeni evine götürdü. Uyanık iken Resûlullahı “sallallahü aleyhi ve sellem” çok gör-\ndüm dedi. Kıymetli sözlerinden ve güzel hâllerinden doğru söylediğini anladım.) \nUykuda iken de, uyanık iken de Resûlullahın “sallallahü aleyhi ve sellem” görül-\ndüğünü ve görenleri (Se’âdet-üd-dâreyn) kitâbında uzun bildirdim).", "gectigiMaddeler": ["3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Nûreddîn Zengî", "slug": "mahmud-nureddin-zengi", "unvan": "", "kategori": "diger", "biyografi": "Mahmûd Nûreddîn Zengî, Haleb sul-\ntânı idi. 569 [m. 1173] de vefât etdi. Salâhuddîn-i Eyyûbî, bunun kumandanlarından \nidi. Şâmda Eyyûbî devletini kurmuş, 589 [m. 1193] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Pâşa", "slug": "mahmud-pasa", "unvan": "", "kategori": "diger", "biyografi": "Fâtih sultân Muhammed zemânında iki def’a sadr- ı \na’zâm olmuşdur. Nûr-i Osmâniyyede câmi’ ile hamâm ve yokuşda çarşısı vardır. \nSofyada da büyük bir câmi’i vardır. 878 [m. 1473] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mahmûd Sâminî", "slug": "mahmud-samini", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî Septînin sohbetin-\nde kemâle gelmişdir. Alî Septînin İcâzetnâmesi Mahmûd Sâhib tarafından hâzırla-\nnıp mevlânâ Hâlid tarafından tasdîk edilerek, Abdüllah-i Mekkî ile kendisine gön-\nderilmişdir. Mahmûd Sâminî, seyyiddir. Palu kasabasının Hun köyünde tevellüd \nve 1313 [m. 1895] senesinde Paluda vefât etdi. Kabri Murâd suyu kenârındadır. \nŞâfi’î mezhebinde ve tesavvufda mütehassıs idi. Ârif-i billah idi. Alî Septîye onüç \nsene hizmet yapdı. Tütün içerdi. Birisi buna, kalbinden i’tirâz edince, (Bizim çubu-\nğumuzu düşüneceğine, Allahü teâlâyı zikr et. Başka birşey düşünme!) buyurdu. \nYirmiye yakın ârif yetişdirdi. Bunlardan Harputlu Osmân Bedreddîn efendi ve o \nzemân Erzurumun kazâsı olan Kiğı kasabasında hâcı Yûsüf efendi ile oğlu Muham-\nmed efendi ve Kiğı müftîsi Muhammed Nûreddîn efendi meşhûrdur. Nûreddîn \nefendi [m. 1964] yılında Antalyada vefât etdi. Alî Septî 1287 [m. 1870] de Paluda \nvefât etdi. Kabri bir tepede mescidinin yanındadır. Bunun torunu Sa’îd efendi 1926 \nda Diyârıbekrde vefât etdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mâhpeyker Sultân", "slug": "mahpeyker-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Sultân Ahmed \nhânın zevcesi ve sultân dördüncü Murâd ile Sultân İbrâhîmin vâlidesidir. \n(Kösem sultân) da denir. 1000 [m. 1592] de tevellüd, 1061 [m. 1651] deşehîd edil-\ndi. Hüsn-i cemâli, aklı ve zekâsı ve hayrât ve hasenâtı ile meşhûr sâliha ve afîfe \nbir sultân idi. Yeni câmi’in temelini atdı. Çarşambadaki (Vâlide medresesi mescidi) \n– 1132 –\nve 1050 [m. 1640] de Üsküdârda Çinili câmi’ini yapdırdı. Çakmakcılar yokuşunda \nbüyük vâlide hânı ile içindeki mescid de, bunun eseridir. Rumelinde milyonlar \ndeğerinde vakfları ve hayrâtı vardır. Otuz sene, devletin idâresinde hizmetleri \noldu. Âsîler veşakîler tarafından serâydaşehîd edildi. Sultân Ahmed türbesinde-\ndir. Sultân dördüncü Murâdın kızı Safiyye sultân da bu türbededir. Hayrât ve \nhasenâtı ile millete hizmetleri (Naîmâ Târîhi) nde uzun yazılıdır. 1033 [m. 1623] \nde, Anadolu kavağı câmi’ini yapdırmışdır. Bu mescidşimdi gazinodur. İki kava-\nğın kal’aları da 1033 [m. 1623] de yapılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Makdonyus", "slug": "makdonyus", "unvan": "", "kategori": "diger", "biyografi": "Papas idi. Îsâ aleyhisselâma tapılmaz. O mahlûkdur, \ndiyordu. Mîlâdın [381]. ci senesinde İstanbulda kurulan ikinci meclisde, tel’în edildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mâlik", "slug": "malik", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın onikinci babasıdır. Nadrın oğludur. Nadr, altun \ndemekdir. Nadrın ismi Kaysdır. Nadr, Kinânenin oğludur.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mâlik bin Dînâr", "slug": "malik-bin-dinar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Âlim ve velî idi. 131 \n[m. 748] senesinde Basrada vefât etdi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mâlik bin Enes", "slug": "malik-bin-enes", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah Mâlik bin \nEnes bin Mâlik bin Ebî Âmir bin Umeyr Teymî Esbahî Humeyrî, Cennet ile müj-\ndelenmiş olan (Ehl-i sünnet vel-cemâ’at) in dört büyük mezhebinden biri olan \n(Mâlikî) mezhebinin reîsidir. Doksan [90] senesinde Medînede tevellüd, 179 [m. \n795] da orada vefât etdiği (İbni Âbidîn) mukaddemesinde yazılıdır. Bir hadîs-işerîf \nokumak için abdest alır, edeble diz çökerdi. Medînede hayvana binmezdi. Haksız \nbir fetvâyı vermediği için, yetmiş kırbaç vuruldu. Abdesti sık bozulan hastalar ve \nihtiyârlar için ve necâsetden tahâret için çok kolaylık gösterdiğinden, diğer üç mez-\nhebde olan müslimânlar, Mâlikî mezhebini de taklîd ederek, ibâdetlerini râhatlıkla \nyapmakdadırlar. (Muvattâ) adındaki hadîs kitâbı çok kıymetlidir. 50, 125, 132, 159, \n172, 251, 288, 423, 465, 466, 467, 575, 783, 881, 1009, 1062, 1077, 1098, 1175, 1195. \n— MANASTIRLI İSMÂ’ÎL HAKKI: Ehl-i sünnet âlimi olduğu meşhûr ise de, \nsinsi bir mason idi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Marko", "slug": "marko", "unvan": "", "kategori": "diger", "biyografi": "St. Marc, dört (İncîl)den birini yazmışdır. Îsâ “aleyhisselâm” \ngöke çıkarıldıkdan sonra Îsevî oldu. Petrosdan işitdiklerini Romada Yunanca yaz-\nmış, bu yazılarına (İncîl) denilmişdir. [68] senesinde Mısrda âyin yaparken tutulup \nöldürüldü. Meşhûr Marko pâşa, [1874] den 1309 [m. 1891] e kadar İstanbulda Tıb-\nbiyye mektebi nâzırı idi. (Derdini Marko pâşaya anlat) sözü meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Marconi", "slug": "marconi", "unvan": "", "kategori": "diger", "biyografi": "İtalyan fizikcisidir. 1874 de tevellüd, 1355 [m. 1937] de vefât \netdi. Telsiz-telgrafa sonşeklini verenlerdendir. 1910 da nobel mükâfâtı aldı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ma'rûf-i Kerhî", "slug": "maruf-i-kerhi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Alî Rızânın halî-\nfesi ve Sırrî Sekâtînin mürşidi idi. İkiyüzde Bağdâdda vefât etdi.", "gectigiMaddeler": ["1/50", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mâverdî", "slug": "maverdi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin Muhammed Mâverdî, \n364 [m. 974] de Basrada tevellüd, 450 [m. 1058] de Bağdâdda vefât etdi. Şâfi’î fıkh \nve tefsîr âlimidir. (Hâvî) fıkh kitâbı çok kıymetlidir. (Ahkâm-üs-sultâniyye) adın-\ndaki sosyal kitâbı Mısrda ve 1269 [m. 1853] da Almanyada Bonnşehrinde basıldı. \nMısrda ikinci baskısı 1386 [m. 1966] da yapıldı.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mazher-i Cân-ı Cânân", "slug": "mazher-i-can-i-canan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemsüddîn \nHabîbullah seyyiddir. Tesavvuf mütehassıslarının büyüklerindendir. Müslimânla-\nrın gözbebeğidir. 1111 [m. 1699] de Hindistânda Ramezân- ışerîfin onbirinci \nCum’a günü tevellüd ve 1195 [m. 1781] deşehîd edildi. Abdüllah- ı Dehlevî kabri-\nnin yanındadır. Şâhcihân câmi’inin civârında, Dergâh câmi’indeki dört kabrden \nbirincisidir. Yirmiiki yaşında iken, Seyyid Muhammed Nûr-i Bedevânî hazretleri-\nnin vâris-i ekmeli oldu. Seyyid Abdüllah- ı Dehlevînin üstâdıdır. Yetişdirdiklerin-\nden biri de kâdî allâme Muhammed Senâullah- ı Dehlevî hazretleridir. Abdüllah- ı \nDehlevî hazretleri, (Makâmât-i mazheriyye) kitâbında diyor ki, Hadîs âlimi Şâh \n– 1133 –\nVeliyyullah buyurdu ki, (Allahü teâlâ, bize sahîh keşfler ihsân eyledi. Bu zemânda, \nhiçbir yerde mirzâ Cân- ı Cânânın benzeri yokdur. Makâmlarda ilerlemek istiyen \nonun hizmetine gelsin!) Hadîs öğrenmek için kendisine gelenleri istifâde etmek \niçin, Mazher-i Cân- ı Cânân hazretlerine gönderirdi. Ona yazdığı mektûblarda, \n(Allahü teâlâ, fazîletlerin tecellî yeri olan sizlere uzun zemân selâmet versin ve \nbütün müslimânları bereketlerinize kavuşdursun!) derdi. (Makâmât-ı Mazheriy-\nye)de, Mazher-i Cân-ı Cânân “kuddise sirruh” buyuruyor ki, Evliyânın mezârlarını \nziyâret edip, cem’iyyet için feyz dilemelidir. Meşâyıh-ı kirâmın rûhlarına fâtiha ve \nsalevât sevâbı göndererek, onları Allahü teâlâya kavuşmak için vesîle yapmalıdır. \nZâhir ve bâtın se’âdetlerine ancak onların güzel ahlâkına sarılmak ile kavuşulur. \nBaşlangıcda olan sâliklerin, kalbleri tasfiye bulmadan, temizlenmeden önce, Evli-\nyânın kabrlerinden feyz almaları güçdür. Bunun için Behâeddîn-i Buhârî “kadde-\nsallahü sirrehül’azîz”, (İslâmın güzel ahlâkına mâlik bir kimse ile olmak, Evliyânın \nkabrleri ile olmakdan dahâ iyidir) buyurdu. İkinci kısmda, dörtyüzellidokuzuncu \nsahîfedeki yazı böylece açıklanmış oluyor. Fârisî \n(Kelimât-i tayyıbât) denilen kitâb-\nda 87 mektûbu ve melfûzâtı vardır.", "gectigiMaddeler": ["1/19", "1/46", "1/90", "2/4", "2/17", "2/47", "2/52", "2/72", "3/27", "3/53", "3/60", "3/62"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mehdî", "slug": "mehdi", "unvan": "aleyhirrahme", "kategori": "diger", "biyografi": "Hazret-i Mehdî, âhır zemânda dünyâya gele-\ncekdir. Adı, Muhammed, babasının adı Abdüllahdır. Resûlullah “sallallahü aleyhi \nve sellem” efendimizin soyundan olacakdır. Îsâ aleyhisselâmla buluşacak, mezheb-\nleri kaldıracak, yalnız onun mezhebi kalacak, her yeri alacak, her yerde adâlet ola-\ncak, Eshâb- ı Kehf, uyanıp mağaradan çıkarak, Mehdînin askeri olacakdır. Ba’zı \nsaf kimseler, büyük zan etdikleri kimselere Mehdî demekdedir. Mehdînin alâmet-\nlerini Resûlullah “sallallahü aleyhi ve sellem” efendimiz bildirmişdir. İbni Hacer-i \nMekkînin (Alâmet-ül-Mehdî) kitâbında ve Süyûtînin (Cüz’ün minel ehâdîs velâsâ-\nril vârideti fî alâmetil mehdî)  kitâbında bunlardan ikiyüze yakın alâmet yazılıdır. \n(El-fütûhât-ül-islâmiyye), ikinci cüz, ikiyüzdoksanyedinci sahîfesinde diyor ki, \n(Beklenilen Mehdî, hazret-i Fâtımanın soyundan olacakdır. Mekkede zuhûr ede-\ncekdir. O zemân, müslimânlar halîfesiz olacakdır. İstemediği hâlde, zor ile halîfe \nyapılacakdır. Zuhûr edeceği zemân ve yaşı ve ömrü kesin belli değildir.) Mehdî \nçıkacağı zemân yeryüzünde halîfe bulunmıyacağı ve Mehdîliklerini i’lân edenlerin \nMehdî olmadıkları, buradan anlaşılmakdadır. İmâm-ı Rabbânî hazretleri, birinci \ncildin ikiyüzellibeşinci mektûbunda, Mehdînin Medînedeki sapık din adamlarını \nöldüreceğini yazmakdadır.", "gectigiMaddeler": ["1/31", "2/1", "2/21", "3/36"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mekkî Efendi", "slug": "mekki-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed Mekkî efendi, âlim, \nârif, veliy-i kâmil olan seyyid Abdülhakîm efendinin büyük oğludur. Annesi, büyük \nvelî, kerâmetler sâhibi seyyid Fehîm efendinin torunu Âişe hanımdır. Mekkî Üç-\nIşık, [1314] de tevellüd, 1387 [m. 1967] de vefât etdi. Medrese tahsîlini bitirdikden \nsonra, peder-i âlîlerinden ulûm-i zâhirenin inceliklerini alarak icâzetleşereflenmiş, \nyüksek teveccühlerine ve himmetlerine mazhar olarak, tesavvuf bilgilerinde de \nkemâle gelmişdir. Son derece edeb veşaşılacak bir tevâzu’ ile, kendilerini agyârdan \nsetr ederdi. Sâf kalbli, temiz rûhlu olan yüzlerce genci ilm ve fazîletle süsledi. \nCenâb-ı Hak, bu feyz ve bereket kaynağından, İstanbul halkını, yıllarca fâidelendir-\ndi. Edirnekapı kabristânında iken Ankarada Bağluma nakl edildi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Melikşâh", "slug": "meliksah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Celâlüddîn, Selçûkî pâdişâhların-\ndan üçüncüsüdür. Alb Arslanın oğludur. 447 [m. 1054] de tevellüd, 485 [m. 1091] de \nBağdâdda zehr verilerek vefât etdi. İsfehânda defn edildi. Babasışehîd olunca, vezîr \nNizâm ül mülkün yardımı ile 465 [m. 1072] de sultân oldu. Mâverâünnehri, Şâmı, \nMısrı, Anadolunun çoğunu aldı. Abbâsî halîfesini emrine aldı. Çok hayrât yapdı. [471] \nhicrî senesinde, güneş takvîmi yapdırdı. Buna (Takvîm-i Celâlî) denir. 441, 1095, 1157. \n— ME’MÛN B İN HÂRÛN: Yedinci Abbâsî halîfesidir. 218 [m. 832] de vefât etdi. \n52, 350, 538, 783, 1058, 1059, 1066, 1070, 1078, 1157, 1162. \n– 1134 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mendeleyef", "slug": "mendeleyef", "unvan": "", "kategori": "diger", "biyografi": "Dimitri, Rus kimyâgeri olup, 1249 [m. 1834] da tevel-\nlüd, 1325 [m. 1907] de öldü. Elementlerin devrî [Periyodik] sistemini bulanlardan-\ndır. Petrollerin teşekkülü teorisi meşhûrdur.", "gectigiMaddeler": ["2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mergınânî", "slug": "merginani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yüzseksenbirinci [181] sıra-\nda, Burhâneddîn-i Mergınânî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mer'î", "slug": "meri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mer’î bin Yûsüf Mukaddisî, Hanbelî \nfıkh âlimlerindendir. 1033 [m. 1623] de vefât etdi. Çok kitâb yazdı. (Tahkîk-ul bur-\nhân fîşân-id-duhân) ve (El-Kevâkib-üd-dürriyye fî menâkıb-il-imâm-ı İbni Tey-\nmiyye) kitâbları meşhûrdur.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Merkez Efendi", "slug": "merkez-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muslih-ud-dîn Mûsâ \nefendi, Kütahyadan İstanbula gelip molla Hızır beğ oğlu Ahmed pâşadan okurken, \nHalvetî Sünbül Sinân yanında yetişdi. Önce Koğacı tekkesinde, sonra Eyyûbde \nŞâh sultân tekkesinde iken, Sultân Süleymânın Topkapı dışında, vâlidesi nâmına \nyapdırdığı tekkede yerleşdi. Sünbül efendi, 936 [m. 1529] da vefât edince, Koca \nMustafâ pâşadaki yerine geçdi. 959 [m. 1551] da vefât etdi. Türbesi karşısındaki \nmektebi Abdülbâkî pâşa yapdırdı. Tokat vâlîsi iken 1034 [m. 1625] senesinde vefât \nedince, İstanbula getirilip, mektebi yanına defn edilmişdir. \nMerkez efendi vefât edince, yerine oğlu ve halîfesi seyyid Ahmed efendi, bun-\ndan sonra da, şeyh Ya’kûb efendi geçdi. Ya’kûb efendi, Sünbül Sinân efendinin \nhalîfesidir. Bu da, 978 [m. 1570] de vefât edince, oğlu Yûsüf Sinân efendişeyh oldu \nise de, altı sene sonra, Medîne-i münevverede Şeyh-ul-harem oldu ve 989 [m. 1580] \nda vefât etdi. Bakî’dedir. Bunun yerine Hasen Necmüddîn efendişeyh oldu. \nAlaca-hisârlıdır. Ya’kûb efendinin halîfesidir. Eğri seferinde bulundu. Sonra hacca \nve Yemene gitdi. Orada, mevlid gecesi, 1019 [m. 1610] senesinde vefât etdi. Mevlid \ngeceleri minârede kandil yakmak âdeti idi. Sultân birinci Ahmed hân beğenerek \nbütün câmi’lerde kandil yakılmasını fermân eyledi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Merkyânus", "slug": "merkyanus", "unvan": "", "kategori": "diger", "biyografi": "Bizans ya’nîşarkî Roma devleti kırallarındandır. Buna \nMarsiyanus da denir. Mîlâdî [391] senesinde tevellüd etdi. Asker iken, ilerliyerek \nsenatör oldu. İkinci Teodosyus [m. 450] de ölünce yerine kız kardeşi Polherya kra-\nliçe oldu. Merkyânus bununla evlendi. Bu kadın ölünce, kral oldu. Cesûr idi. Atti-\nlânın tehdîdlerine cevâb verip, geri çevirdi. Rumlar kendisi ile zevcesi için, Şubatın \nonyedisinde yortu yapıyorlar. [Bu ism, (Fâideli Bilgiler) kitâbındadır.]", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mervân", "slug": "mervan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası, Hakem bin Ebil’âs bin \nÜmeyye bin Abd-i Şems bin Abd-i Menâfdır. Mekkenin fethinde îmân etdiler. \nEmevî halîfelerinin dördüncüsüdür. Hicretin ikinci yılında tevellüd etdi. 65 [m. \n683] senesinde boğduruldu. Yerine, büyük oğlu Abdülmelik geçdi. Hazret-i \nOsmân bin Affânın amcası oğlu ve dâmâdı ve baş kâtibi idi. Çocuk iken, babası \nTâife sürülüp, oraya götürüldü. Sohbetden mahrûm kaldı. Hazret-i Osmân halîfe \nolunca, babasını afv etdi. Babası ile Medîneye geldi. Halîfeye kâtib oldu. Deve har-\nbinde, hazret-i Talhayı kazârâşehîd etdi. Hazret-i Mu’âviye zemânında Medîne \nvâlîsi olup, [48] de azl edildi. [64] de İkinci Mu’âviye halîfelikden çekilince, Abdül-\nlah bin Zübeyr ile harb ederek, halîfe oldu. Zâlim idi. Kardeşi Abdürrahmân bin \nHakem ve ikinci oğlu Abdül’azîz bin Mervân âdil ve sâlih idiler.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mervân bin Muhammed", "slug": "mervan-bin-muhammed", "unvan": "", "kategori": "diger", "biyografi": "Mervân bin Hakemin torunudur. Emevî \ndevletinin ondördüncü ve son halîfesi idi. [72] senesinde tevellüd, [127] de halîfe oldu. \n132 [m. 750] senesinde, Abbâsîler tarafından Mısrda yakalanıp öldürüldü.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Meryem", "slug": "meryem", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Îsâ aleyhisselâmın annesidir. Dâvüd “aley-\nhisselâm” soyundan olan İmrân ile Hunnenin kızı idi. Annesi ölünce, Kudüsde Beyt-\nül-mukaddesin imâmı Zekeriyyâ aleyhisselâmın zevcesi olan teyzesi Îsâ’nın yanında \nbüyüdü. Onbeş yaşında iken, amcasının oğlu Yûsüf-i Neccârla nişânlandı ise de, \nonunla hiç evlenmemişdi. Allahü teâlâ, buna babasız olarak Îsâ aleyhisselâmı verdi. \n– 1135 –\nÎsâ “aleyhisselâm” (Beyt-ül-lahm)da tevellüd etdi. Rum kayserinin Şâmda bulunan \nvâlîsi, zinâ etdiğini zan ederek, ikisini de öldürmek istedi. Yûsüf-i Neccâr, bunları Mıs -\nra götürdü. Oniki sene orada kaldılar. Sonra, Kudüse gelip (Nâsıra) kasabasında yer-\nleşdiler. Îsâ “aleyhisselâm” göke çıkarıldıkdan altı sene sonra, ellidokuz yaşında vefât \netdi. Kudüsdedir. Yehûdîler, bunu kötüliyor. Hıristiyanlar da, Allahın anası, bir kısmı \nda Allahın zevcesi diyor.", "gectigiMaddeler": ["1/83", "2/17", "2/23", "3/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mesleme", "slug": "mesleme", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdülmelik bin Mervânın oğlu-\ndur. 122 [m. 740] de Şâmda vefât etdi. Seyyid gâzî ile Muhammed Battâl gâzî de bu \nsenede vefât etdiler. Başkumandan olarak çok cihâd yapdı. 86 [m. 704] senesinde \nErzurumu ve Trabzonu feth etdi. Emevî halîfelerinin altıncısı, kardeşi Velîd bin \nAbdülmelikin emri ile, hicretin doksanaltıncı 96 [m. 714] senesinde büyük bir ordu \nile Ankara, Eskişehr ve Amûriyyede kanlı savaşlar yapıp, Çanakkal’adan Gelibolu \nve Edirneye, sonra İstanbula geldi. Kardeşi Süleymân da denizden gemilerle geldi. \nBizans imperatörünü korkutdu. Galatayı elegeçirdi. İmperatör ile yapdığı sözleş-\nme ile Ayasofyada nemâz kıldı. Halic kenârında (Arab câmi’i)ni yapdı. İstanbulda \nyedi sene kalıp geri döndü. Hastalık ve sıkıntı yüzünden, Câmi’in bulunduğu yere \n(Kahr köyü)  adını verdi. Şimdi Kara-köy deniliyor. Muhyiddîn-i Arabî hazretleri \n(Musâmere) kitâbında Meslemenin İstanbul seferini uzun anlatmakdadır. Mesle-\nme çekilince, Rumlar verdikleri sözü bozup câmi’i kilise yapdılar. Dördüncü \nMurâd hân zemânına kadar kilise olarak kalıp, 1046 [m. 1637] da eski yeri keşf olu-\nnarak mescide çevrildiği 1288 [m. 1870] de İstanbulda basılmış olan (Fezleke-i \ntârîh-i Osmânî) nin yüzaltmışaltıncı [166] sahîfesinde yazılıdır. Birinci Mahmûd \nhânın vâlidesi Sâliha sultân, câmi’i 1147 [m. 1734] de yeniledi. Binikiyüzyirmiiki \nyangınında yanıp yeniden ta’mîr edildi. \nKaraköydeki Yeraltı câmi’inin adı (Kurşunlu Mahzen) câmi’idir. Mesleme tara-\nfından yapılmış bir mescid iken sonra depo olarak kullanılmışdır. Sadr- ı a’zam \nMustafâ pâşa 1166 [m. 1749] senesinde mahzeni temizletmiş, içinde birkaç kabr \nolduğu görülmüşdür. Bin seneden fazla kapısı kapanarak kilidine kurşun akıtılmış, \nterk edilmiş idi. Birinci Sultân Mahmûd hân tarafından câmi’ hâline getirilmiş, \nsonradan minâre de yapılmışdır. Sultân Mahmûd hân ilk Cum’a nemâzında bulun-\nmuşdur. Mustafâ pâşaya samur kürk hediyye etmişdir. Câmi’de üç kabr vardır. \nŞehîd Alî pâşa önceden 1128 [m. 1812] de câmi’ üstüne bir binâ yapmışdı. Bu binâ, \n1237 [m. 1821] de yenilenmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mes'ûd Kanâvî", "slug": "mesud-kanavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Mes’ûd bin \nHasen Kanâvî, Mısrdaşâfi’î âlimlerindendir. 1205 [m. 1790] hicrî senesinde yazdığı \n(Feth-ur-rahîm) kitâbında İbnül-Verdînin (Lâmiyye) kasîdesinişerh etmekdedir. \nBu kitâbı Mısrda [1281] ve 1315 [m. 1897] senesinde basılmışdır. Burada, tütünün \nharâm olmadığını yazmakdadır.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mevdûdî", "slug": "mevdudi", "unvan": "", "kategori": "diger", "biyografi": "Hicretin [1321]. ci senesinde Hindistânda tevellüd ve 1399 \n[m. 1979] da Amerikada vefât etdi. İbni Teymiyyenin fikrlerine saplanmışdır. \nSiyâsî düşüncelerini islâmiyyet olarak tanıtarak (Cemâ’at-ül İslâmiyye) dediği \nbir islâm fırkası meydâna getirdi. Mevdûd-i Çeştî hazretlerinin soyundandır. \nMevdûd-i Çeştî, 527 [m. 1133] de vefât etdi. İstanbul yüksek islâm enstitüsü eski \nmüdîri ve öğretim üyesi Ahmed Dâvüdoğlu (Din tahrîbcileri)  kitâbında, (Mev-\ndûdî bir felesofdur, şaşırabilir) diyor. Hindistânda molla İlyâsın kurmuş olduğu \n(Teblîgul-cemâ’at)cılar da Mevdûdî gibidirler. Her ikisinin sapık fikrlerine (El-\nüstâd-ül Mevdûdî) ve (Fâideli Bilgiler) kitâblarında uzun yazılmış ve cevâb veril-\nmişdir.", "gectigiMaddeler": ["1/78", "2/1", "2/4", "2/17", "2/22", "3/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Meymûne", "slug": "meymune", "unvan": "radıyallahü teâlâ anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın zevcelerindendir. \nİsmi Birre iken Resûlullah Meymûne yapdı. Hayberin fethinden sonra Mekkeye \numre için gidildikde Meymûnenin zevci vefât etmişdi. Resûlullahın nikâhı ileşereflendi. 53 [m. 673] senesinde Mekkede hastalandı. (Beni Mekkeden çıkarınız! \n– 1136 –\nÇünki, Resûlullah benim Mekkenin dışında vefât edeceğimi haber verdi) dedi. Çı -\nkardılar. Resûlullaha nikâhı yapılmış olduğu yerde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Midhat Pâşa", "slug": "midhat-pasa", "unvan": "", "kategori": "diger", "biyografi": "İngiliz masonudur. Tâifde sürgünde iken, ingilizler \ntarafından boğduruldu. 51, 1059, 1063. (Eshâb-ı Kirâm) sahîfe:", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mihael Kirolarıus", "slug": "mihael-kirolarius", "unvan": "", "kategori": "diger", "biyografi": "Ortodoks kilisesinin kurucusudur. İstanbul \npatrîki iken, hicretin [446]. cı ve mîlâdın [1054]. cü senesinde Romadaki papadan \nayrıldı. Şark kiliselerine ortodoks denildi. Mihael-i Süryânî başkadır.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mihr-i Mâh Sultân", "slug": "mihr-i-mah-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Kânûnî sultân \nSüleymân hânın kızıdır. Zevci Rüstem pâşa, Eminönü ile Unkapanı arasındaki \nmeşhûr câmi’i yapmışdır. Mihr-i Mâh sultân da, Edirnekapı yanında büyük câmi’i \nve 954 [m. 1546] senesinde Üsküdâr iskelesindeki Mihri-Mâh câmi’ini yapdırmış-\ndır. 985 [m. 1578] senesinde vefât etmişdir. Süleymâniyyede babasının türbesinde-\ndir. Rüstem pâşanın kardeşi kapdân-ı deryâ Sinân pâşa, Beşiktaş iskelesi yanında \nmeşhûr câmi’i yapdırdı. 961 [m. 1553] senesinde vefât edip, Üsküdârda Mihr-i Mâh \nsultân câmi’i mihrâbı önüne defn edildi. Câmi’i Rüstem pâşa 963 [m. 1555] de \ntemâmladı. Rüstem pâşa 968 [m. 1560] de vefât etdi. Şâhzâde câmi’i bağçesindeki \ntürbesindedir. 953 [m. 1545] de kapdân- ı deryâ olan Barbaros Hayreddîn pâşa, \nAkdenize gideceği vakt, gemileri bağlamak için, sâhile beş taş direk yapdırmışdı. \nBuraya zemânla Beşiktaş denildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mihr-i Şâh Sultân", "slug": "mihr-i-sah-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Üçüncü Selîm \nhânın vâlidesidir. Halıcıoğlu kışlası ile yeni köprü arasındaki câmi’i yapdırmışdır. \nEyyûb câmi’i ile Bostan iskelesi arasında 1210 [m. 1796] da yapdırdığı türbesinde-\ndir. Kızı Hadîce sultân da yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Milton", "slug": "milton", "unvan": "", "kategori": "diger", "biyografi": "İngilterenin büyükşâ’irlerindendir. [m. 1608] de Londrada \ndoğdu. 1085 [m. 1674] da öldü. Meşhûr Kromwell bunu genel sekreter yapıncaşöh-\nreti artdı. Onun ölümünden sonra bir kenâra çekildi. İki gözü kör oldu. Çok kıymet \nverilen (Gâib olmuş se’âdet) şi’rini zevcesine ve iki kızına yazdırdı. Târîh, lügat ve \nmantık üzerine eserleri vardır. Kur’ân-ı kerîmi incelemiş ve çok övmüşdür.", "gectigiMaddeler": ["2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mîrânşâh", "slug": "miransah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tîmûr hânın üçüncü oğludur. \n[769] da tevellüd, 810 [m. 1407] da Âzerbaycânda Karakoyunlu Yûsüfle harb eder-\nkenşehîd oldu. Tîmûrden sonra üç sene saltanat sürdü. Delhîdeki Gürgâniyye sul-\ntânları bunun soyundandır.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Molla Câmî", "slug": "molla-cami", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrahmân bin Nizâ-\nmeddîn Ahmed Nûreddîn-i Câmî, şeyh-ul-islâm idi. Âlim, veliy-yi kâmil idi. 817 \n[m. 1414] de, Îrânda Câm kasabasında tevellüd, 898 [m. 1492] Muharreminin \nonsekizinci günü, Cum’a ezânı okunurken, Hirâtda vefât etdi. İmâm-ı Muham-\nmed Şeybânî hazretlerinin soyundandır. Beş yaşında iken Muhammed Pârisâ haz-\nretlerinin huzûruna götürülüp teveccühüne mazhar oldu. Ubeydüllah hazretleri-\nne yazdığı mektûblardan ikisi (Reşehât)da mevcûddur. Mevlânâ Sa’düddîn-i Kaş-\ngarîden feyz alarak kemâle geldi ve irşâda me’zûn oldu. Sa’düddîn hazretleri, \nNizâmeddîn-i Hâmûşün halîfesi olup, sekizyüzaltmış senesinde Hirâtda vefât \netmişdir. Nizâmüddîn-i Hâmûş hazretleri, Alâ’üddîn-i Attâr hazretlerinin halîfe-\nlerinin en üstünü idi. Molla Câmî hazretleri çok kitâb yazdı. (Şevâhid-ün-nübüv-\nve) kitâbı, Mahmûd bin Osmân Lâmi’î ve Ehî-zâde Abdülhalîm tarafından, fars-\ncadan türkceye terceme edilmiş ve fârisîsi ve türkçe tercemesi Hakîkat Kitâbevi \ntarafından basdırılmışdır. Kerâmetleri görüldü. Fâtih sultân Muhammed, kendisi-\nni İstanbula da’vet etdi. Konyaya kadar geldi. Fâtihin vefâtını haber alarak geri \ndöndü.", "gectigiMaddeler": ["1/97", "2/52", "2/53", "3/49", "3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Molla Hüsrev", "slug": "molla-husrev", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed efendi, \nOsmânlıların üçüncüşeyh-ul-islâmı idi. Hanefî fıkh âlimidir. Babası dönme idi. Bir \ndüğünde, Fâtih sultân Muhammed, molla Gürânîyi sağ yanına, molla Hüsrevi sol \n– 1137 –                                  Se’âdet-i Ebediyye 3-F:72\nyanına aldı. [865] deşeyh-ul-islâm oldu. Yirmi sene, bu vazîfeyi çok iyi yaparken \n885 [m. 1480] de vefât etdi. Nemâzı Fâtih câmi’inde kılınıp, Bursaya götürülüp, \nEmîr Sultânın doğusunda defn edildi. (Dürer ve gurer) fıkh kitâbı, çok kıymetlidir. \n1319 [m. 1900] da İstanbulda, Şernblâlîşerhı basılmışdır. Vefâda Ekmekci medre-\nsesi yanında mescidi vardır.", "gectigiMaddeler": ["1/54", "1/74", "1/98", "2/37", "2/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Molla Kudsî", "slug": "molla-kudsi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindli Abbâs kulu molla \nKudsî, arabî (Esrâr-ı melekût) astronomi kitâbının sâhibidir. 1262 [m. 1846] \nsenesinde Mekke-i mükerremede vefât etdi. Bu kitâbı Elbüstânlı Hayâtî zâde \nHalîl Şeref efendi türkceye terceme ederek (Efkâr-ül-ceberût)  adını vermişdir. \nŞeref efendi [1211] de Elbüstânda tevellüd, 1267 [m. 1851] de orada vefât etmiş-\ndir.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Molyer", "slug": "molyer", "unvan": "", "kategori": "diger", "biyografi": "Moliére, Fransız komedi yazarıdır. 1031 [m. 1622] de Pârisde \ntevellüd, 1083 [m. 1673] de vefât etdi. Tiyatroculuk yapdı. Yazdığı komedileri \noynardı.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Moseley", "slug": "moseley", "unvan": "", "kategori": "diger", "biyografi": "Henri Mosli, ingiliz fizikcisidir. 1304 [m. 1887] de tevellüd, \n1334 [m. 1916] de vefât etdi. [m. 1913] de Mosli kanûnunu buldu. Buna göre, bir \nelementin hâsıl etdiği Röntgenşuâ’larının frekanslarının kare kökleri, bu elemen-\ntin periyodik sistemdeki sıra numarası [atom numarası] ile orantılıdır. Mosli, böy-\nlece, elementlerin atomlarındaki proton sayısını hesâblamış oldu. Mosli [m. 1916] \nda İngiliz subayı olarak Çanakkalede Türklere karşı harb etdi.", "gectigiMaddeler": ["2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mozart", "slug": "mozart", "unvan": "", "kategori": "diger", "biyografi": "Avusturyalı bestekârdır. 1169 [m. 1756] da tevellüd, 1205 [m. \n1791] de vefât etdi. Kilise müziğine hizmet etdi. Figaronun evlenmesi meşhûrdur.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mu'âviye", "slug": "muaviye", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Babası Ebû Süfyân bin Harb bin Ümey-\nyedir. Annesi Hind bint-i Utbe bin Rebî’a bin Abd-i Şemsdir. Hicretden ondokuz \nsene önce tevellüd, 60 [m. 680] senesinde, Receb ayında vefât etdi. Mekkenin feth \nedildiği gün, babası ile berâber, Resûlullahın önünde müslimân oldu. Eshâb- ı kirâ-\nmın büyüklerindendir. Resûlullahın “sallallahü aleyhi ve sellem” vahy kâtibi ve \nkayınbirâderi idi. Hazret-i Ömer zemânında dört yıl, Osmân zemânında oniki yıl, \nAlî zemânında beş yıl, imâm-ı Hasen zemânında altı ay olarak Şâmda yirmibirbu-\nçuk sene vâlî oldu. [41]. ci senede, Şevvâl ayında Kûfede halîfe seçildi. Ondokuz \nsene, dört ay halîfelik yapdı. Bir islâm devletinin reîsine (Halîfe) denir. İslâmiyyet-\nde ilk seçilen halîfe, Ebû Bekr-i Sıddîkdır. Bundan sonra sıra ile Ömer, Osmân, Alî, \nHasen ve Mu’âviyedir. Emevî ve Abbâsî halîfelerinin ismleri, (Eshâb-ı Kirâm) ve \n(Fâideli Bilgiler)  kitâblarında yazılıdır. Aklı, zekâsı, fesâhatı, sabrı, yumuşaklığı, \nikrâmı, cömertliği fevkal’âde çok idi. Müslimânların başına geçeceği, hadîs-işerîfde \nbildirilmişdi. Kendisinden çok hadîs-işerîf alınmış, kitâblara yazılmışdır. Bu da, \nbüyüklüğünü ve kendisine güvenildiğini göstermekdedir. Şâmdaki Emevî devleti-\nnin kurucusudur. Şâmda medfûndur. Hicretin 42 senesinde Sicistânı, 43 de Sudanı, \n44 de Efganistânı ve Kâbilşehrini ve Hindistânınşimâl kısmını, 45 de Tunusda Efrî-\nkıyyeşehrini aldı. 48 de gemilerle kendisi Kıbrısa giderek Bizans devletinden feth \netdi. [Ada 586 [m. 1191] de İngilizlerin ve 878 [m. 1473] de Venediklilerin eline \ngeçdi. 978 [m. 1570] de İkinci Selîm hân tarafından feth edildi. 1295 [m. 1878] Ayas-\ntefanos muâhedesi ile Balkan yarım adası ve Anadolunun mühim kısmları Ruslara \nverilince, ikinci Abdülhamîd hân, devletin idâresini eline alıp, ingilizleri Kıbrısın \nidâresine ortak ederek, Berlin muâhedesini hâzırladı. Bütün toprakları kurtardı. \nBalkan harbinin fecî’ bozgunundan sonra, 1331 [m. 1913] de Londra muâhedesin-\nde, İttihâdcılar, bütün Rumeliyi ve Kıbrısı, Edirneyi düşmanlara terk etdi.] Haz-\nret-i Mu’âviye, 50 de Îrânda büyük Kuhistanşehrini aldı. Yine 50 [m. 670] senesin-\nde, Bizans imperatoru dördüncü Kostantin zemânında, oğlu Yezîdi büyük bir ordu \nile İstanbula cihâd etmeğe gönderdi. Her sene büyük vergi almakşartı ile sulh \nyapıldı. 54 de Ubeydüllah bin Ziyâdı Horâsândaki orduya kumandan yapıp, Cey-\n– 1138 –\nhûn nehrini develerle geçerek, Buhârâyı aldı. Kudüs-işerîfi hazret-i Ömer feth et -\nmişdi. Sonra, kâfirler geri almışlardı. Hazret-i Mu’âviye tekrâr feth etdi. Yemen, \nMısr, Kayruvan, Irâk, Azerbaycan, Anadolu, Horâsân ve Mâverâ-ün-nehrşehrleri-\nne hâkim oldu. Bütün millete kendini sevdirdi. Büyük saltanata nâil oldu. Resûlul-\nlahın sohbetinin ve hayrlı düâlarının bereketi ile islâmiyyetden hiç ayrılmadı.", "gectigiMaddeler": ["1/46", "1/61", "2/17", "2/21", "2/22", "2/23", "2/24", "2/41", "3/2", "3/3", "3/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mu'âz bin Cebel", "slug": "muaz-bin-cebel", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmın büyüklerin-\ndendir. İkinci Akabede îmân eden yetmiş Ensârdandır. Bütün gazâlarda bulundu. \nOnsekiz yaşında îmân etdi. 18 [m. 639] senesinde tâ’ûndan vefât etdi. Resûlullahın \nYemende vâlîsi idi.", "gectigiMaddeler": ["2/17", "2/44", "2/45", "3/17", "3/21", "3/61"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mücâhid", "slug": "mucahid", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası, Cebr-i Mahzûmîdir. \nTâbi’înin ve tefsîr imâmlarının büyüklerindendir. [24] senesinde tevellüd, 104 [m. \n723] senesinde Mekkede, nemâzda secdede vefât etdi. Abdüllah ibni Abbâsın tale-\nbesi idi. Tefsîri vardır.", "gectigiMaddeler": ["1/43", "1/97", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mudar", "slug": "mudar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Resûlullahın onsekizinci babasıdır. \nNizârın oğludur. Mudarın sesi çok güzel idi. Deve yanında okuyup onu harekete \ngetirmek Mudardan kalmışdır. İbrâhîm aleyhisselâmın islâm dîninde idi.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Müdrike", "slug": "mudrike", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Resûlullahın onaltıncı babasıdır. \nİsmi Amr idi. Tavşan arkasından koşup yakaladığı için, babası buna Müdrike \ndemişdi. Dedelerininşereflerini kendinde topladığı için de Müdrike denilmişdir.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed", "slug": "muhammed", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Allahü teâlânın Resûlüdür. Habîbidir. \nPeygamberlerin en üstünü ve sonuncusudur. Babası Abdüllahdır. Mîlâdın beşyüz-\nyetmişbir [571] senesi nisan ayının yirmisine rastlayan, Rebî’ul-evvel ayının oniki-\nnci pazartesi gecesi, sabâha karşı, Mekkede tevellüd etdi. Babası, dahâ önce vefât \netmiş idi. Altı yaşında iken annesi, sekiz yaşında iken dedesi vefât etdi. Sonra, \namcası Ebû Tâlibin yanında büyüdü. Yirmibeş yaşında iken, Hadîce-tül-kübrâ ile \nevlendi. Bundan dört kızı, iki oğlu oldu. İlk oğlunun adı Kâsım idi. Bundan dolayı, \nkendisine (Ebül-Kâsım) da denir. Kırk yaşında iken, bütün insanlara ve cinne Pey-\ngamber olduğu bildirildi. Üç sene sonra, herkesi îmâna çağırmağa başladı. Elliiki \nyaşında iken, bir gece Mekkeden Kudüse ve oradan göklere götürülüp getirildi. Bu \nyolculuğuna (Mi’râc) denir. Mi’râcda, Cennetleri, Cehennemleri ve Allahü teâlâyı \ngördü. Beş vakt nemâz, bu gece farz oldu. Târîhcilere göre mîlâdın 622 senesinde, \nAllahü teâlânın emri ile, Mekkeden Medîneye gitdi. Bu yolculuğuna (Hicret) \ndenir. Medîneşehrinin Kubâ köyüne geldiği, Rebî’ul-evvel ayının sekizinci pazar-\ntesi gününe tesâdüf eden efrencî Eylül ayının yirminci günü müslimânların (Hicrîşemsî) târîh başlangıcı oldu. Müslimânların (Hicrî kamerî) seneleri de, o senenin \nMuharrem ayından başlar ve gökdeki ayın, dünyâ etrafında oniki def’a dönmesi \nbir kamerî sene olur. Hicrî 11 [m. 632] senesinde, Rebî’ul-evvel ayının onikinci \npazartesi günü, öğleden evvel vefât etdi. Salıyı çarşambaya bağlıyan gece [Çarşam-\nba gecesi] yarısı, vefât etmiş olduğu odaya defn edildi. Vefâtında, kamerî 63, şemsî \nseneye göre 61 yaşında idi. \nMuhammed “aleyhisselâm” beyâz idi. Bütün insanların en güzeli idi. Güzelliği-\nni, herkese belli etmezdi. Onun güzelliğini bir kerre gören, hattâ rü’yâda gören \nkimsenin ömrü, lezzet ve neş’e ile geçmekdedir. O, her zemânda, dünyânın her \nyerinde olan ve gelecek olan her insandan, her bakımdan üstündür. Aklı, fikri, \ngüzel huyları, bütün organlarının kuvveti her insandan ziyâde idi. \nÇocuk iken iki kerre, ticâret edenlerle Şâm tarafına gitdi ve Busrâ denilen \nyerden geri döndüler. Ondört veyâ onyedi yaşında amcası Zübeyr ile Yemene git -\n– 1139 –\ndi. Başka hiçbir zemân, hiçbir yere gitmedi. Ümmî idi. Ya’nî hiç mektebe gitmedi. \nKimseden ders almadı. Fekat, herşeyi biliyordu. Ya’nî her neyi düşünse, her neyi \nbilmek istese, Allahü teâlâ Ona bildiriyordu. Cebrâîl “aleyhisselâm” adındaki \nmelek gelip, Ona her istediğini söylüyordu. Mubârek kalbi, güneş gibi, nûr saçıyor-\ndu. Onun saçdığı ilm, ma’rifet nûrları, radyo dalgaları gibi, yerlere, göklere, heryere \nsaçılıyordu. Şimdi, kabrinden de yaymakdadır. Yayma kuvveti, her ân artmakdadır. \nElektro-manyetik dalgaları almak için, radyo alıcısı lâzım olduğu gibi, Onun nûrla-\nrını almak için de, Ona inanan ve seven ve gösterdiği yolda giderek temizlenen kalb \nlâzımdır. Böyle kalbi olan insan, bu nûrları alır ve bu da, etrâfa neşr eder, yayar. \nBöyle büyük insanlara (Velî) denir. Bu Velîyi tanıyan, inanan ve seven kimse, \nbunun karşısında edeble oturur veyâ uzakda, onu edeb ile, sevgi ile düşünürse, bu \nkimsenin de kalbi, nûr, feyz almağa, temizlenmeğe, olgunlaşmağa başlar. Allahü \nteâlâ, bedenimizi, maddemizi, yetişdirmek için güneş enerjisini sebeb kıldığı gibi, \nrûhlarımızı, kalblerimizi olgunlaşdırmak, insanlıkda yükseltmek için de, Muham-\nmed aleyhisselâmın kalbini, oradan fışkıran nûrları sebeb kılmışdır. İnsanı besliyen, \nyapısını ve enerjisini sağlıyan bütün besi maddeleri, güneş enerjisi, özümleme ile \nhâsıl oldukları gibi, kalbe, rûha gıdâ olan, Evliyânın sohbetleri, sözleri ve yazıları \nda, hep Resûlullahın mubârek kalbinden fışkıran nûrlarla hâsıl olmuşdur. \nAllahü teâlâ, Cebrâîl “aleyhisselâm” adındaki bir melek ile, Muhammed aley-\nhisselâma (Kur’ân-ı kerîm)i gönderdi. İnsanlara dünyâda ve âhıretde lüzûmlu, fâi-\ndeli olanşeyleri emr etdi. Zararlı olanları yasak etdi. Bu emrlerin ve yasakların \nhepsine (İslâm dîni) veyâ (İslâmiyyet) denir. \nMuhammed aleyhisselâmın her sözü doğrudur, kıymetlidir, fâidelidir. Böyle \nolduğuna inanan kimseye (Mü’min) ve (Müslimân) denir. Muhammed aleyhisse-\nlâmın sözlerinden birine inanmıyan, beğenmiyen kimseye kâfir denir. Allahü \nteâlâ, mü’min olanı sever. Bunu Cehennemde sonsuz olarak bırakmaz. Yâ Cehen-\nneme hiç sokmaz, yâhud, kabâhati için, soksa da, sonra Cehennemden çıkarır. \nKâfir olan kimse, Cennete giremez. Doğru Cehenneme girer ve oradan hiç çıkmaz. \nOna inanmak, Onu sevmek, bütün se’âdetlerin, râhatlıkların, iyiliklerin başıdır. \nOnun Peygamber olduğuna inanmamak ise, bütün felâketlerin, sıkıntıların, kötü-\nlüklerin başıdır. Aklı, zekâsı, güzel ahlâkı ve deryâ gibi olan her nev’ ilmi ve mu’ci-\nzeleri, islâmiyyetin hak din olduğunu gösteren vesîkalardır. 4, 9, 17, 18, 21, 22, 23, \n24, 32, 33, 36, 40, 41, 43, 44, 45, 47, 48, 49, 51, 52, 53, 56, 57, 59, 60, 65, 66, 69, 71, \n89, 94, 98, 99, 102, 103, 104, 106, 109, 166, 209, 229, 263, 267, 274, 276, 285, 289, 311, \n313, 327, 329, 332, 337, 352, 353, 354, 355, 356, 358, 364, 367, 368, 369, 370, 372, 373, \n(374),", "gectigiMaddeler": ["1/95", "1/96", "1/97", "1/98", "2/1", "2/4", "2/15", "2/17", "2/18", "2/19", "2/20", "2/21", "2/22", "2/23", "2/24", "2/26", "2/27", "2/28", "2/29", "2/34", "2/39", "2/42", "2/48", "2/51", "2/53", "2/67", "2/72", "2/73", "3/28", "3/29", "3/47", "3/50", "3/51", "3/52", "3/53", "3/56", "3/59", "3/61"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Âkif", "slug": "muhammed-akif", "unvan": "", "kategori": "diger", "biyografi": "Osmânlışâ’irlerindendir. 1290 [m. 1873] da tevel-\nlüd, 1354 [m. 1936] de İstanbulda vefât etdi. Edirnekapı kabristânındadır. Fâtih rüş-\ndiyesinden sonra, mülkiye i’dâdîsini bitirdi. Baytar mektebini okuyup, veteriner \noldu. Dînî, millîşi’rleri çok heyecânlıdır. Her müslimân türkün kalbine yerleşmiş \nolup ve her evde saygı ve sevgi ile okunan türk istiklâl marşının yazarıdır. (Safahât) \nkitâbı heyecânlışi’rlerle dolu ise de, seksenaltıncı sahîfesinde ( İstibdâd) adındaki \nyazısında ve dörtyüzbeşinci sahîfesinde, müslimânların halîfesi ve islâmiyyetin bek-\nçisi olan sultân ikinci Abdülhamîd hânınşânını ve kıymetini zedeleyen çok çirkin ve \nbayağı iftirâları ve Mısr müftîsi sicilli mason, Muhammed Abdühü öven ve bir çal-\ngıcıyı, çalgısını\nn seslerini nidâ-yı ilâhîye benzeterek övenşi’rleri kendisini lekele-\nmekde, îmânlı kalblerde nefret hâsıl etmekdedir. İstanbuldaki yüksek islâm enstitü-\nsü eski müdîrlerinden ve öğretim üyelerinden Ahmed Dâvüdoğlu, 1394 [m. 1974] \n– 1140 –\nsenesinde İstanbulda basılan (Dîni ta’mîr da’vâsında din tahrîbcileri) kitâbında, \nMuhammed Âkifin de sâir reformcular gibi, ilhâmı doğrudan doğruya Kur’ân- ı \nkerîmden almak istediğini bildirmekdedir.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Akkermânî", "slug": "muhammed-akkermani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Doksanal-\ntıncı [96] sırada, Akkermânî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Alî Pâşa", "slug": "muhammed-ali-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "1183 [m. 1769] \nde Kavalada tevellüd, 1266 [m. 1849] da Mısrda vefât etdi. [1215] de Mısr vâlîsi \noldu. Dînine bağlı iyi adam idi. Bundan sonra, Mısr bozuldu.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Arabî", "slug": "muhammed-arabi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nTebbânî Magribî, (İfâde-tül-ahyâr) kitâbının yazarıdır. Bu kitâbı iki cilddir. Mek-\nkede basılmışdır. Burada, Abdühün Ehl-i sünnete karşı yapdığı haksız hücûmları \naçıklamakda, herbirine cevâb vermekdedir.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Bâbâ Semmâsî", "slug": "muhammed-baba-semmasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm \nâlimlerinin büyüklerindendir. Râmîten ile Buhârâ arasında Semmâs köyünde \ntevellüd, 755 [m. 1354] de orada vefât etdi. Alî Râmitenînin halîfesidir. Çok kerâ-\nmetleri görüldü.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Bâkî-Billah", "slug": "muhammed-baki-billah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası kâdî \nAbdüsselâm Semerkandîdir. Sôfiyye-i aliyyenin büyüklerindendir. Rûh ilmlerinin \nmütehassısı idi. İmâm-ı Rabbânî Ahmed-i Fârûkînin “kuddise sirruhümâ” üstâdı-\ndır. 971 [m. 1563] senesinde Kâbilşehrinde tevellüd etdi. Kâbilden Semerkanda \ngidip, zâhir ilmlerinde yüksek dereceye yetişdikden sonra, hâce İmkenegî hazret-\nlerinin sohbet ve teveccühleri ile deşereflenerek vilâyetin yüksek mertebelerine \nkavuşdu. Şâh-ı Nakşîbend ve Ubeydüllah-i Ahrâr hazretlerinin rûhâniyyetlerin-\nden de feyz alarak (Üveysî) oldu. İmâm-ı Rabbânî hazretlerinin eshâbından mev-\nlânâ Bedreddîn-i Serhendî (Hadarât-ül-kuds) adındaki fârisî kitâbında, hayâtını ve \nkerâmetlerini uzun yazmakdadır. Bu kitâb, fârisî olup, Bâyezîd kütübhânesi \n(Veliyyeddîn) kısmında [1788] sayıda mevcûddür. Muhammed Bâkî-billah, Delhî-\nde 1012 [m. 1603] senesinde vefât etdi. Kutabrol denilen yerdeki mescidinin yanın-\nda ziyâret edilmekdedir. Türbesininşarkında vâlidesi ile oğlu Ubeydüllah, garbın-\nda diğer oğlu Abdüllah medfûndur. 1387 [m. 1967] de Lâhorda basılan (Külliyât-i \nBâkî-billah) kitâbında, hayâtı ve mektûbları yazılıdır. (Hadarât-ül-kuds) kitâbı da, \n1391 [m. 1971] de Lâhorda basılmışdır. 312 sahîfedir.", "gectigiMaddeler": ["2/47", "2/61", "3/1", "3/44", "3/45", "3/51", "3/52", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Bâkır", "slug": "muhammed-bakir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Oniki imâmın \nbeşincisidir. Zeynel’âbidîn Alî bin imâm- ı Hüseynin oğlu, imâm-ı Ca’fer-i Sâdıkın \nbabasıdır. [57] senesinde Medînede tevellüd, 113 [m. 732] senesinde vefât etdi. \nMedînede, Bakî’de, babasının yanındadır.", "gectigiMaddeler": ["1/31", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Bâkır-ı Lâhorî", "slug": "muhammed-bakir-i-lahori", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası \nŞerefeddîndir. Muhammed Ma’sûm Fârûkînin halîfelerindendir. İmâm-ı Rabbânî \nhazretlerinin (Mektûbât)ını 1080 [m. 1669] senesinde fârisî olarak hulâsa etmiş, \n(Kenz-ül-hidâyât) adını vermişdir. Ayrıca fârisî (Ürve-tül-vüskâ) kitâbını yazmış-\ndır. 1080 [m. 1669]de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Bedevânî", "slug": "muhammed-bedevani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Nûr \nismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Behâeddîn-i Buhârî", "slug": "muhammed-behaeddin-i-buhari-rahmetullahi-teala-a", "unvan": "", "kategori": "alim", "biyografi": "Yüzaltmışıncı [160] sırada Behâeddîn-i Buhârî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Abdüllah", "slug": "muhammed-bin-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Veliy-\nyüddîn hatîb-i Tebrîzî, şâfi’î hadîs âlimlerindendir. 749 [m. 1348] senesinde vefât \netdi. İmâm-ı Begavînin (Mesâbîh) kitâbına ek ve açıklamalar yaparak (Mişkât-ül-\nMesâbîh) adını verdiği kitâbı meşhûrdur. 458. \n– 1141 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Abdülvehhâb", "slug": "muhammed-bin-abdulvehhab", "unvan": "", "kategori": "diger", "biyografi": "1111 [m. 1699] senesinde, \nNecdde, Hureymile kasabasında tevellüd, 1206 [m. 1791] da öldü. Genç yaşında \niken, 1125 [m. 1713] de Basrada, Hempher isminde bir ingiliz câsûsunun tuzağına \ndüşdü. Ehl-i sünnet i’tikâdından ve islâmın güzel ahlâkından ayrıldı. İngilizlerin \n(İslâmiyyeti yok etmek) çalışmalarına âlet oldu. Hempherin yazdırdığı bozukşeyleri, 1150 [m. 1737] de (Vehhâbîlik) ismi ile neşr eyledi. (İngiliz Câsûsunun \nİ’tirâfları) kitâbımızda, vehhâbîliğin kurulması uzun yazılıdır.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Abdürresûl", "slug": "muhammed-bin-abdurresul-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Berzencî âlimlerindendir. Seyyiddir. [1040] da Zûrşehrinde tevellüd, 1103 [m. 1692] de Medînede vefât etmişdir. Şî’îleri red eden mirzâ Mahdûmun (Nevâkıd) kitâbını ihtisâr etmişdir. Çok bilgili olduğu hâlde, tesavvufdan nasîbi olmamışdır. İmâm-ı Rabbânî hazretlerine karşı edeb dışı hücûmlarda bulunmuşdur. (Makâmât-i Mazherî)de diyor ki, (İmâm-ı Rabbânînin “rahmetullahi aleyh” torunlarından Muhammed Ferruh Şâh bin Muhammed Sa’îd, çok âlim idi. Hacca gitdi. Muhammed Berzencî bunu mahcûb etmek için, Medîneden Mekkeye gitmek istedi. Ağır hastalandı. Muhammed Ferruh, Medîneyi de ziyâret edip gemi ile Hindistâna döndü. Berzencî iyi oldu. Kayıkla gemiye yetişmek istedi. Yolda boğuldu.)", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Ahmed Ebşîhî", "slug": "muhammed-bin-ahmed-ebsihi-rahmetullahi-teala-al", "unvan": "", "kategori": "alim", "biyografi": "Behâeddîn Muhammed, [790] senesinde tevellüd, 850 [m. 1446] de Mısrda vefât etdi. (Mustatraf) kitâbı, Rat tarafından fransızcaya terceme edilmiş, [m. 1902] de Pârisde basılmışdır.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Ahmed Semerkandî", "slug": "muhammed-bin-ahmed-semerkandi-rahmetullahi-teala", "unvan": "", "kategori": "alim", "biyografi": "Alâüddîn-i Semerkandî 540 [m. 1145] da vefât etdi. 531. ci isme bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Ahmed Zâhid", "slug": "muhammed-bin-ahmed-zahid-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Hindistânda 632 [m. 1234] de vefât etdi. Hanefî fıkh âlimlerindendir. (Tergîb-üs-salât) kitâbı meşhûrdur. Nûr-i Osmâniyye kütübhânesinde vardır.", "gectigiMaddeler": ["1/74"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Ebû Bekr", "slug": "muhammed-bin-ebu-bekr", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Onuncu \n[10] senede, Vedâ’ haccına giderken tevellüd etdi. 38 [m. 659]. ci senede işkence ile \nöldürüldü. Sahâbî değildir. Tâbi’îndendir. Hazret-i Osmânışehîd edenler arasında \nidi. Deve ve Sıffîn harblerinde hazret-i Alî ile birlikde idi. Hazret-i Alî tarafından \nMısr vâlîsi yapıldı. Amr ibni Âs ile yapdığı muhârebedeşehîd oldu.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Ebî Bekr", "slug": "muhammed-bin-ebi-bekr", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâmzâde \nve Rükn-ül-islâm denir. Buhârâda müftî idi. 573 [m. 1178] senesinde vefât etdi. \nBunun (Şir’atül-islâm) kitâbını Ya’kûb bin Seyyid Alîşerh etmişdir.", "gectigiMaddeler": ["1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammedibni Hanefiyye", "slug": "muhammedibni-hanefiyye-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Dörtyüzkırkdördüncü [444] sırada İbni Hanefiyye ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Binishak", "slug": "muhammed-binishak", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dedesi Huzey-\nmedir. [223] yılında tevellüd, 311 [m. 923] senesinde Nîşâpûrda vefât etdi. İmâm-\nül-eimme denir. Yüzkırkdan fazla kitâbı vardır. Hadîs âlimidir.", "gectigiMaddeler": ["1/79", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Mahmûd Bâbertî", "slug": "muhammed-bin-mahmud-baberti-rahmetullahi-teala-al", "unvan": "", "kategori": "alim", "biyografi": "Ekmelüddîn-i Mısrî, Hanefî fıkh âlimidir. 712 [m. 1312] de Bağdâdın Bâberta kasabasında tevellüd ve 786 [m. 1384] da, Mısrda vefât etdi. (Tercîh-u mezheb-i İmâm-ı a’zam) risâlesi ve (İrşâd) ismindeki (Fıkhı ekber) şerhı ve (Envâr) isminde (Menâr) şerhı ve (Tuhfe-tül-ebrâr) ismindeki (Meşârık) şerhı ve (Takrîr) ismindeki (Pezdevî usûli) şerhı ve (İnâye) isminde (Hidâye) şerhı ve dahâşerhleri ve tefsîri vardır. Sa’dî Çelebînin bu (İnâye)ye hâşiyesi vardır.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Mahmûd Harezmî", "slug": "muhammed-bin-mahmud-harezmi-rahmetullahi-teala-al", "unvan": "", "kategori": "alim", "biyografi": "İmâm-ı a’zamın (Müsned)ini toplamışdır. 665 [m. 1266] de vefât etmişdir. Celâlüddîn-i Pânî-pütî, başka olup, yüzdoksanüçüncü sırada bildirilmişdir. 1085. – 1142 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Münkedir", "slug": "muhammed-bin-munkedir", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i \naliyyedendir. Bezzâz idi. 130 [m. 748] senesinde Medînede vefât etdi.", "gectigiMaddeler": ["3/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Süleymân", "slug": "muhammed-bin-suleyman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Medîne-i \nmünevverenin Şâfi’î âlimlerinden idi. 1124 [m. 1712] de Şâmda tevellüd, 1194 [m. \n1780] de Medînede vefât etdi. Çok kitâb yazdı. İki cild fetvâsı meşhûrdur. Vehhâ-\nbîlerin i’tikâdlarının bozuk olduklarına fetvâ verdi.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Süleymân Cezûlî", "slug": "muhammed-bin-suleyman-cezuli-rahmetullahi-teala", "unvan": "", "kategori": "alim", "biyografi": "Ebû Abdüllah Cezûlî [veyâ Cüzûlî], hadîs âlimidir. Şerîflerdendir. Fasda yetişdi. Şâzilî tarîkatinde yükseldi. 870 [m. 1465] senesinde zehrlenerek Fasdaşehîd edildi. Yetmişyedi sene sonra Merrâküşe nakl edildi. Bunun (Delâil-ül-hayrât) salevât kitâbını Kara Dâvüd Muhammed bin Kemâl İzmîtî türkçeye terceme veşerh etmiş, 948 [m. 1541] de Bursada vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed bin Sü'ûd", "slug": "muhammed-bin-suud", "unvan": "", "kategori": "diger", "biyografi": "Arabistânda, Necd çölünde kabîle reîsi idi. \nVehhâbîlik meydâna çıkınca, hâkimiyyetini artdırmak için vehhâbî oldu. İngilizle-\nrin yardımı ile herkesi zorla vehhâbî yapdı. Vehhâbî olmıyan çok müslimânı öldür-\ndü. Birinci Vehhâbî Sü’ûdî devletini kurdu. 1178 [m. 1765] de öldü.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Buhârî", "slug": "muhammed-buhari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMensûr Nevkadî, Semerkand müftîsi iken 434 [m. 1043] de ve Kâdî Muhammed \nZahîrüddîn Buhârî 619 [m. 1222] de ve Muhammed bin Abdürrahmân Zâhid \nBuhârî 546 [m. 1151] de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Cevâd", "slug": "muhammed-cevad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Oniki imâmın \ndokuzuncusudur. Takıy ismi ile meşhûrdur. İmâm-ı Alî Rızânın oğludur. Yüzdok-\nsanbeş [195] senesinde Medînede tevellüd ve ikiyüzyirmi 220 [m. 835] senesinde \nBağdâdda vefât etdi. Zevcesi Ümm-ül-fadlın amcası olan Mu’tesım halîfe ile \ngörüşmek için Bağdâda gidince vefât etmişdir. Zevcesi serâya alınmışdır.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Es'ad", "slug": "muhammed-esad", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyiddir. Nakîb-ül-\neşrâf idi. (Sahhâflarşeyhi zâde) adı ile meşhûrdur. 1264 [m. 1848] senesinde, mec-\nlis-i me’ârif-i umûmiyye reîsi iken vefât etmişdir. Ayasofya câmi’i yanındaki meş-\nhûr (Es’ad efendi) kütübhânesi, şimdi Süleymâniyye umûmî kitâblığındadır. Yeni-\nçeri askerinin ilgâsını anlatan (Üss-i zafer) târîh kitâbı çok kıymetlidir. Başka eser-\nleri de vardır. Mevlânâ Hâlid-i Bağdâdînin seyyid Es’ad efendiye yazdığı arabî \nmektûb, türkce tercemesi ile berâber, (Reşehât) kitâbının kenârında basılmışdır. \n(Ulemâ-ül-müslimîn ve Vehhâbiyyûn)  kitâbının sonunda da vardır.", "gectigiMaddeler": ["1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Es'ad", "slug": "muhammed-esad-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyiddir. Nakîb-ül-\neşrâf idi. (Sahhâflarşeyhi zâde) adı ile meşhûrdur. 1264 [m. 1848] senesinde, mec-\nlis-i me’ârif-i umûmiyye reîsi iken vefât etmişdir. Ayasofya câmi’i yanındaki meş-\nhûr (Es’ad efendi) kütübhânesi, şimdi Süleymâniyye umûmî kitâblığındadır. Yeni-\nçeri askerinin ilgâsını anlatan (Üss-i zafer) târîh kitâbı çok kıymetlidir. Başka eser-\nleri de vardır. Mevlânâ Hâlid-i Bağdâdînin seyyid Es’ad efendiye yazdığı arabî \nmektûb, türkce tercemesi ile berâber, (Reşehât) kitâbının kenârında basılmışdır. \n(Ulemâ-ül-müslimîn ve Vehhâbiyyûn)  kitâbının sonunda da vardır.", "gectigiMaddeler": ["1/74", "1/97", "2/5", "2/46", "2/49", "3/14"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Hakkı", "slug": "muhammed-hakki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Muhammed \nHakkı bin Alî, Hanefîdir. Nâzillide tevellüd, Mekke-i mükerremede 1301 [m. \n1884] de vefât etdi. Üstâdları Ödemişli Halîl efendi ve Muhammed Cân Mekkî \nvâsıtası ile Abdüllah-i Dehlevîye vâsıl olmakdadır. Bezm-i âlem sultân, Muham-\nmed Cân için Mekkede bir tekke yapdırmışdır. (Sakal-bıyık risâlesi), (Hazîne-tül-\nesrâr) arabî olup, Beyrutda (Mekteb-üt-ticâri)de satılmakdadır.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Hân I", "slug": "muhammed-han-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlı pâdişâhla-\nrının beşincisi ve Osmânlı devletinin ikinci kurucusudur. Tîmûr bozgununda esîr \nolmadan Amasyaya geldi. Pederinin vefâtından sonra, burada saltanatını i’lân \netdi. Bursadaki Îsâ çelebiye ve sonra Rumelide Mûsâ çelebîye gâlib geldi. Oniki \nsene aralıkdan sonra 816 [m. 1413] da Osmânlı sultânı oldu. Anadoludaki isyân-\nları basdırdı. Rumelide Macaristâna kadar aldı. Herekeyi ve Gebzeyi de Bizans-\ndan aldı. Serezde ilhâd ve isyân çıkaran Samâvne kâdîsı oğlu denilenşeyh Bedred-\ndîni yakalayıp i’dâm etdi. 824 [m. 1421] senesinde Edirnede vefât edip Bursaya ge -\n– 1143 –\ntirildi. Haremeyne her sene Surre alayı göndermek güzel âdetini çıkarmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Hân IIı", "slug": "muhammed-han-iii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin \nyetmişsekizincisidir ve Osmânlı pâdişâhlarının onüçüncüsüdür. Üçüncü Murâd \nhânın oğlu ve birinci Ahmed hânın babasıdır. Eğri fâtihidir. 974 [m. 1566] de tevel-\nlüd, 1012 [m. 1603] de vefât etdi. Ayasofya câmi’i bağçesindeki türbesindedir. Bu \ntürbede, Ahmed hânın vâlidesi Handan sultân ve Ahmed hânın üçşâhzâdesi ile \naltı kerîmesi ve Murâd hânın onbeş kerîmesi olmak üzere yirmialtı sandûka vardır. \nTürbenin hâricinde de Murâd hânın dört kerîmesi vardır. Üçüncü Muhammed \nhânın oğlu, birinci Mustafâ hân, babasının türbesi yanındaki türbesindedir. Sultân \nMustafâ türbesinde onbeş sanduka olup, birâder zâdesi İbrâhîm hân ve dördüncü \nMurâd hânın kerîmesi İsmihân sultân veşâhzâde ve sultânlar vardır. 1003 [m. \n1593] de halîfe oldu. Celâlî eşkıyâsı ile ve Macarlarla uğraşdı. İçkiyi sıkı yasak \nedip, bütün meyhâneleri kapatdı. Bunun zemânında, 1012 [m. 1603] de tütün içil-\nmeğe başlandı.", "gectigiMaddeler": ["2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Hâ Şim-i Keşmî", "slug": "muhammed-ha-sim-i-kesmi-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Asyada Bedahşânın Keşm kasabasındandır. Seyyid Muhammed Nu’mân hazretlerinin huzûrunda tevbe ve inâbet eyledi. Sohbetinde yetişip, Seyyid hazretlerinin işâreti ile, [1031] senesinde, İmâm-ı Rabbânî hazretlerinin sohbeti ileşereflendi. İmâm-ı Rabbânî iki sene askerde kaldığı zemân hep hizmetinde bulunup, teveccüh ve ihsânlarına kavuşdu. Hâşim-i Keşmî diyor ki, seyyidim Muhammed Nu’mân buyurdu ki, Burhânpurşehrinin câmi’inde Resûlullahı “sallallahü aleyhi ve sellem” dört halîfesi ile rü’yâda gördüm. Beni görünce, hazret-i Sıddîk-ı ekbere karşı buyurdu ki, ( Şeyh Ahmedin kabûl etdiği kimseyi biz de ve Allahü teâlâ da kabûl ederiz. Şeyh Ahmedin red etdiği kimseyi, biz de ve Allahü teâlâ da red ederiz.) Bu sözü işitince, İmâm-ı Rabbânînin makbûllerinden olduğum için, Cenâb-ı Hakkaşükr e", "gectigiMaddeler": ["3/38", "3/40", "3/41", "3/42"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Hayât", "slug": "muhammed-hayat", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şeyh Muhammed \nHayât muhaddis Medenî Sindî 1163 [m. 1749] de Medînede vefât etdi. Babası İbrâ-\nhîmdir. Hanefî fıkh âlimidir. Nevevînin (Erba’în)ini, Münzirînin (Tergîb)ini ve \n(Hikem-i Atâıyye)yişerh, İbni Hacerin (Zevâcir)ini ihtisâr etmişdir. Mezheb tak-\nlîdini bildiren (Gâyet-üt-tahkîk) ve (Nihâyet-üt-tedkîk) risâlesini 1413 [m. 1992] \nde, Hakîkat Kitâbevi basdırmışdır. 208, 466. (Misbâh)ın 103.cü sahîfesi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Kassâb", "slug": "muhammed-kassab", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyye-i aliyye-\ndendir. Dâmeganda va’z verirdi. (Kör olanlar yalnız sıfata bakar. Ni’metleri, \nihsânları görür. Sôfiyye ise, zâta, ihsân yapana bakar. Zâtdan başka olanşeyler \nperdedir, mâni’ olur) derdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Ma'sûm-i Fârûkî", "slug": "muhammed-masum-i-faruki-rahmetullahi-teala-aley", "unvan": "", "kategori": "alim", "biyografi": "İmâm-ı Rabbânî “kuddise sirruhümâ” hazretlerinin üçüncü oğludur. [1007] yılında Serhendde tevellüd, binyetmişdokuz 1079 [m. 1668] da orada vefât etdi. Mu – 1144 – bârek babası türbesinin birkaçyüz metreşimâlindeki büyük türbededir. [1068] de hacca gitdi. Hacdaki hâlleri (Yevâkît-ül-Haremeyn) kitâbında ve Yüsûf-i Nebhânînin (Câmi’u kerâmât-il-evliyâ) kitâbında yazılıdır. İmâm-ı Rabbânînin mescidini Şâh-ı Cihân mermerden yenilemiş, yanında Muhammed Ma’sûm hazretleri için bir oda yapdırmışdır. (Urve-tül-vüskâ) adı ile meşhûrdur. İmâm-ı Rabbânî müceddid-i elf-i sânî Ahmed-i Fârûkî Serhendînin “kuddise sirruhümâ” halef-üs-sıdk ve vâris-i a’zamı idi. Aklî ve naklî ilmlerin, sûrî ve ma’nevî kemâlâtın câmi’iyyetini edinmiş idi. (Kutbiyyet) makâmına ve (Kayyûmiyyet) mansıbına, yüce peder", "gectigiMaddeler": ["1/31", "1/41", "1/46", "1/50", "1/60", "1/64", "2/12", "2/17", "2/24", "2/38", "2/45", "2/47", "2/64", "3/2", "3/36", "3/37", "3/43", "3/53", "3/57", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Ma'sûm-i Ömerî", "slug": "muhammed-masum-i-omeri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Doksa-\nnıncı [90] sırada Ahmed Sa’îd ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Mer'aşî", "slug": "muhammed-merasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdı\n Muhammed \nbin Reşîd Mer’aşî İstanbulda yerleşmişdir. Hanefîdir. Vehbî ve Sünbülzâde ismleri \nile meşhûrdur. 1224 [m. 1809] de vefât etdi. (Tuhfe-i Vehbî) lügati çok basılmışdır. \nEyyûb câmi’i ile Bostan iskelesi arasındaki Mihr-işâh sultânın türbesi ve imâreti \ndışında yazılı kasîdeler bunun olup, Yesârî-zâdenin yazısıdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Murâd I Kazânî", "slug": "muhammed-murad-i-kazani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "[1272] \nhicrî senesinde Rusyada, Kazan vilâyetinin Ufa kasabasında tevellüd etdi. Memle-\nketinde medrese tahsîlini bitirip, 1293 [m. 1876] de Buhârâya geldi. Buhârâ ve Taş-\nkendde tahsîlini temâmlayıp 1295 [m. 1878] de Hindistâna ve Hicâza geldi. Me -\ndîne-i münevverede tarîkat- ı Nakşibendiyyeye intisâb edip, rûh âleminde terak -\n– 1145 –\nkî etdi. 1352 [m. 1933] de vefât etdi. \n1302 [m. 1884] de (Reşehât) kitâbını ve sonra, İmâm- ı Rabbânînin \n(Mektûbât)ını fârisîden arabîye terceme etdi. (Mektûbât)ın arabîsine (Dürer-ül-\nmeknûnât) adını verdi. İmâm-ı Rabbânî hazretlerinin hâl tercemesini de arabî \nuzun yazıp, 1317 [m. 1898] de Mekke-i mükerremede (Mîriyye) matba’asında, \n(Mektûbât)ın kenârında basıldı. İstanbulda Bâyezîdde belediye kütübhânesinde \nelliüç [53] numarada mevcûddür. Bunun foto-kopisi 1383 [m. 1963] de İstanbulda \nbasılmışdır. Bu baskılardaki hâl tercemesinin uzun bir kısmı (Eshâb-ı Kirâm) ve \n(Hak Sözün Vesîkaları) kitâblarında mevcûddur. Bu arabî mektûbâtdan yüzdok-\nsandört mektûb seçilerek, (El-Müntehabât) ismi ile 1392 [m. 1972] senesinde \nİstanbulda ofset yolu ile basdırılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Nu'mân", "slug": "muhammed-numan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mîr Muhammed \nNu’mân bin Seyyid Şemseddîn, 977 [m. 1567] senesinde Semerkandda tevellüd \netdi. Binaltmış 1060 [m. 1650] senesinde Egreşehrinde vefât etdi. Hindistâna \ngelip, hâce Bâkîbillah hazretlerinin sohbeti ileşereflendi. Vefâtına kadar Delhîde \nhizmetinde bulundu. Hâce hazretlerinin vefâtında, İmâm-ı Rabbânî Dehlîye teşrîf \netmişdi. Merhamet buyurup, seyyid Nu’mânı, Serhende götürdü. Uzun zemân hiz-\nmet ve sohbetde bulundukdan sonra, talebe yetişdirmesi için Burhânpura gönde-\nrildi.", "gectigiMaddeler": ["1/45", "1/73", "2/20", "2/25", "2/57", "2/61", "2/67", "3/69"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Osmân", "slug": "muhammed-osman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâcı Muhammed \nOsmân Sâhib, Hindistânda yetişen Evliyânın büyüklerindendir. Hicretin biniki-\nyüzkırkdört [1244] senesinde Pencâbın Loni kasabasında tevellüd, 1314 [m. 1896] \nde Pencâb Musâ zey kasabasında vefât etdi. Binikiyüzaltmışaltı senesinde, Ahmed \nSa’îd-i Serhendî hazretlerinin talebesinden hâcı Dost Muhammed Kandihârînin \nsohbetine kavuşdu. Onsekiz sene feyz aldı. Zâhir ve bâtın ilmlerinde kemâle geldi. \nÜstâdı [1284] senesinde vefât edince yerine geçmekleşereflendi. Binlerle Velî \nyetişdirdi. Yirmidokuz sene, tâlibleri irşâd eyledi. Vefâtından bir sene sonra, baba-\nsının yerinde onyedi yaşında irşâda başlayan oğlu Muhammed Sirâcüddînin emri \nile talebelerinden seyyid Ekber Alî Dehlevînin yazdığı (Fevâid-i Osmâniyye) kitâ-\nbında mektûbları ve kerâmetleri uzun bildirilmişdir. 1382 [m. 1962] de Mültanda \nbasılmışdır. Siracüddîn binüçyüzotuzüç 1333 [m. 1915] senesinde vefât edince, oğlu \nMuhammed Zâhid “rahmetullahi aleyh” zâhir ve bâtın ilmlerinin menbaı oldu. \nSirâcüddînin halîfelerinden Muhammed Fadl Alî Şâh 1354 [m. 1935] de vefât etdi. \nYerinde irşâda başlıyan Muhammed Sa’îd Kureyşî Ahmed purî de 1363 [m. 1944] \nde Pânî-pütşehrinde vefât etdi. Dost Muhammed Kandihârînin (Mektûbât)ındaki \notuz mektûbu Muhammed Âdil toplamış, Muhammed Zâhid bin Sirâcüddînin \nemri ile Atâ Muhammed tarafından 1383 [m. 1964] de Mültanda basılmışdır.", "gectigiMaddeler": ["3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Pârisâ", "slug": "muhammed-parisa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMuhammed bin Mahmûd [756] da Buhârâda tevellüd, 822 [m. 1419] de Medînede \nvefât etdi. Nemâzını, Molla Fenârî kıldırdı. (Umdet-ül-makâmât)da diyor ki, \n(Zeyneddîn Hâfî, kabr taşını Mısrdan gönderdi. Taş 1212 de yerinde idi. 1225 de \ngörmedim. Vehhâbîler kırmış.) Medrese tahsîlini bitirip, hadîs ve fıkh bilgilerin-\nde ihtisâsını ilerletdi. Sonra Muhammed Behâeddîn-i Buhârî hazretlerinin sohbet \nve teveccühlerine kavuşarak kemâle geldi. (Risâle-i kudsiyye), (Tuhfe-tüs-sâli-\nkîn), (Tahkîkât)  ve (Faslül-hitâb) kitâbları meşhûrdur. Hepsi de fârisîdir. \n(Tuhfe)si 1390 [m. 1970] senesinde Delhîde basılmışdır.", "gectigiMaddeler": ["1/26", "1/46", "2/17", "2/52", "2/61"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Rebhâmî", "slug": "muhammed-rebhami", "unvan": "", "kategori": "alim", "biyografi": "“rahmetullahi teâlâ aleyh”: Hindistânın fıkh \nâlimlerindendir. 835 [m. 1432] de yazdığı fârisî (Riyâd-un-nâsıhîn) ismindeki ilmi-\nhâl kitâbı 1313 de Bombayda basılmış, 1981 de İstanbulda ofset baskısı yapılmış-\n– 1146 –\ndır. Bunu dörtyüzkırkdört kitâbdan toplamışdır.", "gectigiMaddeler": ["1/63", "1/78", "2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Sâdık", "slug": "muhammed-sadik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Rabbânî hazretlerinin birinci oğludur. Vilâyet bostanının meyveli ağacı idi. Bin [1000] senesinde Serhendde tevellüd, 1025 [m. 1616] senesinde tâ’ûndan, orada vefât etdi. Babası, kabri üzerine kubbe yapdırdı. [1008] senesinde, pederi ile birlikde hâce Muhammed Bâkî ile teşerrüf edip, zikr almakla, murâkabe, cezbe ve nisbet-işerîfe ileşereflendi. İsti’dâdı ve fıtrati yüksek olduğundan, onların terbiyesi ve merhametli nazarlarının bereketleri sâyesinde kıymetli hâllere ve büyük işlere kavuşdu. Dahâ çocuk iken, uzak yerlerdekişeyleri, mezârdaki hâlleri keşf ederdi. Sonra, kendi peder-i âlîsinden feyz alarak kemâl mertebelerinin sonuna erişdi. Babasının esrârına mahrem oldu. Hazret-i Îşân her Cum’a nemâzlarından sonra, kabr-işerîfine gelip, bir müddet mürâkabe buyururdu.", "gectigiMaddeler": ["3/50", "3/66"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Sâdık", "slug": "muhammed-sadik-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Alîdir. \nSakızlıdır. 1059 [m. 1649] senesinde vefât etdi. (Surre-tül-fetâvâ)\n kitâbı meşhûr-\ndur.", "gectigiMaddeler": ["3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Sâdık Efendi", "slug": "muhammed-sadik-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hafîdzâde \nMuhammed Sâdık bin Muhammed efendi 1230 [m. 1815] da vefât etdi. (Nevâdir-i \nfıkhiyye) kitâbı meşhûrdur.", "gectigiMaddeler": ["1/74"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Sa'îd", "slug": "muhammed-said", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Rabbânî haz-\nretlerinin ikinci mahdûmudur. [1005] senesinde tevellüd, 1070 [m. 1660] senesinde \nvefât etdi. Babasının türbesindedir. Ahlâkının güzelliği, fazîletlerinin çokluğu, \ngüler yüzü, yumuşak sözü, işlerinin hâlis olması ile zînetlenmişdi. Tahsîlini genç \nyaşında bitirdi. Aklî ve naklî bilgilerde mütehassıs oldu. Babasının tesarrufu ve \nteveccühleri sâyesinde, büyüklerinin nisbetine ve yüksek hâllere kavuşdu. Onyedi \nyaşında sûrî ve ma’nevî kemâlâta vâsıl oldu. Birçok kıymetli kitâblara ta’lîkler ve \nhâşiyeler yapdı. (Mişkât-i Mesâbîh) ve Hayâlî hâşiyesine ta’lîkleri çok kıymetlidir. \nNemâzda otururken parmak kaldırmamak için, Hanefî mezhebine göre yazdığı \nrisâlesişâh-eserdir. Parmak kaldırmamanı\nn dahâ iyi olduğunu isbât etmişdir. \nPederinin garîb sırlarına, acîb ma’rifetlerine mahrem idi. (Mektûbât-i Sa’îdiyye) \nkitâbında yüz mektûb vardır. 1385 [m. 1965] de Pâkistânda basılmışdır.", "gectigiMaddeler": ["1/73", "2/8", "2/53", "3/43", "3/46"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Sıddîk", "slug": "muhammed-siddik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hidâye ismi ile \nmeşhûrdur. Bedahşânın Keşm kasabasındandır. Küçük iken, Hân-ı Hânân Abdür-\nrahîmin sohbetinde bulundu. Bunun vâsıtası ile, Hâce Bâkî-billahın sohbeti ileşereflendi. Vefâtından sonra, İmâm-ı Rabbânî hazretlerinin sohbet ve hizmetine \nkavuşdu. Vilâyet-i hâssa ile müşerref oldu. 1032 [m. 1622] de izn alarak hacca gitdi. \nHicâzda iken, İmâm-ı Rabbânî buyurdu ki, ( Şimdi, uzakda olan kardeşlerimizden \nba’zısının ahvâline müteveccih idim. Mevlânâ Muhammed Sıddîk göründü. Tam \nbir sevgi ve ihlâs ile bize müteveccihdir. Şu ânda Mâverâ’ün-nehrde, Bedahşânda \nyolcudur. Hâli hoş olsun!). 1019 senesinde, İmâm-ı Rabbânînin (Mebde’ ve me’âd) \nrisâlesini toplamışdır. Fârisî olup, Urdu tercemesi ile birlikde, 1388 [m. 1968] de \nPâkistânda basılmış, 1977 de İstanbulda ofset baskısı yapılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammedşeybânî", "slug": "muhammedseybani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı a’zam Ebû \nHanîfenin derslerinde yetişen islâm âlimlerinin en üstünlerindendir. Büyük müc -\ntehid idi. İmâm-ı a’zamın derslerini, sözlerini kitâblara geçiren budur. Adı, Muham-\nmed bin Hasen bin Abdüllah bin Tâvus bin Hürmüzdür. Bu Hürmüz, imâm- ı a’zam \nEbû Hanîfenin ceddi olup, Bağdâd sultânı idi. Hazret-i Ömerin elinde îmân etmiş \nidi. 135 [m. 752] senesinde Vâsıtşehrinde tevellüd, 189 [m. 805] senesinde Reyde \nvefât etdi. 120, 133, 134, 137, 138, 144, 154, 155, 231, 234, 268, 269, 285, 293, 294, \n301, 303, 304, 324, 325, 340, 413, 415, 439, 443, 444, 565, 566, 568, 576, 586, 595, 621, \n625, 626, 630, 634, 636, 637, 786, 792, 801, 803, 806, 809, 821, 826, 830, 851, 857, 858, \n– 1147 –", "gectigiMaddeler": ["3/19", "3/20", "3/63", "3/64"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Tarsûsî", "slug": "muhammed-tarsusi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nAhmed bin Muhammed, Hanefî âlimlerindendir. 1117 [m. 1705] senesinde vefât \netdi. Birçok kitâblara hâşiyesi vardır. Tütün harâm değildir, derdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Zâhid", "slug": "muhammed-zahid", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâce Muhammed \nZâhid-i Semerkandî, derin âlim ve veliy-yi kâmil idi. Rûh bilgilerinin mütehassısı \nidi. Dokuzyüzotuzaltı 936 [m. 1530] senesinde Hisârın Vahş köyünde vefât etdi. \nÖnce çok riyâzet ve mücâhede yapdı ise de, Ubeydüllah-i Ahrâr “kuddise sirruh” \nhazretlerinin teveccühü ile birinci sohbetinde kemâle kavuşdu. Ya’kûb-i Çerhî \nhazretlerinin kızının oğludur. (El-Hadâik-ul-verdiyye) kitâbında kerâmetleri yazı-\nlıdır. Mevlânâ Muhammed Kâdînın (Silsile-tül’ârifîn) kitâbı meşhûrdur. (Mes-\nmû’ât) kitâbı Mîr Abdülevvele âid olup, Süleymâniyye kütübhânesi (Es’ad efendi) \nkısmında [1715] sayıda mevcûddur. (Hakîkat Kitâbevi) tarafından 1414 [m. 1993] \nde neşr edilmişdir. Ubeydüllah-i Ahrâr hazretlerinin fârisî sözleridir. Yetişdirdiği \nVelîler arasında, hemşîresinin oğlu mevlânâ Dervîş Muhammed, bu silsilenin \nbüyüklerindendir.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhammed Zihnî", "slug": "muhammed-zihni", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâcı Zihnî efendi, \nOsmânlı devleti me’ârif meclisi a’zâsından idi. [1262] de tevellüd, 1332 [m. 1914] \nsenesinde vefât etdi. Beğlerbeği küplücesindedir. (Ni’met-i İslâm) kitâbı, (Kimyâ-i \nse’âdet mukaddimesi) ile (Elmünkızü aniddalâl) tercemeleri meşhûrdur.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhibbullah-ı Mankpûrî", "slug": "muhibbullah-i-mankpuri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindis-\ntânda, Burhânpurda, şeyh Muhammed bin Fadlullah sohbetine devâm ile halîfe \nolmuş, irşâda icâzet almış iken, seyyid Muhammed Nu’mânın hizmetine devâm \netmiş, burada İmâm-ı Rabbânînin ismini işiterek ve (Mektûbât)ı dinliyerek aşk veşevk ile Serhende gelmişdir. Hizmet ederek, icâzet aldı. Mankpûra irşâda gönde-\nrildi.", "gectigiMaddeler": ["2/3", "2/10", "3/28"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Muhyiddîn-i Arabî", "slug": "muhyiddin-i-arabi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Bekr ibnü \nArabî ismi ile de meşhûrdur. Sôfiyye-i aliyyenin büyüklerindendir. Adışeyh-i \nekber Ebû Bekr-i Muhammed bin Alîdir. 560 [m. 1165] da, Endülüsde Mürsiye \nkasabasında tevellüd, 638 [m. 1240] de Şâmda vefât etdi. Büyük Velî ve müctehid \nidi. Konyaya gelip, Sadreddîn-i Konevînin üvey babası oldu. Nakl etdiği bilgilerin \nhepsi, birer vesîkadır. Devlet ve mevkı’ sâhiblerinden çok hediyye gelir, hepsini \nfakîrlere dağıtırdı. Beşyüzden fazla kitâb yazdı. Câhiller, buna zındık dedi. İbni \nTeymiyye gibiler kâfir dedi. Âlimler, Ârifler ise, veliy-yi kâmil olduğunu anladı. \n(Fütûhât-i Mekkiyye)si dört büyük cild hâlinde 1393 [m. 1973] de Beyrutda basıl-\nmışdır. 50, 79, 84, 90, 93, 94, 279, 388, 414, 458, 497, 696, 727, 736, 739, 750, 927, \n928, 942, 947, 962, 968, 1037, 1117, 1136, 1164, 1193. \nİbn-ül-arabî ismi ile meşhûr olan Kâdî Ebû Bekr ibn-ül-arabî başkadır. İsmi \nMuhammed bin Abdüllahdır. Endülüsde 468 [m. 1076] de tevellüd etmiş, 543 [m. \n1149] de Fasda vefât etmişdir. Mâlikîdir. 391, 431. \nMuhyiddîn Muhammed bin Behâüddîn başka olup, (El-Kavl-ül-fasl) ismindeki \n(Fıkh-ı ekber) şerhı çok kıymetlidir. Buşerh, yeniden yazdırılıp 1979 da, Hakîkat \nKitâbevi tarafından İstanbulda basdırılmışdır. Dokuzyüzellialtıda vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mu'înüddîn-i Çeştî", "slug": "muinuddin-i-cesti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindistânda ye -\ntişen Evliyânın büyüklerindendir. Hâce Kutbüddîn-i Bahtiyârın üstâdıdır. Hâce \nOsmân-ı Hârûnîden Bağdâdda feyz alıp, Hâce hazretleri altıyüzonyedi 617 [m. \n1220] senesinde vefât edinciye kadar hizmetinde bulundu. [1312] de Hindistânda \nbasılan (Enîs-ül-ervâh)  kitâbında, hocasının sohbetini anlatmakdadır. Kitâb \notuzaltı sahîfe olup fârisîdir. Hâce Osmân-i Hârûnî, hâce Şerîf-i Zendenînin, bu \n– 1148 –\nda Mevdûd-i Çeştînin talebesidir. Mu’în-üd-dîn-i Çeştî, [531] de tevellüd, 633 [m. \n1235] senesinde Ecmîrde vefât etdi. Çeşt, Hirâta bir sâat mesâfede bir kariyyedir. \nİmâm-ı Rabbânî Ahmed-i Fârûkî “kuddise sirruh” hicretin binotuzüç [1033] sene-\nsinde Ecmîrşehrine gitmişdi. Orada hâce Mu’înüddîn-i Çeştînin kabrini ziyâret \netdi. (Hoca hazretleri merhamet eyledi. İhsânda bulundu. Husûsî bereketlerinden \nziyâfetde bulundu. Çok konuşduk. Esrâr açıldı. Bana, asker arasında kalmamak \niçin uğraşma! Allahü teâlânın rızâsına tâbi’ ol dedi) buyurdu. Kabre bakan türbe-\ndârlar gelip, kabr üzerinden kaldırılmış olan örtüyü hediyye verdiler. Kabûl ede-\nrek, (Hâce hazretleri en yakın elbisesini bize ihsân etdi. Bunu kefenim olmak için \nsaklıyalım) dedi. Bir sene sonra, buna kefenlendi.", "gectigiMaddeler": ["1/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mukâtil", "slug": "mukatil", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Mukâtil bin Süleymân, \ntefsîr âlimlerindendir. Belhde tevellüd edip, Mervde yetişdi. Basrada yerleşdi. 150 \n[m. 767] de orada vefât etdi. Tefsîri meşhûr olup, Londrada basılmışdır.", "gectigiMaddeler": ["1/97", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Münâvî [veyâ Menâvî]", "slug": "munavi-veya-menavi", "unvan": "", "kategori": "diger", "biyografi": "MÜNÂVÎ [veyâ Menâvî]: Abdürraûf-i Münâvî Şâfi’î âlimi idi. 924 [m. \n1518] de tevellüd, 1031 [m. 1621] de Kâhirede vefât etdi. Çok kitâb yazdı. (Künûz-\nüd-dekâ’ık) kitâbı, [1285] de İstanbulda basılmışdır. İçinde onbin hadîs-işerîf var-\ndır.", "gectigiMaddeler": ["2/1", "2/5", "2/17", "2/43", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Münîb Efendi", "slug": "munib-efendi", "unvan": "", "kategori": "diger", "biyografi": "Hâce Muhammed Münîb efendi, Ayntablıdır. [1182] \nde İstanbula geldi. Anadolu kâdî-askeri oldu. (Siyer-i kebîr) şerhini türkçeye ter-\nceme etmişdir. 1238 [m. 1823] senesinde Aydın Güzelhisârında vefât etdi.", "gectigiMaddeler": ["3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Murâd Hân I", "slug": "murad-han-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sultân Murâd- ı Hüdâven-\ndigâr, Osmânlı pâdişâhlarının üçüncüsüdür. Sultân Orhânın oğlu, Yıldırım sultân \nBâyezîdin babasıdır. 726 [m. 1326] da tevellüd etdi. Bursa vâlîsi oldu. Babası zemâ-\nnında altın para basılmasında hizmeti görüldü. 763 [m. 1362] de, pederi vefât edin-\nce tahta çıkdı. Selçûkî devleti parçalanınca Ankarada bir devlet kuran Ehîlerin, \nKonyadaki Karaman oğulları ile, Osmânlı aleyhine birleşdikleri işitilince, 763 de \nAnkarayı aldı. Lala Şâhin pâşayı ilk serdâr ve sadr- ı a’zam yapdı. Çorlu, Keşân, \nEdirne, Gümülcineyi alıp Bursaya döndü. Bigayı aldı. Haçlı ordusu geldiğinden \nRumeliye geçip (Sırp Sındığı) muhârebesini kazandı. Tunaya kadar aldı. İkiyüzbin \nkişilik ikinci haçlı ordusu geldi. Kosova ovasında çetin savaşı kazandı. Sırb Kralı \nLazari ve kumandanları öldü. Sırb devleti yok edildi. 791 [m. 1389] de, bir yaralı \nsırbın hâlini sorarkenşehîd edildi. Bursada Çekirgede defn edildi. Dîni bütün, âdil, \nmerhametli, fazîletli idi. Otuzyedi gazâ etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Murâd Hân IIı", "slug": "murad-han-iii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin yet-\nmişyedincisi, Osmânlı pâdişâhlarının onikincisidir. İkinci Selîm hânın oğlu, sultân \nüçüncü Muhammed hânın babasıdır. 953 [m. 1546] de tevellüd, 1003 [m. 1595] de \nvefât etdi. Türbesi Ayasofya câmi’i yanındaki, babası ikinci Selîm hân türbesinin \nyanındadır. Selim hânın türbesinde kırkdört sandûka olup, üçüncü Murâd hânın \nvâlidesi Nûr Bânû sultân ve iki pâdişâhınşâhzâdeleri ve kerîmeleri vardır. 1288 [m. \n1871] de beşinci baskısı yapılan (Fezleke-i Târîh-i Osmânî)  kitâbında diyor ki: \n(İkinci Selîm hân, serâydaki yangında yanıp yeniden yapılan dâireleri ve hamâmı \ngezerken, ayağı kayıp mermerler üzerine düşdü. Bu kazâ, ölümüne sebeb oldu.) \nİslâm düşmânları, (Sarı Selîm hamâmda zevk, safâ yaparken serhoş olduğundan \ndüşüp öldü) diye gençleri aldatıyorlar. Uydurma târîh kitâblarına da, bu yalan ve \nçirkin iftirâları yazarak ecdâdımızı lekeliyorlar. Evlâdları, babalarına düşman \nyapıyorlar. Hâlbuki, ikinci Selîm hân halvetiyye meşâyıhinden Süleymân Âmedî-\nden feyz almış, sâlih müslimân idi. Murâd hânın türbesinde ellidört sandûka olup, \nMuhammed hânın vâlidesi Safiyye sultân veşâhzâde ve sultânlar buradadır. 982 \n[m. 1574] de halîfe oldu. Tûnusu aldı. Azerbaycânı, Tebrîzi aldı. Âlimleri çok sever-\ndi. Nakşibendî meşâyıhinden hâce Ahmed Sâdık Kâbilîden feyz alarak kemâle \ngeldi. Rasadhâne ve astronomik araştırmalar ile logaritma hesâbları yapdırdı. Top-\ntaşı tımarhânesini yapdı. Çok hayrât yapdı. Mescid-i harâma kârgir kubbeler yap -\n– 1149 –\ndırdı. Çok para sarf ederek su da getirtdi. Türkçe dîvânını Şems-üd-dîn-i Sîvâsîşerh \netmişdir. \nMurâd hânın vâlidesi Nûr Bânû sultân 991 [m. 1582] senesinde Üsküdârda Zey-\nneb Kâmil çocuk hastahânesi yakınında bulunan Atîk Vâlide câmi’ini yapdırmış-\ndır. İki minârelidir. Nûr Bânû sultân 991 [m. 1582] de vefât etmişdir. Bu câmi’in \nartıklarından Dabaklar mescidini yapmışdır. Câmi’e yakın olarak bir de (Dâr-üş-\nşifâ) mescidi yapdırmışdır.", "gectigiMaddeler": ["1/73", "2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Murâd Hân Iv", "slug": "murad-han-iv", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin sekse-\nnikincisi, Osmânlı pâdişâhlarının onyedincisidir. 1018 [m. 1609] de tevellüd, 1049 \n[m. 1640] da vefât etdi. Babası, birinci Ahmed hânın türbesindedir. Kardeşi ikinci \nOsmân hân da buradadır. 1032 [m. 1623] de halîfe oldu. Yavuz gibi cesûr idi. \nAnnesi Mâhpeyker Kösem sultânın yardımı ile, iş başına, kıymetli adamlar getire-\nrek, ortalığı düzeltdi. Şâh Abbâs Bağdâdı alıp, otuzbin Ehl-i sünneti kadın, çocuk \nayırmadan kesdi. Sadr- ı a’zam hâfız Ahmed pâşa Bağdâdı geri aldı. Îrân askeri \ntelef oldu. Tütün, enfiye ve içkiyi yasak etdi. Kendi harbe giderek Tebrîzi geri aldı. \nİkinci def’a giderek Bağdâdı tekrâr aldı. Kâ’be-i mu’azzamayı yeniden yapdırdı. \nHâfız Ahmed pâşa, Fâtihde Malta çarşısındaki câmi’inin kıble dıvarı önündedir. \nMurâd hân, Revân seferine çıkarken Kandillide bir serây yapılmasını emr eyle-\ndi. 1042 [m. 1632] de seferden dönüşde bu serâya yerleşdi. Burada Muhammed \nadında oğlu oldu. Yedi gece kandiller asılıpşenlik yapıldı. Bu sebeble, buraya, \nKandilli denildi. Kandilli câmi’ini, 1165 [m. 1751] de birinci Mahmûd hân yapdır-\nmışdır. Birinci cihân harbinden sonra yeniden yapıldı. Topkapı serâyında Bağdâd \nköşkünü de yapdırdı. 1033 [m. 1623] de Kavaklardaki kal’aları yapdırdı.", "gectigiMaddeler": ["1/84", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Murâd-i Münzâvî", "slug": "murad-i-munzavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Murâd \nbin Alî Keşmîrî, İstanbuldaki meşâyıhin büyüklerindendir. Buhârâda 1054 [m. \n1643] de tevellüd etdi. Şâm ve Hicâz taraflarında çok seyâhat etdi. Hindistânda Ser-\nhendşehrinde Muhammed Ma’sûm-i Fârûkî hazretlerinden feyz aldı. Kemâle erip \nhilâfetleşereflendi. Şâmda yerleşip, bir medrese yapdı. 1092 [m. 1680] de İstanbula \ngeldi. Eyyûbde beş sene kalıp, Şâma ve hacca gitdi. 1120 [m. 1707] de İstanbula \ngeldi. Sultân Selîmde yerleşdi. Çorlulu Alî pâşa tarafından Bursaya sürüldü. 1129 \n[m. 1716] da tekrâr İstanbula gelip, Eyyûbde reîs-ül-etibbâ Nûh efendi yalısında \nikrâm edildi. 1132 [m. 1719] senesinde vefât etdi. Edirnekapı dışında, Münzevî \ncâmi’i karşısında, birinci sultân Mahmûd hânşeyh-ül-islâmlarından Ahmed Ebül-\nhayr efendinin kabri yanındaki türbesini ziyâret edenler, mubârek rûhundan feyz \nalmakdadırlar. Türkçe (Âdâb-ı tarîkatin-nakşibendiyye) risâlesi meşhûrdur. (El-\nmüfredât-ül-Kur’âniyye) tefsîri çok kıymetlidir. Tefsîrler, arabî, fârisî ve türkce bir \naradadır. Ebül-hayr efendi 1154 [m. 1741] senesinde vefât etmişdir. 666. cı sırada \nMuhammed Murâd bin Abdüllah Kazânî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Murâd Molla", "slug": "murad-molla", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dâmâd zâde Murâd efen-\ndi, İstanbulda Çarşambada 1189 [m. 1775] da bir tekke ve bir büyük kütübhâne yap-\nmışdır. [1332] deki sayımda, burada [2276] kıymetli kitâb vardı.", "gectigiMaddeler": ["1/70", "1/73"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Murâd Pâşa", "slug": "murad-pasa", "unvan": "", "kategori": "diger", "biyografi": "Nemçe, ya’nî Avusturya muhârebesinden başarı ile dö -\nnünce, 1015 [m. 1605] de Sadr- ı a’zam oldu. Üçüncü Muhammed hânın son senesi \n1012 [m. 1602] de Şâh Abbâsa yenilen ordunun kaçakları, hurûfî kızılbaşları ile \nbirlikde Celâlîısyânı çıkardılar. Buısyân Anadolunun yarısına yayıldığından, \nMurâd pâşa, 1017 [m. 1607] de bunların üzerine yürüdü. Reîsleri Canpolad, \nKalenderzâde ve Kara Saîd gibişakîleri ve otuzbinden ziyâde kızılbaşı, çoğunu \nkuyulara gömerek öldürdü. Doğu Karahisârdaki yuvalarını da basarak, yüzbin \nâsiyi imhâ etdi. 1019 [m. 1610] da Îrâna yürüdü. Zafer kazandıkdan sonra, hastala -\n– 1150 –\nnarak 1020 [m. 1610] senesinde vefât etdi. İstanbula getirilip medresesine defn \nedildi. Doksan yaşında idi. Gayretli, dindâr, Nakşibendî idi. Üçyüzondokuzuncu \n[319] sırada Fâtih ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mürre", "slug": "murre", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Resûlullahın yedinci babasıdır. \nKâ’bın oğludur.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mûsâ", "slug": "musa", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Büyük Peygamberdir. Benî İsrâîle gelen Resûl-\ndür. Avrupalılar, buna Möise, Moşe der. Ya’kûb aleyhisselâmın soyundandır. \nİmrân adında bir zâtın oğludur. Yûsüf aleyhisselâmdan sonra, Benî İsrâîl, Mısrda \nçoğaldı. Dinlerine sarılıp, ibâdet ederlerdi. Fekat, zulm ve hakâret görürlerdi. Îsâ \naleyhisselâmdan bir rivâyete göre, binyediyüzbeş [1705] sene önce, Mûsâ “aleyhis-\nselâm” tevellüd etdi. Annesi bunu bir beşiğe koyup, Nil nehrine bırakdı. Beşik \nFir’avnın serâyı önünden geçerken, Fir’avnın zevcesi (Âsiye) bunu alıp büyütdü. \nKırk yaşına gelince, akrabâlarını öğrenip, onların yanına gitdi. Kendisinden üç yaş \nbüyük olan Hârûn ile buluşdu. Birgün, bir Mısrlı kâfirin [kıptînin], Benî-İsrâîlden \nbirine işkence etdiğini gördü. Kurtarırken, kıptî öldü. Korkup, Medyenşehrine \ngitdi. Orada Şu’ayb aleyhisselâmın kızı ile evlendi. Ona, on sene hizmet etdi. Mısra \ndönmek için yola çıkdı. Yolda Tûr dağında, Allahü teâlâ ile konuşdu. Mısra gelip \nFir’avnı dîne da’vet etdi, Benî İsrâîle serbestlik verilmesini istedi. Fir’avn kabûl \netmedi. (Mûsâ büyük sihrbâzdır. Bizi aldatıp, memleketimizi elimizden almak isti-\nyor) dedi. Yanındaki vezîrlere sordu. Onlar da, (Sihrbâzları topla, onu mağlûb \netsinler) dediler. Sihrbâzlar geldiler. Mısr halkı önünde, ipleri yere atdılar. Her ip, \nyılan görünüp, Mûsâ aleyhisselâma doğru yürüdü. Mûsâ “aleyhisselâm” asâsını \nyere bırakdı. Büyük yılan oldu. İpleri yutdu. Sihrbâzlarşaşırdı. Îmân etdiler. \nFir’avn kızdı. (O, sizin ustanız imiş. Ellerinizi, ayaklarınızı keseceğim. Hepinizi \nhurma dallarına asacağım) dedi. (Biz Mûsâya inandık. Onun Rabbine sığınıyoruz. \nYalnız Onun afv ve merhametini isteriz) dediler. Kâfirlerin suları kan oldu. Kur-\nbağa yağdı. Cild hastalıkları ve üç gün karanlık oldu. Fir’avn, bu mu’cizeleri görün-\nce korkdu. İzn verdi. Mûsâ aleyhisselâm, Benî İsrâîl ile, Mısrdan çıkıp, Kudüse \ndoğru giderken, Fir’avn pişmân oldu. Askerleri ile arkalarına düşdü. Süveyş kör-\nfezi açılıp, mü’minler karşıya geçdi. Fir’avn geçerken, deniz kapandı. Fir’avn aske-\nri ile birlikde boğuldu. Benî İsrâîl, yolda öküze tapanları gördüler. (Biz de böyle \ntanrı isteriz) dediler. Mûsâ aleyhisselâm, (Allahdan başka ma’bûd yokdur. Allah \nsizi kurtardı) dedi. Sonra Tîh çölüne düşdüler. Yoluşaşırdılar. Aç ve susuz kaldı-\nlar. Gökden (Men) ve (Selva) inerdi. Bunları yirlerdi. Asâsı ile yere vurdu. Su \nçıkdı. Bundan içerlerdi. (Helva ile etden bıkdık. Bakla, soğan gibişeyler isteriz) \ndediler. Mûsâ aleyhisselâmı gücendirdiler. Bunun için, kırk sene çölde kaldılar. \nMûsâ “aleyhisselâm”, Hârûn “aleyhisselâm” ı vekîl bırakıp, Tûr dağına gitdi. \nOrada kırk gün ibâdet etdi. Allahü teâlânın kelâmını işitdi. (Tevrât) kitâbı kendi-\nsine indirildi. Tîh çölünde, Sâmirî adında bir münâfık, herkesdeki altınları, süs \neşyâsını eritip, bunlardan bir buzağı yapdı. (Mûsânın ilâhı budur. Buna tapınız!) \ndedi. Tapmağa başladılar. Hârûn aleyhisselâmı dinlemediler. Mûsâ “aleyhisselâm” \nTûrdan gelip bu hâli görünce çok kızdı. Sâmirîye la’net etdi. Kardeşinin sakalından \ntutup darıldı. Pişmân olup kendisine yalvardılar. (Tevrât)a göre ibâdet etmeğe baş-\nladılar. Mûsâ “aleyhisselâm” ümmeti ile Lût gölünün cenûb tarafına geldi. (Üc bin \nUnk) adında bir melik ile harb etdi. Şerî’a nehrişarkındaki yerleri ele geçirdi. Erîhaşehri karşısındaki dağa çıkdı. Ken’ân ilini uzakdan gördü. Yerine Yûşa’ aleyhisse-\nlâmı halîfe bırakıp, yüzyirmi [120] yaşında, orada vefât etdi. Erîhaşehrini, sonra \nKudüsü, Amâlika kâfirlerinden Yûşa’ “aleyhisselâm” ele geçirdi. Yûşa’ “aleyhisse-\nlâm”, Mûsâ aleyhisselâmın hemşîresinin oğludur. Yûsüf aleyhisselâmın soyundan \nolan (Nûn)un oğludur. Mısrda dünyâya gelmişdir. İstanbula geldiği ma’lûm değil-\ndir. Mûsâ aleyhisselâmdan yirmiyedi sene sonra, yüzyirmiyedi [127] yaşında vefât \netdi. Kabri Nablüsşehrinde veyâ Halebe yakın Me’arreşehrinde veyâ İstan -\n– 1151 –\nbuldadır. Hıristiyanlar buna Yeşû’ diyor. \n(Hadîka-tül-cevâmi’) de diyor ki: (İstanbulda, Beykoz tepelerinden birinde ziyâ-\nret edilmekde olan kabrin, Yûşa’ Nebî olduğu söyleniyor ise de, târîhî bilgilere \nuygun değildir. Bir Velî veyâ havârîlerden birinin kabri olabilir. Böyle ise, yine kıy-\nmetlidir. Yûşa’ Nebînin kabri olup olmadığını kesin olarak söylemek câiz değildir. \nBuradaki mescidi, 1169 [m. 1755] da üçüncü Osmân hânın sadr-ı a’zamı Muham-\nmed Sa’îd pâşa yapdırdı. Mescidde sık sık mevlid okunur. Dinlemeğe akın akın \ngidilirdi. Çok toplanıldığından, üçüncü Selîm hân, fitneye sebeb olmamak için, \nburada meşâyıhın zikr yapmasını men’ ve yalnız mevlid okunmasına izn verdi.) \nMûsâ aleyhisselâmdan sonra yine bozuldular. Yetmişbir fırkaya ayrıldılar. Tev-\nrâtı değişdirdiler. (Talmud) denilen din kitâbı yazdılar ki, (Mişnâ) ve (Gamârâ) \ndiye iki kısmdır. (Mîzân-ül-mevâzîn) kitâbı, yehûdîlerin ve hıristiyanların ellerin-\ndeki Tevrât ve İncîl dedikleri kitâbların Allah kelâmı olmadıklarını isbât etmekde-\ndir. Kitâb fârisîdir. Hakîkat Kitâbevi tarafından basdırılmışdır. İkiyüzelliyedinci \nsahîfesinde diyor ki, (Yehûdî i’tikâdına göre, Allahü teâlâ, Mûsâ aleyhisselâma, \nTûr dağında Tevrât kitâbını verdiği gibi, ba’zı ilmleri de ilhâm eylemiş. Mûsâ, bu \nilmleri Hârûna, Yûşa’a ve El-Ye’âzâra bildirmiş. Bunlar da, sonra gelen peygam-\nberlere ve nihâyet mukaddes Yehûdâya bildirmişler. Bu da, mîlâdın ikinci asrında, \nbu ilmleri, kırk senede, bir kitâb hâline getirmiş. Bu kitâba (Mişnâ) denilmiş. Mîlâ-\ndın üçüncü asrında Kudüsde ve altıncı asrında Bâbilde Mişnâya birerşerh yazıl-\nmış. Buşerhlere (Gamârâ) denilmiş. Mişnâ ile iki Gamârâdan birini, bir kitâb hâli-\nne getirip, bu kitâba (Talmud) demişlerdir. Kudüs Gamârâsından meydâna gelen \nTalmuda (Kudüs Talmudu), Bâbil Gamârâsından meydâna gelene (Bâbil Talmu-\ndu) demişlerdir. Hıristiyanlar bu üç kitâba düşmandır. Bu düşmanlıklarının sebeb-\nlerinden birisi, Îsâ aleyhisselâmı asmak için hâzırladıkları çarmıhı taşıyan ve çar-\nmıha gerilme hâdisesinde bulunan Şem’un, Mişnâyı rivâyet edenler arasındadır \nderler. Talmudda müslimânların inandığışeyler de bulunduğu için, hıristiyanlar, \nmüslimânları bu bakımdan da inkâr ediyorlar.) Yehûdîler kendi din adamlarına \n(Haham) derler. El-Ye’âzâr, Hârûn aleyhisselâmın oğlu idi.", "gectigiMaddeler": ["1/3", "1/7", "1/25", "1/31", "1/41", "1/43", "1/46", "1/85", "1/93", "1/94", "1/95", "1/97", "2/17", "2/20", "2/21", "2/22", "2/25", "2/30", "2/47", "2/50", "3/28", "3/31", "3/66"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mûsâ Cârullah Beykıyef", "slug": "musa-carullah-beykiyef", "unvan": "", "kategori": "diger", "biyografi": "Rusyada dinde reformcudur. Ehl-i \nsünnet düşmanıdır. (Fâideli Bilgiler) kitâbımıza bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mûsâ Kâzım", "slug": "musa-kazim", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Oniki imâmın yedincisidir. \nCa’fer-i Sâdıkın oğlu, imâm- ı Alî Rızânın babasıdır. 128 [m. 745] de Medînede \ntevellüd ve 183 [m. 799] de Bağdâdda habshânede vefât etdi. Kâzimiyyededir. \nMehdî, sonra Hârûn Reşîd kendisini Medîneden Bağdâda getirip habs etdiler. \nİsmâ’îliyye fırkası bunun imâmlığını inkâr etdi.", "gectigiMaddeler": ["1/31", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Müseyleme-Tül Kezzâb", "slug": "museyleme-tul-kezzab", "unvan": "", "kategori": "sahabi", "biyografi": "Yemâmede, Peygamber olduğunu \niddi’â eden bir yalancıdır. Önce îmâna gelmişdi. Mürted oldu. Ebû Bekr-i Sıddîkın \n“radıyallahü anh” hilâfetinin ikinci senesinde, Hâlid bin Velîdin askeri ile Yemâ-\nmede büyük muhârebe yapdı. Mürtedlerden yirmibin, müslimânlardan ikibin kişi \nöldü. Müseyleme askeri mağlûb oldu. Hazret-i Hamzanın “radıyallahü anh” kâtili \nolan Vahşî, hazret-i Hamzayışehîd etmiş olduğu kılınc ile Müseylemeyi öldürdü. \nHazret-i Ömerin büyük kardeşi Zeyd bin Hattâb bu muhârebede bayrak taşıyor-\ndu. Bu ve hatîb-i nebevî Sâbit bin Kays Ensârî ve Ebû Dücâne ve Ebû Huzeyfe-\ntebni Utbe ve üçyüzaltmış Muhâcir ve o kadar Ensâr ve binden fazla Tâbi’înşehîd \noldu. Yetmişden ziyâdesi kurrâ hâfız idi.", "gectigiMaddeler": ["2/6"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Müslim", "slug": "muslim", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül-Hüseyn Müslim bin Haccâc \nKuşeyrî, Şâfi’îdir. Hadîs âlimlerinin en üstünlerindendir. 206 [m. 821] da Nîşâpûr-\nda tevellüd, 261 [m. 875] de orada vefât etdi. (Sahîh-i Müslim) kitâbı, (Buhâ -\n– 1152 –\nrî)den sonra, müslimânların en kıymetli temel kitâbıdır. İçinde yedibinikiyüzyet-\nmişbeş [7275] hadîs vardır. Bu iki kitâba (Sahîhayn) denir. İmâm-ı Buhârî ile Nîşâ-\npûrda buluşdu.", "gectigiMaddeler": ["1/97", "2/6", "2/18"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Âtıf", "slug": "mustafa-atif", "unvan": "", "kategori": "diger", "biyografi": "Defterdâr Mustafâ Âtıf efendi, İstanbulludur. [1104] \nde Vefâda kütübhâne yapdı. 1155 [m. 1742] senesinde vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Bekrî", "slug": "mustafa-bekri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kutb-üd-dîn Mustafâ \nbin Kemâlüddîn 1099 [m. 1688] da Şâmda tevellüd, 1162 [m. 1749] de orada vefât \netdi. Fıkhı Abdülganî Nablüsîden, tesavvufu Abdüllatîf-i Halvetîden aldı. Yazdığı \nkitâblar [222] yi aşmakdadır. (El-hikem-ül-ilâhiyye vel-mevârid-ül-behiyye) ve \n(El-vasıyyet-ül-celiyye) ve (Ber-ül-eskâm) kitâbları çok kıymetlidir.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Hân II", "slug": "mustafa-han-ii", "unvan": "", "kategori": "diger", "biyografi": "Sultân dördüncü Muhammedin oğlu, birinci Mah-\nmûd ile sultân üçüncü Osmânın babalarıdır. 1074 [m. 1664] de tevellüd, 1115 [m. \n1703] de vefât etdi. 1106 [m. 1695] da halîfe oldu. Yeni Câmi’ yanında, Turhân sultân \ntürbesindedir. Babası da bu türbededir. Mustafâ hânın silâhdârı olan Çorlulu Alî \npâşa tarafından tersâne içinde iki katlı bir câmi’ yapılmışdır. Mihrâbı üstünde Kâ’be \ntaşı yerleşdirilmişdir. İkinci Mustafâ hânın zevcesi Sâliha sultân, oğlu Birinci Mah-\nmûd hân zemânında, Azâbkapısı dâhilinde sebîl ve çeşme, hamâm, mekteb yapmış \nve Arab câmi’ini tecdîd ve tevsî’ eylemişdir. Ta’mîr târîhinin 1147 [m. 1734] olduğu, \nşâdırvânı etrâfındaki beytlerde yazılıdır.", "gectigiMaddeler": ["1/84", "2/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Hân IIı", "slug": "mustafa-han-iii", "unvan": "", "kategori": "diger", "biyografi": "Sultân üçüncü Ahmedin oğlu, üçüncü Selîm hânın \nbabasıdır. 1129 [m. 1717] da tevellüd, 1187 [m. 1774] de vefât etdi. 1171 [m. 1757] \nde halîfe oldu. Yapdırmış olduğu Lâleli câmi’inin yanındaki türbededir. Dört kerî-\nmesi ile iki oğlu da buradadır. Fâtih câmi’ini yeniden yapdırdı. Çakmakçılar yoku-\nşunda kendi adında bir câmi’i vardır. [1174] de Kâdî-köy İskele câmi’ini yapdırdı. \n1177 [m. 1763] de Pâşabağçe İncirliköy câmi’ini yapdırdı. Üsküdârda Ayazma \ncâmi’ini de 1174 [m. 1760] de yapdırmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Kemâl Pâşa", "slug": "mustafa-kemal-pasa", "unvan": "", "kategori": "diger", "biyografi": "1881 de Selânikde doğdu. Osmânlı ordu-\nsunda subay oldu. 1923 de Lozan antlaşması ile Osmânlı devletine son verip, Tür-\nkiye Cumhûriyyetini kurdu. 1934 de Atatürk soyadını aldı. 1938 de İstanbulda \nvefât etdi. Ankaradadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Nâilî", "slug": "mustafa-naili", "unvan": "", "kategori": "diger", "biyografi": "Sultân Abdül’azîz hân zemânında sadr-ı a’zam [Baş \nvekîl] idi. Kabri Fâtih Câmi’i yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Reşîd Pâşa", "slug": "mustafa-resid-pasa", "unvan": "", "kategori": "diger", "biyografi": "1262 [m. 1846] da sadr- ı a’zam oldu. 1274 \n[m. 1857] de öldü. 1252 [m. 1836] de Londra sefîri iken mason oldu. Bir sene sonra \nhâriciye nâzırı oldu. İngilterenin Osmânlı sefîri lord Redcliffe ile berâber hâzırla-\ndıkları (Tanzîmât fermânı)nı sultân Abdülmecîd hâna tasdîk etdirerek, Osmânlı \ntürklerinin din, ahlâk, fen, teknikdeki muvâffakıyyetlerine büyük darbe indirdi. 26 \nŞa’bân 1255 [m. 1839] da Gülhâne meydânında okunan bu fermâna göre, birçokşehrlerde mason locaları açılarak, gençler dinsiz yetişdirilmeğe başlandı. Medrese-\nlerden fen dersleri kaldırılarak, din adamları câhil bırakıldı. İktisâd doktoru pro-\nfesör Ömer Aksu, 22 Ocak 1989 târîhli Türkiye gazetesine verdiği beyânâtda, \n(Bizde batılılaşma hareketinin başlangıcı olarak, 1839 Tanzîmât fermânı gösterilir. \nBiz, batıdan almamız gerekenşeyin teknoloji olduğunu, kültürün ise millî olması \ngerekdiğini görememişiz. Batılılaşma hareketine, hıristiyanlığı benimseme olarak \nbakmışız. Mustafâ Reşîd Pâşanın, ingilizlerle yapdığı ticâret anlaşması, sanâyileş-\nmemize büyük darbe vurmuşdur) demekdedir.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mustafâ Sabrî", "slug": "mustafa-sabri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin so -\nnuncusu olan sultân Vahîdeddîn hân zemânındaki islâm âlimlerindendir. Tokad \nmeb’ûsu idi. 4 Mart 1337 [m. 1919] deşeyh-ul-islâm oldu. Yedi ay sonra yerine Hay-\nderî zâde İbrâhîm efendi geçdi. 31 Temmuz 1920 de ikinci def’aşeyh-ul-islâm olup, \niki ay sonra yerine, sonşeyh-ul-islâm olan Medenî Mehmed Nûrî efendi geçdi. Kay-\n– 1153 –                                  Se’âdet-i Ebediyye 3-F:73\nseri medresesinde Divrikli hâcı Emîn efendiden ders okudu. [1277] de Tokadda \ntevellüd, 1373 [m. 1954] de Mısrda vefât etdi. 1340 [m. 1922] senesinde, İstanbuldan \nKâhireye hicret etdi. Orada yazdığı arabî eserleri ile, zemânının âlimlerini hayretde \nbırakdı. (Mevkıf-ül-akl vel-ilm vel-âlem ) kitâbı dört cilddir. Burada Abdühün islâ-\nmı yıkmak için çalışdığını göstermekde, fikrlerini red etmekdedir.", "gectigiMaddeler": ["2/1", "2/17", "2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Mutrif bin Abdüllah", "slug": "mutrif-bin-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâbi’îndendir. \nÇok takvâ sâhibi idi. Doksanbeş 95 [m. 714] senesinde vefât etdi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nâbî", "slug": "nabi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yûsüf Nâbî efendi Osmânlışâ’irlerin-\ndendir. Urfalıdır. 1124 [m. 1712] senesinde vefât etdi.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nâmık Kemâl", "slug": "namik-kemal", "unvan": "", "kategori": "diger", "biyografi": "Yenişehrli Mustafâ Âsım beğin oğlu, Râtıb bin Osmân \npâşanın torunudur. İstanbulda doğmuş, 1306 [m. 1889] da Sakız adasında ölmüşdür. \nAnası Arnavuddur. Tanınmış masonlardandır. Bir yandan, ikinci Abdülhamîd \nhâna, (Zemânımızın kutbu, asrımızın imâm-ı Rabbânîsi) diye mektûblar yazar ve \nZiyâ pâşa gibi mesâî arkadaşlarını jurnal ederdi. Öte yandan da, halîfeyi kötüleyici \nyazılar yazıp hürriyyet kahramanı olmağa çalışırdı. Riyâkârca yazdığı mektûb ve \njurnallarından birçoğu, İstanbulda başvekâlet arşivinde mevcûddur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Napolyon", "slug": "napolyon", "unvan": "", "kategori": "diger", "biyografi": "Bonapart âilesinin birincisidir. 1182 [m. 1769] de Korsika \nadasında tevellüd, 1236 [m. 1821] da öldü. Ondokuz sene sonra kemikleri Fransaya \ngötürüldü. General ve kumandan iken, kendinden kat kat fazla Avusturya ordula-\nrını mağlûb etdi. İngilizlere karşı gönderilmek istendi ise de, önce Hindistânın \nyolunu kesmek için Mısrı almak lâzım dedi ve 1212 [m. 1798] de Mısra geldi. Şâma \nda yürüdü. Sayda vâlîsi Cezzâr Ahmed pâşa Akkâ kal’asını kahramanca müdâfe’a \nedip, Napolyonun ordusu dağıldı, kaçdı. Ahmed pâşa Şâm vâlîsi yapıldı. 1219 da \nŞâmda vefât etdi. Napolyon, [m. 1804] de Fransız imperatörü oldu. [m. 1812] de \nMoskovaya kadar ilerledi. [m. 1814] de mağlûb olup hükûmetden çekildi. Tekrâr \niş başına geldi ise de, Belçikada Vaterlo muhârebesini gayb edip, çekildi. Yerini \noğlu ikinci Napolyona bırakdı. İngiliz harb gemisine sığındı. \nİngilizler, iyi karşıla-\nmadı. (Sent Halen) adasına habs etdiler. Orada öldü.", "gectigiMaddeler": ["2/4", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nasreddîn Hoca", "slug": "nasreddin-hoca", "unvan": "", "kategori": "diger", "biyografi": "Latîfe sözleri ve hikâyeleri ile meşhûrdur. Akşe-\nhirde 683 [m. 1284] de vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Necâşî", "slug": "necasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Habeş pâdişâhlarının hepsine \n(Necâşî) denir. Resûlullah “sallallahü aleyhi ve sellem” zemânındaki Necâşînin adı \nEshame idi. Nasrânî iken müslimân oldu. Cenâze nemâzını Resûlullah “sallallahü \naleyhi ve sellem” Medînede kıldırdı.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Necmeddîn-i Gazzî", "slug": "necmeddin-i-gazzi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nMuhammed Gazzî, Şâfi’î fıkh âlimlerindendir. [977] de tevellüd, 1061 [m. 1651] \nsenesinde vefât etdi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Necmeddîn-i Kübrâ", "slug": "necmeddin-i-kubra", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin \nÖmer, Hârezmlidir. Bir kimseye teveccüh edince, vilâyet derecesine yükselirdi. \nAmcası olan Ebû Necîb-i Sühreverdîden ve Mısrdaşeyh Rûz-i Behân hazretlerin-\nden feyz aldı. 539 [m. 1145] da tevellüd etdi. 618 [m. 1221] senesinde Hârezme \nCengiz askeri tatârlar hücûm edince, talebelerine: (Memleketinize gidiniz! Şark-\ndan fitne ateşi geliyor. Her tarafı yakacakdır. İslâmiyyetde bu kadar fitne görülme-\nmişdir) dedi. (Düâ buyursanız, bu belâ müslimân memleketlerinden uzaklaş\nsın) \ndediler. Bu, (Kazâ-i mübremdir. Düâ bunu gideremez) buyurdu. Eshâbı Horâsâna \ngitdi. Kâfirlerşehre girince cihâda çıkdı. Şehîd oldu. Kübreviyye veyâ Zehebiyye \ntarîkatinin reîsidir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nemrûd", "slug": "nemrud", "unvan": "", "kategori": "diger", "biyografi": "Keldânî pâdişâhlarına denir. Birinci Nemrûd, Nûh aleyhis-\nselâmın oğlu Hâm soyundandır. Bâbilşehrini yapdı. Heykellere tapardı. İbrâhîm \naleyhisselâmı ateşe atdı. Sivri sineklerle öldü. 62, 356, 391, 850, 1118. \n– 1154 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Neron", "slug": "neron", "unvan": "", "kategori": "diger", "biyografi": "Roma imperatörlerinin beşincisidir. Mîlâdın [37]. ci senesinde \ndoğdu. [m. 68] de vatan hâini i’lân edildi. Mağarada saklanıp kama ile intihâr etdi. \n[m. 54] de üvey babası birinci Klavdiyos ölünce tahta çıkdı. Çok zulm yapardı. \nTiyatrolarda oynardı. [m. 64] de, tiyatro piyesi hâzırlamak için Romanın büyük bir \nkısmını yakdı. Kendi annesini öldürdü. Etrâfına nâmûssuzları topladı. Zevcesini \nde öldürdü. Çok işkence yapdı. Çok adam öldürdü.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesâî", "slug": "nesai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdürrahmân Ahmed bin Alî, \n215 [m. 829] de Horâsânda, Nesâşehrinde tevellüd, 303 [m. 915] de Remleşehrin-\nde vefât etdi. Hadîs âlimidir. (Sünen-i kebîr) ve (Sünen-i sagîr)  adında iki hadîs \nkitâbı çok kıymetlidir. (Sünen-i sagîr) kütüb-i sittedendir.", "gectigiMaddeler": ["2/6", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesefî Abdüllah", "slug": "nesefi-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebülberekât Hâfı-\nzüddîn Abdüllah bin Ahmed, Hanefî fıkh âlimidir. 710 [m. 1310] da Bağdâdda \nvefât etdi. (Vâfî) ve bununşerhı (Kâfî) ve (Kenz-üd-dekâık) kitâbları ve (Medâ-\nrik) tefsîri ile (Menâr) adında üsûl-i fıkh kitâbı meşhûrdur. Ömer Nesefînin (Man-\nzûme)sinişerh edip, (Müstasfâ) adını vermişdir. (Umde-tül-akâid) kitâbı, William \nCourton tarafından 1259 [m. 1843] da Londrada basılmışdır.", "gectigiMaddeler": ["1/66"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesefî Lütfullah", "slug": "nesefi-lutfullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanefîdir. (Hulâ-\nsa-i Gîdânî) fıkh kitâbı meşhûrdur. 750 [m. 1349] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesefî Ömer", "slug": "nesefi-omer", "unvan": "", "kategori": "diger", "biyografi": "Necm-üd-dîn Ebû Hafs Ömer bin Muhammed, Îrânın \nFâris vilâyetinde, Nesef kasabasında 461 [m. 1068] de tevellüd, 537 [m. 1143] de \nSemerkandda vefât etdi. (Akâid-i Nesefî) kitâbı ve Teftâzânîninşerhi ve Abdül’azîz \nFerhârevî Hindînin buşerhe yapdığı (Nebrâs) hâşiyesi çok kıymetlidir. Çeşidlişerh-\nleri vardır. (Zahîre) fıkh kitâbı ve (Manzûme)si meşhûrdur.", "gectigiMaddeler": ["1/26", "1/78", "2/59", "3/19"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesefî", "slug": "nesefi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Meymûn bin Muhammed Nesefî, \nHanefîdir. (Temhîd) akâid kitâbı meşhûrdur. Beşyüzsekiz 508 [m. 1114] senesinde \nvefât etmişdir. Ebû Şekür Muhammed Sülemînin (Temhîd)i başkadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesîmî", "slug": "nesimi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid İmâd-üddîn-i Nesîmî, şâir ve \ntesavvuf ehlinden idi. (Kâmûsül-a’lâm)da, Bağdâdın Nesim nâhiyesinde doğduğu \nyazılıdır. Sultân birinci Murâd- ı Hüdâvendigâr zemânında Bursaya geldi. Mısrdaki \nÇerkes sultânlarının elinde bulunan Halebşehrinde yerleşdi. Orada iken, Vahdet-i \nvücûd serhoşluğundaki ba’zı yazıları ve sözleri, islâmiyyete uygun görülmiyerek, \n820 [m. 1417] de i’dâm edildi. Mesnevîşârihlerinden sarı Abdüllah efendi, (Seme-\nrât-ül-füâd) kitâbında ve İsmâ’îl Hakkı efendi, (Rûh-ul-beyân) tefsîrinde, kendisi-\nnin Ehl-i sünnet ve ehl-i tarîk olduğunu yazmakdadırlar. (Müncid)de ve 990 da ölen, \nTokatlışâir Lutfullah efendinin türkçe (Tezkiret-üş-şu’arâ)sında, Nesîmînin hurûfî \nzındıklarından olduğu bildirilmekdedir. Alî Cânib beğ, (Edebiyyât) kitâbında diyor \nki, (Bu türkşâiri hakkında en mevsûk ma’lûmâtı, kendi asrında yaşamış olan meşhûr \nâlim İbni Hacer-i Askalânî vermekdedir. İbni Hacere göre, seyyid Nesîmî Tebrîzli-\ndir. Asl ismişeyh Nesîmeddîndir. Hurûfîlik denilen yolun müessisi Fadlullah Esterâ-\nbâdînin talebesidir. Dîvânının en doğru olanı Bâyezîd kütübhânesindedir. Âzerî leh-\ncesi ile yazmışdır.) Önce hurûfî olduğu, sonra tevbe etdiği anlaşılıyor. Sarı Abdüllah \nefendinin hâl tercemesi, (Mesnevî) şerhinin önsözünde yazılıdır.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesli Şâh Sultân", "slug": "nesli-sah-sultan", "unvan": "", "kategori": "diger", "biyografi": "813. cü sırada Selîm hân I ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nestorius", "slug": "nestorius", "unvan": "", "kategori": "diger", "biyografi": "Hıristiyanlığın Nestûriyye fırkasını kurdu. Mîlâdın [428]. \nci senesinde, Kostantîniyye patrîki oldu. [m. 421] senesinde, İstanbulda yapılan \ntoplantıda, bunun kitâbı incelendi. Kabûl edildi. Buna göre, Allah birdir. Bunun \nvücûd, hayât ve ilm sıfatlarından, ilm uknûmu [kelime] Îsâya hulûl etmiş, ilâh \nolmuşdur. Meryem, ilâh anası değil, insan anasıdır. Îsâ, Allahın oğludur diyordu. \nBu fikrleri, şark memleketlerinde yayıldı. [m. 431] senesinde, Efesus [Efes]de, dör-\ndüncü papas meclisi kurulup, Nestorius red ve tekfîr edildi. Mısra gitdi. [m. 439] \nda orada öldü. \n– 1155 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nesûhî", "slug": "nesuhi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Nesûh, Halvetî \nmeşâyıhindendir. Kastamonilişeyh Şa’bân-i Velî torunlarındandır. Şa’bân-ı Velî \nsilsilesinden Karabaş tecvîd sâhibi Alî efendinin halîfesidir. 1130 [m. 1717] Rame-\nzânında vefât etdi. Üsküdârda, Doğancılarda, 1099 [m. 1687] senesinde Dördüncü \nMuhammed hânın dâmâdı Hasen pâşanın yapdırdığı câmi’ yanında medfûndur. \nOn cild tefsîri, Niyâzî Mısrî gazelininşerhı ve çeşidli risâleleri vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Neş'et Efendi", "slug": "neset-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hoca Süleymân Neş’et \nefendi, Osmânlı âlim veşâ’irlerindendir. 1148 [m. 1735] de Edirnede tevellüd, 1222 \n[m. 1807] de İstanbulda vefât etdi. (Mesnevî) dersi verirdi. Mesnevînin iki beytine \nMolla Câmî tarafından yapılan fârisî manzumşerhı türkçeye terceme etmişdir. Buşerh ve tercemesi, [1263] de basılmışdır. Dîvânı vardır.", "gectigiMaddeler": ["2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nevevî", "slug": "nevevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yahyâ bin Şeref Nevevî, büyük \nislâm âlimlerindendir. Şâfi’îdir. 631 [m. 1233] de tevellüd, 676 [m. 1277] da \nŞâmda vefât etdi. Çok kitâb yazdı. (Minhâc-üt-tâlibîn) fıkh kitâbı, Râfi’înin (El-\nmuharrer)inin muhtasarıdır. Minhâcın çokşerhleri vardır. Sübkînin ve Süyûtînin \nve ibni Hacer Mekkînin ve Celâlüddîn Mehallîninşerhleri ile Nevreddîn Alî bin \nYahyâ Ziyâdînin Mehallîşerhine hâşiyesi meşhûrdur. (Ravda-tüt-tâlibîn), \n(Rıyâd-us-sâlihîn) ve (Hilye-tül-ebrâr)  da denilen (Ezkâr) kitâbları çok kıymet-\nlidir.", "gectigiMaddeler": ["1/25", "1/46", "1/69", "1/70", "1/85", "2/5", "2/6", "2/15", "2/24", "2/43", "3/2", "3/68"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Newton", "slug": "newton", "unvan": "", "kategori": "diger", "biyografi": "İngiliz matematik ve fizikcisidir. 1052 [m. 1642] de tevellüd, \n1140 [m. 1727] da vefât etdi. Yer çekimi kanûnunu buldu. Işık üzerinde de buluş-\nları vardır. Bir gök dürbünü yapdı.", "gectigiMaddeler": ["2/30", "2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nişâncı Muhammed Pâşa", "slug": "nisanci-muhammed-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Haleb \nkâdîsi pîr Ahmed efendinin oğludur. Üçüncü Murâd hânın nişancısı iken bindört \n1004 [m. 1596] de vefât etdi. Fâtih ile Kara-gümrük arasında yapdırdığı Nişancı \ncâmi’i yanındaki türbesindedir. Câmi’, harâb olmakda iken, 1380 [m. 1960] de baş-\nvekil Adnan Menderes tarafından temelden ta’mîr ve tezyîn edilmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nişâncı Zâde", "slug": "nisanci-zade", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Ahmed \nbin Muhammed bin Ramezân, Edirnede kâdî idi. [898] de tevellüd etdiğini \n(Mir’ât-i kâinât) kitâbında yazmışdır. 1031 [m. 1622] de Edirne yolunda vefât etdi. \n(Mir’ât-i kâinât) ve (Fetâvâ-i rûmiyye) ve başka eserleri vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Niyâzî-i Mısrî", "slug": "niyazi-i-misri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyyenin meşhûrların-\ndan, Halvetî meşâyıhindendir. Anadoluda Soğanlıda tevellüd, Mısrda tahsîl etdi. \nBursada yaşadı. Midilliye nefy edildi. 1105 [m. 1693] de Limni adasında vefât etdi. \nTürkçe divânı çok yanık ve tatlı olup, birkaç kerre basılmışdır. Ba’zı yazarlar, \nbunun için, sonradan sapıtdı diyorlar. (Peygamberimiz Muhammed Mustafâ hepi-\nmizden üstündür. Âli güzel, Eshâbı çok temizdir) beytleri, sapık olmadığını göster-\nmekdedir. İkiyüzikinci [202] sırada Cüneyd-i Bağdâdî ismine bakınız!", "gectigiMaddeler": ["1/64", "2/22", "2/45", "3/43", "3/62"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nizâmüddîn Evliyâ", "slug": "nizamuddin-evliya", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sultân-ül meşâyıh \nEvrenk-Âbâdîdir. Babası Buhârâdan Hindistâna gelip, Bedâyün kasabasında yer-\nleşmişdir. Kendisi 633 de tevellüd, yediyüzyirmibeş 725 [m. 1325] de vefât etdi. \nDelhî civârında Gıyâspurda, Emîr Hüsrev Dehlevî türbesine yakın büyük türbesi \nziyâret edilmekdedir. Yirmi yaşında iken Çeştiyye meşâyıhinden Ferîdeddîn-i \nGenc-işekere intisâb ederek kemâle gelmişdir. (Ferâid-ül-fevâid) ve (Râhat-ül-\nmuhibbîn) kitâbları vardır. Talebesinden Hasen Sencerînin yazdığı (Fevâid-ül-füâd) \nkitâbında hâl tercemesi uzun bildirilmişdir. Talebesinden M.Fahrüddîn, İmâm-ı \na’zamın (Fıkh-ı ekber)inin Molla Aliyy-ül-kârî tarafından yapılanşerhini kısaltarak \nfârisî ve urdu dillerine terceme ederek (Akâid-i nizâmiyye) ismini vermiş, (Hakîkat \nKitâbevi) tarafından 1993 de baskısı yapılmışdır. 721, 733, 767, 1129, 1170, 1177. \n– 1156 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nizâm-Ül-Mülk", "slug": "nizam-ul-mulk", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâce Kıvâm-üd-dîn \nEbû Alî Hasen bin Alî, Îrân Selçûkîlerinden Alb Arslanın ve oğlu Melikşâhın vezî-\nridir. 408 [m. 1018] de Tusşehrinde tevellüd, 485 [m. 1092] de Nihâvendde Hasen \nSabbâhın adamı tarafındanşehîd edildi. Fıkh ve hadîs âlimi idi. Akl, tedbir ve adâ-\nleti ile devleti idâre etdi. Âlimlere, zâhidlere çok ihsân ederdi. Çok sayıda câmi’, \nmedrese, hayrât yapdı. Bağdâdda (Medrese-i nizâmiyye) adında bir üniversite \nyapdı. İsfehânda da büyük mekteb yapdı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nizâr", "slug": "nizar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Resûlullahın ondokuzuncu babası-\ndır. Nizâr, az demekdir. Dünyâya gelince, babası Me’add, bunun alnındaki nûru \ngördü. Çok sevinip, büyük bir ziyâfet vermişdi. Böyle oğul için, bu kadar ziyâfet az \nbirşey demişdi. Bunun için oğlunun ismi Nizâr kaldı. Bu nûr, Âdem aleyhisselâm-\ndan beri oğuldan oğula gelmiş, nihâyet, asl sâhibi olan Muhammed aleyhisselâmda \nkalmışdır. Böylece Adnân oğulları arasında, nûrlu bir soy vardır. Her asrda, bu \nsoydan olan zât, alnındaki nûrdan belli olurdu. Bu zât hangi kabîlede ise, o kabîleşerefli olurdu. Nizâr oğulları arasında buşeref, Mudar ve İlyâs kabîlesinde bulun-\ndu. Sonra Kureyş kabîlesinde kaldı.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nûh", "slug": "nuh", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "İdrîs “aleyhisselâm” göke çıkarıldıkdan sonra, \ninsanlar azdı. Doğru yoldan ayrıldı. Putlara ya’nî heykellere tapmağa başladılar. \nCenâb-ı Hak, bunlara Nûh aleyhisselâmı gönderdi. O zemân, elli yaşında idi. Nice \nyıl, onları dîne da’vet etdi. Yalnız oğulları Sâm, Hâm, Yâfes ile az kimse îmân etdi. \nÇoğu kulak asmadı. Kendi oğlu Yâm, ya’nî Ken’ân bile îmân etmedi. Alay ve \nişkence etdiler. Onlara bed düâ etdi. Beşyüz yaşından sonra, gemi yapması emr \nolundu. Gemi bitince, tûfân oldu. Mü’minler ile gemiye bindi. Gemiye binenlerin \nseksen kişi olduğu ve geminin üç kat olduğu (Arâis-ül-mecâlis)de yazılıdır. Bu \nkitâb Mısrda bası\nlmışdır. Her hayvandan da birer çift aldı. Oğlu Ken’ânı da gemiye \nçağırdı. Ben, dağa çıkar kurtulurum dedi. Bir dalga geldi. Oğlunu alıp boğdu. Sular \ndağları aşdı. İnsanlar ve hayvanlar telef oldu. Altı ay sonra, yağmurlar durdu. \nSular çekildi. Gemi, Hakkârîde Cûdî dağına oturdu. İnsanlar, üç oğlundan üredi. \nNûh aleyhisselâma ikinci Âdem “aleyhisselâm” denildi. Sâmdan arab, fars ve rum, \nHâmdan Hindistân, Habeş ve Afrika halkı, Yâfesden de Asyalılar ve türkler mey-\ndâna geldi. Behreng buğazından Amerikaya da geçip yerleşenler oldu. Nûh “aley-\nhisselâm”, bin yaşında vefât etdi.", "gectigiMaddeler": ["1/11", "1/31", "1/39", "1/46", "1/85", "1/95", "2/15", "2/20", "2/21", "2/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nûh bin Mustafâ", "slug": "nuh-bin-mustafa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Allâme Nûh efendi, \nKonyalıdır. Mısra gitdi. 1070 [m. 1659] de Kâhirede vefât etdi.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Nüzhet", "slug": "nuzhet", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Me’ârif mektûbcusu idi. 1244 de \nİstanbulda tevellüd ve 1304 [m. 1886] de, Sivâsda vefât etdi. Hıristiyanlara cevâb \nolan (İzhâr-ul hak) kitâbının birinci kı\nsmını türkceye terceme ederek (Îzâh-ul-\nhak) ismini vermişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Oğuz Hân", "slug": "oguz-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Eski türkler, şark ve garb türk-\nleri diye ikiye ayrılmışdı. Şark türkleri, beş, garb türkleri, onbeş kabîle idi. Uygur-\nlarşark, Oğuz ve Kırgızlar da, garb türklerinden idi. Hicretden beşbin sene önce, \nHind, Îrân ve Irâka yayılmışlardı. \nOğuz türkleri hicretden binüçyüz sene önce, Oğuz hânın kumandasında, Şâma \nkadar gelmişdi. İslâmiyyet yayılınca, Mâverâünnehr ve Buhârâ tarafları (Horâsân) \nemâretine verildi. Me’mûn halîfe tarafından buraya vâlî ta’yîn edilen Sâmân oğul-\nları, sonra [261] de hükûmet kurdu. Merkezleri Buhârâ idi. Oğuz türkleri ve Sel-\nçuk türkleri, Abbâsî halîfesi Mutî’ zemânında [334] de müslimân oldu. Oğuzların \nen kıymetlisi, Kayı hânın kabîlesi idi. Bunun torunlarından Süleymânşâh, Cengiz \nzemânında Anadolu tarafına gelip, 626 [m. 1229] senesinde Fıratda boğuldu. \nDört oğlu kaldı. Bunlardan Ertuğrul beğ, Cengizlerden uzaklaşmak için, kabîle -\n– 1157 –\nsi ile Sivâs tarafına geldi. Bir tatâr ordusu ile, Selçuk sultânı Alâ’üddîn harb edi-\nyordu. Selçuklulara yardım etdi. Sultân, Ertuğrul beğin Kayı hân kabîlesini Anka-\nra civârına yerleşdirdi. Sonra, beşyüz kişi ile Söğüde yerleşdi. 680 [m. 1281] sene-\nsinde vefât etdi. Üç oğlundan küçüğü olan Osmân beğ, babası yerine emîr seçildi. \n699 [m. 1299] da Osmânlı devletini kurdu.", "gectigiMaddeler": ["2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân Ağa", "slug": "osman-aga", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sultân Ahmed hân- ı evvelin \nbâb-üs-seâde ağası idi. Binyirmibir 1021 [m. 1612] senesinde Kadıköyünde Osmân \nağa câmi’ini yapdı. Bunun yerinde kadı Muhammed efendi câmi’i vardı. Bunun \niçin oraya Kadı-köyü denilmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân Bedreddîn", "slug": "osman-bedreddin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Selmân efen-\ndinin oğludur. 1274 [m. 1857] de Erzurumda tevellüd, 1340 [m. 1922] da Harputda \nvefât etdi. 1293 [m. 1875] de Karsda üçüncü tabur imâmı oldu. O yıllarda seyyid \nTâhânın oğlu ve halîfesi seyyid Ubeydüllah ile ve mevlânâ Hâlidin halîfelerinden \nKufrevîşeyh Muhammed ve Gümüşhâneli Ahmed Ziyâeddînin ve Erzincanlı \nTerzi baba demekle meşhûr Vehbî Hayyâtın talebelerinden hâcı Fehmi efendilerle \nsohbet eyledi. 1297 [m. 1879] de Palu kasabasında yirmisekizinci alayın üçüncü \ntabur imâmı iken seyyid Mahmûd-i Sâminî ile mülâkî oldu. Sâminî, sekizinci \nmüceddid demekdir. Onsekiz günde icâzet aldı. 1325 [m. 1906] de emekli olunca, \nHarputda birçok zevâtı sülûk ile, bir kısmını da yalnız sohbet ile cehâletden kur-\ntardı. İkiyüzbine yakın teşnedilân, çeşme-i feyzinden sîrâb olmuşdur. 1327 [m. \n1908] de Hicâz seferinde, Şâm, Mekke ve Medîne âlimlerinin ta’zîm ve tekrîmleri-\nne mazhar olmuşdur. (Gülzâr-ı Sâminî) adındaki mektûbâtı ve (Gülbün-i irşâd) ve \n(Mecâlis-i sâminiyye) adındaki beş cild kasîdeleri vardır. Beyâz fes üzerine beyâz \nsarık sarardı. Oğulları Nûreddîn ve Ziyâeddîn Uz birer cevher idi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân B‹n Affân", "slug": "osman-bn-affan", "unvan": "rad› yallahü anh", "kategori": "diger", "biyografi": "Ebul’âs bin Ümeyye bin \nAbd-i Şems bin Abd-i Menâf torunudur. Aşere-i mübeşşeredendir. Üçüncü halîfe-\ndir. Resûlullah›n iki k› z› n› ald› ğ› için (Zinnûreyn) denir. Önce müslimân olanlar›n \nbeşincisidir. Zevcesi Rukayye “rad› yallahü anhâ” ile iki kerre Habeşistâna ve \nsonra Medîne-i münevvereye hicret etdi. Çok zengin tüccâr idi. Bütün mal› n›, dîn-i \nislâm için sarf etdi. Hilm ve hayâ ile meşhûrdur. Hicretin yirmidördüncü [24] sene \nbaş› olan Muharremin birinci günü halîfe seçildi. K›br›s adas› n›n ilk fâtihidir. [35]. \nci senenin Zil-hicce ay›nda, Kur’ân-› kerîm okurkenşehîd edildi. Mubarek kan› \nbulunan Kur’ân-› kerîm için, 388. ci sahîfeye bak› n›z! Hadîs-işerîflerle medh-u senâ \nedilmişdir. Orta boylu, gür sakall›, sar› ş›n güzel yüzlü, doğan burunlu idi. Sallanan \ndişlerini alt›n tel ile sard›rm› şd›. Bedr gazâs›ndan başka her gazâda bulundu. Bed-\nrin fazîletine de dâhil edildi. Nemâzda bir rek’atde bütün Kur’ân-› kerîmi okuyan \ndört kimseden biridir. Çok okumakdan iki mushaf eskitdi. Hazret-i Ebû Bekrin \ntoplad› ğ› bir Kur’ân-› kerîmden alt› nüsha dahâ yazd› r›p, alt› vilâyete gönderdi.", "gectigiMaddeler": ["1/25", "1/31", "1/46", "1/61", "1/68", "1/71", "1/84", "1/95", "1/97", "2/16", "2/23", "2/41", "2/42", "2/51", "2/53", "2/61", "2/73", "3/3", "3/4", "3/59", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân Gâzî", "slug": "osman-gazi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sultân birinci Osmân hân, \nErtuğrul beğin oğlu ve Süleymânşâhın torunudur. Süleymânşâh, Cengiz fitnesin-\nde Ahlat taraflarına yerleşmişdi. Osmân hân, Osmânlı devletinin kurucusudur. 656 \n[m. 1258] da Söğüdde tevellüd, 726 [m. 1326] da Söğüdde vefât etdi. Bursadadır. \n680 [m. 1281] de babası Ertuğrul beğ vefât edince yerine geçdi. İnegölü, Karacahi-\nsârı rumlardan aldı. 699 [m. 1299] da Konyadaki Selçûk sultânı üçüncü Alâüddîn \nKeykûbâd, Gazân hâna esîr olunca, Yenişehrde Osmânlı devletini kurdu. Cesûr, \nzekî ve tam bir müslimân idi. Çok cömerd idi. Şeyh Edebâlî hazretlerinin kızı ile \nteehhül edip, bundan Alâüddîn pâşa oldu. Ömer beğin kızı Bâlâ hâtundan da sul-\ntân Orhân oldu. Konya Selçûkî sultânı Alâüddînşâhın altıyüzseksensekiz [688] \nsenesinde sultân Osmâna gönderdiği takdîr ve iltifât ve nasîhatlerle dolu uzun \n– 1158 –\nmektûbu ve sultân Osmânın edeb ve nezâket dolu cevâbı, (Mir’ât-i kâinât)  kitâ-\nbında yazılıdır. Ömrü, rum kâfirleri ile savaşmakla ve islâmiyyeti yaymakla geçdi. \nMüslimânları râhata, huzûra kavuşdurmak için çalışdı. Vefât edeceği zemân, oğlu \nOrhân beğe gönderdiği vasıyyetnâmesi, islâmiyyete olan sevgi ve saygısını ve türk \nmilletinin râhat ve huzûrunu düşündüğünü ve insan haklarına olan gönülden bağ-\nlılığını açıkça bildirmekdedir. Vasıyyetnâmenin özüşöyledir: \n(Allahü teâlânın emrlerine muhâlif bir iş işlemiyesin! Bilmediğini islâm ulemâ-\nsından sorup anlıyasın! İyice bilmeyince bir işe başlamıyasın! Sana itâ’at edenleri \nhoş tutasın! Askerine in’âmı, ihsânı eksik etmiyesin ki, insan ihsânın kulcağızıdır. \nZâlim olma! Âlemi adâletleşenlendir. Ve Allah için cihâdı terk etmiyerek benişâd et! Ulemâya ri’âyet eyle ki, ahkâm- ı islâmiyye işleri nizâm bulsun! Nerede bir \nilm ehli duyarsan, ona rağbet, ikbâl ve hilm göster! Askerine ve malına gurûr geti-\nrip, islâmiyyet ehlinden uzaklaşma! Bizim mesleğimiz Allah yoludur ve maksadı-\nmız Allahın dînini yaymakdır. Yoksa, kuru gavga ve cihângirlik da’vâsı değildir. \nSana da bunlar yaraşır. Dâimâ herkese ihsânda bulun! Memleket işlerini noksânsız \ngör! Hepinizi Allahü teâlâya emânet ediyorum.) Osmânlı sultânları, bu vasıyyet-\nnâmeye cândan sarılmış, devletin altıyüz sene hiç değişmiyen anayasası olmuşdur.", "gectigiMaddeler": ["2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân Hân IIı", "slug": "osman-han-iii", "unvan": "", "kategori": "diger", "biyografi": "İslâm halîfelerinin doksanıncısı ve Osmânlı pâdişâhla-\nrının yirmibeşincisidir. Binyüzaltmışsekiz 1168 [m. 1754] de cülûs etdi. Binyüzyetmiş-\nbir 1171 [m. 1757]de vefât etdi. Yeni câmi’ yanında, Turhân sultân türbesindedir. \nKardeşi birinci Mahmûd hân da buradadır. 1169 [m. 1755] da Üsküdârda (İhsâniyye \ncâmi’i) ile (İhsâniyye mescidi) ni ve aynı senede İstanbulda (Nûr-i Osmâniyye)  \ncâmi’ini yapdırmışdır. Bu câmi’i, kardeşi birinci Mahmûd hân yapdırmağa başlamış-\ndı. Vâlidesi Şâhsuvâr sultân, câmi’ yanındaki türbededir.", "gectigiMaddeler": ["2/46"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân Hopavî", "slug": "osman-hopavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Babası Hasendir. 1241 [m. \n1825] de vefât etdi. (Dürre-tün-nâsıhîn) tefsîri ve hadîs kitâbları vardır.", "gectigiMaddeler": ["2/5", "2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmân Karabıyık", "slug": "osman-karabiyik", "unvan": "", "kategori": "diger", "biyografi": "Hüseyn Hilmi Işıkın talebesi ve Hakîkat Kitâ -\nbevinin müdîridir. İslâm kitâblarının basılması ve yayılmasına çok hizmet etmiş-\ndir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Osmânlı Sultânları", "slug": "osmanli-sultanlari-rahmetullahi-teala-aleyhim-ecm", "unvan": "", "kategori": "alim", "biyografi": "Osmânlı devleti 699 [m. 1299] da kuruldu. Dîn-i islâm ile idâre edildi. Osmânlı sultânları 923 [m. 1517] den i’tibâren bütün müslimânların halîfeleri oldular. Her işlerinde islâmiyyete uydular. Altıyüzyirmiüç sene islâmiyyete hizmet etdiler. Ehl-i sünnet olup, hanefî mezhebinde idiler. Üçüncü kısm, 65. ci maddenin sonuna bakınız! İslâmiyyeti yaymak ve müslimânları korumak için kâfirlerle cihâd yapdılar. İslâmiyyeti bozmak, müslimânları bölmek için saldıran mezhebsizleri terbiye etmek için çok uğraşdılar. Âlûsî (Gâliyye)nin doksanbeşinci sahîfesinde diyor ki, (Yeryüzünü sâlih kullarıma mîrâs bırakırım) meâlindeki âyet-i kerîmenin Osmânlı sultânlarını övdüğünü Abdülganî Nablûsî bildirmekdedir. (Burhân) kitâbı da bunu yazmakdadır. 940 [m. 1534] da Hindistân sâhillerine gitdiler", "gectigiMaddeler": ["1/84", "2/16", "2/17", "2/29", "2/41", "3/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ömer bin Abdül'azîz", "slug": "omer-bin-abdulaziz", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mervân bin Ha -\n– 1159 –\nkemin torunudur. Emevî halîfelerinin sekizincisidir. Annesi, Ömer bin Hattâbın \noğlu Âsımın kızıdır. [60] senesinde Medînede tevellüd, 101 [m. 720] senesinde \nzehrlenerekşehîd edildi. [99] da halîfe oldu. Amcası olan halîfe Abdülmelikin \ndâmâdı idi. Adâletde ikinci Ömer idi. Hazret-i Mu’âviyeden sonra hutbelerde, \nEhl-i beyte la’net edilmeğe başlanmışdı. Bu kötü âdeti kaldırdı. Beyâz, ince ve \nnâzik yüzlü, za’îf, güzel sakallı, sevimli bir zât idi. İmâmlığı, Resûlullah efendimize \nçok benzerdi. Malatyayı rumlardan, yüzbin esîr karşılığı satın aldı.", "gectigiMaddeler": ["1/50", "1/84", "2/17", "2/24", "2/40", "2/53", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ömer bin Alî", "slug": "omer-bin-ali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbni Mülkın Sirâcüddîn \nEbû Hafs Mısrî, Şâfi’î hadîs ve fıkh âlimlerindendir. [723] de tevellüd, 804 [m. \n1401] senesinde vefât etdi. Çok kitâb yazdı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ömer bin Fârıd", "slug": "omer-bin-farid", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tesavvuf büyüklerin-\nden ve Resûlullahın âşıklarındandır. Benî-Sa’d kabîlesindendir. 576 [m. 1180] da \nMısrda tevellüd, 636 [m. 1238] da orada vefât etdi. (Kurâfe)dedir. Onbeş sene \nHicâzda kaldı. (Hamriyye) ve (Tâiyye) kasîdeleri çok makbûldür. (Tâiyye)sinde \ndin bilgilerinin hakîkatini ve Evliyânın zevklerini toplamışdır. Böyle olgun kasîde \nyazmak başkasına nasîb olmamışdır. Yediyüzelli beyt kadardır.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ömer bin Hattâb", "slug": "omer-bin-hattab", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın ikinci halîfesi-\ndir. Aşere-i mübeşşeredendir. Hicret-i Nebeviyyede kırk yaşında idi. Kureyşin \neşrâfından idi. Önce, islâma düşman oldu. Bi’setin altıncı yılında, kırkıncı veyâ \nkırkbeşinci olarak îmâna geldi. Bununla müslimânlar çok kuvvetlendi. Silâhlı ola-\nrak, açıkca hicret etdi. Resûlullahın gelmekde olduğunu Medînedeki müslimânla-\nra müjdeledi. Bütün gazâlarda bulundu. Çok kahramânlık gösterdi. Fârûk adını \naldı. Ebû Bekri halîfe yaparak, karışıklık çıkmasını önledi. Onüçüncü yılın Cemâ-\nzil’âhır ayı yirmisekizinci Salı günü halîfe seçildi. Çok memleket aldı. İslâmın adâ-\nletini bütün dünyâya tanıtdı. Yirmiüçüncü [23] senenin son ayında, câmi’de sabâh \nnemâzına durunca, Mugîre bin Şu’benin kölesi Ebû Lü’lü Fîruz kâfiri tarafından \nbıçakla, karnından yaralanıp yirmidört sâat sonra vefât etdi. Resûlullahın yanına \ndefn edildi. Oğluna, islâmiyyetin emr etdiği kadar değnek vurulmasını emr etdi. \nEshâb-ı kirâm yalvardığı hâlde, bir değnek az vurulmasına izn vermedi. Dayakdan \noğlu bayıldı. Çok üzüldü ise de, pişmân olmadı. Çok hadîs-işerîf ile medh edildi. \nBunların çoğunu hazret-i Alî haber vermişdir. İri yarı, buğday renkli, uzun boylu, \ngözleri kızıl, bıyıklarının ucu sarı idi. Üzüntülü veyâ düşünceli olunca uclarını \nbükerdi. Sakalı ve bıyıkları sık idi. Yanaklarının üzerinde az idi. Sol elini, sağ eli \ngibi iyi kullanırdı. Eğere dokunmadan ata binerdi. Çok heybetli, yüreği çok kuv-\nvetli idi. Edebinden, hayâsından, Resûlullahın huzûrunda o kadar yavaş konuşur-\ndu ki, (Yüksek söyle yâ Ömer! İşitmiyorum) buyurulurdu. Resûlullahın kayın \npederi idi. Hazret-i Alînin dâmâdı idi. Benî-Adiy kabîlesi büyüklerinden olup, \nsoyu Hattâb bin Nüfeyl bin Abdül’uzza bin Rebâh bin Abdüllah bin Kurat bin \nRezâh bin Adiy bin Kâ’bdır.", "gectigiMaddeler": ["1/3", "1/11", "1/25", "1/31", "1/35", "1/46", "1/61", "1/67", "1/70", "1/71", "1/84", "1/95", "1/97", "2/16", "2/17", "2/18", "2/21", "2/23", "2/25", "2/29", "2/35", "2/36", "2/38", "2/40", "2/41", "2/44", "2/47", "2/48", "2/51", "2/52", "2/53", "2/61", "3/3", "3/4", "3/17", "3/23", "3/28", "3/31", "3/36", "3/37", "3/50", "3/55", "3/58", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ömer Fehmî", "slug": "omer-fehmi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Ömer Fehmî bin \nHasen 1292 [m. 1875] de (İzhâr-ül-hak) ikinci kısmını terceme ederek, (İbrâz-ül-\nhak) ismini vermişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ömer Rızâ", "slug": "omer-riza", "unvan": "", "kategori": "diger", "biyografi": "Şâ’ir Muhammed Âkifin dâmâdıdır. 1310 [m. 1893] da Kâ -\nhirede tevellüd, 1371 [m. 1952] de İstanbulda vefât etdi. Edirne-kapıdadır. Câ -\nmi’ulezherde okudu. Muhammed Abduhun reformcu fikrlerine saplandı. Mu -\n– 1160 –\nhammed Alî ismindeki bir Kadyânînin ingilizce tefsîrini türkçeye terceme ederek \n(Tanrı buyruğu) ismini verdi. Burada, Îsâ aleyhisselâmın babası vardır demekde \nve Nahl sûresinin altmışsekizinci âyetine verdiği ma’nâ da küfre sebeb olmakdadır. \nİngilizceden çevirdiği (Asr-ı se’âdet târîhi) de, onun gibi düşünen bir zümre tara-\nfından halkın önüne sürülmekdedir. 468, 499, 887, 1088. \n— PÂNİ-PÜTÎ: Senâüllah ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Paskal", "slug": "paskal", "unvan": "", "kategori": "diger", "biyografi": "Fransız fizikcisidir. 1032 [m. 1623] de tevellüd, 1072 [m. 1662] \nde vefât etdi. Papas idi. Fizikde sıvıların basınc kanûnu ile ve geometride bilhâssa \nkoniler üzerindeki buluşları ile meşhûrdur. Dahâ onsekiz yaşında iken bir hesâb \nmakinesi yapmışdır. Dînî düşünceleri fransız papasları ve papa tarafından kabûl \nedilmemişdir. Hıristiyanlık dîni, ilm ve fen adamlarını kabûl etmemekdedir.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Pastör", "slug": "pastor", "unvan": "", "kategori": "diger", "biyografi": "Fransız kimyâgeridir. 1237 [m. 1822] de tevellüd, 1312 [m. \n1895] de vefât etdi. Bulaşıcı hastalıklar, mikroblar ve aşılar üzerine keşfleri vardır. \nCenâzesinin hıristiyan merâsimi ile kaldırılmasını vasıyyet etmişdir.", "gectigiMaddeler": ["1/11", "2/49"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Paulus", "slug": "paulus", "unvan": "", "kategori": "diger", "biyografi": "Bolüs adında bir yehûdî idi. Fransızlar (Saint Paul) derler. \nMîlâdın ikinci yılında Tarsusda doğdu. Îsevî görünüp, kendini din âlimi tanıtdı. Îsâ \naleyhisselâmdan sonra ilk işi, semâdan inen İncîli yok etdirmek oldu. Îsâ, Allahın \noğludur dedi. Şerâbı ve domuzu halâl etdi. Kıblelerini Kâ’bedenşarka, güneşin \ndoğduğu tarafa döndürdü. Allahın kendisi birdir. Sıfatları üç dürlüdür dedi. Bu \nsıfatlara (Uknûm) dedi. Dönme yehûdînin bu sözleri ilk yazılan dört (İncîl)e, bil-\nhâssa Lukanın İncîline karışdı. Havârîlerden olan Barnabas, bunun yalanlarına \naldanmadı. Îsâ aleyhisselâmdan gördüklerini ve işitdiklerini doğru olarak yazdı. \nFekat bozuk dört İncîle aldananlar, fırka fırka ayrıldı. Birbirine uymaz yetmişiki \nfırka hâsıl oldu. Paulusün düşmanlığı anlaşılarak Kudüsde iki kerre habs edildi. \nSonra Romaya götürüldü. Mîlâdın altmışyedinci [67] senesinde Neron tarafından \norada başı kesildi. Kemikleri, Sen Piyer kilisesindedir. Hazîranın yirmidokuzunda \nyortusu yapılır.", "gectigiMaddeler": ["1/24"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Petrus", "slug": "petrus", "unvan": "", "kategori": "diger", "biyografi": "Sen Piyer de denir. Eski ismi Şem’ûn idi. Havârîlerdendir. \nAndreasın kardeşidir. Üçyüzdoksandokuzuncu [399] sırada (Havârîler) ismine \nbakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Pezdevî", "slug": "pezdevi", "unvan": "", "kategori": "diger", "biyografi": "Üçyüzonyedinci [317] sırada Fahr-ul-islâm ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Pisagor", "slug": "pisagor", "unvan": "", "kategori": "diger", "biyografi": "Eski yunan filosofudur. Bunun felsefesine ( İşrâkıyyun) denir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Râbi'a-i Adviyye", "slug": "rabia-i-adviyye", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Babası İsmâ’îldir. \nZühd ve salâh ile meşhûr bir hâtundur. Basralıdır. Süfyân-ı Sevrî ve Hasen-i Basrî, \nRâbi’adan feyz alırlardı. 135 [m. 752] de Kudüs civârında vefât etdi.", "gectigiMaddeler": ["1/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Râfi'î", "slug": "rafii", "unvan": "", "kategori": "diger", "biyografi": "Yirmiikinci [22] sırada Abdülkerîm-i Râfi’î ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rahmetullah Efendi", "slug": "rahmetullah-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Rahmetullah \nbin Halîl-ür-rahmân Hindî, Hanefî fıkh âlimidir. Delhîde yetişdi. Abdül’azîz hân \nkendisini İstanbula da’vet etdi. Madalya verdi. Ma’âş bağladı. Hıristiyanlara bir \nreddiye yazmasını istedi. İstanbulda, arabca (İzhâr-ül-hak) kitâbını yazdı. Kitâb \ndört cilddir. Mekke baskısı pek nefîsdir. Londradan Hindistâna gelen protestân \npapasları ile yapdığı mücâdelesini ve onları kaçırdığı yazılıdır. Kitâbı Sultân \nAbdül’azîz Hân için yazmışdır. İngiliz gazeteleri, (Bu kitâb yayılırsa, hıristiyanlık \nmahv olur) yazmışlardır. Nüzhet efendi bunun birinci kısmını, Ömer Fehmî efendi \nde ikinci kısmını türkceye terceme etdi. Delhîde hıristiyan papasları ile mücâdele \nedip, hepsini mağlûb etdi. Bu mücâdeleleri (Beyân-ül-hak) kitâbında ve türkce \ntercemesinde yazılıdır. 1306 [m. 1889] da 75 yaşında iken Mekkede vefât etdi.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Râkım Efendi", "slug": "rakim-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Meşhûr hattâtdır. Anado-\nlu kâdı-askeri idi. 1242 [m. 1826] de vefât etdi. Kara-gümrükde Zincirli kuyu civâ-\nrındadır. Mezâr taşındaki yazı kendisinindir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Râkım Efendi", "slug": "rakim-efendi-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Meşhûr hattâtdır. Anado-\nlu kâdı-askeri idi. 1242 [m. 1826] de vefât etdi. Kara-gümrükde Zincirli kuyu civâ-\nrındadır. Mezâr taşındaki yazı kendisinindir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Râsim Efendi", "slug": "rasim-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Eğri kapılı Muhammed \nRâsim efendi, hattât veşâ’irdir. 1099 da İstanbulda tevellüd, 1185 [m. 1771] de \nvefât etmişdir. Ahmed Yekdest hazretlerinin talebesi olan Tatâr Ahmed efendi-\nden feyz almışdır. Nûr-i Osmâniyye câmi’işerîfi orta kapı hâricindeki âyet-i kerî-\nmeler bunun yazısıdır. Câmi’in târîhini gösteren (Humâyûn ola bu nev’u câmi’i \nsultân Osmânın) beytini de bu yazmışdır. Kabri İğri kapı hâricinde, kapıya karşı \nparmaklık içindeki Eshâb-ı kirâmdan Abdüs-Sâdık Âmir bin Ubâdenin ayak tara-\nfındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rat", "slug": "rat", "unvan": "", "kategori": "diger", "biyografi": "Fransız müsteşriki olup, kıymetli islâm kitâblarını fransızcaya terceme etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rebî' bin Haysem", "slug": "rebi-bin-haysem", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Zühd ve takvâsı ile \nmeşhûrdur. 68 [m. 687] de Tusşehrinde vefât etdi.", "gectigiMaddeler": ["2/43", "2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Remlî Hanefî", "slug": "remli-hanefi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Dörtyüzüçüncü [403] sıra-\nda Hayreddîn-i Remlî ismine bakınız!", "gectigiMaddeler": ["3/12"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Remlîşâfi'î", "slug": "remlisafii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Ahmed Şihâbüd-\ndîn-i Remlî, şâfi’î âlimlerinden olup, 973 [m. 1565] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Remlîşâfi'î", "slug": "remlisafii-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Ahmed Şihâbüd-\ndîn-i Remlî, şâfi’î âlimlerinden olup, 973 [m. 1565] de vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Remlîşemsüddîn", "slug": "remlisemsuddin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Allâme Şemseddîn \nMuhammed bin Ahmed bin Ahmed Menûfî, 919 da tevellüd ve 1004 [m. 1596] de \nvefât etmişdir. Çok eser yazmış ve babasının fetvâlarını toplamışdır. Bu fetvâlar, \nİbni Hacerin (Fetâvâ-yı kübrâ)sı kenarında Mı\nsrda 1357 de basılmışdır. Nevevînin \n(Minhâc)ını daşerh etmişdir.", "gectigiMaddeler": ["1/65", "1/80"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Reşîd Pâşa", "slug": "resid-pasa", "unvan": "", "kategori": "diger", "biyografi": "Şerîf Ahmed Reşîd bin seyyid Nu’mân Fikri, Mûsul vâlîsi \nidi. Tekaüd olunca, 1325 [m. 1907] de (Rûh-ul-Mecelle) kitâbını, sekiz cild olarak, \nİstanbulda, bir senede yazmış, bu ve (Dîn-i mübîn-i islâm)  kitâbı basılmışdır.", "gectigiMaddeler": ["1/91", "3/7", "3/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Reşîd Rızâ", "slug": "resid-riza", "unvan": "", "kategori": "diger", "biyografi": "Muhammed Reşîd Rızâ, 1281 [m. 1865] de Lübnânda \nKalemun kasabasında tevellüd ve 1354 [m. 1935] de vefât etdi. Muhammed Abdü-\nhün talebesi olduğu (Müncid)de de yazılıdır. Hocasının dinde reformcu fikrlerini \nyaymak için Mısrda (El-Menâr) mecmû’asını çıkardı. (Elda’vetü vel-irşâd) medre-\nsesinde hocalık yapdı. (El-muhâverât) kitâbında, Ehl-i sünnet mezhebine ve fıkh \nkitâblarına saldırdı. Diyânet işleri reîslerinden Hamdi Akseki bu kitâbı türkçeye \nçevirmişdir. (Fâideli Bilgiler) kitâbında, buna cevâb verilmişdir.", "gectigiMaddeler": ["1/78"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rızâ", "slug": "riza", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Alî Rızâ, oniki imâmın seki-\nzincisidir. İmâm-ı Mûsâ Kâzımın oğlu ve Muhammed Cevâd Takînin babasıdır. \n153 [m. 770] de Medînede tevellüd ve 203 [m. 818] de Tus, ya’nî Meşhedde vefât \netdi. Nemâzını halîfe kıldırdı. Me’mûn halîfe, İmâm hazretlerini çok sever ve \nsayardı. İmâmı dâmâd yapdı. Yerine halîfe olmasını emr ve i’lân edip, paralara \nismini yazdı. Bayrağı ve asker elbisesini siyâh yerine yeşil yapdı. Fekat, İmâm önce \nvefât etdi. Bâyezîd-i Bistâmî, İmâmın sohbeti ileşereflendi.", "gectigiMaddeler": ["1/31", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rişliö", "slug": "rislio", "unvan": "", "kategori": "diger", "biyografi": "Fransada onüçüncü Louisnin başvekîli idi. 993 [m. 1585] de \ntevellüd, 1052 [m. 1642] de vefât etdi. Papas idi. Kardinal olmuşdu. Protestan düş-\nmanı idi. Çok kurnaz ve zâlim idi.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rukayye", "slug": "rukayye", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın kızıdır. Otuzüç yaşında iken \ntevellüd eyledi. Çok güzel idi. Ebû Lehebin oğlu Utbeye nikâh edildi. (Tebbet ye -\n– 1162 –\ndâ) sûresi gelince Utbe, düğünden önce boşadı. Vahy gelerek hazret-i Osmâna ni -\nkâh edildi. Birlikde iki kerre Habeşistâna hicret etdiler. Yirmiiki yaşında iken, Bedr \ngazâsında hasta oldu. Hazret-i Osmâna Bedre gelmeyip zevcesine hizmet etmesi \nemr olundu. Bedr zaferinin müjdesi Medîneye geldiği gün defn olundu.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rutherford", "slug": "rutherford", "unvan": "", "kategori": "diger", "biyografi": "1288 [m. 1871] de Yeni Zelândada tevellüd, 1356 [m. \n1937] de vefât etdi. Fizikcidir. Radio-aktifşu’âların üç çeşid olduğunu buldu. Ato-\nmun yapısını keşf etdi. Gazların ionisation teorisini kurdu. 1326 [m. 1908] da \nNobel mükâfâtını aldı.", "gectigiMaddeler": ["2/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ruzbehân-ı Baklî", "slug": "ruzbehan-i-bakli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şeyh Ebû Muham-\nmed Şîrâzî, Kübrevîyye meşâyıhindendir. Necmüddîn-i Kübrânın mürşididir. Ebû \nNecîb-i Sühreverdînin halîfesi olan Ammâr Yâserin halîfesidir. Altıyüzaltı 606 [m. \n1209] târîhinde Şîrâzda vefât etdi. (Tefsîr-i arâyis), (Kitâb-ül envâr) ve (Şerh-ul-\nşathiyyât) kitâbları vardır.", "gectigiMaddeler": ["2/71"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rükneddîn-i Çeştî", "slug": "rukneddin-i-cesti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Rabbânînin \n“kuddise sirruh” babası olan Abdül-Ehadın üstâdıdır. Şeyh Abdül-kuddüsün ikin-\nci oğlu ve halîfesidir. Tesavvufun ve islâmiyyetin esrârını bildiren (Merec-ül-bah-\nreyn) kitâbı ve (Mektûbât)ı çok kıymetlidir. 983 [m. 1575] senesinde vefât etdi. \nHindistânda babasının yanındadır.", "gectigiMaddeler": ["1/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Rükneddîn-i Hâfî", "slug": "rukneddin-i-hafi", "unvan": "", "kategori": "diger", "biyografi": "(Mesmû’at)  99.cu sahîfesinde ismi geçmekde-\ndir. 99.cu sırada Alaüddevle ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sâbit bin Kays", "slug": "sabit-bin-kays", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ensâr- ı kirâmdandır. Resûlulla-\nhın hatîbi idi. Bütün gazâlarda bulundu. Hazret-i Ebû Bekr zemânında, Arabistâ-\nnın ortasındaki Yemâme cengindeşehîd oldu.", "gectigiMaddeler": ["2/44", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'd bin Ebî Vakkâs", "slug": "sad-bin-ebi-vakkas", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Mâlik bin Übeyd bin \nAbd-i Menâf bin Kâ’b bin Zühre bin Hakîm bin Mürre torunudur. İlk müslimân \nolanların yedincisidir. Cennetle müjdelenen on kişiden biridir. Onyedi yaşında \nmüslimân oldu. Mekkede nemâz kılarlarken, alay eden kâfirin başına deve kemiği \natarak ilk kâfir kanı akıtan bu oldu. Bütün gazâlarda bulundu. Düşmana ilk ok \natan budur. Îrânı alan, Kadsiye zaferini kazanan ordunun başkumandanı idi. \nSonra Irâk vâlîsi oldu. Hazret-i Osmân zemânında Kûfe vâlîsi oldu. Deve ve Sıffîn \nmuhârebelerine karışmadı. Ellibeş 55 [m. 675] senesinde vefât etdi. Medîne-i \nmünevverededir.", "gectigiMaddeler": ["2/23", "2/40", "2/44", "3/15", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'd bin Mu'âz", "slug": "sad-bin-muaz", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Evs kabîlesinin reîsi idi. Hicret-\nden evvel Medînede îmân etdi. Bedr, Uhud ve Hendek gazâlarında bulundu. \nBeşinci yılda, Hendekde aldığı yaradan vefât etdi. Resûlullah “sallallahü aleyhi ve \nsellem” buna çok ağladı. Cenâze nemâzını kendisi kıldırdı. Hadîs-işerîflerle medh \nedilmişdir.", "gectigiMaddeler": ["2/23", "2/47", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'düddîn-i Cebâvî", "slug": "saduddin-i-cebavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sa’dî tarîkatinin \nreîsidir. Babası, Mûsâ Şeybânîdir. Şâmda Havran ile Kuds arasında Cebâ kasaba-\nsındandır. Üç vâsıta ile Ebû Medyen-i Magribîden feyz almışdır. Yediyüz 700 [m. \n1300] senesinde vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'düddîn-i Kaşgarî", "slug": "saduddin-i-kasgari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Molla Câmî’nin \nüstâdı, Nizâm-i Hâmûşun halîfesidir. Bu da, Alâüddîn-i Attârın talebesi idi. Vefâtı \n860 dadır.", "gectigiMaddeler": ["2/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'düddîn-i Muhammed Hamevî", "slug": "saduddin-i-muhammed-hamevi-rahmetullahi-teala-al", "unvan": "", "kategori": "alim", "biyografi": "Büyük Velîdir. Necmüddîn-i kübrâdan feyz almışdır. Sadr-eddîn-i Konevî ile de sohbet etmişdir. (Mahbûbül-muhibbîn) kitâbı meşhûrdur. 650 [m. 1252] senesinde vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'düddîn-i Teftâzânî", "slug": "saduddin-i-teftazani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mes’ûd bin \nÖmer, en büyükşâfi’î âlimlerindendir. 722 [m. 1322] de Horâsânda, Teftâzânda te -\nvellüd, 792 [m. 1389] de Semerkandda vefât etdi. (Mutavvel) kitâbı, (Telhîs) şer -\n– 1163 –\nhi olup, bedî, beyân, me’âni ve belâgat ilmlerini bildirmekdedir. 1309 İstanbul bas-\nkısı nefîsdir. (Telhîs)i Celâlüddîn Muhammed Kazvîni yazmış, 739 da vefât etmiş-\ndir. (Akâid-i Nesefîşerhı) meşhûrdur. Sadr-üş-şerî’anın (Tenvîh) kitâbınaşerhı \nolan (Telvîh) kitâbından, imâm- ı Rabbânînin ders verdiği, (Berekât)da, Bedî’ud-\ndîn isminde yazılıdır. İlm-i kelâmda yazdığı (Mekâsıd) kitâbı ve buna yapdığışerhı \nçok kıymetlidir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'dîçelebî", "slug": "sadicelebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sa’dullah bin Îsâ, Kastamo-\nnilidir. İstanbul kâdîsı ve müftîsi idi. Kemâl pâşa zâdeden sonra, onuncu Şeyh-ul-\nislâm oldu. 945 [m. 1539] de vefât etdi. Eyyûbdedir. Beydâvî tefsîrine ve (İnâye) \nadındaki Hidâyeşerhine ve Fîrûzâbâdî Kâmûsuna yapdığı hâşiyeleri çok kıymetli-\ndir. 518. ci sıraya bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'dîşîrâzî", "slug": "sadisirazi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Müslih-ud-dînşeyh Sa’dî, \nEhl-i sünnet âlimlerindendir. Tesavvuf büyüklerindendir. 589 [m. 1193] da Şîrâzda \ntevellüd ve 691 [m. 1292] de orada vefât etdi. Abdülkâdir-i Geylânînin halîfesinin \ntalebesidir. İlm öğrenmekle, tâlibleri irşâdla ve kâfirlerle cihâdla uğraşdı. Nazm ve \nnesr üzere kitâblar yazdı. (Gülistân) kitâbında Etabekler devletinin beşinci sultânı \nEbû Bekr bin Sa’di çok medh etmekdedir. (Gülistân) ve (Bostân) kitâbları çeşidli \ndillere terceme edilmişdir. Ondört kerre hacca gitdi. Haçlı ordularına esîr düşdü. \nŞîrâzdaki Etabekler devleti 543 den 662 ye kadar devâm etdi.", "gectigiMaddeler": ["2/41", "3/51"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sadreddîn-i Konevî", "slug": "sadreddin-i-konevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebülme’âlî \nMuhammed bin İshak, Sôfiyye-i aliyyeden veşâfi’î kelâm âlimlerindendir. Konya-\nlıdır. Üvey babası olan Muhyiddîn-i Arabîden feyz aldı. Celâleddîn-i Rûmînin ve \nSa’îdeddîn-i Fergânînin hocaları idi. 671 [m. 1272] senesinde vefât etdi. Konyada-\ndır.", "gectigiMaddeler": ["3/52"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sadr-Üş-Şehîd Hüsâmeddîn", "slug": "sadr-us-sehid-husameddin-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Dörtyüzonsekizinci [418] sırada Hüsâmeddîn Ömere bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sadr-Üş-Şerî'a-i Sânî", "slug": "sadr-us-seria-i-sani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ubeydüllah bin \nMes’ûd bin Tâc-üş-şerî’a Ömer, Burhân-üş-şerî’a Mahmûd bin Ubeydüllahın kızının \noğludur. Birinci Sadr-üş-şerî’a Ahmed bin Ubeydüllah, anasının da, babasının da \ndedesidir. Dedesinin (Vikâye) kitâbını hemşerh etmiş, hem de kısaltmışdır. Kısaltdı-\nğına (Muhtasar-ı Vikâye) veyâ (Nikâye) adını vermişdir. Bunun (Vikâyeşerhı)ne \nçeşidli hâşiyeler yapılmışdır. Bunlar arasında, Ehî Çelebînin ve Hasen Çelebînin ve \nimâm-ı Birgivînin hâşiyeleri meşhûrdur. (Tenkîh) ve bununşerhi (Tevdîh) üsûl \nkitâbları çok kıymetlidir. 750 [m. 1349] de Buhârâda vefât etdi. Hasen bin Muham-\nmed Çelebî, molla Fenârî neslinden olup, 886 [m. 1480] da vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Safiyye", "slug": "safiyye", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Hayber yehûdîlerinin başı olan Huyey ibni \nAhtabın kızı idi. Hayberde bir yehûdîye nişanlı idi. Sonra çok zengin olan Kenâne \nbin Hakîk ile evlenmişdi. Hicretin yedinci senesinde Hayber feth olundukda Safiyye \nde esîr edilmişdi. Resûlullahın hissesine düşüp âzâd buyurdu. Îmân eyledi ve Resû-\nlullahın nikâhı ileşereflendi. 50 [m. 670] senesinde Medînede vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Safiyye", "slug": "safiyye-2", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Hayber yehûdîlerinin başı olan Huyey ibni \nAhtabın kızı idi. Hayberde bir yehûdîye nişanlı idi. Sonra çok zengin olan Kenâne \nbin Hakîk ile evlenmişdi. Hicretin yedinci senesinde Hayber feth olundukda Safiyye \nde esîr edilmişdi. Resûlullahın hissesine düşüp âzâd buyurdu. Îmân eyledi ve Resû-\nlullahın nikâhı ileşereflendi. 50 [m. 670] senesinde Medînede vefât etdi.", "gectigiMaddeler": ["1/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Safiyyüddîn-i Erdebîlî", "slug": "safiyyuddin-i-erdebili", "unvan": "", "kategori": "diger", "biyografi": "Tanınmış tesavvufculardandır. Muham-\nmed Geylânîden feyz almışdır. Yediyüzotuzbeş 735 [m. 1335] senesinde Erdebilde \nvefât etdi. Hâcı Bayram- ı velînin feyzi, Erdebîlî yolundan gelmekdedir. Erdebil, \nTebrîz civârında bir kasabadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Salâh [ibni]", "slug": "salah-ibni", "unvan": "", "kategori": "diger", "biyografi": "SALÂH [İbni]: İbni Salâh Osmânşâfi’îşehr-i zûrî, 643 [m. 1277] de vefât \netdi. \n– 1164 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'îd bin Cübeyr", "slug": "said-bin-cubeyr", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tâbi’înin büyüklerin-\ndendir. Hadîs ve tefsîrde bir dâne idi. 95 [m. 714] de Vâsıtda vefât etdi.", "gectigiMaddeler": ["2/16", "2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'îd Efendi", "slug": "said-efendi", "unvan": "", "kategori": "diger", "biyografi": "Hüseyn Hilmi Işıkın pederidir. Eyyûb sultânda Vezîr \ntekke mahallesinin eşrâfından idi. 1929 da vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'îd bin Mensûr", "slug": "said-bin-mensur", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hadîs âlimlerinden-\ndir. Horâsânlıdır. 229 [m. 844] senesinde Mekkede vefât etdi.", "gectigiMaddeler": ["1/98"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'îd bin Müseyyib", "slug": "said-bin-museyyib", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Muhammed \nMedenî, Tâbi’înin büyüklerinden ve Medînedeki yedi büyük âlimdendir. Onbeşin-\nci [15] senede tevellüd, 91 [m. 710] senesinde Medînede vefât etdi. Kırk hac yapdı.", "gectigiMaddeler": ["1/31", "2/42", "2/44", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'îd bin Zeyd", "slug": "said-bin-zeyd", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Aşere-i mübeşşeredendir. Dedesi \nAmr, hazret-i Ömerin amcasıdır. Yine bunun kayın birâderi ve eniştesi idi. Bedr-\nden başka gazâlarda bulundu. Yermük muhârebesinde ve Şâmın fethinde bulun-\ndu. 51 [m. 671] senesinde vefât etdi.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'îdeddîn-i Fergânî", "slug": "saideddin-i-fergani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin \nAhmed, Sôfiyye-i aliyyeden ve fıkh âlimlerindendir. Necîbeddîn Alî Şîrâzîden, bu \nda Şihâbüddîn-i Sühreverdîden ve Sadreddîn-i Konevîden feyz aldı. 699 [m. 1299] \nsenesinde vefât etdi. (Füsûs)uşerh etmişdir. (Menâhic-ül-ibâd) fıkh kitâbını dört \nmezhebe göre fârisî yazmışdır. 1409 [m. 1988] senesinde, Hakîkat Kitâbevi tarafın-\ndan, ofset baskısı yapılarak neşr edilmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'lebe", "slug": "salebe", "unvan": "", "kategori": "diger", "biyografi": "Sa’lebe bin Ebî Hâtıb, Ensârdan idi. Bedr gazâsında bulun-\nmadı. Tefsîrlerin çoğuna göre, (Hazret-i Osmân zemânında vefât etdi. Malının çok \nolması için düâ istedi. Resûlullah “sallallahü aleyhi ve sellem”, (Kanâ’at et!) \nbuyurdu. Düâ için, tekrâr tekrâr isrâr etdi. Düâ buyurunca malı, hayvânları çoğal-\ndı. Onlarla uğraşıp nemâza gelmez oldu. Resûlullahın gönderdiği zekât toplama \nme’mûrlarına zekât vermedi. Hakkında Tevbe sûresinin yetmişaltıncı [76] âyeti \nnâzil oldu. Bunu işitince, sadakasını getirip yalvardı ise de, kabûl buyurulmadı. \n(Sa’lebeye yazıklar olsun!) hadîs-işerîfine hedef olmak felâketine dûçâr oldu.) \nYukarıdaki âyet-i kerîmenin çeşidli kimseler hakkında geldiği ve bunlardan Sa’le-\nbe bin Ebî Hâtıbın meşhûr olduğu (Beydâvî) hâşiyesinin tercemesi olan (Tibyân) \ntefsîrinde ve (Hüseynî), (Ebüssü’ûd) ve (Râzî) tefsîrlerinde uzun yazılıdır. (El-\nisâbe fî-temyîz-is-sahâbe) de birinci cüz, yüzdoksansekizinci sahîfede diyor ki, \n(Münâfık olan Sa’lebe, Bedr gazâsında bulunan Sa’lebe “radıyallahü anh” değil-\ndir. Çünki, Bedr gazâsında bulunan Sa’lebenin Uhud gazâsındaşehîd olduğunu \nİbni Kelbî bildirmekdedir. Bundan başka, Ahmed bin Mûsâ ibni Merdeveyh tefsî-\nrinde yazdığı üzere, ibni Abbâs “radıyallahü anh”, Sa’lebenin zekât vermediğini \nanlatırken, Sa’lebe bin Ebî Hâtıb demekdedir. Bedr gazâsında bulunan ise Sa’lebe \nbin Hâtıbdır. Bundan başka, Resûlullah “sallallahü aleyhi ve sellem”, (Bedr gazâ-\nsında ve Hudeybiyede bulunanların hiçbiri Cehenneme girmez!) buyurdu. Bunlar-\ndan biri münâfık olabilir mi?) Bunun gibi, iki Hâtıb vardır. (Tefsîr-i Mazherî) de, \nNisâ sûresinin altmışbeşinci âyetinde diyor ki, (Hâtıb ibni Ebî Beltea muhâcirîn-\nden idi. Bedr gazâsında bulundu. [Otuz senesinde vefât etdi.] İkincisi, Hâtıb ibni \nBeltea ise, Ensârın arasında olup, bir münâfık idi.) Eshâb-ı kirâmın hepsi Cennete \ngireceklerdir. Allahü teâlâ, hepsinden râzı olduğunu bildirmişdir. Bu müjde, hep-\nsinin îmân ile öleceklerini haber vermekdedir. Fekat, Aşere-i mübeşşereden baş-\nkasının îmân ile öleceği önceden bilinemezdi. Çünki, aralarına karışmış olan \nmünâfıkları Resûlullahdan başka kimse bilmezdi. Bu münâfıklar îmânsız gitdi. \nResûlullahın vefâtından sonra, Eshâb- ı kirâmdan hiçbiri mürted olmadı. Hepsi \nSahâbî olarak öldü. Cennete gitdiler.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sa'lebî", "slug": "salebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû İshak Ahmed bin Muhammed, \nfıkh âlimidir. Nîşâpûrda tevellüd, 427 [m. 1035] de orada vefât etdi. 416. \n– 1165 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sâlih Gülâbî", "slug": "salih-gulabi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Rabbânî “kuddise \nsirruh” hazretlerinin eshâbındandır. İbrik tutmak hizmetini görürdü. Kemâle \nyetişdi. İrşâda izn verildi. Mevlânâ Muhammed Sâlih bir mektûbunda diyor ki: (O \nmukaddes makâmın süpürgecilerinin en aşağısı olan Muhammed Sâlih, o kapının \nhizmetcilerine arz ederim ki, bu garîb zerre, o makâmın kölelerinin sadakasına \nkavuşarak, muhlislerinize ihsân buyurduğunuz hâller içindeyim. Hep tecellîlerleşereflenmekdeyim. Her tecellîde, başka bir fenâ hâsıl olmakdadır. Bir tecellîde, \nbundan başka tecellî olmaz sanıyorum. Bu sonsuz tecellîlerden anlaşılıyor ki, ism-\nlerde ve sıfatlarda ayrı ayrı seyr edip ilerlemek nasîb olmakdadır. Böyle ayrı ayrı \ntecellîlerle, bu yolda ilerlemek pek güc olacakdır. O hakîkî kıblenin kapısına sığı-\nnarak, bu hiçbirşeye yaramıyan beceriksizi, alçak olan yerinden kaldırdığınız, \nböyleşerefli hâllere ulaşdırdığınız ve bu alçağın hâtırına, hayâline bile gelmiyen \nni’metlere kavuşdurduğunuz gibi, lutf ve ihsân buyurarak, husûsî bir teveccühünüz \nile, bu yolun sonuna ulaşdırmanızı, noksânlıkdan, yolda kalmakdan kurtarmanızı, \nkendi murâdlarından, isteklerinden vaz geçerek, Allahü teâlânın rızâsından başka \nhiçbirşey söylememek, yapmamak ve düşünmemek se’âdetine kavuşdurmanızı, \nyalvarırım. Arayanların özlediği o yüksek teveccühünüz ve ihsânınız olmadıkça, \nbunlara kavuşmak imkânsızdır. Ucu bucağı olmıyan, o merhamet deryânızdan bu \nfakîre birkaç damla serpmekleşereflendireceğinizi ümmîd ediyorum. Bunları yaz-\nmak, bunları istemek, bu alçak için çok yersiz olduğunu düşünüyorum. Bu garîbi, \ndoğru olarak, size lâyık olarak sevebilmekleşereflendiriniz. İnsanı, bütün se’âdet-\nlere, bütün yüksekliklere kavuşduracak, ancak, sizi böyle sevebilmekdir. Allahü \nteâlâ, sizin yetişdirme, yükseltme gölgenizi, bütün insanların başları üstünden ayır-\nmasın! Âmîn.) \nMevlânâ Sâlih, İmâm-ı Rabbânî hazretlerinin hergün ve her gece yapdığı ibâ-\ndetleri ve vazîfeleri, mubârek oğullarının işâret ve emrleri üzerine, toplamış ve \nyazmışdır. Bir yerinde diyor ki, ( İbâdetlerinin, vazîfelerinin hepsini yapmaklığım \niçin izn vermelerini ricâ etdim. Yapılacak, uyulacak iş yalnız Resûlullahın “sallal-\nlahü aleyhi ve sellem” yapdıklarıdır. Bunları, hadîs kitâblarından öğrenip, hepsini \nyapmağa çalışmalı buyurdu. Efendim sizin her hareketiniz, her işiniz, o insanların \nve cinnin en yükseğinin işleri gibidir dedim. Evet öyledir. Ammâ, her yapacağınızı \niyi düşününüz! Sünnete uygun olan her sözü, her işi yapınız. Uygun olmıyanı yap-\nmayınız, buyurdu.) Mevlânâ Sâlih, 1038 [m. 1628] senesinde Hindistânda vefât \netdi.", "gectigiMaddeler": ["2/51"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sâlih", "slug": "salih", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Semûd kavmine gönderilen Peygamberdi. Bun-\nlar, Hicâz ile Şâm arasında idi. Âd kavminden sonra idiler. Putlara, heykellere \ntapıyorlardı. Dinlemediler, inanmadılar. Kayadan deve çıkdı, yavruladı. Yine \ninanmadılar. Deveyi öldürdüler. Dağları, taşları oyup, sağlam sığınaklar yapdılar. \nSâlih “aleyhisselâm”, îmân eden birkaç kişi ile, Mekkeye veyâ Kudüse gitdi. Kâfir-\nlere gökden azâb gelip helâk oldular.", "gectigiMaddeler": ["2/20"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sâm", "slug": "sam", "unvan": "", "kategori": "diger", "biyografi": "Nûh aleyhisselâmın büyük oğlu idi. Keldânîler, Âsûrîler, Süryânîler, Finikeliler, İbrânîler ve Arablar, bunun soyundandır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "San'ânî", "slug": "sanani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrezzak Ebû Bekr San’ânî, \nfıkh âlimidir. Yüzyirmiyedide [127] tevellüd ve 211 [m. 826] de vefât etmişdir. (El-\nmusannef) kitâbı 1392 [m. 1972] de Beyrutda basılmışdır. Altı cilddir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "San'ânî", "slug": "sanani-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdürrezzak Ebû Bekr San’ânî, \nfıkh âlimidir. Yüzyirmiyedide [127] tevellüd ve 211 [m. 826] de vefât etmişdir. (El-\nmusannef) kitâbı 1392 [m. 1972] de Beyrutda basılmışdır. Altı cilddir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sedideddîn-i Kaşgarî", "slug": "sedideddin-i-kasgari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed, \n705 [m. 1305] de vefât etdi. (Münye-tül-musallî) fıkh kitâbı meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sehl-i Tüsterî", "slug": "sehl-i-tusteri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Muhammed Sehl bin \n– 1166 –\nAbdüllah, Sôfiyye-i aliyyedendir. 200 [m. 815] senesinde tevellüd, 283 [m. 896] de \nBasrada vefât etdi.", "gectigiMaddeler": ["1/7", "2/40", "2/47", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sehl bin Sa'd", "slug": "sehl-bin-sad", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ensârî ve Sâ’idî, Eshâb-ı kirâmdan-\ndır. Resûlullahın vefâtında onbeş yaşında idi. Seksensekiz 88 [m. 707] senesinde \nvefât etdi. Medîne-i münevverede en son vefât eden Sahâbî budur.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Selâmî Efendi", "slug": "selami-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Selâmî Alî efendi, İstan-\nköy müftîsi iken Zâkirzâde Abdüllah efendiden hilâfet almışdır. Kısıklıda tekke, \nSelâmsızda ve Acıbâdemde ve Bulgurluda birer câmi’ ve Bursada bir tekke yapdır-\nmışdır. 1104 [m. 1693] senesinde vefât edip Kısıklıda defn edilmişdir. Pîrdâşi olan \nseyyid Osmân efendi, Üsküdâr Atpazarında bir câmi’ yapdırmışdır. 1103 [m. 1692]  \nde vefât etmişdir. Selâmî efendinin halîfesi Kütâhyalı seyyid Alî Fenâyî efendi, \neski vâlide câmi’ine yakın bir tekke ve mescid yapmışdır. Mağnisâda da bir câmi’i \nvardır. Baltacı Muhammed pâşanın Rusya seferinde bulunarak bayrak taşımışdır. \n1151 [m. 1738] de vefât etmişdir. Kendi adındaki câmi’i yanındadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Selîm Cihângîrşâh", "slug": "selim-cihangirsah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hindistândaki \nTîmûr sultânlarının dördüncüsüdür. Ekberşâhın oğlu, Hurrem Şâhcihânın babasıdır. \n977 [m. 1569] de tevellüd edip, [1014] de babasının yerine geçdi. 1037 [m. 1627] de \nvefât etdi. Lâhordadır. İmâm-ı Rabbânî hazretlerini 1027 [m. 1617] de habs etdi. İki \nsene sonra pişmân olup özr diledi. Fekat iki sene dahâ askerde bırakdı. Hindistânda \ningilizlere ilk ticâret te’sisleri veren budur. Yerine geçen oğlu, otuzbir sene hükûmet \nsürmüş ve sekiz sene Egrede habs olmuşdur. Zevcesi için burada yapdırmış olduğu \n(Tâc mahal) türbesine 1076 [m. 1665] da defn edilmişdir.", "gectigiMaddeler": ["2/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Selîm Hân I", "slug": "selim-han-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin yetmişdör-\ndüncüsü ve Osmânlı pâdişâhlarının dokuzuncusudur. İkinci Bâyezîd hânın oğlu, sul-\ntân Süleymân hânın babasıdır. Hilâfeti Osmânlı pâdişâhlarına bağlıyan budur. 875 \n[m. 1470] de tevellüd, 926 [m. 1520] da vefât etdi. Fâtihde sultân Selîm câmi’i bağçe-\nsindedir. 920 [m. 1514] de Çaldıranda Îrânşâhı İsmâ’îl-i Safevîyi mağlûb ederek, \nbozuk inanışlarının yayılmasını önledi. Böylece islâmiyyete büyük hizmet etdi. Teb-\nrîzi de aldı. 922 [m. 1516] de İstanbulda ilk tersâneyi yapdı. Burada gemiler inşâ edil-\ndi. 923 [m. 1517] de Mısrı aldı. Haremeyn-işerîfeyn de ele girmiş oldu. Hutbelerde, \n(Mekke ve Medînenin hizmetcisi) diye ismini okutdu. Mısrdaki son Abbâsî halîfesi \nolan Ya’kûb bin Müstemsîk-billahdan emânetleri alarak halîfe oldu. Büyük donan-\nma yapdı. 926 [m. 1520] da Çorlu ovasında hastalanarak vefât etdi. Sekiz buçuk \nsenede devleti iki kat büyütdü. Yavûz adını kazandı. Türbesinin yanındaki bir tür-\nbede, kızı Hadîce sultân ile bunun da kızı Hânım sultân vardır. Başka bir türbede, \nsultân Süleymânın vâlidesi Hafsa sultân ile sultân Süleymânın üç oğlu Murâd, Mah-\nmûd ve Abdüllah efendiler vardır. Bir türbede de sultân Abdülmecîd hân medfûn-\ndur. Kızı Şâh sultân, Dâvüdpâşada bir câmi’ ve tekke ve Eyyûbde Bahâriyye caddesi \nile deniz arasında (Şâh Sultân câmi’i)ni ve yanında, ilkşeyhi Merkez efendi olan tek-\nkesini 963 [m. 1555] de yapdırmış olup, bu câmi’ yanındaki türbededir. \nSelîm hânın kızkardeşi Gevher Mülûk sultânın kızı Nesli-şâh sultân, Edirneka-\npıda ve İstinyede birer câmi’ yapdırmışdır. Zevci İskender beğ ile birlikde Eyyûb-\nde zâl Mahmûd pâşa câmi’i yanındadır. Gevher Mülûk sultân ve zevci Muhammed \nbeğ de buradadır. 487, 500, 504, 1100, 1150, 1173, 1175, 1176, 1195. \nÇaldıran bozgununda Anadoluya dağılan kızılbaşlardan yirmibin kadarı Bozokşeyhi Celâl adında bir sapık yanında toplanarak Turhaldaısyân etdiler. Ankaraya \nyürüdüler. Mer’aş vâlîsi Şâhsuvâr oğlu Alî beğ, 926 da bunları imhâ etdi. Böyle \nkızılbaşısyânlarına (Celâlî vak’ası) denildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Selîm Hân IIı", "slug": "selim-han-iii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm halîfelerinin doksa-\nnüçüncüsü ve Osmânlı pâdişâhlarının yirmisekizincisidir. Sultân üçüncü Mustafâ-\nnın oğludur. 1175 de tevellüd etdi. 1203 [m. 1789] de amcası birinci Abdülhamîd \n– 1167 –\nhândan sonra halîfe oldu. 1222 [m. 1807] de ingiliz câsûslarının teşvîki ile, yeniçeri \nzorbalarıısyân ederek tahtdan indirildi. 1223 [m. 1808] de Topkapı serâyındaşehîd \nedildi. Halîm, selîm ve çok zekî idi. Dâhilde, hâricde düşmanların saldırdığı sırada \ntahta çıkdı. Vehhâbîlik bunun zemânında ortaya çıkdı. Yeni, modern ordu kurma-\nğa başladı. 1205 [m. 1791] de Bahriye mektebi ve Halıcıoğlunda mühendis ve topçu \nmektebleri yapdı. Üsküdârda Selimiyye kışlasını ve 1220 [m. 1805] de Selimiyye \ncâmi’ini ve Çiçekçi câmi’ini yapdı. Eyyûb câmi’ini yeniden büyük olarak yapdı. \nBunu önce Fâtih, küçük yapdırmışdı. Karaca-Ahmedde Miskînler tekkesi denilen \n(Dedeler Mescidi)ni yapdı. Küçük Mustafâ pâşada (Gül câmi’i)ni kiliseden çevir-\ndi. Yeni bölükler kurdu. Tâm islâhata başlıyacağı sıradaşehîd edildi. Lâleli câmi’i \nyanında, babasının türbesindedir. Yerine amcasının oğlu sultân dördüncü Mustafâ \nhân ve bir yıl sonra bunun kardeşi, ikinci Mahmûd hân geçdi.", "gectigiMaddeler": ["2/4", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Selmân-ı Fârisîisfehânlı idi. M", "slug": "selman-i-farisiisfehanli-idi-m", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "SELMÂN-I FÂRİSÎ “radıyallahü anh” İsfehânlı idi. Mecûsî idi. Îrânda iken kiliseye girip hıristiyan oldu. Anadoluya kaçıp, kiliselerde hizmet etdi. Şâma geldi. Medînede âhır-zemân Peygamberinin çıkacağını bir papasdan işitdi. (İncîl)i öğrendi. Âlim oldu. Medîneye girerken, köle yapdılar. Hicretden sonra, Medîneye gelerek, evvelce işitmiş olduğu alâmetleri gördü. Hemen îmân etdi. Çok hâlis müslimân oldu. Ehl-i beytden sayıldı. Hendek gazâsında, hendek kazılmasını istedi. Ondan sonraki gazâların hepsinde bulundu. Hazret-i Ömer zemânında Medâyn vâlîsi oldu. Resûlullahın huzûrunda ve sohbetinde kemâle geldi. Zâhir ve bâtın ilmlerinde çok yüksek derecelere kavuşdu. Eshâb-ı kirâmın hepsi de böyle olmuşdu. Fekat, Resûlullahdan herkes, kendi kâbiliyyeti ve kapasitesi kadar feyz alırdı. Hazre", "gectigiMaddeler": ["1/25", "1/79", "2/21", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Semhûdî", "slug": "semhudi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nûr-üd-dîn Alî bin Abdüllah, \n844 [m. 1440] de Mısrda tevellüd, 911 [m. 1506] de Medînede vefât etdi. Şâfi’îdir. \nŞerîflerdendir. Mescid-i Nebînin ta’mîri, kütübhâne inşâsı ile uğraşdı. Çok kitâb \nyazdı. (Hulâsat-ül-vefâ) ve (Cevâhir-ul-akdeyn) kitâblarını okuyan, İbni Teymiy-\nyenin ve Vehhâbîlerin bozuk yola sapmış olduklarını iyi anlar.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Semnânî", "slug": "semnani", "unvan": "", "kategori": "diger", "biyografi": "Doksandokuzuncu sırada, Alâüddevle ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Senâüllah-i Pânî-Pütî", "slug": "senaullah-i-pani-puti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \nSenâüllah, Şeyh Celâl-i kebîr-i Çeştînin onikinci torunudur. Hazret-i Osmân bin Affân \nsoyundandır. Hanefî, Mazherîdir. 1143 [m. 1730] senesinde Hindistânda Pânî-pütşeh-\nrinde tevellüd etdi. Yedi yaşında Kur’ân-ı kerîmi ezberledi. Naklî ve aklî ilmlerde ihti-\nsâs kazandı. Delhîye giderek Şâh Veliyyullah-i Dehlevîden hadîs ilminde kemâle \ngeldi. Önce mevlânâ Muhammed Âbid-i Semânînin, bundan sonra, Mazher-i Cân- ı \nCânânın teveccühleri ile büyük Velî oldu. Sonra, vatanına gidip, ölünceye kadar kâdî-\nlık ile hizmet etdi. 1225 [m. 1810] de Pânî-pütşehrinde vefât etdi. Mazher-i Cân- ı \nCânân hazretlerinin zevcesinin kabri yanındadır. Şeyh Celâlüddîn de orada büyük bir \ntürbededir. Otuzdan fazla kitâb yazmışdır. (Tefsîr-i Mazherî) si arabîdir. 1384 [m. \n1964] senesinde Delhîde basılmışdır. On cilddir. Büyük fıkh kitâbı ve (İrşâd-üt-tâlibîn) \ntesavvuf kitâbı da çok kıymetlidir. (Kıyâmet ve Âhıret) kitâbı, 290.cı sahîfeye bakınız! \nFârisî (Mâ-lâ-büdde) fıkh kitâbı 1409 [m. 1989] da Hakîkat Kitâbevi tarafından da bas-\ndırılmışdır. (İbn-ül-hüdâ) adı ile meşhûr oldu. Mazher-i Cân- ı Cânân buyurdu ki, \n(Kıyâmet günü, bana, ne getirdin denilince, Senâ-üllah- ı pânîpütîyi getirdim, diyece-\nğim.) Muhammed Âbid hazretleri, Abdül-ehad hazretlerinin talebesidir. Abdül-ehad \n– 1168 –\nhazretleri de, Muhammed Sa’îd-i Fârûkî hazretlerinin oğlu ve talebesi olup, 1126 [m. \n1714] de vefât etmişdir. (Gülşen-i vahdet) adındaki fârisî mektûbâtı, 1386 [m. 1966] da \nKaraşide basılmışdır.", "gectigiMaddeler": ["1/58", "1/71", "1/97", "2/17", "2/39", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Serahsî", "slug": "serahsi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şems-ül-eimme Ebû Bekr \nMuhammed bin Ahmed, Türkistândaki islâm âlimlerindendir. 483 [m. 1090] de \nvefât etdi. On sene habsde kaldı. Habsde iken yazdığı (Usûl) kitâbı ve (Câmi’-i \nkebîr) ve (Câmi’-i sagîr) ve (Siyer-i kebîr), (Muhtasar- ı Tahâvî) şerhleri ve (Meb-\nsût) adındaki (Kâfîşerhi) ve (Muhît) kitâbları meşhûrdur.", "gectigiMaddeler": ["2/16", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sevde", "slug": "sevde", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Sevde binti Zem’a, Resûlullahın üçüncü \nzevcesidir. Zevci ile îmâna gelip Habeşistâna hicret etmişlerdi. Mekkeye dönünce \nzevci vefât etdi. Resûlullah önce hazret-i Âişeyi, sonra Sevdeyi nikâhladı. Sevdeyi \nMekkede, hazret-i Âişeyi ise Medînede evine aldı. Yaşlı olduğundan Medînede \nsırasını hazret-i Âişeye bağışladı. Hazret-i Ömer zemânında vefât etdi.", "gectigiMaddeler": ["1/84"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyf bin Zilyezen", "slug": "seyf-bin-zilyezen", "unvan": "", "kategori": "diger", "biyografi": "Habeş pâdişâhı iken, Abdülmuttalibi Yemende \nserâyına da’vet etdi. Konuşmaları, (Şevâhid-ün-nübüvve)de yazılıdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyfeddîn-i Fârûkî", "slug": "seyfeddin-i-faruki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \nMa’sûm-i Fârûkînin altı oğlu da kemâle gelmiş, vilâyet-i hâssa-i Muhammediyye-\nye kavuşmaklaşereflenmişlerdir. Bunlardan Muhammed Seyfeddîn, tesavvuf bil-\ngilerinin mütehassısı idi. (Muhyis-sünne) adı ile meşhûr oldu. Binkırkdokuz \n[1049] senesinde Serhendşehrinde tevellüd, 1096 [m. 1684] da orada vefât etdi. \nMubârek babasının türbesinin birkaçyüz metre cenûbundaki büyük türbededir. \nÇok kerâmetleri görüldü. (Açlık çekmeğe lüzûm yokdur. Açlık ve nefsle mücâhe-\nde hârika ve kerâmeti artdırır. Evliyânın sohbeti ise, kalbe zikr etmeği yerleşdirir. \nSünnete tâbi’ olmağı kolaylaşdırır) buyururdu. Her sâat emr-i ma’rûf yapardı. \nBindörtyüz Velî yetişdirdi. (Mektûbât-ı Seyfiyye) adındaki kitâbı, 1331 [m. 1913] \nde Haydarâbâdda basılmışdır. İçinde yüzdoksan [190] mektûb vardır.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyid Abdülhakîm Efendi", "slug": "seyyid-abdulhakim-efendi", "unvan": "", "kategori": "diger", "biyografi": "SEYYİD ABDÜLHAKÎM EFEND İ: 14. cü sıradadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyid Abdüllah", "slug": "seyyid-abdullah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah-i Şemdînî, \nHâlid-i Bağdâdînin Süleymâniyye kazâsındaki medresede arkadaşı ve talebesinin \nbüyüklerindendir. 1229 [m. 1813] da ruhsat aldı. Abdülkâdir-i Geylânînin onuncu \ntorunu ve Tâhâ-i Hakkârînin amcasıdır. Şemdinanın Nehri köyünde medfûndur.", "gectigiMaddeler": ["3/37", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyîd Emîr Gilâl", "slug": "seyyid-emir-gilal", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "300. cü sırada, Emîr \nGilâl ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyid Fehîm Efendi", "slug": "seyyid-fehim-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İslâm âlimleri-\nnin büyüklerinden ve Sôfiyye-i aliyyedendir. Tâhâ-i Hakkârînin sohbetinde kemâ-\nle geldi. Seyyid Tâhâ “kuddise sirruh”, 1269 [m. 1852] de vefât edince, kardeşi olan \nseyyid Muhammed Sâlihi ziyâret ederdi. Muhammed Sâlih [1281] de vefât etdi. \nNehride Seyyid Tâhâ yanındadır. Fazla bilgi almak için, (Abdülhakîm Efendi)  ve \n(Tâhâ-yı Hakkârî)  “rahmetullahi teâlâ aleyh” ismlerini ve (Eshâb-ı Kirâm)  kitâ-\nbında, bu ismleri okuyunuz! Seyyid Fehîm efendi [1241] de tevellüd, 1313 [m. \n1895] de vefât etdi. Vanda, Müküs kazâsının Arvâs köyünde medfûndur. Babası, \nmolla Abdülhamîd efendidir. Vâlidesi Âmine hânım, hâcı İbrâhîm efendinin kızı-\ndır. Dedesi seyyid Abdürrahmân, seyyid Abdülhakîm efendinin dedesinin dedesi-\ndir. Seyyid Fehîm efendinin kardeşi Molla Safiyyüddînin torunu Abdülhamîd \nefendi [m. 1967] de hayâtda idi.", "gectigiMaddeler": ["1/77", "3/37", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyid Kutb", "slug": "seyyid-kutb", "unvan": "", "kategori": "diger", "biyografi": "1321 [m. 1903] de Mısrda doğdu. Kâhire ilm enstitüsün-\nde okudu. Önce sosyalist fikrlerini yaydı. Sonra din adamışekline girerek, eski Kâ -\nhire müftîsi ve mason locası başkanı olan Abduhun dinde reformist yolunu tutdu. \nBütün kitâblarında olduğu gibi, (Fî-zılâl-il-Kur’ân) ismindeki tefsîrinin birinci \n– 1169 –                                  Se’âdet-i Ebediyye 3-F:74\ncildinde de, cihâdın bir kısmını kabûl, esâs kısmını inkâr etmekde, (İnsanların dîne \ngirmelerini kolaylaşdırmak için cihâd edilmez) demekdedir. Seyyid Kutb hakkında \nbize sorulanları ve cevâbları, (Fâideli Bilgiler) kitâbında uzun yazılıdır. Lütfen ora-\ndan okuyunuz! (Cihâd, zulm edenlere ve zâlimlere karşıdır) meâlindeki âyet-i kerî-\nmeyi ileri sürerek hükûmetlere karşı ayaklanmağa, ısyâna ve fitne çıkarmağa kış-\nkırtmakdadır. Hâlbuki, zâlim sultânlara, hattâ kâfir hükûmetlere bile ayaklanmağı \ndînimiz yasak etmekdedir. Böyle ayaklanmak, cihâd değil, ahmaklıkdır. Böyle \nzemânlarda yapılacak cihâd, islâm bilgilerini yaymak, îmânlı gençlik yetişmesine \nçalışmakdır. Hac sûresinin otuzdokuzuncu âyetinde meâlen, (Mü’minlere saldıran \nzâlimlerle cihâd etmeğe izn verildi) buyruldu. Mekkede kâfirler, müslimânlara, \nzulm edip, öldürünce, bunlarla döğüşmek için, tekrâr tekrâr izn istediler. İzn veril-\nmedi. Medîneye hicret edince, bu âyet gelerek, yeni kurulan islâm devletinin, Mek-\nkedeki zâlimler ile cihâd etmesine izn verildi. Bu âyet, müslimânların kâfir, zâlim \nhükûmete isyân etmesi için değil, islâm devletinin, insanların islâm dînini işitmele-\nrine, müslimân olmalarına mâni’ olan, zâlim diktatörlerin orduları ile cihâd etme-\nsine izn vermekdedir. Seyyid Kutbun bu câhilce, ahmakca yazıları, Mısrda fitne \nçıkarmasına, onbinlerce müslimânın zindânlarda çürümelerine, çoklarının ölmesi-\nne sebeb oldu. Bu fâci’a ve fitnelerin cezâsını kıyâmetde çekecekdir. Câhilce dav-\nranışları ve gâfilce yazıları ile devlete karşı ihtilâle sebeb olduğu için, kendisi de \n1386 [m. 1966] da i’dâm edildi. İlmi, aklı ve ihlâsı olmıyan din adamları târîh \nboyunca, hep böyle felâketlere sebeb olmuşlardır. İslâm bilgilerini sessizce yayan \nilmli ve akllı din âlimleri, hep başarı sağlamışlardır. Kâdî zâde Ahmed efendi, (Bir-\ngivî vasıyyetnâmesi) şerhinde 200. cü sahîfesinde buyuruyor ki, (El ile, güc kulla-\nnarak emr-i ma’rûf ve nehyi münker yapmak, ya’nî günâh iş\nliyene mâni’ olmak; \ndevlet adamlarının vazîfesidir. Söz ile, yazı ile cihâd etmek, âlimlerin vazîfesidir. \nKalb ile, düâ etmekle mâni’ olmak ise, her mü’minin vazîfesidir. Te’sîrli, başarılı \nolacağı zan olunursa, bu vazîfeleri yapmak vâcib olur. Fitneye sebeb olacağı zan \nolunursa, terk etmek vâcib olur. Fitne bulunan mahalle zarûretsiz varmak câiz \ndeğildir. Eğer dînini korumak için hicret ederse, güzel olur. Cennete girmeğe lâyık \nolur. Şefâ’ate mazhar olur. Emr-i ma’rûf ve nehy-i münker yaparken niyyetin hâlis \nolması ve işi anlayıp, Allahü teâlânın buradaki emrini iyi bilmesi ve sabrlı olup \nmünâkaşa ve kavga etmemesi, yumuşak ve tatlı dil ve yazı ile yapması lâzımdır.) \nGörülüyor ki, zor kullanarak cihâdı devlet yapar. Cihâd, Seyyid Kutbun anladığı \ngibi değildir. Eğer cihâd ile emr-i ma’rûfu iyi anlamış olsaydı, kendi başını yimez ve \nkırkbinden fazla müslimânı felâkete sürüklemezdi. İstanbuldaki yüksek islâm ens-\ntitüsü eski müdîrlerinden ve öğretim üyelerinden Ahmed Dâvüdoğlu, 1394 [m. \n1974] de İstanbulda basılan (Dîni ta’mîr da’vâsında din tahrîbcileri) kitâbında, (Sey-\nyid Kutb bir edîbdir. Biraz dînî kültürü vardır. Mehmed Âkife benzemekdedir. \nSözü dinde sened olamaz. Çünki, din âlimi değildir) demekdedir. Seyyid Kutb, \nZümer sûresinin üçüncü âyetinin tefsîrinde, (Tevhîd ve ihlâs sâhibi, Allahdan başka \nkimseden birşey istemez. Hiçbir mahlûka i’timâd etmez. İnsanlar, islâmiyyetin bil-\ndirdiği tevhîdden ayrıldı. Bugün bütün islâm memleketlerinde Evliyâya ibâdet edi-\nliyor. Câhiliyye zemânındaki arabların meleklere, heykellere tapınmaları gibi, \nonlardanşefâ’at istiyorlar. Tevhîd ve ihlâs sâhibleri, Allah ile kul arasına vâsıta koy-\nmaz. Kimsedenşefâ’at istemez) diyor. Bu sözleri ve Ehl-i sünnet âlimlerinin bunla-\nra verdikleri cevâblar (Fâideli Bilgiler)  kitâbımızın ve arabî olarak (Fitne-tül-veh-\nhâbiyye) kitâbımızın sonunda da yazılıdır. Bu sözleri ile de, vehhâbî, mezhebsiz \nolduğunu i’lân etmekdedir.", "gectigiMaddeler": ["1/78", "2/1", "2/4", "2/17", "3/15", "3/23", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyid Nûr", "slug": "seyyid-nur", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Bedâyûnî, Beril-\nlîşehrine yakın Bedâyûn kasabasındandır. Zâhir ve bâtın ilmlerinde mütehassıs \nidi. Seyf-üd-dîn-i Fârûkînin talebesi ve Mazher-i Cân- ı Cânânın üstâdıdır. Kerâ-\nmetlerişöhret bulmuşdu. 1135 [m. 1722] senesinde vefât etdi. Türbesi, Delhînin \ncenûbunda, Nizâmeddîn-i Evliyânın garbındadır. Bir teveccühü ile tâliblerin kalb-\n– 1170 –\nleri zikre başlardı. Tecellî-i sıfat hâsıl olurdu. (Sokakda fâsıkla karşılaşmak, kalbde \nzulmet hâsıl eder) buyurur, talebesinin hangi fıskı işliyenle karşılaşdığını haber \nverirdi.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyid Sâlih", "slug": "seyyid-salih", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdülkâdir-i Geylânî haz-\nretlerinin onbirinci torunu ve seyyid Tâhâ-i Hakkârînin kardeşidir. 1281 [m. 1865] \nde Nehrîde vefât etdi. Halîfelerindenşeyh Ezrâ’ î, Giride ve oradan Brezilyaya hic-\nret edip, orada islâmiyyeti neşr etdi. Şeyh Ezrâ’înin kerîmesi, seyyid Fehîm Arvâ-\nsînin zevcesi ve seyyid Reşîdin annesidir. Bir halîfesi de, seyyid Fehîm-i Arvâsî \nolup, seyyid Abdülhakîm-i Arvâsînin mürşididir.", "gectigiMaddeler": ["3/37", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyidşerîf-i Cürcânî", "slug": "seyyidserif-i-curcani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alî bin \nMuhammed Cürcânî, 740 [m. 1339] da Cürcânda tevellüd, 816 [m. 1413] da Şîrâzda \nvefât etdi. Hanefî âlimlerindendir. Alâeddîn-i Attâr hazretlerinin sohbetinde \nbulundu. Çok kitâb yazdı.", "gectigiMaddeler": ["1/24", "2/4", "2/21", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyidet Nefîse", "slug": "seyyidet-nefise", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Hazret-i Hasenin oğlu \nZeydin oğlu Hasenin kızıdır. [145] de Mekkede tevellüd, Medînede ikâmet, Mısra hic-\nret edip, 208 [m. 823] senesinde Mısrda vefât etdi. İshak bin Ca’fer Sâdıkın zevcesi idi. \nVelî idi. Çok kerâmeti görüldü. Buna nezr olunarak yapılan düâ kabul olunmakdadır. \n(Tabakât-ül-kübrâ)ya, 1290 senesinde Mısrda basılmış olan (Nûr-ul-ebsâr) kitâbının \n188. ci ve kenârındaki (İs’âf) kitâbının 212. ci sahîfelerine bakınız!", "gectigiMaddeler": ["2/18"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Seyyidet Sükeyne", "slug": "seyyidet-sukeyne", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Hazret-i Hüsey-\nnin kızı idi. Aklı, zekâsı, ilmi veşi’rleri ve edebi ve hüsn-i cemâli ile meşhûrdur. \n117 [m. 735] de Mısrda vefât etdi.", "gectigiMaddeler": ["2/30"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sıbgatullâh-i Hîzânî", "slug": "sibgatullah-i-hizani", "unvan": "", "kategori": "diger", "biyografi": "Seyyid Tâhâ-i Hakkârînin halîfelerinden-\ndir. (Eshâb-ı Kirâm) kitâbına bakınız!", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sicstânî", "slug": "sicstani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hâfız Ebû Dâvüd Süleymân bin \nEş’âs, hadîs âlimlerindendir. Hanbelî mezhebindendir. 202 [m. 817] de tevellüd, \n275 [m. 888] de Basrada vefât etdi. (Sünen) ve (Delâil-ün-nübüvve) kitâbları meş-\nhûrdur.", "gectigiMaddeler": ["1/58", "1/83", "1/90", "2/6", "2/17", "2/45"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sırrı Pâşa", "slug": "sirri-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Muhammed \nSâlih, Osmânlı vâlî ve ilm adamlarındandır. [1260] da Giridde tevellüd, 1312 [m. \n1895] de vefât etdi. Sultân Mahmûd türbesi kabristânındadır. (Şerh-i akâid) terce-\nmesi ve (Sırr-ül-Furkân) tefsîri basılmışdır.", "gectigiMaddeler": ["1/91"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sırrî-Yi Sekâtî", "slug": "sirri-yi-sekati", "unvan": "", "kategori": "diger", "biyografi": "Ebül-Hasen denir. Sôfiyye-i aliyyedendir. Ma’rûf-i \nKerhîden ve Fudayl bin Iyâddan feyz aldı. Cüneyd-i Bağdâdînin dayısı ve mürşidi-\ndir. 251 [m. 865] de Bağdâdda vefât etdi.", "gectigiMaddeler": ["1/78", "3/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sîret Nefîse", "slug": "siret-nefise", "unvan": "", "kategori": "diger", "biyografi": "Hüseyn Hilmi Işıkın zevcesidir. Annesi Sü’adâ hânım, \nbabası Yûsüf Ziyâ Akışıkdır.", "gectigiMaddeler": ["3/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sokrat", "slug": "sokrat", "unvan": "", "kategori": "diger", "biyografi": "Eski yunan hakîmlerindendir. Mîlâddan [470] yıl önce Atina-\nda tevellüd etmiş, yetmiş yaşında habs olunarak, zehr içirilerek öldürülmüşdür. Bir \nyaratanın bulunduğuna inanmış ise de, madde ve rûha kadîm demiş, küfrden sıy-\nrılamamışdır. Hiç kitâb yazmadı. Eflâtun, Ksenefon ve Oklidis, Sokratın talebele-\nridir. Kendisi de, Fisagorsun talebesidir. Din bilgilerini, eski Peygamberlerin \nkitâblarından ve kendi zemânına kadar ağızdan ağıza gelen sözlerden öğrenmişdir.", "gectigiMaddeler": ["1/95", "2/67"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sokullu Muhammed Pâşa", "slug": "sokullu-muhammed-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kânûnî \nsultân Süleymân hân ve ikinci Selîm hân ve üçüncü Murâd hân zemânlarında onbeş \nsene kadar Sadr- ı a’zamlık yapmışdır. Bosnanın Sokol kasabasındandır. [969] da \ndâmâd-ışehriyârî olmuşdur. [972] de Sadr- ı a’zam olmuş, [985] de Azâbkapı \ncâmi’ini yapdırmış, 987 [m. 1579] de dîvân kurmuş iken, bir meczûb tarafındanşehîd edilmişdir. Eyyûbde Şeyh-ul-islâm Ebüssü’ûd efendinin kabri yanındaki tür-\n– 1171 –\nbesindedir. Türbesi yanındaki (Yazılı medrese)yi de kendisi yapdırmışdır. Zevcesi \nİsmi-hân sultân, ikinci Selîm hânın kızıdır. Sultân Ahmed câmi’i ile Kumkapı ara-\nsındaki Muhammed pâşa câmi’ini, Sokullu, zevcesi İsmi-hân sultân için yapdırmış-\ndır. Orta kapısı, mihrâbı ve minber kapısı üstlerinde birer (Hacer-i esved) taşı par-\nçaları vardır. Câmi’ [979] da yapılmışdır. Sultânın kabri, Ayasofyada babasının tür-\nbesindedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Stalin", "slug": "stalin", "unvan": "", "kategori": "diger", "biyografi": "Josef Cugaşvilî, 1295 [m. 1879] de Rusyada tevellüd, 1372 [m. \n1953] de Moskovada vefât etdi. Teflisde yetişmişdir. [m. 1920] de komünist partisi-\nnin genel sekreteri oldu. [m. 1924] de, Lenin ölünce, Rusyanın idâresini eline aldı. \nÖlünciye kadar Rus milletini ve hele Rusyadaki müslimânları işkence altında inlet-\ndi. Yirmisekiz sene içinde ellibeşmilyon vatandaşın cânına kıydı. Milleti kendine \ntapındırdı. Ölümünden sonra, heykelleri yıkıldı. Resimleri her yerden kaldırıldı. \nStalingrad dediği büyükşehrin adı Volga-grad yapıldı. Rus târîhlerine kötü adam \ndiye yazıldı. Cugaşvilî, gürcü lisânında, yehûdî oğlu demekdir.", "gectigiMaddeler": ["2/26"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sü'adâ Akışık", "slug": "suada-akisik", "unvan": "", "kategori": "diger", "biyografi": "Hüseyn Hilmi Işıkın kayın vâlidesi olup, 1958 de \nvefât etmişdir. Edirnekapı kabristânında, zevci Yûsüf Ziyâ Akışıkın yanında med-\nfûn iken, 2000 senesinde, Eyyûbde Kaşgârî dergâhı yanındaki kabrlerine nakl edil-\nmişlerdir.", "gectigiMaddeler": ["3/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sübkî", "slug": "subki", "unvan": "", "kategori": "diger", "biyografi": "İkiyüzkırküçüncü [243] sırada, Ebû Hasen ismine bakınız!", "gectigiMaddeler": ["1/54", "1/84"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süfyân bin Uyeyne", "slug": "sufyan-bin-uyeyne", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Muhammed, \nmüctehid idi. Mezhebi zemânla unutuldu. [107] de Kûfede tevellüd, 198 [m. 813] \nsenesinde Mekke-i mükerremede vefât etdi.", "gectigiMaddeler": ["1/41", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süfyân-ı Sevrî", "slug": "sufyan-i-sevri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah bin Sa’îd, \nbüyük islâm âlimlerindendir. Müctehid idi. Mezhebi zemânla unutuldu. 95 [m. \n713] senesinde Kûfede tevellüd, 161 [m. 778] de Basrada vefât etdi. Cüneyd-i Bağ-\ndâdî bunun mezhebinde idi.", "gectigiMaddeler": ["1/27", "2/34", "2/40", "2/44", "3/28"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süheyb-i Rûmî", "slug": "suheyb-i-rumi", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ebû Yahyâ Süheyb bin Sinân, ilk \nislâma gelenlerdendir. Rumların elinde köle idi. Bütün gazâlarda bulundu. Hadîs-işerîfle medh olundu. Otuzsekiz 38 [m. 659] senesinde, yetmiş yaşında, Medîne-i \nmünevverede vefât etdi. İyi rumca bilirdi.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sülemî", "slug": "sulemi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdürrahmân Muhammed \nbin Hüseyn, Nîşâpûrludur. [330] da tevellüd, 412 [m. 1021] de vefât etdi. Tefsîr, \nhadîs ve tesavvuf âlimidir. (Tabakât-i sôfiyye) si ve (Hakâyık) tefsîri meşhûrdur. \nHâl tercemesi (Nefehât)da yazılıdır. (Temhîd) kitâbının sâhibi olan Ebû Şekûr \nMuhammed Ebû Bekr Sülemî başkadır.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süleymân", "slug": "suleyman", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Dâvüd aleyhisselâmın oğludur. Hem Pey-\ngamber, hem sultân idi. Kudüsde, Mescid-i aksâyı yedi yılda, çok san’atlı yapdı. \nSerâylar yapdırdı. Akabe körfezinden Fırat kenârına kadar kırk sene adâletle \nhükûmet sürdü. Ticâret gemileri yapdı. Kızıl deniz ve Ummân denizinde ticâret \nyapdırdı. Yemendeki Sebe’ sultânı olan Belkıs ile evlendi. Vezîri (Âsâf) çok akllı \nve hakîm idi.", "gectigiMaddeler": ["1/31", "1/95", "2/20", "2/53", "2/73", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süleymân bin Abdülvehhâb", "slug": "suleyman-bin-abdulvehhab-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Ehl-i sünnet âlimlerinden idi. Kardeşi Mehmedin kitâblarına reddiyyeler yazdı. Bunlardan (Savâik-ul-ilâhiyye firredd-i alel-vehhâbiyye) kitâbında diyor ki, ( İbn-ül-kayyım-ı Cevziyye (Şerh-ul-menâzil) kitâbında, Allahü teâlâ bir kimseyi bir bakımdan sever, başka bir bakımdan sevmez diyor. Böylece bir kimsede îmân ile küfr birlikde bulunur. Peygamberlere inanmazsa, îmânının fâidesi olmaz. Peygamberlere inanmış ise, çeşidlişirkleri onu îmândan çıkarmaz, diyor. Vehhâbîlerin her biri, bir müslimânda başka başka küfr bulunduğunu söylüyor. Her birine göre, bir müslimâna başka çeşid kâfir diyenlerin kendilerinin de kâfir olmaları lâzım ge – 1172 – lir. Vehhâbîler, kendilerinin Hanbelî mezhebinde olduklarını söylüyorlar. Hanbelî mezhebinin çok kıymetli (İknâ’) kitâbında, Peygamberle", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süleymân bin Cezâ'", "slug": "suleyman-bin-ceza", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Birçok kitâbdan \nve en çok hüccet-ül-islâm imâm-ı Gazâlînin kitâblarından toplıyarak hâzırladığı (Ey \noğul) ilm-i hâl kitâbını 960 [m. 1552] senesinde yazmışdır. Çok kıymetlidir. Hakîkat \nKitâbevi tarafından (İslâm Ahlâkı) kitâbının üçüncü kısmı olarak çeşidli baskıları \nyapılmışdır. Yanlış olarak (Huccet-ül-islâm) adı ile de sık sık basılmakdadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süleymânçelebî", "slug": "suleymancelebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Süleymân bin Ivez \npâşa bin Mahmûd, meşhûr türkce mevlidin yazarıdır. Mevlidin asl adı (Vesîle-tün-\nnecât)dır. Süleymân Çelebî 800 [m. 1398] senesinde Bursada vefât etdi. Çekirge-\ndedir. Dedesi Mahmûd beğ, 738 [m. 1338] senesinde, Süleymân pâşa ile, Rumeliye \nsal ile geçenlerdendir. Mevlid cem’iyyeti, ilk olarak 604 [m. 1207] de yapıldı.", "gectigiMaddeler": ["1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süleymân Hân I", "slug": "suleyman-han-i", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kânûnî sultân Süley-\nmân, islâm halîfelerinin yetmişbeşincisi ve Osmânlı pâdişâhlarının onuncusudur. \nYavuz sultân Selîm hânın oğlu, ikinci Selîm hânın babasıdır. Dokuzyüz 900 [m. \n1494] senesinde tevellüd, 974 [m. 1566] de vefât etdi. Süleymâniyye câmi’i yanında-\nki türbededir. İkinci Süleymân ve ikinci Ahmed hân da bu türbededirler. 926 [m. \n1520] de halîfe oldu. Onüç kerre cihâd yapdı. Hepsinde zafer kazandı. Yapdığı \ndonanma, Avrupada birinci idi. Atlas okyânusundan Ummân denizine kadar ve \nMacaristân, Kırım ve Kazandan Habeşistâna kadar geniş yerleri, Allahü teâlânın \ndîni ile, adâlet ile idâre etdi. Almanya İmperatoru ve İspanya kralı olan Şarlkent \nya’nî beşinci Şarl 932 [m. 1526] senesinde Fransaya saldırdığı zemân, Fransızlar \nOsmânlı devletinden yardım istedi. Sultân Süleymân, Barbaros Hayreddîn pâşayı \nbüyük bir donanma ile imdâda gönderdi. Şarlkent, Fransa ile sulh yapmağa mecbûr \noldu. Karada da, sultân Süleymânın idâre etdiği Osmânlı ordusuna mağlûb oldu. \nSultân Süleymân hân pekçok hayr ve hasenât yapdı. Sultân Selîm, Şâhzâdebaşı, \nCihângir ve Süleymâniyye câmi’lerini ve Anadolu ve Rumelinin her yerinde, Rodos \nve başka adalarda müzeyyen câmi’ler, medrese, hastahâneler, aşhâneler, yollar, \nköprüler yapdı. Kızları, dâmâdları, kumandanları da sayılamıyacak kadar çok hayrlı \neserler bırakdı. 969 [m. 1561] da İstanbulda kahve içilmesine başlandı. Kur’ân-ı kerî-\nmi sekiz kerre yazdı. 932 [m. 1526] de Fransa hükûmeti, sultân Süleymâna sığındı. \n945 [m. 1539] de Osmânlı donanması, Avrupalıların birleşik deniz kuvvetlerini boz-\nguna uğratdı. 963 [m. 1555] de Süleymâniyye câmi’i ve külliyesi yapıldı. 967 [m. \n1559] de Avrupalıların donanmaları ikinci bozguna uğradı. Eyyûbde (Baba Haydar) \ncâmi’ini yapdırdı. Baba Haydar, Ubeydüllah- ı Ahrâr halîfelerinden olup, 957 [m. \n1549] de vefât etdi. Edirne-kapı mezârlığında, Münzevîye giden yol üzerinde (Emîr \nBuhârî Tekkesi) mescidini yapdırdı. Bu tekkenin ilkşeyhi Mahmûd Çelebî efendi, \ncâmi’in karşısında medfûndur. Seyyid Ahmed-i Buhârînin dâmâdıdır. Kayınpederi \nvefât edince, yerine geçerek Maltadaki Emîr Buhârî tekkesine nakl etdi. 1391 [m. \n1971] de Buğaz köprüsü çevre yolu yapılırken, tekke ve kabrler yıkılıp kaldırıldı. \nSüleymâniyye câmi’ini ve Edirnedeki Selîmiye câmi’ini mi’mâr Sinân yapdı. \n(Kâmûs-ul a’lâm)da diyor ki, (Sultân Süleymânın torunu ve sultân ikinci Selîm \nhânın kızı Şâh sultân ile dâmâdı Zâl Mahmûd pâşa, Eyyûbde Defterdâr caddesin-\nde büyük bir câmi’ yapmışlardır. İkisi de 988 [m. 1580] senesinde vefât etdiler.) \nCâmi’ yanındaki türbededirler. Sultân üçüncü Selîm hânın büyük hemşîresi Şâh \nsultân bu câmi’in yanına bir mekteb ve kendi için bir türbe yapdırdı. Türbede zevci \nMustafâ pâşa ile vâlidesi sultân da vardır. Sultân Mahmûd hân ve son olarak 1380 \n[m. 1960] de, başvekîl Adnân Menderes, câmi’i ve türbeyi ta’mîr etdiler. \n– 1173 –\nOğlu sultân Cihângirin rûhu için, 967 [m. 1559] de Cihângir câmi’ini yapdı. Ci -\nhângir 960 [m. 1552] da Halebde vefât etmiş, Şâhzâde câmi’i yanında ağabeğsi \nMuhammed sultânın türbesine defn edilmişdir. Cihângir câmi’i üç def’a yandı. Son \nolarak, ikinci Mahmûd hânın sadr-ı a’zamı silâhdar Alî pâşa 1239 [m. 1823] da yap-\ndırmışdır. 978 [m. 1570] de, İskender pâşa, Kanlıca câmi’ini yapdırdı. Aynı senede \nKıbrısda Magosa kal’asını feth etdikden iki gün sonra orada vefât etdi. Câmi’i \nönündeki türbede hangi İskender pâşa olduğu kesinlikle belli değildir. Câmi’in sağ \ntarafında Yenişehrli Abdüllah efendi medfûndur.", "gectigiMaddeler": ["1/78", "2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sünbül Sinân", "slug": "sunbul-sinan", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şeyh Sinân-üd-dîn-i Yûsüf \nefendi, Merzifonludur. Halvetî tarîkatinin Sünbülî kolunun reîsidir. Çelebî halîfe \nMuhammed Cemâleddîn efendinin halîfesi ve Merkez efendinin mürşididir. 936 \n[m. 1529] da vefât etdi. Koca Mustafâ pâşadaki tekkesindedir. Çelebî halîfe, sultân \nBâyezîd-i Velî vezîrlerinden Koca Mustafâ pâşanın da mürşididir. Pâş\na bir câmi’ \nve tekke yapdı. Fâtih sultân Muhammedin oğlu Cem sultânı Napolide, Koca Mus-\ntafâ pâşa veyâ papa zehrledi. Pâşa 918 [m. 1511] de Bursada katl edildi. \nSünbül Sinân efendi, önce Efdâlzâdeden ilm tahsîl eyledi. Sonra Mısra gitdi. \nMürşidi hacca giderken, kendisini Koca-Mustafâ pâşadaki tekkesine halîfe bırakdı. \nMürşidinin kızı Safiyye hânımı aldı. 936 [m. 1529] da vefât edince, yerine Şâh sultân \ntekkesindeki Merkez efendi geldi. Simâ’ ve raksın ve cenâze taşırken, cehren ilâhî, \nzikr okumanın efdal olduğunu bildiren (Tahkîkiyye) risâlesi vardır. Büyük âlim, \nbüyük velî Ya’kûb-i Çerhî ve Sa’îdeddîn-i Fergânî “rahmetullahi aleyhimâ”nın \n(Ünsiyye) ve (Menâhic-ül ’ibâd) kitâblarında, simâ’ hakkında geniş bilgi verilmek-\ndedir. Üçüncü kısm, 27. ci maddeye ve (Mektûbât Tercemesi)nde 286.cı mektûba \nbakınız! Efdâlzâde Hamîdüddîn efendi, yedincişeyh-ul-islâm olup, 908 [m. 1501] \nde vefât etdi. Eyyûbdedir. Fâtih Maltasında medresesi vardır.", "gectigiMaddeler": ["3/27"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sünbülzâde", "slug": "sunbulzade", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzaltmışbeşinci [665] \nsırada Muhammed Mer’aşî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Sü'ûd", "slug": "suud", "unvan": "", "kategori": "diger", "biyografi": "Sü’ûd bin Abdül’azîz, iki kimsedir. Birincisi Sü’ûdî Arabistânın \nüçüncü meliki olup, 1217 [m. 1802] de idâreyi ele aldı. Çok müslimân kanı dökdü. \n[1231] de öldü. İkincisi, yirminci melikidir. 1372 [m. 1953] de hükûmet reîsi oldu. \nEhl-i sünnete işkence yapdı. Zevk ve safâya daldı. 1384 [m. 1964] de tahtdan indi-\nrildi. Yunanistâna gidip, Atinada içkili, kadınlı kötü hayât geçirdi. 1388 [m. 1968] \nde orada öldü. Yerine kardeşi, ellisekiz yaşındaki Faysal getirildi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süveydî", "slug": "suveydi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah bin Hüseyn Bağdâdî, \nŞâfi’î fıkh âlimidir. 1104 [m. 1692] de tevellüd, 1174 [m. 1760] de vefât etdi. Nâdirşâh tarafından hâzırlanan meclisde, yetmiş şî’î âlimi ile münâzara edip, aldandık-\nlarını hepsine tasdîk etdirdi. O meclisdeki konuşmaları (Hucec-i kat’ıyye) kitâbın-\nda yazmışdır. Arabca olup, 1323 [m. 1905] ve 1981 senelerinde Mısrda ve İstanbul-\nda basdırılmışdır. Yine kendisi tarafından Türkceye terceme edilip, [1326] da \nMısrda ve (Hak Sözün Vesîkaları) ismi ile İstanbulda (Hakîkat Kitâbevi)  tarafın-\ndan basdırılmışdır. Nâdîrşâh, 1148 de Îrânşâhı oldu. 1160 da vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süveydî", "slug": "suveydi-2", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah bin Hüseyn Bağdâdî, \nŞâfi’î fıkh âlimidir. 1104 [m. 1692] de tevellüd, 1174 [m. 1760] de vefât etdi. Nâdirşâh tarafından hâzırlanan meclisde, yetmiş şî’î âlimi ile münâzara edip, aldandık-\nlarını hepsine tasdîk etdirdi. O meclisdeki konuşmaları (Hucec-i kat’ıyye) kitâbın-\nda yazmışdır. Arabca olup, 1323 [m. 1905] ve 1981 senelerinde Mısrda ve İstanbul-\nda basdırılmışdır. Yine kendisi tarafından Türkceye terceme edilip, [1326] da \nMısrda ve (Hak Sözün Vesîkaları) ismi ile İstanbulda (Hakîkat Kitâbevi)  tarafın-\ndan basdırılmışdır. Nâdîrşâh, 1148 de Îrânşâhı oldu. 1160 da vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süveydî", "slug": "suveydi-3", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdüllah bin Hüseyn Bağdâdî, \nŞâfi’î fıkh âlimidir. 1104 [m. 1692] de tevellüd, 1174 [m. 1760] de vefât etdi. Nâdirşâh tarafından hâzırlanan meclisde, yetmiş şî’î âlimi ile münâzara edip, aldandık-\nlarını hepsine tasdîk etdirdi. O meclisdeki konuşmaları (Hucec-i kat’ıyye) kitâbın-\nda yazmışdır. Arabca olup, 1323 [m. 1905] ve 1981 senelerinde Mısrda ve İstanbul-\nda basdırılmışdır. Yine kendisi tarafından Türkceye terceme edilip, [1326] da \nMısrda ve (Hak Sözün Vesîkaları) ismi ile İstanbulda (Hakîkat Kitâbevi)  tarafın-\ndan basdırılmışdır. Nâdîrşâh, 1148 de Îrânşâhı oldu. 1160 da vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Süyûtî", "slug": "suyuti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Celâleddîn Abdürrahmân bin \nMuhammed, şâfi’î âlimlerinin büyüklerindendir. Hadîs imâmı, müctehid idi. 849 \n– 1174 –\n[m. 1445] da Mısrda tevellüd, 911 [m. 1505] de orada vefât etdi. Her biri çok kıy-\nmetli olan, beşyüzden fazla kitâb yazdı. Çoğu Mısrda ve Avrupada ve İstanbulda \nbasıldı. Dahâ yirmiiki yaşında iken, Celâleddîn Muhammed bin Ahmed Mehallî-\nnin İsrâ sûresine kadar yapdığı ve [864] de vefât edince, yarıda bırakdığı tefsîri \ntemâmladı. Bunun için (Celâleyn tefsîri) denildi. Ahmed Sâvînin bu tefsîre hâşiye-\nsi meşhûrdur. Almanca (Meyer Lexikon) adındaki kitâbda, (Yorulmadan, yılma-\ndan yazan Süyûtînin üçyüzden fazla eseri vardır) diyor. Yetîm olarak büyüdü. Sekiz \nyaşında hâfız oldu. Tefsîr, hadîs, fıkh, nahv, me’ânî, beyân, bedî’ ve lügat ilmlerinde \nmütehassıs oldu. Şâma, Hicâza, Yemene, Hindistâna, Fasa gitdi.", "gectigiMaddeler": ["1/25", "1/31", "1/50", "1/97", "2/5", "2/16", "2/17", "2/22", "2/47", "2/53", "3/21", "3/58", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şa'bân-ı Velî", "slug": "saban-i-veli", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kastamonilidir. Hayred-\ndîn-i Tokâdî 941 [m. 1535] de vefât edince, halîfesi olmuşdur. Hayreddîn efendi \nde, Çelebî halîfe Muhammed Cemâleddîn efendinin halîfesidir. Çelebî halîfe, 899 \n[m. 1493] de, hacca giderken Şâmda vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şa'bî", "slug": "sabi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Amr Âmir, Tâbi’înin büyüklerin-\ndendir. Kûfenin en büyük âlimi idi. İmâm-ı a’zamın hocalarındandır. Yirminci [20] \nsenede Basrada tevellüd, 104 [m. 723] senesinde Kûfede vefât etdi. (El-Kifâye) \nkitâbı meşhûrdur.", "gectigiMaddeler": ["2/67"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şâfi'î", "slug": "safii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Ebû Abdüllah Muhammed \nbin İdrîsin dedesinin dedesi Şâfi’, Kureyş kabîlesinden ve Eshâb-ı kirâmdan oldu-\nğu için, Şâfi’î adı ile meşhûr olmuşdur. Şâfi’in dedesinin dedesi de Hâşim bin \nAbd-i Menâfdır. Büyük müctehid ve mezheb reîsidir. 150 [m. 767] senesinde Gaz-\nzede tevellüd, 204 [m. 820] de Mısrda vefât etdi. Kurâfe kabristânındadır. İki \nyaşında Medîneye götürüldü. İmâm-ı Mâlikden okudu. Yedi yaşında hâfız oldu. \nHadîs, fıkh, lügat ve edebiyyâtda çok yükseldi. Vera’, takvâ ve salâhda eşi yok idi. \nİmâm-ı Ahmedin hocasıdır. [195] de Bağdâda, [197] de Mekkeye, [199] da Mısra \ngeldi. Üsûl-i fıkh ilmini ilk yazandır. Hadîsde (Sünen) ve (Müsned)i, fıkhda \n(Kitâb-ül-ümm)ü çok kıymetlidir.", "gectigiMaddeler": ["1/26", "1/27", "1/31", "1/50", "1/54", "1/65", "1/70", "1/76", "1/84", "1/85", "2/4", "2/5", "2/16", "2/17", "2/21", "2/24", "2/25", "2/34", "2/36", "2/37", "2/38", "2/41", "2/53", "2/72", "3/22", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şâhismâ'îl", "slug": "sahismail", "unvan": "", "kategori": "diger", "biyografi": "Şeyh Safiyyeddînin torunlarından olduğu için, Safevî de -\nnir. Îrânda, Tebrîzde 908 [m. 1502] de Safevîşî’î hükûmetini kurdu. İmâm-ı Mûsâ \nKâzım “rahmetullahi aleyh” soyundan olduğunu söylerdi. Fekat, Hüseyn Şirvânî-\nnin, (Ahkâm-üd-dîniyye) kitâbında, bu sözü tekzîb ve red etdiği (Kâmûs-ül-\na’lâm)da yazılıdır. Hatay denilen türk kabîlesindendir. Babasışeyh Haydar, Îrânın \nErdebîlşehrinde yerleşen Hatay kabîlesindenşeyh Cüneydin oğlu olup, kızıl başlık \ngiyerdi. 1355 [m. 1937] yılında Îrânın edebiyyât târîhini yazan ingiliz Eduard Braun \n(Yavûz sultân Selîm mektûblarında, kendisini efsânevî Îrânşâhlarına, şâh İsmâ’îli \nise, türk Efrâsyâba benzetiyordu. Şâh İsmâ’îlin ordusu, Mûsullu, Şâmlı, Rumlu gibi \ntürk kabîlelerinden askerlerle dolu idi. Türkçe konuşuyorlardı) diyor. [Efrâsyâb, \neski Tûrân hükümdârı idi. Îrânşâhlarından Ferîdûnün oğlunun torunu idi. Îrânı \naldı. Çıkarıldı. Tekrâr aldı. Zâl oğlu Rüstemin kahramânlıkları ile yine çıkarıldı. \nNihâyet Keyhusrev tarafından öldürüldü. (Şâhnâme)de uzun yazılıdır.] Şâh \nİsmâ’îlin türkceşi’rleri, el yazma dîvânı, Erdebîlde türbesindedir. [892] de tevellüd \netdi. Babasından kalan Hataylı tekkesindeşeyh oldu. [905] de, mürîdleri ile Şirvâna \nsaldırdı. Şî’îliği i’lân edince, Ehl-i sünneti öldürdü. Bunu haber alan Yavuz Selîm \nhân, 920 [m. 1514] senesinde, Çaldırandaşâhı ve askerlerini perîşan etdi. Kaçdılar. \n930 [m. 1524] da Erdebîlin Serab kasabasında öldü. İntikâmcı, sefîh, alçak bir zındık \nidi. (Mir’ât-i kâinât) da diyor ki, Yıldırım Bâyezîd zemânındaki Evliyâdan Abdür-\nrahmân-ı Erzincânî, Safiyyeddîn-i Erdebîlî hazretlerinin halîfelerinden idi. Amasya-\nda, bir sabâh çok üzgün olup, sebebi soruldukda, (Erdebîlî oğullarının i’tikâd ve tak-\n– 1175 –\nvâları güzel idi. Şimdişeytân onları doğru yoldan sapdırdı) buyurdu. Sonra, şeyh \nHaydarınşî’î olduğu haberi geldi.", "gectigiMaddeler": ["1/31", "2/22", "2/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şâh Sultân", "slug": "sah-sultan", "unvan": "rahmetullahi teâlâ aleyhinne", "kategori": "alim", "biyografi": "Osmânlı pâdişâhların-\ndan, birinci Selîm hânın ve birinci Süleymân hânın ve üçüncü Mustafâ hânın kızla-\nrıdır. Selîm hân ve Süleymân hân ismlerine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şâh Veliyyullah-ı Dehlevî", "slug": "sah-veliyyullah-i-dehlevi-rahmetullahi-teala-aley", "unvan": "", "kategori": "alim", "biyografi": "Ahmed bin Abdürrahîm, 1114 [m. 1702] de Delhîde tevellüd, 1176 [m. 1762] da Delhîde vefât etdi. Babası, hazret-i Ömer, vâlidesi hazret-i Alî soyundandır. Mevdûdînin yazdığı gibi, mezhebsiz değildir. Ehl-i sünnet âlimi idi. (Fâideli Bilgiler) kitâbına bakınız! Büyük Velî, Mazher-i Cân- ı Cânân buyurdu ki, ( Şâh Velîyyullah derin hadîs âlimidir. Ma’rifet esrârının tahkîkinde ve ilmin inceliklerini bildirmekde, yeni bir çığır açmışdır. Bütün bu bilgileri ve üstünlükleri ile birlikde, doğru yolun âlimlerindendir.) Çok kitâb yazdı. Eserleri Pâkistânda yeniden basılmakdadır. Şî’îlere karşı (Kurretül ayneyn fî tafdîl-işeyhayn) ve (İzâle-tül hafâ an hilâfet-il-hulefâ) kitâbları ndan birincisi türkçe kısaltılarak (Müslimânların iki gözbebeği) adı ile (Eshâb-ı kirâm) kitâbının içinde, 1394", "gectigiMaddeler": ["1/58", "1/71", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şâhzâde Sultân Muhammed", "slug": "sahzade-sultan-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kânûnî \nsultân Süleymânın oğludur. 949 [m. 1541] da vefât etdi. Sultân Süleymân, bunun \nadına Şâhzâde câmi’ini yapdı. Câmi’ 955 [m. 1547] de temâm oldu. Câmi’ yanındaki \ntürbesindedir. Bu türbede, sağında birâderi Cihângir sultân, sol yanında da kızı \nHümâşâh sultân yatmakdadır. Şâhzâde Cihângîr Halebde 960 [m. 1552] da vefât edip \nİstanbula getirildi. Babası, bunun için Beyoğlunda Cihângîr câmi’ini yapdırdı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şarl", "slug": "sarl", "unvan": "", "kategori": "diger", "biyografi": "Fransa, Almanya, İngiltere, İsveç, Napoli, Sicilya, Navara ve Sar-\ndenya kralları arasında çok Charle vardır. Fransadaki onbir Şarlşunlardır: \n– 1176 –\nŞarl Martel 69 [m. 689] dan 124 [m. 741] e kadar yaşadı. 113 [m. 732] senesinde \nPuvatiyye yakınında Endülüs müslimânlarına gâlip gelmiş ve papa üçüncü Gregu-\nvar [Grégoire] tarafından tebrîk edilmişdir. \n1. ci Şarl, buna Şarlman, ya’nî büyük Şarl denir. Şarl Martelin torunudur. [m. \n742-814] Endülüs müslimânlarına mağlûb oldu. Almanyanın çoğunu aldı. Hârû-\nnürreşîd buna sâat ve başka hediyyeler göndermişdir. Senelerin, mîlâd gününden \nbaşlanmasını, ilk olarak 192 [m. 808] de, bunun kabûl etdiği, sonra Kostantin \ntarafından kânunlaşdırıldığı Hasîb beğin Kozmoğrafya kitâbında yazılıdır. 761, \n1107. \n2. ci Şarl [m. 823-877] âciz idi. Ömrü, kardeşleri ile harb etmekle geçdi. \n3. cü Şarl [m. 879-929], ömrü iç harblerle geçdi ve harbde öldü. \n4. cü Şarl [m. 1294-1328], güzel Filipin oğludur. İngiliz kralı ikinci Edvard \nbunun eniştesi idi. Edvarda hiyânet edip, öldürülmesine sebeb oldu. \n5. ci Şarl [m. 1368-1380], Fransayı İngiliz işgâlinden kurtardı. 1173. \n6. ci Şarl [m. 1368-1422] zemânında, İngiltere kralı beşinci Hanri Fransayı alıp \nFransa krallığını i’lân etdi. \n7. ci Şarl [m. 1403-1461], Jandark isminde bir kızın yardımı ile Fransayı İngiliz \nişgâlinden kurtardı. \n8. ci Şarl [m. 1470-1498], Napoliyi almış, yine gayb etmişdir. \n9. cu Şarl [m. 1550-1574], on yaşında kral oldu. Annesi Katerina saltanat sürüp, \nkadınlar saltanatı Fransayı karışdırdı. Katoliklerle protestanlar arasında harbler \noldu. Kral, hemşîresini, protestan olan Navara prensi dördüncü Hanriye verdi ise \nde, düğünde [Sent Bartelemi] yortusu gecesi, Fransadaki protestanların öldürül-\nmesini emr etdi. Kendisi de, serây penceresinden silâh atmışdır. Sefâhat içinde \nöldü. 358, 534. \n10. cu Şarl Filip [m. 1757-1836], onbeşinci Louinin torunu ve onaltıncı Loui ile \nonsekizinci Louinin birâderidir. 1203 [m. 1789] ihtilâlinde Fransadan kaçdı. 1795 \nde İngilizlerin yardımı ile Fransaya girmek istedi ise de, 1824 de girebildi. 1830 da \nzâlim idâresine karşı isyân çıkararak yine kaçdı. \nŞarl-kent başka olup, Alman imperatörleri olan yedi Şarlden beşincisidir. \nBütün Avrupayı aldı ise de, 932 [m. 1526] de Osmânlılara mağlub oldu.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şâzilî", "slug": "sazili", "unvan": "", "kategori": "diger", "biyografi": "İkiyüzellisekizinci [258] sırada Ebül-Hasen ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şehâbüddîn Sühreverdî", "slug": "sehabuddin-suhreverdi", "unvan": "", "kategori": "diger", "biyografi": "888. ci sırada (Şihâbüddîn-i Sührever-\ndi) ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şeker-Genc", "slug": "seker-genc", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ferîd-üd-dîn Mes’ûd \nGenc-işeker, Hindistândaki Çeştiyye Evliyâsındandır. 569 [m.1173] da Delhîde \ntevellüd, 664 [m. 1265] de Mültanda vefât etdi. Kutbeddîn-i Bahtiyârın talebesi \nve Nizâm-üd-dîn-i Evliyânın üstâdıdır. Bahtiyâr Üşî, 633 [m. 1234] de Delhîde \nvefât etdi. Ağzına aldığı taş, toprak, çömlek parçalarışeker gibi tatlı olurmuş. \nBunun için, (Şeker hazînesi) demek olan Genc-işeker adı ile meşhûr olmuşdur. \nFârisî (Râhat-ül-kulûb) ve (Fevâid-üs-sâlikîn) kitâbları ve başka eserleri ve kerâ-\nmetleri bilinmekdedir. Hicretin binellialtı [1056] senesinde yazılıp 1331 [m. 1913] \nde Lüknovşehrinde basılmış olan (Siyer-ül-Evliyâ) kitâbında hâl tercemesi fârisî \nolarak uzun yazılıdır. (Mültânşeyhı) adı ile her sene, Muharremin beşinde kabri \nziyâret edilmekdedir.", "gectigiMaddeler": ["2/72"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şemsüddîn Sâmî", "slug": "semsuddin-sami", "unvan": "", "kategori": "diger", "biyografi": "1266 [m. 1850] da Arnavutlukda tevellüd, 1322 [m. \n1904] de İstanbulda vefât etdi. Erenköydedir. Fransızcadan türkceye resmli lügât \nkitâbı ve altı cild (Kâmûs-ül-a’lâm)ı basılmışdır.", "gectigiMaddeler": ["1/97", "2/15", "2/16", "2/24"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şemsüddîn Sehâvî", "slug": "semsuddin-sehavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Ab -\n– 1177 –\ndürrahmân-ı Sehâvî, 830 [m. 1427] da Mısrda Sehâ kasabasında tevellüd, 902 [m. \n1496] de Medîne-i münevverede vefât etdi. Şâfi’î idi. Çok kitâb yazdı.", "gectigiMaddeler": ["2/5", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şemsüddîn Tîmûrtâşî", "slug": "semsuddin-timurtasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şemsüddîn \nMuhammed bin Abdüllah Gazzî, Hanefî fıkh âlimlerindendir. 1004 [m. 1595] de \nGazzede vefât etdi. (Tenvîr-ül-ebsâr) kitâbı ile (Kenz) ve (Vikâye) ve (Minah-ul-\ngaffâr) adını verdiği (Tenvîr-ül-ebsâr) şerhleri meşhûrdur. Gazze, Filistindedir. \nHâşim bin Abd-i Menâf oradadır.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şems-i Tebrîzî", "slug": "sems-i-tebrizi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mevlânâ Muhammed bin \nAlî, ilk mektebe giderken Resûlullahın “sallallahü aleyhi ve sellem” aşkından, \nyimez, içmez olmuşdu. Ebû Bekr-i Kermânîden ve Bâbâ Kemâl-i Cündîden de \nfeyz aldı. Bâbâ Kemâlin yanındaşeyh Fahreddîn-i Irâkî de yetişmekde idi. Şeyh \nFahreddîn, her keşf ve hâlini, şi’rler hâlinde, Bâbâ Kemâle bildirirdi. Bâbâ Kemâl, \nŞemseddîne, (Sana bu esrârdan ve hakîkatlerden birşey hâsıl olmıyor mu? Neden \nhiç söylemiyorsun?) dedi. (Ondan dahâ çok oluyor. Fekat, ben onun gibişi’r söy-\nliyemiyorum) dedi. Bâbâ Kemâl buyurdu ki, (Allahü teâlâ, sana öyle bir arkadaş \nihsân eder ki, o senin adına her ma’rifet ve hakîkatleri söyler) buyurdu. 642 [m. \n1244] de Konyaya geldi. Şekerrîzân hânına yerleşdi. Celâleddîn-i Rûmî talebesi ile \ngeçerken karşılaşdılar. Celâleddîne Resûlullah ile Bâyezîdin derecelerini sordu. \nAldığı cevâblardan bayıldı. Birgün, Mevlânâ havz kenârında idi. Yanında kitâblar \nvardı. Şemseddîn gelip, kitâbları sordu. (Sen bunları anlamazsın) dedi. Şemseddîn \nkitâbları suya atdı. Mevlânâ, âh babamın bulunmaz yazıları gitdi, diyerek çok üzül-\ndü. Şemseddîn elini uzatıp herbirini aldı. Hiçbiriıslanmamış görüldü. Mevlânâ (Bu \nnasıl işdir?) dedi. (Bu zevk ve hâldir. Sen anlamazsın) buyurdu. Bir kâfir, Allah \nnerede, kendisi ve bulunduğu yer bilinmeyenşey yok demekdir. O hâlde Allah \nyokdur dedi. Şeyh hazretleri, elindeki kerpiçi kâfirin başına atdı. Başı çok acıdı. \nSeni mahkemeye vereceğim dedi. Ağrıyı ve başının neresinde olduğunu göster, \nsana hak vereyim buyurdu. Kâfir bunları gösteremeyince, Allahın var olduğuna \ninandım deyip, müslimân oldu. 645 [m. 1247] de, bir gece Mevlânâ ile otururken, \nyedi kişi gelip dışarı çağırdılar veşehîd etdiler. Bunlardan biri, Mevlânânın oğlu \nAlâüddîn Muhammed idi. Kuyuya atdılar. Mevlânânın diğer oğlu Behâüddîn Sul-\ntân veled rü’yâda görüp çıkardı. Mevlânânın medresesinde defn edildi. Sultân \nVeled 712 [m. 1311] de vefât edip, oraya defn edildi.", "gectigiMaddeler": ["3/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şemsi Ahmed Pâşa", "slug": "semsi-ahmed-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "988 [m. 1580] de \nÜsküdârda, Şemsi pâşa câmi’ini yapdırmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şems-Ül-Eimme Hulvânî", "slug": "sems-ul-eimme-hulvani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Abdül’azîz \nbin Ahmed, Hanefî fıkh âlimidir. 456 [m. 1064] da Buhârâda vefât etdi. Muham-\nmed Şeybânînin (Câmi’ul-kebîr) ve (Siyer-ül-kebîr)inişerh etmiş, (Nevâdir), \n(Mebsût), (Vâkı’ât) ve başka kitâblar yazmışdır.", "gectigiMaddeler": ["1/64", "1/65", "1/73", "1/78", "2/16", "3/12"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şems-Ül-Eimme-i Serahsî", "slug": "sems-ul-eimme-i-serahsi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyü-\nzondokuzuncu [819] sırada Serahsî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şerefüddîn Ahmed Münîrî", "slug": "serefuddin-ahmed-muniri", "unvan": "", "kategori": "diger", "biyografi": "Babası Yahyâdır. Fârisî mektûbâtı \nvardır. 782 [m. 1380] de Bihârda vefât etdi. (Ahbâr-ül-Ahyâr) da hâl tercemesi \nyazılıdır. (Herkese Lâzım Olan Îmân) kitâbının 92.ci sahîfesine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şerhabîl", "slug": "serhabil", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullah “sallallahü aleyhi ve sellem” \nile konuşmak için Necrandan gelen altmış süvârî hıristiyanın en âlimi idi. Buna \nSeyyid derlerdi. Sonradan müslimân oldu. Sohbet ileşereflendi.", "gectigiMaddeler": ["1/93"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şernblâlî", "slug": "sernblali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül- İhlâs Hasen bin Ammâr \nŞernblâlî, Hanefî fıkh âlimidir. Şürnblâlî de denir. Câmi’ul-ezherde müderris idi. \n(Câmi’ul-ezher), Mısrda Fâtımîler zemânında [361] de yapılan câmi’ olup, med -\nrese olarak kullanılmakdadır. [994] de tevellüd, 1069 [m. 1658] da Mısrda vefât \netdi. (Nûr-ül-îzâh) ve bununşerhı olan (İmdâd-ül-Fettâh) veyâ (Merâkıl-felâh) \n– 1178 –\nismlerindeki kitâbı ve kelâm ilminde (Merak-ıs-se’âde) kitâbı ve (Dürer) hâşiyesi \nçok kıymetlidir.", "gectigiMaddeler": ["1/43", "1/73", "1/74", "1/78", "1/79", "1/85", "1/98", "2/43", "3/4", "3/6", "3/19", "3/63"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şevberî", "slug": "sevberi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şems-üd-dîn Muhammed bin \nAhmed Şevberî, Şâfi’î fıkh âlimidir. [977] de Şevberde tevellüd, 1069 [m. 1658] da \nvefât etdi. Kıymetli kitâbları vardır. Şevber Mısrdadır.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şevkânî", "slug": "sevkani", "unvan": "", "kategori": "diger", "biyografi": "Kâdî Muhammed bin Alî Şevkânî, 1173 [m. 1759] de San’aşehrinin Şevkân kasabasında tevellüd, 1250 [m. 1834] de San’ada vefât etdi. San’ada \nkâdî idi. Babasından ve başkalarından (Ezhâr-ül-fıdda) ve (Bahr-ül-zehhâr) şî’î \nkitâblarınınşerhlerini senelerce okuyarak, şî’î mezhebinde yetişdirildiği, (Feth-ul-\nkadîr) tefsîri Mısrda basılırken eklenen önsözde yazılıdır. Şî’îlerin Zeydî fırkasından \nolduğu Kuveyt müftîsi Muhammed bin Ahmed Halefin (Cevâb-üs-sâil) kitâbının 69. \ncu sahîfesinde yazılıdır. Zeydî mezhebinde olduğunu saklar, hanefî görünürdü. \nŞî’îler, gitdiklerişehrlerdeki mezhebden olduklarını söylerler. Kendi mezheblerini \nsaklarlar. Şevkânî de hanefî olduğunu söyler, fekat zeydî mezhebine göre fetvâ \nverirdi. Böyleceşî’î mezhebini yaymağa çalışırdı. Şî’îler böyledir. Bu yola (Takıyye) \nyapmak denir. Çok sayıda, istifâdeli kitâbları vardır. Ehl-i sünnete uymıyan yazıları \nzararlıdır. 1976 senesinde Pâkistânda Siyalkütşehrinde urdu dilinde basılmış olan \n(Vehhâbî mezhebinin iç yüzü) kitâbında, İbni Teymiyyenin ve Şevkânînin mezheb-\nsiz oldukları, vesîkalarla isbât edilmekdedir. Hindistânın büyük âlimlerinden \nAbdülhay Lüknevînin, Şevkânî için ( Şevkânînin kötü hâllerini ve bozuk kitâblarını \nöğrenmek istiyen, benim (Ferhat-ül-müderrisîn bi-zikril-müellefât-i vel-müellifîn)  \nkitâbımı okusun! Burada İbni Teymiyyenin (Minhâc-üssünne) kitâbını anlatırken, \nŞevkânînin de İbni Teymiyye gibi olduğunu, onun gibi ilmi çok ve aklı az olduğunu \nve ondan da aşağı olduğunu uzun bildirdim) dediğini yazmakdadır. Abdülhay Lükn-\nevî (Fevâid-ül-behiyye) kitâbının sâhibidir.", "gectigiMaddeler": ["2/5", "2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şevkî", "slug": "sevki", "unvan": "", "kategori": "diger", "biyografi": "Behâîlik dinsizliğini yaymağa uğraşanlardan biridir. Babası \nAbdülbehâ Abbâs 1339 [m. 1921] da Hayfada öleceği zemân büyük oğlu Şevkîyı, \nilâhî emrin reîsi olarak rûhânî reis ve Behâîliğin açıklayıcısı ta’yîn etdi. Şevkî, 1315 \n[m. 1897] de Akkâda doğdu. Oksford üniversitesinde okudu. Amerikalı bir kızla \nevlendi. Her yerde Behâî teşkîlâtının ve ma’bedlerinin kurulmasına çalışdı. 1377 \n[m. 1957] de Londrada öldü.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şeybe", "slug": "seybe", "unvan": "", "kategori": "diger", "biyografi": "Rebî’anın oğlu, Utbenin kardeşi ve Abd-i Şems bin Abd-i Me -\nnâfın torunu idi. Ümeyyenin kardeşi oğlu [yeğeni] idi. Bedr gazâsında hazret-i \nHamza tarafından öldürüldü.", "gectigiMaddeler": ["1/85", "2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şeyh Emân", "slug": "seyh-eman", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sôfiyyedendir. 964. \n— Şeyh Müzzemmil: (Mektûbât Tercemesi)  sahîfe 236 ya bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şeyh-i Necdî", "slug": "seyh-i-necdi", "unvan": "", "kategori": "diger", "biyografi": "Şeytânın ismidir. Muhammedi öldürmek lâzım, bu işi \nŞeyh-i Necdî yapar dedi. (Fâideli Bilgiler) kitâbının 84.cü sahîfesine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şeyh Tâceddîn bin Zekeriyyâ", "slug": "seyh-taceddin-bin-zekeriyya-rahmetullahi-teala", "unvan": "", "kategori": "alim", "biyografi": "Hindistân asîlzâdelerinden idi. Delhî köylerinden birinde Şeyhullah Bahş hazretlerinden icâzeti olduğu hâlde, hâce Muhammed Bâkî-billah “kuddise sirruh” Mâverâ-ün-nehr seferinden dönüp irşâda başlayınca, sohbetine koşdu. Tevâzu’ ve insâfına karşılık teveccühe ve husûsî ve mahrem halvetlere kavuşdu. Kemâle erdi. Tekrâr icâzet aldı. Hazret-i Hâce vefât edince, şeyh Tâc, şaşkına döndü. Seyâhate çıkdı. Hacca gitdi. Hicâzda çok kimselere nasîhat etdi. Mekke âlimlerinden Ahmed ibni Allân, (Reşehât) kitâbını arabîye terceme etmişdi. Şeyh Tâcın sohbeti ileşereflendi. Kemâle erdi. 1031 [m. 1621] senesinde vefât etdi. Şeyh Tâceddîn, arabî olarak çeşidli kitâb yazdı. Tesavvuf büyüklerinin fârisî kitâblarını arabîye çevirdi. Bu büyüklere dil uzatan din adamlarına, güzel cevâb yazdı. (Reşeh", "gectigiMaddeler": ["3/51"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şeyhzâde Muhammed", "slug": "seyhzade-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \n– 1179 –\nbin Mustafâ, Hanefî âlimlerindendir. Müderris idi. 951 [m. 1544] de vefât etdi. \nBeydâvînin (Envâr-üt-tenzîl) tefsîrine hâşiyesi çok kıymetli olup, hicretin 1306 [m. \n1888] senesinde İstanbulda matba’a-i Osmâniyyede basılmış ve Hakîkat Kitâbevi \ntarafından, dört cüz hâlinde basdırılmışdır. (Kasîde-i bürde), (Meşârık) ve (Vikâ-\nye) şerhleri meşhûrdur. Babasışeyh Mustafâ Müslih-uddîn efendi, Bâyezîd-i Velî \nzemânı meşâyıhından olup, Abdüllah-i ilâhînin halîfesi idi ve Hırka-işerîfde (Müs-\nlih-uddîn) mescidini yapdırmışdır. Buna Tahta minâreli mescid de denir. Kabri, \ncâmi’inin yanındadır.", "gectigiMaddeler": ["2/21", "3/12"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şihâbüddîn-i Sühreverdî", "slug": "sihabuddin-i-suhreverdi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Hafs \nÖmer bin Muhammed, Şâfi’î fıkh âlimi ve Sôfiyye-i aliyyedendir. Ebû Bekr-i Sıd-\ndîkın soyundandır. 539 [m. 1145] da tevellüd, 632 [m. 1234] de, Bağdâdda vefât etdi. \nEbû Necîb Sühreverdînin halîfesidir. Abdülkâdir-i Geylânînin sohbeti ileşerefle-\nnip kemâle erdi. Kitâbları arasında (Avârif-ül-me’ârif) kitâbı Beyrutda (Mekteb-\nüt-ticârî) kitâbevinde satılmakdadır. Ayrıca Beyrutda (Dâr-ül-ma’rife) tarafından \nbasdırılan (İhyâ-ül-ulûm) beşinci cildine de ilâve edilmişdir. Tesavvuf bilgilerini \nçok iyi bildirmekdedir. Şihâbeddîn Yahyâ bin Hüseyn Sühreverdî başka olup, fel-\nsefeye bağlanmışdı. 586 [m. 1189] da, Salâhaddîn-i Eyyûbînin emri ile Halebde katl \nedildi.", "gectigiMaddeler": ["2/60", "2/61", "3/41", "3/51"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şihristânî", "slug": "sihristani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül Feth Muhammed bin \nAbdülkerîm, fıkh ve kelâm âlimidir. 479 [m. 1086] da Horâsânda tevellüd, 548 [m. \n1154] de Bağdâdda vefât etdi. Eş’arî mezhebinde idi. Yetmişüç islâm fırkasını \ngeniş anlatan (Milel-nihal) kitâbı 1070 [m. 1660] senesinde vefât eden Nûh bin \nMustafâ tarafından Mısrda türkceye terceme edildiği gibi, çeşidli Avrupa dillerine \nde çevrilmişdir. Arabîsi Beyrutda (Mekteb-üt-ticârî)de satılmakdadır.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şiller", "slug": "siller", "unvan": "", "kategori": "diger", "biyografi": "Alman doktoru veşâ’iridir. 1172 [m. 1759] de tevellüd, 1219 \n[m. 1805] da vefât etdi. Papaslar elinde din terbiyesi ile büyüdü ise de, hıristiyan-\nlıkda, akl ve ilm dışı olan bozuklukları görerek, fâci’a [trajedi] tiyatroşi’rleri yaza-\nrakşöhret kazanmışdır.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şît [şis]", "slug": "sit-sis", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Âdem aleyhisselâmın oğludur. Babası ölünce, \nPeygamber oldu. Allahü teâlâ, buna elli suhuf (forma) gönderdi. Kâ’beyi taşdan \nyapdı. Nûh “aleyhisselâm” bunun soyundan olduğu için tûfândan kurtulanlar ve \nbütün insanlar bunun çocukları olmakdadırlar. Bunun için, ikinci Âdem sayılır.", "gectigiMaddeler": ["1/39", "1/97", "2/20"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şopen", "slug": "sopen", "unvan": "", "kategori": "diger", "biyografi": "Chopin Polonyalı müzikcidir. 1225 [m. 1810] de tevellüd, 1265 [m. 1849] de vefât etdi. Romantizm üzerinde idi. (Polonya) yazısı meşhûrdur.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Şüreyh (kâdî)", "slug": "sureyh-kadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Ümeyye bin Hars, \nTâbi’înin büyüklerindendir. Kırk yaşında iken hazret-i Ömer tarafından Kûfeye \nkâdî [hâkim] yapıldı. Hazret-i Alî halîfe iken, bunun karşısında, bir zimmî yehûdî \nile muhâkeme edilmişdi. Çok âdil idi. Fıkhda ve tecribî ilmlerde çok bilgisi vardı. \nYetmişdokuz 79 [m. 698] senesinde, yüzyirmi yaşında vefât etdi. Babasının adı \nHani idi. Elçi olarak Medîneye gelmişdi. Resûlullahı görünce, müslimân oldu. \nResûlullah, buna Ebû Şüreyh diye soy adı verdi. Kâdî Şüreyk başkadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Taberânî", "slug": "taberani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Süleymân bin Ahmed Taberâ-\nnî, hadîs âlimidir. Şâmda Taberiyyede [260] da tevellüd, 360 [m. 971] da orada \nvefât etdi. (Kebîr), (Evsat) ve (Sagîr) hadîs kitâblarını yazmak için, otuzüç sene, \nIrâk, Hicâz, Yemen, Mısr ve başka yerleri dolaşdı.", "gectigiMaddeler": ["1/77", "1/97", "1/98", "2/17", "2/18", "2/44", "3/34", "3/59"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Taberî", "slug": "taberi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Ca’fer Muhammed bin Cerîr, \ntefsîr ve hadîs ve Şâfi’î fıkh âlimidir. 224 [m. 839] de Taberistânda tevellüd ve 310 \n[m. 923] da Bağdâdda vefât etdi. (Târîh-ul-ümem) ve yirmiüç cild (Câmi’ul-beyân) \ntefsîri çok kıymetlidir. Alî bin Muhammed Şimşâtî adında birşî’î bu târîhi ihtisâr \n– 1180 –\netmiş, buşî’î kitâbı, (Taberî târîhi) adı ile türkceye terceme edilmişdir. Okuyanlar \naldanmakdadır. Muhammed bin Cerîr bin Rüstem Taberîninşî’î olduğu, Âlûsînin \n(Tuhfe-i isnâ-aşeriyye muhtasarı) kitâbının altmışsekizinci [68] sahîfesinde yazılı-\ndır. Muhammed bin Ebil-Kâsım Taberînin deşî’î olduğu (Esmâ-ül-müellifîn)de \nyazılıdır. Bunları İbni Cerîr hazretleri ile karışdırmamalıdır. 548 [m. 1153] de vefât \neden imâmiyye fırkasından Fadl bin Hasen Taberînin (Mecma’ul-beyân) adındaki \n(Tabersî) şî’î tefsîri de, (Taberî) tefsîri ile karışdırılmakdadır. Muhibbuddîn \nAhmed Taberîşâfi’î 694 de vefât etdi.", "gectigiMaddeler": ["1/97", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tâc-Üd-Dîn-i İskenderî", "slug": "tac-ud-din-i-iskenderi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin \nMuhammed, İbni Atâullah İskenderî adı ile meşhûr olmuşdur. Mâlikî âlimlerinin \nve Şâzilî tarîkatinin büyüklerindendir. Ebül Abbâs- ı Mürsînin talebesi ve Ebül-\nHasen-i Sübkînin mürşididir. 709 [m. 1309] senesinde Mısrda vefât etdi. Kurâfe \nkabristânındadır. (Hikem-i Atâ-iyye) ve (Letâif-ül-minen) kitâbları ve İbni Tey-\nmiyyeye reddiyyesi meşhûrdur. [Hindlişeyh Tâc-üd-dîn-i Nakşibendî başka olup, \nrâbıtayı isbât eden (Tâciyye risâlesi) , Hâlid-i Bağdâdînin (Tahkîk-ı râbıta) risâle-\nsinde mevcûddur. Bu risâle (İslâm Âlimleri)  kitâbının sonunda basdırılmışdır. \nTâcüddin 1050 de Mekkede vefât etmişdir.]", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tâc-Üd-Dîn-i Sübkî", "slug": "tac-ud-din-i-subki", "unvan": "", "kategori": "diger", "biyografi": "İkiyüzkırküçüncü [243] sırada Ebû Hasen-i \nSübkî ismine bakınız!", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tâc-Üş-Şerî'a", "slug": "tac-us-seria", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ömer bin Sadr-üşşerî’at-ül-\nevvel Ahmed bin Ubeydüllah Mahbûbî, Burhân-üş-şerî’a Mahmûdun kardeşidir. \nTâc-üş-şerî’a Ömerin oğlu Mes’ûd, amcası olan Burhân-üş-şerî’a Mahmûdun dâmâ-\ndıdır. Tâc-üş-şerî’a, Buhârâda Hanefî fıkh âlimi idi. 673 [m. 1274] de, Moğol fitne-\nsindeşehîd oldu. (Hidâye)yişerh edip (Nihâye-tül-kifâye) adını vermişdir.", "gectigiMaddeler": ["3/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tahâvî", "slug": "tahavi", "unvan": "", "kategori": "diger", "biyografi": "Ebû Ca’fer Ahmed bin Muhammed, Hanefî fıkh âlimidir. 238 de Mısrda tevellüd, 321 [m. 933] de orada vefât etdi.", "gectigiMaddeler": ["1/71", "1/78", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tâhâ-i Hakkârî", "slug": "taha-i-hakkari", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Seyyid Tâhâ, Abdülkâ-\ndir-i Geylânî hazretlerinin onbirinci torunudur. Ya’nî Peygamberimizin soyundan \nseyyid olup, kürdlükle bir ilgisi yokdur. Hâlid-i Bağdâdînin talebelerinin büyüklerin-\ndendir. Rûh bilgilerinin mütehassısıdır. Mevlânâ Hâlidin halîfesi olan seyyid Abdül-\nlahın kardeşi molla Ahmedin oğludur. Seyyid Abdüllah, ma’kûl ve menkûl ilmlerde \nmâhir idi. 1229 da Bağdâda gelerek, tesavvufda da kemâle erdi. Seyyid Tâhâ, Nehri \nkasabasında ders vermeğe me’mûr edildi. 1269 [m. 1853] senesinde orada vefât etdi. \nBütün hocaları gibi, islâmın güzel ahlâkını yaymış, siyâsete karışmamış, müslimânla-\nrı hükûmete hizmet, kanûnlara itâat etmeğe ve herkese iyilik yapmağa teşvîk eyle-\nmişdir. Hâl tercemesi, Hakîkat Kitâbevinin İstanbulda neşr etdiği (The proof of \nprophethood) kitâbında ingilizce olarak yazılıdır. Oğlu, seyyid Ubeydüllah, Mekke-\nde vefât etdi. Bunun dört oğlundan seyyid Abdülkâdir efendi İstanbulda a’yân \n[Senato] başkanı idi. 1344 [m. 1926] de Diyâr- ı Bekrde oğlu seyyid Muhammed ile \nbirlikdeşehîd oldu. Seyyid Muhammedin iki oğlundan seyyid Mûsâ, 1391 [m. 1971] \nde Ş\nâh Rızâ Pehlevînin izni ve yardımı ile, Îrânın Rıdâiyyeşehrinde Ehl-i sünnet bil-\ngilerini ve tesavvuf ma’rifetlerini neşr etmekde idi. İkinci oğlu Ahmed Hıdır beğ \nAmerikada yüksek mühendislik tahsîli yapdı. Seyyid Ubeydüllah efendinin ikinci \noğlu Muhammed Sıddîk efendi, Şemdinanda Katûne köyünde medfûndur. Bunun \ndört oğlu Râşid, Tâhâ, Şemseddîn ve Müslihüddîndir. Abdülkâdir efendinin ikinci \noğlu Abdüllah efendi Rıdâiyyede neşr-i ilm ederken [m. 1969] da vefât etdi. Dize \nkasabasındadır. İki oğlundan Abdülkâdir efendi Rıdâiyyededir. Büyük oğlu \nAbdül’azîz efendi, 1401 [m. 1981] deşî’î lideri Humeynî tarafından Îrândan çıkarıldı. \nBağdâddadır. Seyyid Tâhânın babası Ahmed ve dedesi Seyyid Sâlih ve bunun babası \nSeyyid İbrâhîm, Nehridedirler.", "gectigiMaddeler": ["3/37", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tâhir-i Bedahşî", "slug": "tahir-i-bedahsi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Önce subay idi. Bir kal’a \n– 1181 –\nalmağa giderlerken, rü’yâda Resûlullah “sallallahü aleyhi ve sellem” buna, (Bu \nmuhârebeden dönüşde askerlikden ayrıl, tesavvuf büyüklerinin sohbetinde \nbulun!) buyurdu. Seferden dönüşde, askerliği bırakdı. Delhîye geldi. Sorup, araş-\ndırıp, İmâm-ı Rabbânî “kuddise sirruh” hazretlerinin sohbetine kavuşdu. Yalvar-\ndı. Cân ve gönülden hizmet etdi. Yüce İmâmın merhametine kavuşdu. Nasîbini \naldı. Uyanık iken, tenhâda ve galabalıkda, hergün Resûlullahı “sallallahü aleyhi ve \nsellem” görürdü. Sâf ve temiz rûhlu idi. Ba’zı keşflerini ve hâllerini, öylece bildirir, \nİmâm hazretlerini güldürürdü. Yüksek ma’rifetleri işitirken, (Evet öyledir, evet \ndoğrudur) buyurur, mubârek başını sallardı. Tâliblere ta’lîm için icâzet verilip, \nCumbura gönderildi.", "gectigiMaddeler": ["1/75"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tahtâvî", "slug": "tahtavi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Muhammed bin \nİsmâ’îl, Kâhirede Hanefî müftîsi idi. 1231 [m. 1815] de vefât etdi. (Dürr-ül-muh-\ntâr)a ve (Merâkıl-felâh)a hâşiyeleri basılmışdır. Dürr-ül-muhtâr hâşiyesini Ayn-\ntablı Abdülhamîd efendi, arabîden türkçeye terceme etmiş ve basılmışdır.", "gectigiMaddeler": ["1/54", "1/60", "1/68", "1/70", "1/71", "1/73", "1/74", "1/78", "1/79", "1/82", "1/84", "1/90", "2/16", "2/17", "2/42", "2/43", "2/72", "3/21", "3/57"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Talha", "slug": "talha", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Talha bin Ubeydüllah bin Osmân bin Amr, \nilk îmâna gelenlerden ve aşere-i mübeşşeredendir. Dedesi, Ebû Bekr-i Sıddîkın \ndedesinin kardeşidir. Bedr gazâsında, Şâm tarafında vazîfede idi. Diğer gazâlarda \nbulundu. Uhudda Resûlullahı korumak için çok yara aldı. Arkasında taşıyarak \nkayaya çıkardı. (Talha ile Zübeyr, Cennetde komşularımdır) hadîs-işerîfi ile medh \nedildi. Çok zengin olup bütün malını Allah yolunda dağıtdı. Deve harbinde haz-\nret-i Alîye karşı idi. Orada, ok ileşehîd oldu. Hazret-i Alî, buna çok üzüldü. Ağlı-\nyarak, mubârek eli ile, yüzünden toprağı sildi. Nemâzını kendi kıldırdı.", "gectigiMaddeler": ["2/23", "2/41", "3/60"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tâlût", "slug": "talut", "unvan": "", "kategori": "diger", "biyografi": "Benî-İsrâîlin ilk hükümdârı idi. İşmôîl “aleyhisselâm” ta’yîn bu -\nyurmuşdu. Filistinliler ve Amâlika ile harb edip, gâlib geldi. Askeri arasında bulu-\nnan Dâvüd “aleyhisselâm”, onsekiz yaşında idi. Filistin ordusundaki, cesûr ve çok \nkuvvetli olan Câlûtu öldürdü. İşmôîl “aleyhisselâm” Tâlût yerine Dâvüd aleyhis-\nselâmı hükûmet reîsi yapdı. O sırada Tâlût, harbde öldü. Kırk sene hükûmet \nsürdü. Yerine Dâvüd “aleyhisselâm” melik oldu.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tarsûsî", "slug": "tarsusi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Ahmed, Hanefî \nfıkh âlimlerindendir. 1117 [m. 1705] de vefât etdi. (Üsûl) ilminde (Mir’ât) kitâbına \nhâşiyesi meşhûrdur.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Târuh", "slug": "taruh", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İbrâhîm aleyhisselâmın asl babası \nidi. Mü’min idi. (Mir’ât-i kâinât)da ve (Tefsîr-i teysîr)de ve molla Miskîn Mu’înin \nfârisî (Me’âric-ün-nübüvve) kitâbında ve tefsîrlerde, İbrâhîm aleyhisselâmın baba-\nsı Târuhdur yazılıdır. Kâfir olan Âzer, İbrâhîm aleyhisselâmın öz babası değildi. \nAmcası idi. Târuh ölünce Âzer, İbrâhîm aleyhisselâmın annesini aldı. Böylece, \nüvey babası oldu. Târuh ile Âzer, iki kardeş idi. Âzerin (Tevrât)daki adı Târuh idi \ndemek yanlışdır.", "gectigiMaddeler": ["1/95", "1/97"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Taşköprü Zâde", "slug": "taskopru-zade", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Mustafâ, \nOsmânlı âlimlerindendir. 901 [m. 1495] de Bursada tevellüd, 968 [m. 1561] de İs -\ntanbulda Âşıkpâşa mahallesinde vefât etdi. (Şakâ’ik-i Nu’mâniyye) târîh kitâbı ile \n(Miftâh-üs-se’âde) kitâbı meşhûrdur. Oğlu Kemâleddîn Muhammed, (Miftâh)ı \ntürkçeye terceme ederek (Mevdû’ât-ül ulûm) ismini vermişdir.", "gectigiMaddeler": ["1/7", "1/78", "2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tayyıbî", "slug": "tayyibi", "unvan": "", "kategori": "diger", "biyografi": "Şerefüddîn Hasen bin Muhammed 743 [m. 1342] de vefât et -\ndi. (Mişkât) şerhi meşhûrdur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Teftâzânî", "slug": "teftazani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yediyüzseksenbeşinci [785] \nsırada Sa’düddîn ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Temîm-i Dârî", "slug": "temim-i-dari", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ensâr- ı kirâmdandır. Nasrânî âlim-\n– 1182 –\nlerinden idi. Hicretin dokuzuncu senesinde Filistinden Medîneye gelip, Resûlulla-\nhı görünce, hemen îmân etdi. Resûlullah “sallallahü aleyhi ve sellem” Filistindeki \nHebron, ya’nî Halîl-rahmân idâresini buna vermişdi. Şimdiki idârecileri bunun \nsoyundandır. Şâmda vefât etdi.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Terman", "slug": "terman", "unvan": "", "kategori": "diger", "biyografi": "Amerikalı felsefeci ve fikr adamıdır. 1380 [m. 1960] senesin-\nde hayâtda idi.", "gectigiMaddeler": ["2/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tezveren Dede", "slug": "tezveren-dede", "unvan": "", "kategori": "diger", "biyografi": "Sultân Mahmûd türbesinden, Nûr-i Osmâniyye cad-\ndesine giden yolda, solda ufak bir türbededir. Fâtih sultân Muhammed zemânında \nidi. İstanbul halkı, hâcetlerinin hâsıl olması için, bu türbeye adak yapar idi. Bursada \nmedfun olan seyyid Atâullah hazretlerine de Tezveren dede denilmekdedir.", "gectigiMaddeler": ["1/83"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ticânî", "slug": "ticani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül’Abbâs Ahmed ticânî, büyük \ntesavvuf âlimidir. Ahmed bin İdrîs hazretlerinin halîfesidir. Cezâirin cenûbunda \n(Ayn-ı mâdî) denilen yerde 1150 [m. 1737] de tevellüd ve Fasda 1230 [m. 1815] da \nvefât etdi. Halvetînin bir kolu olan (Ticânî) tarîkatinin reîsidir. (Cevheret-üt-hakâık \nfissalât-i alâ hayril-halâik) ve (Cevâhir-ül-me’ânî) ve (Kitâb-ür-remâh) ve (Fid-\ndifâ’an turuk- ı ehl-il-hüdâ) ve (Câmi’u-kerâmât-il-Evliyâ) ve (Nasara-tüz-zâkirîn) \nkitâblarında ve (Gâyet-ül-emânî) kitâbında kendisi ve tarîkati uzun anlatılmakda-\ndır. İlk ikisi birlikde 1344 [m. 1926] da Mısrda, diğerleri Beyrutda basılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Timoçin", "slug": "timocin", "unvan": "", "kategori": "diger", "biyografi": "Cengizin adıdır. 197. ci sırada Cengiz ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tîmûr Hân", "slug": "timur-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Emîr Tîmûr Gürgân, 736 [m. \n1336] da Mâverâ-ün-nehrde, Semerkandla Belh arasında, Keş kasabasında tevellüd, \n807 [m. 1405] de vefât etdi. Semerkanddadır. Cengiz gibi Moğol soyundandır. 770 \n[m. 1369] de Belhi alıp, hânlığını i’lân etdi. Çok harb etdi. Hep gâlib geldi. Çine ve \nDelhîye kadar bütün Asyayı, Irâk, Sûriye ve İzmire kadar Anadoluyu aldı. İkiyüzbin \nkişi ile Çine giderken vefât etdi. Âlimleri severdi. Çok medrese ve kütübhâneler \nyapdı. Kanûnlar çıkardı. Kendi târîhini kendi yazdı. Teftâzânî gibi büyük âlimleri \nmeclisinde bulundurur, nasîhatlerini dinlerdi. Nasreddîn hoca ile sohbeti vâki’ değil-\ndir. Yıldırım ile harb etdiği için, Osmânlı târîhleri bunu haksız olarak kötülemekde, \nharb sâhasında ölenleri, zulm ve ortalığı kana boyamakşeklinde bildirmekdedir. \nDört oğlundan ikisi kaldı. Biri Mîrânşâh olup, üç sene sonra, Kara-koyunlu askeri \nile harb ederken öldürüldü. İkinci oğlu Mu’în-üddîn Şâhruh 779 [m. 1377] da Semer-\nkandda tevellüd etdi. Babasının devletine hâkim oldu. 850 [m. 1445] de vefât etdi. \nBunun oğlu Uluğ beğ 797 [m. 1395] de Semerkandda tevellüd etdi. Semerkand vâlîsi \nidi. İlme, fenne çok hizmet etdi. Babası ölünce, idâreyi ele aldı ise de, 853 [m. 1448] \nde, oğlu Abdüllatîf tarafından öldürüldü. Bu da, altı ay sonra öldürüldü. Tîmûr hân, \nhurûfîliği kuran Fadlullah- ı Tebrîzîyi öldürterek ve yanındakileri dağıtarak, çoğal-\nmalarını önleyerek, islâmiyyete büyük hizmet etmişdir.", "gectigiMaddeler": ["2/22", "2/61"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tîmûrtâşî", "slug": "timurtasi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "872. ci sırada, Şemseddîn Tî -\nmûrtâşî ve dokuzyüzseksenyedinci [987] sırada Zahîrüddîn Hârezmî ismlerine \nbakınız! Doğrusu Tümürtaş olup, Hârezmşehrinde bir kasabadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tirmüzî", "slug": "tirmuzi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Îsâ, hadîs âlimle-\nrindendir. Buhârânın cenûbunda, Ceyhûn nehri kenârında Tirmüz kasabasında 209 \n[m. 824] da tevellüd, 279 [m. 892] da Boğşehrinde vefât etdi. (Sahîh-i Tirmizî) ve \n(Şemâil-işerîfe) kitâbları çok kıymetlidir. (Şemâil) kitâbını Hüsâmeddîn-i Nakşi-\nbendî 1248 [m. 1832] de türkceye çevirmiş, tekrâr tekrâr basılmışdır. (Sünen-i Tirmi-\nzî) adındaki sahîhinin, Hindistânda, Diyobendşehrindeki (Dâr-ül-ulûm) müderris-\nlerinden Muhammed Enverşâh Keşmîrî tarafından arabîşerhı yapılmış, (Me’ârif-\nüs-sünen) adı verilerek 1383 [m. 1963] senesinde, Muhammed Yûsüf Benûrî tara-\nfından Pâkistânda basılmışdır. Altı cilddir. Enverşâh, burada İbni Teymiyyeyi \nmezheb imâmları derecesine çıkararak, onun sapık fikrlerine de yer vermiş, hattâ \n– 1183 –\nbirinci cildde, rûhun madde olduğunu söyliyerek, imâm- ı Gazâlînin madde değildir \ndemesini felsefeye kaymakla ithâm etmişdir. Hâlbuki, çok övdüğü Şâh Veliyyul-\nlah-ı Dehlevî, (İzâle-tül-hafâ) kitâbının ikinci cildinde, Gazâlînin fıkh âlimi oldu-\nğunu, beşinci yüzyılın müceddidi olduğunu bildirmekde, onu çok övmekdedir. \nYûsüf-i Benûrî, altıncı cildin yüzkırkdokuzuncu sahîfesinde, ( İbni Teymiyyenin, \nkendi mezheb imâmı olan Ahmed bin Hanbelden ayrılarak, Dâvüd-i Zâhirî mezhe-\nbini tutduğunu) ve ( İbni Teymiyye, birçok üsûl ve fürû’ mes’elesinde Ehl-i sünnet \nâlimlerinden ayrılmış, asrının âlimleri ve sonra gelenler, onu red etmişlerdir) diye-\nrek, (Me’ârif-üs-sünen) kitâbının kıymet kazanmasını sağlamışdır.", "gectigiMaddeler": ["1/60", "1/83", "1/97", "2/6", "2/41", "2/44", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tokâdlı Emîn Efendi", "slug": "tokadli-emin-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed \nEmîn efendi, İstanbulda bulunan meşâyıhın büyüklerindendir. Mekke-i mükerre-\nmede Ahmed Yekdest-i Cüryânîden 1114 [m. 1701] senesinde icâzet almaklaşereflendi. Üç sene sonra İstanbula geldi. Ayvanserâydaki Emîr Buhârî tekkesininşeyhi olan Kırîmî Ahmed efendi 1156 [m. 1743] da vefât edince, buna halef oldu \nve 1158 [m. 1745] de vefât etdi. (Savâ’ık-ı Muhrika) yı türkceye terceme etdi. \nUnkapanına inen cadde ile Zeyrek yokuşunun kesişdiği tepe üzerinde Soğuk kuyu \nPîrî pâşa medresesi kabristânında, âşıkları ziyâret edip feyz almakda, murâdlarına \nkavuşmakdadırlar. Talebesi Müstekîmzâde de orada medfûndur. Muhammed \nEmîn efendi kahve ve tütün içerdi.", "gectigiMaddeler": ["2/5"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tosun Pâşa", "slug": "tosun-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mısr hâkimi Kavalalı Mehmed \nAlî pâşanın oğludur. Vehhâbîler Mekke ve Medîneyi ele geçirip yedi sene Ehl-i sün-\nnet hâcılarını Mekkeye sokmadı. Tosun pâşa 1226 [m. 1811] de Mısrdan gönderildi \nise de, muvaffak olamadı. Sonra Mısrda vefât etdi.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Turhân Sultân", "slug": "turhan-sultan", "unvan": "rahmetullahi teâlâ aleyhâ", "kategori": "alim", "biyografi": "Sultân İbrâhîmin zev-\ncesi ve dördüncü sultân Muhammedin vâlidesidir. Hadîce Turhân sultân, sâliha ve \nhayrı sever bir hânım idi. Eminönünde büyük Yeni câmi’in temelini Mâhpeyker \nKösem sultân atmışdı. Turhân sultân temâmlatıp, 1074 [m. 1664] de ibâdete açıldı. \nMekteb, medrese, imârethâne, kütübhâneler, çeşmeler yapdırdı. 1094 [m. 1682] de \nvefât etdi. Yeni câmi’ yanındaki, Turhân sultân türbesindedir. Oğlu sultân dördün-\ncü Muhammed ile torunları sultân ikinci Mustafâ ve üçüncü sultân Ahmed ve \nbirinci sultân Mahmûd ve sultân üçüncü Osmân hân ve sultân beşinci Murâd ve \nsultân Mahmûdun vâlidesi Sâliha sultân ve diğerşâhzâdeler de buradadırlar. \nÜçüncü Mustafâ hânın vâlidesi Mihr-işâh Emîne sultân ile birinci Abdülhamîd \nhânın vâlidesi Râbi’a sultân da buradadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Tür-Püştî", "slug": "tur-pusti", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Fadlullah bin Hasen, hanefî \nfıkh âlimlerinden olduğu (Esmâ-ül-müellifîn)de yazılıdır. 661 [m. 1262] senesinde \nvefât etdi. Tesavvufda (Tuhfe-tüs-sâlikîn) kitâbı ve (Müyessir) adındaki (Mesâ-\nbîh) şerhı çok kıymetlidir. (El-mu’temed fil-mu’tekad) adındaki akâid risâlesini \nHakîkat Kitâbevi 1990 da basdırmışdır. (Herkese Lâzım Olan Îmân)  kitâbında, \n68.ci sahîfeyi okuyunuz!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ubeydüllah-i Ahrâr", "slug": "ubeydullah-i-ahrar", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ubeydüllah bin \nMahmûd bin Şehâbüddîn, Sôfiyye-i aliyyenin büyüklerindendir. Müslimânların \ngözbebeğidir. Sekizyüzaltı [806] da Taşkendde tevellüd, 895 [m. 1490] de Semer-\nkandda vefât etdi. Ya’kûb-i Çerhînin talebesi, Mevlânâ Hâce Muhammed Zâhid \nhazretlerinin üstâdı idi. Zâhirî ve bâtınî ilmlerin hazînesi idi. Dahâ çocuk iken \nkerâmetleri görülüyordu. Halâl kazanmak için, zirâ’at ile meşgûl olurdu. O kadar \nbereket oldu ki, binüçyüzden fazla çiftliği vardı. Herbirinde üçbin amele çalışırdı. \nHer sene sekizyüzbin batman zahîre uşr verirdi. (Tesavvuf bilgilerinin maksad ve \nnetîcesi, kendini zorlamadan, uğraşmadan, her ân Allahü teâlâya teveccüh ve \nikbâldir. Ya’nî, her ân, Allahü teâlâyı\n hâtırlamakdır) ve (Bir kimse, erbâb-ı cem’iy-\nyet sohbetinde oturup, gönlünü Hak teâlâya verebilirse, ona zikr yapmağa ihtiyâc \nyokdur) buyururdu. (Râbıta edenler için, bedenin uzak olması, ma’nevî yakınlığa \n– 1184 –\nmâni’ olmaz) derdi. (Çok açlık ve çok uykusuzluk dimâgı yorar. Hakîkatleri ve \nince bilgileri anlamağı önler. Bunun için, riyâzet çekenlerin keşfleri hatâlı olur) ve \n(Zikr ve murâkaba, bir müslimâna hizmet yapılamadığı zemânda olur. Gönül \nkabûlüne sebeb olan hizmet, zikr ve murâkabadan önce gelir) buyururdu. \nUbeydüllah-i Ahrârın talebelerinden biri, Abdüllah-i İlâhîdir. Simavlıdır. İlm \nedindikden sonra Semerkanda, Buhârâya giderek feyz aldı. İcâzetleşereflenip \nUbeydüllah-i Ahrâra intisâbı bulunan Emîr Ahmed-i Buhârî ile İstanbula geldi. \nYolda Molla Câmî ile sohbet eyledi. Zeyrek kilise câmi’inde va’z ve halkı irşâd \netdi. Emîr Buhârîye icâzet verdi. Vardar Yenicesinde 896 [m. 1491] da vefât etdi. \nUbeydüllah-i Ahrâr›n bir talebesi de Abdüllah-i Semerkandîdir. Önce, Ya’kûb-i \nÇerhîye intisâb etmiş ve Alâüddîn-i Attâr›n halîfelerinden olan Nizâmeddîn-i \nHâmûşdan da feyz alm› şd›r. Uluğ beğ medresesinde müderris idi. Yûsüf-i Nebhânî \ndiyor ki, (Sokakda giderken, ans› z›n at› n› istedi. Eshâb› ile Semerkand›n d› ş› na \nç›kd›. Onlardan ayr› l›p, çok zemân sonra yanlar› na geldi. Türk sultân› Muhammed \nhân, kâfirlerle harb ediyordu. Onun yard› m› na gitdim. Gâlib geldi dedi.) Fâtih, \n‹stanbulu bu sûretle ald›. Sekizyüzyetmişbeş 875 [m. 1470] de vefât etdi. Ubeydül-\nlah-i Ahrâr›n bir talebesi de Haydar babad›r. K›rk sene devâml› Eyyûb câmi’inde \ni’tikâf etdi. Sultân Süleymân bu zât›n üstün hâllerini işitince, Eyyûb Nişâncas› ile \nHalic aras›nda, Cezrî Kâs›m pâşa câmi’ine inen yol üzerinde (Haydar baba mesci-\ndi)ni yapd›rd›. Haydar baba, 957 [m. 1550] de vefât etdi. Mescide girerken soldad›r. \nMuhammed Ma’sûm-i Fârûkînin oğlu Muhammed Ubeydüllah 1083 de, bunun \noğlu Muhammed Pârisâ 1142 de vefât etdi.", "gectigiMaddeler": ["1/41", "1/46", "1/97", "2/61", "3/47", "3/51", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ubeydüllah bin Cahş", "slug": "ubeydullah-bin-cahs", "unvan": "", "kategori": "diger", "biyografi": "Resûlullahın halası Ümeymenin oğludur. \nÖnce îmâna geldi, Eshâbdan oldu. Zevcesi Ümm-i Habîbe ve kardeşi Abdüllah ile \nHabeşistâna hicret etdi. Orada, mal ve mevkı’ için, mürted oldu ve öldü.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ubeydüllah bin Mes'ûd", "slug": "ubeydullah-bin-mesud", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yediyüz-\ndoksanıncı [790] sırada Sadrüşşerî’a ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ubeydüllah bin Utbe", "slug": "ubeydullah-bin-utbe", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Abdüllah \nUbeydüllah bin Mes’ûd bin Abdüllah bin Utbe, Tâbi’înin büyüklerinden ve Medîne-\ndeki yedi fıkh âlimlerindendir. Abdüllah ibni Mes’ûd “radıyallahü anh” hazretlerinin \nkardeşi olan Utbenin torunudur. 102 [m. 721] senesinde Medînede vefât etdi. 66. \n— Uhud Gazvesi: Hamza ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ukâşe", "slug": "ukase", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ebû Muhsin Esedîdir. Bedr gazâsında kılıncı \nkırıldı. Resûlullahın verdiği hurma dalı ile harb edip, çok kâfir katl etdi. Bütün \ngazâlarda bulundu. Çok yerinden yaralandı. Cennetle müjdelendi. Bir muhârebe-\nde Tuhayla bin Huveylid ismindeki bir papas tarafından sırtından hançerlenerek, \nkırkbeş yaşındaşehîd edildi. Beyâz ve çok güzel idi. Kabri, Gâzîayntabda Nûrdağı \nkazâsı, Durmuşlar köyündedir.", "gectigiMaddeler": ["2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ukayl", "slug": "ukayl", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Ebû Tâlibin dört oğlundan ikincisidir. Bedr \ngazâsında esîr oldu. Hazret-i Abbâs kendisi ile bunun fidyelerini verip Mekkeye \ngitdiler. Hudeybiyyeden önce Medîneye gelip îmân etdi. Gazâlarda bulunup, ilti-\nfâta mazhar oldu. Neseb bilgisi çok idi. Kardeşi hazret-i Alîye karşı hazret-i \nMu’âviye ile birlikde idi.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Urve", "slug": "urve", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Urve-tebniz-Zübeyr, Tâbi’înin bü -\nyüklerinden ve Medînedeki yedi büyük âlimden biridir. Zübeyr bin Avvâmın oğlu-\ndur. Annesi, Esmâ bint-i Ebû Bekrdir. Yirmiikinci [22] senede tevellüd, 94 [m. \n712] senesinde Medîne yanında Fer’ ovasında vefât etdi.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Utbe", "slug": "utbe", "unvan": "", "kategori": "diger", "biyografi": "Utbe bin Rebî’a bin Abd-i \nŞems bin Abd-i Menâf, Bedrde \nKureyş ordusunun reîslerinden idi. Velîdin ve Ebû Huzeyfenin ve Hindin babası \nidi. Hind de, hazret-i Mu’âviyenin annesidir. Babası Rebî’a, Ümeyyenin kardeşi \n– 1185 –                                  Se’âdet-i Ebediyye 3-F:75\nidi. Âyet-i kerîmeleri işitince, (Bu sözşi’r değil, sihr değil, kehânet değildir. Ey \nKureyşliler! Beni dinlerseniz, bu adama dokunmayınız!) demişdi. Bedrde, kardeşi \nŞeybe ile birlikde, hazret-i Hamza tarafından öldürüldü.", "gectigiMaddeler": ["1/85", "2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ümm-i Gülsüm", "slug": "umm-i-gulsum", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın kızıdır. Ebû Lehe-\nbin ikinci oğlu Uteybeye nikâhlandı ise de, (Tebbet yedâ)  sûresi gelince, dahâ \ndüğünleri olmadan boşadı ve Resûlullaha üzücü sözler söyledi. Resûlullah “sallal-\nlahü aleyhi ve sellem” da, (Yâ Rabbî! Buna canavarlarından birini musallat et!) \ndiye beddüâ eyledi. Şâm yolunda bir arslan bunu parçaladı. Rukayye öldükden \nsonra vahy gelerek, Ümm-i Gülsüm hazret-i Osmâna “radıyallahü anhüm” nikâh-\nlandı. Hicretin dokuzunda [9] vefât etdi. Nemâzını Resûlullah kıldırıp, defn olu-\nnurken kabri yanında durup, mübârek gözlerinden yaş akardı.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ümm-i Habîbe", "slug": "umm-i-habibe", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Ebû Süfyân bin Harb bin \nÜmeyyenin kızı idi. Hazret-i Mu’âviyenin kız kardeşi idi. Annesi Hind idi. Zevci \nUbeydüllah bin Cahş ile birlikde müslimân olup, Habeşistâna hicret etdiler. \nZevci, orada papaslara aldanıp mürted oldu ve öldü. Bu, yalnız, garîb, fakîr \nkaldı. Resûlullahın dîninden ayrılmam, dedi. Resûlullah “sallallahü aleyhi ve sel-\nlem” onu sevindirmek için nikâh etmek istedi. Necâşîye, ya’nî Habeş sultânına \nhicretin yedinci [7] senesinde mektûb yazdı. Necâşî, bu emr-i nebevî üzerine, \nbunu Resûl-i ekreme nikâh etdi ve Medîneye gönderdi. Babası Ebû Süfyân, o \nzemân, henüz îmâna gelmemişdi. Mekke kâfirlerinin reîsi idi. 44 [m. 664] sene-\nsinde Medînede vefât etdi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ümm-i Hânî", "slug": "umm-i-hani", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Ebû Tâlibin kızı ve hazret-i Alînin \n“radıyallahü anh” kızkardeşidir. Hübeyre bin Amrin zevcesi idi. Öz adı Fâkite \nidi. Mekke-i mükerremenin feth edildiği gün, Hübeyre kaçdığı zemân, kendisi \nîmâna geldi. Resûlullah, bunun evinde gusl abdesti alıp, sekiz rek’at duhâ ya’nî \nkuşluk nemâzı kıldı ve su ile ekmekıslatıp tuz ve sirke koyup yidi. (Ey Ümm-i \nHânî! Sirke ne iyi yemekdir. Sirke bulunan ev fakîr olmaz!) buyurdu.", "gectigiMaddeler": ["1/85"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ümm-i Ma'bed", "slug": "umm-i-mabed", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Adı Âtike idi. Resûl “aleyhisse-\nlâm”, Hicretde bunun çadırına uğrayıp, za’îf koyunu sağınca, çok süt çıkmışdı. Bu \nmu’cizeyi zevcine söyledi. Sonra ikisi de, Medîneye gelip müslimân oldu.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ümm-i Seleme", "slug": "umm-i-seleme", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Adı Hind idi. Zevci Ebû Seleme \nile Habeşistâna ilk olarak hicret etdiler. Ebû Seleme, Resûlullahın halası Berrenin \noğlu olup, Medînede, hicretin dördüncü [4] senesi Uhud gazâsında aldığı yaradan \nvefât etdi. Ümmü Seleme, Ebû Bekr ve Ömerin “radıyallahü anhümâ” nikâh taleb-\nlerini kabûl etmedi. Resûlullahın nikâhı ileşereflendi. 59 [m. 678] senesinde Medî-\nnede seksendört yaşında vefât etdi. Son vefât eden zevceleri bu idi.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ümri-Ül-Kays", "slug": "umri-ul-kays", "unvan": "", "kategori": "diger", "biyografi": "İslâmiyyetden önce yaşayanşâ’irlerdendir. Hîre \nhükümdârının oğludur. Ankarada, kralın Kayseriden gönderdiği zehrli gömleği \ngiymekle vefât etdi. Kâ’beye asılanşi’ri edebî san’at bakımından çok kıymetlidir. \nOğulları, zemân- ı se’âdete yetişmişdir. Şi’rleri Avrupa lisânlarına çevrilmiş, ilk \nolarak 1294 [m. 1877] de Pârisde basılmışdır.", "gectigiMaddeler": ["1/91"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Üsâme bin Zeyd", "slug": "usame-bin-zeyd", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmın büyüklerin-\ndendir. Anası Ümm-i Eymen ve babası, Resûlullahın “sallallahü aleyhi ve sellem” \nâzâdlılarındandır. Onsekiz yaşında iken, bir birliğe kumandan yapıldı. [54] veyâ 59 \n[m. 678] senesinde Medînede vefât etdi.", "gectigiMaddeler": ["1/95", "3/56"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Üstüvânî", "slug": "ustuvani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Ahmed, Hane-\nfî âlimlerindendir. Şâmda tevellüd ve 1072 [m. 1662] de orada vefât etdi. Ayasofya \ncâmi’inde yıllarca va’z etdi. Fıkhda (Üstüvânî risâlesi) meşhûrdur.", "gectigiMaddeler": ["1/61"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vahîdeddîn Hân", "slug": "vahideddin-han", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sultân altıncı Muham-\n– 1186 –\nmed, İslâm halîfelerinin yüzbirincisi ve sonuncusudur. Osmânlı pâdişâhlarının \notuzaltıncı ve sonuncusudur. Sultân Abdülmecîd hânın en küçük oğludur. 1277 [m. \n1861] de tevellüd, 1344 [m. 1926] de, İtalyada San Remoda vefât etdi. Şâmda, sul-\ntân Selîm câmi’i kabristânındadır. 4 Temmuz 1336 [m. 1918] da büyük kardeşi sul-\ntân Reşâdın öldüğü gün halîfe oldu. İngilizlerin türk ve islâm düşmanı olduğunu \niyi biliyordu. İsmâ’îl Hâmî Danişmend, (Osmânlı Târîhi Kronolojisi) kitâbının \ndördüncü cildinde, Vahîdeddîn hân hakkında geniş bilgi vermekdedir.", "gectigiMaddeler": ["2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vâhidî", "slug": "vahidi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebül-Hasen Alî bin Ahmed, tefsîr \nâlimi idi. (Basît), (Vesît), (Vecîz)  adında üç tefsîri meşhûrdur. 468 [m. 1075] de, \nNîşâpûrda vefât etdi.", "gectigiMaddeler": ["2/5", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vahşî", "slug": "vahsi", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Vahşî bin Harb Habeşî, hazret-i Hamzanın \nBedr gazâsında öldürdüğü Tu’avme adındaki kâfirin kardeşinin oğlu Cübeyr bin \nMut’imin kölesi idi. Uhud gazâsında, Cübeyr, buna, Hamzayı öldürürsen âzâd ol \ndemişdi. Hind de babasının ve amcasının intikâmı için, Hamzayı öldürene çok altın \nva’d etmişdi. Bunlar için Vahşî, hazret-i Hamzayı, ok atarak ağır yaraladı ve kılıncı \nileşehîd etdi. Ciğerlerini çıkarıp Hinde götürdü. Her ikisi de, dünyâ zîneti için, bu \nişi yapdı. Uhudda, Resûlullah, birkaç kâfire beddüâ etmişdi. Vahşîye niçin la’net \netmiyorsun dediklerinde, (Mi’râc gecesi, Hamza ile Vahşîyi kolkola, birlikde Cen-\nnete girerlerken görmüşdüm) buyurdu. Mekkenin fethinden sonra, Vahşî, Tâifli-\nlerle birlikde Medînede mescide gelip, îmân etdi. Afva kavuşdu. Fekat, Yemâme \ntarafına gitmesi emr olundu. Resûlullaha karşı çok mahcûb olup, başı önünde \nyaşadı. Bir dahâ Medîneye gelmedi. (Muhammediyye) kitâbında (Adı da Vahşî, \nkendi de vahşî) yazısı, müslimân olmadan önce Vahşî olduğunu bildiriyor. Îmân \nedince, tertemiz oldu. Bütün Evliyâdan yüksek oldu. Hicretin onbirinci [11] senesi \nYemâmede mürtedler ile çokşiddetli harb oldu. Müseyleme ordusundan yirmibin, \nHâlid ibni Velîd askerinden ikibin kişi öldü. Önce müslimânlar bozuldu. Sonra, \nVahşî hazretleri kahramanca saldırıp, hazret-i Hamzayışehîd etmiş olduğu kılınç \nile Müseyleme-tül-kezzâbı öldürdü. Bunu gören müslimânlar hücûm edip, zafer \nelde edildi. Resûlullahın vaktîle, Vahşîyi Yemâme tarafına göndermesinin, büyük \nmu’cize olduğu böylece meydâna çıkdı. Yermük gazâsında da bulunup, rumlara \nkarşı çok kahramânlıkları görüldü. Humsda yerleşdi. Hazret-i Osmân zemânında \norada vefât etdi. Vahşînin îmân etdikden sonra, şerâb içdiğini ve bu yüzden had \ncezâsı verildiğini söyliyenler oluyor. Bu haberlere sahîh diyemeyiz. Sahîh desek \nbile, bu yüzden bir sahâbîye hattâ herhangi bir müslimâna dil uzatmak câiz olmaz. \nHer müslimânı ve Eshâb- ı kirâmın hepsini iyilikle yâd etmemiz emr olundu. \nBüyük âlim ve onüçüncü asrın müceddidlerinden mevlânâ Hâlid-i Bağdâdî, \n(Âdâb-ı tarîka-i aliyye) kitâbında buyuruyor ki, (Ehl-ullaha i’tirâz eden kimsenin \nküfr üzere öleceğini gösteren hadîs-işerîfler vardı\nr. Velînin ma’sûm olmasışart \ndeğildir. Eshâb- ı kirâm arasında had cezâsı verilen ve eli kesilen oldu. Hâlbuki, \nSahâbenin en aşağı derecede olanı da Velî idi. Hepsi, Sahâbî olmıyan Velîlerin \nhepsinden dahâ yüksek idiler. Velîlerin hepsi, günâha devâm etmekden mahfûz-\ndurlar. Hepsi tevbe ve istigfâr eder. Belki, ba’zan günâh işlediği için pişmânlıkları, \nağlamaları, Allahü teâlâya yalvarmaları dahâ çok olur. Dereceleri artar. Bu sebeb-\nle, (Hikem-i Atâiyye)de, (Zillet ve inkisâra sebeb olan günâh, izzet-i nefse ve kibre \nsebeb olan tâ’atden dahâ hayrlıdır) denilmişdir. Amelleri ve sıfatları müsâvî olan \niki Velîden, tevbesi dahâ çok olanın, ma’sûm olandan dahâ üstün olduğu bildiril-\ndi.) (Buhârî)de diyor ki, (Eshâb- ı kirâmdan Abdüllah adında birine, şerâb içdiği \niçin had cezâsı verildi. Resûlullah “sallallahü aleyhi ve sellem”, buna la’net edildi-\nğini işitince, (Ona la’net etmeyiniz! Çünki O, Allahı ve Resûlünü sevmekdedir) \nbuyurdu.) (Merec-ül-bahreyn)de, Ahmed Zerrûkdan alarak diyor ki, (Ma’sûm \nol -\nmak, kusûrsuz olmak, Peygamberlere mahsûsdur. Velînin ma’sûm olmasışart de -\n– 1187 –\nğildir. İsrâr ve devâm olmadan, büyük günâh işlemek, vilâyeti bozmaz. Velî, günâ-\nhından vazgeçer ve tevbe eder. Günâh işlemek, insanı helâk etmez. Günâha \ndevâm etmek, tevbeyi terk etmek, helâk eder. Âdem aleyhisselâmın zellesi ile, \nİblîsinısyânı, bundan dolayı farklı oldular.) Eshâb- ı kirâmın hepsini sevmekle ve \nhepsine saygılı olmakla emr olunduk. Sevilmeleri az veyâ çok olabilir. Fekat, hiç-\nbirine dil uzatmamız, kötü bilmemiz câiz değildir. Kendi kusûrlarımıza bakmamız, \nhiçbir müslimânı gıybet etmememiz lâzımdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vânî Muhammed Efendi", "slug": "vani-muhammed-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kendisi \nVanlıdır. Fâzıl Ahmed pâşa 1072 [m. 1661] senesinde Vandan getirmişdir. Serây-\nda sultân dördüncü Muhammed hâna, va’z ederdi. İkinci Mustafâ hânın hocası \noldu. Binyetmişaltı 1076 [m. 1665] da Mevlevîlerin simâ’larını ve Halvetîlerin \nrakslarını yasak etdirdi. Babaeskideki Hurûfî tekkesini yıkdırdı. Binseksenbir \n1081 [m. 1670] de, şerâb satılmasını yasak etdirdi. Yeni câmi’de ilk Cum’a va’zı \nyapan budur. 1094 [m. 1682] de, sadr- ı a’zam Merzifonlu kara Mustafâ pâşa Viya-\nnada haçlı orduları karşısında bozguna uğradığında, Vânî Muhammed efendi \norduşeyhi idi. Bunun için, Bursada Kestel köyüne sürüldü. Kestelde büyük câmi’ \nve mekteb yapdırdı. 1096 [m. 1684] da orada vefât etdi. Boğaziçinde Vaniköy \ncâmi’ini de yapdırmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vâsıl bin Atâ", "slug": "vasil-bin-ata", "unvan": "", "kategori": "diger", "biyografi": "Mu’tezile fırkasının kurucusudur. 80 [m. 699] de \nMedînede tevellüd, 131 [m. 748] de vefât etdi. Hasen-i Basrî hazretlerinin talebesi \nidi. Bunu dersinden kovdu.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vâsile bin Eska'", "slug": "vasile-bin-eska", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb- ı kirâmdan idi. Tebük \ngazâsından önce îmâna geldi. Bu gazâda bulundu.", "gectigiMaddeler": ["3/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vehbî", "slug": "vehbi", "unvan": "", "kategori": "diger", "biyografi": "Muhammed Vehbî bin Hüseyn Çelik, [1280] hicrî yılında, Kon-\nyanın Hâdim kazâsında tevellüd, 1362 [m. 1943] de Konyada vefât etdi. Siyâsî \nhayâta atıldı. Şer’ıyye vekîli iken, hilâfetin ilgâsı için fetvâ vermişdir.", "gectigiMaddeler": ["1/25"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Vehbî Efendi", "slug": "vehbi-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzaltmışbeşinci [665] \nsırada Muhammed Mer’aşî ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Veheb bin Verd Mekkî", "slug": "veheb-bin-verd-mekki", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "153 [m. 770] \nsenesinde vefât etdi.", "gectigiMaddeler": ["2/40", "2/47"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Velîd bin Mugîre", "slug": "velid-bin-mugire", "unvan": "", "kategori": "diger", "biyografi": "Kureyş kâfirlerinin ileri gelenlerindendir. Ebû Ceh-\nlin amcasıdır. Babasına Mugayre de denir. Birgün Resûlullahın yanına gelip, bana \nbir mikdâr Kur’ân oku dinleyeyim dedi. Dinledi. Çok tatlı, latîf, derin ve çok fâideli, \nbunu insan söyliyemez, dedi. Kâfirlerin yanına gidip, içinizde, şi’ri benden iyi bilen \nyokdur. Muhammedin okuduğu kelâm, insan ve cinşi’rlerine benzemiyor. O kâhin \ndeğildir. Sözleri kâhin sözüne benzemiyor. Deli dersek kimse inanmaz. Onda cünûn \nalâmeti yokdur. Şâ’ir de değildir. Sihirbâz da diyemeyiz. Sihre benziyen bir işi yok. \nOkuyup, üflemiyor, düğüm bağlamıyor, dedi. Öyle ise, ne diyelim, dediler. Velîd, ne \ndemeli bilmem. Fekat, şu sözlerimizin hiçbiri yakışmıyor. Hangisini söylesek inanıl-\nmaz dedi. Diyecek birşey bulamadılar. Çünki, Peygamberdir demekden başka birşey \nyakışdıramadılar. Hicretin birinci [1] senesinde Mekkede öldü.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Velîd bin Utbe", "slug": "velid-bin-utbe", "unvan": "", "kategori": "diger", "biyografi": "Kureyş kâfirlerinden Utbenin oğludur. Babası gibi, \nİslâm düşmanı idi. Kardeşi Ebû Huzeyfe ise, hâlis müslimân olup, bütün gazâlarda \nbulundu. Velîd, Bedrde babası ve amcası ile, meydâna yürüdü. Hazret-i Alî çıkıp, \nVelîdi bir hamlede katl eyledi.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Veliyyüddîn Tebrîzî", "slug": "veliyyuddin-tebrizi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Altıyüzotuzye-\ndinci [637] sırada Muhammed bin Abdüllah ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Veliyyullah Dehlevî", "slug": "veliyyullah-dehlevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Sekizyüzalt-\nmışdördüncü [864] sırada Şâh Veliyyullah ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Velvâlicî", "slug": "velvalici", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdî Zahîrüddîn Abdürreşîd \n– 1188 –\n467 de Bedahşânın Velvâlc kasabasında tevellüd ve 540 [m. 1146] da vefât etmiş-\ndir. Semerkandda kâdî idi. Fıkhda (Emâlî) kasîdesi ve fetvâları vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Veysel Karânî", "slug": "veysel-karani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Üveys bin Âmir Karnî \nde denir. Tâbi’înin büyüklerinden olduğu hadîs-işerîfde bildirilmişdir. Yemenli-\ndir. Resûlullah sağ iken, görmediği hâlde müslimân oldu. Fekat, Sahâbî olamadı. \nHazret-i Ömer zemânında Medîneye geldi. Çok hurmet gördü. Basrada yaşadı. \nSıffîn muhârebesinde hazret-i Alînin yanında bulundu ve 37 [m. 657] deşehîd \noldu. Anadoluya hiç gelmemişdir. Veysel Karânîye hediyye edilen hırka-i se’âdet, \nVan civârında İrisân beğlerine kadar gelmiş ve bunlardan Şükrüllah efendi, 1027 \n[m. 1618] senesinde, halîfe-i müslimîn ikinci Osmân hâna getirip hediyye etmişdir. \nAbdülmecîd hân, bu hırka-i se’âdet için, Fâtih civârında (Hırka-işerîf) câmi’ini \nyapdırmışdır. Her sene Ramezân- ışerîfde camekân içinde olarak Şükrüllah efen-\ndinin torunları tarafından halka ziyâret etdirilmekdedir. İstanbuldaki bütün \ncâmi’ler hakkında, geniş bilgi veren (Hadîkatül-cevâmi’) kitâbında (Akseki mesci-\ndi)ni anlatırken diyor ki, (Bu mescidi Kemâleddîn efendi yapmışdır. Fâtih sultân \nMuhammed hân ile gelenlerdendir. Mescidin karşısında, Çorlulu Alî pâşanın yap-\ndırdığı binâda (Hırka-işerîf) ziyâret edilmekdedir. Binânın yanına bir imâret ve \nçeşme de yapmışdır. Sultân Mahmûd-i Adlî, binikiyüzkırkaltı [1246] da, bu binâyı \nyeniden yapdı.) Bu kitâb 1193 [m. 1779] de te’lîf ve 1253 de tevsî’ ve 1281 [m. 1864] \nde tab’ edilmişdir. Rûhların terbiye etdiği kimseye (Üveysî) denir.", "gectigiMaddeler": ["2/47", "3/28", "3/37"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Volter", "slug": "volter", "unvan": "", "kategori": "diger", "biyografi": "Fransızşâ’irdir. 1105 [m. 1694] de tevellüd etdi. 1192 [m. \n1778] de öldü. İslâm düşmanı idi. Resûlullahın hazret-i Zeynebi nikâh etmesini, \ntiyatro olarak yazmış, âdî, alçak iftirâlar etmişdir. Bu yüzden, düşmanı olan papa-\ndan tebrîk mektûbu almışdır. İkinci Abdülhamîd hân, bu tiyatronun Avrupada \noynatılmasına, çokşiddet göstererek mâni’ olmuşdur.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Wegener", "slug": "wegener", "unvan": "", "kategori": "diger", "biyografi": "Meteoroloji âlimi ve kutub kâşifidir. 1297 [m. 1880] de \ntevellüd, 1348 [m. 1930] de vefât etdi. Grönland seyâhatinde, buzlar arasında öldü. \nKaraların kayması teorisini kurdu.", "gectigiMaddeler": ["1/39"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Westenfeld", "slug": "westenfeld", "unvan": "", "kategori": "diger", "biyografi": "Alman müsteşriklerindendir. İbni İshakın (Sîret-i \nResûlillah) kitâbını basdırmışdır.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Wıllıam Ceyms", "slug": "william-ceyms", "unvan": "", "kategori": "diger", "biyografi": "Amerikalı felsefecidir. 1258 [m. 1842] de tevellüd \netdi. 1328 [m. 1910] de öldü. (Pragmatizm)in kurucusudur. (Dînî tecribeler) ve \nbaşka kitâblarında, îmânlı olmağı övmüşdür.", "gectigiMaddeler": ["1/11"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Wıllıam Stern", "slug": "william-stern", "unvan": "", "kategori": "diger", "biyografi": "Alman psikolog ve pedagoglarındandır. 1287 [m. \n1871] de tevellüd etdi. Zekâyı ta’rîf ederken, zekâ, düşünceyi hayâtın yenişartla-\nrına uydurmakdır, demişdir.", "gectigiMaddeler": ["2/4"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yâfes", "slug": "yafes", "unvan": "", "kategori": "diger", "biyografi": "Nûh aleyhisselâmın üç oğlundan biridir. Çin, rus, slav ve türk-\nler, bunun soyundandır. Yâfes beşyüz yaşında suda boğuldu. Binlerle torunu, \nAsyaya ve o zemân mevcûd olan kara yolları ile, okyânus adalarına yayıldılar. Nûh \naleyhisselâmın ve Yâfesin dînini ve nasîhatlerini unutarak, yıldızlara, güneşe, hey-\nkellere tapınmağa başladılar.", "gectigiMaddeler": ["1/31", "1/95", "2/15", "2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yâfi'î", "slug": "yafii", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Afîf-üddîn Abdüllah bin Es’ad \nYâfi’î, Şâfi’î mezhebi âlimlerindendir. 698 [m. 1298] senesinde Yemende tevellüd \netdi. Mekkede yerleşdi. Kutb-i Mekke denir. 768 [m. 1367] de Mekkede vefât etdi. \n(Ravd-ur-rıyâhîn), (Neşr-ül-mehâsin-il-gâliyye) ve (Menâkıb-i Abdülkâdir) kitâb-\nları meşhûrdur. (Neşr-ül-Mehâsin)de (Makâmât-i aşere)yi anlatmakdadır. Bu \nkitâbı, (Câmi’ul Kerâmât) kenârında basılmışdır.", "gectigiMaddeler": ["2/5", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yahyâ", "slug": "yahya", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Zekeriyyâ aleyhisselâmın oğludur. Annesi \nElisâ, İmrânın kızı idi. Hıristiyanlar Elizabeth diyor. Hazret-i Meryemin teyzesi \noğlu idi. Dâvüd “aleyhisselâm” soyundandır. (Tevrât)da yazılı olan Îsâ aleyhisse-\n– 1189 –\nlâmın geleceğini haber verdi. Îsâ “aleyhisselâm” göke çıkarıldıkdan sonra, (İncîl)e \nuyduğu için, zâlim yehûdî hükümdârı büyük Herodun torunu, birinci Herod tara-\nfındanşehîd edildi. Mubârek bedeninin parçaları başkaşehrlerdedir. İbni Âbidîn, \nönsözünde diyor ki, (Mubârek başı, Şâmda Ümeyye câmi’indedir.)", "gectigiMaddeler": ["2/20", "2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yahyâ bin Mu'âz", "slug": "yahya-bin-muaz", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Zekeriyyâ Sôfiy-\nyedendir. Reyşehrinde tevellüd etdiği için Râzî denir. 258 [m. 872] senesinde Nîşâ-\npûrda vefât etdi.", "gectigiMaddeler": ["2/5", "2/40"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yahyâ bin Muhammed", "slug": "yahya-bin-muhammed", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Kâdî İbn-ül-\nHâşim-il-Bağdâdî [228] de tevellüd, 318 [m. 930] de vefât etdi. Fıkh ve hadîs âlimi-\ndir. (Kitâb-ül-kırâet) ve fıkhda (Sünen) ve hadîsde (Müsned) kitâbları vardır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yahyâ Efendi", "slug": "yahya-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Beşiktaş ile Ortaköy ara-\nsındaki câmi’işerîfi yapdı. Amasyalıdır. Dokuzyüz [900] de Trabzonda tevellüd, \n977 [m. 1569] de vefât etdi. Kabri üzerine ikinci Selîm hân tarafından türbe yapıldı. \nTıb, matematik ve fizik bilgisi çok idi. Trabzonda vâlî olan sultân Süleymân ile süt \nkardeşi idi. Sultân Süleymân halîfe olunca, İstanbulda meşhûr olan yere yerleşdir-\ndi. Babası Şâmlı Ömer efendi Trabzonda kâdî iken tevellüd etdi. Şi’r ve dîvânı var-\ndır. Üveysîdir. Türbesinde dört erkek, dört kadın dahâ vardır. Yanındaki üç türbe-\nnin herbirinde birer Alî pâşa yatmakdadır. Yanında bir de niyyet kuyusu vardır. \nBir niyyet kuyusu da, Eyyûbde Kaşgarî dergâhı yokuşunda 16 numaralı evin bağ-\nçesindedir.  \nFetvâ sâhibi Minkârî-zâde Yahyâ efendi başkadır. Kırkikincişeyh-ul-islâm idi. \n1088 [m. 1677] de vefât etdi. Üsküdârda medresesi yanındadır.", "gectigiMaddeler": ["1/70", "1/84", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ya'kûb", "slug": "yakub", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "İshak aleyhisselâmın oğlu, Yûsüf aleyhisselâ-\nmın babasıdır. Adı İsrâîl idi. Oniki oğlunun torunlarına (Benî-İsrâîl), ya’nî İsrâîl \noğulları denir. Sonradan yehûdî denildi. Şâmdadır. İshak aleyhisselâmın ikinci \noğlu İys idi. Bunun oğlu Rûm sarışın olduğu için bunun soyundan olanlara (Rûm) \nveyâ (Benî-Asfer) denildi.", "gectigiMaddeler": ["1/85", "1/97", "2/20", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ya'kûb bin Seyyid Alî", "slug": "yakub-bin-seyyid-ali", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Edirnede kâdî \nidi. Sonra Bursada müderris iken 931 [m. 1525] senesinde vefât etdi. (Gülistân) \nşerhı ve (Mefâtîh-ul-cinân) ismindeki (Şir’a-tül-islâm) şerhı meşhûrdur. Buşerh \n1288 [m. 1871]de İstanbulda basılmış ve Hakîkat Kitâbevi tarafından 1413 [m. \n1992] de İstanbulda ofset baskısı yapılmışdır.", "gectigiMaddeler": ["1/98", "2/38", "3/69"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ya'kûb-i Çerhî", "slug": "yakub-i-cerhi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Alâüddîn-i Attâr hazret-\nlerinin talebelerinin büyüklerindendir. Derin âlim, veliy-yi kâmil idi. Gaznede \nÇerh köyünde tevellüd ve 851 [m. 1447] de Hülfetûda vefât eyledi. Hirâtda ve \nMısrda tahsîl edip, Buhârâda Behâeddîn-i Buhârî hazretlerinin sohbeti ve tevec-\ncühleri ileşereflendi. Tebâreke ve Amme cüz’lerinin tefsîri ve fârisî (Risâle-i \nünsiyye) kitâbı Hindistânda basılmışdır.", "gectigiMaddeler": ["3/51", "3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yehûdâ", "slug": "yehuda", "unvan": "", "kategori": "diger", "biyografi": "Îsâ aleyhisselâma îmân eden oniki havârîden biridir. Bunun \nmürted olup, Îsâ aleyhisselâmı otuz dirhem gümüş karşılığında yehûdîlere haber \nverdiği söylenmekdedir. Yudas İsharyot da denilmekdedir. Üçyüzdoksandoku-\nzuncu [399] sırada (Havârîler) ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yekdest", "slug": "yekdest", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed Yekdest Cüryânî, Buhâ-\nrânın Cüryân kasabasında tevellüd etdi. 1069 [m. 1658] da ticâret için Hindistâna \ngiderken Cüryândaki tâ’ûnda çoluk çocuğunun öldüklerini işitdi. Yolda eşkıyâlar \nbasıp mallarını aldılar ve sol kolunu kesdiler. Çok üzüntülü Serhendşehrine geldi. \n1069 [m. 1658] senesinde Muhammed Ma’sûm-i Fârûkînin hizmeti ileşereflendi. \nOnbir sene kahvesini pişirdi. Sonra hilâfet verilip Mekke-i mükerremede irşâda \nemr olundu. Otuzdokuz sene bu vazîfeyi yapdıkdan sonra 1119 [m. 1707] da Mek-\nkede vefât etdi. Şeyh Ahmed Yekdest hazretlerinin çok talebesi vardır. Bunlardan \nbiri, Muhammed Emîn Tokâdî hazretleridir. Bir talebesi de, Eğrikapı dâhilinde Emîr \n– 1190 –\nBuhârî mescidi tekkesindeki tatâr Ahmed efendidir. 1156 [m. 1743] da vefât etmiş-\ndir. Bu mescid, İvez pâşa câmi’inden Ayvanserâya inerken sağda sed üzerinde \nolup, 1384 [m. 1964] de kasden yakılmış, dört dıvârı ve mihrâbı dışındaki tatâr \nAhmed efendinin ve başka birkaç taş kabr kalmışdır. Ahmed Yekdestin bir talebe-\nsi de, seyyid Abdülhakîm efendi hazretlerinin ikâmet etdiği, İdrîs köşkü civârında-\nki evi, Kaşgarî tekkesini ve câmi’i yapdıran, hâcı Murtezâ efendi olup, hesâb uzma-\nnı idi. 1160 [m. 1747] da vefât etmişdir. Bu tekkenin bağçesinde medfûndur. Bun-\nları 1158 [m. 1745] de yapdırmışdır. Tekkenin ilkşeyhi olan Abdüllah-i Kaşgârî, \nondört sene sonra 1174 [m. 1760] de vefât etmişdir. Birinci sultân Mahmûd zemâ-\nnındaki altmışüçüncüşeyh-ul-islâm seyyid Mustafâ efendi de, 1112 [m. 1699] de \nAhmed Yekdest hazretlerine intisâb etmişdir. 1090 [m. 1678] da tevellüd ve 1158 \n[m. 1745] de vefât edip Üsküdârda medfûndur. 1157 [m. 1744] de, Eyyûb Nişânca-\nsındaşeyh-ul-islâm tekkesini ve mescidini yapdırdı. Bu mescid kapısında ve ayrıca \nSarâchânede birer çeşmesi vardır. Ahmed Yekdestin bir halîfesi de dördüncü \nMuhammed hânın baş çuhâdârı Kahramân ağadır. 1147 [m. 1734] de vefât eden \ntârîhci Muhammed Râşid efendi, bunun halîfesi Emîr ağaya mensûbdur. İki cild \ntârîh kitâbı çok kıymetlidir. Kahramân ağanın bir halîfesi de, Enderûnlu Sührâb \nefendi olup, sonra Abdülganî Nablüsîden de feyz almışdır. Üsküdârda Azîz Mah-\nmûd-i Hüdâî tekkesindeki mürşidlerden Mudanyalı zâde Muhammed Revşen \nefendi, Sührâb efendiden feyz almışdır. Ahmed Yekdestin halîfelerinden biri, kâdî \nZıyâüddîn efendi, biri de rûznâmeci başı Muhammed Kumul beğdir. 1132 [m. 1719] \nde vefât etmişdir. Fındıklıda sâhilde molla Çelebî câmi’i yanında, 1121 [m. 1708] de \nvefât edenşeyh-ul-islâm Muhammed Sâdık efendinin kabri yanındadır. Sâdık efen-\ndi, kırksekizincişeyh-ul-islâm olup, ikinci Ahmed hân zemânında, 1105 [m. 1691] \ndeşeyh-ul-islâm olmuş, dokuz ay sonra, ikinci Mustafâ hân tarafından azl edilmiş-\ndir. Üçüncü Ahmed hân zemânında tekrârşeyh-ul-islâm yapılmış, ihtiyâr olduğun-\ndan bir sene sonra azl edilmişdir. Bu câmi’i yapdıran Molla Muhammed Çelebî, \nİstanbul kâdîsı [hâkimi] idi. 998 [m. 1590] de vefât etdi. Eyyûbde Defterdâr caddesi \nile Kızılmescidden gelen yolun kesişdiği yerde büyük türbededir. Ahmed-i Yek-\ndestin bir talebesi de, 1117 [m. 1704] de vefât edip, Karaca Ahmed kabristânında \ndefn edilen Muhammed Semerkandîdir. Bir talebesi de, Dâr-üs-se’âde ağası [ya’nî \nİstanbul vâlîsi] Beşîr ağadır. Bu isme bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yesevî", "slug": "yesevi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin Muhammed Yesevî, Yû -\nsüf-i Hemedânînin üçüncü halîfesidir. Türkistânda Yesi kasabasında tevellüd, 590 \n[m. 1194] da orada vefât etdi. Hâce Atâ-i Yesevî denir. Nevâyî dilinde (Atâ), baba \ndemek ise de türkler meşâyıh ulularına (Atâ) derler. Buhârâda irşâd edip, sonra \nTürkistâna gitdi. Vedâ’ ederken, hâce Abdülhâlık-ı Goncdüvânîye tâbi’ olmaları \niçin talebesine vasıyyet etdi. Türkistân meşâyıhının birincisidir.", "gectigiMaddeler": ["2/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yezîd", "slug": "yezid", "unvan": "", "kategori": "diger", "biyografi": "Emevî halîfelerinin ikincisidir. Hazret-i Mu’âviyenin oğludur. \nYirmialtıncı [26] yılda Şâmda tevellüd etdi. [64] de vefât etdi. [60] senesinde halîfe \noldu. 61 [m. 681] senesinin Muharrem ayında Kerbelâ fâci’ası oldu. Yezîd buna \nüzüldü. (Allah ibni Mercâneye la’net eylesin! Hüseynin istediklerini kabûl etme-\nyip de, onu katl etdirdi. Böylece, beni kötü tanıtdı) dedi. İbni Mercâne, Ubeydül-\nlah bin Ziyâdın adıdır. Yezîd, müslimân idi. Nemâz kılardı. İslâmiyyete düşmân \ndeğildi. Yüzüğünün taşı üzerinde (Rabbünallah) yazılı idi.", "gectigiMaddeler": ["2/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yezîd bin Amr Hübeyre", "slug": "yezid-bin-amr-hubeyre", "unvan": "", "kategori": "diger", "biyografi": "Emevîlerin son halîfesi olan Mervân \nbin Muhammed zemânında Irâk ve Horâsân vâlîsi idi. Ebâ Müslim ile çok harb \netdi. İmâm-ı a’zam Ebû Hanîfeyi habs etdi. Başına kamçı vurdurdu. 132 [m. 750] \nsenesinde Ca’fer Mensûr tarafından öldürüldü.", "gectigiMaddeler": ["2/16"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yuhannâ", "slug": "yuhanna", "unvan": "", "kategori": "diger", "biyografi": "Îsâ aleyhisselâma îmân eden oniki havârîden biridir. İbrâ -\nnî dilinde Yahyâ demekdir. Rumcada Yohannes, yâhud Yani, ermenilerde Ohan-\n– 1191 –\nnes, ingilizlerde Con, fransızcada Jan denir. Dört İncîl yazanlardan biridir. Îsâ \naleyhisselâmın teyzesinin oğlu idi. Üçyüzdoksandokuzuncu [399] sırada, (Havârî-\nler) ismine bakınız!", "gectigiMaddeler": ["1/94"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûnüs", "slug": "yunus", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Yûnüs bin Metâ, Mûsul yanındaki Nineve ehâ-\nlîsine Peygamber idi. Dinlemediler. Heykellere tapmakdan vazgeçmediler. Yûnüs \n“aleyhisselâm” üzüldü. Dicle kenârına geldi. Gemiye bindi. Hâlbuki, Allahü teâlâ, \nböyle emr vermemişdi. Gemi yürümedi. Kur’a çekdiler. Buna isâbet etdi. Suçlu \nbenim buyurdu. Denize atdılar. Balık yutdu. Tevbe etdi. Balık, bunu bir kenâra \nçıkardı. Ölüm hâlinde idi. Tekrâr kuvvet buldu. Tekrâr Nineveye gitmesi emr \nolundu. Yûnüs “aleyhisselâm” gelmeden önce, hava kararmış, her yeri kara \nduman kaplamışdı. Kavmi korkup, tevbe etmiş, tevbeleri kabûl olup, azâb geri \nalınmışdı. Gelince sözlerini dinlediler. Yıllar geçdi. Şarkda Midyalılar Bâbilde \nKeldânîler meydâna geldi.", "gectigiMaddeler": ["1/85", "2/12", "2/20", "3/55"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûnüs bin Abîd", "slug": "yunus-bin-abid", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Takvâ ehli idi. Bezzâz \nidi. Ya’nî kumaş tüccârı idi.", "gectigiMaddeler": ["3/15"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûnüs Emre", "slug": "yunus-emre", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Tesavvuf ehli ve halkşâ’iri-\ndir. Boluludur. Porsuk çayının Sakaryaya karışdığı mahalde türbesi vardır. Tapdık \nEmreden feyz aldı. 843 [m. 1439] de vefât etdi. İlâhîleri zevkle okunmakdadır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûnüsşemmâs", "slug": "yunussemmas", "unvan": "", "kategori": "diger", "biyografi": "Roma İmperatörlerinden ikinci Klaudius zemânın-\nda [m. 268-270] Antakya patrîki idi. Allahü teâlânın bir olduğunu, Îsâ aleyhisselâ-\nmın Onun kulu ve Peygamberi olduğunu i’lân etdi. Çok kimseleri doğru yola getir-\ndi. (Kâmûs)da Şemmâs kelimesinde diyor ki, (Hıristiyanlıkda, Patrîk, müctehid, \nmezheb sâhibidir. Papa, halîfedir. Matrân, Kâdî, hâkimdir. Üskuf, müftîdir. Kıssîs, \nhâfız, okuyucudur. Câsilîk, imâmdır. Şemmâs, müezzindir.)", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf", "slug": "yusuf", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Yâ’kûb “aleyhisselâm” oniki oğlundan en çok \nYûsüfü severdi. Kardeşleri, onu kıra götürüp kuyuya atdı. Onu kurt yidi dediler. \nFekat Allahü teâlâ Onu korudu. Hem Peygamber yapdı, hem de Mısra hükümdâr \nyapdı. Dahâ çok bilgi için, (Eshâb-ı Kirâm)  kitâbına bakınız!", "gectigiMaddeler": ["1/85", "2/20", "2/25", "3/3", "3/58"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf bin Ahmed Sicstânî", "slug": "yusuf-bin-ahmed-sicstani-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "(Münyetül-müftî) ve (Gunye-tül-fükahâ) kitâblarını yazmışdır. Altıyüzotuzsekiz 638 [m. 1240] senesinden sonra Sivâsda vefât etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf bin Cüneyd", "slug": "yusuf-bin-cuneyd", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ehî Çelebî denir. \nİkinci Bâyezîd hân devri âlimlerindendir. Tokatlıdır. Bursada, Edirnede ve İstan-\nbulda müderrislik yapdı. Vikâyenin (Sadr-üş-şerî’a-şerhı)ne hâşiye yaparak (Zahî-\nret-ül-Ukbâ) ismini vermişdir. Bu hâşiyesi ve (Hediyyet-ül-mehdiyyîn) adındaki \n(Elfâz-ı küfr) kitâbı ve (Beydâvî hâşiyesi) meşhûrdur. (Hediyyet-ül-mehdiyyîn) \nkitâbı da arabî olup, Hakîkat Kitâbevi tarafından 1394 [m. 1973] de İstanbulda \nbasdırılmışdır. Akserây ile Topkapı arasında (Ehî zâde)  câmi’ini yapdı. 905 [m. \n1499] de vefât etdi. Câmi’i yanındadır. Kızının torunu Ehî-zâde Abdülhalîm bin \nMuhammedin (Riyâdüssâdâd fî-isbât-il-kerâmât lil-Evliyâ-i hâlel-hayât ve ba’del-\nmemât) kitâbı ve Molla Câmînin fârisî (Şevâhid-ün-nübüvve) kitâbının tercemesi \nmeşhûrdur.", "gectigiMaddeler": ["1/39", "1/41", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf bin Ömer", "slug": "yusuf-bin-omer", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Hanefî fıkh âlimlerin-\ndendir. 832 [m. 1429] de vefât etdi. (Kudûrî muhtasarı)nışerh edenlerdendir. Buşerhıne (Câmi’ul-mudmerât) veyâ kısaca (Mudmerât) denir. Yûsüf bin Ömer Sa -\nkafî başka olup, Emevîlerin Irâk vâlîsi idi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf Decvî", "slug": "yusuf-decvi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Decve, Mısrda Dimyât yakı-\nnındadır. Fıkh âlimidir. İbni Teymiyyeyi ve Muhammed Abdühü red etmekdedir. \nTütün içmek harâm değildir derdi. 1365 [m. 1945] de vefât etdi. 366, 461, 639. \n– 1192 –", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf-‹ Hemedânî", "slug": "yusuf-hemedani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Ya’kûb Yûsüf \nbin Eyyûb Hemedânî, Ehl-i sünnet âlimlerinden ve Evliyân›n büyüklerindendir. \nBüyük âlimlerdendir. (Umdet-ül-makâmât)da diyor ki, (Piyâde olarak otuzyedi hac \nyapd›. Kur’ân-› kerîmi binlerce hatm eyledi. Gece nemâzlar›nda, her rek’atde, bir \ncüz’ okurdu. Tefsîr, hadîs, kelâm ve f›khdan yediyüz cüz’ ezberinde idi. ‹kiyüzonüç \nmürşid-i kâmilden istifâde etdi. Yedibin kâfirin îmâna gelmesine sebeb oldu. H› z›r \naleyhisselâm ile çok sohbet etdi. Hastalara ve nazar değenlere ta’vîz ve m›ska \nyazard›. ‹mâm-› a’zam soyundan idi). [440] da Hemedânda tevellüd, 535 [m. 1141] \nsenesinde Hirâtda vefât etdi. Mervşehrindedir. Onsekiz yaş›nda Bağdâda gelip, Ebû \n‹shak-› Şîrâzîden okudu. Hanefî f›kh ve münâzara âlimi oldu. Ebû Alî Fârmedîden \nfeyz al›p, kemâle geldi. Muhyiddîn-i Arabî hazretleri bir kitâb›nda diyor ki, [602] \nsenesindeşeyh Evhâd-eddîn-i Hâmid Kezmânî Konyaya geldi. Hemedânda Yûsüf-i \nHemedânî, altm› ş y›ldan ziyâde irşâd etmişdir. Birgün bir yere gitmek istedi. Hay-\nvân›n yular› n› serbest b› rakd›. Hayvân bunu, şehr hâricinde bir mescide götürdü. \nMescidde bir genç, buna birşey sordu. Cevâb› n› verdi, dedi. Muhyiddîn-i Arabî haz-\nretleri, burada buyuruyor ki, (Sâd›k olan talebe üstâd› kendi yan› na çeker.) (Fetâ-\nvâ-i hadîsiyye) sonunda diyor ki, (Ebû Sa’îd Abdüllah ve ‹bn-üs-sakkâ ve Abdülkâ-\ndir-i Geylânî hazretleri, ilm tahsîli için Bağdâda gelmişlerdi. Yûsüf-i Hemedânî Bağ-\ndâdda, Nizâmiyye medresesinde va’z ediyordu. ‹bn-üs-sakkâ ad›ndaki meşhûr derin \nâlim, kalk›p birşey sordu. Otur, senin sözünden küfr kokusu geliyor buyurdu. Hakî-\nkaten ‹stanbula sefîr olarak gidip, orada h› ristiyan oldu.) Abdülhâl›k-i Goncdüvânî \nve Ahmed-i Yesevî gibi büyük Velîler yetişdirdi. (Zînet-ül-hayât), (Menâzil-üs-sâyi-\nrîn) ve (Menâzil-üs-sâlikîn) kitâblar› meşhûrdur.", "gectigiMaddeler": ["3/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf Nebhânî", "slug": "yusuf-nebhani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Yûsüf bin İsmâ’îl bin \nYûsüf Nebhânî, Hayfada Eczîm kariyyesinde 1265 [m. 1849] de tevellüd, 1350 [m. \n1932] Ramezân ayında Beyrutda vefât etdi. Ondördüncü asrın büyük âlimlerinden-\ndir. Câmi’ul-ezheri bitirdi. Çok kitâb yazdı. Bunlardan 46 sının ismleri, vehhâbîleri \nred eden (Şevâhid-ül-hak) kitâbının başında yazılıdır. Bunların hepsi basılmışdır. \nFazla bilgi için (Eshâb-ı kirâm) kitâbına bakınız!", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Yûsüf Ziyâ Akışık", "slug": "yusuf-ziya-akisik", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Bosnada, Foçalıdır. \n[1303] de tevellüd, 1378 [m. 1958] de Fâtihde vefât etdi. Edirne-kapı kabristânında \niken, mubârek cesedi m. 2000 senesinde, zevcesi Sü’adâ hanımın cesedi ile birlik-\nde, Eyyûbde Kaşgârî dergâhı yanındaki kabrlerine nakl edilmişdir. Ahmed bin \nhâcı Sâlih bin Zülfikâr pâşa oğludur. Zülfikâr pâşa, Akkoyunlu soyundandır. \nYûsüf Ziyâ beğ, Vefâda Karamürsel kumaş fabrikası müdîri idi. Yüzlerce müsli-\nmân fakîrin sığınağı idi. Yüzlerce gencin hidâyete kavuşmasına sebeb oldu. Seyyid \nAbdülhakîm efendinin sohbeti ve hizmeti ileşereflenmiş, teveccüh ve feyzlerine \nmazhar olmuş, derece-i kemâle vâsıl olmuşdur. Halk içinde, Hak ile idi. Seyyid \nAbdülhakîm efendi, 1348 [m. 1929] de Ziyâ beğe hediyye etdiği (Mektûbât) kitâbı \niç kapağına (Bu kitâb, Yûsüf Ziyâ ibni Ahmede, din kardeşi hattâ babası yerindeki \nAbdülhakîm vâsıtası ile, Allahü teâlâ tarafından ihsân edilmişdir) yazmışdır. Bu \nkitâbı, altı cild bir arada, fârisî olarak, 1166 [m. 1752] da Fâtihde Mesîh pâşa câmi’i \ncivârındaki (Hâcı İlyâs Mescidi) imâmı Vâsık İbrâhîm efendi, çok nefîs olarak yaz-\nmışdır. Hüseyn Hilmi Işık, Ziyâ beğin dâmâdıdır. 1171, 1172, 1197. \n— YÛ ŞA’: Mûsâ aleyhisselâmın dînini yayan peygamberlerdendir. Kur’ân- ı \nkerîmde ismi yazılı değildir. Mûsâ aleyhisselâmın hemşîresinin oğludur. Kabri, \nİstanbulda, Beykozda Yûşa’ tepesinde olduğu söylenmekdedir.", "gectigiMaddeler": ["2/20"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zâhidî", "slug": "zahidi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhtâr bin Mahmûd, Hanefî fıkh \nâlimlerindendir. Îrânda Hârezmde tevellüd, 658 [m. 1259] senesinde vefât etdi. \n(Hâvî), (Müctebâ), (Kudûrîşerhı) kitâbları çok kıymetlidir. (Kınye-tül-fetâvâ) \nkitâbında za’îf bilgiler de vardır.", "gectigiMaddeler": ["1/73", "1/95", "3/19", "3/21"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zâhid-Ül-Kevserî", "slug": "zahid-ul-kevseri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed Zâhid bin \nHasen, sultân Vahîdeddîn hân zemânında, şeyh-ul-islâm Mustafâ Sabrî efendinin \n– 1193 –\nders vekîli idi. Kafkasyalı çerkesdir. 1295 [m. 1878] de tevellüd, 1370 [m. 1951] de Mısr-\nda vefât etdi. Zemânının tefsîr, hadîs ve fıkh âlimi idi. Vehhâbîliği red eden (Esseyf-üs-\nsakîl) kitâbına tekmilesi ile (Makâlât)ı çok kıymetlidir. (El-işfâk alâ ahkâm- ıt talâk) \nkitâbı Kâhirede ve (İrgâmül-merîd) kitâbı Hakîkat Kitâbevi tarafından İstanbulda \nbasılmışdır. (Hüsn-üt-tekâdî) kitâbında Şâh Veliyyullahı tenkîd etmekdedir.", "gectigiMaddeler": ["2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zahîrüddîn-i Hârezmî", "slug": "zahiruddin-i-harezmi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed bin \nİsmâ’îl Zahîrüddîn-i Tîmûr-tâşî Hârezmî, 601 [m. 1204] de vefât etmişdir. Hanefî \nfıkh âlimlerindendir. İmâm-ı Muhammedin (Câmi’us-sagîr)inişerh etmişdir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zahîreddîn-i İshâk", "slug": "zahireddin-i-ishak", "unvan": "", "kategori": "diger", "biyografi": "Ebül Mekârim Velvâlicî. (Velvâliciyye fetvâ-\nsı) İstanbulda basılmışdır. 710 [m. 1310] da vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zebîdî [zübeydî]", "slug": "zebidi-zubeydi", "unvan": "", "kategori": "diger", "biyografi": "ZEBÎDÎ [Zübeydî] : Ahmed bin Ahmed, 893 [m. 1488] de vefât etdi. \n(Tecrîd-üs-sarîh) adındaki iki cild (Buhârî) muhtasarı meşhûrdur. Şerkâvî ve İbni \nKâsım-ı Gazzînin hâşiyeleri ile birlikde 1347 [m. 1928] de Mısrda basılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zehebî", "slug": "zehebi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "İmâm-ı Ebû Abdüllah Şemseddîn \nMuhammed bin Ahmed bin Osmân bin Kaymaz Türkmânî Mısrî, hadîs ve târîh \nâlimlerindendir. 673 [m. 1274] de Şâmda tevellüd, 748 [m. 1348] de Mısrda vefât \netdi. Eserlerinden (Mîzân-ül i’tidâl), oniki cild (Târîh-ül-islâm), (Tecrîd fî-esmâ-i \nSahâbe) ve (Es-sahîfe fî-menâkıb-i Ebî Hanîfe) kitâbları vardır. (Et-tıbbün-Nebevî) \nçok fâideli olup, İbrâhîm Ezrakın (Teshîl-ül-menâfî’)i hâmişinde olarak Mısrda ve \n1396 [m. 1975] da İstanbulda basılmışdır. (Tecrîd) Beyrutda, (Mekteb-üt-ticârî)de \nsatılmakdadır. İbni Teymiyyenin talebesidir.", "gectigiMaddeler": ["2/16", "2/46", "2/52", "2/71"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zekeriyyâ", "slug": "zekeriyya", "unvan": "aleyhisselâm", "kategori": "diger", "biyografi": "Süleymân aleyhisselâmın soyundandır. \nKudüsde Beyt-i mukaddesde (Tevrât) yazmağı, kurban kesmeği idâre ederdi. Zev-\ncesi Îsâ’ hâtûn veyâ Elîsa’, hazret-i Meryemin hemşîresi idi. Babaları İmrân idi. \nİmrân, önce Îsâ’ hâtûnun annesi ile, sonra bunun başka erkekden olan kızı Hunne \nile evlenmişdi. Hazret-i Meryemin annesi Hunne, (Cenâb- ı Hak bana bir oğul \nihsân ederse, Beyt-ül-mukaddese hizmetci yapacağım) diye adadı. Kızı oldu. Adını \nMeryem koydu. Hazret-i Meryem dünyâya gelmeden önce, babası İmrân vefât \netdi. Hunne, kızını Beyt-ül-mukaddese hediyye etdi. Zekeriyyâ “aleyhisselâm”, \nonu evine götürdü. Teyzesi Îsâ’ büyütdü. Sonra, ona Beyt-ül-mukaddesde oda \nyapdırdı. Hazret-i Meryem, bu odada ibâdet ederdi. Yanına Zekeriyyâ aleyhisse-\nlâmdan başka kimse giremezdi. Cebrâîl “aleyhisselâm”, Zekeriyyâ aleyhisselâma \ngelip, Îsâdan Yahyâ adında oğlu olacağını haber verdi. Yahyâ aleyhisselâmdan altı \nay sonra, (Beyt-üllahm) denilen yerde, hazret-i Meryemin oğlu Îsâ “aleyhisselâm” \ntevellüd etdi. Yehûdîler, Zekeriyyâ aleyhisselâma iftirâ etdiler. Sonra, şehîd etdi-\nler, şehîd olurken, yüz yaşında idi.", "gectigiMaddeler": ["2/20", "2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zemâhşerî", "slug": "zemahseri", "unvan": "", "kategori": "diger", "biyografi": "Zimâhşerî de denir. Allâme Ebül-Kâsım Mahmûd Cârul-\nlah bin Ömer, tefsîr, fıkh ve lügat âlimi idi. Mu’tezile mezhebinde idi. Ölürken \ntevbe etdiği söylenmekdedir. 467 [m. 1074] de Hârezmde Zemâhşer kasabasında \ntevellüd, 538 [m. 1144] de arefe gecesinde Cürcâniyyede vefât etdi. Belâgat ilminde \nçok yüksek idi. (Esâs-ül-belâga) kitâbı iki cilddir. Mısrda basılmışdır. (Mukadde-\nme-tül edeb) lügat kitâbı, [1117] de Bursada Murâdiyye medresesi müderrisi tara-\nfından türkceye terceme edilmiş, İstanbulda basılmışdır. (Keşşâf tefsîri)  Kur’ân- ı \nkerîmin belâgatini göstermekde birşâheserdir. Hanefî mezhebine göre ibâdet eder-\ndi. (Kudûrî muhtasarı)nışerh etdi. İmâm-ı a’zam Ebû Hanîfenin menâkıbını yazdı. \nAyasofya câmi’i hakkında da bir risâlesi vardır. Bir ayağı kırık, takma idi. Mekke-i \nmükerremede beş yıl kaldı\n. Bunun için Cârullah denir.", "gectigiMaddeler": ["2/5", "2/44"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zemânşâh", "slug": "zemansah", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Şâh-ı zemân da denir. Efga-\nnistân hükümdârlarındandır. Ahmed Şâh-ı Ebdalînin torunu ve Tîmûr Şâhın oğ -\nludur. 1207 [m. 1793] de pederi ölünce, Kâbilde hükümdâr oldu. 1210 da Lahore \nve Delhîye ziyârete giderken Hirât hâkimi küçük kardeşi Mahmûdşâh Kâbile te -\n– 1194 –\ncâvüz edince, geri döndü. 1214 de Mahmûda mağlûb oldu. 1255 [m. 1839] de ingi-\nlizler, Kâbile en küçük kardeşişâh Şücâ’ı getirdiler ise de, 1258 de Şâh-ı zemân \nhükûmeti tekrâr eline aldı. Serhendşehrinde imâm-ı Rabbânî hazretlerinin küçük \ntürbesini ta’mîr edip üzerine büyük, çok müzeyyen, mermerden bir türbe yapdırdı. \nBunun yanındaki türbede zevcesi ile birlikde medfûndur.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zenbilli Alî Efendi", "slug": "zenbilli-ali-efendi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmânlı Şeyh-ul-\nislâmlarının sekizincisidir. Karamanlıdır. Mevlânâ Muslih-uddîn efendinin talebesi \nve dâmâdıdır. 908 [m. 1502] de Şeyh-ul-islâm oldu. 932 [m. 1526] de vefât edinciye \nkadar ikinci Bâyezîd ve Yavuz sultân Selîm ve Kânûnî sultân Süleymân zemânla-\nrında, bu makâmda başarı ile çalışdı. Yavuz sultân Selîminşiddetli hareketlerini \nbile teskîne muvaffak oldu. Zühd ve takvâsı ve istikâmeti ileşöhret yapdı. İbni \nKemâl Ahmed Şemseddîn efendi, kendisine halef oldu. Cemâlî ismini kullanırdı. \n(El-muhtârât) fıkh kitâbı çok kıymetlidir. Zeyrek yokuşundaki türbesindedir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zenon", "slug": "zenon", "unvan": "", "kategori": "diger", "biyografi": "Eski yunan felesofudur. Bunun felsefesine (Revâkıyyûn) denir.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zerdüşt", "slug": "zerdust", "unvan": "", "kategori": "diger", "biyografi": "Mecûsî ya’nî ateşe tapma dîninin kurucusudur. Mîlâddan \naltıyüz [600] sene önce Hindistânda doğdu. Berehmen din adamları tarafından \nkovuldu. Belhde Mecûsî dînini yaydı. İyilik tanrısı (Îzed) veyâ (Ormüzd) ile kötü-\nlük ve karanlık tanrısı (Ehrimen) olmak üzere iki tanrı vardır dedi. (Zend) kitâbı \nve (Avesta) denilenşerhı Avrupada basılmışdır. Îrânşâhı İsfendiyâr, bu dîni yay-\nmak için Tûranlılarla çok harb etdi. Mejdek, Mecûsîliğe (İştirâkiyye) i’tikâdını da \nkatdı. Ondan önce Îrânlılar (Sâbi’î) idi. Güneşe ve yıldızlara taparlardı. Hazret-i \nÖmer Îrânı alınca, acemler müslimân oldu. Mecûsî dîni Hindistânda kaldı. Bugün, \nÎrânlılar, eski millî âdetler diye mecûsî âyinlerini ve sayılı günlerini ortaya çıkarı-\nyorlar.", "gectigiMaddeler": ["2/27"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zerkânî", "slug": "zerkani", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Muhammed bin Abdülbâkî \nEzherî, Mısrda, Mâlikî hadîs ve fıkh âlimlerindendir. Babası gibi, Zerkânî adı ile \nmeşhûrdur. 1055 [m. 1645] de Zerkânda tevellüd, 1122 [m. 1710] de vefât etdi. \nİmâm-ı Mâlikin (Muvattâ)ını ve Kastalânînin (Mevâhib)inişerh etdi. Bu, sekiz \ncild olup, 1329 [m. 1911] senesinde Mısrda ve 1393 [m. 1973] de Lübnanda basıl-\nmışdır.", "gectigiMaddeler": ["1/25", "1/74", "1/95", "1/97", "2/17", "2/43", "2/47", "2/52", "3/2"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zerkeşî", "slug": "zerkesi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Bedreddîn Muhammed bin Behâ-\ndır, Şâfi’î fıkh âlimidir. 745 [m. 1344] de tevellüd, 794 [m. 1391] de Mısrda vefât \netdi. Şâmda kâdî idi. (Ukûd-ül-cemân fî-vefiyyât-il-a’yan) ı meşhûrdur.", "gectigiMaddeler": ["2/5", "2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyd bin Hârise", "slug": "zeyd-bin-harise", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Resûlullahın kölelerinin en sev-\ngilisi idi. Hazret-i Hadîcenin kölesi idi. Resûlullaha hediyye etdi. O zemân sekiz \nyaşında idi. Resûlullah “sallallahü aleyhi ve sellem” âzâd edip, evlâd edindi. Baba-\nsı yıllarca oğlunu aramış, haber alınca Mekkeye gelip oğlunu istemişdi. Resûlullah, \n(Çocuğun re’yine bırakalım. Kimi isterse, onun olsun) buyurdu. Zeydi getirip sor-\ndular. Benim anam babam budur diyerek, Resûlullahın yanından ayrılmak isteme-\ndi. Resûlullah, bunun üzerine, (Zeyd benim oğlumdur) buyurdu. Babası ve amca-\nsı, sevinip geri döndüler. İlk îmân edenlerdendir. Bütün gazâlarda kahramânlık \ngösterdi. Resûlullah, Zeydi, kendi âzâdlısı Ümm-i Eymen ile nikâhladı. Üsâme \ntevellüd etdi. Sonra, Resûlullah kendi halası Ümeymenin kızı Zeyneb bint-i Cahşı \nda, Zeyde nikâh etdi. Zeyd, Zeynebin ri’âyetine kâdir olamayıp, hicretin üçüncü \n[3] senesinde, arzûları ile ayrıldılar. Hicretin sekizinci [8] senesinde, Şâm civârında \nMu’te denilen yerde üçbin islâm askeri, yüzbinden ziyâde ve tam techîzâtlı rum \nordusu ile cihâd ederken kumandan idi. Şehîd oldu. Yerine Ca’fer bin Ebî Tâlib \nkumandayı ele aldı. O daşehîd oldu. Sonra sancağı Abdüllah ibni Revâha eline \naldı. O daşehîd oldu. Sonra Hâlid bin Velîd, kumandan oldu. Ansızın hücûm \netdi. Elinde dokuz kılınc kırıldı. Düşman bozuldu. Resûlullah, Medînede Mesci-\n– 1195 –\ndinde, bu hâli görüyor. Eshâbına haber veriyordu. Eshâbınınşehîd olduğuna çok \nüzüldü. Zeydden başka hiçbir Sahâbînin ismi, Kur’ân- ı kerîmde açıkca bildirilme-\nmişdir. Zeyd beyâz, güzel idi. Üsâme ise esmer idi. Çünki, Ümm-i Eymen, Resû-\nlullaha annesinden mîrâs kalan habeşî câriye idi.", "gectigiMaddeler": ["1/85", "1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyd bin Sâbit", "slug": "zeyd-bin-sabit", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Eshâb-ı kirâmın büyüklerinden-\ndir. Hazrec kabîlesindendir. Hicretde on yaşında idi. Babası dört sene önce ölmüş-\ndü. Hendek ve sonraki gazâlarda bulundu. Ferâiz ilminde derin bilgisi vardı. Sür-\nyânî öğrenmesi emr olundu. Resûlullahın komşusu idi. Vahy gelince, Resûlullah \nbuna adam gönderir, çağırır, vahyi yazardı. Deve ve Sıffînde ictihâdı, hazret-i Alî-\nnin ictihâdına uymadı. Kur’ân-ı kerîm toplanırken, kendisi yazdı. [45] veyâ 55 [m. \n674] de vefat etdi. Nemâzını Mervân bin Hakem kıldırdı.", "gectigiMaddeler": ["2/16", "2/29"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyd bin Vehb", "slug": "zeyd-bin-vehb", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebû Süleymân Cühnî, \nResûlullahı uzakdan işitip îmâna geldi. Cemâlini görmekleşereflenmeğe gelirken \nvefât etdiğini yolda haber aldı. Tâbi’înin büyüklerinden oldu. Kûfede yerleşdi. \nHazret-i Alînin sohbetinde bulundu.", "gectigiMaddeler": ["1/77"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyd bin Zeynel'âbidîn", "slug": "zeyd-bin-zeynelabidin-rahmetullahi-teala-aleyh", "unvan": "", "kategori": "alim", "biyografi": "Hazret-i Hüseynin torunudur. Hişâm bin Abdülmelik zemânında, Kûfeliler Zeyde, halîfe olursan sana kırkbin asker veririz dediler. Fekat, sözlerinde durmadılar. Ehl-i beyte hıyânet etdiler. Bunların sözlerine aldanarak, yüzyirmiiki 122 [m. 739] de Kûfede halîfeliğini i’lân etdi. Irâk vâlîsi Yûsüf bin Âmirin askeri ile harb ederken yanındakilerin çoğu dağıldı. Zeydşehîd oldu. (Eshâb-ı Kirâm) kitâbına bakınız!", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyla'î", "slug": "zeylai", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Osmân bin Alî, Hanefî fıkh âlim-\nlerindendir. 743 [m. 1343] de Mısrda vefât etdi. İmâm-ı Muhammedin (Câmi’ul-\nkebîr)inişerh etmiş ve (Kenz) kitâbınışerh ederek (Tebyîn-ül-hakâık) adını ver-\nmişdir. (Tebyîn) kitâbı, Ahmed bin Muhammed Şelbînin hâşiyesi ile birlikde 1313 \n[m. 1895] senesinde Mısrda ve sonra Beyrutda basılmışdır. Şelbî 1031 [m. 1621] de \nMısrda vefât etmişdir.", "gectigiMaddeler": ["1/74", "1/80", "3/20", "3/22"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyneb", "slug": "zeyneb", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın dört kızından birincisidir. \nOtuz yaşında iken tevellüd etdi. Nübüvvetden önce, annesi Hadîcenin hemşîrezâ-\ndesi Ebul’âs bin Rebî’ ile evlendi. Ebul’âs îmân etmedi. Bedr gazâsında esîr olup, \nzevcesini Medîneye göndermekşartı ile bırakıldı. Kendi kardeşi ile gönderdi ise \nde, kâfirler Zeynebi yolda geri çevirdi. Resûl “aleyhisselâm” Zeyd bin Hâriseyi \nMekkeye gönderip Zeynebi gece Medîneye kaçırdı. Ebul’âs, Hudeybiye gazâsın-\ndan sonra îmâna geldi. Zeyneb tekrâr kendisine verildi. Hicretin sekizinci [8] \nsenesinde otuzbir yaşında vefât etdi. Oğlu Alî, Mekkenin fethinde Resûlullahın \ndevesinde ve arkasında idi. Zeynebin kızı Ümâmeyi hazret-i Alî kendine nikâh \neyledi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyneb Bint-i Cahş", "slug": "zeyneb-bint-i-cahs", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın halası olan \nÜmeymenin kızı, Abdüllah bin Cahşın kardeşi idi. Babasının adı Burre idi. Îmân \netmediği için, Cahş denildi. Zeyneb ilk îmân edenlerdendir. Resûlullah “sallallahü \naleyhi ve sellem” bunu, önce, oğulluğu olan Zeyd bin Hâriseye nikâh etdi. Zeyd, \nZeynebin hakkını gözetemediğinden, hicretin üçüncü [3] senesinde ayrıldılar. \nResûl “aleyhisselâm” nikâh etmek istedi. Zeyneb bunu işitince, sevincinden iki \nrek’at nemâz kılıp, (Yâ Rabbî! Senin Resûlün beni istiyor. Eğer Onun zevceliği ileşereflenmemi takdîr buyurdun ise, beni Ona sen ver!) diye düâ etdi. Düâsı kabûl \nolup, Ahzâb sûresinin, (Zeyd, onun hakkında istediğini yapdıkdan sonra [ya’nî \nZeynebi boşadıkdan sonra], biz, onu sana zevce eyledik), meâl-işerîfinde olan \notuzyedinci âyeti nâzil oldu. Zeynebin nikâhını Allahü teâlâ yapdığı için, Resûlul-\nlah “sallallahü aleyhi ve sellem” ayrıca nikâh yapmadı. Hazret-i Zeyneb “radıyal-\nlahü anhâ” bununla her an öğünür ve her kadını babası evlendirir. Beni ise, Allahü \nteâlâ nikâhladı, derdi. O zemân otuzsekiz yaşında idi. Hicretin yirminci [20] yılın-\n– 1196 –\nda, elliüç yaşında vefât etdi. Hayrı, ihsânı, sadakayı pekçok severdi. El işlerinde de \nmâhir idi. İşlediğişeyleri ve eline geçen herşeyi akrabâsına ve fakîrlere verirdi. \nHattâ, halîfe Ömer “radıyallahü anh” Ezvâc- ı Mutahheratın herbirine onikibin \ndirhem verirdi. Bu, alır almaz hepsini sadaka eder, dağıtırdı. Resûlullahdan sonra, \nZevcât-i tâhirât arasında, en önce vefât eden budur. Hazret-i Âişe, bunu çok medh \nve senâ eyledi. (Zevcelerim arasında, bana en önce kavuşacak olanı, eli uzun ola-\nnıdır) hadîs-işerîfi, bunun önce vefât edeceğini haber vermişdi. Çünki, en çok \nsadaka veren bu idi. Fransız edebsizşâ’iri Volter, Resûlullahın “sallallahü aleyhi \nve sellem” hazret-i Zeynebi “radıyallahü anhâ” zevceliğe kabûl buyurmasını, \ntârîhlere, vak’a ve haberlere taban tabana zıd ve uydurma, alçak iftirâlarla, şi’r \ndüzerek bir tiyatro kitâbı yazmışdır. Edebiyyât ve fikr adamına yakışmıyan bu çir-\nkin, iğrenç yazısı, kendisini aforoz etmiş olan, büyük düşmanı papanın hoşuna git-\nmiş, kendisini okşayıcı mektûb yazmışdır. Müslimânların halîfesi, sultân ikinci \nAbdülhamîd hân, bu piyesin sahnede oynatılacağını işitince, Fransa ve İngiltere \nhükûmetlerine ültimatom vererek hemen önlemiş, bütün insanlığı, yüz kızartıcı, \naşağılıklardan kurtarmışdır.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeyneb Bint-i Huzeyme", "slug": "zeyneb-bint-i-huzeyme", "unvan": "radıyallahü anhâ", "kategori": "sahabi", "biyografi": "Resûlullahın zev-\ncelerindendir. Çok ibâdet eder, çok sadaka verirdi. Önce Abdüllah bin Cahşın zev-\ncesi idi. Abdüllah, Resûlullahın halası Ümeymenin oğlu idi. Uhud gazâsındaşehîd \noldu. Resûlullahın nikâhı ileşereflendi ise de, sekiz ay sonra vefât etdi.", "gectigiMaddeler": ["1/95"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeynel'âbidîn", "slug": "zeynelabidin", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Oniki imâmın dördün-\ncüsüdür. Zeydin ve Muhammed Bâkırın babalarıdır. Alî bin Hüseyn bin hazret-i \nAlîdir. Bir ismi de Seccâddır. 46 da tevellüd, doksandört 94 [m. 713] de halîfe Velî-\ndin emri ile, Medîne vâlîsi Osmân bin Hayyân tarafından zehrletilerekşehîd edil-\ndi. Mubârek başının, Mısrda Kurâfe kabristânında olduğu, (Tezkîre-i Kurtûbî \nmuhtasarı)nda yazılı ise de, bunun Zeynel’âbidîn hazretlerinin oğlu Zeydin mübâ-\nrek başı olduğu (Tuhfetürrâgıb fî sîreti cemâ’ati min ayânı Ehl-i beytil atayib) kitâ-\nbının 31. sahîfesinde tashîh edilmekdedir.", "gectigiMaddeler": ["1/31"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeynüddîn-i Hâfî", "slug": "zeynuddin-i-hafi", "unvan": "", "kategori": "diger", "biyografi": "İsmi Ebû Bekr Muhammeddir. Büyük Velîler-\ndendir. Nûreddîn Abdürrahmân Mısrînin halîfesi ve Abdüllatîf Kudsî Bursavînin \nmürşididir. [Nefehât.] Bu da, İstanbuldaki Ebül Vefâ hazretlerinin mürşididir. \nHalvetiyye kolundan Zeyniyye tarîkatinin müessisidir. 838 [m. 1435] de vefât etdi. \nHorasânın Haf kasabasındandır. [(Mesmû’ât)da sahîfe 110.]", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zeynüddîn-i Taybâdî", "slug": "zeynuddin-i-taybadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mevlânâ Zey-\nneddîn-i Ebû Bekr, mevlânâ Nizâmeddîn-i Hirevînin talebesi idi. İslâmiyyete \nyapışmakla, sünnete uymakla, bâtınî ilmlere kavuşdu. Evliyânın hâlleri, makâmla-\nrı ihsân olundu. Üveysî idi. Şeyh-ul-islâm Ahmed-i Nâmıkî Câmînin rûhâniyyetin-\nden feyz aldı. Onun türbesine çok gitdi. Şâh-ı Nakşibend Behâeddîn-i Buhârî haz-\nretleri hacca giderken, Hirâtdan geçdi. Taybâda uğrayıp, mevlânâ Zeyneddîn ile \ngörüşdü. 791 [m. 1388] senesinde vefât etdi. 903. \n— ZİYÂ BEĞ: 984 numarada YÛSÜF Z İYÂ ismine bakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ziyâdî", "slug": "ziyadi", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Nûr-üd-dîn Alî bin Yahyâ Ziyâdî, \nMısrdaki Şâfi’î âlimlerindendir. 1024 [m. 1615] de vefât etdi. (Minhâcşerhı)ne hâşi-\nyesi, âlimler arasında çok makbûldür. (Muharrer)işerh etmişdir.", "gectigiMaddeler": ["2/43"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ziyâ Pâşa", "slug": "ziya-pasa", "unvan": "", "kategori": "diger", "biyografi": "Osmânlı devlet adamlarından veşâ’irlerindendir. Erzurum-\nludur. Abdül’azîz hân zemânında Mâ-beyn kâtibi idi. İkinci Abdülhamîd hân zemâ-\nnında Adana vâlîsi oldu ise de, İstanbuldan ayrı kalmak zor geldi. 1295 [m. 1878] de \nvefât etdi. Kabri Adanadadır. Mason olduğu meydâna çıkmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Ziyâ-Üd-Dîn-i Gümüşhânevî", "slug": "ziya-ud-din-i-gumushanevi-rahmetullahi-teala-aley", "unvan": "", "kategori": "alim", "biyografi": "Ah med Ziyâ-üd-dîn efendi, [1235] de Gümüşhânenin Emîrler mahallesinde tevellüd ve 1311 [m. 1893] de İstanbulda vefât etdi. Süleymâniyye câmi’i bağçesindedir. Hâ – 1197 – lid-i Bağdâdînin talebelerinden Ahmed bin Süleymân Ervâdîden [1264] de icâzet aldı. İcâzet alırken, Hâlid-i Bağdâdînin talebelerinden veliy-yi kâmil Abdülfettâh-i Akrî hâzır idi. Bâb- ı âlîde Fâtıma sultân câmi’i yanında ders verirdi. Çok kitâb yazdı. (Râmûz-ül-ehâdîs) hadîs kitâbı çok kıymetlidir.", "gectigiMaddeler": ["2/1", "2/17"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zübeyr bin Avvâm", "slug": "zubeyr-bin-avvam", "unvan": "radıyallahü anh", "kategori": "sahabi", "biyografi": "Huveyled bin Esed bin \nAbdil’uzzâ bin Kusay torunudur. Eshâb- ı kirâmın büyüklerinden ve aşere-i \nmübeşşeredendir. Hazret-i Hadîcenin erkek kardeşinin ve Resûlullahın halası \nolan hazret-i Safiyyenin oğludur. Onsekiz yaşında dördüncü olarak îmâna geldi. \nİslâmda ilk kılınc çeken budur. Bütün gazâlarda bulundu. Çok yaralandı. Mısrın \nfethinde de bulundu. Zengin idi. Bütün malını Allah için dağıtdı. Eshâb- ı kirâmşehîd olunca, yetîmlerine vasî olur, onları beslerdi. Deve vak’asında hazret-i \nTalha ve hazret-i Âişe ile birlikde, hazret-i Alîye karşı idi. Harbden çekilip nemâz \nkılarken, İbni Cermuz tarafından [36]. cı senede, şehîd edildi. Altmışyedi yaşında \nidi. Hazret-i Alî bunu işitince, çok üzüldü. Nemâzını kendi kıldırdı. Zübeyr bin \nEbül’ulâ müceddidî, Muhammed Nakşibend-i sânînin hafîdi olup 1152 de Ser-\nhendde vefât etdi.", "gectigiMaddeler": ["1/54", "2/23", "2/41"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Züfer", "slug": "zufer", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Züfer bin Hüzeyl, Hanefî fıkh \nâlimlerindendir. İmâm-ı a’zam Ebû Hanîfenin talebesindendir. [110] da İsfehânda \ntevellüd, 158 [m. 775] de Basrada vefât etdi. Zarûret hâlinde imâm- ı Züferin sözü \nile amel câizdir.", "gectigiMaddeler": ["1/50", "1/78", "2/16", "3/5", "3/19"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zühdü Pâşa", "slug": "zuhdu-pasa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ahmed Zühdü pâşa sey-\nyiddir. Me’ârif nâzırı idi. 1319 [m. 1901] da vefât etdi. Türkçe (Mecmû’at-üz-Züh-\ndiyye) fıkh kitâbı çok fâidelidir. 1311 de İstanbulda basılmışdır.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zülkarneyn", "slug": "zulkarneyn", "unvan": "", "kategori": "diger", "biyografi": "496. cı sırada, İskender ismine bakınız!", "gectigiMaddeler": ["1/31", "2/20", "2/53"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zülyedeyn", "slug": "zulyedeyn", "unvan": "rad ıyallahü anh", "kategori": "diger", "biyografi": "Resûlullahın bir öğle veyâ ikindi \nnemâzında, ikinci rek’atde selâm verdiğini edeble soran, bu zâtdır. Resûlullah “sal-\nlallahü aleyhi ve sellem”, sonra kalkıp iki rek’at dahâ kıldı ve secde-i sehv yapdı.", "gectigiMaddeler": ["2/23"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Zünnûn-i Mısrî", "slug": "zunnun-i-misri", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Ebülfadl Sevbân bin \nİbrâhîm, Sôfiyye-i aliyyedendir. Sehl-i Tüsterînin mürşididir. Mısrda, tesavvufu ilk \nolarak açıklıyan bu zâtdır. 245 [m. 860] de vefât etdi.", "gectigiMaddeler": ["2/40", "3/3"], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Züvvâr Hüseyn", "slug": "zuvvar-huseyn", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Pâkistânda Karaşişehrinin Nâzımâbâd kısmında, 1401 [m. 1981] de vefât etmişdir. Pâkistânda Hay-\ndarâbâd üniversitesi profesörlerinden gulâm Mustafâ hânın mürşididir. Muham-\nmed Sa’îd-i Kureyşînin halîfesidir. İmâm-ı Rabbânî Ahmed Fârûkînin “rahmetul-\nlahi aleyh” üç cild fârisî (Mektûbât) kitâbını 1392 [m. 1972] senesinde ve Muham-\nmed Ma’sûm-i Fârûkînin “rahmetullahi aleyh”, üç cild fârisî (Mektûbât)ını 1396 \n[m. 1976] senesinde, Pâkistânda Karaşişehrinde tab’ etdirdi. İstanbulda Hakîkat \nKitâbevi, birincinin hepsini 1397 [m. 1977] de ofset yolu ile basdırmış, bu üç cild-\nden seçdiği yüzelliüç mektûbu ve arabîlerinden seçdiği yüzdoksandört mektûbu \n(El-müntehabât) ismi ile ayrı birer kitâb hâlinde basdırmışdır. Ma’sûmiyyeden \nseçdiği yüzaltmışbeş mektûbu da, (Müntehabât-i Ma’sûmiyye) ismi ile, 1399 [m. \n1979] da basdırmışdır. Altıyüzaltmışsekizinci sırada Muhammed Osmân ismine \nbakınız!", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}, {"isim": "Züvâvî Îsâ", "slug": "zuvavi-isa", "unvan": "rahmetullahi teâlâ aleyh", "kategori": "alim", "biyografi": "Mâlikî fıkh âlimidir. İbni \nTeymiyyeyi red eden risâlesi ve (Müdevvene) şerhı meşhûrdur. 743 [m. 1342] de \nKâhirede vefât etdi.", "gectigiMaddeler": [], "kaynak": "Se'âdet-i Ebediyye, Hâl Tercemeleri"}];
